UPDATE hadiths SET urdu = 'ہم کو سعید بن یحییٰ بن سعید اموی قریشی نے یہ حدیث سنائی، انہوں نے اس حدیث کو اپنے والد سے نقل کیا، انہوں نے ابوبردہ بن عبداللہ بن ابی بردہ سے، انہوں نے ابی بردہ سے، انہوں نے ابوموسیٰ رضی اللہ عنہ سے، وہ کہتے ہیں کہ لوگوں نے پوچھا یا رسول اللہ! کون سا اسلام افضل ہے؟ تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا وہ جس کے ماننے والے مسلمانوں کی زبان اور ہاتھ سے سارے مسلمان سلامتی میں رہیں۔' WHERE id = 12;
UPDATE hadiths SET urdu = 'اس حدیث کو ہم سے سلیمان بن حرب نے بیان کیا، ان سے شعبہ نے، وہ قتادہ سے روایت کرتے ہیں، وہ انس رضی اللہ عنہ سے، اور وہ نبی کریم صلی اللہ علیہ وسلم سے نقل کرتے ہیں کہ آپ صلی اللہ علیہ وسلم نے فرمایا، جس شخص میں یہ تین باتیں ہوں گی وہ ایمان کا مزہ پالے گا، ایک یہ کہ وہ شخص جسے اللہ اور اس کا رسول ان کے ماسوا سے زیادہ عزیز ہوں اور دوسرے یہ کہ جو کسی بندے سے محض اللہ ہی کے لیے محبت کرے اور تیسری بات یہ کہ جسے اللہ نے کفر سے نجات دی ہو، پھر دوبارہ کفر اختیار کرنے کو وہ ایسا برا سمجھے جیسا آگ میں گر جانے کو برا جانتا ہے۔' WHERE id = 22;
UPDATE hadiths SET urdu = 'ہم سے بیان کیا عبدالرحمٰن بن مبارک نے، کہا ہم سے بیان کیا حماد بن زید نے، کہا ہم سے بیان کیا ایوب اور یونس نے، انہوں نے حسن سے، انہوں نے احنف بن قیس سے، کہا کہ میں اس شخص ( علی رضی اللہ عنہ ) کی مدد کرنے کو چلا۔ راستے میں مجھ کو ابوبکرہ ملے۔ پوچھا کہاں جاتے ہو؟ میں نے کہا، اس شخص ( علی رضی اللہ عنہ ) کی مدد کرنے کو جاتا ہوں۔ ابوبکرہ نے کہا اپنے گھر کو لوٹ جاؤ۔ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا ہے آپ صلی اللہ علیہ وسلم فرماتے تھے جب دو مسلمان اپنی اپنی تلواریں لے کر بھڑ جائیں تو قاتل اور مقتول دونوں دوزخی ہیں۔ میں نے عرض کیا یا رسول اللہ! قاتل تو خیر ( ضرور دوزخی ہونا چاہیے ) مقتول کیوں؟ فرمایا ”وہ بھی اپنے ساتھی کو مار ڈالنے کی حرص رکھتا تھا۔“ ( موقع پاتا تو وہ اسے ضرور قتل کر دیتا دل کے عزم صمیم پر وہ دوزخی ہوا ) ۔' WHERE id = 32;
UPDATE hadiths SET urdu = 'امام مالک رحمہ اللہ کہتے ہیں مجھے زید بن اسلم نے خبر دی، انہیں عطاء بن یسار نے، ان کو ابو سعید خدری رضی اللہ عنہ نے بتایا کہ انہوں نے رسول اللہ صلی اللہ علیہ وسلم کو یہ ارشاد فرماتے ہوئے سنا کہ جب ( ایک ) بندہ مسلمان ہو جائے اور اس کا اسلام عمدہ ہو ( یقین و خلوص کے ساتھ ہو ) تو اللہ اس کے گناہ کو جو اس نے اس ( اسلام لانے ) سے پہلے کیا معاف فرما دیتا ہے اور اب اس کے بعد کے لیے بدلا شروع ہو جاتا ہے ( یعنی ) ایک نیکی کے عوض دس گنا سے لے کر سات سو گنا تک ( ثواب ) اور ایک برائی کا اسی برائی کے مطابق ( بدلا دیا جاتا ہے ) مگر یہ کہ اللہ تعالیٰ اس برائی سے بھی درگزر کرے۔ ( اور اسے بھی معاف فرما دے۔ یہ بھی اس کے لیے آسان ہے۔)' WHERE id = 42;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن حمزہ نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے بیان کیا، انہوں نے صالح بن کیسان سے، انہوں نے ابن شہاب سے، انہوں نے عبیداللہ بن عبداللہ سے، ان کو عبداللہ بن عباس رضی اللہ عنہما نے خبر دی، ان کو ابوسفیان بن حرب نے کہ ہرقل ( روم کے بادشاہ ) نے ان سے کہا۔ میں نے تم سے پوچھا تھا کہ اس رسول کے ماننے والے بڑھ رہے ہیں یا گھٹ رہے ہیں۔ تو نے جواب میں بتلایا کہ وہ بڑھ رہے ہیں۔ ( ٹھیک ہے ) ایمان کا یہی حال رہتا ہے یہاں تک کہ وہ پورا ہو جائے اور میں نے تجھ سے پوچھا تھا کہ کوئی اس کے دین میں آ کر پھر اس کو برا جان کر پھر جاتا ہے؟ تو نے کہا۔ نہیں، اور ایمان کا یہی حال ہے۔ جب اس کی خوشی دل میں سما جاتی ہے تو پھر اس کو کوئی برا نہیں سمجھ سکتا۔' WHERE id = 52;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے اسماعیل بن جعفر نے بیان کیا، انہوں نے عبداللہ بن دینار سے، انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا درختوں میں ایک درخت ایسا ہے کہ اس کے پتے نہیں جھڑتے اور مسلمان کی مثال اسی درخت کی سی ہے۔ بتاؤ وہ کون سا درخت ہے؟ یہ سن کر لوگوں کا خیال جنگل کے درختوں کی طرف دوڑا۔ عبداللہ رضی اللہ عنہ نے کہا میرے دل میں آیا کہ وہ کھجور کا درخت ہے۔ مگر میں اپنی ( کم سنی کی ) شرم سے نہ بولا۔ آخر صحابہ نے نبی کریم صلی اللہ علیہ وسلم ہی سے پوچھا کہ وہ کون سا درخت ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا وہ کھجور کا درخت ہے۔' WHERE id = 62;
UPDATE hadiths SET urdu = 'ہم سے سعید بن عفیر نے بیان کیا، ان سے وہب نے یونس کے واسطے سے نقل کیا، وہ ابن شہاب سے نقل کرتے ہیں، ان سے حمید بن عبدالرحمٰن نے کہا کہ میں نے معاویہ سے سنا۔ وہ خطبہ میں فرما رہے تھے کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو یہ فرماتے ہوئے سنا کہ جس شخص کے ساتھ اللہ تعالیٰ بھلائی کا ارادہ کرے اسے دین کی سمجھ عنایت فرما دیتا ہے اور میں تو محض تقسیم کرنے والا ہوں، دینے والا تو اللہ ہی ہے اور یہ امت ہمیشہ اللہ کے حکم پر قائم رہے گی اور جو شخص ان کی مخالفت کرے گا، انہیں نقصان نہیں پہنچا سکے گا، یہاں تک کہ اللہ کا حکم ( قیامت ) آ جائے ( اور یہ عالم فنا ہو جائے ) ۔' WHERE id = 72;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا ان سے یحییٰ نے شعبہ سے نقل کیا، وہ قتادہ سے اور قتادہ انس سے روایت کرتے ہیں، انہوں نے فرمایا کہ میں تم سے ایک ایسی حدیث بیان کرتا ہوں جو میرے بعد تم سے کوئی نہیں بیان کرے گا، میں نے رسول اللہ صلی اللہ علیہ وسلم کو یہ فرماتے ہوئے سنا کہ علامات قیامت میں سے یہ ہے کہ علم ( دین ) کم ہو جائے گا۔ جہل ظاہر ہو جائے گا۔ زنا بکثرت ہو گا۔ عورتیں بڑھ جائیں گی اور مرد کم ہو جائیں گے۔ حتیٰ کہ 50 عورتوں کا نگراں صرف ایک مرد رہ جائے گا۔' WHERE id = 82;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، ان سے ابوعامر العقدی نے، وہ سلیمان بن بلال المدینی سے، وہ ربیعہ بن ابی عبدالرحمٰن سے، وہ یزید سے جو منبعث کے آزاد کردہ تھے، وہ زید بن خالد الجہنی سے روایت کرتے ہیں کہ ایک شخص ( عمیر یا بلال ) نے رسول اللہ صلی اللہ علیہ وسلم سے پڑی ہوئی چیز کے بارے میں دریافت کیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا، اس کی بندھن پہچان لے یا فرمایا کہ اس کا برتن اور تھیلی ( پہچان لے ) پھر ایک سال تک اس کی شناخت ( کا اعلان ) کراؤ پھر ( اس کا مالک نہ ملے تو ) اس سے فائدہ اٹھاؤ اور اگر اس کا مالک آ جائے تو اسے سونپ دو۔ اس نے پوچھا کہ اچھا گم شدہ اونٹ ( کے بارے میں ) کیا حکم ہے؟ آپ کو اس قدر غصہ آ گیا کہ رخسار مبارک سرخ ہو گئے۔ یا راوی نے یہ کہا کہ آپ کا چہرہ سرخ ہو گیا۔ ( یہ سن کر ) آپ صلی اللہ علیہ وسلم نے فرمایا۔ تجھے اونٹ سے کیا واسطہ؟ اس کے ساتھ خود اس کی مشک ہے اور اس کے ( پاؤں کے ) سم ہیں۔ وہ خود پانی پر پہنچے گا اور خود پی لے گا اور خود درخت پر چرے گا۔ لہٰذا اسے چھوڑ دو یہاں تک کہ اس کا مالک مل جائے۔ اس نے کہا کہ اچھا گم شدہ بکری کے ( بارے میں ) کیا ارشاد ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا، وہ تیری ہے یا تیرے بھائی کی، ورنہ بھیڑئیے کی ( غذا ) ہے۔' WHERE id = 92;
UPDATE hadiths SET urdu = 'ہم سے آدم نے بیان کیا، ان سے شعبہ نے، ان سے ابن الاصبہانی نے، انہوں نے ابوصالح ذکوان سے سنا، وہ ابو سعید خدری رضی اللہ عنہ سے روایت کرتے ہیں کہ عورتوں نے رسول اللہ صلی اللہ علیہ وسلم سے کہا کہ ( آپ صلی اللہ علیہ وسلم سے فائدہ اٹھانے میں ) مرد ہم سے آگے بڑھ گئے ہیں، اس لیے آپ اپنی طرف سے ہمارے ( وعظ کے ) لیے ( بھی ) کوئی دن خاص فرما دیں۔ تو آپ صلی اللہ علیہ وسلم نے ان سے ایک دن کا وعدہ فرما لیا۔ اس دن عورتوں سے آپ نے ملاقات کی اور انہیں وعظ فرمایا اور ( مناسب ) احکام سنائے جو کچھ آپ صلی اللہ علیہ وسلم نے ان سے فرمایا تھا اس میں یہ بات بھی تھی کہ جو کوئی عورت تم میں سے ( اپنے ) تین ( لڑکے ) آگے بھیج دے گی تو وہ اس کے لیے دوزخ سے پناہ بن جائیں گے۔ اس پر ایک عورت نے کہا، اگر دو ( بچے بھیج دے ) آپ صلی اللہ علیہ وسلم نے فرمایا ہاں! اور دو ( کا بھی یہ حکم ہے ) ۔' WHERE id = 102;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، انہیں وکیع نے سفیان سے خبر دی، انہوں نے مطرف سے سنا، انہوں نے شعبی رحمہ اللہ سے، انہوں نے ابوحجیفہ سے، وہ کہتے ہیں کہ میں نے علی رضی اللہ عنہ سے پوچھا کہ کیا آپ کے پاس کوئی ( اور بھی ) کتاب ہے؟ انہوں نے فرمایا کہ نہیں، مگر اللہ کی کتاب قرآن ہے یا پھر فہم ہے جو وہ ایک مسلمان کو عطا کرتا ہے۔ یا پھر جو کچھ اس صحیفے میں ہے۔ میں نے پوچھا، اس صحیفے میں کیا ہے؟ انہوں نے فرمایا، دیت اور قیدیوں کی رہائی کا بیان ہے اور یہ حکم کہ مسلمان، کافر کے بدلے قتل نہ کیا جائے۔' WHERE id = 112;
UPDATE hadiths SET urdu = 'ہم سے حجاج نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، انہوں نے کہا مجھے علی بن مدرک نے ابوزرعہ سے خبر دی، وہ جریر رضی اللہ عنہ سے نقل کرتے ہیں کہ نبی اکرم صلی اللہ علیہ وسلم نے ان سے حجۃ الوداع میں فرمایا کہ لوگوں کو بالکل خاموش کر دو ( تاکہ وہ خوب سن لیں ) پھر فرمایا، لوگو! میرے بعد پھر کافر مت بن جانا کہ ایک دوسرے کی گردن مارنے لگو۔' WHERE id = 122;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، ان سے مالک نے عبداللہ بن دینار کے واسطے سے بیان کیا، وہ عبداللہ بن عمر سے روایت کرتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم نے (ایک مرتبہ) فرمایا کہ درختوں میں سے ایک درخت ( ایسا ) ہے۔ جس کے پتے ( کبھی ) نہیں جھڑتے اور اس کی مثال مسلمان جیسی ہے۔ مجھے بتلاؤ وہ کیا ( درخت ) ہے؟ تو لوگ جنگلی درختوں ( کی سوچ ) میں پڑ گئے اور میرے دل میں آیا ( کہ میں بتلا دوں ) کہ وہ کھجور ( کا پیڑ ) ہے، عبداللہ کہتے ہیں کہ پھر مجھے شرم آ گئی ( اور میں چپ ہی رہا ) تب لوگوں نے عرض کیا یا رسول اللہ! آپ ہی ( خود ) اس کے بارہ میں بتلائیے، آپ صلی اللہ علیہ وسلم نے فرمایا، وہ کھجور ہے۔ عبداللہ کہتے ہیں کہ میرے جی میں جو بات تھی وہ میں نے اپنے والد ( عمر رضی اللہ عنہ ) کو بتلائی، وہ کہنے لگے کہ اگر تو ( اس وقت ) کہہ دیتا تو میرے لیے ایسے ایسے قیمتی سرمایہ سے زیادہ محبوب ہوتا۔' WHERE id = 132;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے جریر نے منصور کے واسطے سے روایت کیا، انہوں نے سالم ابن ابی الجعد سے نقل کیا، وہ کریب سے، وہ ابن عباس رضی اللہ عنہما سے روایت کرتے ہیں، وہ اس حدیث کو نبی کریم صلی اللہ علیہ وسلم تک پہنچاتے تھے کہ آپ صلی اللہ علیہ وسلم نے فرمایا ”جب تم میں سے کوئی اپنی بیوی سے جماع کرے تو کہے «بسم الله اللهم جنبنا الشيطان وجنب الشيطان ما رزقتنا‏» ”اللہ کے نام کے ساتھ شروع کرتا ہوں۔ اے اللہ! ہمیں شیطان سے بچا اور شیطان کو اس چیز سے دور رکھ جو تو ( اس جماع کے نتیجے میں ) ہمیں عطا فرمائے۔“ یہ دعا پڑھنے کے بعد ( جماع کرنے سے ) میاں بیوی کو جو اولاد ملے گی اسے شیطان نقصان نہیں پہنچا سکتا۔' WHERE id = 142;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، وہ عطاء بن ابی میمونہ سے نقل کرتے ہیں، انہوں نے انس رضی اللہ عنہ سے سنا، وہ کہتے ہیں کہ جب نبی کریم صلی اللہ علیہ وسلم قضاء حاجت کے لیے نکلتے، میں اور ایک لڑکا دونوں آپ صلی اللہ علیہ وسلم کے پیچھے جاتے تھے اور ہمارے ساتھ پانی کا ایک برتن ہوتا تھا۔' WHERE id = 152;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا انہیں یونس نے زہری کے واسطے سے خبر دی، کہا انہیں ابوادریس نے بتایا، انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا، وہ نبی کریم صلی اللہ علیہ وسلم سے نقل کرتے ہیں کہ آپ صلی اللہ علیہ وسلم نے فرمایا جو شخص وضو کرے اسے چاہیے کہ ناک صاف کرے اور جو پتھر سے استنجاء کرے اسے چاہیے کہ طاق عدد ( یعنی ایک یا تین یا پانچ ہی ) سے کرے۔' WHERE id = 162;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبدالرحیم نے بیان کیا، انہوں نے کہا ہم کو سعید بن سلیمان نے خبر دی انہوں نے، کہا ہم سے عباد نے ابن عون کے واسطے سے بیان کیا۔ وہ ابن سیرین سے، وہ انس بن مالک رضی اللہ عنہ سے نقل کرتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم نے ( حجۃ الوداع میں ) جب سر کے بال منڈوائے تو سب سے پہلے ابوطلحہ رضی اللہ عنہ نے آپ صلی اللہ علیہ وسلم کے بال لیے تھے۔' WHERE id = 172;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا ہم کو یزید بن ہارون نے یحییٰ سے خبر دی، وہ موسیٰ بن عقبہ سے، وہ کریب ابن عباس کے آزاد کردہ غلام سے، وہ اسامہ بن زید سے نقل کرتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم جب عرفہ سے لوٹے، تو ( پہاڑ کی ) گھاٹی کی جانب مڑ گئے، اور رفع حاجت کی۔ اسامہ کہتے ہیں کہ پھر ( آپ صلی اللہ علیہ وسلم نے وضو کیا اور ) میں آپ صلی اللہ علیہ وسلم کے ( اعضاء ) پر پانی ڈالنے لگا اور آپ صلی اللہ علیہ وسلم وضو فرماتے رہے۔ میں نے کہا یا رسول اللہ! آپ ( اب ) نماز پڑھیں گے؟ آپ صلی اللہ علیہ وسلم نے فرمایا نماز کا مقام تمہارے سامنے ( یعنی مزدلفہ میں ) ہے۔ وہاں نماز پڑھی جائے گی۔' WHERE id = 182;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا ہم سے خالد بن عبداللہ نے بیان کیا، ان سے عمرو بن یحییٰ نے اپنے باپ (یحییٰ) کے واسطے سے بیان کیا، وہ عبداللہ بن زید رضی اللہ عنہ سے نقل کرتے ہیں کہ ( وضو کرتے وقت ) انہوں نے برتن سے ( پہلے ) اپنے دونوں ہاتھوں پر پانی ڈالا۔ پھر انہیں دھویا۔ پھر دھویا۔ ( یا یوں کہا کہ ) کلی کی اور ناک میں ایک چلو سے پانی ڈالا۔ اور تین مرتبہ اسی طرح کیا۔ پھر تین مرتبہ اپنا چہرہ دھویا پھر کہنیوں تک اپنے دونوں ہاتھ دو دو بار دھوئے۔ پھر سر کا مسح کیا۔ اگلی جانب اور پچھلی جانب کا اور ٹخنوں تک اپنے دونوں پاؤں دھوئے، پھر کہا کہ رسول اللہ صلی اللہ علیہ وسلم کا وضو اسی طرح ہوا کرتا تھا۔' WHERE id = 192;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے مسعر نے، کہا مجھ سے ابن جبیر نے، انہوں نے انس رضی اللہ عنہ کو یہ فرماتے ہوئے سنا کہ رسول اللہ صلی اللہ علیہ وسلم جب دھوتے یا ( یہ کہا کہ ) جب نہاتے تو ایک صاع سے لے کر پانچ مد تک ( پانی استعمال فرماتے تھے ) اور جب وضو فرماتے تو ایک مد ( پانی ) سے۔' WHERE id = 202;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر اور قتیبہ نے بیان کیا، انہوں نے کہا ہم سے لیث نے بیان کیا، وہ عقیل سے، وہ ابن شہاب سے، وہ عبیداللہ بن عبداللہ بن عتبہ سے، وہ عبداللہ بن عباس رضی اللہ عنہما سے روایت کرتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم نے دودھ پیا، پھر کلی کی اور فرمایا اس میں چکنائی ہوتی ہے۔ اس حدیث میں عقیل کی یونس اور صالح بن کیسان نے زہری سے متابعت کی ہے۔' WHERE id = 212;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہمیں عبداللہ نے خبر دی، کہا ہمیں یحییٰ بن سعید نے خبر دی، کہا میں نے انس بن مالک رضی اللہ عنہ سے سنا، وہ رسول اللہ صلی اللہ علیہ وسلم سے روایت کرتے ہیں کہ ایک دیہاتی شخص آیا اور اس نے مسجد کے ایک کونے میں پیشاب کر دیا۔ لوگوں نے اس کو منع کیا تو رسول اللہ صلی اللہ علیہ وسلم نے انہیں روک دیا۔ جب وہ پیشاب کر کے فارغ ہوا تو آپ صلی اللہ علیہ وسلم نے اس ( کے پیشاب ) پر ایک ڈول پانی بہانے کا حکم دیا۔ چنانچہ بہا دیا گیا۔' WHERE id = 222;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے کہا ہم سے عبدالواحد نے بیان کیا، انہوں نے کہا ہم سے عمرو بن میمون نے، وہ کہتے ہیں کہ میں نے اس کپڑے کے متعلق جس میں جنابت ( ناپاکی ) کا اثر آ گیا ہو، سلیمان بن یسار سے سنا وہ کہتے تھے کہ عائشہ رضی اللہ عنہا نے فرمایا کہ میں رسول اللہ صلی اللہ علیہ وسلم کے کپڑے سے منی کو دھو ڈالتی تھی پھر آپ صلی اللہ علیہ وسلم نماز کے لیے باہر نکلتے اور دھونے کا نشان یعنی پانی کے دھبے کپڑے میں ہوتے۔' WHERE id = 232;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، کہا ہم سے سفیان نے حمید کے واسطے سے بیان کیا، وہ انس رضی اللہ عنہ سے روایت کرتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم نے ( ایک مرتبہ ) اپنے کپڑے میں تھوکا۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) نے فرمایا کہ سعید بن ابی مریم نے اس حدیث کو طوالت کے ساتھ بیان کیا انہوں نے کہا ہم کو خبر دی یحییٰ بن ایوب نے، کہا مجھ سے حمید نے بیان کیا، کہا میں نے انس سے سنا، وہ نبی کریم صلی اللہ علیہ وسلم سے روایت کرتے ہیں۔' WHERE id = 242;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے حدیث بیان کی، انہوں نے کہا کہ ہم سے عبدالصمد نے، انہوں نے کہا ہم سے شعبہ نے، انہوں نے کہا ہم سے ابوبکر بن حفص نے، انہوں نے کہا کہ میں نے ابوسلمہ سے یہ حدیث سنی کہ میں ( ابوسلمہ ) اور عائشہ رضی اللہ عنہا کے بھائی عائشہ رضی اللہ عنہا کی خدمت میں گئے۔ ان کے بھائی نے نبی کریم صلی اللہ علیہ وسلم کے غسل کے بارے میں سوال کیا۔ تو آپ نے صاع جیسا ایک برتن منگوایا۔ پھر غسل کیا اور اپنے اوپر پانی بہایا۔ اس وقت ہمارے درمیان اور ان کے درمیان پردہ حائل تھا۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) کہتے ہیں کہ یزید بن ہارون، بہز اور جدی نے شعبہ سے قدر صاع کے الفاظ روایت کئے ہیں۔ ( نوٹ: صاع کے اندر 2.488 کلو گرام ہوتا ہے۔)' WHERE id = 252;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، کہا ہم سے افلح بن حمید نے بیان کیا قاسم سے، وہ عائشہ رضی اللہ عنہا سے، آپ نے فرمایا کہ میں اور نبی کریم صلی اللہ علیہ وسلم ایک برتن میں اس طرح غسل کرتے تھے کہ ہمارے ہاتھ باری باری اس میں پڑتے تھے۔' WHERE id = 262;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے حدیث بیان کی، کہا ہم سے حکم نے ابراہیم کے واسطہ سے، وہ اسود سے، وہ عائشہ رضی اللہ عنہا سے، آپ نے فرمایا گویا کہ میں نبی کریم صلی اللہ علیہ وسلم کی مانگ میں خوشبو کی چمک دیکھ رہی ہوں اس حال میں کہ آپ صلی اللہ علیہ وسلم احرام باندھے ہوئے ہیں۔' WHERE id = 272;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے، کہا ہم سے حمید طویل نے، کہا ہم سے بکر بن عبداللہ نے ابورافع کے واسطہ سے، انہوں نے ابوہریرہ سے سنا کہ مدینہ کے کسی راستے پر نبی کریم صلی اللہ علیہ وسلم سے ان کی ملاقات ہوئی۔ اس وقت ابوہریرہ رضی اللہ عنہ جنابت کی حالت میں تھے۔ ابوہریرہ رضی اللہ عنہ نے کہا کہ میں پیچھے رہ کر لوٹ گیا اور غسل کر کے واپس آیا۔ تو رسول اللہ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ اے ابوہریرہ! کہاں چلے گئے تھے۔ انہوں نے جواب دیا کہ میں جنابت کی حالت میں تھا۔ اس لیے میں نے آپ صلی اللہ علیہ وسلم کے ساتھ بغیر غسل کے بیٹھنا برا جانا۔ آپ صلی اللہ علیہ وسلم نے ارشاد فرمایا۔ سبحان اللہ! مومن ہرگز نجس نہیں ہو سکتا۔' WHERE id = 283;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے ہشام بن عروہ سے، کہا مجھے خبر دی میرے والد نے، کہا مجھے خبر دی ابوایوب نے، کہا مجھے خبر دی ابی بن کعب نے کہ انھوں نے پوچھا: یا رسول اللہ! جب مرد عورت سے جماع کرے اور انزال نہ ہو تو کیا کرے؟ آپ صلی اللہ علیہ وسلم نے فرمایا عورت سے جو کچھ اسے لگ گیا اسے دھو لے پھر وضو کرے اور نماز پڑھے۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) نے کہا غسل میں زیادہ احتیاط ہے اور یہ آخری احادیث ہم نے اس لیے بیان کر دیں ( تاکہ معلوم ہو جائے کہ ) اس مسئلہ میں اختلاف ہے اور پانی ( سے غسل کر لینا ہی ) زیادہ پاک کرنے والا ہے۔ ( نوٹ: یہ اجازت ابتداء اسلام میں تھی بعد میں یہ حکم منسوخ ہو گیا ) ۔' WHERE id = 293;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم سے امام مالک نے ہشام بن عروہ کے واسطہ سے بیان کیا، انہوں نے اپنے والد سے، انہوں نے عائشہ رضی اللہ عنہا سے، آپ نے بیان کیا کہ فاطمہ ابی حبیش کی بیٹی نے رسول اللہ صلی اللہ علیہ وسلم سے کہا کہ یا رسول اللہ! میں تو پاک ہی نہیں ہوتی، تو کیا میں نماز بالکل چھوڑ دوں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ رگ کا خون ہے حیض نہیں اس لیے جب حیض کے دن ( جن میں کبھی پہلے تمہیں عادتاً آیا کرتا تھا ) آئیں تو نماز چھوڑ دے اور جب اندازہ کے مطابق وہ دن گزر جائیں، تو خون دھو ڈال اور نماز پڑھ۔' WHERE id = 304;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے، کہا ہم سے ابن شہاب زہری نے عروہ کے واسطہ سے کہ عائشہ رضی اللہ عنہا نے بتلایا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کے ساتھ حجۃ الوداع کیا، میں تمتع کرنے والوں میں تھی اور ہدی ( یعنی قربانی کا جانور ) اپنے ساتھ نہیں لے گئی تھی۔ عائشہ رضی اللہ عنہا نے اپنے متعلق بتایا کہ پھر وہ حائضہ ہو گئیں اور عرفہ کی رات آ گئی اور ابھی تک وہ پاک نہیں ہوئی تھیں۔ اس لیے انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے کہا کہ یا رسول اللہ! آج عرفہ کی رات ہے اور میں عمرہ کی نیت کر چکی تھی، رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اپنے سر کو کھول ڈال اور کنگھا کر اور عمرہ کو چھوڑ دے۔ میں نے ایسا ہی کیا۔ پھر میں نے حج پورا کیا۔ اور لیلۃ الحصبہ میں عبدالرحمٰن بن ابوبکر کو نبی کریم صلی اللہ علیہ وسلم نے حکم دیا۔ وہ مجھے اس عمرہ کے بدلہ میں جس کی نیت میں نے کی تھی تنعیم سے ( دوسرا ) عمرہ کرا لائے۔' WHERE id = 314;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا ہم سے اسماعیل بن علیہ نے بیان کیا، انہوں نے ایوب سختیانی سے، وہ محمد بن سیرین سے، وہ ام عطیہ سے، آپ نے فرمایا کہ ہم زرد اور مٹیالے رنگ کو کوئی اہمیت نہیں دیتی تھیں۔' WHERE id = 324;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، انہوں نے کہا ہم سے حکم بن عیینہ نے بیان کیا، انہوں نے ذر بن عبداللہ سے، انہوں نے سعید بن عبدالرحمٰن بن ابزیٰ سے، وہ اپنے باپ سے، انہوں نے بیان کیا کہ ایک شخص عمر بن خطاب رضی اللہ عنہ کے پاس آیا اور عرض کی کہ مجھے غسل کی حاجت ہو گئی اور پانی نہیں ملا ( تو میں اب کیا کروں ) اس پر عمار بن یاسر رضی اللہ عنہما نے عمر بن خطاب رضی اللہ عنہ سے کہا، کیا آپ کو یاد نہیں جب میں اور آپ سفر میں تھے، ہم دونوں جنبی ہو گئے۔ آپ نے تو نماز نہیں پڑھی لیکن میں نے زمین پر لوٹ پوٹ لیا، اور نماز پڑھ لی۔ پھر میں نے نبی کریم صلی اللہ علیہ وسلم سے اس کا ذکر کیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ تجھے بس اتنا ہی کافی تھا اور آپ نے اپنے دونوں ہاتھ زمین پر مارے پھر انہیں پھونکا اور دونوں سے چہرے اور پہنچوں کا مسح کیا۔' WHERE id = 335;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے حدیث بیان کی، کہا ہمیں عبداللہ نے خبر دی، کہا ہمیں عوف نے ابورجاء سے خبر دی، کہا کہ ہم سے کہا عمران بن حصین خزاعی نے کہ رسول اللہ صلی اللہ علیہ وسلم نے ایک آدمی کو دیکھا کہ الگ کھڑا ہوا ہے اور لوگوں کے ساتھ نماز میں شریک نہیں ہو رہا ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اے فلاں! تمہیں لوگوں کے ساتھ نماز پڑھنے سے کس چیز نے روک دیا۔ اس نے عرض کی یا رسول اللہ! مجھے غسل کی ضرورت ہو گئی اور پانی نہیں ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا پھر تم کو پاک مٹی سے تیمم کرنا ضروری تھا، بس وہ تمہارے لیے کافی ہوتا۔' WHERE id = 345;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہمیں امام مالک نے ابن شہاب کے حوالہ سے خبر دی، وہ سعید بن مسیب سے نقل کرتے ہیں، وہ ابوہریرہ رضی اللہ عنہ سے کہ ایک پوچھنے والے نے رسول اللہ صلی اللہ علیہ وسلم سے ایک کپڑے میں نماز پڑھنے کے متعلق پوچھا تو آپ صلی اللہ علیہ وسلم نے فرمایا ( کچھ برا نہیں ) بھلا کیا تم سب میں ہر شخص کے پاس دو کپڑے ہیں؟' WHERE id = 355;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ بن عقبہ نے بیان کیا، انہوں نے کہا کہ ہم سے سفیان نے بیان کیا، جو ابوالزناد سے نقل کرتے ہیں، وہ اعرج سے، وہ ابوہریرہ رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم نے دو طرح کی بیع و فروخت سے منع فرمایا۔ ایک تو چھونے کی بیع سے، دوسرے پھینکنے کی بیع سے اور اشتمال صماء سے ( جس کا بیان اوپر گزرا ) اور ایک کپڑے میں گوٹ مار کر بیٹھنے سے۔' WHERE id = 365;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبدالرحیم نے بیان کیا کہ کہا ہم سے یزید بن ہارون نے، کہا ہم کو حمید طویل نے خبر دی انس بن مالک رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم ( 5 ھ میں ) اپنے گھوڑے سے گر گئے تھے۔ جس سے آپ کی پنڈلی یا کندھا زخمی ہو گئے اور آپ نے ایک مہینے تک اپنی بیویوں کے پاس نہ جانے کی قسم کھائی۔ آپ اپنے بالاخانہ پر بیٹھ گئے۔ جس کے زینے کھجور کے تنوں سے بنائے گئے تھے۔ صحابہ رضی اللہ عنہم مزاج پرسی کو آئے۔ آپ نے انہیں بیٹھ کر نماز پڑھائی اور وہ کھڑے تھے۔ جب آپ نے سلام پھیرا تو فرمایا کہ امام اس لیے ہے کہ اس کی پیروی کی جائے۔ پس جب وہ تکبیر کہے تو تم بھی تکبیر کہو اور جب وہ رکوع میں جائے تو تم بھی رکوع میں جاؤ اور جب وہ سجدہ کرے تو تم بھی سجدہ کرو اور اگر کھڑے ہو کر تمہیں نماز پڑھائے تو تم بھی کھڑے ہو کر نماز پڑھو اور آپ انتیس دن بعد نیچے تشریف لائے، تو لوگوں نے کہا یا رسول اللہ! آپ نے تو ایک مہینہ کے لیے قسم کھائی تھی۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ مہینہ انتیس دن کا ہے۔' WHERE id = 375;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن نصر نے بیان کیا کہ کہا ہم سے ابواسامہ نے بیان کیا اعمش کے واسطہ سے، انہوں نے مسلم بن صبیح سے، انہوں نے مسروق بن اجدع سے، انہوں نے مغیرہ بن شعبہ سے، انہوں نے کہا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کو وضو کرایا۔ آپ صلی اللہ علیہ وسلم نے اپنے موزوں پر مسح کیا اور نماز پڑھی۔' WHERE id = 385;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے ہشام بن عبداللہ دستوائی نے، کہا ہم سے یحییٰ بن ابی کثیر نے محمد بن عبدالرحمٰن کے واسطہ سے، انہوں نے جابر بن عبداللہ سے، انہوں نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم اپنی سواری پر خواہ اس کا رخ کسی طرف ہو ( نفل ) نماز پڑھتے تھے لیکن جب فرض نماز پڑھنا چاہتے تو سواری سے اتر جاتے اور قبلہ کی طرف منہ کر کے نماز پڑھتے۔' WHERE id = 396;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے، کہا ہم سے امام زہری نے حمید بن عبدالرحمٰن سے، انہوں نے ابو سعید خدری سے کہ نبی کریم صلی اللہ علیہ وسلم نے مسجد کے قبلہ کی دیوار پر بلغم دیکھا تو آپ صلی اللہ علیہ وسلم نے اسے کنکری سے کھرچ ڈالا۔ پھر فرمایا کہ کوئی شخص سامنے یا دائیں طرف نہ تھوکے، البتہ بائیں طرف یا بائیں پاؤں کے نیچے تھوک لینا چاہیے۔ دوسری روایت میں زہری سے یوں ہے کہ انہوں نے حمید بن عبدالرحمٰن سے ابو سعید خدری کے واسطہ سے اسی طرح یہ حدیث سنی۔' WHERE id = 409;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، انہوں نے کہا ہم سے ابراہیم بن سعد نے ابن شہاب کے واسطہ سے بیان کیا، انہوں نے محمود بن ربیع سے انہوں نے عتبان بن مالک سے (جو نابینا تھے) کہ نبی کریم صلی اللہ علیہ وسلم ان کے گھر تشریف لائے۔ آپ صلی اللہ علیہ وسلم نے پوچھا کہ تم اپنے گھر میں کہاں پسند کرتے ہو کہ تمہارے لیے نماز پڑھوں۔ عتبان نے بیان کیا کہ میں نے ایک جگہ کی طرف اشارہ کیا۔ پھر نبی کریم صلی اللہ علیہ وسلم نے تکبیر کہی اور ہم نے آپ صلی اللہ علیہ وسلم کے پیچھے صف باندھی پھر آپ صلی اللہ علیہ وسلم نے دو رکعت نماز ( نفل ) پڑھائی۔' WHERE id = 419;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام بیکندی نے بیان کیا، انہوں نے کہا ہم کو عبدہ بن سلیمان نے خبر دی، انہوں نے ہشام بن عروہ سے، انہوں نے اپنے باپ عروہ بن زبیر سے، انہوں نے عائشہ رضی اللہ عنہا سے کہ ام سلمہ رضی اللہ عنہا نے نبی کریم صلی اللہ علیہ وسلم سے ایک گرجا کا ذکر کیا جس کو انہوں نے حبش کے ملک میں دیکھا اس کا نام ماریہ تھا۔ اس میں جو مورتیں دیکھی تھیں وہ بیان کیں۔ اس پر رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ یہ ایسے لوگ تھے کہ اگر ان میں کوئی نیک بندہ ( یا یہ فرمایا کہ ) نیک آدمی مر جاتا تو اس کی قبر پر مسجد بناتے اور اس میں یہ بت رکھتے۔ یہ لوگ اللہ کے نزدیک ساری مخلوقات سے بدتر ہیں۔' WHERE id = 429;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، انہوں نے کہا ہم سے یعقوب بن ابراہیم بن سعید نے بیان کیا، انہوں نے کہا مجھ سے میرے والد ابراہیم بن سعید نے صالح بن کیسان کے واسطے سے، ہم سے نافع نے، عبداللہ بن عمر رضی اللہ عنہما کے واسطہ سے خبر دی کہ نبی کریم صلی اللہ علیہ وسلم کے زمانہ میں مسجد نبوی کچی اینٹوں سے بنائی گئی تھی۔ اس کی چھت کھجور کی شاخوں کی تھی اور ستون اسی کی کڑیوں کے۔ ابوبکر رضی اللہ عنہ نے اس میں کسی قسم کی زیادتی نہیں کی۔ البتہ عمر رضی اللہ عنہ نے اسے بڑھایا اور اس کی تعمیر رسول اللہ صلی اللہ علیہ وسلم کی بنائی ہوئی بنیادوں کے مطابق کچی اینٹوں اور کھجوروں کی شاخوں سے کی اور اس کے ستون بھی کڑیوں ہی کے رکھے۔ پھر عثمان رضی اللہ عنہ نے اس کی عمارت کو بدل دیا اور اس میں بہت سی زیادتی کی۔ اس کی دیواریں منقش پتھروں اور گچھ سے بنائیں۔ اس کے ستون بھی منقش پتھروں سے بنوائے اور چھت ساگوان سے بنائی۔' WHERE id = 440;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، انہوں نے کہا ہم سے حماد بن زید نے بیان کیا، انہوں نے ثابت سے، انہوں نے ابورافع سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے کہ ایک حبشی مرد یا حبشی عورت مسجد نبوی میں جھاڑو دیا کرتی تھی۔ ایک دن اس کا انتقال ہو گیا تو رسول اللہ صلی اللہ علیہ وسلم نے اس کے متعلق دریافت فرمایا۔ لوگوں نے بتایا کہ وہ تو انتقال کر گئی۔ آپ صلی اللہ علیہ وسلم نے اس پر فرمایا کہ تم نے مجھے کیوں نہ بتایا، پھر آپ صلی اللہ علیہ وسلم قبر پر تشریف لائے اور اس پر نماز پڑھی۔' WHERE id = 451;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان محمد بن فضل اور قتیبہ بن سعید نے بیان کیا کہ ہم سے حماد بن زید نے ایوب سختیانی کے واسطہ سے، انہوں نے نافع سے، انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے کہ نبی کریم صلی اللہ علیہ وسلم جب مکہ تشریف لائے ( اور مکہ فتح ہوا ) تو آپ نے عثمان بن طلحہ رضی اللہ عنہ کو بلوایا۔ ( جو کعبہ کے متولی، چابی بردار تھے ) انہوں نے دروازہ کھولا تو نبی کریم صلی اللہ علیہ وسلم ، بلال، اسامہ بن زید اور عثمان بن طلحہ چاروں اندر تشریف لے گئے۔ پھر دروازہ بند کر دیا گیا اور وہاں تھوڑی دیر تک ٹھہر کر باہر آئے۔ ابن عمر رضی اللہ عنہما نے فرمایا کہ میں نے جلدی سے آگے بڑھ کر بلال سے پوچھا ( کہ نبی کریم صلی اللہ علیہ وسلم نے کعبہ کے اندر کیا کیا ) انہوں نے بتایا کہ نبی کریم صلی اللہ علیہ وسلم نے اندر نماز پڑھی تھی۔ میں نے پوچھا کس جگہ؟ کہا کہ دونوں ستونوں کے درمیان۔ عبداللہ بن عمر رضی اللہ عنہما نے فرمایا کہ یہ پوچھنا مجھے یاد نہ رہا کہ آپ نے کتنی رکعتیں پڑھی تھیں۔' WHERE id = 461;
UPDATE hadiths SET urdu = 'اور عاصم بن علی نے کہا، ہم سے عاصم بن محمد نے بیان کیا کہ میں نے اس حدیث کو اپنے باپ محمد بن زید سے سنا۔ لیکن مجھے حدیث یاد نہیں رہی تھی۔ تو میرے بھائی واقد نے اس کو درستی سے اپنے باپ سے روایت کر کے مجھے بتایا۔ وہ کہتے ہیں کہ عبداللہ بن عمرو بن عاص رضی اللہ عنہما سے رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ عبداللہ بن عمرو تمہارا کیا حال ہو گا جب تم برے لوگوں میں رہ جاؤ گے اس طرح ( یعنی آپ صلی اللہ علیہ وسلم نے ایک ہاتھ کی انگلیاں دوسرے ہاتھ میں کر کے دکھلائیں ) ۔' WHERE id = 472;
UPDATE hadiths SET urdu = 'اور عبداللہ بن عمر رضی اللہ عنہما نے نافع سے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم اس نالے میں اترا کرتے تھے جو وادی مرالظہران کے نشیب میں ہے۔ مدینہ کے مقابل جب کہ مقام صفراوات سے اترا جائے۔ نبی کریم صلی اللہ علیہ وسلم اس ڈھلوان کے بالکل نشیب میں قیام کرتے تھے۔ یہ راستے کے بائیں جانب پڑتا ہے جب کوئی شخص مکہ جا رہا ہو ( جس کو اب بطن مرو کہتے ہیں ) راستے اور رسول اللہ صلی اللہ علیہ وسلم کی منزل کے درمیان صرف ایک پتھر ہی کے مار کا فاصلہ ہوتا۔' WHERE id = 482;
UPDATE hadiths SET urdu = 'ہم سے محمد بن حاتم بن بزیع نے بیان کیا، کہا کہ ہم سے شاذان بن عامر نے شعبہ بن حجاج کے واسطہ سے بیان کیا، انہوں نے عطاء بن ابی میمونہ سے، انہوں نے کہا کہ میں نے انس بن مالک رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم جب رفع حاجت کے لیے نکلتے تو میں اور ایک اور لڑکا آپ صلی اللہ علیہ وسلم کے پیچھے پیچھے جاتے۔ ہمارے ساتھ عکازہ ( ڈنڈا جس کے نیچے لوہے کا پھل لگا ہوا ہو ) یا چھڑی یا عنزہ ہوتا۔ اور ہمارے ساتھ ایک چھاگل بھی ہوتا تھا۔ جب نبی کریم صلی اللہ علیہ وسلم حاجت سے فارغ ہو جاتے تو ہم آپ صلی اللہ علیہ وسلم کو وہ چھاگل دے دیتے تھے۔' WHERE id = 492;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تینسی نے بیان کیا، انہوں نے کہا ہم سے امام مالک نے عمر بن عبیداللہ کے غلام ابونضر سالم بن ابی امیہ سے خبر دی۔ انہوں نے بسر بن سعید سے کہ زید بن خالد نے انہیں ابوجہیم عبداللہ انصاری رضی اللہ عنہ کی خدمت میں ان سے یہ بات پوچھنے کے لیے بھیجا کہ انہوں نے نماز پڑھنے والے کے سامنے سے گزرنے والے کے متعلق نبی کریم صلی اللہ علیہ وسلم سے کیا سنا ہے۔ ابوجہیم نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا تھا کہ اگر نمازی کے سامنے سے گزرنے والا جانتا کہ اس کا کتنا بڑا گناہ ہے تو اس کے سامنے سے گزرنے پر چالیس تک وہیں کھڑے رہنے کو ترجیح دیتا۔ ابوالنضر نے کہا کہ مجھے یاد نہیں کہ بسر بن سعید نے چالیس دن کہا یا مہینہ یا سال۔' WHERE id = 502;
UPDATE hadiths SET urdu = 'ہم سے احمد بن اسحاق سرماری نے بیان کیا، انہوں نے کہا کہ ہم سے اسرائیل نے ابواسحاق کے واسطہ سے بیان کیا۔ انہوں نے عمرو بن میمون سے، انہوں نے عبداللہ بن مسعود رضی اللہ عنہ سے، کہا کہ رسول اللہ صلی اللہ علیہ وسلم کعبہ کے پاس کھڑے نماز پڑھ رہے تھے۔ قریش اپنی مجلس میں ( قریب ہی ) بیٹھے ہوئے تھے۔ اتنے میں ان میں سے ایک قریشی بولا اس ریاکار کو نہیں دیکھتے؟ کیا کوئی ہے جو فلاں قبیلہ کے ذبح کئے ہوئے اونٹ کا گوبر، خون اور اوجھڑی اٹھا لائے۔ پھر یہاں انتظار کرے۔ جب یہ ( نبی کریم صلی اللہ علیہ وسلم ) سجدہ میں جائے تو گردن پر رکھ دے ( چنانچہ اس کام کو انجام دینے کے لیے ) ان میں سے سب سے زیادہ بدبخت شخص اٹھا اور جب آپ صلی اللہ علیہ وسلم سجدہ میں گئے تو اس نے آپ صلی اللہ علیہ وسلم کی گردن مبارک پر یہ غلاظتیں ڈال دیں۔ نبی کریم صلی اللہ علیہ وسلم سجدہ ہی کی حالت میں سر رکھے رہے۔ مشرکین ( یہ دیکھ کر ) ہنسے اور مارے ہنسی کے ایک دوسرے پر لوٹ پوٹ ہونے لگے۔ ایک شخص ( غالباً ابن مسعود رضی اللہ عنہ ) فاطمہ رضی اللہ عنہا کے پاس آئے۔ وہ ابھی بچہ تھیں۔ آپ رضی اللہ عنہا دوڑتی ہوئی آئیں۔ نبی کریم صلی اللہ علیہ وسلم اب بھی سجدہ ہی میں تھے۔ پھر ( فاطمہ رضی اللہ عنہا نے ) ان غلاظتوں کو آپ صلی اللہ علیہ وسلم کے اوپر سے ہٹایا اور مشرکین کو برا بھلا کہا۔ نبی کریم صلی اللہ علیہ وسلم نے نماز پوری کر کے فرمایا ”یا اللہ قریش پر عذاب نازل کر۔ یا اللہ قریش پر عذاب نازل کر۔ یا اللہ قریش پر عذاب نازل کر۔“ پھر نام لے کر کہا یا اللہ! عمرو بن ہشام، عتبہ بن ربیعہ، شیبہ بن ربیعہ، ولید بن عتبہ، امیہ بن خلف، عقبہ بن ابی معیط اور عمارہ ابن ولید کو ہلاک کر۔ عبداللہ بن مسعود رضی اللہ عنہ نے کہا، اللہ کی قسم! میں نے ان سب کو بدر کی لڑائی میں مقتول پایا۔ پھر انہیں گھسیٹ کر بدر کے کنویں میں پھینک دیا گیا۔ اس کے بعد رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ کنویں والے اللہ کی رحمت سے دور کر دئیے گئے۔' WHERE id = 512;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا ہم سے یزید بن ابراہیم نے، انہوں نے کہا کہ ہم سے قتادہ نے انس بن مالک رضی اللہ عنہ سے بیان کیا، آپ نبی کریم صلی اللہ علیہ وسلم سے روایت کرتے تھے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ سجدہ کرنے میں اعتدال رکھو ( سیدھی طرح پر کرو ) اور کوئی شخص تم میں سے اپنے بازوؤں کو کتے کی طرح نہ پھیلائے۔ جب کسی کو تھوکنا ہی ہو تو سامنے یا داہنی طرف نہ تھوکے، کیونکہ وہ نماز میں اپنے رب سے پوشیدہ باتیں کرتا رہتا ہے اور سعید نے قتادہ رضی اللہ عنہ سے روایت کر کے بیان کیا ہے کہ آگے یا سامنے نہ تھوکے البتہ بائیں طرف پاؤں کے نیچے تھوک سکتا ہے اور شعبہ نے کہا کہ اپنے سامنے اور دائیں جانب نہ تھوکے، بلکہ بائیں طرف یا پاؤں کے نیچے تھوک سکتا ہے۔ اور حمید نے انس بن مالک رضی اللہ عنہ سے وہ نبی کریم صلی اللہ علیہ وسلم سے روایت کرتے ہیں کہ قبلہ کی طرف نہ تھوکے اور نہ دائیں طرف البتہ بائیں طرف یا پاؤں کے نیچے تھوک سکتا ہے۔' WHERE id = 523;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم فضل بن دکین نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے ابن شہاب زہری سے بیان کیا، انہوں نے عروہ سے، انہوں نے عائشہ صدیقہ رضی اللہ عنہا سے، آپ نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم جب عصر کی نماز پڑھتے تو سورج ابھی میرے حجرے میں جھانکتا رہتا تھا۔ ابھی سایہ نہ پھیلا ہوتا تھا۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) کہتے ہیں کہ امام مالک اور یحییٰ بن سعید، شعیب رحمہم اللہ اور ابن ابی حفصہ کے روایتوں میں ( زہری سے ) «والشمس قبل أن تظهر‏» کے الفاظ ہیں، ( جن کا مطلب یہ ہے کہ دھوپ ابھی اوپر نہ چڑھی ہوتی ) ۔' WHERE id = 535;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، انہوں نے کہا ہم سے شیبان نے یحییٰ بن ابی کثیر سے، انہوں نے ابوسلمہ سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اگر عصر کی نماز کی ایک رکعت بھی کوئی شخص سورج غروب ہونے سے پہلے پا سکا تو پوری نماز پڑھے ( اس کی نماز ادا ہوئی نہ قضاء ) اسی طرح اگر سورج طلوع ہونے سے پہلے فجر کی نماز کی ایک رکعت بھی پا سکے تو پوری نماز پڑھے۔' WHERE id = 545;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، انہوں نے کہا ہم سے لیث بن سعد نے عقیل کے واسطے سے بیان کیا، انہوں نے ابن شہاب سے، انہوں نے عروہ سے کہ عائشہ رضی اللہ عنہا نے انہیں خبر دی کہ ایک رات رسول اللہ صلی اللہ علیہ وسلم نے عشاء کی نماز دیر سے پڑھی۔ یہ اسلام کے پھیلنے سے پہلے کا واقعہ ہے۔ آپ صلی اللہ علیہ وسلم اس وقت تک باہر تشریف نہیں لائے جب تک عمر رضی اللہ عنہ نے یہ نہ فرمایا کہ عورتیں اور بچے سو گئے۔ پس آپ صلی اللہ علیہ وسلم تشریف لائے اور فرمایا کہ تمہارے علاوہ دنیا میں کوئی بھی انسان اس نماز کا انتظار نہیں کرتا۔' WHERE id = 555;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، انہوں نے کہا ہمیں لیث نے خبر دی، انہوں نے عقیل بن خالد سے، انہوں نے ابن شہاب سے، انہوں نے کہا کہ مجھے عروہ بن زبیر رضی اللہ عنہ نے خبر دی کہ ام المؤمنین عائشہ رضی اللہ عنہا نے انہیں خبر دی کہ مسلمان عورتیں رسول اللہ صلی اللہ علیہ وسلم کے ساتھ نماز فجر پڑھنے چادروں میں لپٹ کر آتی تھیں۔ پھر نماز سے فارغ ہو کر جب اپنے گھروں کو واپس ہوتیں تو انہیں اندھیرے کی وجہ سے کوئی شخص پہچان نہیں سکتا تھا۔' WHERE id = 566;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم فضل بن دکین نے بیان کیا، کہ کہا ہم سے عبدالواحد بن ایمن نے بیان کیا، کہا کہ مجھ سے میرے باپ ایمن نے حدیث بیان کی کہ انہوں نے عائشہ رضی اللہ عنہا سے سنا، آپ نے فرمایا کہ اللہ کی قسم! جس نے رسول اللہ صلی اللہ علیہ وسلم کو اپنے یہاں بلا لیا۔ آپ صلی اللہ علیہ وسلم نے عصر کے بعد کی دو رکعات کو کبھی ترک نہیں فرمایا، یہاں تک کہ آپ صلی اللہ علیہ وسلم ، اللہ پاک سے جا ملے۔ اور آپ صلی اللہ علیہ وسلم کو وفات سے پہلے نماز پڑھنے میں بڑی دشواری پیش آتی تھی۔ پھر اکثر آپ صلی اللہ علیہ وسلم بیٹھ کر نماز ادا فرمایا کرتے تھے۔ اگرچہ نبی کریم صلی اللہ علیہ وسلم انہیں پوری پابندی کے ساتھ پڑھتے تھے لیکن اس خوف سے کہ کہیں ( صحابہ بھی پڑھنے لگیں اور اس طرح ) امت کو گراں باری ہو، انہیں آپ صلی اللہ علیہ وسلم مسجد میں نہیں پڑھتے تھے۔ آپ صلی اللہ علیہ وسلم کو اپنی امت کا ہلکا رکھنا پسند تھا۔' WHERE id = 577;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن صباح نے بیان کیا، کہا ہم سے ابوعلی عبیداللہ حنفی نے، کہا ہم سے قرہ بن خالد سدوسی نے، انہوں نے کہا کہ ایک دن حسن بصری رحمہ اللہ نے بڑی دیر کی۔ اور ہم آپ کا انتظار کرتے رہے۔ جب ان کے اٹھنے کا وقت قریب ہو گیا تو آپ آئے اور ( بطور معذرت ) فرمایا کہ میرے ان پڑوسیوں نے مجھے بلا لیا تھا ( اس لیے دیر ہو گئی ) پھر بتلایا کہ انس بن مالک رضی اللہ عنہ نے کہا تھا کہ ہم ایک رات نبی کریم صلی اللہ علیہ وسلم کا انتظار کرتے رہے۔ تقریباً آدھی رات ہو گئی تو آپ صلی اللہ علیہ وسلم تشریف لائے، پھر ہمیں نماز پڑھائی۔ اس کے بعد خطبہ دیا۔ پس آپ نے فرمایا کہ دوسروں نے نماز پڑھ لی اور سو گئے۔ لیکن تم لوگ جب تک نماز کے انتظار میں رہے ہو گویا نماز ہی کی حالت میں رہے ہو۔ امام حسن بصری رحمہ اللہ نے فرمایا کہ اگر لوگ کسی خیر کے انتظار میں بیٹھے رہیں تو وہ بھی خیر کی حالت ہی میں ہیں۔ قرہ بن خالد نے کہا کہ حسن کا یہ قول بھی انس رضی اللہ عنہ کی حدیث کا ہے جو انہوں نے نبی کریم صلی اللہ علیہ وسلم سے روایت کی ہے۔' WHERE id = 587;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے اسماعیل بن جعفر انصاری نے حمید سے بیان کیا، انہوں نے انس رضی اللہ عنہ سے انہوں نے نبی کریم صلی اللہ علیہ وسلم سے کہ جب نبی کریم صلی اللہ علیہ وسلم ہمیں ساتھ لے کر کہیں جہاد کے لیے تشریف لے جاتے، تو فوراً ہی حملہ نہیں کرتے تھے۔ صبح ہوتی اور پھر آپ انتظار کرتے اگر اذان کی آواز سن لیتے تو حملہ کا ارادہ ترک کر دیتے اور اگر اذان کی آواز نہ سنائی دیتی تو حملہ کرتے تھے۔ انس رضی اللہ عنہ نے کہا کہ ہم خیبر کی طرف گئے اور رات کے وقت وہاں پہنچے۔ صبح کے وقت جب اذان کی آواز نہیں سنائی دی تو آپ اپنی سواری پر بیٹھ گئے اور میں ابوطلحہ رضی اللہ عنہ کے پیچھے بیٹھ گیا۔ چلنے میں میرے قدم نبی کریم صلی اللہ علیہ وسلم کے قدم مبارک سے چھو چھو جاتے تھے۔ انس رضی اللہ عنہ نے کہا کہ خبیر کے لوگ اپنے ٹوکروں اور کدالوں کو لیے ہوئے ( اپنے کام کاج کو ) باہر نکلے۔ تو انہوں نے رسول اللہ صلی اللہ علیہ وسلم کو دیکھا، اور چلا اٹھے کہ ” «محمد والله محمد» ( صلی اللہ علیہ وسلم ) پوری فوج سمیت آ گئے۔“ انس رضی اللہ عنہ نے کہا کہ جب نبی کریم صلی اللہ علیہ وسلم نے انہیں دیکھا تو آپ نے فرمایا «الله أكبر،‏‏‏‏ ‏‏‏‏ الله أكبر» خیبر پر خرابی آ گئی۔ بیشک جب ہم کسی قوم کے میدان میں اتر جائیں تو ڈرائے ہوئے لوگوں کی صبح بری ہو گی۔' WHERE id = 597;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، کہا کہ ہمیں امام مالک نے عبداللہ بن دینار سے خبر دی، انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، دیکھو بلال رضی اللہ عنہ رات رہے میں اذان دیتے ہیں، اس لیے تم لوگ ( سحری ) کھا پی سکتے ہو۔ جب تک ابن ام مکتوم اذان نہ دیں۔' WHERE id = 607;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا کہ ہم سے یحییٰ بن سعید قطان نے عبیداللہ بن عمر عمری سے بیان کیا، انہوں نے کہا کہ مجھ سے نافع نے بیان کیا کہ عبداللہ بن عمر رضی اللہ عنہما نے ایک سرد رات میں مقام ضجنان پر اذان دی پھر فرمایا «ألا صلوا في الرحال‏» کہ لوگو! اپنے اپنے ٹھکانوں میں نماز پڑھ لو اور ہمیں آپ نے بتلایا کہ نبی کریم صلی اللہ علیہ وسلم مؤذن سے اذان کے لیے فرماتے اور یہ بھی فرماتے کہ مؤذن اذان کے بعد کہہ دے کہ لوگو! اپنے ٹھکانوں میں نماز پڑھ لو۔ یہ حکم سفر کی حالت میں یا سردی یا برسات کی راتوں میں تھا۔' WHERE id = 618;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر عبداللہ بن عمرو نے بیان کیا، کہا کہ ہم سے عبدالوارث بن سعید نے بیان کیا، کہا کہ ہم سے عبدالعزیز بن صہیب نے انس رضی اللہ عنہ سے بیان کیا، انہوں نے کہا کہ نماز کے لیے تکبیر ہو چکی تھی اور نبی کریم صلی اللہ علیہ وسلم کسی شخص سے مسجد کے ایک گوشے میں چپکے چپکے کان میں باتیں کر رہے تھے۔ پھر آپ صلی اللہ علیہ وسلم نماز کے لیے جب تشریف لائے تو لوگ سو رہے تھے۔' WHERE id = 628;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے امام مالک سے بیان کیا، انہوں نے ابوبکر بن عبدالرحمٰن کے غلام سمی نامی سے، انہوں نے ابوصالح سمان سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ایک شخص کہیں جا رہا تھا۔ راستے میں اس نے کانٹوں کی بھری ہوئی ایک ٹہنی دیکھی، پس اسے راستے سے دور کر دیا۔ اللہ تعالیٰ ( صرف اسی بات پر ) راضی ہو گیا اور اس کی بخشش کر دی۔' WHERE id = 638;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا کہ ہمیں ہشام بن یوسف نے خبر دی معمر سے، انہوں نے زہری سے، کہا کہ مجھے عبیداللہ بن عبداللہ بن عتبہ بن مسعود نے خبر دی کہ عائشہ رضی اللہ عنہا نے فرمایا کہ جب نبی کریم صلی اللہ علیہ وسلم بیمار ہو گئے اور تکلیف زیادہ بڑھ گئی تو آپ صلی اللہ علیہ وسلم نے اپنی بیویوں سے اس کی اجازت لی کہ بیماری کے دن میرے گھر میں گزاریں۔ انہوں نے اس کی آپ صلی اللہ علیہ وسلم کو اجازت دے دی۔ پھر آپ صلی اللہ علیہ وسلم باہر تشریف لے گئے۔ آپ صلی اللہ علیہ وسلم کے قدم زمین پر لکیر کر رہے تھے۔ آپ صلی اللہ علیہ وسلم اس وقت عباس رضی اللہ عنہ اور ایک اور شخص کے بیچ میں تھے ( یعنی دونوں حضرات کا سہارا لیے ہوئے تھے ) عبیداللہ راوی نے بیان کیا کہ میں نے یہ حدیث عائشہ رضی اللہ عنہا کی عبداللہ بن عباس رضی اللہ عنہما سے بیان کی، تو آپ نے فرمایا اس شخص کو بھی جانتے ہو، جن کا نام عائشہ رضی اللہ عنہا نے نہیں لیا۔ میں نے کہا کہ نہیں! آپ نے فرمایا کہ وہ دوسرے آدمی علی رضی اللہ عنہ تھے۔' WHERE id = 648;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، کہا کہ ہم سے ابراہیم بن سعد نے صالح بن کیسان سے بیان کیا، انہوں نے ابن شہاب سے، انہوں نے کہا کہ مجھ کو جعفر بن عمرو بن امیہ نے خبر دی کہ ان کے باپ عمرو بن امیہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو دیکھا کہ آپ صلی اللہ علیہ وسلم بکری کی ران کا گوشت کاٹ کاٹ کر کھا رہے تھے۔ اتنے میں آپ صلی اللہ علیہ وسلم نماز کے لیے بلائے گئے آپ صلی اللہ علیہ وسلم کھڑے ہوئے اور چھری ڈال دی، پھر آپ صلی اللہ علیہ وسلم نے نماز پڑھائی اور وضو نہیں کیا۔' WHERE id = 658;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا کہ ہمیں حماد بن زید نے خبر دی ایوب سختیانی سے، انہوں نے ابوقلابہ سے، انہوں نے مالک بن حویرث رضی اللہ عنہ سے، انہوں نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کی خدمت میں اپنے ملک سے حاضر ہوئے۔ ہم سب ہم عمر نوجوان تھے۔ تقریباً بیس راتیں ہم آپ کی خدمت میں ٹھہرے رہے۔ آپ صلی اللہ علیہ وسلم بڑے ہی رحم دل تھے۔ آپ صلی اللہ علیہ وسلم نے ( ہماری غربت کا حال دیکھ کر ) فرمایا کہ جب تم لوگ اپنے گھروں کو جاؤ تو اپنے قبیلہ والوں کو دین کی باتیں بتانا اور ان سے نماز پڑھنے کے لیے کہنا کہ فلاں نماز فلاں وقت اور فلاں نماز فلاں وقت پڑھیں۔ اور جب نماز کا وقت ہو جائے تو کوئی ایک اذان دے اور جو عمر میں بڑا ہو وہ امامت کرائے۔' WHERE id = 668;
UPDATE hadiths SET urdu = 'امام بخاری رحمہ اللہ نے کہا کہ ہم سے محمد بن یوسف فریابی نے کہا کہ ہم سے امام اوزاعی نے بیان کیا، کہا ہم سے امام زہری نے حمید بن عبدالرحمٰن سے نقل کیا۔ انہوں نے عبیداللہ بن عدی بن خیار سے کہ وہ خود عثمان غنی رضی اللہ عنہ کے پاس گئے۔ جب کہ باغیوں نے ان کو گھیر رکھا تھا۔ انہوں نے کہا کہ آپ ہی عام مسلمانوں کے امام ہیں مگر آپ پر جو مصیبت ہے وہ آپ کو معلوم ہے۔ ان حالات میں باغیوں کا مقررہ امام نماز پڑھا رہا ہے۔ ہم ڈرتے ہیں کہ اس کے پیچھے نماز پڑھ کر گنہگار نہ ہو جائیں۔ عثمان رضی اللہ عنہ نے جواب دیا نماز تو جو لوگ کام کرتے ہیں ان کاموں میں سب سے بہترین کام ہے۔ تو وہ جب اچھا کام کریں تم بھی اس کے ساتھ مل کر اچھا کام کرو اور جب وہ برا کام کریں تو تم ان کی برائی سے الگ رہو اور محمد بن یزید زبیدی نے کہا کہ امام زہری نے فرمایا کہ ہم تو یہ سمجھتے ہیں کہ ہیجڑے کے پیچھے نماز نہ پڑھیں۔ مگر ایسی ہی لاچاری ہو تو اور بات ہے جس کے بغیر کوئی چارہ نہ ہو۔' WHERE id = 679;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، کہا کہ ہم سے محارب بن دثار نے بیان کیا، کہا کہ میں نے جابر بن عبداللہ انصاری سے سنا، آپ نے بتلایا کہ ایک شخص پانی اٹھانے والا دو اونٹ لیے ہوئے آیا، رات تاریک ہو چکی تھی۔ اس نے معاذ رضی اللہ عنہ کو نماز پڑھاتے ہوئے پایا۔ اس لیے اپنے اونٹوں کو بٹھا کر ( نماز میں شریک ہونے کے لیے ) معاذ رضی اللہ عنہ کی طرف بڑھا۔ معاذ رضی اللہ عنہ نے نماز میں سورۃ البقرہ یا سورۃ نساء شروع کی۔ چنانچہ وہ شخص نیت توڑ کر چل دیا۔ پھر اسے معلوم ہوا کہ معاذ رضی اللہ عنہ نے مجھ کو برا بھلا کہا ہے۔ اس لیے وہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور معاذ کی شکایت کی، نبی کریم صلی اللہ علیہ وسلم نے اس سے فرمایا، معاذ! کیا تم لوگوں کو فتنہ میں ڈالتے ہو۔ آپ صلی اللہ علیہ وسلم نے تین مرتبہ ( «فتان» یا «فاتن» ) فرمایا: «سبح اسم ربك،‏‏‏‏ ‏‏‏‏ والشمس وضحاها،‏‏‏‏ ‏‏‏‏ والليل إذا يغشى» ( سورتیں ) تم نے کیوں نہ پڑھیں، کیونکہ تمہارے پیچھے بوڑھے، کمزور اور حاجت مند نماز پڑھتے ہیں۔ شعبہ نے کہا کہ میرا خیال ہے کہ یہ آخری جملہ ( کیونکہ تمہارے پیچھے الخ ) حدیث میں داخل ہے۔ شعبہ کے ساتھ اس کی متابعت سعید بن مسروق، مسعر اور شیبانی نے کی ہے اور عمرو بن دینار، عبیداللہ بن مقسم اور ابوالزبیر نے بھی اس حدیث کو جابر کے واسطہ سے بیان کیا ہے کہ معاذ نے عشاء میں سورۃ البقرہ پڑھی تھی اور شعبہ کے ساتھ اس روایت کی متابعت اعمش نے محارب کے واسطہ سے کی ہے۔' WHERE id = 689;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید ہشام بن عبدالملک نے بیان کیا، کہا کہ ہم سے شعبہ نے سعد بن ابراہیم سے بیان کیا، وہ ابوسلمہ بن عبدالرحمٰن سے، وہ ابوہریرہ رضی اللہ عنہ سے، آپ نے بتلایا کہ نبی کریم صلی اللہ علیہ وسلم نے ( ایک مرتبہ ) ظہر کی صرف دو ہی رکعتیں پڑھیں ( اور بھول سے سلام پھیر دیا ) پھر کہا گیا کہ آپ نے صرف دو ہی رکعتیں پڑھی ہیں۔ پس آپ صلی اللہ علیہ وسلم نے دو رکعتیں اور پڑھیں پھر سلام پھیرا۔ پھر دو سجدے کئے۔' WHERE id = 699;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، ان سے سفیان بن عیینہ نے بیان کیا، وہ اسحٰق بن عبداللہ بن ابی طلحہ سے وہ انس بن مالک رضی اللہ عنہ سے انہوں نے بتلایا کہ میں نے اور ایک یتیم لڑکے ( ضمیرہ بن ابی ضمیرہ ) نے جو ہمارے گھر میں موجود تھا، نبی کریم صلی اللہ علیہ وسلم کے پیچھے نماز پڑھی اور میری والدہ ام سلیم ہمارے پیچھے تھیں۔' WHERE id = 710;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن شاہین واسطی نے بیان کیا، کہا کہ ہم سے خالد بن عبداللہ طحان نے بیان کیا خالد حذاء سے، انہوں نے ابوقلابہ سے کہ انہوں نے مالک بن حویرث صحابی کو دیکھا کہ جب وہ نماز شروع کرتے تو تکبیر تحریمہ کے ساتھ رفع یدین کرتے، پھر جب رکوع میں جاتے اس وقت بھی رفع یدین کرتے اور جب رکوع سے سر اٹھاتے تب بھی کرتے اور انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم بھی اسی طرح کیا کرتے تھے۔' WHERE id = 720;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، کہا کہ ہمیں ابواسحاق عمرو بن عبداللہ سبیعی نے خبر دی، کہا کہ میں نے عبداللہ بن یزید رضی اللہ عنہ سے سنا کہ آپ خطبہ دے رہے تھے۔ آپ نے بیان کیا کہ ہم سے براء بن عازب رضی اللہ عنہ نے بیان کیا اور وہ جھوٹے نہیں تھے کہ جب وہ ( صحابہ ) نبی کریم صلی اللہ علیہ وسلم کے ساتھ نماز پڑھتے تو نبی کریم صلی اللہ علیہ وسلم کے رکوع سے سر اٹھانے کے بعد اس وقت تک کھڑے رہتے جب تک دیکھتے کہ آپ صلی اللہ علیہ وسلم سجدہ میں چلے گئے ہیں ( اس وقت وہ بھی سجدے میں جاتے ) ۔' WHERE id = 730;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا کہ ہم سے یحییٰ بن سعید قطان نے عبیداللہ عمری سے بیان کیا، کہا کہ مجھ سے سعید بن ابی سعید مقبری نے اپنے باپ ابوسعید مقبری سے بیان کیا، انہوں نے ابوہریرہ رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم مسجد میں تشریف لائے اس کے بعد ایک اور شخص آیا۔ اس نے نماز پڑھی، پھر نبی کریم صلی اللہ علیہ وسلم کو سلام کیا۔ آپ نے سلام کا جواب دے کر فرمایا کہ واپس جاؤ اور پھر نماز پڑھ، کیونکہ تو نے نماز نہیں پڑھی۔ وہ شخص واپس گیا اور پہلے کی طرح نماز پڑھی اور پھر آ کر سلام کیا۔ لیکن آپ نے اس مرتبہ بھی یہی فرمایا کہ واپس جا اور دوبارہ نماز پڑھ، کیونکہ تو نے نماز نہیں پڑھی۔ آپ نے اس طرح تین مرتبہ کیا۔ آخر اس شخص نے کہا کہ اس ذات کی قسم! جس نے آپ کو حق کے ساتھ مبعوث کیا ہے۔ میں اس کے علاوہ اور کوئی اچھا طریقہ نہیں جانتا، اس لیے آپ مجھے نماز سکھا دیجئیے۔ آپ نے فرمایا کہ جب نماز کے لیے کھڑا ہو تو پہلے تکبیر تحریمہ کہہ۔ پھر آسانی کے ساتھ جتنا قرآن تجھ کو یاد ہو اس کی تلاوت کر۔ اس کے بعد رکوع کر، اچھی طرح سے رکوع ہو لے تو پھر سر اٹھا کر پوری طرح کھڑا ہو جا۔ اس کے بعد سجدہ کر پورے اطمینان کے ساتھ۔ پھر سر اٹھا اور اچھی طرح بیٹھ جا۔ اسی طرح اپنی تمام نماز پوری کر۔' WHERE id = 740;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید ہشام بن عبدالملک نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا عدی بن ثابت سے، انہوں نے بیان کیا کہ میں نے براء بن عازب سے سنا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا۔ آپ صلی اللہ علیہ وسلم سفر میں تھے کہ عشاء کی دو پہلی رکعات میں سے کسی ایک رکعت میں آپ صلی اللہ علیہ وسلم نے «والتين والزيتون‏» پڑھی۔' WHERE id = 750;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا کہ ہم سے جریر بن عبدالحمید نے اعمش سے بیان کیا، وہ عمارہ بن عمیر سے، وہ ابومعمر عبداللہ بن مخبرہ سے، انہوں نے بیان کیا کہ ہم نے خباب بن ارت رضی اللہ عنہ سے کہا کہ کیا رسول اللہ صلی اللہ علیہ وسلم ظہر اور عصر میں قرآن مجید پڑھتے تھے؟ انہوں نے جواب دیا کہ ہاں! ہم نے پوچھا کہ آپ کو معلوم کس طرح ہوتا تھا۔ انہوں نے بتایا کہ آپ صلی اللہ علیہ وسلم کی ریش مبارک کے ہلنے سے۔' WHERE id = 761;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن عون نے بیان کیا، کہا کہ ہمیں ہشیم بن بشیر نے ابوبشر حفص بن ابی وحشیہ سے خبر دی، انہوں نے عکرمہ سے، انہوں نے بیان کیا کہ میں نے ایک شخص کو مقام ابراہیم میں ( نماز پڑھتے ہوئے ) دیکھا کہ ہر جھکنے اور اٹھنے پر وہ تکبیر کہتا تھا۔ اسی طرح کھڑے ہوتے وقت اور بیٹھتے وقت بھی۔ میں نے ابن عباس رضی اللہ عنہما کو اس کی اطلاع دی۔ آپ نے فرمایا، ارے تیری ماں مرے! کیا یہ رسول اللہ صلی اللہ علیہ وسلم کی سی نماز نہیں ہے۔' WHERE id = 771;
UPDATE hadiths SET urdu = 'ہم سے معاذ بن فضالہ نے بیان کیا، انہوں نے ہشام دستوائی سے، انہوں نے یحییٰ بن ابی کثیر سے، انہوں نے ابوسلمہ سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے، انہوں نے کہا کہ لو میں تمہیں نبی کریم صلی اللہ علیہ وسلم کی نماز کے قریب قریب کر دوں گا۔ چنانچہ ابوہریرہ رضی اللہ عنہ، ظہر، عشاء اور صبح کی آخری رکعات میں قنوت پڑھا کرتے تھے۔ «سمع الله لمن حمده» کے بعد۔ یعنی مومنین کے حق میں دعا کرتے اور کفار پر لعنت بھیجتے۔' WHERE id = 781;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا کہ مجھ سے بکر بن مضر نے جعفر بن ربیعہ سے بیان کیا، انہوں نے عبدالرحمٰن بن ہرمز سے، انہوں نے عبداللہ بن مالک بن بحینہ سے کہ نبی کریم صلی اللہ علیہ وسلم جب نماز پڑھتے سجدے میں اپنے دونوں بازوؤں کو اس قدر پھیلا دیتے کہ بغل کی سفیدی ظاہر ہو جاتی تھی۔ لیث بن سعد نے بیان کیا کہ مجھ سے بھی جعفر بن ربیعہ نے اسی طرح حدیث بیان کی۔' WHERE id = 791;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا کہ ہم سے یحییٰ بن سعید قطان نے، سفیان ثوری سے، انہوں نے کہا کہ مجھ سے منصور بن معتمر نے مسلم بن صبیح سے بیان کیا، انہوں نے مسروق سے، ان سے عائشہ صدیقہ رضی اللہ عنہا نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم سجدہ اور رکوع میں اکثر یہ پڑھا کرتے تھے۔ «سبحانك اللهم ربنا وبحمدك،‏‏‏‏ اللهم اغفر لي» ( اس دعا کو پڑھ کر ) آپ قرآن کے حکم پر عمل کرتے تھے۔' WHERE id = 801;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا کہ شعیب نے ہمیں خبر دی، انہوں نے زہری سے خبر دی، انہوں نے کہا کہ مجھ سے عبدالرحمٰن بن ہرمز نے بیان کیا جو مولی بن عبدالمطلب (یا مولی ربیعہ بن حارث) تھے، کہ عبداللہ بن بحینہ رضی اللہ عنہ جو صحابی رسول اور بنی عبد مناف کے حلیف قبیلہ ازدشنوہ سے تعلق رکھتے تھے، نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے انہیں ظہر کی نماز پڑھائی اور دو رکعتوں پر بیٹھنے کے بجائے کھڑے ہو گئے، چنانچہ سارے لوگ بھی ان کے ساتھ کھڑے ہو گئے، جب نماز ختم ہونے والی تھی اور لوگ آپ صلی اللہ علیہ وسلم کے سلام پھیرنے کا انتظار کر رہے تھے تو آپ صلی اللہ علیہ وسلم نے «الله أكبر‏» کہا اور سلام پھیرنے سے پہلے دو سجدے کئے، پھر سلام پھیرا۔' WHERE id = 812;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، انہوں نے کہا کہ ہم سے سفیان بن عیینہ نے بیان کیا، انہوں نے کہا کہ ہم سے عمرو بن دینار نے بیان کیا، کہا کہ مجھے ابو معبد نے ابن عباس رضی اللہ عنہما سے خبر دی کہ آپ نے فرمایا کہ میں نبی کریم صلی اللہ علیہ وسلم کی نماز ختم ہونے کو تکبیر ( «الله اكبر» ) کی وجہ سے سمجھ جاتا تھا۔ علی بن مدینی نے کہا کہ ہم سے سفیان نے عمرو کے حوالے سے بیان کیا کہ ابومعبد ابن عباس کے غلاموں میں سب سے زیادہ قابل اعتماد تھے۔ علی بن مدینی نے بتایا کہ ان کا نام نافذ تھا۔' WHERE id = 823;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، کہا کہ ہم سے ابوعاصم ضحاک بن مخلد نے بیان کیا، کہا کہ ہمیں ابن جریج نے خبر دی کہا کہ مجھے عطاء بن ابی رباح نے خبر دی کہا کہ میں نے جابر بن عبداللہ انصاری رضی اللہ عنہما سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جو شخص یہ درخت کھائے ( آپ کی مراد لہسن سے تھی ) تو وہ ہماری مسجد میں نہ آئے عطاء نے کہا میں نے جابر سے پوچھا کہ آپ کی مراد اس سے کیا تھی۔ انہوں نے جواب دیا کہ آپ کی مراد صرف کچے لہسن سے تھی۔ مخلد بن یزید نے ابن جریج کے واسطہ سے ( الانیہ کے بجائے ) الانتنہ نقل کیا ہے ( یعنی آپ صلی اللہ علیہ وسلم کی مراد صرف لہسن کی بدبو سے تھی ) ۔' WHERE id = 834;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا کہ ہمیں شعیب نے زہری سے خبر دی، انہوں نے کہا کہ مجھے عروہ بن زبیر نے عائشہ رضی اللہ عنہا سے بیان کیا، آپ رضی اللہ عنہ نے فرمایا کہ رسول اللہ صلی اللہ علیہ وسلم نے ایک مرتبہ عشاء کی نماز میں اتنی دیر کی کہ عمر رضی اللہ عنہ کو کہنا پڑا کہ عورتیں اور بچے سو گئے۔ پھر نبی کریم صلی اللہ علیہ وسلم ( حجرے سے ) تشریف لائے اور فرمایا کہ دیکھو روئے زمین پر اس نماز کا ( اس وقت ) تمہارے سوا اور کوئی انتظار نہیں کر رہا ہے۔ ان دنوں مدینہ کے سوا اور کہیں نماز نہیں پڑھی جاتی تھی اور لوگ عشاء کی نماز شفق ڈوبنے کے بعد سے رات کی پہلی تہائی گزرنے تک پڑھا کرتے تھے۔' WHERE id = 844;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا کہ ہمیں شعیب نے خبر دی، کہا کہ ہم سے ابوالزناد نے بیان کیا، ان سے ربیعہ بن حارث کے غلام عبدالرحمٰن بن ہرمز اعرج نے بیان کیا کہ انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا اور آپ رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ نے فرمایا کہ ہم دنیا میں تمام امتوں کے بعد ہونے کے باوجود قیامت میں سب سے آگے رہیں گے فرق صرف یہ ہے کہ کتاب انہیں ہم سے پہلے دی گئی تھی۔ یہی ( جمعہ ) ان کا بھی دن تھا جو تم پر فرض ہوا ہے۔ لیکن ان کا اس کے بارے میں اختلاف ہوا اور اللہ تعالیٰ نے ہمیں یہ دن بتا دیا اس لیے لوگ اس میں ہمارے تابع ہوں گے۔ یہود دوسرے دن ہوں گے اور نصاریٰ تیسرے دن۔' WHERE id = 856;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، انہوں نے کہا کہ ہمیں امام مالک نے نافع سے خبر دی، انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ عمر بن خطاب رضی اللہ عنہ نے ( ریشم کا ) دھاری دار جوڑا مسجد نبوی کے دروازے پر بکتا دیکھا تو کہنے لگے یا رسول اللہ! بہتر ہو اگر آپ اسے خرید لیں اور جمعہ کے دن اور وفود جب آپ صلی اللہ علیہ وسلم کے پاس آئیں تو ان کی ملاقات کے لیے آپ اسے پہنا کریں۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اسے تو وہی پہن سکتا ہے جس کا آخرت میں کوئی حصہ نہ ہو۔ اس کے بعد رسول اللہ صلی اللہ علیہ وسلم کے پاس اسی طرح کے کچھ جوڑے آئے تو اس میں سے ایک جوڑا آپ نے عمر بن خطاب رضی اللہ عنہ کو عطا فرمایا۔ انہوں نے عرض کیا: یا رسول اللہ! آپ مجھے یہ جوڑا پہنا رہے ہیں حالانکہ اس سے پہلے عطارد کے جوڑے کے بارے میں آپ نے کچھ ایسا فرمایا تھا۔ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ میں نے اسے تمہیں خود پہننے کے لیے نہیں دیا ہے، چنانچہ عمر رضی اللہ عنہ نے اسے اپنے ایک مشرک بھائی کو پہنا دیا جو مکے میں رہتا تھا۔' WHERE id = 866;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا کہ ہم سے وہیب بن خالد نے بیان کیا، کہا کہ ہم سے عبداللہ بن طاؤس نے بیان کیا، ان سے ان کے باپ طاؤس نے، ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ہم ( دنیا میں ) تو بعد میں آئے لیکن قیامت کے دن سب سے آگے ہوں گے، فرق صرف یہ ہے کہ یہود و نصاریٰ کو کتاب ہم سے پہلے دی گئی اور ہمیں بعد میں۔ تو یہ دن ( جمعہ ) وہ ہے جس کے بارے میں اہل کتاب نے اختلاف کیا، اللہ تعالیٰ نے ہمیں یہ دن بتلا دیا ( اس کے بعد ) دوسرا دن ( ہفتہ ) یہود کا دن ہے اور تیسرا دن ( اتوار ) نصاریٰ کا۔ آپ پھر خاموش ہو گئے۔' WHERE id = 876;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا کہ ہم سے ولید بن مسلم نے بیان کیا، کہا کہ ہم سے یزید بن ابی مریم نے بیان کیا، کہا کہ ہم سے عبایہ بن رفاعہ بن رافع بن خدیج نے بیان کیا، انہوں نے بیان کیا کہ میں جمعہ کے لیے جا رہا تھا۔ راستے میں ابوعبس رضی اللہ عنہ سے میری ملاقات ہوئی، انہوں نے کہا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا ہے کہ جس کے قدم اللہ کی راہ میں غبار آلود ہو گئے اللہ تعالیٰ اسے دوزخ پر حرام کر دے گا۔' WHERE id = 886;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا کہ ہم سے یعقوب بن عبدالرحمٰن بن محمد بن عبداللہ بن عبد القاری قرشی اسکندرانی نے بیان کیا، انہوں نے کہا کہ ہم سے ابوحازم بن دینار نے بیان کیا کہ کچھ لوگ سہل بن سعد ساعدی رضی اللہ عنہ کے پاس آئے۔ ان کا آپس میں اس پر اختلاف تھا کہ منبرنبوی علی صاحبہا الصلوۃ والسلام کی لکڑی کس درخت کی تھی۔ اس لیے سعد رضی اللہ عنہ سے اس کے متعلق دریافت کیا گیا آپ نے فرمایا اللہ گواہ ہے میں جانتا ہوں کہ منبرنبوی کس لکڑی کا تھا۔ پہلے دن جب وہ رکھا گیا اور سب سے پہلے جب اس پر رسول اللہ صلی اللہ علیہ وسلم بیٹھے تو میں اس کو بھی جانتا ہوں۔ رسول اللہ صلی اللہ علیہ وسلم نے انصار کی فلاں عورت کے پاس جن کا سعد رضی اللہ عنہ نے نام بھی بتایا تھا۔ آدمی بھیجا کہ وہ اپنے بڑھئی غلام سے میرے لیے لکڑی جوڑ دینے کے لیے کہیں۔ تاکہ جب مجھے لوگوں سے کچھ کہنا ہو تو اس پر بیٹھا کروں چنانچہ انہوں نے اپنے غلام سے کہا اور وہ غابہ کے جھاؤ کی لکڑی سے اسے بنا کر لایا۔ انصاری خاتون نے اسے رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں بھیج دیا۔ نبی کریم صلی اللہ علیہ وسلم نے اسے یہاں رکھوایا میں نے دیکھا کہ رسول اللہ صلی اللہ علیہ وسلم نے اسی پر ( کھڑے ہو کر ) نماز پڑھائی۔ اسی پر کھڑے کھڑے تکبیر کہی۔ اسی پر رکوع کیا۔ پھر الٹے پاؤں لوٹے اور منبر کی جڑ میں سجدہ کیا اور پھر دوبارہ اسی طرح کیا جب آپ نماز سے فارغ ہوئے تو لوگوں کو خطاب فرمایا۔ لوگو! میں نے یہ اس لیے کیا کہ تم میری پیروی کرو اور میری طرح نماز پڑھنی سیکھ لو۔' WHERE id = 896;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابان نے بیان کیا، انہوں نے کہا کہ ہم سے ابن غسیل عبدالرحمٰن بن سلیمان نے بیان کیا، انہوں نے کہا کہ ہم سے عکرمہ نے ابن عباس رضی اللہ عنہما کے واسطے سے بیان کیا، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم منبر پر تشریف لائے۔ منبر پر یہ آپ کی آخری بیٹھک تھی۔ آپ دونوں شانوں سے چادر لپیٹے ہوئے تھے اور سر مبارک پر ایک پٹی باندھ رکھی تھی۔ آپ نے حمد و ثنا کے بعد فرمایا لوگو! میری بات سنو۔ چنانچہ لوگ آپ کی طرف کلام مبارک سننے کے لیے متوجہ ہو گئے۔ پھر آپ نے فرمایا «امابعد» ! یہ قبیلہ انصار کے لوگ ( آنے والے دور میں ) تعداد میں بہت کم ہو جائیں گے پس محمد صلی اللہ علیہ وسلم کی امت کا جو شخص بھی حاکم ہو اور اسے نفع و نقصان پہنچانے کی طاقت ہو تو انصار کے نیک لوگوں کی نیکی قبول کرے اور ان کے برے کی برائی سے درگزر کرے۔' WHERE id = 906;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، انہوں نے کہا کہ ہمیں امام مالک رحمہ اللہ نے نافع سے خبر دی، ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم ظہر سے پہلے دو رکعت، اس کے بعد دو رکعت اور مغرب کے بعد دو رکعت اپنے گھر میں پڑھتے اور عشاء کے بعد دو رکعتیں پڑھتے اور جمعہ کے بعد دو رکعتیں جب گھر واپس ہوتے تب پڑھا کرتے تھے۔' WHERE id = 916;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، انہوں نے کہا کہ ہم سے حماد بن زید نے بیان کیا، ان سے عبدالعزیز بن صہیب اور ثابت بنانی نے، بیان کیا ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے صبح کی نماز اندھیرے ہی میں پڑھا دی، پھر سوار ہوئے ( پھر آپ صلی اللہ علیہ وسلم خیبر پہنچ گئے اور وہاں کے یہودیوں کو آپ کے آنے کی اطلاع ہو گئی ) اور فرمایا «الله اكبر» خیبر پر بربادی آ گئی۔ ہم تو جب کسی قوم کے آنگن میں اتر جائیں تو ڈرائے ہوئے لوگوں کی صبح منحوس ہو گی۔ اس وقت خیبر کے یہودی گلیوں میں یہ کہتے ہوئے بھاگ رہے تھے کہ محمد صلی اللہ علیہ وسلم لشکر سمیت آ گئے۔ راوی نے کہا کہ ( روایت میں ) لفظ «خميس» لشکر کے معنی میں ہے۔ آخر رسول اللہ صلی اللہ علیہ وسلم کو فتح ہوئی۔ لڑنے والے جوان قتل کر دئیے گئے، عورتیں اور بچے قید ہوئے۔ اتفاق سے صفیہ، دحیہ کلبی کے حصہ میں آئیں۔ پھر رسول اللہ صلی اللہ علیہ وسلم کو ملیں اور آپ صلی اللہ علیہ وسلم نے ان سے نکاح کیا اور آزادی ان کا مہر قرار پایا۔ عبدالعزیز نے ثابت سے پوچھا: ابو محمد! کیا تم نے انس رضی اللہ عنہ سے دریافت کیا تھا کہ صفیہ کا مہر آپ صلی اللہ علیہ وسلم نے مقرر کیا تھا انہوں نے جواب دیا کہ خود انہیں کو ان کے مہر میں دے دیا تھا۔ کہا کہ ابو محمد اس پر مسکرا دیئے۔' WHERE id = 926;
UPDATE hadiths SET urdu = 'ہم سے یعقوب بن ابراہیم نے بیان کیا، انہوں نے کہا کہ ہم سے ابواسامہ حماد بن ابواسامہ نے بیان کیا، انہوں نے کہا کہ ہم سے عبیداللہ نے نافع سے بیان کیا، ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم ، ابوبکر اور عمر رضی اللہ عنہما عیدین کی نماز خطبہ سے پہلے پڑھا کرتے تھے۔' WHERE id = 938;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر حزامی نے بیان کیا، کہا کہ ہم سے ولید بن مسلم نے بیان کیا، کہا کہ ہم سے ابوعمرو اوزاعی نے بیان کیا، کہا کہ ہم سے نافع نے ابن عمر رضی اللہ عنہما سے بیان کیا۔ انہوں نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم عیدگاہ جاتے تو برچھا ( ڈنڈا جس کے نیچے لوہے کا پھل لگا ہوا ہو ) آپ صلی اللہ علیہ وسلم کے آگے آگے لے جایا جاتا تھا پھر یہ عیدگاہ میں آپ صلی اللہ علیہ وسلم کے سامنے گاڑ دیا جاتا اور آپ صلی اللہ علیہ وسلم اس کی آڑ میں نماز پڑھتے۔' WHERE id = 948;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا کہ ہم سے ابوالاحوص سلام بن سلیم نے بیان کیا، کہا کہ ہم سے منصور بن معتمر نے بیان کیا کہ ان سے عامر شعبی نے، ان سے براء بن عازب رضی اللہ عنہ نے، انہوں نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم نے بقر عید کے دن نماز کے بعد خطبہ دیا اور فرمایا کہ جس نے ہماری طرح کی نماز پڑھی اور ہماری طرح کی قربانی کی، اس کی قربانی درست ہوئی۔ لیکن جس نے نماز سے پہلے قربانی کی تو وہ ذبیحہ صرف گوشت کھانے کے لیے ہو گا۔ اس پر ابوبردہ بن نیار نے عرض کیا کہ یا رسول اللہ صلی اللہ علیہ وسلم قسم اللہ کی میں نے تو نماز کے لیے آنے سے پہلے قربانی کر لی میں نے یہ سمجھا کہ آج کا دن کھانے پینے کا دن ہے۔ اسی لیے میں نے جلدی کی اور خود بھی کھایا اور گھر والوں کو اور پڑوسیوں کو بھی کھلایا۔ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ بہرحال یہ گوشت ( کھانے کا ) ہوا ( قربانی نہیں ) انہوں نے عرض کیا کہ میرے پاس ایک بکری کا سال بھر کا بچہ ہے وہ دو بکریوں کے گوشت سے زیادہ بہتر ہے۔ کیا میری ( طرف سے اس کی ) قربانی درست ہو گی؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہاں مگر تمہارے بعد کسی کی طرف سے ایسے بچے کی قربانی کافی نہ ہو گی۔' WHERE id = 958;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا کہ ہمیں شعیب نے زہری سے خبر دی، انہوں نے کہا کہ مجھ سے عروہ بن زبیر نے بیان کیا کہ عائشہ رضی اللہ عنہا نے انہیں خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم گیارہ رکعتیں ( وتر اور تہجد کی ) پڑھتے تھے، آپ صلی اللہ علیہ وسلم کی یہی نماز تھی۔ مراد ان کی رات کی نماز تھی۔ آپ صلی اللہ علیہ وسلم کا سجدہ ان رکعتوں میں اتنا لمبا ہوتا تھا کہ سر اٹھانے سے پہلے تم میں سے کوئی شخص بھی پچاس آیتیں پڑھ سکتا اور فجر کی نماز فرض سے پہلے آپ صلی اللہ علیہ وسلم سنت دو رکعتیں پڑھتے تھے اس کے بعد ( ذرا دیر ) داہنے پہلو پر لیٹ رہتے یہاں تک کہ مئوذن بلانے کے لیے آپ صلی اللہ علیہ وسلم کے پاس آتا۔' WHERE id = 968;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا کہ ہمیں اسماعیل بن علیہ نے خبر دی، کہا کہ ہمیں خالد حذاء نے خبر دی، انہیں ابوقلابہ نے، انہیں انس بن مالک رضی اللہ عنہ نے، آپ نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم کے عہد میں قنوت مغرب اور فجر میں پڑھی جاتی تھی۔' WHERE id = 978;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، ان سے امام مالک نے بیان کیا، ان سے شریک بن عبداللہ بن ابی نمر نے، ان کو انس رضی اللہ عنہ نے بتلایا کہ ایک آدمی رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور عرض کیا کہ جانور ہلاک ہو گئے اور راستے بند ہو گئے۔ آپ صلی اللہ علیہ وسلم نے دعا کی اور ایک ہفتہ تک بارش ہوتی رہی پھر ایک شخص آیا اور عرض کیا کہ ( بارش کی کثرت سے ) گھر گر گئے راستے بند ہو گئے۔ چنانچہ آپ صلی اللہ علیہ وسلم نے پھر کھڑے ہو کر دعا کی «اللهم على الآكام والظراب والأودية ومنابت الشجر» کہ اے اللہ! بارش ٹیلوں، پہاڑوں، وادیوں اور باغوں میں برسا ( دعا کے نتیجہ میں ) بادل مدینہ سے اس طرح پھٹ گئے جیسے کپڑا پھٹ کر ٹکڑے ٹکڑے ہو جاتا ہے۔' WHERE id = 989;
UPDATE hadiths SET urdu = 'مجھ سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا کہ ہم سے سفیان بن عیینہ نے عبداللہ بن ابی بکر سے بیان کیا، ان سے عباد بن تمیم نے، ان سے ان کے چچا عبداللہ بن زید رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے دعائے استسقاء کی تو دو رکعت نماز پڑھی اور چادر پلٹی۔' WHERE id = 999;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان حکم بن نافع نے بیان کیا، کہا کہ ہمیں شعیب نے خبر دی، کہا کہ ہم سے ابوالزناد (عبداللہ بن ذکوان) نے بیان کیا، ان سے عبدالرحمٰن بن ہرمز اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ قیامت اس وقت تک نہ آئے گی جب تک علم دین نہ اٹھ جائے گا اور زلزلوں کی کثرت نہ ہو جائے گی اور زمانہ جلدی جلدی نہ گزرے گا اور فتنے فساد پھوٹ پڑیں گے اور «هرج» کی کثرت ہو جائے گی اور «هرج» سے مراد قتل ہے۔ قتل اور تمہارے درمیان دولت و مال کی اتنی کثرت ہو گی کہ وہ ابل پڑے گا۔' WHERE id = 1009;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، انہوں نے کہا کہ مجھ سے لیث بن سعد نے بیان کیا، ان سے عقیل نے بیان کیا، ان سے ابن شہاب نے (دوسری سند) اور مجھ سے احمد بن صالح نے بیان کیا کہ ہم سے عنبسہ بن خالد نے بیان کیا، کہا کہ ہم سے یونس بن یزید نے بیان کیا، ان سے ابن شہاب نے، انہوں نے کہا کہ مجھ سے عروہ نے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ صدیقہ رضی اللہ عنہا سے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کی زندگی میں سورج گرہن لگا، اسی وقت آپ صلی اللہ علیہ وسلم مسجد میں تشریف لے گئے۔ انہوں نے بیان کیا کہ لوگوں نے نبی کریم صلی اللہ علیہ وسلم کے پیچھے صف باندھی آپ صلی اللہ علیہ وسلم نے تکبیر کہی اور بہت دیر قرآن مجید پڑھتے رہے پھر تکبیر کہی اور بہت لمبا رکوع کیا پھر «سمع الله لمن حمده‏» کہہ کر کھڑے ہو گئے اور سجدہ نہیں کیا ( رکوع سے اٹھنے کے بعد ) پھر بہت دیر تک قرآن مجید پڑھتے رہے۔ لیکن پہلی قرآت سے کم، پھر تکبیر کے ساتھ رکوع میں چلے گئے اور دیر تک رکوع میں رہے، یہ رکوع بھی پہلے رکوع سے کم تھا۔ اب «سمع الله لمن حمده‏» اور «ربنا ولك الحمد‏» کہا پھر سجدہ میں گئے۔ آپ صلی اللہ علیہ وسلم نے دوسری رکعت میں بھی اسی طرح کیا ( ان دونوں رکعتوں میں ) پورے چار رکوع اور چار سجدے کئے۔ نماز سے فارغ ہونے سے پہلے ہی سورج صاف ہو چکا تھا۔ نماز کے بعد آپ صلی اللہ علیہ وسلم نے کھڑے ہو کر خطبہ فرمایا اور پہلے اللہ تعالیٰ کی اس کی شان کے مطابق تعریف کی پھر فرمایا کہ سورج اور چاند اللہ کی دو نشانیاں ہیں ان میں گرہن کسی کی موت و حیات کی وجہ سے نہیں لگتا لیکن جب تم گرہن دیکھا کرو تو فوراً نماز کی طرف لپکو۔ زہری نے کہا کہ کثیر بن عباس اپنے بھائی عبداللہ بن عباس سے روایت کرتے تھے وہ سورج گرہن کا قصہ اس طرح بیان کرتے تھے جیسے عروہ نے عائشہ صدیقہ رضی اللہ عنہا سے نقل کیا۔ زہری نے کہا میں نے عروہ سے کہا تمہارے بھائی عبداللہ بن زبیر نے جس دن مدینہ میں سورج گرہن ہوا صبح کی نماز کی طرح دو رکعت پڑھی اور کچھ زیادہ نہیں کیا۔ انہوں نے کہا ہاں مگر وہ سنت کے طریق سے چوک گئے۔' WHERE id = 1019;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید طیالسی نے بیان کیا، انہوں نے کہا کہ ہم سے زائدہ بن قدامہ نے بیان کیا، انہوں نے کہا کہ ہم سے زیاد بن علاقہ نے بیان کیا، انہوں نے کہا کہ میں نے مغیرہ بن شعبہ رضی اللہ عنہ سے سنا کہ انہوں نے کہا کہ جس دن ابراہیم رضی اللہ عنہ کی موت ہوئی سورج گرہن بھی اسی دن لگا۔ اس پر بعض لوگوں نے کہا کہ گرہن ابراہیم رضی اللہ عنہ ( نبی کریم صلی اللہ علیہ وسلم کے صاحبزادے ) کی وفات کی وجہ سے لگا ہے۔ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ سورج اور چاند اللہ تعالیٰ کی نشانیوں میں سے دو نشان ہیں۔ ان میں گرہن کسی کی موت و حیات کی وجہ سے نہیں لگتا۔ جب اسے دیکھو تو اللہ پاک سے دعا کرو اور نماز پڑھو تاآنکہ سورج صاف ہو جائے۔' WHERE id = 1031;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن داؤد ابوالربیع نے بیان کیا، انہوں نے کہا کہ ہم سے اسماعیل بن جعفر نے بیان کیا، کہا کہ ہمیں یزید بن خصیفہ نے خبر دی، انہیں (یزید بن عبداللہ) ابن قسیط نے، اور انہیں عطاء بن یسار نے کہ انہوں نے زید بن ثابت رضی اللہ عنہ سے سوال کیا۔ آپ نے یقین کے ساتھ اس امر کا اظہار کیا کہ نبی کریم صلی اللہ علیہ وسلم کے سامنے سورۃ النجم کی تلاوت آپ نے کی تھی اور نبی کریم صلی اللہ علیہ وسلم نے اس میں سجدہ نہیں کیا۔' WHERE id = 1042;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا کہ ہم سے یحییٰ نے عبیداللہ عمری سے بیان کیا، کہا کہ مجھے نافع نے خبر دی اور انہیں عبداللہ بن مسعود رضی اللہ عنہ نے، کہا کہ میں نے نبی کریم صلی اللہ علیہ وسلم ابوبکر اور عمر رضی اللہ عنہما کے ساتھ منیٰ میں دو رکعت ( یعنی چار رکعت والی نمازوں میں ) قصر پڑھی۔ عثمان رضی اللہ عنہ کے ساتھ بھی ان کے دور خلافت کے شروع میں دو ہی رکعت پڑھی تھیں۔ لیکن بعد میں آپ رضی اللہ عنہ نے پوری پڑھی تھیں۔' WHERE id = 1052;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، انہوں نے کہا کہ ہم سے عبدالاعلیٰ نے بیان کیا، کہا کہ ہم سے معمر نے زہری سے بیان کیا، ان سے عبداللہ بن عامر نے اور ان سے ان کے باپ نے کہا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو دیکھا کہ اونٹنی پر نماز پڑھتے رہتے خواہ اس کا منہ کسی طرف ہو۔' WHERE id = 1062;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، ان سے عمرو بن مرہ نے، ان سے ابن ابی لیلیٰ نے، انہوں نے کہا کہ ہمیں کسی نے یہ خبر نہیں دی کہ رسول اللہ صلی اللہ علیہ وسلم کو انہوں نے چاشت کی نماز پڑھتے دیکھا ہاں ام ہانی رضی اللہ عنہا کا بیان ہے کہ فتح مکہ کے دن نبی کریم صلی اللہ علیہ وسلم نے ان کے گھر غسل کیا تھا اور اس کے بعد آپ صلی اللہ علیہ وسلم نے آٹھ رکعتیں پڑھی تھیں، میں نے آپ صلی اللہ علیہ وسلم کو کبھی اتنی ہلکی پھلکی نماز پڑھتے نہیں دیکھا البتہ آپ صلی اللہ علیہ وسلم رکوع اور سجدہ پوری طرح کرتے تھے۔' WHERE id = 1072;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، ان سے امام مالک رحمہ اللہ نے، ان سے ہشام بن عروہ نے، ان سے ان کے باپ عروہ نے، ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم بیمار تھے اس لیے آپ صلی اللہ علیہ وسلم نے اپنے گھر میں بیٹھ کر نماز پڑھائی، بعض لوگ آپ صلی اللہ علیہ وسلم کے پیچھے کھڑے ہو کر پڑھنے لگے۔ لیکن آپ صلی اللہ علیہ وسلم نے انہیں اشارہ کیا کہ بیٹھ جاؤ۔ نماز سے فارغ ہونے کے بعد آپ صلی اللہ علیہ وسلم نے فرمایا کہ امام اس لیے ہے کہ اس کی پیروی کی جائے اس لیے جب وہ رکوع کرے تو تم بھی رکوع کرو اور جب وہ سر اٹھائے تو تم بھی سر اٹھاؤ۔' WHERE id = 1082;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، انہوں نے کہا کہ ہمیں سفیان ثوری نے اسود بن قیس سے خبر دی، ان سے جندب بن عبداللہ رضی اللہ عنہ نے فرمایا کہ جبرائیل علیہ السلام ( ایک مرتبہ چند دنوں تک ) نبی کریم صلی اللہ علیہ وسلم کے پاس ( وحی لے کر ) نہیں آئے تو قریش کی ایک عورت ( ام جمیل ابولہب کی بیوی ) نے کہا کہ اب اس کے شیطان نے اس کے پاس آنے سے دیر لگائی۔ اس پر یہ سورت اتری «والضحى * والليل إذا سجى * ما ودعك ربك وما قلى‏» ۔' WHERE id = 1093;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا کہ ہم سے شعبہ نے اعمش سے بیان کیا، ان سے ابووائل نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے فرمایا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کے ساتھ ایک مرتبہ رات کو نماز پڑھی۔ آپ صلی اللہ علیہ وسلم نے اتنا لمبا قیام کیا کہ میرے دل میں ایک غلط خیال پیدا ہو گیا۔ ہم نے پوچھا کہ وہ غلط خیال کیا تھا تو آپ نے بتایا کہ میں نے سوچا کہ بیٹھ جاؤں اور نبی کریم صلی اللہ علیہ وسلم کا ساتھ چھوڑ دوں۔' WHERE id = 1104;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، ان سے امام مالک رحمہ اللہ نے، ان نے ابن شہاب نے، ان سے ابوسلمہ عبدالرحمٰن اور ابوعبداللہ اغر نے اور ان دونوں حضرات سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ ہمارا پروردگار بلند برکت والا ہے ہر رات کو اس وقت آسمان دنیا پر آتا ہے جب رات کا آخری تہائی حصہ رہ جاتا ہے۔ وہ کہتا ہے کوئی مجھ سے دعا کرنے والا ہے کہ میں اس کی دعا قبول کروں، کوئی مجھ سے مانگنے والا ہے کہ میں اسے دوں کوئی مجھ سے بخشش طلب کرنے والا ہے کہ میں اس کو بخش دوں۔' WHERE id = 1114;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا کہ ہم سے لیث بن سعد نے بیان کیا، ان سے یونس نے، ان سے ابن شہاب نے، انہوں نے کہا کہ مجھ کو ہیثم بن ابی سنان نے خبر دی کہ انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا، آپ اپنے وعظ میں رسول اللہ صلی اللہ علیہ وسلم کا ذکر کر رہے تھے۔ پھر آپ نے فرمایا کہ تمہارے بھائی نے ( اپنے نعتیہ اشعار میں ) یہ کوئی غلط بات نہیں کہی۔ آپ کی مراد عبداللہ بن رواحہ رضی اللہ عنہ اور ان کے اشعار سے تھی جن کا ترجمہ یہ ہے: ”ہم میں اللہ کے رسول موجود ہیں، جو اس کی کتاب اس وقت ہمیں سناتے ہیں جب فجر طلوع ہوتی ہے۔ ہم تو اندھے تھے آپ صلی اللہ علیہ وسلم نے ہمیں گمراہی سے نکال کر صحیح راستہ دکھایا۔ ان کی باتیں اسی قدر یقینی ہیں جو ہمارے دلوں کے اندر جا کر بیٹھ جاتی ہیں اور جو کچھ آپ نے فرمایا وہ ضرور واقع ہو گا۔ آپ صلی اللہ علیہ وسلم رات بستر سے اپنے کو الگ کر کے گزارتے ہیں جبکہ مشرکوں سے ان کے بستر بوجھل ہو رہے ہوتے ہیں“۔ یونس کی طرح اس حدیث کو عقیل نے بھی زہری سے روایت کیا اور زبیدی نے یوں کہا سعید بن مسیب اور اعرج سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے۔' WHERE id = 1124;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا کہ ہمیں شعبہ نے خبر دی، انہیں عمرو بن دینار نے خبر دی، کہا کہ میں نے جابر بن عبداللہ انصاری رضی اللہ عنہما سے سنا کہ رسول اللہ صلی اللہ علیہ وسلم نے جمعہ کا خطبہ دیتے ہوئے فرمایا کہ جو شخص بھی ( مسجد میں ) آئے اور امام خطبہ دے رہا ہو یا خطبہ کے لیے نکل چکا ہو تو وہ دو رکعت نماز ( تحیۃ المسجد کی ) پڑھ لے۔' WHERE id = 1137;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یزید نے بیان کیا، کہا کہ ہم سے سعید بن ابی ایوب نے بیان کیا، کہا کہ مجھ سے یزید بن ابی حبیب نے بیان کیا، انہوں نے کہا کہ میں نے مرثد بن عبداللہ یزنی سے سنا کہ میں عقبہ بن عامر جہنی صحابی رضی اللہ عنہ کے پاس آیا اور عرض کیا آپ کو ابوتمیم عبداللہ بن مالک پر تعجب نہیں آیا کہ وہ مغرب کی نماز فرض سے پہلے دو رکعت نفل پڑھتے ہیں۔ اس پر عقبہ نے فرمایا کہ ہم بھی رسول اللہ صلی اللہ علیہ وسلم کے زمانہ میں اسے پڑھتے تھے۔ میں نے کہا پھر اب اس کے چھوڑنے کی کیا وجہ ہے؟ انہوں نے فرمایا کہ دنیا کے کاروبار مانع ہیں۔' WHERE id = 1149;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، انہوں نے کہا کہ ہم سے شعبہ نے بیان کیا، ان سے عبدالملک بن عمیر نے بیان کیا، انہوں نے زیاد کے غلام قزعہ سے سنا، انہوں نے بیان کیا کہ میں نے ابو سعید خدری رضی اللہ عنہ کو رسول اللہ صلی اللہ علیہ وسلم کے حوالہ سے چار حدیثیں بیان کرتے ہوئے سنا جو مجھے بہت پسند آئیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ عورت اپنے شوہر یا کسی ذی رحم محرم کے بغیر دو دن کا بھی سفر نہ کرے اور دوسری یہ کہ عیدالفطر اور عید الاضحی دونوں دن روزے نہ رکھے جائیں۔ تیسری بات یہ کہ صبح کی نماز کے بعد سورج کے نکلنے تک اور عصر کے بعد سورج چھپنے تک کوئی نفل نماز نہ پڑھی جائے۔ چوتھی یہ کہ تین مسجدوں کے سوا کسی کے لیے کجاوے نہ باندھے جائیں۔ مسجد الحرام، مسجد الاقصیٰ اور میری مسجد ( یعنی مسجد نبوی ) ۔' WHERE id = 1160;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا کہ ہم سے شیبان نے بیان کیا، ان سے یحییٰ بن کثیر نے، ان سے ابوسلمہ نے، انہوں نے کہا کہ مجھ سے معیقیب بن ابی طلحہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ایک شخص سے جو ہر مرتبہ سجدہ کرتے ہوئے کنکریاں برابر کرتا تھا فرمایا اگر ایسا کرنا ہے تو صرف ایک ہی بار کر۔' WHERE id = 1171;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، کہا کہ ہم سے عبدالوارث نے بیان کیا، کہا کہ ہم سے کثیر بن شنظیر نے بیان کیا، ان سے عطاء بن ابی رباح نے ان سے جابر بن عبداللہ رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے مجھے اپنی ایک ضرورت کے لیے ( غزوہ بنی مصطلق میں ) بھیجا۔ میں واپس آیا اور میں نے کام پورا کر دیا تھا۔ پھر میں نے نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہو کر آپ صلی اللہ علیہ وسلم کو سلام کیا۔ لیکن آپ صلی اللہ علیہ وسلم نے کوئی جواب نہیں دیا۔ میرے دل میں اللہ جانے کیا بات آئی اور میں نے اپنے دل میں کہا کہ شاید رسول اللہ صلی اللہ علیہ وسلم مجھ پر اس لیے خفا ہیں کہ میں دیر سے آیا ہوں۔ میں نے پھر دوبارہ سلام کیا اور جب اس مرتبہ بھی آپ صلی اللہ علیہ وسلم نے کوئی جواب نہ دیا تو اب میرے دل میں پہلے سے بھی زیادہ خیال آیا۔ پھر میں نے ( تیسری مرتبہ ) سلام کیا، اور اب آپ صلی اللہ علیہ وسلم نے جواب دیا اور فرمایا کہ پہلے جو دو بار میں نے جواب نہ دیا تو اس وجہ سے تھا کہ میں نماز پڑھ رہا تھا، اور آپ صلی اللہ علیہ وسلم اس وقت اپنی اونٹنی پر تھے اور اس کا رخ قبلہ کی طرف نہ تھا بلکہ دوسری طرف تھا۔' WHERE id = 1181;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، ان سے سعد بن ابراہیم نے، ان سے ابوسلمہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے ظہر یا عصر کی نماز پڑھائی جب آپ صلی اللہ علیہ وسلم نے سلام پھیرا تو ذوالیدین کہنے لگا کہ یا رسول اللہ صلی اللہ علیہ وسلم ! کیا نماز کی رکعتیں کم ہو گئی ہیں؟ ( کیونکہ آپ صلی اللہ علیہ وسلم نے بھول کر صرف دو رکعتوں پر سلام پھیر دیا تھا ) نبی کریم صلی اللہ علیہ وسلم نے اپنے اصحاب سے دریافت کیا کہ کیا یہ سچ کہتے ہیں؟ صحابہ نے کہا جی ہاں، اس نے صحیح کہا ہے۔ تب نبی کریم صلی اللہ علیہ وسلم نے دو رکعت اور پڑھائیں پھر دو سجدے کئے۔ سعد نے بیان کیا کہ عروہ بن زبیر کو میں نے دیکھا کہ آپ نے مغرب کی دو رکعتیں پڑھ کر سلام پھیر دیا اور باتیں بھی کیں۔ پھر باقی ایک رکعت پڑھی اور دو سجدے کئے اور فرمایا کہ نبی کریم صلی اللہ علیہ وسلم نے اسی طرح کیا تھا۔' WHERE id = 1191;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا کہ ہم سے مہدی بن میمون نے، کہا کہ ہم سے واصل بن حیان احدب (کبڑے) نے، ان سے معرور بن سوید نے بیان کیا اور ان سے ابوذر غفاری رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ( کہ خواب میں ) میرے پاس میرے رب کا ایک آنے والا ( فرشتہ ) آیا۔ اس نے مجھے خبر دی، یا آپ صلی اللہ علیہ وسلم نے یہ فرمایا کہ اس نے مجھے خوشخبری دی کہ میری امت میں سے جو کوئی اس حال میں مرے کہ اللہ تعالیٰ کے ساتھ اس نے کوئی شریک نہ ٹھہرایا ہو تو وہ جنت میں جائے گا۔ اس پر میں نے پوچھا اگرچہ اس نے زنا کیا ہو، اگرچہ اس نے چوری کی ہو؟ تو رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ ہاں اگرچہ زنا کیا ہو اگرچہ چوری کی ہو۔' WHERE id = 1202;
UPDATE hadiths SET urdu = 'ہم سے علی نے بیان کیا، ان سے سفیان نے، انہوں نے کہا کہ میں نے زہری سے سنا، انہوں نے سعید بن مسیب سے سنا اور انہوں نے ابوہریرہ رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کسی کے اگر تین بچے مر جائیں تو وہ دوزخ میں نہیں جائے گا اور اگر جائے گا بھی تو صرف قسم پوری کرنے کے لیے۔ ابوعبداللہ امام بخاری رحمہ اللہ فرماتے ہیں۔ ( قرآن کی آیت یہ ہے ) تم میں سے ہر ایک کو دوزخ کے اوپر سے گزرنا ہو گا۔' WHERE id = 1214;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا کہ ہم سے یحییٰ بن سعید نے بیان کیا، ان سے ہشام بن حسان نے بیان کیا، کہا کہ ہم سے حفصہ نے بیان کیا، ان سے ام عطیہ رضی اللہ عنہا نے کہ رسول اللہ صلی اللہ علیہ وسلم کی ایک صاحبزادی کا انتقال ہو گیا تو نبی کریم صلی اللہ علیہ وسلم تشریف لائے اور فرمایا کہ ان کو پانی اور بیری کے پتوں سے تین یا پانچ مرتبہ غسل دے دو۔ اگر تم مناسب سمجھو تو اس سے زیادہ بھی دے سکتی ہو اور آخر میں کافور یا ( آپ صلی اللہ علیہ وسلم نے یہ فرمایا کہ ) تھوڑی سی کافور استعمال کرو پھر جب غسل دے چکو تو مجھے خبر دو۔ چنانچہ فارغ ہو کر ہم نے آپ صلی اللہ علیہ وسلم کو خبر دی تو آپ صلی اللہ علیہ وسلم نے ( ان کے کفن کے لیے ) اپنا ازار عنایت کیا۔ ہم نے اس کے سر کے بالوں کی تین چٹیاں کر کے انہیں پیچھے کی طرف ڈال دیا تھا۔' WHERE id = 1225;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا کہا کہ مجھ سے مالک نے بیان کیا ‘ ان سے ہشام بن عروہ نے ‘ ان سے ان کے باپ عروہ بن زبیر نے ‘ ان سے عائشہ رضی اللہ عنہا نے کہ رسول اللہ صلی اللہ علیہ وسلم کو سحول کے تین سفید کپڑوں کا کفن دیا گیا تھا نہ ان میں قمیص تھی اور نہ عمامہ تھا۔' WHERE id = 1235;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا ‘ کہا ہم سے ابوعامر عقدی نے بیان کیا ‘ کہا ہم سے فلیح بن سلیمان نے بیان کیا ‘ ان سے ہلال بن علی نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ ہم نبی کریم صلی اللہ علیہ وسلم کی ایک بیٹی ( ام کلثوم رضی اللہ عنہا ) کے جنازہ میں حاضر تھے۔ ( وہ عثمان غنی رضی اللہ عنہ کی بیوی تھیں۔ جن کا 5 ھ میں انتقال ہوا ) نبی کریم صلی اللہ علیہ وسلم قبر پر بیٹھے ہوئے تھے۔ انہوں نے کہا کہ میں نے دیکھا کہ آپ صلی اللہ علیہ وسلم کی آنکھیں آنسوؤں سے بھر آئی تھیں۔ نبی کریم صلی اللہ علیہ وسلم نے پوچھا۔ کیا تم میں کوئی ایسا شخص بھی ہے کہ جو آج کی رات عورت کے پاس نہ گیا ہو۔ اس پر ابوطلحہ رضی اللہ عنہ نے کہا کہ میں ہوں۔ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ پھر قبر میں تم اترو۔ چنانچہ وہ ان کی قبر میں اترے۔' WHERE id = 1246;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص نے بیان کیا ‘ ان سے ان کے باپ حفص نے اور ان سے اعمش نے اور ان سے عبداللہ بن مرہ نے ‘ ان سے مسروق نے اور ان سے عبداللہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جو ( کسی کی موت پر ) اپنے رخسار پیٹے ‘ گریبان چاک کرے اور جاہلیت کی باتیں کرے وہ ہم میں سے نہیں ہے۔' WHERE id = 1257;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا ‘ انہوں نے کہا کہ ہم سے لیث بن سعد نے بیان کیا ‘ انہوں نے کہا کہ ہم سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے عامر بن ربیعہ رضی اللہ عنہ کے حوالہ سے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جب تم میں سے کوئی جنازہ دیکھے تو اگر اس کے ساتھ نہیں چل رہا ہے تو کھڑا ہی ہو جائے تاآنکہ جنازہ آگے نکل جائے یا آگے جانے کی بجائے خود جنازہ رکھ دیا جائے۔' WHERE id = 1267;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا ‘ کہا کہ ہم کو ہشام بن یوسف نے خبر دی کہ انہیں ابن جریج نے خبر دی ‘ انہوں نے بیان کیا کہ مجھے عطاء بن ابی رباح نے خبر دی ‘ انہوں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ آج حبش کے ایک مرد صالح ( نجاشی حبش کے بادشاہ ) کا انتقال ہو گیا ہے۔ آؤ ان کی نماز جنازہ پڑھو۔ جابر رضی اللہ عنہ نے بیان کیا کہ پھر ہم نے صف بندی کر لی اور نبی کریم صلی اللہ علیہ وسلم نے ان کی نماز جنازہ پڑھائی۔ ہم صف باندھے کھڑے تھے۔ ابوالزبیر نے جابر رضی اللہ عنہ کے حوالہ سے نقل کیا کہ میں دوسری صف میں تھا۔' WHERE id = 1278;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا ‘ کہا کہ ہمیں امام مالک رحمہ اللہ نے خبر دی ‘ انہیں ابن شہاب نے ‘ انہیں سعید بن مسیب نے ‘ انہیں ابوہریرہ رضی اللہ عنہ نے کہ نجاشی کا جس دن انتقال ہوا اسی دن رسول اللہ صلی اللہ علیہ وسلم نے ان کی وفات کی خبر دی اور آپ صلی اللہ علیہ وسلم صحابہ کے ساتھ عیدگاہ گئے۔ پھر آپ صلی اللہ علیہ وسلم نے صف بندی کرائی اور چار تکبیریں کہیں۔' WHERE id = 1289;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا ‘ انہوں نے کہا کہ ہم سے لیث بن سعد نے بیان کیا ‘ انہوں نے کہا کہ مجھ سے ابن شہاب نے بیان کیا ‘ ان سے عبدالرحمٰن بن کعب بن مالک نے ‘ ان سے جابر بن عبداللہ رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے احد کے دو دو شہیدوں کو ملا کر ایک ہی کپڑے کا کفن دیا۔ آپ صلی اللہ علیہ وسلم دریافت فرماتے کہ ان میں قرآن کسے زیادہ یاد ہے۔ کسی ایک کی طرف اشارہ سے بتایا جاتا تو آپ صلی اللہ علیہ وسلم بغلی قبر میں اسی کو آگے کرتے اور فرماتے کہ میں قیامت میں ان کے حق میں شہادت دوں گا۔ پھر آپ صلی اللہ علیہ وسلم نے سب کو ان کے خون سمیت دفن کرنے کا حکم دیا۔ نہ انہیں غسل دیا گیا اور نہ ان کی نماز جنازہ پڑھی گئی۔' WHERE id = 1299;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا ‘ کہا کہ ہم سے حماد بن زید نے بیان کیا ‘ ان سے ثابت نے ‘ ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ ایک یہودی لڑکا ( عبدالقدوس ) نبی کریم صلی اللہ علیہ وسلم کی خدمت کیا کرتا تھا، ایک دن وہ بیمار ہو گیا۔ آپ صلی اللہ علیہ وسلم اس کا مزاج معلوم کرنے کے لیے تشریف لائے اور اس کے سرہانے بیٹھ گئے اور فرمایا کہ مسلمان ہو جا۔ اس نے اپنے باپ کی طرف دیکھا، باپ وہیں موجود تھا۔ اس نے کہا کہ ( کیا مضائقہ ہے ) ابوالقاسم صلی اللہ علیہ وسلم جو کچھ کہتے ہیں مان لے۔ چنانچہ وہ بچہ اسلام لے آیا۔ جب نبی کریم صلی اللہ علیہ وسلم باہر نکلے تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ شکر ہے اللہ پاک کا جس نے اس بچے کو جہنم سے بچا لیا۔' WHERE id = 1310;
UPDATE hadiths SET urdu = 'ہم سے عفان بن مسلم صفار نے بیان کیا ‘ کہا کہ ہم سے داؤد بن ابی الفرات نے ‘ ان سے عبداللہ بن بریدہ نے ‘ ان سے ابوالاسود دئلی نے کہ میں مدینہ حاضر ہوا۔ ان دنوں وہاں ایک بیماری پھیل رہی تھی۔ میں عمر بن خطاب رضی اللہ عنہ کی خدمت میں تھا کہ ایک جنازہ سامنے سے گزرا۔ لوگ اس میت کی تعریف کرنے لگے تو عمر رضی اللہ عنہ نے فرمایا کہ واجب ہو گئی پھر ایک اور جنازہ گزرا، لوگ اس کی بھی تعریف کرنے لگے۔ اس مرتبہ بھی آپ نے ایسا ہی فرمایا کہ واجب ہو گئی۔ پھر تیسرا جنازہ نکلا ‘ لوگ اس کی برائی کرنے لگے ‘ اور اس مرتبہ بھی آپ نے یہی فرمایا کہ واجب ہو گئی۔ ابوالاسود دئلی نے بیان کیا کہ میں نے پوچھا کہ امیرالمؤمنین کیا چیز واجب ہو گئی؟ آپ نے فرمایا کہ میں نے اس وقت وہی کہا جو رسول اللہ صلی اللہ علیہ وسلم نے فرمایا تھا کہ جس مسلمان کی اچھائی پر چار شخص گواہی دے دیں اللہ اسے جنت میں داخل کرے گا۔ ہم نے کہا اور اگر تین گواہی دیں؟ آپ نے فرمایا کہ تین پر بھی، پھر ہم نے پوچھا اور اگر دو مسلمان گواہی دیں؟ آپ نے فرمایا کہ دو پر بھی۔ پھر ہم نے یہ نہیں پوچھا کہ اگر ایک مسلمان گواہی دے تو کیا؟' WHERE id = 1321;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا ‘ کہا ہم سے جریر نے بیان کیا ‘ ان سے اعمش نے ‘ ان سے مجاہد نے ‘ ان سے طاؤس نے کہ ابن عباس رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کا گزر دو قبروں پر ہوا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ان دونوں کے مردوں پر عذاب ہو رہا ہے اور یہ بھی نہیں کہ کسی بڑی اہم بات پر ہو رہا ہے۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہاں! ان میں ایک شخص تو چغل خوری کیا کرتا تھا اور دوسرا پیشاب سے بچنے کے لیے احتیاط نہیں کرتا تھا۔ ابن عباس رضی اللہ عنہما نے بیان کیا کہ پھر آپ صلی اللہ علیہ وسلم نے ایک ہری ٹہنی لی اور اس کے دو ٹکڑے کر کے دونوں کی قبروں پر گاڑ دیا اور فرمایا کہ شاید جب تک یہ خشک نہ ہوں ان کا عذاب کم ہو جائے۔' WHERE id = 1331;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا کہ ہم سے محمد بن جعفر نے بیان کیا ‘ کہا مجھے ہشام بن عروہ نے خبر دی ‘ انہیں ان کے باپ نے اور انہیں عائشہ رضی اللہ عنہا نے کہ ایک شخص نے نبی کریم صلی اللہ علیہ وسلم سے پوچھا کہ میری ماں کا اچانک انتقال ہو گیا اور میرا خیال ہے کہ اگر انہیں بات کرنے کا موقع ملتا تو وہ کچھ نہ کچھ خیرات کرتیں۔ اگر میں ان کی طرف سے کچھ خیرات کر دوں تو کیا انہیں اس کا ثواب ملے گا؟ آپ صلی اللہ علیہ وسلم نے فرمایا ہاں ملے گا۔' WHERE id = 1341;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے حدیث بیان کی ‘ کہا کہ ہم سے حماد بن زید نے بیان کیا ‘ کہا کہ ہم سے ابوجمرہ نصر بن عمران ضبعی نے بیان کیا ‘ کہا کہ میں نے ابن عباس رضی اللہ عنہما سے سنا ‘ آپ نے بتلایا کہ قبیلہ عبدالقیس کا وفد نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور عرض کی کہ یا رسول اللہ! ہم قبیلہ ربیعہ کی ایک شاخ ہیں اور قبیلہ مضر کے کافر ہمارے اور آپ صلی اللہ علیہ وسلم کے درمیان پڑتے ہیں۔ اس لیے ہم آپ صلی اللہ علیہ وسلم کی خدمت میں صرف حرمت کے مہینوں ہی میں حاضر ہو سکتے ہیں ( کیونکہ ان مہینوں میں لڑائیاں بند ہو جاتی ہیں اور راستے پرامن ہو جاتے ہیں ) آپ صلی اللہ علیہ وسلم ہمیں کچھ ایسی باتیں بتلا دیجئیے جس پر ہم خود بھی عمل کریں اور اپنے قبیلہ کے لوگوں سے بھی ان پر عمل کرنے کے لیے کہیں جو ہمارے ساتھ نہیں آ سکے ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں تمہیں چار باتوں کا حکم دیتا ہوں اور چار چیزوں سے روکتا ہوں۔ اللہ تعالیٰ پر ایمان لانے اور اس کی وحدانیت کی شہادت دینے کا ( یہ کہتے ہوئے ) آپ صلی اللہ علیہ وسلم نے اپنی انگلی سے ایک طرف اشارہ کیا۔ نماز قائم کرنا ‘ پھر زکوٰۃ ادا کرنا اور مال غنیمت سے پانچواں حصہ ادا کرنے ( کا حکم دیتا ہوں ) اور میں تمہیں کدو کے تونبی سے اور حنتم ( سبز رنگ کا چھوٹا سا مرتبان جیسا گھڑا ) فقیر ( کھجور کی جڑ سے کھودا ہوا ایک برتن ) اور زفت لگا ہوا برتن ( زفت بصرہ میں ایک قسم کا تیل ہوتا تھا ) کے استعمال سے منع کرتا ہوں۔ سلیمان اور ابوالنعمان نے حماد کے واسطہ سے یہی روایت اس طرح بیان کی ہے۔ «الإيمان بالله شهادة أن لا إله إلا الله» یعنی اللہ پر ایمان لانے کا مطلب «لا إله إلا الله» کی گواہی دینا۔' WHERE id = 1353;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا ‘ انہوں نے کہا کہ ہم سے شعبہ نے بیان کیا ‘ انہوں نے کہا کہ ہم سے سعید بن خالد نے بیان کیا ‘ انہوں نے کہا کہ میں نے حارثہ بن وہب رضی اللہ عنہ سے سنا ‘ انہوں نے فرمایا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا تھا کہ صدقہ کرو ‘ ایک ایسا زمانہ بھی تم پر آنے والا ہے جب ایک شخص اپنے مال کا صدقہ لے کر نکلے گا اور کوئی اسے قبول کرنے والا نہیں پائے گا۔' WHERE id = 1364;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا ‘ کہا کہ ہمیں شعیب نے خبر دی ‘ کہا کہ ہم سے ابوالزناد نے بیان کیا ‘ ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ ایک شخص نے ( بنی اسرائیل میں سے ) کہا کہ مجھے ضرور صدقہ ( آج رات ) دینا ہے۔ چنانچہ وہ اپنا صدقہ لے کر نکلا اور ( ناواقفی سے ) ایک چور کے ہاتھ میں رکھ دیا۔ صبح ہوئی تو لوگوں نے کہنا شروع کیا کہ آج رات کسی نے چور کو صدقہ دے دیا۔ اس شخص نے کہا کہ اے اللہ! تمام تعریف تیرے ہی لیے ہے۔ ( آج رات ) میں پھر ضرور صدقہ کروں گا۔ چنانچہ وہ دوبارہ صدقہ لے کر نکلا اور اس مرتبہ ایک فاحشہ کے ہاتھ میں دے آیا۔ جب صبح ہوئی تو پھر لوگوں میں چرچا ہوا کہ آج رات کسی نے فاحشہ عورت کو صدقہ دے دیا۔ اس شخص نے کہا اے اللہ! تمام تعریف تیرے ہی لیے ہے ‘ میں زانیہ کو اپنا صدقہ دے آیا۔ اچھا آج رات پھر ضرور صدقہ نکالوں گا۔ چنانچہ اپنا صدقہ لیے ہوئے وہ پھر نکلا اور اس مرتبہ ایک مالدار کے ہاتھ پر رکھ دیا۔ صبح ہوئی تو لوگوں کی زبان پر ذکر تھا کہ ایک مالدار کو کسی نے صدقہ دے دیا ہے۔ اس شخص نے کہا کہ اے اللہ! حمد تیرے ہی لیے ہے۔ میں اپنا صدقہ ( لاعلمی سے ) چور ‘ فاحشہ اور مالدار کو دے آیا۔ ( اللہ تعالیٰ کی طرف سے ) بتایا گیا کہ جہاں تک چور کے ہاتھ میں صدقہ چلے جانے کا سوال ہے۔ تو اس میں اس کا امکان ہے کہ وہ چوری سے رک جائے۔ اسی طرح فاحشہ کو صدقہ کا مال مل جانے پر اس کا امکان ہے کہ وہ زنا سے رک جائے اور مالدار کے ہاتھ میں پڑ جانے کا یہ فائدہ ہے کہ اسے عبرت ہو اور پھر جو اللہ عزوجل نے اسے دیا ہے ‘ وہ خرچ کرے۔' WHERE id = 1374;
UPDATE hadiths SET urdu = 'ہم سے صدقہ بن فضل نے بیان کیا ‘ کہا کہ ہمیں عبدہ نے ہشام سے خبر دی ’ انہیں ان کی بیوی فاطمہ بنت منذر نے اور ان سے اسماء رضی اللہ عنہا نے بیان کیا کہ مجھ سے نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ خیرات کو مت روک ورنہ تیرا رزق بھی روک دیا جائے گا۔' WHERE id = 1385;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا ‘ کہا کہ ہم سے وہیب نے بیان کیا ‘ کہا کہ ہم سے عبداللہ بن طاؤس نے بیان کیا ‘ ان سے ان کے باپ طاؤس نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ بخیل اور صدقہ دینے والے کی مثال ایسے دو شخصوں کی طرح ہے جن کے بدن پر لوہے کے دو کرتے ہیں۔ ( دوسری سند ) امام بخاری رحمہ اللہ نے کہا اور ہم سے ابوالیمان نے بیان کیا ‘ کہا کہ ہمیں شعیب نے خبر دی ‘ کہا کہ ہمیں ابوالزناد نے خبر دی کہ عبداللہ بن ہرمز اعرج نے ان سے بیان کیا اور انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا اور ابوہریرہ رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم کو یہ کہتے سنا کہ بخیل اور خرچ کرنے والے کی مثال ایسے دو شخصوں کی سی ہے جن کے بدن پر لوہے کے دو کرتے ہوں چھاتیوں سے ہنسلی تک۔ خرچ کرنے کا عادی ( سخی ) خرچ کرتا ہے تو اس کے تمام جسم کو ( وہ کرتہ ) چھپا لیتا ہے یا ( راوی نے یہ کہا کہ ) تمام جسم پر وہ پھیل جاتا ہے اور اس کی انگلیاں اس میں چھپ جاتی ہے اور چلنے میں اس کے پاؤں کا نشان مٹتا جاتا ہے۔ لیکن بخیل جب بھی خرچ کرنے کا ارادہ کرتا ہے تو اس کرتے کا ہر حلقہ اپنی جگہ سے چمٹ جاتا ہے۔ بخیل اسے کشادہ کرنے کی کوشش کرتا ہے لیکن وہ کشادہ نہیں ہو پاتا۔ عبداللہ بن طاؤس کے ساتھ اس حدیث کو حسن بن مسلم نے بھی طاؤس سے روایت کیا ‘ اس میں دو کرتے ہیں۔' WHERE id = 1395;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبداللہ انصاری نے بیان کیا ‘ کہا کہ مجھ سے میرے باپ نے بیان کیا ‘ کہا کہ مجھ سے ثمامہ نے بیان کیا اور ان سے انس رضی اللہ عنہ نے کہ ابوبکر رضی اللہ عنہ نے ان کے پاس فرض زکوٰۃ کے ان فریضوں کے متعلق لکھا تھا جن کا اللہ نے اپنے رسول صلی اللہ علیہ وسلم کو حکم دیا ہے۔ یہ کہ جس کے اونٹوں کی زکوٰۃ ”جذعہ“ تک پہنچ جائے اور وہ ”جذعہ“ اس کے پاس نہ ہو بلکہ ”حقہ“ ہو تو اس سے زکوٰۃ میں ”حقہ“ ہی لے لیا جائے گا لیکن اس کے ساتھ دو بکریاں بھی لی جائیں گی ‘ اگر ان کے دینے میں اسے آسانی ہو ورنہ بیس درہم لیے جائیں گے۔ ( تاکہ ”حقہ“ کی کمی پوری ہو جائے ) اور اگر کسی پر زکوٰۃ میں ”حقہ“ واجب ہو اور ”حقہ“ اس کے پاس نہ ہو بلکہ ”جذعہ“ ہو تو اس سے ”جذعہ“ ہی لے لیا جائے گا اور زکوٰۃ وصول کرنے والا زکوٰۃ دینے والے کو بیس درہم یا دو بکریاں دے گا اور اگر کسی پر زکوٰۃ ”حقہ“ کے برابر واجب ہو گئی اور اس کے پاس صرف ”بنت لبون“ ہے تو اس سے ”بنت لبون“ لے لی جائے گی اور زکوٰۃ دینے والے کو دو بکریاں یا بیس درہم ساتھ میں اور دینے پڑیں گے اور اگر کسی پر زکوٰۃ ”بنت لبون“ واجب ہو اور اس کے پاس ”حقہ“ ہو تو ”حقہ“ ہی اس سے لے لیا جائے گا اور اس صورت میں زکوٰۃ وصول کرنے والا بیس درہم یا دو بکریاں زکوٰۃ دینے والے کو دے گا اور کسی کے پاس زکوٰۃ میں ”بنت لبون“ واجب ہوا اور ”بنت لبون“ اس کے پاس نہیں بلکہ ”بنت مخاض“ ہے تو اس سے ”بنت مخاض“ ہی لے لیا جائے گا۔ لیکن زکوٰۃ دینے والا اس کے ساتھ بیس درہم یا دو بکریاں دے گا۔' WHERE id = 1405;
UPDATE hadiths SET urdu = 'ہم سے معاذ بن فضالہ نے بیان کیا ‘ کہا کہ مجھ سے ہشام دستوائی نے ‘ یحییٰ سے بیان کیا۔ ان سے ہلال بن ابی میمونہ نے بیان کیا ‘ کہا کہ ہم سے عطاء بن یسار نے بیان کیا ‘ اور انہوں نے ابو سعید خدری رضی اللہ عنہ سے سنا ‘ وہ کہتے تھے کہ نبی کریم صلی اللہ علیہ وسلم ایک دن منبر پر تشریف فرما ہوئے۔ ہم بھی آپ صلی اللہ علیہ وسلم کے اردگرد بیٹھ گئے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں تمہارے متعلق اس بات سے ڈرتا ہوں کہ تم پر دنیا کی خوشحالی اور اس کی زیبائش و آرائش کے دروازے کھول دئیے جائیں گے۔ ایک شخص نے عرض کیا۔ یا رسول اللہ! کیا اچھائی برائی پیدا کرے گی؟ اس پر نبی کریم صلی اللہ علیہ وسلم خاموش ہو گئے۔ اس لیے اس شخص سے کہا جانے لگا کہ کیا بات تھی۔ تم نے نبی کریم صلی اللہ علیہ وسلم سے ایک بات پوچھی لیکن نبی کریم صلی اللہ علیہ وسلم تم سے بات نہیں کرتے۔ پھر ہم نے محسوس کیا کہ آپ صلی اللہ علیہ وسلم پر وحی نازل ہو رہی ہے۔ بیان کیا کہ پھر نبی کریم صلی اللہ علیہ وسلم نے پسینہ صاف کیا ( جو وحی نازل ہوتے وقت آپ صلی اللہ علیہ وسلم کو آنے لگتا تھا ) پھر پوچھا کہ سوال کرنے والے صاحب کہاں ہیں۔ ہم نے محسوس کیا کہ آپ صلی اللہ علیہ وسلم نے اس کے ( سوال کی ) تعریف کی۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ اچھائی برائی نہیں پیدا کرتی ( مگر بے موقع استعمال سے برائی پیدا ہوتی ہے ) کیونکہ موسم بہار میں بعض ایسی گھاس بھی اگتی ہیں جو جان لیوا یا تکلیف دہ ثابت ہوتی ہیں۔ البتہ ہریالی چرنے والا وہ جانور بچ جاتا ہے کہ خوب چرتا ہے اور جب اس کی دونوں کوکھیں بھر جاتی ہیں تو سورج کی طرف رخ کر کے پاخانہ پیشاب کر دیتا ہے اور پھر چرتا ہے۔ اسی طرح یہ مال و دولت بھی ایک خوشگوار سبزہ زار ہے۔ اور مسلمان کا وہ مال کتنا عمدہ ہے جو مسکین ‘ یتیم اور مسافر کو دیا جائے۔ یا جس طرح نبی کریم صلی اللہ علیہ وسلم نے ارشاد فرمایا۔ ہاں اگر کوئی شخص زکوٰۃ حقدار ہونے کے بغیر لیتا ہے تو اس کی مثال ایسے شخص کی سی ہے جو کھاتا ہے لیکن اس کا پیٹ نہیں بھرتا۔ اور قیامت کے دن یہ مال اس کے خلاف گواہ ہو گا۔' WHERE id = 1416;
UPDATE hadiths SET urdu = 'ہم سے یعقوب بن ابراہیم نے بیان کیا، کہا کہ ہم سے اسماعیل بن علیہ نے بیان کیا ‘ کہا کہ ہم سے خالد حذاء نے بیان کیا ‘ ان سے ابن اشوع نے ‘ ان سے عامر شعبی نے۔ کہا کہ مجھ سے مغیرہ بن شعبہ رضی اللہ عنہ کے منشی وراد نے بیان کیا۔ کہ معاویہ رضی اللہ عنہ نے مغیرہ بن شعبہ رضی اللہ عنہ کو لکھا کہ انہیں کوئی ایسی حدیث لکھئے جو آپ نے رسول اللہ صلی اللہ علیہ وسلم سے سنی ہو۔ مغیرہ رضی اللہ عنہ نے لکھا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ تمہارے لیے تین باتیں پسند نہیں کرتا۔ بلاوجہ کی گپ شپ، فضول خرچی اور لوگوں سے بہت مانگنا۔' WHERE id = 1427;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا ‘ کہا کہ ہم سے لیث نے بیان کیا ‘ ان سے عقیل نے ‘ ان سے ابن شہاب نے ‘ ان سے سالم نے کہ عبداللہ بن عمر رضی اللہ عنہما بیان کرتے تھے کہ عمر بن خطاب رضی اللہ عنہ نے ایک گھوڑا اللہ کے راستہ میں صدقہ کیا۔ پھر اسے آپ نے دیکھا کہ وہ بازار میں فروخت ہو رہا ہے۔ اس لیے ان کی خواہش ہوئی کہ اسے وہ خود ہی خرید لیں۔ اور اجازت لینے رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے۔ تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اپنا صدقہ واپس نہ لو۔ اسی وجہ سے اگر ابن عمر رضی اللہ عنہما اپنا دیا ہوا کوئی صدقہ خرید لیتے ‘ تو پھر اسے صدقہ کر دیتے تھے۔ ( اپنے استعمال میں نہ رکھتے تھے۔ باب اور حدیث میں مطابقت ظاہر ہے ) ۔' WHERE id = 1438;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا ‘ انہوں نے کہا کہ ہمیں امام مالک نے خبر دی ‘ انہیں ابن شہاب نے ‘ ان سے سعید بن مسیب اور ابوسلمہ بن عبدالرحمٰن نے بیان کیا ‘ اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا جانور سے جو نقصان پہنچے اس کا کچھ بدلہ نہیں اور کنویں کا بھی یہی حال ہے اور کان کا بھی یہی حکم ہے اور رکاز میں سے پانچواں حصہ لیا جائے۔' WHERE id = 1448;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا انہوں نے کہا کہ ہم سے حفص بن میسرہ نے بیان کیا ‘ انہوں نے کہا کہ مجھ سے موسیٰ بن عقبہ نے بیان کیا ‘ ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے صدقہ فطر نماز ( عید ) کے لیے جانے سے پہلے پہلے نکالنے کا حکم دیا تھا۔' WHERE id = 1458;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، انہوں نے کہا کہ ہم سے ابراہیم بن سعد نے بیان کیا، انہوں نے کہا کہ ہم سے زہری نے بیان کیا، ان سے سعید بن مسیب نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم سے کسی نے پوچھا کہ کون سا کام بہتر ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ اور اس کے رسول پر ایمان لانا۔ پوچھا گیا کہ پھر اس کے بعد؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ کے راستے میں جہاد کرنا۔ پھر پوچھا گیا کہ پھر اس کے بعد؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ حج مبرور۔' WHERE id = 1468;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا کہ ہم سے حماد بن زید نے بیان کیا، انہوں نے کہا کہ ہم سے عمرو بن دینار نے، ان سے طاؤس نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے مدینہ والوں کے لیے ذوالحلیفہ میقات ٹھہرایا اور شام والوں کے لیے حجفہ، یمن والوں کے لیے یلملم اور نجد والوں کے لیے قرن المنازل۔ یہ ان ملکوں کے لوگوں کے لیے ہیں اور دوسرے ان تمام لوگوں کے لیے بھی جو ان ملکوں سے گزریں۔ اور حج اور عمرہ کا ارادہ رکھتے ہوں۔ لیکن جو لوگ میقات کے اندر رہتے ہوں۔ تو وہ اپنے شہروں سے احرام باندھیں، تاآنکہ مکہ کے لوگ مکہ ہی سے احرام باندھیں۔' WHERE id = 1478;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، انہوں کہا کہ ہم سے سفیان بن عیینہ نے بیان کیا، انہوں نے کہا کہ ہم سے موسیٰ بن عقبہ نے بیان کیا، انہوں نے کہا کہ میں نے سالم بن عبداللہ سے سنا، انہوں نے کہا کہ میں نے ابن عمر رضی اللہ عنہما سے سنا (دوسری سند) امام بخاری رحمہ اللہ نے کہا اور ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، ان سے امام مالک نے، ان سے موسیٰ بن عقبہ نے، ان سے سالم بن عبداللہ نے، انہوں نے اپنے باپ سے سنا، کہ وہ کہہ رہے تھے کہ رسول اللہ صلی اللہ علیہ وسلم نے مسجد ذوالحلیفہ کے قریب ہی پہنچ کر احرام باندھا تھا۔' WHERE id = 1489;
UPDATE hadiths SET urdu = 'اور ابومعمر نے کہا کہ ہم سے عبدالوارث نے بیان کیا، انہوں نے کہا کہ ہم سے ایوب سختیانی نے نافع سے بیان کیا، انہوں نے کہا کہ عبداللہ بن عمر رضی اللہ عنہما جب ذوالحلیفہ میں صبح کی نماز پڑھ چکے تو اپنی اونٹنی پر پالان لگانے کا حکم فرمایا، سواری لائی گئی تو آپ اس پر سوار ہوئے اور جب وہ آپ کو لے کر کھڑی ہو گئی تو آپ کھڑے ہو کر قبلہ رو ہو گئے اور پھر لبیک کہنا شروع کیا تاآنکہ حرم میں داخل ہو گئے۔ وہاں پہنچ کر آپ نے لبیک کہنا بند کر دیا۔ پھر ذی طویٰ میں تشریف لا کر رات وہیں گزارتے صبح ہوتی تو نماز پڑھتے اور غسل کرتے ( پھر مکہ میں داخل ہوتے ) آپ یقین کے ساتھ یہ جانتے تھے کہ رسول اللہ صلی اللہ علیہ وسلم نے بھی اسی طرح کیا تھا۔ عبدالوارث کی طرح اس حدیث کو اسماعیل نے بھی ایوب سے روایت کیا۔ اس میں غسل کا ذکر ہے۔' WHERE id = 1500;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، انہوں نے کہا کہ ہم سے غندر نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، ان سے حکم نے، ان سے علی بن حسین (زین العابدین) نے اور ان سے مروان بن حکم نے بیان کیا کہ عثمان اور علی رضی اللہ عنہما کو میں نے دیکھا ہے۔ عثمان رضی اللہ عنہ حج اور عمرہ کو ایک ساتھ ادا کرنے سے روکتے تھے لیکن علی رضی اللہ عنہ نے اس کے باوجود دونوں کا ایک ساتھ احرام باندھا اور کہا «لبيك بعمرة وحجة» آپ نے فرمایا تھا کہ میں کسی ایک شخص کی بات پر رسول اللہ صلی اللہ علیہ وسلم کی حدیث کو نہیں چھوڑ سکتا۔' WHERE id = 1510;
UPDATE hadiths SET urdu = 'ہم سے یعقوب بن ابراہیم نے بیان کیا، ان سے اسماعیل بن علیہ نے بیان کیا، انہیں ایوب سختیانی نے خبر دی، انہیں نافع نے، انہوں نے بیان کیا کہ جب عبداللہ بن عمر رضی اللہ عنہما حرم کی سرحد کے قریب پہنچتے تو تلبیہ کہنا بند کر دیتے۔ رات ذی طویٰ میں گزارتے، صبح کی نماز وہیں پڑھتے اور غسل کرتے ( پھر مکہ میں داخل ہوتے ) آپ بیان کرتے تھے کہ نبی کریم صلی اللہ علیہ وسلم بھی اسی طرح کیا کرتے تھے۔' WHERE id = 1520;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، ان سے امام مالک رحمہ اللہ نے بیان کیا، ان سے ابن شہاب نے بیان کیا، ان سے سالم بن عبداللہ نے کہ عبداللہ بن محمد بن ابی بکر نے انہیں خبر دی، انہیں عبداللہ بن عمر رضی اللہ عنہما نے خبر دی اور انہیں نبی کریم صلی اللہ علیہ وسلم کی پاک بیوی عائشہ صدیقہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا کہ تجھے معلوم ہے جب تیری قوم نے کعبہ کی تعمیر کی تو بنیاد ابراہیم کو چھوڑ دیا تھا۔ میں نے عرض کیا یا رسول اللہ! پھر آپ بنیاد ابراہیم پر اس کو کیوں نہیں بنا دیتے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر تمہاری قوم کا زمانہ کفر سے بالکل نزدیک نہ ہوتا تو میں بیشک ایسا کر دیتا۔ عبداللہ بن عمر رضی اللہ عنہما نے کہا کہ اگر عائشہ صدیقہ رضی اللہ عنہا نے یہ بات رسول اللہ صلی اللہ علیہ وسلم سے سنی ہے ( اور یقیناً عائشہ رضی اللہ عنہا سچی ہیں ) تو میں سمجھتا ہوں یہی وجہ تھی جو نبی کریم صلی اللہ علیہ وسلم حطیم سے متصل جو دیواروں کے کونے ہیں ان کو نہیں چومتے تھے۔ کیونکہ خانہ کعبہ ابراہیمی بنیادوں پر پورا نہ ہوا تھا۔' WHERE id = 1530;
UPDATE hadiths SET urdu = 'ہم سے احمد بن حفص نے بیان کیا، کہا کہ ہم سے میرے والد نے بیان کیا، کہا کہ ہم سے ابراہیم بن طہمان نے بیان کیا، ان سے حجاج بن حجاج اسلمی نے، ان سے قتادہ نے، ان سے عبداللہ بن ابی عتبہ نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے فرمایا بیت اللہ کا حج اور عمرہ یاجوج اور ماجوج کے نکلنے کے بعد بھی ہوتا رہے گا۔ عبداللہ بن ابی عتبہ کے ساتھ اس حدیث کو ابان اور عمران نے قتادہ سے روایت کیا اور عبدالرحمٰن نے شعبہ کے واسطہ سے یوں بیان کیا کہ قیامت اس وقت تک قائم نہیں ہو گی جب تک بیت اللہ کا حج بند نہ ہو جائے۔ امام بخاری رحمہ اللہ نے کہا کہ پہلی روایت زیادہ راویوں نے کی ہے اور قتادہ نے عبداللہ بن عتبہ سے سنا اور عبداللہ نے ابو سعید خدری رضی اللہ عنہ سے سنا۔' WHERE id = 1540;
UPDATE hadiths SET urdu = 'ہم سے اصبغ بن فرج نے بیان کیا، کہا کہ مجھے عبداللہ بن وہب نے خبر دی، انہیں یونس نے، انہیں زہری نے، انہیں سالم نے اور ان سے ان کے والد نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو دیکھا۔ جب آپ صلی اللہ علیہ وسلم مکہ تشریف لاتے تو پہلے طواف شروع کرتے وقت حجر اسود کو بوسہ دیتے اور سات چکروں میں سے پہلے تین چکروں میں رمل کرتے تھے۔' WHERE id = 1550;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا کہ ہم سے خالد بن عبداللہ نے بیان کیا، کہا کہ ہم سے خالد حذاء نے بیان کیا، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا نبی کریم صلی اللہ علیہ وسلم نے بیت اللہ کا طواف ایک اونٹنی پر سوار رہ کر کیا۔ جب بھی آپ صلی اللہ علیہ وسلم حجر اسود کے سامنے پہنچتے تو کسی چیز سے اس کی طرف اشارہ کرتے اور تکبیر کہتے۔ خالد طحان کے ساتھ اس حدیث کو ابراہیم بن طہمان نے بھی خالد حذاء سے روایت کیا ہے۔' WHERE id = 1560;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، انہوں نے کہا کہ ہم سے شعبہ نے بیان کیا انہوں کہا کہ عم سے عمرو بن دینار نے بیان کیا، انہوں نے کہا کہ میں نے ابن عمر رضی اللہ عنہما سے سنا، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم ( مکہ میں ) تشریف لائے تو آپ صلی اللہ علیہ وسلم نے خانہ کعبہ کا سات چکروں سے طواف کیا اور مقام ابراہیم کے پیچھے دو رکعت نماز پڑھی پھر صفا کی طرف ( سعی کرنے ) گئے اور اللہ تعالیٰ نے فرمایا ہے کہ تمہارے لیے رسول اللہ صلی اللہ علیہ وسلم کی زندگی بہترین نمونہ ہے۔' WHERE id = 1572;
UPDATE hadiths SET urdu = 'ہم سے یعقوب بن ابراہیم نے بیان کیا، کہا کہ ہم سے اسماعیل بن علیہ نے بیان کیا، ان سے ایوب سختیانی نے، ان سے نافع نے کہ ابن عمر رضی اللہ عنہما کے لڑکے عبداللہ بن عبداللہ ان کے یہاں گئے۔ حج کے لیے سواری گھر میں کھڑی ہوئی تھی۔ انہوں نے کہا کہ مجھے خطرہ ہے کہ اس سال مسلمانوں میں آپس میں لڑائی ہو جائے گی اور آپ کو وہ بیت اللہ سے روک دیں گے۔ اس لیے اگر آپ نہ جاتے تو بہتر ہوتا۔ ابن عمر رضی اللہ عنہما نے جواب دیا کہ رسول اللہ صلی اللہ علیہ وسلم بھی تشریف لے گئے تھے ( عمرہ کرنے صلح حدیبیہ کے موقع پر ) اور کفار قریش نے آپ کو بیت اللہ تک پہنچنے سے روک دیا تھا۔ اس لیے اگر مجھے بھی روک دیا گیا تو میں بھی وہی کام کروں گا جو رسول اللہ صلی اللہ علیہ وسلم نے کیا تھا اور تمہارے لیے رسول اللہ صلی اللہ علیہ وسلم کی زندگی بہترین نمونہ ہے۔ پھر آپ نے فرمایا کہ میں تمہیں گواہ بناتا ہوں کہ میں نے اپنے عمرہ کے ساتھ حج ( اپنے اوپر ) واجب کر لیا ہے۔ انہوں نے بیان کیا کہ پھر آپ مکہ آئے اور دونوں عمرہ اور حج کے لیے ایک ہی طواف کیا' WHERE id = 1583;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، کہا کہ ہم سے عبدالوہاب ثقفی نے بیان کیا۔ (دوسری سند) اور مجھ سے خلیفہ بن خیاط نے بیان کیا کہ ہم سے عبدالوہاب ثقفی نے بیان کیا، کہا کہ ہم سے حبیب معلم نے بیان کیا، ان سے عطاء بن ابی رباح نے اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم اور آپ کے اصحاب نے حج کا احرام باندھا۔ نبی کریم صلی اللہ علیہ وسلم اور طلحہ کے سوا اور کسی کے ساتھ قربانی نہیں تھی، علی رضی اللہ عنہ یمن سے آئے تھے اور ان کے ساتھ بھی قربانی تھی۔ اس لیے نبی کریم صلی اللہ علیہ وسلم نے حکم دیا کہ ( سب لوگ اپنے حج کے احرام کو ) عمرہ کا کر لیں۔ پھر طواف اور سعی کے بعد بال ترشوا لیں اور احرام کھول ڈالیں لیکن وہ لوگ اس حکم سے مستثنیٰ ہیں جن کے ساتھ قربانی ہو۔ اس پر صحابہ نے کہا کہ ہم منیٰ میں اس طرح جائیں گے کہ ہمارے ذکر سے منی ٹپک رہی ہو۔ یہ بات جب رسول اللہ صلی اللہ علیہ وسلم کو معلوم ہوئی تو آپ نے فرمایا، اگر مجھے پہلے معلوم ہوتا تو میں قربانی کا جانور ساتھ نہ لاتا اور جب قربانی کا جانور ساتھ نہ ہوتا تو میں بھی ( عمرہ اور حج کے درمیان ) احرام کھول ڈالتا اور عائشہ رضی اللہ عنہا ( اس حج میں ) حائضہ ہو گئی تھیں۔ اس لیے انہوں نے بیت اللہ کہ طواف کے سوا اور دوسرے ارکان حج ادا کئے۔ پھر پاک ہو لیں تو طواف بھی کیا۔ انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے شکایت کی کہ آپ سب لوگ تو حج اور عمرہ دونوں کر کے جا رہے ہیں لیکن میں نے صرف حج ہی کیا ہے۔ چنانچہ رسول اللہ صلی اللہ علیہ وسلم نے عبدالرحمٰن بن ابی بکر کو حکم دیا کہ انہیں تنعیم لیے جائیں ( اور وہاں سے عمرہ کا احرام باندھیں ) اس طرح عائشہ رضی اللہ عنہا نے حج کے بعد عمرہ کیا۔' WHERE id = 1593;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، ان سے امام مالک رحمہ اللہ نے، ان سے ابوالنضر نے، ان سے عبداللہ بن عباس رضی اللہ عنہما کے غلام عمیر نے، ان سے ام فضل بنت حارث رضی اللہ عنہا نے کہا کہ ان کے یہاں لوگوں کا عرفات کے دن رسول اللہ صلی اللہ علیہ وسلم کے روزے سے متعلق کچھ اختلاف ہو گیا، بعض نے کہا کہ آپ صلی اللہ علیہ وسلم ( عرفہ کے دن ) روزے سے ہیں اور بعض کہتے ہیں کہ نہیں، اس لیے انہوں نے آپ کے پاس دودھ کا ایک پیالہ بھیجا، نبی کریم صلی اللہ علیہ وسلم اس وقت اونٹ پر سوا ہو کر عرفات میں وقوف فرما رہے تھے، آپ نے وہ دودھ پی لیا۔' WHERE id = 1603;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی العلاء نے بیان کیا، کہا ہم سے ابن ابی ذئب نے بیان کیا، ان سے زہری نے ان سے سالم بن عبداللہ بن عمر رضی اللہ عنہما نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ ہم سے آدم بن ابی العلاء نے بیان کیا ، کہا ہم سے ابن ابی ذئب نے بیان کیا ، ان سے زہری نے ان سے سالم بن عبداللہ بن عمر ؓ نے اور ان سے عبداللہ بن عمر ؓ نے بیان کیا کہ مزدلفہ میں نبی کریم ﷺ نے مغرب اور عشاء ایک ساتھ ملا کر پڑھیں تھیں ہر نماز الگ الگ تکبیر کے ساتھ نہ ان دونوں کے درمیان کوئی نفل و سنت پڑھی تھی اور نہ ان کے بعد ۔' WHERE id = 1614;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن رجاء نے بیان کیا، کہا کہ ہم سے اسرائیل نے بیان کیا، ان سے ابواسحٰق نے، ان سے عبدالرحمٰن بن یزید نے کہ ہم عبداللہ بن مسعود رضی اللہ عنہ کے ساتھ مکہ کی طرف نکلے ( حج شروع کیا ) پھر جب ہم مزدلفہ آئے تو آپ نے دو نمازیں ( اس طرح ایک ساتھ ) پڑھیں کہ ہر نماز ایک الگ اذان اور ایک الگ اقامت کے ساتھ تھی اور رات کا کھانا دونوں کے درمیان میں کھایا، پھر طلوع صبح کے ساتھ ہی آپ نے نماز فجر پڑھی، کوئی کہتا تھا کہ ابھی صبح صادق نہیں ہوئی اور کچھ لوگ کہہ رہے تھے کہ ہو گئی۔ اس کے بعد عبداللہ بن مسعود رضی اللہ عنہ نے فرمایا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا تھا یہ دونوں نمازیں اس مقام سے ہٹا دی گئیں ہیں، یعنی مغرب اور عشاء، مزدلفہ میں اس وقت داخل ہوں کہ اندھیرا ہو جائے اور فجر کی نماز اس وقت۔ پھر عبداللہ اجالے تک وہیں مزدلفہ میں ٹھہرے رہے اور کہا کہ اگر امیرالمؤمنین عثمان رضی اللہ عنہ اس وقت چلیں تو یہ سنت کے مطابق ہو گا۔ ( حدیث کے راوی عبدالرحمٰن بن یزید نے کہا ) میں نہیں کہہ سکتا کہ یہ الفاظ ان کی زبان سے پہلے نکلے یا عثمان رضی اللہ عنہ کی روانگی پہلے شروع ہوئی، آپ دسویں تاریخ تک جمرہ عقبہ کی رمی تک برابر لبیک پکارتے رہے۔' WHERE id = 1624;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے عبیداللہ نے کہ مجھے نافع نے خبر دی انہیں ابن عمر رضی اللہ عنہما نے کہ حفصہ رضی اللہ عنہا نے بیان کیا، کہا میں نے کہا: یا رسول اللہ! اور لوگ تو حلال ہو گئے لیکن آپ حلال نہیں ہوئے، اس کی کیا وجہ ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں نے اپنے سر کے بالوں کو جما لیا ہے اور اپنی ہدی کو قلادہ پہنا دیا ہے، اس لیے جب تک حج سے بھی حلال نہ ہو جاؤں میں ( درمیان میں ) حلال نہیں ہو سکتا، ( گوند لگا کر سر کے بالوں کا جما لینا اس کو تلبید کہتے ہیں ) ۔' WHERE id = 1636;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ نے بیان کیا، انہوں نے کہا کہ ہم سے سفیان نے بیان کیا، ان سے ابن ابی نجیح نے، ان سے مجاہد نے، ان سے عبدالرحمٰن بن ابی لیلیٰ نے اور ان سے علی رضی اللہ عنہ نے بیان کیا کہ مجھے رسول اللہ صلی اللہ علیہ وسلم نے ان قربانی کے جانوروں کے جھول اور ان کے چمڑے کو صدقہ کرنے کا حکم دیا تھا جن کی قربانی میں نے کر دی تھی۔' WHERE id = 1646;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا کہا کہ، ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے ابن جریج نے بیان کیا، کہا کہ مجھے حسن بن مسلم اور عبدالکریم جزری نے خبر دی کہ مجاہد نے ان دونوں کو خبر دی، انہیں عبدالرحمٰن بن ابی لیلیٰ نے خبر دی، انہیں علی رضی اللہ عنہ نے خبر دی کہ نبی کریم صلی اللہ علیہ وسلم نے انہیں حکم دیا تھا کہ آپ صلی اللہ علیہ وسلم کی قربانی کے اونٹوں کی نگرانی کریں اور یہ کہ آپ صلی اللہ علیہ وسلم کے قربانی کے جانوروں کی ہر چیز گوشت چمڑے اور جھول خیرات کر دیں اور قصائی کی مزدوری اس میں سے نہ دیں۔' WHERE id = 1656;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو امام مالک نے خبر دی، انہیں نافع نے، انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے دعا کی اے اللہ! سر منڈوانے والوں پر رحم فرما! صحابہ رضی اللہ عنہم نے عرض کی اور کتروانے والوں پر؟ نبی کریم صلی اللہ علیہ وسلم نے اب بھی دعا کی اے اللہ سر منڈوانے والوں پر رحم فرما! صحابہ رضی اللہ عنہم نے پھر عرض کی اور کتروانے والوں پر؟ اب آپ صلی اللہ علیہ وسلم نے فرمایا اور کتروانے والوں پر بھی، لیث نے کہا کہ مجھ سے نافع نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، اللہ نے سر منڈوانے والوں پر رحم کیا ایک یا دو مرتبہ، انہوں نے بیان کیا کہ عبیداللہ نے کہا کہ مجھ سے نافع نے بیان کیا کہ چوتھی مرتبہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا تھا کہ کتروانے والوں پر بھی۔' WHERE id = 1666;
UPDATE hadiths SET urdu = 'ہم سے سعید بن یحییٰ بن سعید نے بیان کیا، ان سے ان کے والد نے بیان کیا، ان سے ابن جریج نے بیان کیا، ان سے زہری نے بیان کیا، ان سے عیسیٰ بن طلحہ نے اور ان سے عبداللہ بن عمرو بن العاص رضی اللہ عنہما نے کہ جب رسول اللہ صلی اللہ علیہ وسلم دسویں تاریخ کو منیٰ میں خطبہ دے رہے تھے تو وہ وہاں موجود تھے۔ ایک شخص نے اس وقت کھڑے ہو کر پوچھا کہ میں اس خیال میں تھا کہ فلاں کام فلاں سے پہلے ہے پھر دوسرا کھڑا ہوا اور کہا کہ میرا خیال تھا کہ فلاں کام فلاں سے پہلے ہے، چنانچہ میں نے قربانی سے پہلے سر منڈا لیا، رمی جمار سے پہلے قربانی کر لی، اور مجھے اس میں شک ہوا۔ تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا، اب کر لو۔ ان سب میں کوئی حرج نہیں۔ اسی طرح کے دوسرے سوالات بھی آپ صلی اللہ علیہ وسلم سے کئے گئے آپ صلی اللہ علیہ وسلم نے ان سب کے جواب میں یہی فرمایا کہ کوئی حرج نہیں اب کر لو۔' WHERE id = 1676;
UPDATE hadiths SET urdu = 'محمد بن کثیر نے بیان کیا، کہا کہ ہم کو سفیان ثوری نے خبر دی، انہیں اعمش نے، انہیں ابراہیم نے اور ان سے عبدالرحمٰن بن زید نے بیان کیا کہ عبداللہ رضی اللہ عنہ نے وادی کے نشیب ( بطن وادی ) میں کھڑے ہو کر کنکری ماری تو میں نے کہا، اے ابوعبدالرحمٰن! کچھ لوگ تو وادی کے بالائی علاقہ سے کنکریاں مارتے ہیں، اس کا جواب انہوں نے یہ دیا کہ اس ذات کی قسم! جس کے سوا کوئی معبود نہیں یہی ( بطن وادی ) ان کے کھڑے ہونے کی جگہ ہے ( رمی کرتے وقت ) جن پر سورۃ البقرہ نازل ہوئی تھی صلی اللہ علیہ وسلم ۔ عبداللہ بن ولید نے بیان کیا کہ ان سے سفیان ثوری نے اور ان سے اعمش نے یہی حدیث بیان کی۔' WHERE id = 1686;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہمیں امام مالک نے خبر دی، انہیں عبدالرحمٰن بن قاسم نے، انہیں ان کے والد نے اور انہیں عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ صفیہ بنت حی رضی اللہ عنہا ( حجۃ الوداع کے موقع پر ) حائضہ ہو گئیں تو میں نے اس کا ذکر نبی کریم صلی اللہ علیہ وسلم سے کیا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر تو یہ ہمیں روکیں گی، لوگوں نے کہا کہ انہوں نے طواف افاضہ کر لیا ہے، تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر کوئی فکر نہیں۔' WHERE id = 1696;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا کہ ہم کو امام مالک نے خبر دی، انہیں ابوبکر بن عبدالرحمٰن کے غلام سمی نے خبر دی، انہیں ابوصالح سمان نے خبر دی اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ایک عمرہ کے بعد دوسرا عمرہ دونوں کے درمیان کے گناہوں کا کفارہ ہے اور حج مبرور کی جزا جنت کے سوا اور کچھ نہیں ہے۔' WHERE id = 1709;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنی نے بیان کیا، ان سے عبدالوہاب بن عبدالمجید نے، ان سے حبیب معلم نے، ان سے عطاء بن ابی رباح نے اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم اور آپ کے اصحاب نے حج کا احرام باندھا تھا اور نبی کریم صلی اللہ علیہ وسلم اور طلحہ رضی اللہ عنہ کے سوا قربانی کسی کے پاس نہیں تھی۔ ان ہی دنوں میں علی رضی اللہ عنہ یمن سے آئے تو ان کے ساتھ بھی قربانی تھی۔ انہوں نے کہا کہ جس چیز کا احرام رسول اللہ صلی اللہ علیہ وسلم نے باندھا ہے میرا بھی احرام وہی ہے، نبی کریم صلی اللہ علیہ وسلم نے اپنے اصحاب کو ( مکہ میں پہنچ کر ) اس کی اجازت دے دی تھی کہ اپنے حج کو عمرہ میں تبدیل کر دیں اور بیت اللہ کا طواف اور صفا و مروہ کی سعی کر کے بال ترشوا لیں اور احرام کھول دیں، لیکن وہ لوگ ایسا نہ کریں جن کے ساتھ قربانی ہو۔ اس پر لوگوں نے کہا کہ ہم منیٰ سے حج کے لیے اس طرح سے جائیں گے کہ ہمارے ذکر سے منی ٹپک رہی ہو۔ یہ بات رسول اللہ صلی اللہ علیہ وسلم تک پہنچی تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ جو بات اب ہوئی اگر پہلے سے معلوم ہوتی تو میں اپنے ساتھ ہدی نہ لاتا اور اگر میرے ساتھ ہدی نہ ہوتی تو ( افعال عمرہ ادا کرنے کے بعد ) میں بھی احرام کھول دیتا۔ عائشہ رضی اللہ عنہا ( اس حج میں ) حائضہ ہو گئی تھیں اس لیے انہوں نے اگرچہ تمام مناسک ادا کئے لیکن بیت اللہ کا طواف نہیں کیا۔ پھر جب وہ پاک ہو گئیں اور طواف کر لیا تو عرض کی یا رسول اللہ! سب لوگ حج اور عمرہ دونوں کر کے واپس ہو رہے ہیں لیکن میں صرف حج کر سکی ہوں، آپ صلی اللہ علیہ وسلم نے اس پر عبدالرحمٰن بن ابوبکر رضی اللہ عنہما سے کہا کہ انہیں ہمراہ لے کر تنعیم جائیں اور عمرہ کرا لائیں، یہ عمرہ حج کے بعد ذی الحجہ کے ہی مہینہ میں ہوا تھا۔ نبی کریم صلی اللہ علیہ وسلم جب جمرہ عقبہ کی رمی کر رہے تھے تو سراقہ بن مالک بن جعشم آپ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور پوچھا کہ یا رسول اللہ! کیا یہ ( عمرہ اور حج کے درمیان احرام کھول دینا ) صرف آپ ہی کے لیے ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ نہیں بلکہ ہمیشہ کے لیے ہے۔' WHERE id = 1720;
UPDATE hadiths SET urdu = 'ہم سے معلی بن اسد نے بیان کیا، کہا ہم سے یزید بن زریع نے بیان کیا، ان سے خالد نے بیان کیا، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم مکہ تشریف لائے تو بنو عبدالمطلب کے چند بچوں نے آپ صلی اللہ علیہ وسلم کا استقبال کیا، آپ صلی اللہ علیہ وسلم نے ایک بچے کو ( اپنی سواری کے ) آگے بٹھا لیا اور دوسرے کو پیچھے۔' WHERE id = 1731;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے جویریہ نے بیان کیا ان سے نافع نے کہ عبداللہ رضی اللہ عنہ کے کسی بیٹے نے ان سے کہا تھا کاش آپ اس سال رک جاتے ( تو اچھا ہوتا اسی اوپر والے واقعہ کی طرف اشارہ ہے ) ۔' WHERE id = 1741;
UPDATE hadiths SET urdu = 'اور محمد بن یوسف سے روایت ہے کہ ہم کو ورقاء نے بیان کیا، ان سے ابن ابی نجیح نے بیان کیا، ان سے مجاہد نے بیان کیا، انہیں عبدالرحمٰن بن ابی لیلیٰ نے خبر دی اور انہیں کعب بن عجرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے انہیں دیکھا تو جوئیں ان کے چہرہ پر گر رہی تھی، پھر یہی حدیث بیان کی۔' WHERE id = 1751;
UPDATE hadiths SET urdu = '(چوتھی سند) اور ہم سے اصبغ نے بیان کیا انہوں نے کہا کہ مجھ سے عبداللہ بن وہب نے بیان کیا، انہوں نے کہا کہ ہم سے یونس نے، ان سے ابن شہاب نے اور ان سے سالم نے بیان کیا، کہ عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا اور ان سے حفصہ رضی اللہ عنہا نے بیان کیا تھا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ پانچ جانور ایسے ہیں جنہیں مارنے میں کوئی گناہ نہیں کوا، چیل، چوہا، بچھو اور کاٹ کھانے والا کتا۔' WHERE id = 1761;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یزید نے بیان کیا، انہوں نے کہا ہم سے لیث نے بیان کیا، ان سے نافع نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ ایک شخص نے کھڑے ہو کر پوچھا یا رسول اللہ! حالت احرام میں ہمیں کون سے کپڑے پہننے کی اجازت دیتے ہیں؟ تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ نہ قمیص پہنو نہ پاجامے، نہ عمامے اور نہ برنس۔ اگر کسی کے جوتے نہ ہوں تو موزوں کو ٹخنوں کے نیچے سے کاٹ کر پہن لے۔ اسی طرح کوئی ایسا لباس نہ پہنو جس میں زعفران یا ورس لگا ہو۔ احرام کی حالت میں عورتیں منہ پر نقاب نہ ڈالیں اور دستانے بھی نہ پہنیں۔ لیث کے ساتھ اس روایت کی متابعت موسیٰ بن عقبہ اور اسماعیل بن ابراہیم بن عقبہ اور جویریہ اور ابن اسحاق نے نقاب اور دستانوں کے ذکر کے سلسلے میں کی ہے۔ عبیداللہ رحمہ اللہ نے «ولا ورس» کا لفظ بیان کیا وہ کہتے تھے کہ احرام کی حالت میں عورت منہ پر نہ نقاب ڈالے اور نہ دستانے استعمال کرے اور امام مالک نے نافع سے بیان کیا اور انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے بیان کیا کہ احرام کی حالت میں عورت نقاب نہ ڈالے اور لیث بن ابی سلیم نے مالک کی طرح روایت کی ہے۔' WHERE id = 1771;
UPDATE hadiths SET urdu = 'ایک شخص نے دوسرے شخص کے ہاتھ میں دانت سے کاٹا تھا، دوسرے نے جو اپنا ہاتھ کھینچا تو اس کا دانت اکھڑ گیا نبی کریم صلی اللہ علیہ وسلم نے اس کا کوئی بدلہ نہیں دلوایا۔' WHERE id = 1781;
UPDATE hadiths SET urdu = 'ہم سے عبدالرحمٰن بن یونس نے بیان کیا، ان سے حاتم بن اسماعیل نے بیان کیا، ان سے محمد بن یوسف نے اور ان سے سائب بن یزید رضی اللہ عنہ نے کہ مجھے رسول اللہ صلی اللہ علیہ وسلم کے ساتھ حج کرایا گیا تھا۔ میں اس وقت سات سال کا تھا۔' WHERE id = 1791;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، کہا ہم سے عبدالوارث نے بیان کیا، ان سے ابوالتیاح نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم جب مدینہ ( ہجرت کر کے ) تشریف لائے تو نبی کریم صلی اللہ علیہ وسلم نے مسجد کی تعمیر کا حکم دیا، آپ صلی اللہ علیہ وسلم نے فرمایا اے بنو نجار تم ( اپنی اس زمین کی ) مجھ سے قیمت لے لو لیکن انہوں نے عرض کی کہ ہم اس کی قیمت صرف اللہ تعالیٰ سے مانگتے ہیں۔ پھر نبی کریم صلی اللہ علیہ وسلم نے مشرکین کی قبروں کے متعلق فرمایا اور وہ اکھاڑی دی گئیں، ویرانہ کے متعلق حکم دیا اور وہ برابر کر دیا گیا، کھجور کے درختوں کے متعلق حکم دیا اور وہ کاٹ دیئے گئے اور وہ درخت قبلہ کی طرف بچھا دیئے گئے۔' WHERE id = 1801;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے ابن شہاب زہری نے، کہا کہ مجھے عروہ نے خبر دی اور انہوں نے اسامہ بن زید رضی اللہ عنہما سے سنا کہ نبی کریم صلی اللہ علیہ وسلم مدینہ کے محلات میں سے ایک محل یعنی اونچے مکان پر چڑھے پھر فرمایا کہ جو کچھ میں دیکھ رہا ہوں کیا تمہیں نظر آ رہا ہے؟ میں بوندوں کے گرنے کی جگہ کی طرح تمہارے گھروں پر فتنوں کے نازل ہونے کی جگہوں کو دیکھ رہا ہوں۔ اس روایت کی متابعت معمر اور سلیمان بن کثیر نے زہری کے واسطہ سے کی ہے۔' WHERE id = 1811;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، ان سے یحییٰ قطان نے بیان کیا، ان سے عبیداللہ بن عمر نے بیان کیا کہ مجھ سے خبیب بن عبدالرحمٰن نے بیان کیا، ان سے حفص بن عاصم نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا میرے گھر اور میرے منبر کے درمیان ( والی جگہ ) جنت کے باغوں میں سے ایک باغ ہے اور میرا منبر قیامت کے دن میرے حوض ( کوثر ) پر ہو گا۔' WHERE id = 1821;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، کہا ہم سے اسماعیل بن جعفر نے بیان کیا، ان سے ابوسہل نافع بن مالک نے، ان سے ان کے والد نے، ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا جب رمضان آتا ہے تو جنت کے دروازے کھول دیئے جاتے ہیں۔' WHERE id = 1831;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے جبلہ بن سحیم نے بیان کیا، کہ میں نے ابن عمر رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا مہینہ اتنے دنوں اور اتنے دنوں کا ہوتا ہے۔ تیسری مرتبہ کہتے ہوئے آپ صلی اللہ علیہ وسلم نے انگھوٹھے کو دبا لیا۔' WHERE id = 1841;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبیداللہ نے بیان کیا، انہوں نے کہا ہم سے عبدالعزیز بن ابی حازم نے بیان کیا، ان سے ابوحازم نے بیان کیا اور ان سے سہل بن سعد رضی اللہ عنہ نے بیان کیا کہ میں سحری اپنے گھر کھاتا پھر جلدی کرتا تاکہ نماز نبی کریم صلی اللہ علیہ وسلم کے ساتھ مل جائے۔' WHERE id = 1852;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، انہوں نے کہا ہم کو عبداللہ بن مبارک نے خبر دی، انہوں نے کہا ہم کو معمر نے خبر دی، انہوں نے کہا ہم سے زہری نے بیان کیا، ان سے عطاء بن زید نے، ان سے حمران نے انہوں نے عثمان بن عفان رضی اللہ عنہ کو وضو کرتے دیکھا، آپ نے ( پہلے ) اپنے دونوں ہاتھوں پر تین مرتبہ پانی ڈالا پھر کلی کی اور ناک صاف کی، پھر تین مرتبہ چہرہ دھویا، پھر دایاں ہاتھ کہنی تک دھویا، پھر بایاں ہاتھ کہنی تک دھویا تین تین مرتبہ، اس کے بعد اپنے سر کا مسح کیا اور تین مرتبہ داہنا پاؤں دھویا، پھر تین مرتبہ بایاں پاؤں دھویا، آخر میں کہا کہ جس طرح میں نے وضو کیا ہے میں نے رسول اللہ صلی اللہ علیہ وسلم کو بھی اسی طرح وضو کرتے دیکھا ہے، پھر آپ نے فرمایا تھا کہ جس نے میری طرح وضو کیا پھر دو رکعت نماز ( تحیۃ الوضو ) اس طرح پڑھی کہ اس نے دل میں کسی قسم کے خیالات و وساوس گزرنے نہیں دیئے تو اس کے اگلے گناہ معاف کر دیئے جائیں گے۔' WHERE id = 1864;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، کہا کہ ہم کو امام مالک نے خبر دی، انہیں ابن شہاب نے، انہیں عبیداللہ بن عبداللہ بن عتبہ نے اور انہیں ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم ( فتح مکہ کے موقع پر ) مکہ کی طرف رمضان میں چلے تو آپ صلی اللہ علیہ وسلم روزہ سے تھے لیکن جب کدید پہنچے تو روزہ رکھنا چھوڑ دیا۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) نے کہا کہ عسفان اور قدید کے درمیان کدید ایک تالاب ہے۔' WHERE id = 1874;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے عبدالواحد نے بیان کیا، ان سے سلیمان شیبانی نے بیان کیا، کہا کہ میں نے عبداللہ بن ابی اوفی رضی اللہ عنہ سے سنا، انہوں نے کہا کہ ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ سفر میں جا رہے تھے، آپ صلی اللہ علیہ وسلم روزے سے تھے، جب سورج غروب ہوا تو آپ نے ایک شخص سے فرمایا کہ اتر کر ہمارے لیے ستو گھول، انہوں نے کہا یا رسول اللہ! تھوڑی دیر اور ٹھہرئیے، آپ صلی اللہ علیہ وسلم نے فرمایا کہ اتر کر ہمارے لیے ستو گھول انہوں نے پھر یہی کہا کہ یا رسول اللہ! ابھی تو دن باقی ہے، آپ صلی اللہ علیہ وسلم نے فرمایا کہ اتر کر ستو ہمارے لیے گھول، چنانچہ انہوں نے اتر کر ستو گھولا۔ نبی کریم صلی اللہ علیہ وسلم نے پھر فرمایا کہ جب تم دیکھو کہ رات کی تاریکی ادھر سے آ گئی تو روزہ دار کو روزہ افطار کر لینا چاہئے۔ آپ صلی اللہ علیہ وسلم نے اپنی انگلی سے مشرق کی طرف اشارہ کیا۔' WHERE id = 1886;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن موسیٰ نے بیان کیا، ان سے عبدالرزاق نے بیان کیا، ان سے معمر نے، ان سے ہمام نے اور انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے دوبار فرمایا، تم لوگ وصال سے بچو! عرض کیا گیا کہ آپ تو وصال کرتے ہیں، اس پر آپ نے فرمایا کہ رات میں مجھے میرا رب کھلاتا اور وہی مجھے سیراب کرتا ہے۔ پس تم اتنی ہی مشقت اٹھاؤ جتنی تم طاقت رکھتے ہو۔' WHERE id = 1896;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا کہ ہم کو شعیب نے خبر دی، انہیں زہری نے، کہا کہ مجھے سعید بن مسیب اور ابوسلمہ بن عبدالرحمٰن نے خبر دی کہ عبداللہ بن عمرو رضی اللہ عنہما نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم تک میری یہ بات پہنچا گئی کہ ”اللہ کی قسم! زندگی بھر میں دن میں تو روزے رکھوں گا۔ اور ساری رات عبادت کروں گا“ میں نے رسول اللہ صلی اللہ علیہ وسلم سے عرض کی، میرے ماں باپ آپ صلی اللہ علیہ وسلم پر فدا ہوں، ہاں میں نے یہ کہا ہے، آپ صلی اللہ علیہ وسلم نے فرمایا لیکن تیرے اندر اس کی طاقت نہیں، اس لیے روزہ بھی رکھ اور بے روزہ بھی رہ۔ عبادت بھی کر لیکن سوؤ بھی اور مہینے میں تین دن کے روزے رکھا کر۔ نیکیوں کا بدلہ دس گنا ملتا ہے، اس طرح یہ ساری عمر کا روزہ ہو جائے گا، میں نے کہا کہ میں اس سے بھی زیادہ کی طاقت رکھتا ہوں، آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر ایک دن روزہ رکھا کر اور دو دن کے لیے روزے چھوڑ دیا کر۔ میں نے پھر کہا کہ میں اس سے بھی زیادہ کی طاقت رکھتا ہوں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اچھا ایک دن روزہ رکھ اور ایک دن بے روزہ کے رہ کہ داؤد علیہ السلام کا روزہ ایسا ہی تھا۔ اور روزہ کا یہ سب سے افضل طریقہ ہے۔ میں نے اب بھی وہی کہا کہ مجھے اس سے بھی زیادہ کی طاقت ہے لیکن اس مرتبہ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس سے افضل کوئی روزہ نہیں ہے۔' WHERE id = 1906;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا کہ ہم سے یحییٰ نے بیان کیا، ان سے شعبہ نے، (دوسری سند) اور امام بخاری رحمہ اللہ نے کہا کہ مجھ سے محمد نے بیان کیا، کہا کہ ہم سے غندر نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، ان سے قتادہ نے، ان سے ابوایوب نے اور ان سے جویریہ بنت حارث رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم ان کے یہاں جمعہ کے دن تشریف لے گئے، ( اتفاق سے ) وہ روزہ سے تھیں۔ نبی کریم صلی اللہ علیہ وسلم نے اس پر دریافت فرمایا کے کل کے دن بھی تو نے روزہ رکھا تھا؟ انہوں نے جواب دیا کہ نہیں۔ پھر آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کیا آئندہ کل روزہ رکھنے کا ارادہ ہے؟ جواب دیا کہ نہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر روزہ توڑ دو۔ حماد بن جعد نے بیان کیا کہ انہوں نے قتادہ سے سنا، ان سے ابوایوب نے بیان کیا اور ان سے جویریہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے حکم دیا اور انہوں نے روزہ توڑ دیا۔' WHERE id = 1916;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم نے بیان کیا، ان سے عمر بن محمد نے، ان سے سالم بن عبداللہ بن عمر رضی اللہ عنہما نے، اور ان سے ان کے والد نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا عاشورہ کے دن اگر کوئی چاہے تو روزہ رکھ لے۔' WHERE id = 1928;
UPDATE hadiths SET urdu = 'اور ابن شہاب سے (امام مالک رحمہ اللہ) کی روایت ہے، انہوں نے عروہ بن زبیر رضی اللہ عنہ سے اور انہوں نے عبدالرحمٰن بن عبدالقاری سے روایت کی کہ انہوں نے بیان کیا میں عمر بن خطاب رضی اللہ عنہ کے ساتھ رمضان کی ایک رات کو مسجد میں گیا۔ سب لوگ متفرق اور منتشر تھے، کوئی اکیلا نماز پڑھ رہا تھا، اور کچھ کسی کے پیچھے کھڑے ہوئے تھے۔ اس پر عمر رضی اللہ عنہ نے فرمایا، میرا خیال ہے کہ اگر میں تمام لوگوں کو ایک قاری کے پیچھے جمع کر دوں تو زیادہ اچھا ہو گا، چنانچہ آپ نے یہی ٹھان کر ابی بن کعب رضی اللہ عنہ کو ان کا امام بنا دیا۔ پھر ایک رات جو میں ان کے ساتھ نکلا تو دیکھا کہ لوگ اپنے امام کے پیچھے نماز ( تراویح ) پڑھ رہے ہیں۔ عمر رضی اللہ عنہ نے فرمایا، یہ نیا طریقہ بہتر اور مناسب ہے اور ( رات کا ) وہ حصہ جس میں یہ لوگ سو جاتے ہیں اس حصہ سے بہتر اور افضل ہے جس میں یہ نماز پڑھتے ہیں۔ آپ کی مراد رات کے آخری حصہ ( کی فضیلت ) سے تھی کیونکہ لوگ یہ نماز رات کے شروع ہی میں پڑھ لیتے تھے۔' WHERE id = 1938;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن سلام نے بیان کیا۔ انہوں نے کہا ہمیں عبدہ بن سلیمان نے خبر دی، انہیں ہشام بن عروہ نے، انہیں ان کے والد (عروہ بن زبیر) نے اور انہیں ام المؤمنین عائشہ صدیقہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم رمضان کے آخری عشرہ میں اعتکاف کرتے اور فرماتے کہ رمضان کے آخری عشرہ میں شب قدر کو تلاش کرو۔' WHERE id = 1948;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا کہ ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے عبیداللہ عمری نے، انہیں نافع نے خبر دی اور انہیں ابن عمر رضی اللہ عنہما نے کہ عمر رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے عرض کیا، میں نے جاہلیت میں یہ نذر مانی تھی کہ مسجد الحرام میں ایک رات کا اعتکاف کروں گا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اپنی نذر پوری کر۔' WHERE id = 1959;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن عبداللہ نے بیان کیا، انہوں نے اپنے بھائی (عبدالحمید) سے، ان سے سلیمان نے، ان سے عبیداللہ بن عمر نے، ان سے نافع نے، ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا، ان سے عمر بن خطاب رضی اللہ عنہ نے کہ انہوں نے پوچھا، یا رسول اللہ! میں نے جاہلیت میں نذر مانی تھی کہ ایک رات کا مسجد الحرام میں اعتکاف کروں گا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر اپنی نذر پوری کر۔ چنانچہ عمر رضی اللہ عنہ نے ایک رات بھر اعتکاف کیا۔' WHERE id = 1969;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، کہا کہ ہم کو سفیان ثوری نے خبر دی، انہیں عبداللہ بن عبدالرحمٰن بن ابی حسین نے خبر دی، ان سے عبداللہ بن ابی ملیکہ نے بیان کیا، ان سے عقبہ بن حارث رضی اللہ عنہ نے کہ ایک سیاہ فام خاتون آئیں اور دعویٰ کیا کہ انہوں نے ان دونوں ( عقبہ اور ان کی بیوی ) کو دودھ پلایا ہے۔ عقبہ نے اس امر کا ذکر رسول اللہ صلی اللہ علیہ وسلم سے کیا تو آپ صلی اللہ علیہ وسلم نے اپنا چہرہ مبارک پھیر لیا اور مسکرا کر فرمایا۔ اب جب کہ ایک بات کہہ دی گئی تو تم دونوں ایک ساتھ کس طرح رہ سکتے ہو۔ ان کے نکاح میں ابواہاب تمیمی کی صاحب زادی تھیں۔' WHERE id = 1979;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا کہ مجھ سے محمد بن فضیل نے بیان کیا، ان سے حصین نے بیان کیا، ان سے سالم بن ابی الجعد نے بیان کیا اور ان سے جابر رضی اللہ عنہ نے بیان کیا کہ ( تجارتی ) اونٹوں ( کا قافلہ ) آیا۔ ہم اس وقت نبی کریم صلی اللہ علیہ وسلم کے ساتھ جمعہ ( کے خطبہ ) میں شریک تھے۔ بارہ صحابہ کے سوا باقی تمام حضرات ادھر چلے گئے اس پر یہ آیت اتری «وإذا رأوا تجارة أو لهوا انفضوا إليها وتركوك قائما» ”جب سوداگری یا تماشا دیکھتے ہیں تو اس کی طرف دوڑ پڑتے ہیں اور آپ کو کھڑا چھوڑ دیتے ہیں۔“' WHERE id = 1990;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا کہ ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، ان سے عبدالرحمٰن بن عوف رضی اللہ عنہ کے غلام ابی عبید نے، انہوں نے ابوہریرہ رضی اللہ عنہ کو یہ کہتے سنا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا وہ شخص جو لکڑی کا گھٹا اپنی پیٹھ پر لاد کر لائے، اس سے بہتر ہے جو کسی کے سامنے ہاتھ پھیلائے چاہئیے وہ اسے کچھ دیدے یا نہ دے۔' WHERE id = 2000;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا کہ ہم سے غندر نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، ان سے منصور نے، ان سے ابوالضحیٰ نے، ان سے مسروق نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ جب ( سورۃ ) بقرہ کی آخری آیتیں «الذين يأكلون الربا *** الخ» نازل ہوئیں تو نبی کریم صلی اللہ علیہ وسلم نے انہیں صحابہ رضی اللہ عنہم کو مسجد میں پڑھ کر سنایا۔ اس کے بعد ان پر شراب کی تجارت حرام کر دیا۔' WHERE id = 2010;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا کہ ہم سے عبدالعزیز نے بیان کیا ان سے ابوحازم نے بیان کیا کہ کچھ لوگ سہل بن سعد ساعدی رضی اللہ عنہ کے یہاں منبرنبوی کے متعلق پوچھنے آئے۔ انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فلاں عورت کے یہاں جن کا نام بھی سہل رضی اللہ عنہ نے لیا تھا، اپنا آدمی بھیجا کہ وہ اپنے بڑھئی غلام سے کہیں کہ میرے لیے کچھ لکڑیوں کو جوڑ کر منبر تیار کر دے، تاکہ لوگوں کو وعظ کرنے کے لیے میں اس پر بیٹھ جایا کروں۔ چنانچہ اس عورت نے اپنے غلام سے غابہ کے جھاؤ کی لکڑی کا منبر بنانے کے لیے کہا۔ پھر ( جب منبر تیار ہو گیا تو ) انہوں نے اسے آپ صلی اللہ علیہ وسلم کی خدمت میں بھیجا۔ وہ منبر آپ صلی اللہ علیہ وسلم کے حکم سے ( مسجد میں ) رکھا گیا۔ اور آپ صلی اللہ علیہ وسلم اس پر بیٹھے۔' WHERE id = 2020;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، ان سے ابوبکر بن حفص نے بیان کیا، ان سے سالم بن عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ ان کے باپ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے عمر رضی اللہ عنہ کے یہاں ایک ریشمی جبہ بھیجا۔ پھر آپ صلی اللہ علیہ وسلم نے دیکھا کہ عمر رضی اللہ عنہ اسے ( ایک دن ) پہنے ہوئے ہیں۔ تو آپ صلی اللہ علیہ وسلم نے فرمایا میں نے اسے تمہارے پاس اس لیے نہیں بھیجا تھا کہ تم اسے پہن لو، اسے تو وہی لوگ پہنتے ہیں جن کا آخرت میں کوئی حصہ نہیں۔ میں نے تو اس لیے بھیجا تھا کہ تم اس سے ( بیچ کر ) فائدہ اٹھاؤ۔' WHERE id = 2030;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن منصور نے بیان کیا، کہا کہ ہم سے حبان نے بیان کیا، کہ ہم سے ہمام نے بیان کیا، ان سے قتادہ نے، ان سے ابوخلیل نے، ان سے عبداللہ بن حارث نے اور ان سے حکیم بن حزام رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، بیچنے اور خریدنے والے کو جب تک وہ جدا نہ ہوں ( بیع توڑ دینے کا ) اختیار ہے۔ ہمام راوی نے کہا کہ میں نے اپنی کتاب میں لفظ «يختار» تین مرتبہ لکھا ہوا پایا۔ پس اگر دونوں نے سچائی اختیار کی اور بات صاف صاف واضح کر دی تو انہیں ان کی بیع میں برکت ملتی ہے اور اگر انہوں نے جھوٹی باتیں بنائیں اور ( کسی عیب کو ) چھپایا تو تھوڑا سا نفع شاید وہ کما لیں، لیکن ان کی بیع میں برکت نہیں ہو گی۔ ( حبان نے ) کہا کہ ہم سے ہمام نے بیان کیا، ان سے ابوالتیاح نے بیان کیا، انہوں نے عبداللہ بن حارث سے سنا کہ یہی حدیث وہ حکیم بن حزام رضی اللہ عنہ سے بحوالہ نبی کریم صلی اللہ علیہ وسلم روایت کرتے تھے۔' WHERE id = 2040;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہمیں جریر نے خبر دی، انہیں مغیرہ نے، انہیں عامر شعبی نے اور ان سے جابر رضی اللہ عنہ نے بیان کیا کہ جب عبداللہ بن عمرو بن حرام رضی اللہ عنہ ( میرے باپ ) شہید ہو گئے تو ان کے ذمے ( لوگوں کا ) کچھ قرض باقی تھا۔ اس لیے میں نے نبی کریم صلی اللہ علیہ وسلم کے ذریعہ کوشش کی کہ قرض خواہ کچھ اپنے قرضوں کو معاف کر دیں۔ نبی کریم صلی اللہ علیہ وسلم نے یہی چاہا، لیکن وہ نہیں مانے۔ آپ صلی اللہ علیہ وسلم نے مجھ سے فرمایا کہ جاؤ اپنی تمام کھجور کی قسموں کو الگ الگ کر لو۔ عجوہ ( ایک خاص قسم کی کھجور ) کو الگ رکھ اور عذق زید ( کھجور کی ایک قسم ) کو الگ کر۔ پھر مجھے بلا بھیج۔ میں نے ایسا ہی کیا اور نبی کریم صلی اللہ علیہ وسلم کو کہلا بھیجا۔ آپ صلی اللہ علیہ وسلم تشریف لائے اور کھجوروں کے ڈھیر پر یا بیچ میں بیٹھ گئے اور فرمایا کہ اب ان قرض خواہوں کو ناپ کر دو۔ میں نے ناپنا شروع کیا۔ جتنا قرض لوگوں کا تھا۔ میں نے سب کو ادا کر دیا، پھر بھی تمام کھجور جوں کی توں تھی۔ اس میں سے ایک دانہ برابر کی کمی نہیں ہوئی تھی۔ فراس نے بیان کیا کہ ان سے شعبی نے، اور ان سے جابر رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے کہ ”برابر ان کے لیے تولتے رہے، یہاں تک کہ ان کا پورا قرض ادا ہو گیا۔“ اور ہشام نے کہا، ان سے وہب نے، اور ان سے جابر رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، کھجور توڑ اور اپنا قرض پورا ادا کر دے۔' WHERE id = 2052;
UPDATE hadiths SET urdu = 'ہم سے فروہ بن ابی مغراء نے بیان کیا، کہا کہ ہم کو علی بن مسہر نے خبر دی، انہیں ہشام نے، انہیں ان کے باپ نے، اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ ایسے دن ( مکی زندگی میں ) بہت ہی کم آئے، جن میں نبی کریم صلی اللہ علیہ وسلم صبح و شام میں کسی نہ کسی وقت ابوبکر رضی اللہ عنہ کے گھر تشریف نہ لائے ہوں۔ پھر جب آپ صلی اللہ علیہ وسلم کو مدینہ کی طرف ہجرت کی اجازت دی گئی، تو ہماری گھبراہٹ کا سبب یہ ہوا کہ آپ ( معمول کے خلاف اچانک ) ظہر کے وقت ہمارے گھر تشریف لائے۔ جب ابوبکر رضی اللہ عنہ کو آپ صلی اللہ علیہ وسلم کی آمد کی اطلاع دی گئی تو انہوں نے بھی یہی کہا کہ نبی کریم صلی اللہ علیہ وسلم اس وقت ہمارے یہاں کوئی نئی بات پیش آنے ہی کی وجہ سے تشریف لائے ہیں۔ جب آپ صلی اللہ علیہ وسلم ابوبکر رضی اللہ عنہ کے پاس پہنچے تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس وقت جو لوگ تمہارے پاس ہوں انہیں ہٹا دو۔ ابوبکر رضی اللہ عنہ نے عرض کیا، یا رسول اللہ! یہاں تو صرف میری یہی دو بیٹیاں ہیں یعنی عائشہ اور اسماء رضی اللہ عنہما۔ اب آپ صلی اللہ علیہ وسلم نے فرمایا کہ تمہیں معلوم بھی ہے مجھے تو یہاں سے نکلنے کی اجازت مل گئی ہے۔ ابوبکر رضی اللہ عنہ نے عرض کیا میرے پاس دو اونٹنیاں ہیں جنہیں میں نے نکلنے ہی کے لیے تیار کر رکھا تھا۔ آپ ان میں سے ایک لے لیجئے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اچھا، قیمت کے بدلے میں، میں نے ایک اونٹنی لے لی۔' WHERE id = 2063;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا کہ ہم سے لیث بن سعد نے بیان کیا، ان سے جعفر بن ربیعہ نے، ان سے عبدالرحمٰن بن ہرمز اعرج نے، ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ( بیچنے کے لیے ) اونٹنی اور بکری کے تھنوں میں دودھ کو روک کر نہ رکھو۔ اگر کسی نے ( دھوکہ میں آ کر ) کوئی ایسا جانور خرید لیا تو اسے دودھ دوہنے کے بعد دونوں اختیارات ہیں چاہے تو جانور کو رکھ لے، اور چاہے تو واپس کر دے۔ اور ایک صاع کھجور اس کے ساتھ دودھ کے بدل دیدے۔ ابوصالح، مجاہد، ولید بن رباح اور موسیٰ بن یسار سے بواسطہ ابوہریرہ رضی اللہ عنہ نبی کریم صلی اللہ علیہ وسلم سے روایت ایک صاع کھجور ہی کی ہے۔ بعض راویوں نے ابن سیرین سے ایک صاع کھجور کی روایت کی ہے اور یہ کہ خریدار کو ( صورت مذکورہ میں ) تین دن کا اختیار ہو گا۔ اگرچہ بعض دوسرے راویوں نے ابن سیرین ہی سے ایک صاع کھجور کی بھی روایت کی ہے، لیکن تین دن کے اختیار کا ذکر نہیں کیا اور ( تاوان میں ) کھجور دینے کی روایات ہی زیادہ ہیں۔' WHERE id = 2073;
UPDATE hadiths SET urdu = 'ہم سے مکی بن ابراہیم نے بیان کیا، کہا کہ مجھے ابن جریج نے خبر دی، انہیں ابن شہاب نے، انہیں سعید بن مسیب نے، انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، کوئی شخص اپنے کسی بھائی کے مول پر مول نہ کرے اور کوئی «نجش» ( دھوکہ، فریب ) نہ کرے، اور نہ کوئی شہری، کسی دیہاتی کے لیے بیچے یا مول لے۔' WHERE id = 2084;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا کہ ہم سے لیث نے بیان کیا، ان سے ابن شہاب نے بیان کیا، ان سے مالک بن اوس نے، انہوں نے عمر رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، گیہوں کو گیہوں کے بدلہ میں بیچنا سود ہے، لیکن یہ کہ سودا ہاتھوں ہاتھ ہو۔ جَو کو جَو کے بدلہ میں بیچنا سود ہے، لیکن یہ کہ ہاتھوں ہاتھ ہو۔ اور کھجور کو کھجور کے بدلہ میں بیچنا سود ہے لیکن یہ کہ سودا ہاتھوں ہاتھ، نقدا نقد ہو۔' WHERE id = 2094;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، کہا کہ ہم سے امام مالک نے بیان کیا، ان سے نافع نے، ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے صاحب عریہ کو اس کی اجازت دی کہ اپنا عریہ اس کے اندازے برابر میوے کے بدل بیچ ڈالے۔' WHERE id = 2108;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ ہم کو امام مالک نے خبر دی، انہیں حمید نے اور انہیں انس بن مالک رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے پھلوں کو «زهو» سے پہلے بیچنے سے منع فرمایا ہے۔ ان سے پوچھا گیا کہ کہ «زهو» کسے کہتے ہیں تو جواب دیا کہ سرخ ہونے کو۔ پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تمہی بتاؤ، اللہ تعالیٰ کے حکم سے پھلوں پر کوئی آفت آ جائے، تو تم اپنے بھائی کا مال آخر کس چیز کے بدلے لو گے؟' WHERE id = 2118;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا کہ ہم کو امام مالک نے خبر دی، انہیں حمید طویل نے اور انہیں انس بن مالک رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم کو ابوطیبہ نے پچھنا لگایا تو آپ صلی اللہ علیہ وسلم نے انہیں ایک صاع کھجور ( مزدوری میں ) دینے کا حکم فرمایا۔ اور اس کے مالکوں سے فرمایا کہ وہ اس کے خراج میں کچھ کمی کر دیں۔' WHERE id = 2129;
UPDATE hadiths SET urdu = 'ہم سے ابوالولیمان نے بیان کیا، کہا کہ ہم کو شعیب نے خبر دی، انہیں زہری نے، کہا کہ مجھے عروہ بن زبیر رضی اللہ عنہ نے خبر دی انہیں حکیم بن حزام رضی اللہ عنہ نے خبر دی کہ انہوں نے پوچھا یا رسول اللہ! ان نیک کاموں کے متعلق آپ کا کیا حکم ہے، جنہیں میں جاہلیت کے زمانہ میں صلہ رحمی، غلام آزاد کرنے اور صدقہ دینے کے سلسلہ میں کیا کرتا تھا کیا ان اعمال کا بھی مجھے ثواب ملے گا؟ حکیم بن حزام رضی اللہ عنہ فرماتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا جتنی نیکیاں تم پہلے کر چکے ہو ان سب کے ساتھ اسلام لائے ہو۔' WHERE id = 2140;
UPDATE hadiths SET urdu = 'ہم سے ابن نمیر نے بیان کیا، کہا کہ ہم سے وکیع نے بیان کیا، ان سے اسماعیل نے بیان کیا، ان سے سلمہ بن کہیل نے، ان سے عطاء نے اور ان سے جابر رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے مدبر غلام بیچا تھا۔' WHERE id = 2150;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، انہیں عمرو نے خبر دی، انہوں نے کہا کہ میں نے ابوالبختری طائی سے سنا، انہوں نے کہا کہ میں نے ابن عباس رضی اللہ عنہما سے کھجور کے درخت میں بیع سلم کے متعلق پوچھا تو آپ نے فرمایا کہ درخت پر پھل کو بیچنے سے نبی کریم صلی اللہ علیہ وسلم نے اس وقت تک کے لیے منع فرمایا تھا جب تک وہ کھانے کے قابل نہ ہو جائے یا اس کا وزن نہ کیا جا سکے۔ ایک شخص نے پوچھا کہ کیا چیز وزن کی جائے گی۔ اس پر ابن عباس رضی اللہ عنہما کے قریب ہی بیٹھے ہوئے ایک شخص نے کہا کہ مطلب یہ ہے کہ اندازہ کرنے کے قابل ہو جائے اور معاذ نے بیان کیا، ان سے شعبہ نے بیان کیا، ان سے عمرو نے کہ ابوالبختری نے کہا کہ میں نے ابن عباس رضی اللہ عنہما سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے منع کیا تھا۔ پھر یہی حدیث بیان کی۔' WHERE id = 2166;
UPDATE hadiths SET urdu = 'ہم سے احمد بن محمد مکی نے بیان کیا، کہا کہ ہم سے عمرو بن یحییٰ نے بیان کیا، ان سے ان کے دادا سعید بن عمرو نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا اللہ تعالیٰ نے کوئی ایسا نبی نہیں بھیجا جس نے بکریاں نہ چرائی ہوں۔ اس پر آپ صلی اللہ علیہ وسلم کے صحابہ رضوان اللہ علیہم نے پوچھا کیا آپ نے بھی بکریاں چرائی ہیں؟ فرمایا کہ ہاں! کبھی میں بھی مکہ والوں کی بکریاں چند قیراط کی تنخواہ پر چرایا کرتا تھا۔' WHERE id = 2179;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا کہ ہم سے عبدالواحد بن زیاد نے بیان کیا، ان سے معمر نے بیان کیا، ان سے ابن طاؤس نے، ان سے ان کے باپ نے، اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے ( تجارتی ) قافلوں سے ( منڈی سے آگے جا کر ) ملاقات کرنے سے منع فرمایا تھا۔ اور یہ کہ شہری دیہاتی کا مال نہ بیچیں، میں نے پوچھا، اے ابن عباس رضی اللہ عنہما! ”شہری دیہاتی کا مال نہ بیچیں“ کا کیا مطلب ہے؟ انہوں نے فرمایا کہ مراد یہ ہے کہ ان کے دلال نہ بنیں۔' WHERE id = 2190;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا کہ ہم سے عبدالوارث اور اسماعیل بن ابراہیم نے بیان کیا، ان سے علی بن حکم نے، ان سے نافع نے اور ان سے ابن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے نرکدانے کی اجرت لینے سے منع فرمایا۔' WHERE id = 2200;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، ان سے سفیان بن عیینہ نے بیان کیا، ان سے عمرو بن دینار نے بیان کیا، انہوں نے محمد بن علی باقر سے سنا، اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا اگر بحرین سے ( جزیہ کا ) مال آیا تو میں تمہیں اس طرح دونوں لپ بھربھر کر دوں گا لیکن بحرین سے مال نبی کریم صلی اللہ علیہ وسلم کی وفات تک نہیں آیا پھر جب اس کے بعد وہاں سے مال آیا تو ابوبکر رضی اللہ عنہ نے اعلان کرا دیا کہ جس سے بھی نبی کریم صلی اللہ علیہ وسلم کا کوئی وعدہ ہو یا آپ پر کسی کا قرض ہو وہ ہمارے یہاں آ جائے۔ چنانچہ میں حاضر ہوا۔ اور میں نے عرض کیا کہ نبی کریم صلی اللہ علیہ وسلم نے مجھ سے یہ وہ باتیں فرمائی تھیں۔ جسے سن کر ابوبکر رضی اللہ عنہ نے مجھے ایک لپ بھر کر دیا۔ میں نے اسے شمار کیا تو وہ پانچ سو کی رقم تھی۔ پھر فرمایا کہ اس کے دو گنا اور لے لو۔' WHERE id = 2211;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ ہم کو امام مالک رحمہ اللہ نے خبر دی، انہیں ابوحازم نے، انہیں سہل بن سعد رضی اللہ عنہ نے، انہوں نے بیان کیا کہ ایک عورت نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئی اور عرض کیا کہ یا رسول اللہ! میں نے خود کو آپ کو بخش دیا۔ اس پر ایک صحابی نے کہا کہ آپ میرا ان سے نکاح کر دیجئیے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں نے تمہارا نکاح ان سے اس مہر کے ساتھ کیا جو تمہیں قرآن یاد ہے۔' WHERE id = 2223;
UPDATE hadiths SET urdu = 'ہم سے معاذ بن فضالہ نے بیان کیا، کہا کہ ہم سے ہشام نے بیان کیا، ان سے یحییٰ بن ابی کثیر نے بیان کیا، ان سے ابوسلمہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، جس شخص نے کوئی کتا رکھا، اس نے روزانہ اپنے عمل سے ایک قیراط کی کمی کر لی۔ البتہ کھیتی یا مویشی ( کی حفاظت کے لیے ) کتے اس سے الگ ہیں۔ ابن سیرین اور ابوصالح نے ابوہریرہ رضی اللہ عنہ کے واسطے سے بیان کیا بحوالہ نبی کریم صلی اللہ علیہ وسلم کہ بکری کے ریوڑ، کھیتی اور شکار کے کتے الگ ہیں۔ ابوحازم نے کہا ابوہریرہ رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے کہ شکاری اور مویشی کے کتے ( الگ ہیں ) ۔' WHERE id = 2234;
UPDATE hadiths SET urdu = 'ہم سے صدقہ بن فضل نے بیان کیا، کہا کہ ہم کو سفیان بن عیینہ نے خبر دی، انہیں یحییٰ بن سعید انصاری نے، انہوں نے حنظلہ زرقی سے سنا کہ رافع بن خدیج رضی اللہ عنہ نے کہا کہ ہمارے پاس مدینہ کے دوسرے لوگوں کے مقابلے میں زمین زیادہ تھی۔ ہمارے یہاں طریقہ یہ تھا کہ جب زمین بصورت جنس کرایہ پر دیتے تو یہ شرط لگا دیتے کہ اس حصہ کی پیداوار تو میری رہے گی اور اس حصہ کی تمہاری رہے گی۔ پھر کبھی ایسا ہوتا کہ ایک حصہ کی پیداوار خوب ہوتی اور دوسرے کی نہ ہوتی۔ اس لیے نبی کریم صلی اللہ علیہ وسلم نے لوگوں کو اس طرح معاملہ کرنے سے منع فرما دیا۔' WHERE id = 2244;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سنان نے بیان کیا، کہا کہ ہم سے فلیح نے بیان کیا، ان سے ہلال بن علی نے بیان کیا، (دوسری سند) اور ہم سے عبداللہ بن محمد نے بیان کیا، انہوں نے کہا کہ ہم سے ابوعامر نے بیان کیا، ان سے فلیح نے بیان کیا، ان سے ہلال بن علی نے، ان سے عطاء بن یسار نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم ایک دن بیان فرما رہے تھے ایک دیہاتی بھی مجلس میں حاضر تھا کہ اہل جنت میں سے ایک شخص اپنے رب سے کھیتی کرنے کی اجازت چاہے گا۔ اللہ تعالیٰ اس سے فرمائے گا کیا اپنی موجودہ حالت پر تو راضی نہیں ہے؟ وہ کہے گا کیوں نہیں! لیکن میرا جی کھیتی کرنے کو چاہتا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر اس نے بیج ڈالا۔ پلک جھپکنے میں وہ اگ بھی آیا۔ پک بھی گیا اور کاٹ بھی لیا گیا۔ اور اس کے دانے پہاڑوں کی طرح ہوئے۔ اب اللہ تعالیٰ فرماتا ہے، اے ابن آدم! اسے رکھ لے، تجھے کوئی چیز آسودہ نہیں کر سکتی۔ یہ سن کر دیہاتی نے کہا کہ قسم اللہ کی وہ تو کوئی قریشی یا انصاری ہی ہو گا۔ کیونکہ یہی لوگ کھیتی کرنے والے ہیں۔ ہم تو کھیتی ہی نہیں کرتے۔ اس بات پر رسول اللہ صلی اللہ علیہ وسلم کو ہنسی آ گئی۔' WHERE id = 2257;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا کہ ہم کو مخلد نے خبر دی کہا کہ مجھے ابن جریج نے خبر دی، کہا کہ مجھ سے ابن شہاب نے بیان کیا، ان سے عروہ بن زبیر رضی اللہ عنہ نے بیان کیا کہ ایک انصاری مرد نے زبیر رضی اللہ عنہ سے حرہ کے ندی کے بارے میں جس سے کھجوروں کے باغ سیراب ہوا کرتے تھے، جھگڑا کیا۔ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا زبیر! تم سیراب کر لو۔ پھر اپنے پڑوسی بھائی کے لیے جلد پانی چھوڑ دینا۔ اس پر انصاری رضی اللہ عنہ نے کہا۔ جی ہاں! آپ کی پھوپھی کے بیٹے ہیں نا! رسول اللہ صلی اللہ علیہ وسلم کا رنگ بدل گیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا، اے زبیر! تم سیراب کرو، یہاں تک کہ پانی کھیت کی مینڈوں تک پہنچ جائے۔ اس طرح آپ نے زبیر رضی اللہ عنہ کو ان کا پورا حق دلوا دیا۔ زبیر رضی اللہ عنہ کہتے تھے کہ قسم اللہ کی یہ آیت اسی بارے میں نازل ہوئی تھی «لا وربك لا يؤمنون حتى يحكموك فيما شجر بينهم‏» ”ہرگز نہیں، تیرے رب کی قسم! اس وقت تک یہ ایمان والے نہیں ہوں گے جب تک اپنے جملہ اختلافات میں آپ کو حکم نہ تسلیم کر لیں۔“ ابن شہاب نے کہا کہ انصار اور تمام لوگوں نے اس کے بعد نبی کریم صلی اللہ علیہ وسلم کے اس ارشاد کی بنا پر کہ ”سیراب کرو اور پھر اس وقت تک رک جاؤ، جب تک پانی منڈیروں تک نہ پہنچ جائے۔“ ایک اندازہ لگا لیا، یعنی پانی ٹخنوں تک بھر جائے۔' WHERE id = 2269;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا کہ ہم سے امام مالک نے بیان کیا، ان سے ربیعہ بن ابی عبدالرحمٰن نے، ان سے منبعت کے غلام یزید نے اور ان سے زید بن خالد رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں ایک شخص آیا اور آپ سے لقطہ ( راستے میں کسی کی گم ہوئی چیز جو پا گئی ہو ) کے متعلق پوچھا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس کی تھیلی اور اس کے بندھن کی خوب جانچ کر لو۔ پھر ایک سال تک اس کا اعلان کرتے رہو۔ اس عرصے میں اگر اس کا مالک آ جائے ( تو اسے دے دو ) ورنہ پھر وہ چیز تمہاری ہے۔ سائل نے پوچھا، اور گمشدہ بکری؟ آپ صلی اللہ علیہ وسلم نے فرمایا، وہ تمہاری ہے یا تمہارے بھائی کی ہے یا پھر بھیڑئیے کی ہے۔ سائل نے پوچھا اور گمشدہ اونٹ؟ آپ صلی اللہ علیہ وسلم نے فرمایا، تمہیں اس سے کیا مطلب؟ اس کے ساتھ اسے سیراب رکھنے والی چیز ہے اور اس کا گھر ہے، پانی پر بھی وہ جا سکتا ہے اور درخت ( کے پتے ) بھی کھا سکتا ہے یہاں تک کہ اس کا مالک اس کو پا جائے۔' WHERE id = 2279;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن قزعہ نے بیان کیا، انہوں نے کہا کہ ہم کو امام مالک نے خبر دی، انہیں داؤد بن حصین نے، انہیں ابواحمد کے غلام ابوسفیان نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے بیع عرایا کی اندازہ کر کے خشک کھجور کے بدلے پانچ وسق سے کم، یا ( یہ کہا کہ ) پانچ وسق کے اندر اجازت دی ہے اس میں شک داؤد بن حصین کو ہوا ( بیع عریہ کا بیان پیچھے مفصل ہو چکا ہے ) ۔' WHERE id = 2289;
UPDATE hadiths SET urdu = 'ہم سے خلاد نے بیان کیا، ان سے مسعر نے بیان کیا، ان سے محارب بن دثار نے بیان کیا، اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا تو آپ صلی اللہ علیہ وسلم مسجد نبوی میں تشریف رکھتے تھے۔ مسعر نے بیان کیا کہ میرا خیال ہے کہ انہوں نے چاشت کے وقت کا ذکر کیا۔ ( کہ اس وقت خدمت نبوی میں حاضر ہوا ) پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ دو رکعت نماز پڑھ لو۔ میرا آپ صلی اللہ علیہ وسلم پر قرض تھا۔ آپ صلی اللہ علیہ وسلم نے اسے ادا کیا، بلکہ زیادہ بھی دے دیا۔' WHERE id = 2300;
UPDATE hadiths SET urdu = 'لیث نے بیان کیا کہ مجھ سے جعفر بن ربیعہ نے بیان کیا، ان سے عبدالرحمٰن بن ہرمز نے اور ان سے ابوہریرہ رضی اللہ عنہ نے رسول اللہ صلی اللہ علیہ وسلم سے کہ آپ صلی اللہ علیہ وسلم نے کسی اسرائیلی شخص کا تذکرہ فرمایا جس نے دوسرے اسرائیلی شخص سے قرض مانگا تھا اور اس نے ایک مقررہ مدت کے لیے اسے قرض دے دیا۔ ( جس کا ذکر پہلے گزر چکا ہے ) ۔' WHERE id = 2310;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، انہوں نے کہا کہ ہم سے عثمان بن عمر نے بیان کیا، انہوں نے کہا کہ ہم کو یونس نے خبر دی، انہیں زہری نے، انہیں عبداللہ بن کعب بن مالک رضی اللہ عنہ نے، انہوں نے کعب رضی اللہ عنہ سے روایت کیا کہ انہوں نے ابن ابی حدرد رضی اللہ عنہ سے مسجد میں اپنے قرض کا تقاضا کیا۔ اور دونوں کی آواز اتنی بلند ہو گئی کہ رسول اللہ صلی اللہ علیہ وسلم نے بھی گھر میں سن لی۔ آپ صلی اللہ علیہ وسلم نے حجرہ مبارک کا پردہ اٹھا کر پکارا اے کعب! انہوں نے عرض کیا، یا رسول اللہ میں حاضر ہوں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اپنے قرض میں سے اتنا کم کر دے اور آپ صلی اللہ علیہ وسلم نے آدھا قرض کم کر دینے کا اشارہ کیا۔ انہوں نے کہا کہ میں نے کم کر دیا۔ پھر آپ صلی اللہ علیہ وسلم نے ابن ابی حدرد رضی اللہ عنہ سے فرمایا کہ اٹھ اب قرض ادا کر دے۔' WHERE id = 2322;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن عبداللہ نے بیان کیا، کہا کہ مجھ سے سلیمان تیمی نے بیان کیا، ان سے یحییٰ بن سعید انصاری نے، ان سے منبعث کے غلام یزید نے، انہوں نے زید بن خالد سے سنا، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم سے لقطہٰ کے متعلق پوچھا گیا۔ وہ یقین رکھتے تھے کہ آپ صلی اللہ علیہ وسلم نے فرمایا اس کے برتن کی بناوٹ اور اس کے بندھن کو ذہن میں رکھ، پھر ایک سال تک اس کا اعلان کرتا رہ۔ یزید بیان کرتے تھے کہ اگر اسے پہچاننے والا ( اس عرصہ میں ) نہ ملے تو پانے والے کو اپنی ضروریات میں خرچ کر لینا چاہئے۔ اور یہ اس کے پاس امانت کے طور پر ہو گا۔ اس آخری ٹکڑے ( کہ اس کے پاس امانت کے طور پر ہو گا ) کے متعلق مجھے معلوم نہیں کہ یہ رسول اللہ صلی اللہ علیہ وسلم کی حدیث ہے یا خود انہوں نے اپنی طرف سے یہ بات کہی ہے۔ پھر پوچھا، راستہ بھولی ہوئی بکری کے متعلق آپ کا کیا ارشاد ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اسے پکڑ لو۔ وہ یا تمہاری ہو گی ( جب کہ اصل مالک نہ ملے ) یا تمہارے بھائی ( مالک ) کے پاس پہنچ جائے گی، یا پھر اسے بھیڑیا اٹھا لے جائے گا۔ یزید نے بیان کیا کہ اس کا بھی اعلان کیا جائے گا۔ پھر صحابی نے پوچھا، راستہ بھولے ہوئے اونٹ کے بارے میں آپ کا کیا ارشاد ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اسے آزاد رہنے دو، اس کے ساتھ اس کے کھر بھی ہیں اور اس کا مشکیزہ بھی، خود پانی پر پہنچ جائے گا اور خود ہی درخت کے پتے کھا لے گا اور اس طرح وہ اپنے مالک تک پہنچ جائے گا۔' WHERE id = 2332;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، کہا کہ ہم سے سفیان ثوری نے بیان کیا ربیعہ سے، ان سے منبعث کے غلام یزید نے، اور ان سے زید بن خالد رضی اللہ عنہ نے کہا کہ ایک دیہاتی نے رسول اللہ صلی اللہ علیہ وسلم سے لقطہٰ کے متعلق پوچھا، تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ ایک سال تک اس کا اعلان کرتا رہ، اگر کوئی ایسا شخص آ جائے جو اس کی بناوٹ اور بندھن کے بارے میں صحیح صحیح بتائے ( تو اسے دیدے ) ورنہ اپنی ضروریات میں اسے خرچ کر۔ انہوں نے جب ایسے اونٹ کے متعلق بھی پوچھا جو راستہ بھول گیا ہو۔ تو آپ صلی اللہ علیہ وسلم کے چہرہ مبارک کا رنگ بدل گیا اور آپ صلی اللہ علیہ وسلم نے فرمایا کہ تمہیں اس سے کیا مطلب؟ اس کے ساتھ اس کا مشکیزہ اور اس کے کھر موجود ہیں۔ وہ خود پانی تک پہنچ سکتا ہے۔ اور درخت کے پتے کھا سکتا ہے اور اس طرح وہ اپنے مالک تک پہنچ سکتا ہے۔ انہوں نے راستہ بھولی ہوئی بکری کے متعلق بھی پوچھا، تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ یا وہ تمہاری ہو گی یا تمہارے بھائی ( اصل مالک ) کو مل جائے گی۔ ورنہ اسے بھیڑیا اٹھا لے جائے گا۔' WHERE id = 2343;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن موسیٰ نے بیان کیا، کہا ہم سے وکیع نے بیان کیا، کہا ہم سے زکریا بن اسحاق مکی نے بیان کیا، ان سے یحییٰ بن عبداللہ صیفی نے، ان سے ابن عباس رضی اللہ عنہما کے غلام ابومعبد نے، اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے معاذ رضی اللہ عنہ کو جب ( عامل بنا کر ) یمن بھیجا، تو آپ صلی اللہ علیہ وسلم نے انہیں ہدایت فرمائی کہ مظلوم کی بددعا سے ڈرتے رہنا کہ اس ( دعا ) کے اور اللہ تعالیٰ کے درمیان کوئی پردہ نہیں ہوتا۔' WHERE id = 2353;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، کہا کہ مجھ سے ابراہیم بن سعد نے بیان کیا، ان سے صالح بن کیسان نے اور ان سے ابن شہاب نے کہ مجھے عروہ بن زبیر رضی اللہ عنہ نے خبر دی، انہیں زینب بنت ام سلمہ رضی اللہ عنہما نے خبر دی اور انہیں نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ ام سلمہ رضی اللہ عنہا نے کہ رسول اللہ صلی اللہ علیہ وسلم نے اپنے حجرے کے دروازے کے سامنے جھگڑے کی آواز سنی اور جھگڑا کرنے والوں کے پاس تشریف لائے۔ آپ صلی اللہ علیہ وسلم نے ان سے فرمایا کہ میں بھی ایک انسان ہوں۔ اس لیے جب میرے یہاں کوئی جھگڑا لے کر آتا ہے تو ہو سکتا ہے کہ ( فریقین میں سے ) ایک فریق کی بحث دوسرے فریق سے عمدہ ہو، میں سمجھتا ہوں کہ وہ سچا ہے۔ اور اس طرح میں اس کے حق میں فیصلہ کر دیتا ہوں، لیکن اگر میں اس کو ( اس کے ظاہری بیان پر بھروسہ کر کے ) کسی مسلمان کا حق دلا دوں تو دوزخ کا ایک ٹکڑا اس کو دلا رہا ہوں، وہ لے لے یا چھوڑ دے۔' WHERE id = 2363;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث نے بیان کیا، ان سے عقیل نے اور ان سے ابن شہاب نے کہ مجھے عبیداللہ بن عبداللہ بن ابی ثور نے خبر دی اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ میں ہمیشہ اس بات کا آروز مند رہتا تھا کہ عمر رضی اللہ عنہ سے نبی کریم صلی اللہ علیہ وسلم کی ان دو بیویوں کے نام پوچھوں جن کے بارے میں اللہ تعالیٰ نے ( سورۃ التحریم میں ) فرمایا ہے «إن تتوبا إلى الله فقد صغت قلوبكما‏» ”اگر تم دونوں اللہ کے سامنے توبہ کرو ( تو بہتر ہے ) کہ تمہارے دل بگڑ گئے ہیں۔“ پھر میں ان کے ساتھ حج کو گیا۔ عمر رضی اللہ عنہ راستے سے قضائے حاجت کے لیے ہٹے تو میں بھی ان کے ساتھ ( پانی کا ایک ) چھاگل لے کر گیا۔ پھر وہ قضائے حاجت کے لیے چلے گئے۔ اور جب واپس آئے تو میں نے ان کے دونوں ہاتھوں پر چھاگل سے پانی ڈالا۔ اور انہوں نے وضو کیا، پھر میں نے پوچھا، یا امیرالمؤمنین! نبی کریم صلی اللہ علیہ وسلم کی بیویوں میں وہ دو خواتین کون سی ہیں جن کے متعلق اللہ تعالیٰ نے یہ فرمایا کہ «إن تتوبا إلى الله‏» ”تم دونوں اللہ کے سامنے توبہ کرو“ انہوں نے فرمایا، ابن عباس! تم پر حیرت ہے۔ وہ تو عائشہ اور حفصہ ( رضی اللہ عنہا ) ہیں۔ پھر عمر رضی اللہ عنہ میری طرف متوجہ ہو کر پورا واقعہ بیان کرنے لگے۔ آپ نے بتلایا کہ بنوامیہ بن زید کے قبیلے میں جو مدینہ سے ملا ہوا تھا۔ میں اپنے ایک انصاری پڑوسی کے ساتھ رہتا تھا۔ ہم دونوں نے نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضری کی باری مقرر کر رکھی تھی۔ ایک دن وہ حاضر ہوتے اور ایک دن میں۔ جب میں حاضری دیتا تو اس دن کی تمام خبریں وغیرہ لاتا۔ ( اور ان کو سناتا ) اور جب وہ حاضر ہوتے تو وہ بھی اسی طرح کرتے۔ ہم قریش کے لوگ ( مکہ میں ) اپنی عورتوں پر غالب رہا کرتے تھے۔ لیکن جب ہم ( ہجرت کر کے ) انصار کے یہاں آئے تو انہیں دیکھا کہ ان کی عورتیں خود ان پر غالب تھیں۔ ہماری عورتوں نے بھی ان کا طریقہ اختیار کرنا شروع کر دیا۔ میں نے ایک دن اپنی بیوی کو ڈانٹا تو انہوں نے بھی اس کا جواب دیا۔ ان کا یہ جواب مجھے ناگوار معلوم ہوا۔ لیکن انہوں نے کہا کہ میں اگر جواب دیتی ہوں تو تمہیں ناگواری کیوں ہوتی ہے۔ قسم اللہ کی! نبی کریم صلی اللہ علیہ وسلم کی ازواج تک آپ کو جواب دے دیتی ہیں اور بعض بیویاں تو آپ سے پورے دن اور پوری رات خفا رہتی ہیں۔ اس بات سے میں بہت گھبرایا اور میں نے کہا کہ ان میں سے جس نے بھی ایسا کیا ہو گا وہ بہت بڑے نقصان اور خسارے میں ہے۔ اس کے بعد میں نے کپڑے پہنے اور حفصہ رضی اللہ عنہا ( عمر رضی اللہ عنہ کی صاحبزادی اور ام المؤمنین ) کے پاس پہنچا اور کہا اے حفصہ! کیا تم میں سے کوئی نبی کریم صلی اللہ علیہ وسلم سے پورے دن رات تک ناراض رہتی ہیں۔ انہوں نے کہا کہ ہاں! میں بول اٹھا کہ پھر تو وہ تباہی اور نقصان میں رہیں۔ کیا تمہیں اس سے امن ہے کہ اللہ تعالیٰ اپنے رسول صلی اللہ علیہ وسلم کی خفگی کی وجہ سے ( تم پر ) غصہ ہو جائے اور تم ہلاک ہو جاؤ۔ رسول اللہ صلی اللہ علیہ وسلم سے زیادہ چیزوں کا مطالبہ ہرگز نہ کیا کرو، نہ کسی معاملہ میں آپ صلی اللہ علیہ وسلم کی کسی بات کا جواب دو اور نہ آپ پر خفگی کا اظہار ہونے دو، البتہ جس چیز کی تمہیں ضرورت ہو، وہ مجھ سے مانگ لیا کرو، کسی خود فریبی میں مبتلا نہ رہنا، تمہاری یہ پڑوسن تم سے زیادہ جمیل اور نظیف ہیں اور رسول اللہ صلی اللہ علیہ وسلم کو زیادہ پیاری بھی ہیں۔ آپ کی مراد عائشہ رضی اللہ عنہا سے تھی۔ عمر رضی اللہ عنہ نے کہا، ان دنوں یہ چرچا ہو رہا تھا کہ غسان کے فوجی ہم سے لڑنے کے لیے گھوڑوں کو سم لگا رہے ہیں۔ میرے پڑوسی ایک دن اپنی باری پر مدینہ گئے ہوئے تھے۔ پھر عشاء کے وقت واپس لوٹے۔ آ کر میرا دروازہ انہوں نے بڑی زور سے کھٹکھٹایا، اور کہا کیا آپ سو گئے ہیں؟ میں بہت گھبرایا ہوا باہر آیا انہوں نے کہا کہ ایک بہت بڑا حادثہ پیش آ گیا ہے۔ میں نے پوچھا کیا ہوا؟ کیا غسان کا لشکر آ گیا؟ انہوں نے کہا بلکہ اس سے بھی بڑا اور سنگین حادثہ، وہ یہ کہ رسول اللہ صلی اللہ علیہ وسلم نے اپنی بیویوں کو طلاق دے دی۔ یہ سن کر عمر رضی اللہ عنہ نے فرمایا، حفصہ تو تباہ و برباد ہو گئی۔ مجھے تو پہلے ہی کھٹکا تھا کہ کہیں ایسا نہ ہو جائے ( عمر رضی اللہ عنہ نے کہا ) پھر میں نے کپڑے پہنے۔ صبح کی نماز رسول اللہ صلی اللہ علیہ وسلم کے ساتھ پڑھی ( نماز پڑھتے ہی ) آپ صلی اللہ علیہ وسلم اپنے بالا خانہ میں تشریف لے گئے اور وہیں تنہائی اختیار کر لی۔ میں حفصہ کے یہاں گیا، دیکھا تو وہ رو رہی تھیں، میں نے کہا، رو کیوں رہی ہو؟ کیا پہلے ہی میں نے تمہیں نہیں کہہ دیا تھا؟ کیا رسول اللہ صلی اللہ علیہ وسلم نے تم سب کو طلاق دے دی ہے؟ انہوں نے کہا کہ مجھے کچھ معلوم نہیں۔ آپ صلی اللہ علیہ وسلم بالاخانہ میں تشریف رکھتے ہیں۔ پھر میں باہر نکلا اور منبر کے پاس آیا۔ وہاں کچھ لوگ موجود تھے اور بعض رو بھی رہے تھے۔ تھوڑی دیر تو میں ان کے ساتھ بیٹھا رہا۔ لیکن مجھ پر رنج کا غلبہ ہوا، اور میں بالاخانے کے پاس پہنچا، جس میں آپ صلی اللہ علیہ وسلم تشریف رکھتے تھے۔ میں نے آپ صلی اللہ علیہ وسلم کے ایک سیاہ غلام سے کہا، ( کہ نبی کریم صلی اللہ علیہ وسلم سے کہو ) کہ عمر اجازت چاہتا ہے۔ وہ غلام اندر گیا اور آپ صلی اللہ علیہ وسلم سے گفتگو کر کے واپس آیا اور کہا کہ میں نے آپ کی بات پہنچا دی تھی، لیکن آپ صلی اللہ علیہ وسلم خاموش ہو گئے، چنانچہ میں واپس آ کر انہیں لوگوں کے ساتھ بیٹھ گیا جو منبر کے پاس موجود تھے۔ پھر مجھ پر رنج غالب آیا اور میں دوبارہ آیا۔ لیکن اس دفعہ بھی وہی ہوا۔ پھر آ کر انہیں لوگوں میں بیٹھ گیا جو منبر کے پاس تھے۔ لیکن اس مرتبہ پھر مجھ سے نہیں رہا گیا اور میں نے غلام سے آ کر کہا، کہ عمر کے لیے اجازت چاہو۔ لیکن بات جوں کی توں رہی۔ جب میں واپس ہو رہا تھا کہ غلام نے مجھ کو پکارا اور کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے آپ کو اجازت دے دی ہے۔ میں آپ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا تو آپ صلی اللہ علیہ وسلم کھجور کی چٹائی پر لیٹے ہوئے تھے۔ جس پر کوئی بستر بھی نہیں تھا۔ اس لیے چٹائی کے ابھرے ہوئے حصوں کا نشان آپ صلی اللہ علیہ وسلم کے پہلو میں پڑ گیا تھا۔ آپ صلی اللہ علیہ وسلم اس وقت ایک ایسے تکیے پر ٹیک لگائے ہوئے تھے جس کے اندر کھجور کی چھال بھری گئی تھی۔ میں نے آپ صلی اللہ علیہ وسلم کو سلام کیا اور کھڑے ہی کھڑے عرض کی، کہ کیا آپ نے اپنی بیویوں کو طلاق دے دی ہے؟ آپ صلی اللہ علیہ وسلم نے نگاہ میری طرف کر کے فرمایا کہ نہیں۔ میں نے آپ کے غم کو ہلکا کرنے کی کوشش کی اور کہنے لگا…. اب بھی میں کھڑا ہی تھا…. یا رسول اللہ! آپ جانتے ہی ہیں کہ ہم قریش کے لوگ اپنی بیویوں پر غالب رہتے تھے، لیکن جب ہم ایک ایسی قوم میں آ گئے جن کی عورتیں ان پر غالب تھیں، پھر عمر رضی اللہ عنہ نے تفصیل ذکر کی۔ اس بات پر رسول اللہ صلی اللہ علیہ وسلم مسکرا دیئے۔ پھر میں نے کہا میں حفصہ کے یہاں بھی گیا تھا اور اس سے کہہ آیا تھا کہ کہیں کسی خود فریبی میں نہ مبتلا رہنا۔ یہ تمہاری پڑوسن تم سے زیادہ خوبصورت اور پاک ہیں اور رسول اللہ صلی اللہ علیہ وسلم کو زیادہ محبوب بھی ہیں۔ آپ عائشہ رضی اللہ عنہا کی طرف اشارہ کر رہے تھے۔ اس بات پر آپ صلی اللہ علیہ وسلم دوبارہ مسکرا دیئے۔ جب میں نے آپ صلی اللہ علیہ وسلم کو مسکراتے دیکھا، تو ( آپ صلی اللہ علیہ وسلم کے پاس ) بیٹھ گیا۔ اور آپ کے گھر میں چاروں طرف دیکھنے لگا۔ بخدا! سوائے تین کھالوں کے اور کوئی چیز وہاں نظر نہ آئی۔ میں نے کہا۔ یا رسول اللہ! آپ اللہ تعالیٰ سے دعا فرمائیے کہ وہ آپ کی امت کو کشادگی عطا فرما دے۔ فارس اور روم کے لوگ تو پوری فراخی کے ساتھ رہتے ہیں۔ دنیا انہیں خوب ملی ہوئی ہے۔ حالانکہ وہ اللہ تعالیٰ کی عبادت بھی نہیں کرتے۔ آپ صلی اللہ علیہ وسلم ٹیک لگائے ہوئے تھے۔ آپ صلی اللہ علیہ وسلم نے فرمایا، اے خطاب کے بیٹے! کیا تمہیں ابھی کچھ شبہ ہے؟ ( تو دنیا کی دولت کو اچھی سمجھتا ہے ) یہ تو ایسے لوگ ہیں کہ ان کے اچھے اعمال ( جو وہ معاملات کی حد تک کرتے ہیں ان کی جزا ) اسی دنیا میں ان کو دے دی گئی ہے۔ ( یہ سن کر ) میں بول اٹھا۔ یا رسول اللہ! میرے لیے اللہ سے مغفرت کی دعا کیجئے۔ تو نبی کریم صلی اللہ علیہ وسلم نے ( اپنی ازواج سے ) اس بات پر علیحدگی اختیار کر لی تھی کہ عائشہ رضی اللہ عنہا سے حفصہ رضی اللہ عنہ نے پوشیدہ بات کہہ دی تھی۔ نبی کریم صلی اللہ علیہ وسلم نے اس انتہائی خفگی کی وجہ سے جو آپ صلی اللہ علیہ وسلم کو ہوئی تھی، فرمایا تھا کہ میں اب ان کے پاس ایک مہینے تک نہیں جاؤں گا۔ اور یہی موقعہ ہے جس پر اللہ تعالیٰ نے آپ صلی اللہ علیہ وسلم کو متنبہ کیا تھا۔ پھر جب انتیس دن گزر گئے تو آپ عائشہ رضی اللہ عنہا کے گھر تشریف لے گئے اور انہیں کے یہاں سے آپ صلی اللہ علیہ وسلم نے ابتداء کی۔ عائشہ رضی اللہ عنہا نے کہا کہ آپ نے تو عہد کیا تھا کہ ہمارے یہاں ایک مہینے تک نہیں تشریف لائیں گے۔ اور آج ابھی انتیسویں کی صبح ہے۔ میں تو دن گن رہی تھی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، یہ مہینہ انتیس دن کا ہے اور وہ مہینہ انتیس ہی دن کا تھا۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ پھر وہ آیت نازل ہوئی جس میں ( ازواج النبی کو ) اختیار دیا گیا تھا۔ اس کی بھی ابتداء آپ صلی اللہ علیہ وسلم نے مجھ ہی سے کی اور فرمایا کہ میں تم سے ایک بات کہتا ہوں، اور یہ ضروری نہیں کہ جواب فوراً دو، بلکہ اپنے والدین سے بھی مشورہ کر لو۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ آپ کو یہ معلوم تھا کہ میرے ماں باپ کبھی آپ سے جدائی کا مشورہ نہیں دے سکتے۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ نے فرمایا ہے کہ ”اے نبی! اپنی بیویوں سے کہہ دو“ اللہ تعالیٰ کے قول عظیما تک۔ میں نے عرض کیا کیا اب اس معاملے میں بھی میں اپنے والدین سے مشورہ کرنے جاؤں گی! اس میں تو کسی شبہ کی گنجائش ہی نہیں ہے۔ کہ میں اللہ اور اس کے رسول اور دار آخرت کو پسند کرتی ہوں۔ اس کے بعد آپ صلی اللہ علیہ وسلم نے اپنی دوسری بیویوں کو بھی اختیار دیا اور انہوں نے بھی وہی جواب دیا جو عائشہ رضی اللہ عنہا نے دیا تھا۔' WHERE id = 2373;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، انہوں نے کہا ہم سے سفیان نے بیان کیا، انہوں نے کہا ہم سے ابن ابی نجیح نے بیان کیا، ان سے مجاہد نے بیان کیا، ان سے ابومعمر نے بیان کیا، اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم ( فتح مکہ دن جب ) مکہ میں داخل ہوئے تو خانہ کعبہ کے چاروں طرف تین سو ساٹھ بت تھے۔ آپ صلی اللہ علیہ وسلم کے ہاتھ میں ایک چھڑی تھی جس سے آپ صلی اللہ علیہ وسلم ان بتوں پر مارنے لگے اور فرمانے لگے کہ «جاء الحق وزهق الباطل‏» ”حق آ گیا اور باطل مٹ گیا“۔' WHERE id = 2383;
UPDATE hadiths SET urdu = 'ہم سے علی بن حکم انصاری نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، ان سے سعید بن مسروق نے، ان سے عبایہ بن رفاعہ بن رافع بن خدیج رضی اللہ عنہ نے اور ان سے ان کے دادا (رافع بن خدیج رضی اللہ عنہ) نے بیان کیا کہ ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ مقام ذوالحلیفہ میں ٹھہرے ہوئے تھے۔ لوگوں کو بھوک لگی۔ ادھر ( غنیمت میں ) اونٹ اور بکریاں ملی تھیں۔ انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم لشکر کے پیچھے کے لوگوں میں تھے۔ لوگوں نے جلدی کی اور ( تقسیم سے پہلے ہی ) ذبح کر کے ہانڈیاں چڑھا دیں۔ لیکن بعد میں نبی کریم صلی اللہ علیہ وسلم نے حکم دیا اور وہ ہانڈیاں اوندھا دی گئیں۔ پھر آپ صلی اللہ علیہ وسلم نے ان کو تقسیم کیا اور دس بکریوں کو ایک اونٹ کے برابر رکھا۔ ایک اونٹ اس میں سے بھاگ گیا تو لوگ اسے پکڑنے کی کوشش کرنے لگے۔ لیکن اس نے سب کو تھکا دیا۔ قوم کے پاس گھوڑے کم تھے۔ ایک صحابی تیر لے کر اونٹ کی طرف جھپٹے۔ اللہ نے اس کو ٹھہرا دیا۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ ان جانوروں میں بھی جنگلی جانوروں کی طرح سرکشی ہوتی ہے۔ اس لیے ان جانوروں میں سے بھی اگر کوئی تمہیں عاجز کر دے تو اس کے ساتھ تم ایسا ہی معاملہ کیا کرو۔ پھر میرے دادا نے عرض کیا کہ کل دشمن کے حملہ کا خوف ہے، ہمارے پاس چھریاں نہیں ہیں ( تلواروں سے ذبح کریں تو ان کے خراب ہونے کا ڈر ہے جب کہ جنگ سامنے ہے ) کیا ہم بانس کے کھپچی سے ذبح کر سکتے ہیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا، جو چیز بھی خون بہا دے اور ذبیحہ پر اللہ تعالیٰ کا نام لیا گیا ہو، تو اس کے کھانے میں کوئی حرج نہیں۔ سوائے دانت اور ناخن کے۔ اس کی وجہ میں تمہیں بتاتا ہوں۔ دانت تو ہڈی ہے اور ناخن حبشیوں کی چھری ہے۔' WHERE id = 2393;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے لیث نے بیان کیا، ان سے یزید بن ابی حبیب نے، ان سے ابوالخیر نے اور ان سے عقبہ بن عامر رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے انہیں بکریاں دی تھیں کہ قربانی کے لیے ان کو صحابہ میں تقسیم کر دیں۔ پھر ایک سال کا بکری کا بچہ بچ گیا تو انہوں نے آپ صلی اللہ علیہ وسلم سے اس کا ذکر کیا۔ آپ صلی اللہ علیہ وسلم نے عقبہ سے فرمایا تو اس کی قربانی کر لے۔' WHERE id = 2404;
UPDATE hadiths SET urdu = 'ہم سے خلاد بن یحییٰ نے بیان کیا، کہا ہم سے نافع بن عمر نے بیان کیا، ان سے ابن ابی ملیکہ نے کہ میں نے عبداللہ بن عباس رضی اللہ عنہما کی خدمت میں ( دو عورتوں کے مقدمہ میں ) لکھا تو اس کے جواب میں انہوں نے تحریر فرمایا کہ نبی کریم صلی اللہ علیہ وسلم نے فیصلہ کیا تھا کہ ( اگر مدعی گواہ نہ پیش کر سکے ) تو مدعیٰ علیہ سے قسم لی جائے گی۔' WHERE id = 2416;
UPDATE hadiths SET urdu = 'ہم سے احمد بن ابی رجاء نے بیان کیا، انہوں نے کہا ہم سے یحییٰ بن آدم نے بیان کیا، کہا ہم سے جریر بن حازم نے بیان کیا، کہا میں نے قتادہ سے سنا، کہا کہ مجھ سے نضر بن انس بن مالک نے بیان کیا، ان سے بشیر بن نہیک نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جس نے کسی غلام کا ایک حصہ آزاد کیا۔“' WHERE id = 2427;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا، کہا ہم سے جریر نے بیان کیا، ان سے منصور نے، ان سے ابراہیم نے، ان سے اسود نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ بریرہ رضی اللہ عنہا کو میں نے خریدا تو ان کے مالکوں نے ولاء کی شرط لگائی ( کہ آزادی کے بعد وہ انہیں کے حق میں قائم رہے گی ) میں نے رسول اللہ صلی اللہ علیہ وسلم سے اس کا ذکر کیا تو آپ صلی اللہ علیہ وسلم نے فرمایا تم انہیں آزاد کر دو، ولاء تو اسی کی ہوتی ہے جو قیمت دے کر کسی غلام کو آزاد کر دے۔ پھر میں نے انہیں آزاد کر دیا۔ پھر نبی کریم صلی اللہ علیہ وسلم نے بریرہ رضی اللہ عنہا کو بلایا اور ان کے شوہر کے سلسلے میں انہیں اختیار دیا۔ بریرہ نے کہا کہ اگر وہ مجھے فلاں فلاں چیز بھی دیں تب بھی میں اس کے پاس نہ رہوں گی۔ چنانچہ وہ اپنے شوہر سے جدا ہو گئیں۔' WHERE id = 2437;
UPDATE hadiths SET urdu = 'ہم سے بشر بن محمد نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، کہا ہم کو یونس نے خبر دی، انہوں نے زہری سے سنا، انہوں نے کہا کہ میں نے سعید بن مسیب سے سنا، انہوں نے کہا کہ ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ ان سے نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”غلام جو کسی کی ملکیت میں ہو اور نیکو کار ہو تو اسے دو ثواب ملتے ہیں۔“ اور ابوہریرہ رضی اللہ عنہ نے کہا، اس ذات کی قسم جس کے ہاتھ میں میری جان ہے اگر اللہ تعالیٰ کے راستے میں جہاد، حج اور والدہ کی خدمت ( کی روک ) نہ ہوتی تو میں پسند کرتا کہ غلام رہ کر مروں۔' WHERE id = 2448;
UPDATE hadiths SET urdu = 'لیث نے کہا کہ مجھ سے یونس نے بیان کیا، ان سے ابن شہاب نے، ان سے عروہ نے کہ عائشہ رضی اللہ عنہا نے کہا کہ بریرہ رضی اللہ عنہا ان کے پاس آئیں اپنے مکاتبت کے معاملہ میں ان کی مدد حاصل کرنے کے لیے۔ بریرہ رضی اللہ عنہا کو پانچ اوقیہ چاندی پانچ سال کے اندر پانچ قسطوں میں ادا کرنی تھی۔ عائشہ رضی اللہ عنہا نے کہا، انہیں خود بریرہ رضی اللہ عنہا کے آزاد کرانے میں دلچسپی ہو گئی تھی، ( عائشہ رضی اللہ عنہا نے فرمایا ) کہ یہ بتاؤ اگر میں انہیں ایک ہی مرتبہ ( چاندی کے یہ پانچ اوقیہ ) ادا کر دوں تو کیا تمہارے مالک تمہیں میرے ہاتھ بیچ دیں گے؟ پھر میں تمہیں آزاد کر دوں گی اور تمہاری ولاء میرے ساتھ قائم ہو جائے گی۔ بریرہ رضی اللہ عنہا اپنے مالکوں کے ہاں گئیں اور ان کے آگے یہ صورت رکھی۔ انہوں نے کہا کہ ہم یہ صورت اس وقت منظور کر سکتے ہیں کہ رشتہ ولاء ہمارے ساتھ رہے۔ عائشہ رضی اللہ عنہا نے کہا کہ پھر میرے پاس نبی کریم صلی اللہ علیہ وسلم تشریف لائے تو میں نے آپ صلی اللہ علیہ وسلم سے اس کا ذکر کیا آپ صلی اللہ علیہ وسلم نے فرمایا کہ تو خرید کر بریرہ رضی اللہ عنہا کو آزاد کر دے، ولاء تو اس کی ہوتی ہے جو آزاد کرے۔ پھر رسول اللہ صلی اللہ علیہ وسلم نے لوگوں کو خطاب فرمایا کہ کچھ لوگوں کو کیا ہو گیا ہے جو ( معاملات میں ) ایسی شرطیں لگاتے ہیں جن کی کوئی جڑ ( دلیل ) بنیاد کتاب اللہ میں نہیں ہے۔ پس جو شخص کوئی ایسی شرط لگائے جس کی کوئی اصل ( دلیل، بنیاد ) کتاب اللہ میں نہ ہو تو وہ شرط غلط ہے۔ اللہ تعالیٰ کی شرط ہی زیادہ حق اور زیادہ مضبوط ہے۔' WHERE id = 2459;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، کہا کہ مجھ سے محمد بن جعفر نے بیان کیا ابوحازم سے، وہ عبداللہ بن ابی قتادہ سلمی سے اور ان سے ان کے باپ نے بیان کیا کہ مکہ کے راستے میں ایک جگہ میں رسول اللہ صلی اللہ علیہ وسلم کے چند ساتھیوں کے ساتھ بیٹھا ہوا تھا۔ رسول اللہ صلی اللہ علیہ وسلم ہم سے آگے قیام فرما تھے۔ ( حجۃ الوداع کے موقع پر ) اور لوگ تو احرام باندھے ہوئے تھے لیکن میرا احرام نہیں تھا۔ میرے ساتھیوں نے ایک گورخر دیکھا۔ میں اس وقت اپنی جوتی گانٹھنے میں مشغول تھا۔ ان لوگوں نے مجھ کو کچھ خبر نہیں دی۔ لیکن ان کی خواہش یہی تھی کہ کسی طرح میں گورخر کو دیکھ لوں۔ چنانچہ میں نے جو نظر اٹھائی تو گورخر دکھائی دیا۔ میں فوراً گھوڑے کے پاس گیا اور اس پر زین کس کر سوار ہو گیا، مگر اتفاق سے ( جلدی میں ) کوڑا اور نیزہ دونوں بھول گیا۔ اس لیے میں نے اپنے ساتھیوں سے کہا کہ وہ مجھے کوڑا اور نیزہ اٹھا دیں۔ انہوں نے کہا ہرگز نہیں قسم اللہ کی، ہم تمہارے ( شکار میں ) کسی قسم کی مدد نہیں کر سکتے۔ ( کیونکہ ہم سب لوگ حالت احرام میں ہیں ) مجھے اس پر غصہ آیا اور میں نے خود ہی اتر کر دونوں چیزیں لے لیں۔ پھر سوار ہو کر گورخر پر حملہ کیا اور اس کو شکار کر لایا۔ وہ مر بھی چکا تھا۔ اب لوگوں نے کہا کہ اسے کھانا چاہئے۔ لیکن پھر احرام کی حالت میں اسے کھانے ( کے جواز ) پر شبہ ہوا۔ ( لیکن بعض لوگوں نے شبہ نہیں کیا اور گوشت کھایا ) پھر ہم آگے بڑھے اور میں نے اس گورخر کا ایک بازو چھپا رکھا تھا۔ جب ہم رسول اللہ صلی اللہ علیہ وسلم کے پاس پہنچے تو اس کے متعلق آپ سے سوال کیا، ( آپ صلی اللہ علیہ وسلم نے محرم کے لیے شکار کے گوشت کھانے کا فتویٰ دیا ) اور دریافت فرمایا کہ اس میں سے کچھ بچا ہوا گوشت تمہارے پاس موجود بھی ہے؟ میں نے کہا کہ جی ہاں! اور وہی بازو آپ صلی اللہ علیہ وسلم کی خدمت میں پیش کیا۔ آپ صلی اللہ علیہ وسلم نے اسے تناول فرمایا۔ یہاں تک کہ وہ ختم ہو گیا۔ آپ صلی اللہ علیہ وسلم بھی اس وقت احرام سے تھے ( ابوحازم نے کہا کہ ) مجھ سے یہی حدیث زید بن اسلم نے بیان کی، ان سے عطاء بن یسار نے اور ان سے ابوقتادہ رضی اللہ عنہ نے۔' WHERE id = 2469;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا کہ ہم سے حماد بن زید نے بیان کیا ہشام سے، ان سے ان کے والد نے، ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ لوگ تحائف بھیجنے کے لیے میری باری کا انتظار کیا کرتے تھے۔ اور ام سلمہ رضی اللہ عنہا نے کہا میری سوکنیں ( امہات المؤمنین رضوان اللہ علیہن ) جمع تھیں اس وقت انہوں نے نبی کریم صلی اللہ علیہ وسلم سے ( بطور شکایت لوگوں کی اس روش کا ) ذکر کیا۔ تو آپ صلی اللہ علیہ وسلم نے انہیں کوئی جواب نہیں دیا۔' WHERE id = 2479;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، ان سے لیث نے، ان سے یزید بن ابی حبیب نے، ان سے بکیر نے، ان سے ابن عباس کے غلام کریب نے اور انہیں (ام المؤمنین) میمونہ بنت حارث رضی اللہ عنہا نے خبر دی کہ انہوں نے ایک لونڈی نبی کریم صلی اللہ علیہ وسلم سے اجازت لیے بغیر آزاد کر دی۔ پھر جس دن نبی کریم صلی اللہ علیہ وسلم کی باری آپ کے گھر آنے کی تھی، انہوں نے خدمت نبوی میں عرض کیا، یا رسول اللہ صلی اللہ علیہ وسلم ! آپ کو معلوم بھی ہوا، میں نے ایک لونڈی آزاد کر دی ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا، اچھا تم نے آزاد کر دیا؟ انہوں نے عرض کیا کہ ہاں! فرمایا کہ اگر اس کے بجائے تم نے اپنے ننھیال والوں کو دی ہوتی تو تمہیں اس سے بھی زیادہ ثواب ملتا۔ اس حدیث کو بکیر بن مضر نے عمرو بن حارث سے، انہوں نے بکیر سے، انہوں نے کریب سے روایت کیا کہ میمونہ رضی اللہ عنہا نے اپنی لونڈی آزاد کر دی۔ اخیر تک۔' WHERE id = 2490;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن قزعہ نے بیان کیا، کہا ہم سے امام مالک نے، وہ ابوحازم سے، وہ سہل بن سعد رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں پینے کو کچھ لایا، ( دودھ یا پانی ) آپ صلی اللہ علیہ وسلم نے اسے نوش فرمایا، آپ صلی اللہ علیہ وسلم کے دائیں طرف ایک بچہ بیٹھا تھا اور بڑے بوڑھے لوگ بائیں طرف بیٹھے ہوئے تھے، آپ صلی اللہ علیہ وسلم نے اس بچے سے فرمایا کہ اگر تو اجازت دے ( تو بچا ہوا پانی ) میں ان بڑے لوگوں کو دے دوں؟ لیکن اس نے کہا۔ یا رسول اللہ! آپ کے جوٹھے میں سے ملنے والے کسی حصہ کا میں ایثار نہیں کر سکتا۔ آپ صلی اللہ علیہ وسلم نے پیالہ جھٹکے کے ساتھ اسی کی طرف بڑھا دیا۔' WHERE id = 2500;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا کہ مجھے عبدالمالک بن میسرہ نے خبر دی، کہا کہ میں نے زید بن وہب سے سنا کہ علی رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے مجھے ایک ریشمی حلہ ہدیہ میں دیا تو میں نے اسے پہن لیا۔ لیکن جب غصے کے آثار روئے مبارک پر دیکھے تو اسے اپنی عورتوں میں پھاڑ کر تقسیم کر دیا۔' WHERE id = 2511;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، ان سے شیبان نے بیان کیا، ان سے یحییٰ نے، ان سے ابوسلمہ نے اور ان سے جابر رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے عمریٰ کے متعلق فیصلہ کیا تھا کہ وہ اس کا ہو جاتا ہے جسے ہبہ کیا گیا ہو۔' WHERE id = 2521;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا کہ ہم کو شعیب نے خبر دی، ان سے ابوالزناد نے بیان کیا، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”ابراہیم علیہ السلام نے سارہ علیہا السلام کے ساتھ ہجرت کی تو انہیں بادشاہ نے آجر کو ( یعنی ہاجرہ علیہا السلام کو ) عطیہ میں دے دیا۔ پھر وہ واپس ہوئیں اور ابراہیم علیہ السلام سے کہا، دیکھا آپ نے اللہ تعالیٰ نے کافر کو کس طرح ذلیل کیا اور ایک لڑکی خدمت کے لیے بھی دے دی۔ ابن سیرین نے کہا، ان سے ابوہریرہ رضی اللہ عنہ نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے بیان کیا کہ بادشاہ نے ہاجرہ کو ان کی خدمت کے لیے دے دیا تھا۔' WHERE id = 2531;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے ہمام نے بیان کیا، کہا ہم سے قتادہ نے بیان کیا جابر بن زید سے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے حمزہ رضی اللہ عنہ کی صاحبزادی کے متعلق فرمایا ”یہ میرے لیے حلال نہیں ہو سکتیں، جو رشتے نسب کی وجہ سے حرام ہو جاتے ہیں، وہی دودھ کی وجہ سے بھی حرام ہو جاتے ہیں۔ یہ تو میرے رضاعی بھائی کی لڑکی ہے۔“' WHERE id = 2541;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبید بن میمون نے بیان کیا، کہا ہم کو عیسیٰ بن یونس نے خبر دی، انہیں ہشام نے، انہیں ان کے باپ نے، اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ایک شخص کو مسجد میں قرآن پڑھتے سنا تو فرمایا کہ ان پر اللہ تعالیٰ رحم فرمائے مجھے انہوں نے اس وقت فلاں اور فلاں آیتیں یاد دلا دیں جنہیں میں فلاں فلاں سورتوں میں سے بھول گیا تھا۔ عباد بن عبداللہ رضی اللہ عنہما نے اپنی روایت میں عائشہ رضی اللہ عنہا سے یہ الفاظ زیادہ بیان کیے ہیں کہ نبی کریم صلی اللہ علیہ وسلم نے میرے گھر میں تہجد کی نماز پڑھی۔ اس وقت آپ صلی اللہ علیہ وسلم نے عباد رضی اللہ عنہ کی آواز سنی کہ وہ مسجد میں نماز پڑھ رہے ہیں۔ آپ نے پوچھا عائشہ! کیا یہ عباد کی آواز ہے؟ میں نے کہا جی ہاں! آپ نے فرمایا، اے اللہ! عباد پر رحم فرما۔' WHERE id = 2551;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کا، انہوں نے کہا ہم سے سفیان نے بیان کیا، انہوں نے کہا ہم سے صفوان بن سلیم نے بیان کیا، ان سے عطاء بن یسار نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”ہر بالغ پر جمعہ کے دن غسل واجب ہے۔“' WHERE id = 2561;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے کہا کہ ہم سے جویریہ نے بیان کیا، انہوں نے کہا کہ نافع نے عبداللہ بن عمر رضی اللہ عنہما سے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اگر کسی کو قسم کھانی ہی ہے تو اللہ تعالیٰ ہی کی قسم کھائے، ورنہ خاموش رہے۔“' WHERE id = 2572;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے ابوبکر کے غلام سمی نے بیان کیا، ان سے ابوصالح نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اگر لوگوں کو معلوم ہوتا کہ اذان اور صف اول میں کتنا ثواب ہے اور پھر ( انہیں اس کے حاصل کرنے کے لیے ) قرعہ اندازی کرنی پڑتی، تو وہ قرعہ اندازی بھی کرتے اور اگر انہیں معلوم ہو جائے کہ نماز سویرے پڑھنے میں کتنا ثواب ہے تو لوگ ایک دوسرے سے سبقت کرنے لگیں اور اگر انہیں معلوم ہو جائے کہ عشاء اور صبح کی کتنی فضیلتیں ہیں تو اگر گھٹنوں کے بل آنا پڑتا تو پھر بھی آتے۔“' WHERE id = 2582;
UPDATE hadiths SET urdu = 'موسیٰ بن مسعود نے بیان کیا کہ ہم سے سفیان بن سعید نے بیان کیا، ان سے ابواسحاق نے اور ان سے براء بن عازب رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے صلح حدیبیہ مشرکین کے ساتھ تین شرائط پر کی تھی، ( 1 ) یہ کہ مشرکین میں سے اگر کوئی آدمی آپ صلی اللہ علیہ وسلم کے پاس آ جائے تو آپ صلی اللہ علیہ وسلم اسے واپس کر دیں گے۔ لیکن اگر مسلمانوں میں سے کوئی مشرکین کے یہاں پناہ لے گا تو یہ لوگ ایسے شخص کو واپس نہیں کریں گے۔ ( 2 ) یہ کہ آپ صلی اللہ علیہ وسلم آئندہ سال مکہ آ سکیں گے اور صرف تین دن ٹھہریں گے۔ ( 3 ) یہ کہ ہتھیار، تلوار، تیر وغیرہ نیام اور ترکش میں ڈال کر ہی مکہ میں داخل ہوں گے۔ چنانچہ ابوجندل رضی اللہ عنہ ( جو مسلمان ہو گئے تھے اور قریش نے ان کو قید کر رکھا تھا ) بیڑیوں کو گھسیٹتے ہوئے آئے، تو آپ صلی اللہ علیہ وسلم نے انہیں ( شرائط معاہدہ کے مطابق ) مشرکوں کو واپس کر دیا۔ امام بخاری رحمہ اللہ نے کہا کہ مؤمل نے سفیان سے ابوجندل کا ذکر نہیں کیا ہے اور «إلا بجلبان السلاح» کے بجائے «إلا بجلب السلاح‏.» کے الفاظ نقل کیے ہیں۔' WHERE id = 2592;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، کہا ہم سے عثمان بن عمر نے بیان کیا، انہیں یونس نے خبر دی اور لیث نے بیان کیا کہ مجھ سے یونس نے بیان کیا، ان سے ابن شہاب نے، انہیں عبداللہ بن کعب نے خبر دی اور انہیں کعب بن مالک رضی اللہ عنہ نے خبر دی کہ انہوں نے ابن ابی حدرد رضی اللہ عنہ سے اپنا قرض طلب کیا، جو ان کے ذمہ تھا۔ یہ رسول اللہ صلی اللہ علیہ وسلم کے عہد مبارک کا واقعہ ہے۔ مسجد کے اندر ان دونوں کی آواز اتنی بلند ہو گئی کہ رسول اللہ صلی اللہ علیہ وسلم نے بھی سنی۔ آپ صلی اللہ علیہ وسلم اس وقت اپنے حجرے میں تشریف رکھتے تھے۔ چنانچہ آپ صلی اللہ علیہ وسلم باہر آئے اور اپنے حجرہ کا پردہ اٹھا کر کعب بن مالک رضی اللہ عنہ کو آواز دی۔ آپ صلی اللہ علیہ وسلم نے پکارا اے کعب! انہوں نے کہا یا رسول اللہ، میں حاضر ہوں۔ پھر آپ صلی اللہ علیہ وسلم نے اپنے ہاتھ کے اشارے سے فرمایا کہ آدھا معاف کر دے۔ کعب رضی اللہ عنہ نے کہا کہ میں نے کر دیا یا رسول اللہ! آپ صلی اللہ علیہ وسلم نے ( ابن ابی حدرد رضی اللہ عنہ سے ) فرمایا کہ اب اٹھو اور قرض ادا کر دو۔' WHERE id = 2602;
UPDATE hadiths SET urdu = 'ہم سے مالک بن اسماعیل نے بیان کیا، کہا ہم سے ابن عیینہ نے بیان کیا، کہا ہم سے یحییٰ بن سعید نے بیان کیا، کہا کہ میں نے حنظلہ زرقی سے سنا، انہوں نے کہا کہ میں نے رافع بن خدیج رضی اللہ عنہ سے سنا، آپ بیان کرتے تھے کہ ہم اکثر انصار کاشتکاری کیا کرتے تھے اور ہم زمین بٹائی پر دیتے تھے۔ اکثر ایسا ہوتا کہ کسی کھیت کے ایک ٹکڑے میں پیداوار ہوتی اور دوسرے میں نہ ہوتی، اس لیے ہمیں اس سے منع کر دیا گیا۔ لیکن چاندی ( روپے وغیرہ ) کے لگان سے منع نہیں کیا گیا۔' WHERE id = 2613;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا۔ کہا ہم سے سفیان بن عیینہ نے بیان کیا ‘ یحییٰ بن سعید انصاری سے ‘ ان سے عمرہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ بریرہ رضی اللہ عنہا اپنے مکاتبت کے سلسلے میں ان سے مدد مانگنے آئیں تو انہوں نے کہا کہ اگر تم چاہو تو تمہارے مالکوں کو ( پوری قیمت ) دے دوں اور تمہاری ولاء میرے ہو گی۔ پھر جب رسول اللہ صلی اللہ علیہ وسلم تشریف لائے تو آپ صلی اللہ علیہ وسلم سے میں نے اس کا ذکر کیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا انہیں تو خرید لے اور آزاد کر دے۔ ولاء تو بہرحال اسی کی ہو گی جو آزاد کر دے۔ پھر رسول اللہ صلی اللہ علیہ وسلم منبر پر تشریف لائے اور فرمایا ان لوگوں کو کیا ہو گیا ہے جو ایسی شرطیں لگاتے ہیں جن کا کوئی پتہ ( دلیل، سند ) کتاب اللہ میں نہیں ہے ‘ جس نے بھی کوئی ایسی شرط لگائی جس کا پتہ ( دلیل، سند ) کتاب اللہ میں نہ ہو تو خواہ ایسی سو شرطیں لگا لے ان سے کچھ فائدہ نہ اٹھائے گا۔' WHERE id = 2624;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعبنی نے بیان کیا ‘ کہا ہم سے امام مالک نے ابن شہاب سے ‘ وہ عروہ بن زبیر سے اور ان سے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے بیان کیا کہ عتبہ بن ابی وقاص نے مرتے وقت اپنے بھائی سعد بن ابی وقاص رضی اللہ عنہ کو وصیت کی تھی کہ زمعہ کی باندی کا لڑکا میرا ہے ‘ اس لیے تم اسے لے لینا چنانچہ فتح مکہ کے موقع پر سعد رضی اللہ عنہ نے اسے لے لیا اور کہا کہ میرے بھائی کا لڑکا ہے۔ انہوں نے اس بارے میں مجھے اس کی وصیت کی تھی۔ پھر عبد بن زمعہ رضی اللہ عنہ اٹھے اور کہنے لگے کہ یہ تو میرا بھائی ہے میرے باپ کی لونڈی نے اس کو جنا ہے اور میرے باپ کے بستر پر پیدا ہوا ہے۔ پھر یہ دونوں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے۔ سعد بن ابی وقاص رضی اللہ عنہ نے عرض کیا یا رسول اللہ! یہ میرے بھائی کا لڑکا ہے ‘ مجھے اس نے وصیت کی تھی۔ لیکن عبد بن زمعہ رضی اللہ عنہ نے عرض کیا کہ یہ میرا بھائی اور میرے والد کی باندی کا لڑکا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فیصلہ یہ فرمایا کہ لڑکا تمہارا ہی ہے عبد بن زمعہ! بچہ فراش کے تحت ہوتا ہے اور زانی کے حصے میں پتھر ہیں لیکن آپ صلی اللہ علیہ وسلم نے سودہ بنت زمعہ رضی اللہ عنہا سے فرمایا کہ اس لڑکے سے پردہ کر کیونکہ آپ صلی اللہ علیہ وسلم نے عتبہ کی مشابہت اس لڑکے میں صاف پائی تھی۔ چنانچہ اس کے بعد اس لڑکے نے سودہ رضی اللہ عنہا کو کبھی نہ دیکھا تاآنکہ آپ اللہ تعالیٰ سے جا ملیں۔' WHERE id = 2634;
UPDATE hadiths SET urdu = 'ہم سے اسمٰعیل بن ابی اویس نے بیان کیا، کہا ہم سے امام مالک نے بیان کیا، ان سے ابوالزناد نے، ان نے اعرج سے اور ان ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے دیکھا کہ ایک صاحب قربانی کا اونٹ ہانکے لیے جا رہے ہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس پر سوار ہو جا لیکن انہوں نے معذرت کی کہ یا رسول اللہ! یہ تو قربانی کا ہے۔ آپ صلی اللہ علیہ وسلم نے پھر فرمایا کہ سوار بھی ہو جا۔ افسوس! یہ کلمہ آپ صلی اللہ علیہ وسلم نے تیسری یا چوتھی مرتبہ فرمایا تھا۔' WHERE id = 2644;
UPDATE hadiths SET urdu = 'ہم سے عبید بن اسماعیل نے بیان کیا ‘ کہا ہم سے ابواسامہ نے بیان کیا ہشام سے ‘ ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے ( قرآن مجید کی اس آیت ) «ومن كان غنيا فليستعفف ومن كان فقيرا فليأكل بالمعرو» ”اور جو شخص مالدار ہو وہ اپنے کو یتیم کے مال سے بالکل روکے رکھے ‘ البتہ جو شخص نادار ہو تو وہ دستور کے مطابق کھا سکتا ہے“ کے بارے میں فرمایا کہ یتیموں کے ولیوں کے بارے میں نازل ہوئی کہ یتیم کے مال میں سے اگر ولی نادار ہو تو دستور کے مطابق اس کے مال میں سے لے سکتا ہے۔' WHERE id = 2654;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ بن قطان نے بیان کیا، کہا ہم سے عبیداللہ بن عمری نے بیان کیا، کہا کہ مجھ سے نافع نے بیان کیا، اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے اپنا ایک گھوڑا اللہ کے راستے میں ( جہاد کرنے کے لیے ) ایک آدمی کو دے دیا۔ یہ گھوڑا آپ صلی اللہ علیہ وسلم کو عمر رضی اللہ عنہ نے دیا تھا ‘ تاکہ آپ صلی اللہ علیہ وسلم جہاد میں کسی کو اس پر سوار کریں۔ پھر عمر رضی اللہ عنہ کو معلوم ہوا کہ جس شخص کو یہ گھوڑا ملا تھا ‘ وہ اس گھوڑے کو بازار میں بیچ رہا ہے۔ اس لیے رسول اللہ صلی اللہ علیہ وسلم سے پوچھا کہ کیا وہ اسے خرید سکتے ہیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہرگز اسے نہ خرید۔ اپنا دیا ہوا صدقہ واپس نہ لے۔' WHERE id = 2664;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن منصور نے بیان کیا ‘ کہا ہم کو عفان بن مسلم نے خبر دی ‘ کہا ہم سے ہمام نے ‘ کہا ہم سے محمد بن حجادہ نے بیان کیا ‘ کہا کہ مجھے ابوحصین نے خبر دی ‘ ان سے ذکوان نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ ایک صاحب ( نام نامعلوم ) رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں آئے اور عرض کیا کہ مجھے کوئی ایسا عمل بتا دیجئیے جو ثواب میں جہاد کے برابر ہو۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ایسا کوئی عمل میں نہیں پاتا۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کیا تم اتنا کر سکتے ہو کہ جب مجاہد ( جہاد کے لیے ) نکلے تو تم اپنی مسجد میں آ کر برابر نماز پڑھنی شروع کر دو اور ( نماز پڑھتے رہو اور درمیان میں ) کوئی سستی اور کاہلی تمہیں محسوس نہ ہو، اسی طرح روزے رکھنے لگو اور کوئی دن بغیر روزے کے نہ گزرے۔ ان صاحب نے عرض کیا بھلا ایسا کون کر سکتا ہے؟ ابوہریرہ رضی اللہ عنہ نے فرمایا کہ مجاہد کا گھوڑا جب رسی میں بندھا ہوا زمین ( پر پاؤں ) مارتا ہے تو اس پر بھی اس کے لیے نیکیاں لکھی جاتی ہیں۔' WHERE id = 2674;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، انہیں سعید بن مسیب نے، ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم فرما رہے تھے اس ذات کی قسم جس کے ہاتھ میں میری جان ہے! اگر مسلمانوں کے دلوں میں اس سے رنج نہ ہوتا کہ میں ان کو چھوڑ کر جہاد کے لیے نکل جاؤں اور مجھے خود اتنی سواریاں میسر نہیں ہیں کہ ان سب کو سوار کر کے اپنے ساتھ لے چلوں تو میں کسی چھوٹے سے چھوٹے ایسے لشکر کے ساتھ جانے سے بھی نہ رکتا جو اللہ کے راستے میں غزوہ کے لیے جا رہا ہوتا۔ اس ذات کی قسم جس کے ہاتھ میں میری جان ہے! میری تو آرزو ہے کہ میں اللہ کے راستے میں قتل کیا جاؤں، پھر زندہ کیا جاؤں، پھر قتل کیا جاؤں اور پھر زندہ کیا جاؤں پھر قتل کیا جاؤں اور پھر زندہ کیا جاؤں اور پھر قتل کر دیا جاؤں۔' WHERE id = 2685;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا ‘ کہا ہم سے شعبہ نے بیان کیا ‘ ان سے عمرو بن مرہ نے ‘ ان سے ابووائل نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے بیان کیا کہ ایک صحابی ( لاحق بن ضمیرہ ) نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور عرض کیا کہ ایک شخص جنگ میں شرکت کرتا ہے غنیمت حاصل کرنے کے لیے ایک شخص جنگ میں شرکت کرتا ہے ناموری کے لیے ‘ ایک شخص جنگ میں شرکت کرتا ہے تاکہ اس کی بہادری کی دھاک بیٹھ جائے تو ان میں سے اللہ کے راستے میں کون لڑتا ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا جو شخص اس ارادہ سے جنگ میں شریک ہوتا ہے کہ اللہ ہی کا کلمہ بلند رہے ‘ صرف وہی اللہ کے راستہ میں لڑتا ہے۔' WHERE id = 2696;
UPDATE hadiths SET urdu = 'ہم سے احمد بن عبدالملک بن واقد نے بیان کیا ‘ کہا ہم سے حماد بن زید نے بیان کیا ثابت بنانی سے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم سب سے زیادہ حسین ( خوبصورت ) سب سے زیادہ بہادر اور سب سے زیادہ فیاض تھے ‘ مدینہ طیبہ کے تمام لوگ ( ایک رات ) خوف زدہ تھے ( آواز سنائی دی تھی اور سب لوگ اس کی طرف بڑھ رہے تھے ) لیکن نبی کریم صلی اللہ علیہ وسلم اس وقت ایک گھوڑے پر سوار سب سے آگے تھے ( جب واپس ہوئے تو ) فرمایا اس گھوڑے کو ( دوڑنے میں ) ہم نے سمندر پایا۔' WHERE id = 2706;
UPDATE hadiths SET urdu = 'ہم سے بشر بن محمد نے بیان کیا، کہا ہم کو عبداللہ نے خبر دی، کہا ہم کو عاصم نے خبر دی حفصہ بنت سیرین سے اور انہوں نے انس بن مالک رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”طاعون کی موت ہر مسلمان کے لیے شہادت کا درجہ رکھتی ہے۔“' WHERE id = 2716;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن نضر نے بیان کیا ‘ کہا ہم سے عبدالرزاق نے بیان کیا ‘ کہا ہم کو ابن جریج نے خبر دی ‘ کہا کہ مجھے یحییٰ بن سعید اور سہیل بن ابی صالح نے خبر دی ‘ ان دونوں حضرات نے نعمان بن ابی عیاش سے سنا ‘ انہوں نے ابو سعید خدری رضی اللہ عنہ سے ‘ آپ نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا ‘ آپ فرماتے تھے کہ جس نے اللہ تعالیٰ کے راستے میں ( جہاد کرتے ہوئے ) ایک دن بھی روزہ رکھا اللہ تعالیٰ اسے جہنم سے ستر سال کی مسافت کی دوری تک دور کر دے گا۔' WHERE id = 2726;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، ان سے حصین اور ابن ابی السفر نے، ان سے شعبی نے اور ان سے عروہ بن جعد رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”قیامت تک گھوڑے کی پیشانی کے ساتھ خیر و برکت بندھی رہے گی۔“ سلیمان نے شعبہ کے واسطہ سے بیان کیا کہ ان سے عروہ بن ابی الجعد رضی اللہ عنہ نے اس روایت کی متابعت ( جس میں بجائے ابن الجعد کے ابن ابی الجعد ہے ) مسدد نے ہشیم سے کی، ان سے حصین نے، ان سے شعبی نے اور ان سے عروہ ابن ابی الجعد نے۔' WHERE id = 2736;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، ان سے امام مالک رحمہ اللہ نے، ان سے زید بن اسلم نے، ان سے ابوصالح سمان نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ گھوڑے کے مالک تین طرح کے لوگ ہوتے ہیں۔ بعض لوگوں کے لیے وہ باعث اجر و ثواب ہیں، بعضوں کے لیے وہ صرف پردہ ہیں اور بعضوں کے لیے وبال جان ہیں۔ جس کے لیے گھوڑا اجر و ثواب کا باعث ہے یہ وہ شخص ہے جو اللہ کے راستے میں جہاد کی نیت سے اسے پالتا ہے پھر جہاں خوب چری ہوتی ہے یا ( یہ فرمایا کہ ) کسی شاداب جگہ اس کی رسی کو خوب لمبی کر کے باندھتا ہے ( تاکہ چاروں طرف چر سکے ) تو گھوڑا اس کی چری کی جگہ سے یا اس شاداب جگہ سے اپنی رسی میں بندھا ہوا جو کچھ بھی کھاتا پیتا ہے مالک کو اس کی وجہ سے نیکیاں ملتی ہیں اور اگر وہ گھوڑا اپنی رسی تڑا کر ایک زغن یا دو زغن لگائے تو اس کی لید اور اس کے قدموں کے نشانوں میں بھی مالک کے لیے نیکیاں ہیں اور اگر وہ گھوڑا نہر سے گزرے اور اس میں سے پانی پی لے تو اگرچہ مالک نے پانی پلانے کا ارادہ نہ کیا ہو پھر بھی اس سے اسے نیکیاں ملتی ہیں، دوسرا شخص وہ ہے جو گھوڑے کو فخر، دکھاوے اور اہل اسلام کی دشمنی میں باندھتا ہے تو یہ اس کے لیے وبال جان ہے اور رسول اللہ صلی اللہ علیہ وسلم سے گدھوں کے متعلق پوچھا گیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ مجھ پر اس جامع اور منفرد آیت کے سوا ان کے متعلق اور کچھ نازل نہیں ہوا «فمن يعمل مثقال ذرة خيرا يره * ومن يعمل مثقال ذرة شرا يره‏» ”جو کوئی ایک ذرہ برابر بھی نیکی کرے گا اس کا بدلہ پائے گا اور جو کوئی ذرہ برابر برائی کرے گا اس کا بدلہ پائے گا۔“' WHERE id = 2746;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، کہا ہم سے معاویہ نے بیان کیا، کہا ہم سے ابواسحاق نے، ان سے موسیٰ بن عقبہ نے، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ان گھوڑوں کی دوڑ کرائی جنہیں تیار کیا گیا تھا۔ یہ دوڑ مقام حفیاء سے شروع کرائی اور ثنیۃ الوداع اس کی آخری حد تھی ( ابواسحاق راوی نے بیان کیا کہ ) میں نے ابوموسیٰ سے پوچھا اس کا فاصلہ کتنا تھا؟ تو انہوں نے بتایا کہ چھ یا سات میل اور آپ صلی اللہ علیہ وسلم نے ان گھوڑوں کی بھی دوڑ کرائی جنہیں تیار نہیں کیا گیا تھا۔ ایسے گھوڑوں کی دوڑ ثنیۃ الوداع سے شروع ہوئی اور حد مسجد بنی زریق تھی۔ میں نے پوچھا اس میں کتنا فاصلہ تھا؟ انہوں نے کہا کہ تقریباً ایک میل۔ ابن عمر رضی اللہ عنہما بھی دوڑ میں شرکت کرنے والوں میں تھے۔' WHERE id = 2756;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے بشر بن مفضل نے بیان کیا، کہا ہم سے خالد بن ذکوان نے بیان کیا، ان سے ربیع بنت معوذ رضی اللہ عنہا نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ ( غزوہ میں ) شریک ہوتے تھے، مسلمان فوجیوں کو پانی پلاتیں تھیں زخمیوں کی مرہم پٹی کرتی تھیں اور جو لوگ شہید ہو جاتے انہیں مدینہ اٹھا کر لاتیں تھیں۔' WHERE id = 2767;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن منیر نے بیان کیا، انہوں نے ابوالنضر ہاشم بن قاسم سے سنا، انہوں نے کہا ہم سے عبدالرحمٰن بن عبداللہ بن دینار نے بیان کیا، انہوں نے کہا کہ ہم سے ابوحازم (سلمہ بن دینار) نے بیان کیا اور ان سے سہل بن سعد ساعدی رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اللہ کے راستے میں دشمن سے ملی ہوئی سرحد پر ایک دن کا پہرہ «دنيا وما عليها» سے بڑھ کر ہے جنت میں کسی کے لیے ایک کوڑے جتنی جگہ «دنيا وما عليها» سے بڑھ کر ہے اور جو شخص اللہ کے راستے میں شام کو چلے یا صبح کو تو وہ «دنيا وما عليها» سے بہتر ہے۔“' WHERE id = 2777;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عمرو بن دینار نے، ان سے زہری نے، ان سے مالک بن اوس بن حدثان نے اور ان سے عمر رضی اللہ عنہ نے بیان کیا کہ بنونضیر کے باغات وغیرہ ان اموال میں سے تھے جن کو اللہ تعالیٰ نے اپنے رسول صلی اللہ علیہ وسلم کو بغیر لڑے دے دیا تھا۔ مسلمانوں نے ان کے حاصل کرنے کے لیے گھوڑے اور اونٹ نہیں دوڑائے تو یہ اموال خاص طور سے رسول اللہ صلی اللہ علیہ وسلم ہی کے تھے جن میں سے آپ صلی اللہ علیہ وسلم اپنی ازواج مطہرات کو سالانہ نفقہ کے طور پر بھی دے دیتے تھے اور باقی ہتھیار اور گھوڑوں پر خرچ کرتے تھے تاکہ اللہ کے راستے میں ( جہاد کے لیے ) ہر وقت تیاری رہے۔' WHERE id = 2788;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، انہوں نے کہا ہم کو سفیان ثوری نے خبر دی، انہیں اعمش نے، انہیں ابراہیم نے، انہیں اسود نے اور ان سے ام المؤمنین عائشہ رضی اللہ عنہا نے بیان کیا کہ جب رسول اللہ صلی اللہ علیہ وسلم کی وفات ہوئی تو آپ صلی اللہ علیہ وسلم کی زرہ ایک یہودی کے پاس تیس صاع جو کے بدلے میں رہن رکھی ہوئی تھی۔ اور یعلیٰ نے بیان کیا کہ ہم سے اعمش نے بیان کیا کہ لوہے کی زرہ ( تھی ) اور معلیٰ نے بیان کیا، ان سے عبدالواحد نے بیان کیا، ان سے اعمش نے بیان کیا کہ آپ صلی اللہ علیہ وسلم نے لوہے کی ایک زرہ رہن رکھی تھی۔' WHERE id = 2799;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن ابراہیم نے بیان کیا، کہا کہ ہم کو جریر نے خبر دی عمارہ بن قعقاع سے، انہیں ابوزرعہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”قیامت اس وقت تک قائم نہ ہو گی جب تک یہودی سے تمہاری جنگ نہ ہو لے گی اور وہ پتھر بھی اس وقت ( اللہ تعالیٰ کے حکم سے ) بول اٹھیں گے جس کے پیچھے یہودی چھپا ہوا ہو گا کہ اے مسلمان! یہ یہودی میری آڑ لے کر چھپا ہوا ہے اسے قتل کر ڈالو۔“' WHERE id = 2809;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن منصور نے بیان کیا، کہا ہم کو یعقوب بن ابراہیم نے خبر دی، کہا مجھے میرے بھتیجے ابن شہاب نے خبر دی، ان سے ان کے چچا نے بیان کیا، انہیں عبداللہ بن عباس رضی اللہ عنہما نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم نے ( روم کے بادشاہ ) قیصر کو ( خط ) لکھا جس میں آپ صلی اللہ علیہ وسلم نے یہ بھی لکھا تھا کہ اگر تم نے ( اسلام کی دعوت سے ) منہ موڑا تو ( اپنے گناہ کے ساتھ ) ان کاشتکاروں کا بھی گناہ تم پر پڑے گا ( جن پر تم حکمرانی کر رہے ہو ) ۔' WHERE id = 2819;
UPDATE hadiths SET urdu = 'اور مجھ سے احمد بن محمد نے بیان کیا، انہوں نے کہا ہم کو عبداللہ بن مبارک نے خبر دی، انہیں یونس نے خبر دی، ان سے زہری نے بیان کیا، انہیں عبدالرحمٰن بن عبداللہ بن کعب بن مالک نے خبر دی، انہوں نے کہا کہ میں نے کعب بن مالک رضی اللہ عنہ سے سنا آپ بیان کرتے تھے کہ ایسا کم اتفاق ہوتا کہ رسول اللہ صلی اللہ علیہ وسلم کسی جہاد کا قصد کریں اور وہی مقام بیان فرما کر اس کو نہ چھپائیں۔ جب آپ صلی اللہ علیہ وسلم غزوہ تبوک کو جانے لگے تو چونکہ یہ غزوہ بڑی سخت گرمی میں ہونا تھا، لمبا سفر تھا اور جنگلوں کو طے کرنا تھا اور مقابلہ بھی بہت بڑی فوج سے تھا، اس لیے آپ صلی اللہ علیہ وسلم نے مسلمانوں سے صاف صاف فرما دیا تھا تاکہ دشمن کے مقابلہ کے لیے پوری تیاری کر لیں چنانچہ ( غزوہ کے لیے ) جہاں آپ صلی اللہ علیہ وسلم کو جانا تھا ( یعنی تبوک ) اس کا آپ نے صاف اعلان کر دیا تھا۔' WHERE id = 2830;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے وہب نے بیان کیا، کہا ہم سے عمرو بن یحییٰ نے، ان سے عباد بن تمیم نے اور ان سے عبداللہ بن زید رضی اللہ عنہ نے بیان کیا کہ حرہ کی لڑائی کے زمانہ میں ایک صاحب ان کے پاس آئے اور کہا کہ عبداللہ بن حنظلہ لوگوں سے ( یزید کے خلاف ) موت پر بیعت لے رہے ہیں۔ تو انہوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم کے بعد اب میں موت پر کسی سے بیعت نہیں کروں گا۔' WHERE id = 2840;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، کہا ہم سے سفیان نے، ان سے ابن جریج نے، ان سے عطاء نے، ان سے صفوان بن یعلیٰ نے اور ان سے ان کے والد (یعلیٰ بن امیہ رضی اللہ عنہ) نے بیان کیا کہ میں رسول اللہ صلی اللہ علیہ وسلم کے ساتھ غزوہ تبوک میں شریک تھا اور ایک جوان اونٹ میں نے سواری کے لیے دیا تھا، میرے خیال میں میرا یہ عمل، تمام دوسرے اعمال کے مقابلے میں سب سے زیادہ قابل بھروسہ تھا۔ ( کہ اللہ تعالیٰ کے ہاں مقبول ہو گا ) میں نے ایک مزدور بھی اپنے ساتھ لے لیا تھا۔ پھر وہ مزدور ایک شخص ( خود یعلیٰ بن امیہ رضی اللہ عنہ ) سے لڑ پڑا اور ان میں سے ایک نے دوسرے کے ہاتھ میں دانت سے کاٹ لیا۔ دوسرے نے جھٹ جو اپنا ہاتھ اس کے منہ سے کھینچا تو اس کے آگے کا دانت ٹوٹ گیا۔ وہ شخص نبی کریم صلی اللہ علیہ وسلم کی خدمت میں فریادی ہوا لیکن آپ صلی اللہ علیہ وسلم نے ہاتھ کھینچنے والے پر کوئی تاوان نہیں فرمایا بلکہ فرمایا کہ کیا تمہارے منہ میں وہ اپنا ہاتھ یوں ہی رہنے دیتا تاکہ تم اسے چبا جاؤ جیسے اونٹ چباتا ہے۔' WHERE id = 2852;
UPDATE hadiths SET urdu = 'ہم سے صدقہ بن فضل نے بیان کیا، کہا ہم کو عبدہ نے خبر دی، انہیں ہشام نے، انہیں وہب بن کیسان نے اور ان سے جابر رضی اللہ عنہ نے بیان کیا کہ ہم ( ایک غزوہ پر ) نکلے۔ ہماری تعداد تین سو تھی، ہم اپنا راشن اپنے کندھوں پر اٹھائے ہوئے تھے۔ آخر ہمارا توشہ جب ( تقریباً ) ختم ہو گیا، تو ایک شخص کو روزانہ صرف ایک کھجور کھانے کو ملنے لگی۔ ایک شاگرد نے پوچھا، اے ابوعبداللہ! ( جابر رضی اللہ عنہ ) ایک کھجور سے بھلا ایک آدمی کا کیا بنتا ہو گا؟ انہوں نے فرمایا کہ اس کی قدر ہمیں اس وقت معلوم ہوئی جب ایک کھجور بھی باقی نہیں رہ گئی تھی۔ اس کے بعد ہم دریا پر آئے تو ایک ایسی مچھلی ملی جسے دریا نے باہر پھینک دیا تھا۔ اور ہم اٹھارہ دن تک خوب جی بھر کر اسی کو کھاتے رہے۔' WHERE id = 2862;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے حصین بن عبدالرحمٰن نے ان سے سالم بن ابی الجعد نے اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ جب ہم ( کسی بلندی پر ) چڑھتے، تو «الله اكبر» کہتے اور جب ( کسی نشیب میں ) اترتے تو «سبحان الله» کہتے تھے۔' WHERE id = 2872;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا ہم سے مالک رحمہ اللہ نے بیان کیا، ان سے زید بن اسلم نے، ان سے ان کے والد نے کہ میں نے عمر بن خطاب رضی اللہ عنہ سے سنا، آپ فرما رہے تھے کہ میں نے اللہ کے راستے میں ایک گھوڑا سواری کے لیے دیا، اور جسے دیا تھا وہ اسے بیچنے لگا۔ یا ( آپ نے یہ فرمایا تھا کہ ) اس نے اسے بالکل کمزور کر دیا تھا۔ اس لیے میرا ارادہ ہوا کہ میں اسے واپس خرید لوں، مجھے یہ خیال تھا کہ وہ شخص سستے داموں پر اسے بیچ دے گا۔ میں نے اس کے متعلق نبی کریم صلی اللہ علیہ وسلم سے جب پوچھا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر وہ گھوڑا تمہیں ایک درہم میں مل جائے پھر بھی اسے نہ خریدنا۔ کیونکہ اپنے ہی صدقہ کو واپس لینے والا اس کتے کی طرح ہے جو اپنی قے کو خود ہی چاٹتا ہے۔' WHERE id = 2882;
UPDATE hadiths SET urdu = '(سابقہ سند کے ساتھ) زہری سے روایت ہے کہ انہوں نے عبیداللہ سے سنا بواسطہ ابن عباس رضی اللہ عنہما اور ان سے صعب رضی اللہ عنہ نے بیان کیا ‘ اور صرف «ذراري» (بچوں) کا ذکر کیا ‘ سفیان نے کہا کہ عمرو ہم سے حدیث بیان کرتے تھے۔ ان سے ابن شہاب ‘ نبی کریم صلی اللہ علیہ وسلم سے، ( سفیان نے ) بیان کیا کہ پھر ہم نے حدیث خود زہری ( ابن شہاب ) سے سنی۔ انہوں نے بیان کیا کہ مجھے عبیداللہ نے خبر دی، انہیں ابن عباس رضی اللہ عنہما نے اور انہیں صعب رضی اللہ عنہ نے آپ صلی اللہ علیہ وسلم نے فرمایا ” ( مشرکین کی عورتوں اور بچوں کے متعلق کہ ) وہ بھی انہیں میں سے ہیں۔“ ( زہری کے واسطہ سے ) جس طرح عمرو نے بیان کیا تھا کہ «هم من آبائهم» وہ بھی انہیں کے باپ دادوں کی نسل ہیں۔ زہری نے خود ہم سے ان الفاظ کے ساتھ بیان نہیں کیا یعنی «هم من آبائهم» نہیں کہا بلکہ «هم منهم» کہا۔' WHERE id = 2892;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا ‘ کہا ہم سے یحییٰ بن آدم نے بیان کیا ‘ کہا ہم سے یحییٰ بن ابی زائدہ نے بیان کیا ‘ ان سے اس کے والد نے ‘ ان سے ابواسحاق نے اور ان سے براء بن عازب رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے انصار کے چند آدمیوں کو ابورافع کے پاس ( اسے قتل کرنے کے لیے ) بھیجا تھا۔ چنانچہ رات میں عبداللہ بن عتیک رضی اللہ عنہ اس کے قلعہ میں داخل ہوئے اور اسے سوتے ہوئے قتل کیا۔' WHERE id = 2902;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن خالد نے بیان کیا ‘ کہا ہم سے زہیر نے بیان کیا ‘ کہا ہم سے ابواسحاق نے بیان کیا ‘ کہا کہ میں نے براء بن عازب رضی اللہ عنہ سے سنا ‘ آپ بیان کرتے تھے کہ رسول اللہ صلی اللہ علیہ وسلم نے جنگ احد کے موقع پر ( تیر اندازوں کے ) پچاس آدمیوں کا افسر عبداللہ بن جبیر رضی اللہ عنہ کو بنایا تھا۔ آپ صلی اللہ علیہ وسلم نے انہیں تاکید کر دی تھی کہ اگر تم یہ بھی دیکھ لو کہ پرندے ہم پر ٹوٹ پڑے ہیں۔ پھر بھی اپنی جگہ سے مت ہٹنا ‘ جب تک میں تم لوگوں کو کہلا نہ بھیجوں۔ اسی طرح اگر تم یہ دیکھو کہ کفار کو ہم نے شکست دے دی ہے اور انہیں پامال کر دیا ہے پھر بھی یہاں سے نہ ٹلنا ‘ جب میں تمہیں خود بلا نہ بھیجوں۔ پھر اسلامی لشکر نے کفار کو شکست دے دی۔ براء بن عازب رضی اللہ عنہ نے بیان کیا ‘ کہ اللہ کی قسم! میں نے مشرک عورتوں کو دیکھا کہ تیزی کے ساتھ بھاگ رہی تھیں۔ ان کے پازیب اور پنڈلیاں دکھائی دے رہی تھیں۔ اور وہ اپنے کپڑوں کو اٹھائے ہوئے تھیں۔ عبداللہ بن جبیر رضی اللہ عنہ کے ساتھیوں نے کہا ‘ کہ غنیمت لوٹو ‘ اے قوم! غنیمت تمہارے سامنے ہے۔ تمہارے ساتھی غالب آ گئے ہیں۔ اب ڈر کس بات کا ہے۔ اس پر عبداللہ بن جبیر رضی اللہ عنہ نے ان سے کہا کہ کیا جو ہدایت رسول اللہ صلی اللہ علیہ وسلم نے کی تھی ‘ تم اسے بھول گئے؟ لیکن وہ لوگ اسی پر اڑے رہے کہ دوسرے اصحاب کے ساتھ غنیمت جمع کرنے میں شریک رہیں گے۔ جب یہ لوگ ( اکثریت ) اپنی جگہ چھوڑ کر چلے آئے تو ان کے منہ کافروں نے پھیر دیئے ‘ اور ( مسلمانوں کو ) شکست زدہ پا کر بھاگتے ہوئے آئے ‘ یہی وہ گھڑی تھی ( جس کا ذکر سورۃ آل عمران میں ہے کہ ) ”جب رسول اللہ صلی اللہ علیہ وسلم تم کو پیچھے کھڑے ہوئے بلا رہے تھے“۔ اس سے یہی مراد ہے۔ اس وقت رسول اللہ صلی اللہ علیہ وسلم کے ساتھ بارہ صحابہ کے سوا اور کوئی بھی باقی نہ رہ گیا تھا۔ آخر ہمارے ستر آدمی شہید ہو گئے۔ بدر کی لڑائی میں آپ صلی اللہ علیہ وسلم نے اپنے صحابہ کے ساتھ مشرکین کے ایک سو چالیس آدمیوں کا نقصان کیا تھا ‘ ستر ان میں سے قیدی تھے اور ستر مقتول ‘ ( جب جنگ ختم ہو گئی تو ایک پہاڑ پر کھڑے ہو کر ) ابوسفیان نے کہا کیا محمد صلی اللہ علیہ وسلم اپنی قوم کے ساتھ موجود ہیں؟ تین مرتبہ انہوں نے یہی پوچھا۔ لیکن نبی کریم صلی اللہ علیہ وسلم نے جواب دینے سے منع فرما دیا تھا۔ پھر انہوں نے پوچھا ‘ کیا ابن ابی قحافہ ( ابوبکر رضی اللہ عنہ ) اپنی قوم میں موجود ہیں؟ یہ سوال بھی تین مرتبہ کیا ‘ پھر پوچھا ابن خطاب ( عمر رضی اللہ عنہ ) اپنی قوم میں موجود ہیں؟ یہ بھی تین مرتبہ پوچھا ‘ پھر اپنے ساتھیوں کی طرف مڑ کر کہنے لگے کہ یہ تینوں قتل ہو چکے ہیں اس پر عمر رضی اللہ عنہ سے نہ رہا گیا اور آپ بول پڑے کہ اے اللہ کے دشمن! اللہ گواہ ہے کہ تو جھوٹ بول رہا ہے جن کے تو نے ابھی نام لیے تھے وہ سب زندہ ہیں اور ابھی تیرا برا دن آنے والا ہے۔ ابوسفیان نے کہا اچھا! آج کا دن بدر کا بدلہ ہے۔ اور لڑائی بھی ایک ڈول کی طرح ہے ( کبھی ادھر کبھی ادھر ) تم لوگوں کو اپنی قوم کے بعض لوگ مثلہ کئے ہوئے ملیں گے۔ میں نے اس طرح کا کوئی حکم ( اپنے آدمیوں کو ) نہیں دیا تھا ‘ لیکن مجھے ان کا یہ عمل برا بھی نہیں معلوم ہوا۔ اس کے بعد وہ فخر یہ رجز پڑھنے لگا ‘ ہبل ( بت کا نام ) بلند رہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا تم لوگ اس کا جواب کیوں نہیں دیتے۔ صحابہ رضی اللہ عنہم نے پوچھا ہم اس کے جواب میں کیا کہیں یا رسول اللہ؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہو کہ اللہ سب سے بلند اور سب سے بڑا بزرگ ہے۔ ابوسفیان نے کہا ہمارا مددگار عزیٰ ( بت ) ہے اور تمہارا کوئی بھی نہیں، آپ صلی اللہ علیہ وسلم نے فرمایا، جواب کیوں نہیں دیتے، صحابہ نے عرض کیا، یا رسول اللہ! اس کا جواب کیا دیا جائے؟ آپ صلی اللہ علیہ وسلم نے فرمایا، کہو کہ اللہ ہمارا حامی ہے اور تمہارا حامی کوئی نہیں۔' WHERE id = 2915;
UPDATE hadiths SET urdu = 'اور ابراہیم بن طہمان نے بیان کیا ‘ ان سے عبدالعزیز بن صہیب نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں بحرین کا خراج آیا تو عباس رضی اللہ عنہ خدمت نبوی میں حاضر ہوئے اور عرض کیا: یا رسول اللہ! اس مال سے مجھے بھی دیجئیے کیونکہ ( بدر کے موقع پر ) میں نے اپنا اور عقیل دونوں کا فدیہ ادا کیا تھا۔ آپ صلی اللہ علیہ وسلم نے فرمایا ”پھر آپ لے لیں“ چنانچہ آپ صلی اللہ علیہ وسلم نے انہیں ان کے کپڑے میں نقدی کو بندھوا دیا۔' WHERE id = 2925;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا ‘ کہا ہم سے سفیان نے بیان کیا ‘ ان سے اعمش نے ‘ ان سے ابووائل نے اور ان سے حذیفہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جو لوگ اسلام کا کلمہ پڑھ چکے ہیں ان کے نام لکھ کر میرے پاس لاؤ۔“ چنانچہ ہم نے ڈیڑھ ہزار مردوں کے نام لکھ کر آپ صلی اللہ علیہ وسلم کی خدمت میں پیش کئے اور ہم نے آپ صلی اللہ علیہ وسلم سے عرض کیا ہماری تعداد ڈیڑھ ہزار ہو گئی ہے۔ اب ہم کو کیا ڈر ہے۔ لیکن تم دیکھ رہے ہو کہ ( آپ صلی اللہ علیہ وسلم کے بعد ) ہم فتنوں میں اس طرح گھر گئے کہ اب مسلمان تنہا نماز پڑھتے ہوئے بھی ڈرنے لگا ہے۔ ہم سے عبدان نے بیان کیا ‘ ان سے ابوحمزہ نے اور ان سے اعمش نے ( مذکورہ بالا سند کے ساتھ ) کہ ہم نے پانچ سو مسلمانوں کی تعداد لکھی ( ہزار کا ذکر اس روایت میں نہیں ہوا ) اور ابومعاویہ نے ( اپنی روایت میں ) یوں بیان کیا ‘ کہ چھ سو سے سات سو تک۔' WHERE id = 2935;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن علی فلاس نے بیان کیا ‘ کہا ہم سے ابوعاصم نے بیان کیا ‘ انہیں حنظلہ بن ابی سفیان نے خبر دی ‘ انہیں سعید بن میناء نے خبر دی ‘ کہا کہ میں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا۔ آپ نے بیان کیا ‘ کہ میں نے ( جنگ خندق میں آپ صلی اللہ علیہ وسلم کو بھوکا پا کر چپکے سے ) عرض کیا: یا رسول اللہ! ہم نے ایک چھوٹا سا بکری کا بچہ ذبح کیا ہے۔ اور ایک صاع جو کا آٹا پکوایا ہے۔ اس لیے آپ دو چار آدمیوں کو ساتھ لے کر تشریف لائیں۔ لیکن آپ صلی اللہ علیہ وسلم نے بآواز بلند فرمایا ”اے خندق کھودنے والو! جابر نے دعوت کا کھانا تیار کر لیا ہے۔ آؤ چلو ‘ جلدی چلو۔“' WHERE id = 2945;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن ابی الاسود نے بیان کیا ‘ کہا ہم سے یزید بن زریع اور حمید بن الاسود نے بیان کیا ‘ ان سے حبیب بن شہید نے اور ان سے ابن ابی ملیکہ نے کہ عبداللہ بن زبیر رضی اللہ عنہما نے عبداللہ بن جعفر رضی اللہ عنہ سے کہا ‘ تمہیں وہ قصہ یاد ہے جب میں اور تم اور عبداللہ بن عباس رضی اللہ عنہما تینوں آگے جا کر رسول اللہ صلی اللہ علیہ وسلم سے ملے تھے ( آپ صلی اللہ علیہ وسلم جہاد سے واپس آ رہے تھے ) عبداللہ بن جعفر نے کہا ‘ ہاں یاد ہے۔ اور آپ صلی اللہ علیہ وسلم نے مجھ کو اور ابن عباس رضی اللہ عنہما کو اپنے ساتھ سوار کر لیا تھا ‘ اور تمہیں چھوڑ دیا تھا۔' WHERE id = 2956;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن محمد فروی نے بیان کیا ‘ کہا ہم سے مالک بن انس نے ‘ ان سے ابن شہاب نے ‘ ان سے مالک بن اوس بن حدثان نے ( زہری نے بیان کیا کہ ) محمد بن جبیر نے مجھ سے ( اسی آنے والی ) حدیث کا ذکر کیا تھا۔ اس لیے میں نے مالک بن اوس کی خدمت میں خود حاضر ہو کر ان سے اس حدیث کے متعلق ( بطور تصدیق ) پوچھا۔ انہوں نے کہا کہ دن چڑھ آیا تھا اور میں اپنے گھر والوں کے ساتھ بیٹھا ہوا تھا ‘ اتنے میں عمر بن خطاب رضی اللہ عنہ کا ایک بلانے والا میرے پاس آیا اور کہا کہ امیرالمؤمنین آپ کو بلا رہے ہیں۔ میں اس قاصد کے ساتھ ہی چلا گیا اور عمر رضی اللہ عنہ کی خدمت میں حاضر ہوا۔ آپ ایک تخت پر بوریا بچھائے ‘ بورئیے پر کوئی بچھونا نہ تھا ‘ صرف ایک چمڑے کے تکئے پر ٹیک لگائے ہوئے تھے۔ میں سلام کر کے بیٹھ گیا۔ پھر انہوں نے فرمایا ‘ مالک! تمہاری قوم کے کچھ لوگ میرے پاس آئے تھے ‘ میں نے ان کے لیے کچھ حقیر سی امداد کا فیصلہ کر لیا ہے۔ تم اسے اپنی نگرانی میں ان میں تقسیم کرا دو ‘ میں نے عرض کیا ‘ یا امیرالمؤمنین! اگر آپ اس کام پر کسی اور کو مقرر فرما دیتے تو بہتر ہوتا۔ لیکن عمر رضی اللہ عنہ نے یہی اصرار کیا کہ نہیں ‘ اپنی ہی تحویل میں بانٹ دو۔ ابھی میں وہیں حاضر تھا کہ امیرالمؤمنین کے دربان یرفا آئے اور کہا کہ عثمان بن عفان ‘ عبدالرحمٰن بن عوف ‘ زبیر بن عوام اور سعد بن ابی وقاص رضی اللہ عنہما اندر آنے کی اجازت چاہتے ہیں؟ عمر رضی اللہ عنہ نے فرمایا کہ ہاں انہیں اندر بلا لو۔ آپ کی اجازت پر یہ حضرات داخل ہوئے اور سلام کر کے بیٹھ گئے۔ یرفا بھی تھوڑی دیر بیٹھے رہے اور پھر اندر آ کر عرض کیا علی اور عباس رضی اللہ عنہما کو بھی اندر آنے کی اجازت ہے؟ آپ نے فرمایا کہ ہاں انہیں بھی اندر بلا لو۔ آپ کی اجازت پر یہ حضرات بھی اندر تشریف لے آئے۔ اور سلام کر کے بیٹھ گئے۔ عباس رضی اللہ عنہ نے کہا ‘ یا امیرالمؤمنین! میرا اور ان کا فیصلہ کر دیجئیے۔ ان حضرات کا جھگڑا اس جائیداد کے بارے میں تھا جو اللہ تعالیٰ نے اپنے رسول صلی اللہ علیہ وسلم کو بنی نضیر کے اموال میں سے ( خمس کے طور پر ) عنایت فرمائی تھی۔ اس پر عثمان اور ان کے ساتھ جو دیگر صحابہ تھے کہنے لگے ‘ ہاں ‘ امیرالمؤمنین! ان حضرات میں فیصلہ فرما دیجئیے اور ہر ایک کو دوسرے کی طرف سے بےفکر کر دیجئیے۔ عمر رضی اللہ عنہ نے کہا ‘ اچھا ‘ تو پھر ذرا ٹھہرئیے اور دم لے لیجئے میں آپ لوگوں سے اس اللہ کی قسم دے کر پوچھتا ہوں جس کے حکم سے آسمان اور زمین قائم ہیں۔ کیا آپ لوگوں کو معلوم ہے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا تھا کہ ”ہم پیغمبروں کا کوئی وارث نہیں ہوتا ‘ جو کچھ ہم ( انبیاء ) چھوڑ کر جاتے ہیں وہ صدقہ ہوتا ہے۔“ جس سے آپ صلی اللہ علیہ وسلم کی مراد خود اپنی ذات گرامی بھی تھی۔ ان حضرات نے تصدیق کی ‘ کہ جی ہاں ‘ بیشک آپ صلی اللہ علیہ وسلم نے یہ فرمایا تھا۔ اب عمر رضی اللہ عنہ، علی اور عباس رضی اللہ عنہما کی طرف مخاطب ہوئے ‘ ان سے پوچھا۔ میں آپ حضرات کو اللہ کی قسم دیتا ہوں ‘ کیا آپ حضرات کو بھی معلوم ہے کہ آپ صلی اللہ علیہ وسلم نے ایسا فرمایا ہے یا نہیں؟ انہوں نے بھی اس کی تصدیق کی کہ آپ صلی اللہ علیہ وسلم نے بیشک ایسا فرمایا ہے۔ عمر رضی اللہ عنہ نے کہا کہ اب میں آپ لوگوں سے اس معاملہ کی شرح بیان کرتا ہوں۔ بات یہ ہے کہ اللہ تعالیٰ نے اپنے رسول صلی اللہ علیہ وسلم کے لیے اس غنیمت کا ایک مخصوص حصہ مقرر کر دیا تھا۔ جسے آپ صلی اللہ علیہ وسلم نے بھی کسی دوسرے کو نہیں دیا تھا۔ پھر آپ نے اس آیت کی تلاوت کی «وما أفاء الله على رسوله منهم‏» سے اللہ تعالیٰ کے ارشاد «قدير‏» تک اور وہ حصہ آپ صلی اللہ علیہ وسلم کے لیے خاص رہا۔ مگر قسم اللہ کی یہ جائیداد آپ صلی اللہ علیہ وسلم نے تم کو چھوڑ کر اپنے لیے جوڑ نہ رکھی ‘ نہ خاص اپنے خرچ میں لائے ‘ بلکہ تم ہی لوگوں کو دیں اور تمہارے ہی کاموں میں خرچ کیں۔ یہ جو جائیداد بچ رہی ہے اس میں سے آپ اپنی بیویوں کا سال بھر کا خرچ لیا کرتے اس کے بعد جو باقی بچتا وہ اللہ کے مال میں شریک کر دیتے ( جہاد کے سامان فراہم کرنے میں ) خیر آپ صلی اللہ علیہ وسلم تو اپنی زندگی میں ایسا ہی کرتے رہے۔ حاضرین تم کو اللہ کی قسم! کیا تم یہ نہیں جانتے؟ انہوں نے کہا بیشک جانتے ہیں۔ پھر عمر رضی اللہ عنہ نے علی اور عباس رضی اللہ عنہما سے کہا میں آپ حضرات سے بھی قسم دے کر پوچھتا ہوں ‘ کیا آپ لوگ یہ نہیں جانتے ہیں؟ ( دونوں حضرات نے جواب دیا ہاں! ) پھر عمر رضی اللہ عنہ نے یوں فرمایا کہ پھر اللہ تعالیٰ نے اپنے نبی کریم صلی اللہ علیہ وسلم کو دنیا سے اٹھا لیا تو ابوبکر صدیق رضی اللہ عنہ کہنے لگے کہ میں رسول اللہ صلی اللہ علیہ وسلم کا خلیفہ ہوں ‘ اور اس لیے انہوں نے ( آپ صلی اللہ علیہ وسلم کی اس مخلص ) جائیداد پر قبضہ کیا اور جس طرح آپ صلی اللہ علیہ وسلم اس میں مصارف کیا کرتے تھے ‘ وہ کرتے رہے۔ اللہ خوب جانتا ہے کہ ابوبکر رضی اللہ عنہ اپنے اس طرز عمل میں سچے مخلص ‘ نیکوکار اور حق کی پیروی کرنے والے تھے۔ پھر اللہ تعالیٰ نے ابوبکر رضی اللہ عنہ کو بھی اپنے پاس بلا لیا اور اب میں ابوبکر رضی اللہ عنہ کا نائب مقرر ہوا۔ میری خلافت کو دو سال ہو گئے ہیں۔ اور میں نے بھی اس جائیداد کو اپنی تحویل میں رکھا ہے۔ جو مصارف رسول اللہ صلی اللہ علیہ وسلم اور ابوبکر رضی اللہ عنہ اس میں کیا کرتے تھے ویسا ہی میں بھی کرتا رہا اور اللہ خوب جانتا ہے کہ میں اپنے اس طرز عمل میں سچا ‘ مخلص اور حق کی پیروی کرنے والا ہوں۔ پھر آپ دونوں میرے پاس مجھ سے گفتگو کرنے آئے اور بالاتفاق گفتگو کرنے لگے کہ دونوں کا مقصد ایک تھا۔ جناب عباس! آپ تو اس لیے تشریف لائے کہ آپ کو اپنے بھتیجے ( صلی اللہ علیہ وسلم ) کی میراث کا دعویٰ میرے سامنے پیش کرنا تھا۔ پھر علی رضی اللہ عنہ سے فرمایا کہ آپ اس لیے تشریف لائے کہ آپ کو اپنی بیوی ( فاطمہ رضی اللہ عنہا ) کا دعویٰ پیش کرنا تھا کہ ان کے والد ( رسول اللہ صلی اللہ علیہ وسلم ) کی میراث انہیں ملنی چاہئے ‘ میں نے آپ دونوں حضرات سے عرض کر دیا کہ رسول اللہ صلی اللہ علیہ وسلم خود فرما گئے کہ ہم پیغمبروں کا کوئی میراث تقسیم نہیں ہوتی ‘ ہم جو کچھ چھوڑ جاتے ہیں وہ صدقہ ہوتا ہے۔ پھر مجھ کو یہ مناسب معلوم ہوا کہ میں ان جائیدادوں کو تمہارے قبضے میں دے دوں ‘ تو میں نے تم سے کہا ‘ دیکھو اگر تم چاہو تو میں یہ جائیداد تمہارے سپرد کر دیتا ہوں ‘ لیکن اس عہد اور اس اقرار پر کہ تم اس کی آمدنی سے وہ سب کام کرتے رہو گے جو آپ صلی اللہ علیہ وسلم اور ابوبکر صدیق رضی اللہ عنہ اپنی خلافت میں کرتے رہے اور جو کام میں اپنی حکومت کے شروع سے کرتا رہا۔ تم نے اس شرط کو قبول کر کے درخواست کی کہ جائیدادیں ہم کو دے دو۔ میں نے اسی شرط پر دے دی ‘ حاضرین کہو میں نے یہ جائیدادیں اسی شرط پر ان کے حوالے کی ہیں یا نہیں؟ انہوں نے کہا ‘ بیشک اسی شرط پر آپ نے دی ہیں۔ پھر عمر رضی اللہ عنہ نے علی رضی اللہ عنہ اور عباس رضی اللہ عنہ سے فرمایا ‘ میں تم کو اللہ کی قسم دیتا ہوں ‘ میں نے اسی شرط پر یہ جائیدادیں آپ حضرات کے حوالے کی ہیں یا نہیں؟ انہوں نے کہا بیشک۔ عمر رضی اللہ عنہ نے کہا ‘ پھر مجھ سے کس بات کا فیصلہ چاہتے ہو؟ ( کیا جائیداد کو تقسیم کرانا چاہتے ہو ) قسم اللہ کی! جس کے حکم سے زمین اور آسمان قائم ہیں میں تو اس کے سوا اور کوئی فیصلہ کرنے والا نہیں۔ ہاں! یہ اور بات ہے کہ اگر تم سے اس کا انتظام نہیں ہو سکتا تو پھر جائیداد میرے سپرد کر دو۔ میں اس کا بھی کام دیکھ لوں گا۔' WHERE id = 2967;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا ‘ کہا ہم سے جویریہ نے بیان کیا ‘ ان سے نافع نے اور ان سے عبداللہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے خطبہ دیتے ہوئے عائشہ رضی اللہ عنہا کے حجرہ کی طرف اشارہ کیا اور فرمایا کہ اسی طرف سے ( یعنی مشرق کی طرف سے ) فتنے برپا ہوں گے ‘ تین مرتبہ آپ صلی اللہ علیہ وسلم نے اسی طرح فرمایا کہ یہیں سے شیطان کا سر نمودار ہو گا۔' WHERE id = 2977;
UPDATE hadiths SET urdu = 'ہم سے ابوولید نے بیان کیا ‘ کہا ہم سے شعبہ نے بیان کیا ‘ ان سے سلیمان ‘ منصور اور قتادہ نے ‘ انہوں نے سالم بن ابی الجعد سے سنا اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ ہم انصاریوں کے قبیلہ میں ایک انصاری کے گھر بچہ پیدا ہو تو انہوں نے بچے کا نام محمد رکھنے کا ارادہ کیا اور شعبہ نے منصور سے روایت کر کے بیان کیا ہے کہ ان انصاری نے بیان کیا ( جن کے یہاں بچہ پیدا ہوا تھا ) کہ میں بچے کو اپنی گردن پر اٹھا کر نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا۔ اور سلیمان کی روایت میں ہے کہ ان کے یہاں بچہ پیدا ہوا ‘ تو انہوں نے اس کا نام محمد رکھنا چاہا ‘ آپ صلی اللہ علیہ وسلم نے اس پر فرمایا کہ میرے نام پر نام رکھو ‘ لیکن میری کنیت ( ابوالقاسم ) پر کنیت نہ رکھنا ‘ کیونکہ مجھے تقسیم کرنے والا ( قاسم ) بنایا گیا ہے۔ میں تم میں تقسیم کرتا ہوں ‘ اور حصین نے ( اپنی روایت میں ) یوں بیان کیا ‘ کہ مجھے تقسیم کرنے والا ( قاسم ) بنا کر بھیجا گیا ہے ‘ میں تم میں تقسیم کرتا ہوں۔ عمرو بن مرزوق نے کہا کہ ہمیں شعبہ نے خبر دی ‘ ان سے قتادہ نے بیان کیا ‘ انہوں نے سالم سے سنا انہوں نے جابر رضی اللہ عنہ سے کہ ان انصاری صحابی نے اپنے بچے کا نام قاسم رکھنا چاہا تھا تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میرے نام پر نام رکھو لیکن کنیت نہ رکھو۔' WHERE id = 2987;
UPDATE hadiths SET urdu = 'ہم سے محمد بن علاء نے بیان کیا ‘ کہا ہم سے عبداللہ بن مبارک نے بیان کیا ‘ ان سے معمر نے ‘ ان سے ہمام بن منبہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”بنی اسرائیل کے پیغمبروں میں سے ایک نبی ( یوشع علیہ السلام ) نے غزوہ کرنے کا ارادہ کیا تو اپنی قوم سے کہا کہ میرے ساتھ کوئی ایسا شخص جس نے ابھی نئی شادی کی ہو اور بیوی کے ساتھ رات بھی نہ گزاری ہو اور وہ رات گزارنا چاہتا ہو اور وہ شخص جس نے گھر بنایا ہو اور ابھی اس کی چھت نہ رکھی ہو اور وہ شخص جس نے حاملہ بکری یا حاملہ اونٹنیاں خریدی ہوں اور اسے ان کے بچے جننے کا انتظار ہو تو ( ایسے لوگوں میں سے کوئی بھی ) ہمارے ساتھ جہاد میں نہ چلے۔ پھر انہوں نے جہاد کیا ‘ اور جب اس آبادی ( اریحا ) سے قریب ہوئے تو عصر کا وقت ہو گیا یا اس کے قریب وقت ہوا۔ انہوں نے سورج سے فرمایا کہ تو بھی اللہ کا تابع فرمان ہے اور میں بھی اس کا تابع فرمان ہوں۔ اے اللہ! ہمارے لیے اسے اپنی جگہ پر روک دے۔ چنانچہ سورج رک گیا ‘ یہاں تک کہ اللہ تعالیٰ نے انہیں فتح عنایت فرمائی۔ پھر انہوں نے اموال غنیمت کو جمع کیا اور آگ اسے جلانے کے لیے آئی لیکن جلا نہ سکی ‘ اس نبی نے فرمایا کہ تم میں سے کسی نے مال غنیمت میں چوری کی ہے۔ اس لیے ہر قبیلہ کا ایک آدمی آ کر میرے ہاتھ پر بیعت کرے ( جب بیعت کرنے لگے تو ) ایک قبیلہ کے شخص کا ہاتھ ان کے ہاتھ سے چمٹ گیا۔ انہوں نے فرمایا ‘ کہ چوری تمہارے قبیلہ ہی والوں نے کی ہے۔ اب تمہارے قبیلے کے سب لوگ آئیں اور بیعت کریں۔ چنانچہ اس قبیلے کے دو تین آدمیوں کا ہاتھ اس طرح ان کے ہاتھ سے چمٹ گیا ‘ تو آپ نے فرمایا کہ چوری تمہیں لوگوں نے کی ہے۔ ( آخر چوری مان لی گئی ) اور وہ لوگ گائے کے سر کی طرح سونے کا ایک سر لائے ( جو غنیمت میں سے چرا لیا گیا تھا ) اور اسے مال غنیمت میں رکھ دیا ‘ تب آگ آئی اور اسے جلا گئی ‘ پھر غنیمت اللہ تعالیٰ نے ہمارے لیے جائز قرار دے دی ‘ ہماری کمزوری اور عاجزی کو دیکھا۔ اس لیے ہمارے واسطے حلال قرار دے دی۔' WHERE id = 2997;
UPDATE hadiths SET urdu = 'ہم سے محمد بن علاء نے بیان کیا ‘ کہا ہم سے ابواسامہ نے بیان کیا ‘ ان سے برید بن عبداللہ نے بیان کیا ‘ ان سے ابوبردہ نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم کی ہجرت کی خبر ہمیں ملی ‘ تو ہم یمن میں تھے۔ اس لیے ہم بھی آپ کی خدمت میں مہاجر کی حیثیت سے حاضر ہونے کے لیے روانہ ہوئے۔ میں تھا ‘ میرے بھائی تھے۔ ( میری عمران دونوں سے کم تھی ‘ دونوں بھائیوں میں ) ایک ابوبردہ رضی اللہ عنہ تھے اور دوسرے ابورہم۔ یا انہوں نے یہ کہا کہ اپنی قوم کے چند افراد کے ساتھ یا یہ کہا تریپن یا باون آدمیوں کے ساتھ ( یہ لوگ روانہ ہوئے تھے ) ہم کشتی میں سوار ہوئے تو ہماری کشتی نجاشی کے ملک حبشہ پہنچ گئی اور وہاں ہمیں جعفر بن ابی طالب رضی اللہ عنہ اپنے دوسرے ساتھیوں کے ساتھ ملے۔ جعفر رضی اللہ عنہ نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے ہمیں یہاں بھیجا تھا اور حکم دیا تھا کہ ہم یہیں رہیں۔ چنانچہ ہم بھی وہیں ٹھہر گئے۔ اور پھر سب ایک ساتھ ( مدینہ ) حاضر ہوئے ‘ جب ہم خدمت نبوی میں پہنچے ‘ تو آپ صلی اللہ علیہ وسلم خیبر فتح کر چکے تھے۔ لیکن آپ صلی اللہ علیہ وسلم نے ( دوسرے مجاہدوں کے ساتھ ) ہمارا بھی حصہ مال غنیمت میں لگایا۔ یا انہوں نے یہ کہا کہ آپ نے غنیمت میں سے ہمیں بھی عطا فرمایا ‘ حالانکہ آپ صلی اللہ علیہ وسلم نے کسی ایسے شخص کا غنیمت میں حصہ نہیں لگایا جو لڑائی میں شریک نہ رہا ہو۔ صرف انہی لوگوں کو حصہ ملا تھا ‘ جو لڑائی میں شریک تھے۔ البتہ ہمارے کشتی کے ساتھیوں اور جعفر اور ان کے ساتھیوں کو بھی آپ نے غنیمت میں شریک کیا تھا ( حالانکہ ہم لوگ لڑائی میں شریک نہیں ہوئے تھے ) ۔' WHERE id = 3008;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے قتادہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”قریش کو میں ان کا دل ملانے کے لیے دیتا ہوں، کیونکہ ان کی جاہلیت ( کفر ) کا زمانہ ابھی تازہ گزرا ہے ( ان کی دلجوئی کرنا ضروری ہے ) ۔“' WHERE id = 3018;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا ہم کو شعیب نے خبر دی، انہیں زہری نے کہا کہ مجھ سے عروہ بن زبیر رضی اللہ عنہ نے بیان کیا، ان سے مسور بن مخرمہ رضی اللہ عنہما نے اور انہیں عمرو بن عوف رضی اللہ عنہ نے خبر دی وہ بنی عامر بن لوی کے حلیف تھے اور جنگ بدر میں شریک تھے۔ انہوں نے ان کو خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم نے ابوعبیدہ بن جراح رضی اللہ عنہ کو بحرین جزیہ وصول کرنے کے لیے بھیجا تھا۔ آپ صلی اللہ علیہ وسلم نے بحرین کے لوگوں سے صلح کی تھی اور ان پر علاء بن حضرمی رضی اللہ عنہ کو حاکم بنایا تھا۔ جب ابوعبیدہ رضی اللہ عنہ بحرین کا مال لے کر آئے تو انصار کو معلوم ہو گیا کہ ابوعبیدہ رضی اللہ عنہ آ گئے ہیں۔ چنانچہ فجر کی نماز سب لوگوں نے نبی کریم صلی اللہ علیہ وسلم کے ساتھ پڑھی۔ جب آپ صلی اللہ علیہ وسلم نماز پڑھا چکے تو لوگ آپ صلی اللہ علیہ وسلم کے سامنے آئے۔ آپ صلی اللہ علیہ وسلم انہیں دیکھ کر مسکرائے اور فرمایا کہ میرا خیال ہے کہ تم نے سن لیا ہے کہ ابوعبیدہ کچھ لے کر آئے ہیں؟ انصار رضی اللہ عنہم نے عرض کیا جی ہاں، یا رسول اللہ! آپ صلی اللہ علیہ وسلم نے فرمایا، تمہیں خوشخبری ہو، اور اس چیز کے لیے تم پرامید رہو۔ جس سے تمہیں خوشی ہو گی، لیکن اللہ کی قسم! میں تمہارے بارے میں محتاجی اور فقر سے نہیں ڈرتا۔ مجھے اگر خوف ہے تو اس بات کا کچھ دنیا کے دروازے تم پر اس طرح کھول دئیے جائیں گے جیسے تم سے پہلے لوگوں پر کھول دئیے گئے تھے، تو ایسا نہ ہو کہ تم بھی ان کی طرح ایک دوسرے سے جلنے لگو اور یہ جلنا تم کو بھی اسی طرح تباہ کر دے جیسا کہ پہلے لوگوں کو کیا تھا۔' WHERE id = 3029;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو امام مالک نے خبر دی، انہیں عمرو بن عبداللہ کے غلام ابوالنضر نے، انہیں ام ہانی بنت ابی طالب کے غلام ابومرہ نے خبر دی، انہوں نے ام ہانی بنت ابی طالب رضی اللہ عنہا سے سنا، آپ بیان کرتی تھیں کہ فتح مکہ کے موقع پر میں رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئی ( مکہ میں ) میں نے دیکھا کہ آپ غسل کر رہے تھے اور فاطمہ رضی اللہ عنہا آپ کی صاحبزادی پردہ کئے ہوئے تھیں۔ میں نے آپ کو سلام کیا، تو آپ نے دریافت فرمایا کہ کون صاحبہ ہیں؟ میں نے عرض کیا کہ میں ام ہانی بنت ابی طالب ہوں، آپ صلی اللہ علیہ وسلم نے فرمایا، آؤ اچھی آئیں، ام ہانی! پھر جب آپ صلی اللہ علیہ وسلم غسل سے فارغ ہوئے تو آپ نے کھڑے ہو کر آٹھ رکعت چاشت کی نماز پڑھی۔ آپ صلی اللہ علیہ وسلم صرف ایک کپڑا جسم اطہر پر لپیٹے ہوئے تھے۔ میں نے عرض کیا: یا رسول اللہ! میری ماں کے بیٹے علی رضی اللہ عنہ کہتے ہیں کہ وہ ایک شخص کو جسے میں پناہ دے چکی ہوں، قتل کئے بغیر نہیں رہیں گے۔ یہ شخص ہبیرہ کا فلاں لڑکا ( جعدہ ) ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا، ام ہانی! جسے تم نے پناہ دی، اسے ہماری طرف سے بھی پناہ ہے۔ ام ہانی رضی اللہ عنہا نے بیان کیا کہ یہ وقت چاشت کا تھا۔' WHERE id = 3040;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہم کو ابوحمزہ نے خبر دی، کہا کہ میں نے اعمش سے سنا، انہوں نے بیان کیا کہ میں نے ابووائل سے پوچھا، کیا آپ صفین کی جنگ میں موجود تھے؟ انہوں نے بیان کیا کہ ہاں ( میں تھا ) اور میں نے سہل بن حنیف رضی اللہ عنہ کو یہ کہتے سنا تھا کہ تم لوگ خود اپنی رائے کو غلط سمجھو، جو آپس میں لڑتے مرتے ہو۔ میں نے اپنے تئیں دیکھا جس دن ابوجندل آیا ( یعنی حدیبیہ کے دن ) اگر میں نبی کریم صلی اللہ علیہ وسلم کا حکم پھیر دیتا اور ہم نے جب کسی مصیبت میں ڈر کر تلواریں اپنے کندھوں پر رکھیں تو وہ مصیبت آسان ہو گئی۔ ہم کو اس کا انجام معلوم ہو گیا۔ مگر یہی ایک لڑائی ہے ( جو سخت مشکل ہے اس کا انجام بہتر نہیں معلوم ہوتا ) ۔' WHERE id = 3050;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن ابی شیبہ نے بیان کیا، ان سے ابواحمد نے بیان کیا، ان سے سفیان ثوری نے ان سے ابوالزناد نے، ان سے اعرج نے، اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ فرماتا ہے کہ ابن آدم نے مجھے گالی دی اور اس کے لیے مناسب نہ تھا کہ وہ مجھے گالی دیتا۔ اس نے مجھے جھٹلایا اور اس کے لیے یہ بھی مناسب نہ تھا۔ اس کی گالی یہ ہے کہ وہ کہتا ہے، میرا بیٹا ہے اور اس کا جھٹلانا یہ ہے کہ وہ کہتا ہے کہ جس طرح اللہ نے مجھے پہلی بار پیدا کیا، دوبارہ ( موت کے بعد ) وہ مجھے زندہ نہیں کر سکے گا۔' WHERE id = 3061;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، انہوں نے کہا کہ ہم سے لیث بن سعد نے کیا، انہوں نے کہا ہم سے عقیل نے بیان کیا، ان سے ابن شہاب نے بیان کیا کہ مجھے عروہ نے خبر دی، اور انہیں ام المؤمنین عائشہ صدیقہ رضی اللہ عنہا نے خبر دی کہ جس دن سورج گرہن لگا تو رسول اللہ صلی اللہ علیہ وسلم ( مصلے پر ) کھڑے ہوئے۔ «الله اكبر» کہا اور بڑی دیر تک قرآت کرتے رہے۔ پھر آپ صلی اللہ علیہ وسلم نے رکوع کیا، ایک بہت لمبا رکوع، پھر سر اٹھا کر «سمع الله لمن حمده» کہا اور پہلے کی طرح کھڑے ہو گئے۔ اس قیام میں بھی لمبی قرآت کی۔ اگرچہ پہلی قرآت سے کم تھی اور پھر رکوع میں چلے گئے اور دیر تک رکوع میں رہے، اگرچہ پہلے رکوع سے یہ کم تھا۔ اس کے بعد سجدہ کیا، ایک لمبا سجدہ، دوسری رکعت میں بھی آپ صلی اللہ علیہ وسلم نے اسی طرح کیا اور اس کے بعد سلام پھیرا تو سورج صاف ہو چکا تھا۔ اب آپ صلی اللہ علیہ وسلم نے صحابہ کو خطاب فرمایا اور سورج اور چاند گرہن کے متعلق بتلایا کہ یہ اللہ تعالیٰ کی نشانیوں میں سے نشانی ہیں اور ان میں کسی کی موت و حیات کی وجہ سے گرہن نہیں لگتا، اس لیے جب تم گرہن دیکھو تو فوراً نماز کی طرف لپک جاؤ۔' WHERE id = 3071;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے عدی بن ثابت نے اور ان سے براء بن عازب رضی اللہ عنہ نے بیان کیا کہ ہم سے حفص بن عمر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے عدی بن ثابت نے اور ان سے براء بن عازب رضی اللہ عنہ نے بیان کیا کہ' WHERE id = 3081;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، کہا ہم سے ابوالزناد نے بیان کیا، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ فرشتے آگے پیچھے زمین پر آتے جاتے رہتے ہیں، کچھ فرشتے رات کے ہیں اور کچھ دن کے اور یہ سب فجر اور عصر کی نماز میں جمع ہو جاتے ہیں۔ پھر وہ فرشتے جو تمہارے یہاں رات میں رہے۔ اللہ کے حضور میں جاتے ہیں، اللہ تعالیٰ ان سے دریافت فرماتا ہے…. حالانکہ وہ سب سے زیادہ جاننے والا ہے…. کہ تم نے میرے بندوں کو کس حال میں چھوڑا، وہ فرشتے عرض کرتے ہیں کہ جب ہم نے انہیں چھوڑا تو وہ ( فجر کی ) نماز پڑھ رہے تھے۔ اور اسی طرح جب ہم ان کے یہاں گئے تھے، جب بھی وہ ( عصر ) کی نماز پڑھ رہے تھے۔' WHERE id = 3091;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے اعمش نے، ان سے ابراہیم نے، ان سے علقمہ نے اور ان سے عبداللہ رضی اللہ عنہ نے ( اللہ تعالیٰ کے ارشاد ) «لقد رأى من آيات ربه الكبرى‏» کے متعلق بتلایا کہ نبی کریم صلی اللہ علیہ وسلم نے ایک سبز رنگ کا بچھونا دیکھا تھا جو آسمان میں سارے کناروں کو گھیرے ہوئے تھا۔' WHERE id = 3101;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، کہا ہم سے ہمام نے بیان کیا، انہوں نے کہا کہ میں نے ابوعمران جونی سے سنا، ان سے ابوبکر بن عبداللہ بن قیس اشعری نے بیان کیا اور ان سے ان کے والد نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ” ( جنتیوں کا ) خیمہ کیا ہے، ایک موتی ہے خولدار جس کی بلندی اوپر کو تیس میل تک ہے۔ اس کے ہر کنارے پر مومن کی ایک بیوی ہو گی جسے دوسرے نہ دیکھ سکیں گے۔“ ابوعبدالصمد اور حارث بن عبید نے ابوعمران سے ( بجائے تیس میل کے ) ساٹھ میل بیان کیا۔' WHERE id = 3111;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا کہ مجھے عدی بن ثابت نے خبر دی، کہا کہ میں نے براء بن عازب رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ جب رسول اللہ صلی اللہ علیہ وسلم کے ( صاحبزادے ) ابراہیم رضی اللہ عنہ کا انتقال ہوا، تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ جنت میں اسے ایک دودھ پلانے والی انا کے حوالہ کر دیا گیا ہے ( جو ان کو دودھ پلاتی ہے ) ۔' WHERE id = 3122;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا کہ مجھ سے امام مالک رحمہ اللہ نے بیان کیا، ان سے ابوالزناد نے، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”تمہاری ( دنیا کی ) آگ جہنم کی آگ کے مقابلے میں ( اپنی گرمی اور ہلاکت خیزی میں ) سترواں حصہ ہے۔“ کسی نے پوچھا، یا رسول اللہ! ( کفار اور گنہگاروں کے عذاب کے لیے ) یہ ہماری دنیا کی آگ بھی بہت تھی۔ آپ صلی اللہ علیہ وسلم نے فرمایا ”دنیا کی آگ کے مقابلے میں جہنم کی آگ انہتر گنا بڑھ کر ہے۔“' WHERE id = 3132;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث نے بیان کیا، ان سے عقیل نے بیان کیا، ان سے ابن شہاب نے، ان سے تیمیین کے مولیٰ ابن ابی انس نے بیان کیا، ان سے ان کے والد نے بیان کیا کہ ابوہریرہ رضی اللہ عنہ کو یہ کہتے سنا تھا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جب رمضان کا مہینہ آتا ہے تو جنت کے دروازے کھول دئیے جاتے ہیں۔ جہنم کے دروازے بند کر دئیے جاتے ہیں اور شیاطین کو زنجیروں میں کس دیا جاتا ہے۔“' WHERE id = 3143;
UPDATE hadiths SET urdu = 'ہم سے مالک بن اسماعیل نے بیان کیا، کہا ہم سے اسرائیل نے بیان کیا، ان سے مغیرہ نے، ان سے ابراہیم نے اور ان سے علقمہ نے بیان کیا کہ میں شام پہنچا تو لوگوں نے کہا، ابودرداء آئے انہوں نے کہا، کیا تم لوگوں میں وہ شخص ہے جس کو اللہ تعالیٰ نے اپنے رسول کی زبان پر ( یعنی آپ کے زمانے سے ) شیطان سے بچا رکھا ہے۔ ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا اور ان سے مغیرہ نے یہی حدیث، اس میں یہ ہے، جنہیں اللہ تعالیٰ نے اپنے نبی کی زبانی شیطان سے اپنی پناہ میں لینے کا اعلان کیا تھا، آپ کی مراد عمار رضی اللہ عنہ سے تھی۔' WHERE id = 3153;
UPDATE hadiths SET urdu = 'اور عبدالرزاق نے بھی اس حدیث کو معمر سے روایت کیا، اس میں یوں ہے کہ مجھ کو ابولبابہ رضی اللہ عنہ نے دیکھا یا میرے چچا زید بن خطاب نے اور معمر کے ساتھ اس حدیث کو یونس اور ابن عیینہ اور اسحاق کلبی اور زبیدہ نے بھی زہری سے روایت کیا اور صالح اور سالم سے، انہوں نے ابن ابی حفصہ اور ابن مجمع نے بھی زہری سے انہوں نے ابن عمر رضی اللہ عنہما سے اس میں یوں ہے کہ مجھ کو ابولبابہ اور زید بن خطاب ( دونوں ) نے دیکھا۔' WHERE id = 3164;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ قطان نے بیان کیا، ان سے ہشام نے بیان کیا، ان سے ان کے والد نے بیان کیا اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے دم بریدہ سانپ کو مار ڈالنے کا حکم دیا اور فرمایا کہ یہ آنکھوں کو نقصان پہنچاتا ہے اور حمل کو ساقط کر دیتا ہے۔' WHERE id = 3174;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم کو امام مالک نے خبر دی، انہیں نافع نے اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے کتوں کو مارنے کا حکم فرمایا ہے۔' WHERE id = 3186;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے عبیداللہ بن ابی بکر بن انس نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ نے ماں کے رحم کے لیے ایک فرشتہ مقرر کر دیا ہے وہ فرشتہ عرض کرتا ہے، اے رب! یہ «نطفة» ہے، اے رب یہ «مضغة» ہے۔ اے رب! یہ «علقة» ہے۔ پھر جب اللہ تعالیٰ اسے پیدا کرنے کا ارادہ کرتا ہے تو فرشتہ پوچھتا ہے اے رب! یہ مرد ہے یا اے رب! یہ عورت ہے، اے رب! یہ بد ہے یا نیک؟ اس کی روزی کیا ہے؟ اور مدت زندگی کتنی ہے؟ چنانچہ اسی کے مطابق ماں کے پیٹ ہی میں سب کچھ فرشتہ رکھ لیتا ہے۔“' WHERE id = 3196;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عرعرہ نے بیان کیا، ہم سے شعبہ نے بیان کیا، ان سے حکم نے، ان سے مجاہد نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ” ( غزوہ خندق کے موقع پر ) پروا ہوا سے میری مدد کی گئی اور قوم عاد پچھوا ہوا سے ہلاک کر دی گئی تھی۔“' WHERE id = 3206;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے یحییٰ بن سعید نے بیان کیا، کہا ہم سے عبیداللہ نے بیان کیا، کہا کہ مجھ سے سعید بن ابی سعید نے بیان کیا، ان سے ان کے والد نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ عرض کیا گیا: یا رسول اللہ! سب سے زیادہ شریف کون ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جو سب سے زیادہ پرہیزگار ہو۔“ صحابہ نے عرض کیا کہ ہم آپ سے اس کے متعلق نہیں پوچھتے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”پھر اللہ کے نبی یوسف بن نبی اللہ بن نبی اللہ بن خلیل اللہ ( سب سے زیادہ شریف ہیں ) “ صحابہ نے کہا کہ ہم اس کے متعلق بھی نہیں پوچھتے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اچھا عرب کے خاندانوں کے متعلق تم پوچھنا چاہتے ہو۔ سنو جو جاہلیت میں شریف تھے اسلام میں بھی وہ شریف ہیں جب کہ دین کی سمجھ انہیں آ جائے۔“ ابواسامہ اور معتمر نے عبیداللہ سے بیان کیا، ان سے سعید نے اور ان سے ابوہریرہ رضی اللہ عنہ نے اور انہوں نے نبی کریم صلی اللہ علیہ وسلم سے۔' WHERE id = 3216;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، کہا ہم سے ابوعامر عبدالملک بن عمرو نے بیان کیا، کہا کہ ہم سے ابراہیم بن نافع نے بیان کیا، ان سے کثیر بن کثیر نے، ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ ابراہیم علیہ السلام اور ان کی بیوی ( سارہ علیہ السلام ) کے درمیان جو کچھ جھگڑا ہونا تھا جب وہ ہوا تو آپ اسماعیل علیہ السلام اور ان کی والدہ ( ہاجرہ علیہ السلام ) کو لے کر نکلے، ان کے ساتھ ایک مشکیزہ تھا۔ جس میں پانی تھا، اسماعیل علیہ السلام کی والدہ اسی مشکیزہ کا پانی پیتی رہیں اور اپنا دودھ اپنے بچے کو پلاتی رہیں۔ جب ابراہیم مکہ پہنچے تو انہیں ایک بڑے درخت کے پاس ٹھہرا کر اپنے گھر واپس جانے لگے۔ اسماعیل علیہ السلام کی والدہ ان کے پیچھے پیچھے آئیں۔ جب مقام کداء پر پہنچے تو انہوں نے پیچھے سے آواز دی کہ اے ابراہیم! ہمیں کس پر چھوڑ کر جا رہے ہیں؟ انہوں نے فرمایا کہ اللہ پر! ہاجرہ علیہ السلام نے کہا کہ پھر میں اللہ پر خوش ہوں۔ بیان کیا کہ پھر ہاجرہ اپنی جگہ پر واپس چلی آئیں اور اسی مشکیزے سے پانی پیتی رہیں اور اپنا دودھ اپنے بچے کو پلاتی رہیں جب پانی ختم ہو گیا تو انہوں نے سوچا کہ ادھر ادھر دیکھنا چاہئے، ممکن ہے کہ کوئی آدمی نظر آ جائے۔ راوی نے بیان کیا کہ یہی سوچ کر وہ صفا ( پہاڑی ) پر چڑھ گئیں اور چاروں طرف دیکھا کہ شاید کوئی نظر آ جائے لیکن کوئی نظر نہ آیا۔ پھر جب وادی میں اتریں تو دوڑ کر مروہ تک آئیں۔ اسی طرح کئی چکر لگائے، پھر سوچا کہ چلوں ذرا بچے کو تو دیکھوں کس حالت میں ہے۔ چنانچہ آئیں اور دیکھا تو بچہ اسی حالت میں تھا ( جیسے تکلیف کے مارے ) موت کے لیے تڑپ رہا ہو۔ یہ حال دیکھ کر ان سے صبر نہ ہو سکا، سوچا چلوں دوبارہ دیکھوں ممکن ہے کہ کوئی آدمی نظر آ جائے، آئیں اور صفا پہاڑ پر چڑھ گئیں اور چاروں طرف نظر پھیر پھیر کر دیکھتی رہیں لیکن کوئی نظر نہ آیا۔ اس طرح ہاجرہ علیہ السلام نے سات چکر لگائے پھر سوچا، چلوں دیکھوں بچہ کس حالت میں ہے؟ اسی وقت انہیں ایک آواز سنائی دی۔ انہوں نے ( آواز سے مخاطب ہو کر ) کہا کہ اگر تمہارے پاس کوئی بھلائی ہے تو میری مدد کرو۔ وہاں جبرائیل علیہ السلام موجود تھے۔ انہوں نے اپنی ایڑی سے یوں کیا ( اشارہ کر کے بتایا ) اور زمین ایڑی سے کھودی۔ راوی نے بیان کیا کہ اس عمل کے نتیجے میں وہاں سے پانی پھوٹ پڑا۔ ام اسماعیل ڈریں۔ ( کہیں یہ پانی غائب نہ ہو جائے ) پھر وہ زمین کھودنے لگیں۔ راوی نے بیان کیا کہ ابوالقاسم صلی اللہ علیہ وسلم نے فرمایا: اگر وہ پانی کو یوں ہی رہنے دیتیں تو پانی زمین پر بہتا رہتا۔ غرض ہاجرہ علیہ السلام زمزم کا پانی پیتی رہیں اور اپنا دودھ اپنے بچے کو پلاتی رہیں۔ ابن عباس رضی اللہ عنہما نے بیان کیا کہ اس کے بعد قبیلہ جرہم کے کچھ لوگ وادی کے نشیب سے گزرے۔ انہیں وہاں پرند نظر آئے۔ انہیں یہ کچھ خلاف عادت معلوم ہوا۔ انہوں نے آپس میں کہا کہ پرندہ تو صرف پانی ہی پر ( اس طرح ) منڈلا سکتا ہے۔ ان لوگوں نے اپنا آدمی وہاں بھیجا۔ اس نے جا کر دیکھا تو واقعی وہاں پانی موجود تھا۔ اس نے آ کر اپنے قبیلے والوں کو خبر دی تو یہ سب لوگ یہاں آ گئے اور کہا کہ اے ام اسماعیل! کیا ہمیں اپنے ساتھ رہنے کی یا ( یہ کہا کہ ) اپنے ساتھ قیام کرنے کی اجازت دیں گی؟ پھر ان کے بیٹے ( اسماعیل علیہ السلام ) بالغ ہوئے اور قبیلہ جرہم ہی کی ایک لڑکی سے ان کا نکاح ہو گیا۔ ابن عباس رضی اللہ عنہما نے بیان کیا کہ پھر ابراہیم علیہ السلام کو خیال آیا اور انہوں نے اپنی اہلیہ ( سارہ علیہا السلام ) سے فرمایا کہ میں جن لوگوں کو ( مکہ میں ) چھوڑ آیا تھا ان کی خبر لینے جاؤں گا۔ ابن عباس رضی اللہ عنہما نے بیان کیا کہ پھر ابراہیم علیہ السلام مکہ تشریف لائے اور سلام کر کے دریافت فرمایا کہ اسماعیل کہاں ہیں؟ ان کی بیوی نے بتایا کہ شکار کے لیے گئے۔ انہوں نے فرمایا کہ جب وہ آئیں تو ان سے کہنا کہ اپنے دروازے کی چوکھٹ بدل ڈالیں۔ جب اسماعیل علیہ السلام آئے تو ان کی بیوی نے واقعہ کی اطلاع دی۔ اسماعیل علیہ السلام نے فرمایا کہ تمہیں ہو ( جسے بدلنے کے لیے ابراہیم علیہ السلام کہہ گئے ہیں ) اب تم اپنے گھر جا سکتی ہو۔ بیان کیا کہ پھر ایک مدت کے بعد دوبارہ ابراہیم علیہ السلام کو خیال ہوا اور انہوں نے اپنی بیوی سے فرمایا کہ میں جن لوگوں کو چھوڑ آیا ہوں انہیں دیکھنے جاؤں گا۔ راوی نے بیان کیا کہ ابراہیم علیہ السلام تشریف لائے اور دریافت فرمایا کہ اسماعیل کہاں ہیں؟ ان کی بیوی نے بتایا کہ شکار کے لیے گئے ہیں۔ انہوں نے یہ بھی کہا کہ آپ ٹھہرئیے اور کھانا تناول فرما لیجئے۔ ابراہیم علیہ السلام نے دریافت فرمایا کہ تم لوگ کھاتے پیتے کیا ہو؟ انہوں نے بتایا کہ گوشت کھاتے ہیں اور پانی پیتے ہیں۔ آپ نے دعا کی کہ اے اللہ! ان کے کھانے اور ان کے پانی میں برکت نازل فرما۔ بیان کیا کہ ابوالقاسم صلی اللہ علیہ وسلم نے فرمایا، ابراہیم علیہ السلام کی اس دعا کی برکت اب تک چلی آ رہی ہے۔ راوی نے بیان کیا کہ پھر ( تیسری بار ) ابراہیم علیہ السلام کو ایک مدت کے بعد خیال ہوا اور اپنی اہلیہ سے انہوں نے کہا کہ جن کو میں چھوڑ آیا ہوں ان کی خبر لینے مکہ جاؤں گا۔ چنانچہ آپ تشریف لائے اور اس مرتبہ اسماعیل علیہ السلام سے ملاقات ہوئی، جو زمزم کے پیچھے اپنے تیر ٹھیک کر رہے تھے۔ ابراہیم علیہ السلام نے فرمایا، اے اسماعیل! تمہارے رب نے مجھے حکم دیا ہے کہ میں یہاں اس کا ایک گھر بناؤں، بیٹے نے عرض کیا کہ پھر آپ اپنے رب کا حکم بجا لائیے۔ انہوں نے فرمایا اور مجھے یہ بھی حکم دیا ہے کہ تم اس کام میں میری مدد کرو۔ عرض کیا کہ میں اس کے لیے تیار ہوں۔ یا اسی قسم کے اور الفاظ ادا کئے۔ راوی نے بیان کیا کہ پھر دونوں باپ بیٹے اٹھے۔ ابراہیم علیہ السلام دیواریں اٹھاتے تھے اور اسماعیل علیہ السلام انہیں پتھر لا لا کر دیتے تھے اور دونوں یہ دعا کرتے جاتے تھے۔ اے ہمارے رب! ہماری طرف سے یہ خدمت قبول کر۔ بیشک تو بڑا سننے والا، بہت جاننے والا ہے۔ راوی نے بیان کیا کہ آخر جب دیوار بلند ہو گئی اور بزرگ ( ابراہیم علیہ السلام ) کو پتھر ( دیوار پر ) رکھنے میں دشواری ہوئی تو وہ مقام ( ابراہیم ) کے پتھر پر کھڑے ہوئے اور اسماعیل علیہ السلام ان کو پتھر اٹھا اٹھا کر دیتے جاتے اور ان حضرات کی زبان پر یہ دعا جاری تھی۔ ”اے ہمارے رب! ہماری طرف سے اسے قبول فرما لے۔ بیشک تو بڑا سننے والا بہت جاننے والا ہے۔“' WHERE id = 3227;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا ‘ کہا ہم کو شعیب نے خبر دی ‘ ان سے ابوالزناد نے بیان کیا ‘ ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ لوط علیہ السلام کی مغفرت فرمائے کہ وہ زبردست رکن ( یعنی اللہ ) کی پناہ میں گئے تھے۔“' WHERE id = 3237;
UPDATE hadiths SET urdu = 'ہم سے ربیع بن یحییٰ بصریٰ نے بیان کیا ‘ کہا ہم سے زائدہ نے بیان کیا ‘ ان سے عبدالملک بن عمیر نے ‘ ان سے ابوبردہ بن ابی موسیٰ نے اور ان سے ان کے والد نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم جب بیمار پڑے تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ ابوبکر سے کہو کہ لوگوں کو نماز پڑھائیں۔ عائشہ رضی اللہ عنہا نے عرض کیا کہ ابوبکر رضی اللہ عنہ نہایت نرم دل انسان ہیں لیکن نبی کریم صلی اللہ علیہ وسلم نے دوبارہ یہی حکم فرمایا اور انہوں نے بھی وہی عذر دہرایا۔ آخر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ان سے کہو نماز پڑھائیں۔ تم تو یوسف کی ساتھ والیاں ہو۔ ( ظاہر کچھ باطن کچھ ) چنانچہ ابوبکر رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم کی زندگی میں امامت کی اور حسین بن علی جعفی نے زائدہ سے «رجل رقيق‏.» کے الفاظ نقل کئے کہ ابوبکر نرم دل آدمی ہیں۔' WHERE id = 3247;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا ‘ کہا ہم سے سفیان بن عیینہ نے بیان کیا ‘ کہا ہم سے ایوب سختیانی نے بیان کیا ‘ ان سے سعید بن جبیر کے صاحبزادے (عبداللہ) نے اپنے والد سے اور ان سے ابن عباس رضی اللہ عنہما نے کہ جب نبی کریم صلی اللہ علیہ وسلم مدینہ تشریف لائے تو وہاں کے لوگ ایک دن یعنی عاشورا کے دن روزہ رکھتے تھے۔ ان لوگوں ( یہودیوں ) نے بتایا کہ یہ بڑی عظمت والا دن ہے، اسی دن اللہ تعالیٰ نے موسیٰ علیہ السلام کو نجات دی تھی اور آل فرعون کو غرق کیا تھا۔ اس کے شکر میں موسیٰ علیہ السلام نے اس دن کا روزہ رکھا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں موسیٰ علیہ السلام کا ان سے زیادہ قریب ہوں۔ چنانچہ آپ صلی اللہ علیہ وسلم نے خود بھی اس دن کا روزہ رکھنا شروع کیا اور صحابہ کو بھی اس کا حکم فرمایا۔' WHERE id = 3258;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن موسیٰ نے بیان کیا ‘ کہا ہم سے عبدالرزاق نے بیان کیا ‘ کہا ہم کو معمر نے خبر دی ‘ انہیں عبداللہ بن طاؤس نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ اللہ تعالیٰ نے موسیٰ علیہ السلام کے پاس ملک الموت کو بھیجا۔ جب ملک الموت موسیٰ علیہ السلام کے پاس آئے تو انہوں نے انہیں چانٹا مارا ( کیونکہ وہ انسان کی صورت میں آیا تھا ) ملک الموت ‘ اللہ رب العزت کی بارگاہ میں واپس ہوئے اور عرض کیا کہ تو نے اپنے ایک ایسے بندے کے پاس مجھے بھیجا جو موت کے لیے تیار نہیں ہے۔ اللہ تعالیٰ نے فرمایا کہ دوبارہ ان کے پاس جاؤ اور کہو کہ اپنا ہاتھ کسی بیل کی پیٹھ پر رکھیں، ان کے ہاتھ میں جتنے بال اس کے آ جائیں ان میں سے ہر بال کے بدلے ایک سال کی عمر انہیں دی جائے گی ( ملک الموت دوبارہ آئے اور اللہ تعالیٰ کا فیصلہ سنایا ) موسیٰ علیہ السلام بولے: اے رب! پھر اس کے بعد کیا ہو گا؟ اللہ تعالیٰ نے فرمایا کہ پھر موت ہے۔ موسیٰ علیہ السلام نے عرض کیا کہ پھر ابھی کیوں نہ آ جائے۔ ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ پھر موسیٰ علیہ السلام نے اللہ تعالیٰ سے دعا کی کہ بیت المقدس سے مجھے اتنا قریب کر دیا جائے کہ ( جہاں ان کی قبر ہو وہاں سے ) اگر کوئی پتھر پھینکے تو وہ بیت المقدس تک پہنچ سکے۔ ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اگر میں وہاں موجود ہوتا تو بیت المقدس میں ‘ میں تمہیں ان کی قبر دکھاتا جو راستے کے کنارے پر ہے ‘ ریت کے سرخ ٹیلے سے نیچے۔ عبدالرزاق بن ہمام نے بیان کیا کہ ہمیں معمر نے خبر دی ‘ انہیں ہمام نے اور ان کو ابوہریرہ رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے اسی طرح بیان کیا۔' WHERE id = 3268;
UPDATE hadiths SET urdu = 'ہم سے خلاد بن یحییٰ نے بیان کیا ‘ کہا ہم سے مسعر نے بیان کیا ‘ کہا ہم سے حبیب بن ابی ثابت نے بیان کیا ‘ ان سے ابو العباس نے اور ان سے عبداللہ بن عمرو بن عاص رضی اللہ عنہ نے بیان کیا کہ مجھ سے رسول اللہ صلی اللہ علیہ وسلم نے دریافت فرمایا ”کیا میری یہ خبر صحیح ہے کہ تم رات بھر عبادت کرتے ہو اور دن بھر ( روزانہ ) روزہ رکھتے ہو؟“ میں نے عرض کیا کہ جی ہاں۔ آپ صلی اللہ علیہ وسلم نے فرمایا لیکن تم اسی طرح کرتے رہے تو تمہاری آنکھیں کمزور ہو جائیں گی اور تمہارا جی اکتا جائے گا۔ ہر مہینے میں تین روزے رکھا کرو کہ یہی ( ثواب کے اعتبار سے ) زندگی بھر کا روزہ ہے ‘ یا ( آپ صلی اللہ علیہ وسلم نے فرمایا کہ ) زندگی بھر کے روزے کی طرح ہے۔ میں نے عرض کیا کہ میں اپنے میں محسوس کرتا ہوں ‘ مسعر نے بیان کیا کہ آپ کی مراد قوت سے تھی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر داؤد علیہ السلام کے روزے کی طرح روزے رکھا کرو۔ وہ ایک دن روزے رکھا کرتے اور ایک دن بغیر روزے کے رہا کرتے تھے اور دشمن سے مقابلہ کرتے تو میدان سے بھاگا نہیں کرتے تھے۔' WHERE id = 3279;
UPDATE hadiths SET urdu = 'ہم سے ہدبہ بن خالد نے بیان کیا، انہوں نے کہا ہم سے ہمام بن یحییٰ نے بیان کیا، انہوں نے کہا ہم سے قتادہ نے بیان کیا، ان سے انس بن مالک رضی اللہ عنہ نے اور ان سے مالک بن صعصعہ رضی اللہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے شب معراج کے متعلق بیان فرمایا کہ پھر آپ اوپر چڑھے اور دوسرے آسمان پر تشریف لے گئے۔ پھر دروازہ کھولنے کے لیے کہا۔ پوچھا گیا: کون ہیں؟ کہا کہ جبرائیل علیہ السلام۔ پوچھا گیا: آپ کے ساتھ کون ہیں؟ کہا کہ محمد صلی اللہ علیہ وسلم ۔ پوچھا گیا: کیا انہیں لانے کے لیے بھیجا، کہا کہ جی ہاں۔ پھر جب میں وہاں پہنچا تو عیسیٰ اور یحییٰ علیہما السلام وہاں موجود تھے۔ یہ دونوں نبی آپس میں خالہ زاد بھائی ہیں۔ جبرائیل علیہ السلام نے بتایا کہ یہ یحییٰ اور عیسیٰ علیہما السلام ہیں۔ انہیں سلام کیجئے۔ میں نے سلام کیا، دونوں نے جواب دیا اور کہا خوش آمدید نیک بھائی اور نیک نبی۔' WHERE id = 3289;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، انہیں ابوسلمہ نے خبر دی اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم فرما رہے تھے کہ میں ابن مریم علیہما السلام سے دوسروں کے مقابلہ میں زیادہ قریب ہوں، انبیاء علاتی بھائیوں کی طرح ہیں اور میرے اور عیسیٰ علیہ السلام کے درمیان کوئی نبی نہیں ہے۔' WHERE id = 3300;
UPDATE hadiths SET urdu = 'ہم سے عمران بن میسرہ نے بیان کیا، کہا ہم سے عبدالوارث نے بیان کیا، کہا ہم سے خالد نے، ان سے ابوقلابہ نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ ( نماز کے لیے اعلان کے طریقے پر بحث کرتے وقت ) صحابہ نے آگ اور ناقوس کا ذکر کیا، لیکن بعض نے کہا کہ یہ تو یہود و نصاریٰ کا طریقہ ہے۔ آخر بلال رضی اللہ عنہ کو حکم ہوا کہ اذان میں ( کلمات ) دو دو دفعہ کہیں اور تکبیر میں ایک ایک دفعہ۔' WHERE id = 3312;
UPDATE hadiths SET urdu = 'ہم سے سعید بن تلید نے بیان کیا، کہا ہم سے ابن وہب نے بیان کیا، کہا کہ مجھے جریر بن حازم نے خبر دی، انہیں ایوب نے اور انہیں محمد بن سیرین نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے بیان فرمایا ”ایک کتا ایک کنویں کے چاروں طرف چکر کاٹ رہا تھا جیسے پیاس کی شدت سے اس کی جان نکل جانے والی ہو کہ بنی اسرائیل کی ایک زانیہ عورت نے اسے دیکھ لیا۔ اس عورت نے اپنا موزہ اتار کر کتے کو پانی پلایا اور اس کی مغفرت اسی عمل کی وجہ سے ہو گئی۔“' WHERE id = 3322;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص نے بیان کیا، کہا ہم سے میرے باپ حفص بن غیاث نے بیان کیا، کہا ہم سے اعمش نے بیان کیا کہ کہ مجھ سے شقیق بن سلمہ نے بیان کیا کہ عبداللہ بن مسعود رضی اللہ عنہ نے کہا میں گویا نبی کریم صلی اللہ علیہ وسلم کو اس وقت دیکھ رہا ہوں۔ آپ بنی اسرائیل کے ایک نبی کا واقعہ بیان کر رہے تھے کہ ان کی قوم نے انہیں مارا اور خون آلود کر دیا۔ لیکن وہ نبی خون صاف کرتے جاتے اور یہ دعا کرتے «اللهم اغفر لقومي» کہ اے اللہ! میری قوم کی مغفرت فرما۔ یہ لوگ جانتے نہیں ہیں۔' WHERE id = 3332;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا ان سے عمرو بن مرہ نے کہا کہ میں نے سعید بن مسیب سے سنا آپ نے بیان کیا کہ معاویہ بن ابی سفیان رضی اللہ عنہ نے مدینہ کے اپنے آخری سفر میں ہمیں خطاب فرمایا اور ( خطبہ کے دوران ) آپ نے بالوں کا ایک گچھا نکالا اور فرمایا، میں سمجھتا ہوں کہ یہودیوں کے سوا اور کوئی اس طرح نہ کرتا ہو گا اور نبی کریم صلی اللہ علیہ وسلم نے اس طرح بال سنوارنے کا نام «الزور» ( فریب و جھوٹ ) رکھا ہے۔ آپ کی مراد «وصال في الشعر‏.‏» سے تھی۔ یعنی بالوں میں جوڑ لگانے سے تھی ( جیسے اکثر عورتیں مصنوعی بالوں میں جوڑ کیا کرتی ہیں ) آدم کے ساتھ اس حدیث کو غندر نے بھی شعبہ سے روایت کیا ہے۔' WHERE id = 3342;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، ان سے ابن مسیب نے اور ان سے جبیر بن مطعم نے بیان کیا کہ میں اور عثمان بن عفان رضی اللہ عنہما دونوں مل کر نبی کریم صلی اللہ علیہ وسلم کے پاس گئے اور ہم نے عرض کیا: یا رسول اللہ صلی اللہ علیہ وسلم ! بنو مطلب کو تو آپ نے عطا فرمایا اور ہمیں ( بنی امیہ کو ) نظر انداز کر دیا حالانکہ آپ کے لیے ہم اور وہ ایک ہی درجے کے ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ” ( یہ صحیح ہے ) مگر بنو ہاشم اور بنو مطلب ایک ہی ہیں۔“' WHERE id = 3354;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے سعد بن ابراہیم نے، ان سے عبدالرحمٰن بن ہرمز نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”قریش، انصار، جہینہ، مزینہ، اسلم، غفار اور اشجع میرے خیرخواہ ہیں، اور اللہ اور اس کے رسول کے سوا اور کوئی ان کا حمایتی نہیں۔“' WHERE id = 3364;
UPDATE hadiths SET urdu = 'مجھ سے عمرو بن عباس نے بیان کیا، کہا ہم سے عبدالرحمٰن بن مہدی نے، کہا ہم سے مثنیٰ نے، ان سے ابوجمرہ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ ہم سے زید نے جو اخزم کے بیٹے ہیں، بیان کیا، کہا ہم سے ابوقتیبہ سلم بن قتیبہ نے بیان کیا، ان سے مثنیٰ بن سعید قصیر نے بیان کیا، کہا کہ مجھ سے ابوجمرہ نے بیان کیا، کہا کہ ہم سے عبداللہ بن عباس رضی اللہ عنہما نے کہا کہ جب ابوذر رضی اللہ عنہ کو رسول اللہ صلی اللہ علیہ وسلم کی نبوت کے بارے معلوم ہوا تو انہوں نے اپنے بھائی انیس سے کہا مکہ جانے کے لیے سواری تیار کر اور اس شخص کے متعلق جو نبی ہونے کا مدعی ہے اور کہتا ہے کہ اس کے پاس آسمان سے خبر آتی ہے، میرے لیے خبریں حاصل کر کے لا۔ اس کی باتوں کو خود غور سے سننا اور پھر میرے پاس آنا۔ ان کے بھائی وہاں سے چلے اور مکہ حاضر ہو کر آنحضرت صلی اللہ علیہ وسلم کی باتیں خود سنیں پھر واپس ہو کر انہوں نے ابوذر رضی اللہ عنہ کو بتایا کہ میں نے انہیں خود دیکھا ہے، وہ اچھے اخلاق کا لوگوں کو حکم کرتے ہیں اور میں نے ان سے جو کلام سنا وہ شعر نہیں ہے۔ اس پر ابوذر رضی اللہ عنہ نے کہا جس مقصد کے لیے میں نے تمہیں بھیجا تھا مجھے اس پر پوری طرح تشفی نہیں ہوئی۔ آخر انہوں نے خود توشہ باندھا، پانی سے بھرا ہوا ایک پرانا مشکیزہ ساتھ لیا اور مکہ آئے۔ مسجدالحرام میں حاضری دی اور یہاں نبی کریم صلی اللہ علیہ وسلم کو تلاش کیا۔ ابوذر رضی اللہ عنہ آنحضرت صلی اللہ علیہ وسلم کو پہچانتے نہیں تھے اور کسی سے آپ کے متعلق پوچھنا بھی مناسب نہیں سمجھا، کچھ رات گزر گئی کہ وہ لیٹے ہوئے تھے، حضرت علی رضی اللہ عنہ نے ان کو اس حالت میں دیکھا اور سمجھ گئے کہ کوئی مسافر ہے۔ علی رضی اللہ عنہ نے ان سے کہا آپ میرے گھر چل کر آرام کیجئے۔ ابوذر رضی اللہ عنہ ان کے پیچھے پیچھے چلے گئے لیکن کسی نے ایک دوسرے کے بارے میں بات نہیں کی۔ جب صبح ہوئی تو ابوذر رضی اللہ عنہ نے اپنا مشکیزہ اور توشہ اٹھایا اور مسجدالحرام میں آ گئے۔ یہ دن بھی یونہی گزر گیا اور وہ نبی کریم صلی اللہ علیہ وسلم کو نہ دیکھ سکے۔ شام ہوئی تو سونے کی تیاری کرنے لگے۔ علی رضی اللہ عنہ پھر وہاں سے گزرے اور سمجھ گئے کہ ابھی اپنے ٹھکانے جانے کا وقت اس شخص پر نہیں آیا، وہ انہیں وہاں سے پھر اپنے ساتھ لے آئے اور آج بھی کسی نے ایک دوسرے سے بات چیت نہیں کی، تیسرا دن جب ہوا اور علی رضی اللہ عنہ نے ان کے ساتھ یہی کام کیا اور اپنے ساتھ لے گئے تو ان سے پوچھا کیا تم مجھے بتا سکتے ہو کہ یہاں آنے کا باعث کیا ہے؟ ابوذر رضی اللہ عنہ نے کہا کہ اگر تم مجھ سے پختہ وعدہ کر لو کہ میری راہ نمائی کرو گے تو میں تم کو سب کچھ بتادوں گا۔ علی رضی اللہ عنہ نے وعدہ کر لیا تو انہوں نے انہیں اپنے خیالات کی خبر دی۔ علی رضی اللہ عنہ نے فرمایا کہ بلاشبہ وہ حق پر ہیں اور اللہ کے سچے رسول ہیں اچھا صبح کو تم میرے پیچھے پیچھے میرے ساتھ چلنا۔ اگر میں ( راستے میں ) کوئی ایسی بات دیکھوں جس سے مجھے تمہارے بارے میں کوئی خطرہ ہو تو میں کھڑا ہو جاؤں گا ( کسی دیوار کے قریب ) گویا مجھے پیشاب کرنا ہے۔ اس وقت تم میرا انتظار مت کرنا اور جب میں پھر چلنے لگوں تو میرے پیچھے آ جانا تاکہ کوئی سمجھ نہ سکے کہ یہ دونوں ساتھ ہیں اور اس طرح جس گھر میں، میں داخل ہوں تم بھی داخل ہو جانا۔ انہوں نے ایسا ہی کیا اور پیچھے پیچھے چلے تاآنکہ علی رضی اللہ عنہ کے ساتھ وہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں پہنچ گئے، آپ کی باتیں سنیں اور وہیں اسلام لے آئے۔ پھر آنحضرت صلی اللہ علیہ وسلم نے ان سے فرمایا: اب اپنی قوم غفار میں واپس جاؤ اور انہیں میرا حال بتاو تاآنکہ جب ہمارے غلبہ کا علم تم کو ہو جائے ( تو پھر ہمارے پاس آ جانا ) ابوذر رضی اللہ عنہ نے عرض کیا اس ذات کی قسم! جس کے ہاتھ میں میری جان ہے، میں ان قریشیوں کے مجمع میں پکار کر کلمہ توحید کا اعلان کروں گا۔ چنانچہ آنحضرت صلی اللہ علیہ وسلم کے یہاں سے واپس وہ مسجدالحرام میں آئے اور بلند آواز سے کہا کہ ”میں گواہی دیتا ہوں کہ اللہ کے سوا کوئی معبود نہیں اور یہ کہ محمد اللہ کے رسول ہیں“ یہ سنتے ہی ان پر سارا مجمع ٹوٹ پڑا اور سب نے انہیں اتنا مارا کہ زمین پر لٹا دیا۔ اتنے میں عباس رضی اللہ عنہ آ گئے اور ابوذر رضی اللہ عنہ کے اوپر اپنے کو ڈال کر قریش سے انہوں نے کہا افسوس! کیا تمہیں معلوم نہیں کہ یہ شخص قبیلہ غفار سے ہے اور شام جانے والے تمہارے تاجروں کا راستہ ادھر ہی سے پڑتا ہے، اس طرح سے ان سے ان کو بچایا۔ پھر ابوذر رضی اللہ عنہ دوسرے دن مسجدالحرام میں آئے اور اپنے اسلام کا اظہار کیا۔ قوم پھر بری طرح ان پر ٹوٹ پڑی اور مارنے لگے۔ اس دن بھی عباس ان پر اوندھے پڑ گئے۔ کیا میں ابوذر رضی اللہ عنہ کے اسلام کا واقعہ تمہیں سناؤں؟ ہم نے عرض کیا ضرور سنائیے۔ انہوں نے بیان کیا کہ ابوذر رضی اللہ عنہ نے بتلایا۔ میرا تعلق قبیلہ غفار سے تھا۔ ہمارے یہاں یہ خبر پہنچی تھی کہ مکہ میں ایک شخص پیدا ہوئے ہیں جن کا دعویٰ ہے کہ وہ نبی ہیں ( پہلے تو ) میں نے اپنے بھائی سے کہا کہ اس شخص کے پاس مکہ جا، اس سے گفتگو کر اور پھر اس کے سارے حالات آ کر مجھے بتا۔ چنانچہ میرے بھائی خدمت نبوی میں حاضر ہوئے اور آنحضرت صلی اللہ علیہ وسلم سے ملاقات کی اور واپس آ گئے۔ میں نے پوچھا کہ کیا خبر لائے؟ انہوں نے کہا، اللہ کی قسم! میں نے ایسے شخص کو دیکھا ہے جو اچھے کاموں کے لیے کہتا ہے اور برے کاموں سے منع کرتا ہے۔ میں نے کہا کہ تمہاری باتوں سے تو میری تشفی نہیں ہوئی۔ اب میں نے توشے کا تھیلا اور چھڑی اٹھائی اور مکہ آ گیا۔ وہاں میں کسی کو پہچانتا نہیں تھا اور آپ کے متعلق کسی سے پوچھتے ہوئے بھی ڈر لگتا تھا۔ میں ( صرف ) زمزم کا پانی پی لیا کرتا تھا، اور مسجدالحرام میں ٹھہرا ہوا تھا۔ انہوں نے بیان کیا کہ ایک مرتبہ علی رضی اللہ عنہ میرے سامنے سے گزرے اور بولے معلوم ہوتا ہے کہ آپ اس شہر میں مسافر ہیں۔ انہوں نے بیان کیا کہ میں نے کہا: جی ہاں۔ بیان کیا کہ تو پھر میرے گھر چلو۔ پھر وہ مجھے اپنے گھر ساتھ لے گئے۔ بیان کیا کہ میں آپ کے ساتھ ساتھ گیا۔ نہ انہوں نے کوئی بات پوچھی اور نہ میں نے کچھ کہا۔ صبح ہوئی تو میں پھر مسجدالحرام میں آ گیا تاکہ آنحضرت صلی اللہ علیہ وسلم کے بارے میں کسی سے پوچھوں لیکن آپ کے بارے میں کوئی بتانے والا نہیں تھا۔ بیان کیا کہ پھر حضرت علی رضی اللہ عنہ میرے سامنے سے گزرے اور بولے کہ کیا ابھی تک آپ اپنے ٹھکانے کو نہیں پا سکے ہیں؟ بیان کیا، میں نے کہا کہ نہیں۔ انہوں نے کہا کہ اچھا پھر میرے ساتھ آئیے، انہوں نے بیان کیا کہ پھر حضرت علی رضی اللہ عنہ نے پوچھا۔ آپ کا مطلب کیا ہے۔ آپ اس شہر میں کیوں آئے؟ انہوں نے بیان کیا کہ میں نے کہا: آپ اگر ظاہر نہ کریں تو میں آپ کو اپنے معاملے کے بارے میں بتاؤں۔ انہوں نے کہا کہ میں ایسا ہی کروں گا۔ تب میں نے ان سے کہا۔ ہمیں معلوم ہوا ہے کہ یہاں کوئی شخص پیدا ہوئے ہیں جو نبوت کا دعویٰ کرتے ہیں۔ میں نے پہلے اپنے بھائی کو ان سے بات کرنے کے لیے بھیجا تھا۔ لیکن جب وہ واپس ہوئے تو انہوں نے مجھے کوئی تشفی بخش اطلاعات نہیں دیں۔ اس لیے میں اس ارادہ سے آیا ہوں کہ ان سے خود ملاقات کروں۔ علی رضی اللہ عنہ نے کہا کہ آپ نے اچھا راستہ پایا کہ مجھ سے مل گئے۔ میں انہیں کے پاس جا رہا ہوں۔ آپ میرے پیچھے پیچھے چلیں۔ جہاں میں داخل ہوں آپ بھی داخل ہو جائیں۔ اگر میں کسی ایسے آدمی کو دیکھوں گا جس سے آپ کے بارے میں مجھے خطرہ ہو گا تو میں کسی دیوار کے پاس کھڑا ہو جاؤں گا، گویا کہ میں اپنا جوتا ٹھیک کر رہا ہوں۔ اس وقت آپ آگے بڑھ جائیں چنانچہ وہ چلے اور میں بھی ان کے پیچھے ہو لیا اور آخر میں وہ ایک مکان کے اندر گئے اور میں بھی ان کے ساتھ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں اندر داخل ہو گیا۔ میں نے آنحضرت صلی اللہ علیہ وسلم سے عرض کیا کہ اسلام کے اصول و ارکان مجھے سمجھا دیجئیے۔ آپ نے میرے سامنے ان کی وضاحت فرمائی اور میں مسلمان ہو گیا۔ پھر آپ نے فرمایا: اے ابوذر! اس معاملے کو ابھی پوشیدہ رکھنا اور اپنے شہر کو چلے جانا۔ پھر جب تمہیں ہمارے غلبہ کا حال معلوم ہو جائے تب یہاں دوبارہ آنا۔ میں نے عرض کیا اس ذات کی قسم جس نے آپ کو حق کے ساتھ مبعوث کیا ہے میں تو ان سب کے سامنے اسلام کے کلمہ کا اعلان کروں گا۔ چنانچہ وہ مسجدالحرام میں آئے۔ قریش کے لوگ وہاں موجود تھے اور کہا، اے قریش کی جماعت! ( سنو ) میں گواہی دیتا ہوں کہ اللہ کے سوا کوئی معبود نہیں اور میں گواہی دیتا ہوں کہ محمد اس کے بندے اور اس کے رسول ہیں۔ ( صلی اللہ علیہ وسلم ) قریشیوں نے کہا کہ اس بددین کی خبر لو۔ چنانچہ وہ میری طرف لپکے اور مجھے اتنا مارا کہ میں مرنے کے قریب ہو گیا۔ اتنے میں حضرت عباس رضی اللہ عنہ آ گئے اور مجھ پر گر کر مجھے اپنے جسم سے چھپا لیا اور قریشیوں کی طرف متوجہ ہو کر انہوں کہا۔ ارے نادانو! قبیلہ غفار کے آدمی کو قتل کرتے ہو۔ غفار سے تو تمہاری تجارت بھی ہے اور تمہارے قافلے بھی اس طرف سے گزرتے ہیں۔ اس پر انہوں نے مجھے چھوڑ دیا۔ پھر جب دوسری صبح ہوئی تو پھر میں مسجدالحرام میں آیا اور جو کچھ میں نے کل پکارا تھا اسی کو پھر دہرایا۔ قریشیوں نے پھر کہا: پکڑو اس بددین کو۔ جو کچھ انہوں نے میرے ساتھ کل کیا تھا وہی آج بھی کیا۔ اتفاق سے پھر عباس بن عبدالمطلب آ گئے اور مجھ پر گر کر مجھے اپنے جسم سے انہوں نے چھپا لیا اور جیسا ا نہوں نے قریشیوں سے کل کہا تھا ویسا ہی آج بھی کہا۔ عبداللہ بن عباس رضی اللہ عنہما نے کہا کہ حضرت ابوذر رضی اللہ عنہ کے اسلام قبول کرنے کی ابتداء اس طرح سے ہوئی تھی۔' WHERE id = 3374;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، انہوں نے کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے ابوالزناد نے، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”تمہیں تعجب نہیں ہوتا کہ اللہ تعالیٰ مجھ سے قریش کی گالیوں اور لعنت ملامت کو کس طرح دور کرتا ہے۔ مجھے وہ «مذمم» کہہ کر برا کہتے، اس پر لعنت کرتے ہیں۔ حالانکہ میں تو محمد ہوں۔“' WHERE id = 3384;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، کہا ہم سے زبیر نے بیان کیا، کہا ہم سے اسماعیل بن ابی خالد نے بیان کیا اور ان سے ابوحجیفہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کو میں نے دیکھا تھا۔ حسن رضی اللہ عنہ میں آپ کی پوری شباہت موجود تھی۔' WHERE id = 3394;
UPDATE hadiths SET urdu = 'ہم سے ابوعلی حسن بن منصور نے بیان کیا، کہا ہم سے حجاج بن محمد الاعور نے مصیصہ (شہر میں) بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے حکم نے بیان کیا کہ میں نے ابوجحیفہ رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم دوپہر کے وقت سفر کے ارادہ سے نکلے۔ بطحاء نامی جگہ پر پہنچ کر آپ صلی اللہ علیہ وسلم نے وضو کیا اور ظہر کی نماز دو رکعت ( قصر ) پڑھی پھر عصر کی بھی دو رکعت ( قصر ) پڑھی۔ آپ صلی اللہ علیہ وسلم کے سامنے ایک چھوٹا سا نیزہ ( بطور سترہ ) گڑا ہوا تھا۔ عون نے اپنے والد سے اس روایت میں یہ زیادہ کیا ہے کہ ابوجحیفہ رضی اللہ عنہ نے کہا کہ اس نیزہ کے آگے سے آنے جانے والے آ جا رہے تھے۔ پھر صحابہ آپ کے پاس آ گئے اور آپ کے مبارک ہاتھوں کو تھام کر اپنے چہروں پر پھیرنے لگے۔ ابوجحیفہ رضی اللہ عنہ نے بیان کیا کہ میں نے بھی آپ صلی اللہ علیہ وسلم کے دست مبارک کو اپنے چہرے پر رکھا۔ اس وقت وہ برف سے بھی زیادہ ٹھنڈا اور مشک سے بھی زیادہ خوشبودار تھا۔' WHERE id = 3404;
UPDATE hadiths SET urdu = 'مجھ علی بن جعد نے بیان کیا، انہوں نے کہا کہ ہم کو شعبہ نے خبر دی، انہیں اعمش نے، انہیں ابوحازم نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے کبھی کسی کھانے میں عیب نہیں نکالا، اگر آپ کو مرغوب ہوتا تو کھاتے ورنہ چھوڑ دیتے۔' WHERE id = 3415;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن منیر نے بیان کیا، انہوں نے یزید بن ہارون سے سنا، کہا کہ مجھ کو حمید نے خبر دی اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نماز کا وقت ہو چکا تھا، مسجد نبوی سے جن کے گھر قریب تھے انہوں نے تو وضو کر لیا لیکن بہت سے لوگ باقی رہ گئے۔ اس کے بعد نبی کریم صلی اللہ علیہ وسلم کی خدمت میں پتھر کی بنی ہوئی ایک لگن لائی گئی۔ اس میں پانی تھا، آپ صلی اللہ علیہ وسلم نے اپنا ہاتھ اس پر رکھا لیکن اس کا منہ اتنا تنگ تھا کہ آپ صلی اللہ علیہ وسلم اس کے اندر اپنا ہاتھ پھیلا کر نہیں رکھ سکتے تھے، چنانچہ آپ نے انگلیاں ملا لیں اور لگن کے اندر ہاتھ کو ڈال دیا پھر ( اسی پانی سے ) جتنے لوگ باقی رہ گئے تھے سب نے وضو کیا۔ میں نے پوچھا کہ آپ حضرات کی تعداد کیا تھی؟ انس رضی اللہ عنہ نے بتایا کہ اسّی آدمی تھے۔' WHERE id = 3426;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا کہ مجھ سے میرے بھائی نے بیان کیا، ان سے سلیمان بن بلال نے، ان سے یحییٰ بن سعید نے بیان کیا، انہیں حفص بن عبیداللہ بن انس بن مالک نے خبر دی اور انہوں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ مسجد نبوی کی چھت کھجور کے تنوں پر بنائی گئی تھی۔ نبی کریم صلی اللہ علیہ وسلم جب خطبہ کے لیے تشریف لاتے تو آپ ان میں سے ایک تنے کے پاس کھڑے ہو جاتے لیکن جب آپ صلی اللہ علیہ وسلم کے لیے منبر بنا دیا گیا تو آپ صلی اللہ علیہ وسلم اس پر تشریف لائے۔ پھر ہم نے اس تنے سے اس طرح کی رونے کی آواز سنی جیسی بوقت ولادت اونٹنی کی آواز ہوتی ہے۔ آخر جب نبی کریم صلی اللہ علیہ وسلم نے اس کے قریب آ کر اس پر ہاتھ رکھا تو وہ چپ ہوا۔' WHERE id = 3436;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، ان سے سفیان بن عیینہ نے بیان کیا، ان سے زہری نے، ان سے عروہ بن زبیر نے اور ان سے اسامہ بن زید رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم ایک مرتبہ مدینہ کے ایک بلند ٹیلہ پر چڑھے اور فرمایا ”جو کچھ میں دیکھ رہا ہوں کیا تمہیں بھی نظر آ رہا ہے؟ میں فتنوں کو دیکھ رہا ہوں کہ تمہارے گھروں میں وہ اس طرح گر رہے ہیں جیسے بارش کی بوندیں گرا کرتیں ہیں۔“' WHERE id = 3447;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، کہا ہم سے عبدالرزاق نے بیان کیا، کہا ہم کو معمر نے خبر دی، انہیں ہمام نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”قیامت اس وقت تک قائم نہ ہو گی جب تک دو جماعتیں آپس میں جنگ نہ کر لیں۔ دونوں میں بڑی بھاری جنگ ہو گی۔ حالانکہ دونوں کا دعویٰ ایک ہی ہو گا اور قیامت اس وقت تک قائم نہ ہو گی جب تک تقریباً تیس جھوٹے دجال پیدا نہ ہو لیں۔ ان میں ہر ایک کا یہی گمان ہو گا کہ وہ اللہ کا نبی ہے۔“' WHERE id = 3458;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے عبدالملک بن عمیر نے اور ان سے جابر بن سمرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جب کسریٰ ہلاک ہوا تو اس کے بعد کوئی کسریٰ پیدا نہیں ہو گا اور جب قیصر ہلاک ہوا تو کوئی قیصر پھر پیدا نہیں ہو گا“ اور راوی نے ( پہلی حدیث کی طرح اس حدیث کو بھی بیان کیا اور ) کہا کہ آپ صلی اللہ علیہ وسلم نے فرمایا ”تم ان دونوں کے خزانے اللہ کے راستے میں خرچ کرو گے۔“' WHERE id = 3468;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو امام مالک بن انس نے خبر دی، انہیں نافع نے اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ یہود، رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور آپ کو بتایا کہ ان کے یہاں ایک مرد اور ایک عورت نے زنا کیا ہے۔ آپ صلی اللہ علیہ وسلم نے ان سے فرمایا کہ رجم کے بارے میں تورات میں کیا حکم ہے؟ وہ بولے یہ کہ ہم انہیں رسوا کریں اور انہیں کوڑے لگائے جائیں۔ اس پر عبداللہ بن سلام رضی اللہ عنہ نے کہا کہ تم لوگ جھوٹے ہو۔ تورات میں رجم کا حکم موجود ہے۔ تورات لاؤ۔ پھر یہودی تورات لائے اور اسے کھولا۔ لیکن رجم سے متعلق جو آیت تھی اسے ایک یہودی نے اپنے ہاتھ سے چھپا لیا اور اس سے پہلے اور اس کے بعد کی عبارت پڑھنے لگا۔ عبداللہ بن سلام رضی اللہ عنہ نے کہا کہ ذرا اپنا ہاتھ تو اٹھاؤ جب اس نے ہاتھ اٹھایا تو وہاں آیت رجم موجود تھی۔ اب وہ سب کہنے لگے کہ اے محمد! عبداللہ بن سلام نے سچ کہا۔ بیشک تورات میں رجم کی آیت موجود ہے۔ چنانچہ آپ صلی اللہ علیہ وسلم کے حکم سے ان دونوں کو رجم کیا گیا۔ عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ میں نے رجم کے وقت دیکھا۔ یہودی مرد اس عورت پر جھکا پڑتا تھا۔ اس کو پتھروں کی مار سے بچاتا تھا۔' WHERE id = 3481;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، کہا ہم سے ایوب سختیانی نے بیان کیا، ان سے محمد بن سیرین نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم خیبر میں صبح سویرے ہی پہنچ گئے۔ خیبر کے یہودی اس وقت اپنے پھاوڑے لے کر ( کھیتوں میں کام کرنے کے لیے ) جا رہے تھے کہ انہوں نے آپ صلی اللہ علیہ وسلم کو دیکھا اور یہ کہتے ہوئے کہ محمد لشکر لے کر آ گئے، وہ قلعہ کی طرف بھاگے۔ اس کے بعد آپ صلی اللہ علیہ وسلم نے اپنے ہاتھ اٹھا کر فرمایا ”اللہ اکبر خیبر تو برباد ہوا کہ جب ہم کسی قوم کے میدان میں ( جنگ کے لیے ) اتر جاتے ہیں تو پھر ڈرائے ہوئے لوگوں کی صبح بری ہو جاتی ہے۔“' WHERE id = 3492;
UPDATE hadiths SET urdu = 'ہم سے معلیٰ بن اسد اور موسیٰ نے بیان کیا، کہا کہ ہم سے وہیب نے بیان کیا، ان سے ایوب نے ( یہی روایت ) کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر میں کسی کو جانی دوست بنا سکتا تو ابوبکر کو بناتا۔ لیکن اسلام کا بھائی چارہ کیا کم ہے۔ ہم سے قتیبہ نے بیان کیا، ان سے عبدالوہاب نے اور ان سے ایوب نے ایسی ہی حدیث بیان کی۔' WHERE id = 3502;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، کہا ہم کو سفیان ثوری نے خبر دی، کہا ہم سے جامع بن ابی راشد نے بیان کیا، کہا ہم سے ابویعلیٰ نے بیان کیا، ان سے محمد بن حنفیہ نے بیان کیا کہ میں نے اپنے والد ( علی رضی اللہ عنہ ) سے پوچھا کہ رسول اللہ صلی اللہ علیہ وسلم کے بعد سب سے افضل صحابی کون ہیں؟ انہوں نے بتلایا کہ ابوبکر رضی اللہ عنہ میں نے پوچھا پھر کون ہیں؟ انہوں نے بتلایا، اس کے بعد عمر رضی اللہ عنہ ہیں۔ مجھے اس کا اندیشہ ہوا کہ اب ( پھر میں نے پوچھا کہ اس کے بعد؟ ) کہہ دیں گے کہ عثمان رضی اللہ عنہ اس لیے میں نے خود کہا، اس کے بعد آپ ہیں؟ یہ سن کر وہ بولے کہ میں تو صرف عام مسلمانوں کی جماعت کا ایک شخص ہوں۔' WHERE id = 3514;
UPDATE hadiths SET urdu = 'مجھ سے ابوجعفر محمد بن صلت کوفی نے بیان کیا، انہوں نے کہا ہم سے عبداللہ بن مبارک نے بیان کیا، ان سے یونس نے، ان سے زہری نے بیان کیا، کہا مجھ کو حمزہ نے خبر دی اور انہیں ان کے والد (عبداللہ بن عمر رضی اللہ عنہما) نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ میں نے خواب میں دودھ پیا، اتنا کہ میں دودھ کی سیرابی دیکھنے لگا جو میرے ناخن یا ناخنوں پر بہ رہی ہے، پھر میں نے پیالہ عمر کو دے دیا۔ صحابہ نے پوچھا: یا رسول اللہ! اس خواب کی تعبیر کیا ہے آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس کی تعبیر علم ہے۔' WHERE id = 3524;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے بیان کیا، مجھ کو ابوامامہ بن سہل بن حنیف نے خبر دی اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا: آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں نے خواب میں دیکھا کہ کچھ لوگ میرے سامنے پیش کئے گئے جو قمیص پہنے ہوئے تھے ان میں سے بعض کی قمیص صرف سینے تک تھی اور بعض کی اس سے بھی چھوٹی اور میرے سامنے عمر پیش کئے گئے تو وہ اتنی بڑی قمیص پہنے ہوئے تھے کہ چلتے ہوئے گھسٹتی تھی۔ صحابہ نے عرض کیا: یا رسول اللہ! آپ نے اس کی تعبیر کیا لی؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ دین مراد ہے۔' WHERE id = 3534;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے عبدالعزیز نے بیان کیا، ان سے ابوحازم نے اور ان سے سہل بن سعد رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے جنگ خیبر کے موقع پر بیان فرمایا کہ کل میں ایک ایسے شخص کو اسلامی عَلم دوں گا جس کے ہاتھ پر اللہ تعالیٰ فتح عنایت فرمائے گا، راوی نے بیان کیا کہ رات کو لوگ یہ سوچتے رہے کہ دیکھئیے عَلم کسے ملتا ہے، جب صبح ہوئی تو آپ صلی اللہ علیہ وسلم کی خدمت میں سب حضرات ( جو سرکردہ تھے ) حاضر ہوئے، سب کو امید تھی کہ عَلم انہیں ہی ملے گا، لیکن آپ صلی اللہ علیہ وسلم نے دریافت فرمایا، علی بن ابی طالب کہاں ہیں؟ لوگوں نے بتایا کہ ان کی آنکھوں میں درد ہے، آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر ان کے یہاں کسی کو بھیج کر بلوا لو، جب وہ آئے تو آپ صلی اللہ علیہ وسلم نے ان کی آنکھ میں اپنا تھوک ڈالا اور ان کے لیے دعا فرمائی، اس سے انہیں ایسی شفاء حاصل ہوئی جیسے کوئی مرض پہلے تھا ہی نہیں، چنانچہ آپ نے عَلم انہیں کو عنایت فرمایا۔ علی رضی اللہ عنہ نے عرض کیا: یا رسول اللہ! میں ان سے اتنا لڑوں گا کہ وہ ہمارے جیسے ہو جائیں ( یعنی مسلمان بن جائیں ) آپ نے فرمایا: ابھی یوں ہی چلتے رہو، جب ان کے میدان میں اترو تو پہلے انہیں اسلام کی دعوت دو اور انہیں بتاؤ کہ اللہ کے ان پر کیا حقوق واجب ہیں، اللہ کی قسم اگر تمہارے ذریعہ اللہ تعالیٰ ایک شخص کو بھی ہدایت دیدے تو وہ تمہارے لیے سرخ اونٹوں ( کی دولت ) سے بہتر ہے۔' WHERE id = 3544;
UPDATE hadiths SET urdu = 'مجھے عبداللہ بن عبدالوہاب نے خبر دی، کہا کہ ہم سے خالد نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے واقد نے بیان کیا کہ میں نے اپنے والد سے سنا، وہ ابن عمر رضی اللہ عنہما سے بیان کرتے تھے، وہ ابوبکر رضی اللہ عنہ سے کہ انہوں نے کہا: نبی کریم صلی اللہ علیہ وسلم کا خیال آپ کے اہل بیت میں رکھو۔' WHERE id = 3555;
UPDATE hadiths SET urdu = 'ہم سے مکی بن ابراہیم نے بیان کیا، کہا ہم سے ہاشم بن ہاشم نے بیان کیا، ان سے عامر بن سعد نے اور ان سے ان کے والد (سعد بن ابی وقاص رضی اللہ عنہ) نے بیان کیا کہ مجھے خوب یاد ہے۔ میں نے ایک زمانے میں مسلمانوں کا تیسرا حصہ اپنے آپ کو دیکھا۔ امام بخاری رحمہ اللہ نے کہا اسلام کے تیسرے حصے سے یہ مراد ہے کہ رسول اللہ صلی اللہ علیہ وسلم کے ساتھ صرف تین مسلمان تھے جن میں تیسرا مسلمان میں تھا۔' WHERE id = 3566;
UPDATE hadiths SET urdu = 'اور نعیم نے کہا ان سے ابن مبارک نے بیان کیا، انہیں معمر نے خبر دی، انہیں زہری نے، انہیں اسامہ بن زید رضی اللہ عنہما کے ایک مولیٰ (حرملہ) نے خبر دی کہ حجاج بن ایمن بن ام ایمن کو عبداللہ بن عمر رضی اللہ عنہما نے دیکھا ( نماز میں ) انہوں نے رکوع اور سجدہ پوری طرح نہیں ادا کیا، ( ایمن ابن ام ایمن، اسامہ رضی اللہ عنہ کی ماں کی طرف سے بھائی تھے، ایمن رضی اللہ عنہ قبیلہ انصار کے ایک فرد تھے ) تو ابن عمر رضی اللہ عنہما نے ان سے کہا کہ ( نماز ) دوبارہ پڑھ لو۔' WHERE id = 3576;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہم کو عبداللہ نے خبر دی، کہا کہ مجھے عمر بن سعید بن ابی حسین نے خبر دی، انہیں ابن ابی ملیکہ نے، ان سے عقبہ بن حارث نے بیان کیا کہ میں نے ابوبکر رضی اللہ عنہ کو دیکھا کہ آپ حسن رضی اللہ عنہ کو اٹھائے ہوئے ہیں اور فرما رہے ہیں: میرے باپ ان پر فدا ہوں، یہ نبی کریم صلی اللہ علیہ وسلم سے مشابہ ہیں، علی سے نہیں اور علی رضی اللہ عنہ مسکرا رہے تھے۔' WHERE id = 3588;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے ابواسحٰق نے، ان سے عبدالرحمٰن بن زید نے بیان کیا کہ ہم نے حذیفہ رضی اللہ عنہ سے پوچھا کہ صحابہ میں نبی کریم صلی اللہ علیہ وسلم سے عادات و اخلاق اور طور طریق میں سب سے زیادہ قریب کون سے صحابی تھے؟ تاکہ ہم ان سے سیکھیں، انہوں نے کہا اخلاق، طور طریق اور سیرت و عادت میں ابن ام عبد سے زیادہ آپ صلی اللہ علیہ وسلم سے قریب اور کسی کو میں نہیں سمجھتا۔' WHERE id = 3600;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، ان سے شعبہ نے بیان کیا، ان سے حکم نے اور انہوں نے ابووائل سے سنا، انہوں نے بیان کیا کہ جب علی رضی اللہ عنہ نے عمار اور حسن رضی اللہ عنہما کو کوفہ بھیجا تھا تاکہ لوگوں کو اپنی مدد کے لیے تیار کریں تو عمار رضی اللہ عنہ نے ان سے خطاب کرتے ہوئے فرمایا تھا: مجھے بھی خوب معلوم ہے کہ عائشہ رضی اللہ عنہا رسول اللہ صلی اللہ علیہ وسلم کی زوجہ ہیں اس دنیا میں بھی اور آخرت میں بھی، لیکن اللہ تعالیٰ تمہیں آزمانا چاہتا ہے کہ دیکھے تم علی رضی اللہ عنہ کی اتباع کرتے ہو ( جو برحق خلیفہ ہیں ) یا عائشہ رضی اللہ عنہا کی۔' WHERE id = 3610;
UPDATE hadiths SET urdu = 'ہم سے ابوہمام صلت بن محمد نے بیان کیا کہا میں نے مغیرہ بن عبدالرحمٰن سے سنا، کہا ہم سے ابوالزناد نے بیان کیا، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ انصار نے کہا: یا رسول اللہ! کھجور کے باغات ہمارے اور مہاجرین کے درمیان تقسیم فرما دیں، آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں ایسا نہیں کروں گا اس پر انصار نے ( مہاجرین سے ) کہا پھر آپ ایسا کر لیں کہ کام ہماری طرف سے آپ انجام دیا کریں اور کھجوروں میں آپ ہمارے ساتھی ہو جائیں۔ مہاجرین نے کہا ہم نے آپ لوگوں کی یہ بات سنی اور ہم ایسا ہی کریں گے۔' WHERE id = 3620;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، کہا ہم سے شعبہ نے کہا کہ میں نے قتادہ سے سنا، انہوں نے انس بن مالک رضی اللہ عنہ سے اور انہوں نے اسید بن حضیر رضی اللہ عنہ سے کہ ایک انصاری صحابی نے عرض کیا: یا رسول اللہ! فلاں شخص کی طرح مجھے بھی آپ حاکم بنا دیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا ”میرے بعد ( دنیاوی معاملات میں ) تم پر دوسروں کو ترجیح دی جائے گی اس لیے صبر سے کام لینا، یہاں تک کہ مجھ سے حوض پر آ ملو۔“' WHERE id = 3630;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا کہا مجھ سے شعبہ نے بیان کیا، ان سے ابواسحٰق نے کہا کہ میں نے براء بن عازب رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے پاس ہدیہ میں ایک ریشمی حلہ آیا تو صحابہ اسے چھونے لگے اور اس کی نرمی اور نزاکت پر تعجب کرنے لگے، آپ صلی اللہ علیہ وسلم نے اس پر فرمایا کہ تمہیں اس کی نرمی پر تعجب ہے، سعد بن معاذ رضی اللہ عنہ کے رومال ( جنت میں ) اس سے کہیں بہتر ہیں یا ( آپ صلی اللہ علیہ وسلم نے فرمایا کہ ) اس سے کہیں زیادہ نرم و نازک ہیں، اس حدیث کی روایت قتادہ اور زہری نے بھی کی ہے، انہوں نے انس رضی اللہ عنہ سے سنا، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے روایت کیا ہے۔' WHERE id = 3640;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا کہ میں نے امام مالک سے سنا، وہ عمر بن عبیداللہ کے مولیٰ ابونضر کے واسطے سے بیان کرتے ہیں، وہ عامر بن سعد بن ابی وقاص سے اور ان سے ان کے والد (سعد بن ابی وقاص رضی اللہ عنہ) نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے عبداللہ بن سلام رضی اللہ عنہ کے سوا اور کسی کے متعلق یہ نہیں سنا کہ وہ اہل جنت میں سے ہیں، بیان کیا کہ آیت «وشهد شاهد من بني إسرائيل‏» ( سورۃ الاحقاف: 10 ) انہیں کے بارے میں نازل ہوئی تھی ( راوی حدیث عبداللہ بن یوسف نے ) بیان کیا کہ آیت کے نزول کے متعلق مالک کا قول ہے یا حدیث میں اسی طرح تھا۔' WHERE id = 3650;
UPDATE hadiths SET urdu = 'ہم سے اسحاق واسطی نے بیان کیا کہا، ہم سے خالد نے بیان کیا، ان سے بیان نے کہ میں نے قیس سے سنا، انہوں نے بیان کیا کہ جریر بن عبداللہ رضی اللہ عنہ نے فرمایا جب سے میں اسلام میں داخل ہوا رسول اللہ صلی اللہ علیہ وسلم نے مجھے ( گھر کے اندر آنے سے ) نہیں روکا ( جب بھی میں نے اجازت چاہی ) اور جب بھی آپ صلی اللہ علیہ وسلم مجھے دیکھتے تو مسکراتے۔' WHERE id = 3660;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے وہیب نے بیان کیا، کہا ہم سے عبداللہ بن طاؤس نے بیان کیا، ان سے ان کے والد نے اور ان سے عباس رضی اللہ عنہما نے بیان کیا کہ زمانہ جاہلیت میں لوگ حج کے مہینوں میں عمرہ کرنا بہت بڑا گناہ خیال کرتے تھے۔ وہ محرم کو صفر کہتے۔ ان کے ہاں یہ مثل تھی کہ اونٹ کی پیٹھ کا زخم جب اچھا ہونے لگے اور ( حاجیوں کے ) نشانات قدم مٹ چکیں تو اب عمرہ کرنے والوں کا عمرہ جائز ہوا۔ ابن عباس رضی اللہ عنہما نے بیان کیا کہ پھر رسول اللہ صلی اللہ علیہ وسلم اپنے اصحاب کے ساتھ ذی الحجہ کی چوتھی تاریخ کو حج کا احرام باندھے ہوئے ( مکہ ) تشریف لائے تو آپ نے صحابہ کو حکم دیا کہ اپنے حج کو عمرہ کر ڈالیں ( طواف اور سعی کر کے احرام کھول دیں ) ۔ صحابہ نے عرض کیا: یا رسول اللہ! ( اس عمرہ اور حج کے دوران میں ) کیا چیزیں حلال ہوں گی؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ تمام چیزیں! جو احرام کے نہ ہونے کی حالت میں حلال تھیں وہ سب حلال ہو جائیں گی۔' WHERE id = 3670;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا مجھ سے میرے بھائی نے بیان کیا، ان سے سلیمان نے، ان سے یحییٰ بن سعید نے، ان سے عبدالرحمٰن بن قاسم نے، ان سے قاسم بن محمد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ ابوبکر رضی اللہ عنہ کا ایک غلام تھا جو روزانہ انہیں کچھ کمائی دیا کرتا تھا اور ابوبکر رضی اللہ عنہ اسے اپنی ضرورت میں استعمال کیا کرتے تھے۔ ایک دن وہ غلام کوئی چیز لایا اور ابوبکر رضی اللہ عنہ نے بھی اس میں سے کھا لیا۔ پھر غلام نے کہا آپ کو معلوم ہے؟ یہ کیسی کمائی سے ہے؟ آپ نے دریافت فرمایا کیسی ہے؟ اس نے کہا میں نے زمانہ جاہلیت میں ایک شخص کے لیے کہانت کی تھی حالانکہ مجھے کہانت نہیں آتی تھی، میں نے اسے صرف دھوکہ دیا تھا لیکن اتفاق سے وہ مجھے مل گیا اور اس نے اس کی اجرت میں مجھ کو یہ چیز دی تھی، آپ کھا بھی چکے ہیں۔ ابوبکر رضی اللہ عنہ نے یہ سنتے ہی اپنا ہاتھ منہ میں ڈالا اور پیٹ کی تمام چیزیں قے کر کے نکال ڈالیں۔' WHERE id = 3680;
UPDATE hadiths SET urdu = 'ہم سے حمیدی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، کہا ہم سے بیان بن بشر اور اسماعیل بن ابوخالد نے بیان کیا، کہا کہ ہم نے قیس بن ابوحازم سے سنا وہ بیان کرتے تھے کہ میں نے خباب بن ارت سے سنا، انہوں نے بیان کیا کہ میں رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا تو آپ صلی اللہ علیہ وسلم کعبہ کے سائے تلے چادر پر ٹیک لگائے بیٹھے تھے۔ ہم لوگ مشرکین سے انتہائی تکالیف اٹھا رہے تھے۔ میں نے عرض کیا: یا رسول اللہ! اللہ تعالیٰ سے آپ دعا کیوں نہیں فرماتے؟ اس پر آپ صلی اللہ علیہ وسلم سیدھے بیٹھ گئے۔ چہرہ مبارک غصہ سے سرخ ہو گیا اور فرمایا تم سے پہلے ایسے لوگ گزر چکے ہیں کہ لوہے کے کنگھوں کو ان کے گوشت اور پٹھوں سے گزار کر ان کی ہڈیوں تک پہنچا دیا گیا اور یہ معاملہ بھی انہیں ان کے دین سے نہ پھیر سکا، کسی کے سر پر آرا رکھ کر اس کے دو ٹکڑے کر دئیے گئے اور یہ بھی انہیں ان کے دین سے نہ پھیر سکا، اس دین اسلام کو تو اللہ تعالیٰ خود ہی ایک دن تمام و کمال تک پہنچائے گا کہ ایک سوار صنعاء سے حضر موت تک ( تنہا ) جائے گا اور ( راستے ) میں اسے اللہ کے سوا اور کسی کا خوف تک نہ ہو گا۔ بیان نے اپنی روایت میں یہ زیادہ کیا کہ ”سوائے بھیڑیئے کے کہ اس سے اپنی بکریوں کے معاملہ میں اسے ڈر ہو گا۔“' WHERE id = 3690;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے اسماعیل نے، ان سے قیس نے بیان کیا کہ میں نے کوفہ کی مسجد میں سعید بن زید بن عمرو بن نفیل رضی اللہ عنہ سے سنا، وہ کہہ رہے تھے کہ ایک وقت تھا جب عمر رضی اللہ عنہ نے اسلام لانے سے پہلے مجھے اس وجہ سے باندھ رکھا تھا کہ میں نے اسلام کیوں قبول کیا لیکن تم لوگوں نے عثمان رضی اللہ عنہ کے ساتھ جو کچھ کیا ہے اس کی وجہ سے اگر احد پہاڑ بھی اپنی جگہ سے سرک جائے تو اسے ایسا کرنا ہی چاہئے۔' WHERE id = 3700;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد جعفی نے بیان کیا، کہا ہم سے ہشام بن یوسف نے بیان کیا، انہیں معمر نے خبر دی، انہیں زہری نے کہا کہ ہم سے عروہ بن زبیر نے بیان کیا، انہیں عبیداللہ بن عدی بن خیار نے خبر دی، انہیں مسور بن مخرمہ اور عبدالرحمٰن بن اسود بن عبدیغوث ان دونوں نے عبیداللہ بن عدی بن خیار سے کہا کہ تم اپنے ماموں ( امیرالمؤمنین ) عثمان رضی اللہ عنہ سے ان کے بھائی ولید بن عقبہ بن ابی معیط کے باب میں گفتگو کیوں نہیں کرتے ( ہوا یہ تھا کہ لوگوں نے اس پر بہت اعتراض کیا تھا جو عثمان نے ولید کے ساتھ کیا تھا ) ۔ عبیداللہ نے بیان کیا کہ جب عثمان رضی اللہ عنہ نماز پڑھنے نکلے تو میں ان کے راستے میں کھڑا ہو گیا اور میں نے عرض کیا کہ مجھے آپ سے ایک ضرورت ہے، آپ کو ایک خیر خواہانہ مشورہ دینا ہے۔ اس پر انہوں نے کہا کہ بھلے آدمی! تم سے تو میں اللہ کی پناہ مانگتا ہوں۔ یہ سن کر میں وہاں سے واپس چلا آیا۔ نماز سے فارغ ہونے کے بعد میں مسور بن مخرمہ اور ابن عبدیغوث کی خدمت میں حاضر ہوا اور عثمان رضی اللہ عنہ سے جو کچھ میں نے کہا تھا اور انہوں نے اس کا جواب مجھے جو دیا تھا، سب میں نے بیان کر دیا۔ ان لوگوں نے کہا تم نے اپنا حق ادا کر دیا۔ ابھی میں اس مجلس میں بیٹھا تھا کہ عثمان رضی اللہ عنہ کا آدمی میرے پاس ( بلانے کے لیے ) آیا۔ ان لوگوں نے مجھ سے کہا تمہیں اللہ تعالیٰ نے امتحان میں ڈالا ہے۔ آخر میں وہاں سے چلا اور عثمان رضی اللہ عنہ کی خدمت میں حاضر ہوا۔ آپ نے دریافت کیا تم ابھی جس خیر خواہی کا ذکر کر رہے تھے وہ کیا تھی؟ انہوں نے بیان کیا کہ پھر میں نے کہا اللہ گواہ ہے پھر میں نے کہا اللہ تعالیٰ نے محمد صلی اللہ علیہ وسلم کو مبعوث فرمایا اور ان پر اپنی کتاب نازل فرمائی، آپ ان لوگوں میں سے تھے جنہوں نے نبی کریم صلی اللہ علیہ وسلم کی دعوت پر لبیک کہا تھا۔ آپ نبی کریم صلی اللہ علیہ وسلم پر ایمان لائے دو ہجرتیں کیں ( ایک حبشہ کو اور دوسری مدینہ کو ) آپ رسول اللہ صلی اللہ علیہ وسلم کی صحبت سے فیض یاب ہیں اور نبی کریم صلی اللہ علیہ وسلم کے طریقوں کو دیکھا ہے۔ بات یہ ہے کہ ولید بن عقبہ کے بارے میں لوگوں میں اب بہت چرچا ہونے لگا ہے۔ اس لیے آپ کے لیے ضروری ہے کہ اس پر ( شراب نوشی کی ) حد قائم کریں۔ عثمان رضی اللہ عنہ نے فرمایا میرے بھتیجے یا میرے بھانجے کیا تم نے بھی رسول اللہ صلی اللہ علیہ وسلم کو دیکھا ہے؟ میں نے عرض کیا کہ نہیں۔ لیکن آپ صلی اللہ علیہ وسلم کے دین کی باتیں اس طرح میں نے حاصل کی تھیں جو ایک کنواری لڑکی کو بھی اپنے پردے میں معلوم ہو چکی ہیں۔ انہوں نے بیان کیا کہ یہ سن کر پھر عثمان رضی اللہ عنہ نے بھی اللہ کو گواہ کر کے فرمایا: بلاشبہ اللہ تعالیٰ نے محمد صلی اللہ علیہ وسلم کو حق کے ساتھ مبعوث کیا اور آپ پر اپنی کتاب نازل کی تھی اور یہ بھی ٹھیک ہے کہ میں ان لوگوں میں سے تھا جنہوں نے اللہ اور اس کے رسول کی دعوت پر ( ابتداء ہی میں ) لبیک کہا تھا۔ نبی کریم صلی اللہ علیہ وسلم جو شریعت لے کر آئے تھے میں اس پر ایمان لایا اور جیسا کہ تم نے کہا میں نے دو ہجرتیں کیں۔ میں نبی کریم صلی اللہ علیہ وسلم کی صحبت سے فیض یاب ہوا اور آپ صلی اللہ علیہ وسلم سے بیعت بھی کی۔ اللہ کی قسم! میں نے آپ کی نافرمانی نہیں کی اور نہ کبھی خیانت کی۔ آخر اللہ تعالیٰ نے آپ صلی اللہ علیہ وسلم کو وفات دے دی اور ابوبکر رضی اللہ عنہ خلیفہ منتحب ہوئے۔ اللہ کی قسم! میں نے ان کی بھی کبھی نافرمانی نہیں کی اور نہ ان کے کسی معاملہ میں کوئی خیانت کی۔ ان کے بعد عمر رضی اللہ عنہ خلیفہ ہوئے میں نے ان کی بھی کبھی نافرمانی نہیں کی اور نہ کبھی خیانت کی۔ اس کے بعد میں خلیفہ ہوا۔ کیا اب میرا تم لوگوں پر وہی حق نہیں ہے جو ان کا مجھ پر تھا؟ عبیداللہ نے عرض کیا یقیناً آپ کا حق ہے پھر انہوں نے کہا پھر ان باتوں کی کیا حقیقت ہے جو تم لوگوں کی طرف سے پہنچ رہی ہیں؟ جہاں تک تم نے ولید بن عقبہ کے بارے میں ذکر کیا ہے تو ہم ان شاءاللہ اس معاملے میں اس کی گرفت حق کے ساتھ کریں گے۔ راوی نے بیان کیا کہ آخر ( گواہی کے بعد ) ولید بن عقبہ کو چالیس کوڑے لگوائے گئے اور علی رضی اللہ عنہ کو حکم دیا کہ کوڑے لگائیں۔ علی رضی اللہ عنہ ہی نے اس کو کوڑے مارے تھے۔ اس حدیث کو یونس اور زہری کے بھتیجے نے بھی زہری سے روایت کیا اس میں عثمان رضی اللہ عنہ کا قول اس طرح بیان کیا، کیا تم لوگوں پر میرا وہی حق نہیں ہے جو ان لوگوں کا تم پر تھا۔' WHERE id = 3710;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ اویسی نے بیان کیا، انہوں نے کہا مجھ سے ابراہیم بن سعد نے بیان کیا، انہوں نے کہا کہ ہم سے ابن شہاب نے بیان کیا، ان سے سلمہ بن عبدالرحمٰن نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے جنگ حنین کا قصد کیا تو فرمایا ”ان شاءاللہ کل ہمارا قیام خیف بنی کنانہ میں ہو گا۔“ جہاں مشرکین نے کافر ہی رہنے کے لیے عہد و پیمان کیا تھا۔' WHERE id = 3720;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن منصور نے بیان کیا، انہوں نے کہا ہم کو یعقوب بن ابراہیم نے خبر دی، انہوں نے کہا ہم سے ہمارے بھتیجے ابن شہاب نے بیان کیا، ان سے ان کے چچا نے بیان کیا اور انہوں نے کہا کہ ہمیں ابوادریس عائذ اللہ بن عبداللہ نے خبر دی کہ عبادہ بن صامت رضی اللہ عنہ ان صحابہ میں سے تھے جنہوں نے رسول اللہ صلی اللہ علیہ وسلم کے ساتھ بدر کی لڑائی میں شرکت کی تھی اور عقبہ کی رات نبی کریم صلی اللہ علیہ وسلم سے عہد کیا تھا۔ انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا اس وقت آپ کے پاس صحابہ کی ایک جماعت تھی، کہ آؤ مجھ سے اس بات کا عہد کرو کہ اللہ کے ساتھ کسی کو شریک نہ ٹھہراؤ گے، چوری نہ کرو گے، زنا نہ کرو گے، اپنی اولاد کو قتل نہ کرو گے، اپنی طرف سے گھڑ کر کسی پر تہمت نہ لگاؤ گے اور اچھی باتوں میں میری نافرمانی نہ کرو گے، پس جو شخص اپنے اس عہد پر قائم رہے گا اس کا اجر اللہ کے ذمہ ہے اور جس شخص نے اس میں کمی کی اور اللہ تعالیٰ نے اسے چھپا رہنے دیا تو اس کا معاملہ اللہ کے اختیار میں ہے، چاہے تو اس پر سزا دے اور چاہے معاف کر دے۔ عبادہ رضی اللہ عنہ نے بیان کیا چنانچہ میں نے نبی کریم صلی اللہ علیہ وسلم سے ان امور پر بیعت کی۔' WHERE id = 3730;
UPDATE hadiths SET urdu = 'ہم سے مطر بن فضل نے بیان کیا، کہا ہم سے روح نے بیان کیا، ان سے ہشام نے بیان کیا، ان سے عکرمہ نے بیان کیا اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کو چالیس سال کی عمر میں رسول بنایا گیا تھا۔ پھر آپ صلی اللہ علیہ وسلم پر مکہ مکرمہ میں تیرہ سال تک وحی آتی رہی اس کے بعد آپ کو ہجرت کا حکم ہوا اور آپ نے ہجرت کی حالت میں دس سال گزارے۔ ( مدینہ میں ) جب آپ کی وفات ہوئی تو آپ کی عمر تریسٹھ سال کی تھی۔' WHERE id = 3740;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا ہم کو ہشام نے خبر دی، ان سے ابن جریج نے بیان کیا، کہا کہ مجھے عبیداللہ بن عمر نے خبر دی، انہیں نافع نے یعنی ابن عمر رضی اللہ عنہما سے اور وہ عمر بن خطاب رضی اللہ عنہ سے، فرمایا آپ نے تمام مہاجرین اولین کا وظیفہ ( اپنے عہد خلافت میں ) چار چار ہزار چار چار قسطوں میں مقرر کر دیا تھا، لیکن عبداللہ بن عمر رضی اللہ عنہما کا وظیفہ چار قسطوں میں ساڑھے تین ہزار تھا اس پر ان سے پوچھا گیا کہ عبداللہ بن عمر رضی اللہ عنہما بھی مہاجرین میں سے ہیں۔ پھر آپ انہیں چار ہزار سے کم کیوں دیتے ہیں؟ تو عمر رضی اللہ عنہ نے کہا کہ انہیں ان کے والدین ہجرت کر کے یہاں لائے تھے۔ اس لیے وہ ان مہاجرین کے برابر نہیں ہو سکتے جنہوں نے خود ہجرت کی تھی۔' WHERE id = 3750;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ہمام نے بیان کیا، ان سے ثابت نے، ان سے انس رضی اللہ عنہ نے اور ان سے ابوبکر رضی اللہ عنہ نے بیان کیا کہ میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ غار میں تھا۔ میں نے جو سر اٹھایا تو قوم کے چند لوگوں کے قدم ( باہر ) نظر آئے میں نے کہا، اے اللہ کے نبی! اگر ان میں سے کسی نے بھی نیچے جھک کر دیکھ لیا تو وہ ہمیں ضرور دیکھ لے گا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”ابوبکر! خاموش رہو ہم ایسے دو ہیں جن کا تیسرا اللہ ہے۔“' WHERE id = 3760;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے عبدالوارث نے بیان کیا (دوسری سند) اور ہم سے اسحاق بن منصور نے بیان کیا، کہا ہم کو عبدالصمد نے خبر دی، کہا کہ میں نے اپنے والد عبدالوارث سے سنا، انہوں نے بیان کیا کہ ہم سے ابوالتیاح یزید بن حمید ضبعی نے بیان کیا، کہا کہ مجھ سے انس بن مالک رضی اللہ عنہ نے بیان کیا، انہوں نے کہا کہ جب نبی کریم صلی اللہ علیہ وسلم مدینہ تشریف لائے تو مدینہ کے بلند جانب قباء کے ایک محلہ میں آپ نے ( سب سے پہلے ) قیام کیا جسے بنی عمرو بن عوف کا محلہ کہا جاتا تھا۔ راوی نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے وہاں چودہ رات قیام کیا پھر آپ نے قبیلہ بنی النجار کے لوگوں کو بلا بھیجا۔ انہوں نے بیان کیا کہ انصار بنی النجار آپ کی خدمت میں تلواریں لٹکائے ہوئے حاضر ہوئے۔ راوی نے بیان کیا گویا اس وقت بھی وہ منظر میری نظروں کے سامنے ہے کہ نبی کریم صلی اللہ علیہ وسلم اپنی سواری پر سوار ہیں۔ ابوبکر صدیق رضی اللہ عنہ اسی سواری پر آپ کے پیچھے سوار ہیں اور بنی النجار کے انصار آپ کے چاروں طرف حلقہ بنائے ہوئے مسلح پیدل چلے جا رہے ہیں۔ آخر آپ ابوایوب انصاری کے گھر کے قریب اتر گئے۔ راوی نے بیان کیا کہ ابھی تک جہاں بھی نماز کا وقت ہو جاتا وہیں آپ نماز پڑھ لیتے تھے۔ بکریوں کے ریوڑ جہاں رات کو باندھے جاتے وہاں بھی نماز پڑھ لی جاتی تھی۔ بیان کیا کہ پھر آپ صلی اللہ علیہ وسلم نے مسجد کی تعمیر کا حکم فرمایا۔ آپ نے اس کے لیے قبیلہ بنی النجار کے لوگوں کو بلا بھیجا۔ وہ حاضر ہوئے تو آپ صلی اللہ علیہ وسلم نے فرمایا ”اے بنو النجار! اپنے اس باغ کی قیمت طے کر لو۔“ انہوں نے عرض کیا نہیں اللہ کی قسم ہم اس کی قیمت اللہ کے سوا اور کسی سے نہیں لے سکتے۔ راوی نے بیان کیا کہ اس باغ میں وہ چیزیں تھیں جو میں تم سے بیان کروں گا۔ اس میں مشرکین کی قبریں تھیں، کچھ اس میں کھنڈر تھا اور کھجوروں کے درخت بھی تھے۔ نبی کریم صلی اللہ علیہ وسلم کے حکم سے مشرکین کی قبریں اکھاڑ دی گئیں، جہاں کھنڈر تھا اسے برابر کیا گیا اور کھجوروں کے درخت کاٹ دیئے گئے۔ راوی نے بیان کیا کہ کھجور کے تنے مسجد کی طرف ایک قطار میں بطور دیوار رکھ دیئے گئے اور دروازہ میں ( چوکھٹ کی جگہ ) پتھر رکھ دیئے۔ انس رضی اللہ عنہ نے بیان کیا کہ صحابہ جب پتھر لا رہے تھے تو شعر پڑھتے جاتے تھے نبی کریم صلی اللہ علیہ وسلم بھی ان کے ساتھ خود پتھر لاتے اور شعر پڑھتے۔ صحابہ یہ شعر پڑھتے کہ اے اللہ! آخرت ہی کی خیر، خیر ہے، پس تو انصار اور مہاجرین کی مدد فرما۔' WHERE id = 3770;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، انہوں نے کہا ہم سے عبداللہ بن مبارک نے بیان کیا، انہوں نے کہا کہ ہم سے یونس نے، ان سے زہری نے بیان کیا، کہا مجھ کو عبیداللہ بن عبداللہ بن عتبہ نے خبر دی، ان سے عبداللہ بن عباس رضی اللہ عنہما نے کہا کہ نبی کریم صلی اللہ علیہ وسلم سر کے بال کو پیشانی پر لٹکا دیتے تھے اور مشرکین مانگ نکالتے تھے اور اہل کتاب بھی اپنے سروں کے بال پیشانی پر لٹکائے رہنے دیتے تھے۔ جن امور میں نبی کریم صلی اللہ علیہ وسلم کو ( وحی کے ذریعہ ) کوئی حکم نہیں ہوتا تھا آپ صلی اللہ علیہ وسلم ان میں اہل کتاب کی موافقت پسند کرتے تھے۔ پھر بعد میں نبی کریم صلی اللہ علیہ وسلم بھی مانگ نکالنے لگے تھے۔' WHERE id = 3781;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، ہم کو ہشام نے خبر دی، انہیں ابن جریج نے خبر دی، کہا کہ مجھے عبدالکریم نے خبر دی، انہوں نے عبداللہ بن حارث کے مولیٰ مقسم سے سنا، وہ ابن عباس رضی اللہ عنہما سے بیان کرتے تھے، انہوں نے بیان کیا کہ ( سورۃ نساء کی اس آیت سے ) «لا يستوي القاعدون من المؤمنين‏» جہاد میں شرکت کرنے والے اور اس میں شریک نہ ہونے والے برابر نہیں ہو سکتے۔ وہ لوگ مراد ہیں جو بدر کی لڑائی میں شریک ہوئے اور جو اس میں شریک نہیں ہوئے۔' WHERE id = 3791;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، انہوں نے کہا کہ میں نے یوسف بن ماجشون سے یہ حدیث لکھی، انہوں نے صالح بن ابراہیم سے بیان کیا، انہوں نے اپنے والد سے انہوں نے صالح کے دادا ( عبدالرحمٰن بن عوفص ) سے، بدر کے بارے میں عفراء کے دونوں بیٹوں کی حدیث مراد لیتے تھے۔' WHERE id = 3802;
UPDATE hadiths SET urdu = 'ہم سے فروہ بن ابی المغراء نے بیان کیا ‘ ان سے علی بن مسہر نے ‘ ان سے ہشام بن عروہ نے ‘ ان سے ان کے والد عروہ نے بیان کیا کہ زبیر رضی اللہ عنہ کی تلوار پر چاندی کا کام تھا۔ ہشام نے کہا کہ ( میرے والد ) عروہ کی تلوار پر چاندی کا کام تھا۔' WHERE id = 3812;
UPDATE hadiths SET urdu = 'مجھ سے یعقوب نے بیان کیا، ہم سے ابراہیم بن سعد نے بیان کیا، ان سے ان کے والد نے، ان کے دادا سے کہ عبدالرحمٰن بن عوف رضی اللہ عنہ نے کہا بدر کی لڑائی کے موقع پر میں صف میں کھڑا ہوا تھا۔ میں نے مڑ کے دیکھا تو میری داہنی اور بائیں طرف دو نوجوان کھڑے تھے۔ ابھی میں ان کے متعلق کوئی فیصلہ بھی نہ کر پایا تھا کہ ایک نے مجھ سے چپکے سے پوچھا تاکہ اس کا ساتھی سننے نہ پائے۔ چچا! مجھے ابوجہل کو دکھا دو۔ میں نے کہا بھتیجے! تم اسے دیکھ کر کیا کرو گے؟ اس نے کہا، میں نے اللہ تعالیٰ کے سامنے یہ عہد کیا ہے کہ اگر میں نے اسے دیکھ لیا تو یا اسے قتل کر کے رہوں گا یا پھر خود اپنی جان دے دوں گا۔ دوسرے نوجوان نے بھی اپنے ساتھی سے چھپاتے ہوئے مجھ سے یہی بات پوچھی۔ انہوں نے کہا کہ اس وقت ان دونوں نوجوانوں کے درمیان میں کھڑے ہو کر مجھے بہت خوشی ہوئی۔ میں نے اشارے سے انہیں ابوجہل دکھا دیا۔ جسے دیکھتے ہی وہ دونوں باز کی طرح اس پر جھپٹے اور فوراً ہی اسے مار گرایا۔ یہ دونوں عفراء کے بیٹے تھے۔' WHERE id = 3824;
UPDATE hadiths SET urdu = 'مجھ سے عبید بن اسماعیل نے بیان کیا، ہم سے ابواسامہ نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے بیان کیا اور ان سے زبیر رضی اللہ عنہ نے بیان کیا کہ بدر کی لڑائی میں میری مڈبھیڑ عبیدہ بن سعید بن عاص سے ہو گئی۔ اس کا سارا جسم لوہے میں غرق تھا اور صرف آنکھ دکھائی دے رہی تھی۔ اس کی کنیت ابوذات الکرش تھی۔ کہنے لگا کہ میں ابوذات الکرش ہوں۔ میں نے چھوٹے برچھے سے اس پر حملہ کیا اور اس کی آنکھ ہی کو نشانہ بنایا۔ چنانچہ اس زخم سے وہ مر گیا۔ ہشام نے بیان کیا کہ مجھے خبر دی گئی ہے کہ زبیر رضی اللہ عنہ نے کہا کہ پھر میں نے اپنا پاؤں اس کے اوپر رکھ کر پورا زور لگایا اور بڑی دشواری سے وہ برچھا اس کی آنکھ سے نکال سکا۔ اس کے دونوں کنارے مڑ گئے تھے۔ عروہ نے بیان کیا کہ پھر رسول اللہ صلی اللہ علیہ وسلم نے زبیر رضی اللہ عنہ کا وہ برچھا طلب فرمایا تو انہوں نے وہ پیش کر دیا۔ جب نبی کریم صلی اللہ علیہ وسلم کی وفات ہو گئی تو انہوں نے اسے واپس لے لیا۔ پھر ابوبکر رضی اللہ عنہ نے طلب کیا تو انہوں نے انہیں بھی دے دیا۔ ابوبکر رضی اللہ عنہ کی وفات کے بعد عمر رضی اللہ عنہ نے طلب کیا۔ انہوں نے انہیں بھی دے دیا۔ عمر رضی اللہ عنہ کی وفات کے بعد انہوں نے اسے لے لیا۔ پھر عثمان رضی اللہ عنہ نے طلب کیا تو انہوں نے انہیں بھی دے دیا۔ عثمان رضی اللہ عنہ کی شہادت کے بعد وہ علی رضی اللہ عنہ کے پاس چلا گیا اور ان کے بعد ان کی اولاد کے پاس اور اس کے بعد عبداللہ بن زبیر رضی اللہ عنہما نے اسے لے لیا اور ان کے پاس ہی رہا، یہاں تک کہ وہ شہید کر دیئے گئے۔' WHERE id = 3834;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، ہم سے ابوعوانہ نے بیان کیا، ان سے اعمش نے، ان سے ابراہیم نخعی نے، ان سے عبدالرحمٰن بن یزید نخعی نے، ان سے علقمہ بن یسعی نے اور ان سے ابومسعود بدری رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ سورۃ البقرہ کی دو آیتیں ( «امن الرسول» سے آخر تک ) ایسی ہیں کہ جو شخص رات میں انہیں پڑھ لے وہ اس کے لیے کافی ہو جاتی ہیں۔ عبدالرحمٰن نے بیان کیا کہ پھر میں نے خود ابومسعود رضی اللہ عنہ سے ملاقات کی، وہ اس وقت بیت اللہ کا طواف کر رہے تھے۔ میں نے ان سے اس حدیث کے متعلق پوچھا تو انہوں نے یہ حدیث مجھ سے بیان کی۔' WHERE id = 3844;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن ابراہیم نے بیان کیا، انہوں نے محمد بن فضیل سے سنا، انہوں نے اسماعیل ابن ابی خالد سے، انہوں نے قیس بن ابی حازم سے کہ بدری صحابہ کا ( سالانہ ) وظیفہ پانچ پانچ ہزار تھا۔ عمر رضی اللہ عنہ نے فرمایا کہ میں انہیں ( بدری صحابہ کو ) ان صحابیوں پر فضیلت دوں گا جو ان کے بعد ایمان لائے۔' WHERE id = 3856;
UPDATE hadiths SET urdu = 'ہم سے اسحاق نے بیان کیا، کہا ہم کو حبان نے خبر دی، انہیں جویریہ بن اسماء نے، انہیں نافع نے، انہیں ابن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے بنو نضیر کے باغات جلوا دیئے تھے۔ انہوں نے کہا کہ حسان بن ثابت رضی اللہ عنہ نے اسی کے متعلق یہ شعر کہا تھا ( ترجمہ ) ”بنو لوی ( قریش ) کے سرداروں نے بڑی آسانی کے ساتھ برداشت کر لیا۔ مقام بویرہ میں اس آگ کو جو پھیل رہی تھی۔“ بیان کیا کہ پھر اس کا جواب ابوسفیان بن حارث نے ان اشعار میں دیا۔ ”خدا کرے کہ مدینہ میں ہمیشہ یوں ہی آگ لگتی رہے اور اس کے اطراف میں یوں ہی شعلے اٹھتے رہیں۔ تمہیں جلد ہی معلوم ہو جائے گا کہ ہم میں سے کون اس مقام بویرہ سے دور ہے اور تمہیں معلوم ہو جائے گا کہ کس کی زمین کو نقصان پہنچتا ہے۔“' WHERE id = 3866;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، کہا ہم سے زہیر بن معاویہ نے بیان کیا، ان سے اعمش نے بیان کیا، ان سے شقیق بن سلمہ نے اور ان سے خباب بن الارت رضی اللہ عنہ نے بیان کیا کہ ہم نے رسول اللہ صلی اللہ علیہ وسلم کے ساتھ ہجرت کی تھی۔ ہمارا مقصد صرف اللہ کی رضا تھی۔ اس کا ثواب اللہ کے ذمے تھا۔ پھر ہم میں سے بعض لوگ تو وہ تھے جو گزر گئے اور کوئی اجر انہوں نے اس دنیا میں نہیں دیکھا، انہیں میں سے مصعب بن عمیر رضی اللہ عنہ بھی تھے۔ احد کی لڑائی میں انہوں نے شہادت پائی تھی۔ ایک دھاری دار چادر کے سوا اور کوئی چیز ان کے پاس نہیں تھی ( اور وہی ان کا کفن بنی ) جب ہم اس سے ان کا سر چھپاتے تو پاؤں کھل جاتے اور پاؤں چھپاتے تو سر کھل جاتا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ سر چادر سے چھپا دو اور پاؤں پر اذخر گھاس ڈال دو۔ یا نبی کریم صلی اللہ علیہ وسلم نے یہ الفاظ فرمائے تھے کہ «ألقوا على رجله من الإذخر» بجائے «اجعلوا على رجله الإذخر» کے اور ہم بعض وہ تھے جنہیں ان کے اس عمل کا بدلہ ( اسی دنیا میں ) مل رہا ہے اور وہ اس سے فائدہ اٹھا رہے ہیں۔' WHERE id = 3878;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے یحییٰ بن کثیر نے بیان کیا، ان سے ابن المسیب نے، انہوں نے بیان کیا کہ سعد بن ابی وقاص رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے غزوہ احد کے موقع پر ( میری ہمت بڑھانے کے لیے ) اپنے والد اور والدہ دونوں کو جمع فرمایا۔ ان کی مراد آپ کے اس ارشاد سے تھی جو آپ صلی اللہ علیہ وسلم نے اس وقت فرمایا تھا جب وہ جنگ کر رہے تھے کہ میرے ماں باپ تم پر فدا ہوں۔' WHERE id = 3888;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن عبداللہ سلمی نے بیان کیا، کہا ہم کو عبداللہ نے خبر دی، کہا ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں سالم نے اپنے والد عبداللہ بن عمر رضی اللہ عنہما سے کہ انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، جب نبی کریم صلی اللہ علیہ وسلم فجر کی آخری رکعت کے رکوع سے سر مبارک اٹھاتے تو یہ دعا کرتے ”اے اللہ! فلاں، فلاں اور فلاں ( صفوان بن امیہ، سہیل بن عمرو اور حارث بن ہشام ) کو اپنی رحمت سے دور کر دے۔“ یہ دعا آپ «سمع الله لمن حمده ربنا ولك الحمد» کے بعد کرتے تھے۔ اس پر اللہ تعالیٰ نے آیت «ليس لك من الأمر شىء‏» سے «فإنهم ظالمون‏» ( آل عمران: 128 ) تک نازل کی۔' WHERE id = 3899;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے لیث نے بیان کیا، ان سے ابن شہاب نے، ان سے عبدالرحمٰن بن کعب بن مالک نے اور انہیں جابر بن عبداللہ رضی اللہ عنہما نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم نے احد کے شہداء کو ایک ہی کپڑے میں دو دو کو کفن دیا اور آپ صلی اللہ علیہ وسلم دریافت فرماتے کہ ان میں قرآن کا عالم سب سے زیادہ کون ہے؟ جب کسی ایک کی طرف اشارہ کر کے آپ کو بتایا جاتا تو لحد میں آپ صلی اللہ علیہ وسلم انہی کو آگے فرماتے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ قیامت کے دن میں ان سب پر گواہ رہوں گا۔ پھر آپ نے تمام شہداء کو خون سمیت دفن کرنے کا حکم فرما دیا اور ان کی نماز جنازہ نہیں پڑھی اور نہ انہیں غسل دیا گیا۔' WHERE id = 3909;
UPDATE hadiths SET urdu = 'مجھ سے عبدالاعلیٰ بن حماد نے بیان کیا، کہا ہم سے یزید بن زریع نے بیان کیا، کہا ہم سے سعید بن ابی عروبہ نے بیان کیا، ان سے قتادہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ رعل، ذکوان، عصیہ اور بنو لحیان نے رسول اللہ صلی اللہ علیہ وسلم سے اپنے دشمنوں کے مقابل مدد چاہی۔ نبی کریم صلی اللہ علیہ وسلم نے ستر انصاری صحابہ کو ان کی کمک کے لیے روانہ کیا۔ ہم ان حضرات کو قاری کہا کرتے تھے۔ اپنی زندگی میں معاش کے لیے دن میں لکڑیاں جمع کرتے تھے اور رات میں نماز پڑھا کرتے تھے۔ جب یہ حضرات بئرمعونہ پر پہنچے تو ان قبیلے والوں نے انہیں دھوکا دیا اور انہیں شہید کر دیا۔ جب نبی کریم صلی اللہ علیہ وسلم کو اس کی خبر ہوئی تو آپ نے صبح کی نماز میں ایک مہینے تک بددعا کی۔ عرب کے انہیں چند قبائل رعل، ذکوان، عصیہ اور بنو لحیان کے لیے۔ انس رضی اللہ عنہ نے بیان کیا کہ ان صحابہ کے بارے میں قرآن میں ( آیت نازل ہوئی اور ) ہم اس کی تلاوت کرتے تھے۔ پھر وہ آیت منسوخ ہو گئی ( آیت کا ترجمہ ) ”ہماری طرف سے ہماری قوم ( مسلمانوں ) کو خبر پہنچا دو کہ ہم اپنے رب کے پاس آ گئے ہیں۔ ہمارا رب ہم سے راضی ہے اور ہمیں بھی ( اپنی نعمتوں سے ) اس نے خوش رکھا ہے۔“ اور قتادہ سے روایت ہے ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ایک مہینے تک صبح کی نماز میں، عرب کے چند قبائل یعنی رعل، ذکوان، عصیہ اور بنو لحیان کے لیے بددعا کی تھی۔ خلیفہ بن خیاط ( امام بخاری رحمہ اللہ کے شیخ ) نے یہ اضافہ کیا کہ ہم سے یزید بن زریع نے بیان کیا، کہا ہم سے سعید بن ابی عروبہ نے بیان کیا، ان سے قتادہ نے کہ ہم سے انس رضی اللہ عنہ نے بیان کیا کہ یہ ستر صحابہ قبیلہ انصار سے تھے اور انہیں بئرمعونہ کے پاس شہید کر دیا گیا تھا۔' WHERE id = 3919;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر عبداللہ بن عمر عقدی نے بیان کیا، کہا ہم سے عبدالوارث بن سعید نے بیان کیا، ان سے عبدالعزیز بن صہیب نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ مدینہ کے گرد مہاجرین و انصار خندق کھودنے میں مصروف ہو گئے اور مٹی اپنی پیٹھ پر اٹھانے لگے۔ اس وقت وہ یہ شعر پڑھ رہے تھے «نحن الذين بايعوا محمدا *** على الأسلام ما بقينا أبدا» ہم نے ہی محمد ( صلی اللہ علیہ وسلم ) سے اسلام پر بیعت کی ہے جب تک ہماری جان میں جان ہے۔ انہوں نے بیان کیا کہ اس پر نبی کریم صلی اللہ علیہ وسلم نے دعا کی «اللهم إنه لا خير إلا خير الآخرة. فبارك في الأنصار والمهاجره» ”اے اللہ! خیر تو صرف آخرت ہی کی خیر ہے۔ پس انصار اور مہاجرین کو تو برکت عطا فرما۔“ انس رضی اللہ عنہ نے بیان کیا کہ ایک مٹھی جَو آتا اور ان صحابہ کے لیے ایسے روغن میں جس کا مزہ بھی بگڑ چکا ہوتا ملا کر پکا دیا جاتا۔ یہی کھانا ان صحابہ کے سامنے رکھ دیا جاتا۔ صحابہ بھوکے ہوتے۔ یہ ان کے حلق میں چپکتا اور اس میں بدبو ہوتی۔ گویا اس وقت ان کی خوراک کا بھی یہ حال تھا۔' WHERE id = 3929;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا ‘ کہا ہم سے یحییٰ بن آدم نے بیان کیا ‘ کہا ہم سے اسرائیل بن یونس نے بیان کیا ‘ انہوں نے ابواسحاق سے سنا ‘ انہوں نے بیان کیا کہ میں نے سلیمان بن صرد رضی اللہ عنہ سے سنا ‘ انہوں نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا ‘ جب عرب کے قبائل ( جو غزوہ خندق کے موقع پر مدینہ چڑھ کر آئے تھے ) ناکام واپس ہو گئے تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اب ہم ان سے جنگ کریں گے ‘ وہ ہم پر چڑھ کر نہ آ سکیں گے بلکہ ہم ہی ان پر فوج کشی کیا کریں گے۔' WHERE id = 3939;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ ابی الاسود نے بیان کیا ‘ کہا ہم سے معتمر بن سلیمان نے بیان کیا (دوسری سند امام بخاری رحمہ اللہ فرماتے ہیں) اور مجھ سے خلیفہ بن خیاط نے بیان کیا ‘ کہا ہم سے معتمر بن سلیمان نے بیان کیا ‘ کہ میں نے اپنے والد سے سنا اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ بطور ہدیہ صحابہ رضی اللہ عنہم اپنے باغ میں سے نبی کریم صلی اللہ علیہ وسلم کے لیے چند کھجور کے درخت مقرر کر دیئے تھے یہاں تک کہ بنو قریظہ اور بنو نضیر کے قبائل فتح ہو گئے ( تو نبی کریم صلی اللہ علیہ وسلم نے ان ہدایا کو واپس کر دیا ) میرے گھر والوں نے بھی مجھے اس کھجور کو، تمام کی تمام یا اس کا کچھ حصہ لینے کے لیے آپ صلی اللہ علیہ وسلم کی خدمت میں بھیجا۔ آپ صلی اللہ علیہ وسلم نے وہ کھجور ام ایمن رضی اللہ عنہا کو دے دی تھی۔ اتنے میں وہ بھی آ گئیں اور کپڑا میری گردن میں ڈال کر کہنے لگیں ‘ قطعاً نہیں۔ اس ذات کی قسم! جس کے سوا کوئی معبود نہیں یہ پھل تمہیں نہیں ملیں گے۔ یہ نبی کریم صلی اللہ علیہ وسلم مجھے عنایت فرما چکے ہیں۔ یا اسی طرح کے الفاظ انہوں نے بیان کئے۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا کہ تم مجھ سے اس کے بدلے میں اتنے لے لو۔ ( اور ان کا مال انہیں واپس کر دو ) لیکن وہ اب بھی یہی کہے جا رہی تھیں کہ قطعاً نہیں، خدا کی قسم! یہاں تک کہ نبی کریم صلی اللہ علیہ وسلم نے انہیں، میرا خیال ہے کہ انس رضی اللہ عنہ نے بیان کیا کہ اس کا دس گنا دینے کا وعدہ فرمایا ( پھر انہوں نے مجھے چھوڑا ) یا اسی طرح کے الفاظ انس رضی اللہ عنہ نے بیان کئے۔' WHERE id = 3949;
UPDATE hadiths SET urdu = 'اور معاذ نے بیان کیا ‘ ان سے ہشام نے بیان کیا ‘ ان سے ابوزبیر نے اور ان سے جابر رضی اللہ عنہ نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ مقام نخل میں تھے۔ پھر انہوں نے نماز خوف کا ذکر کیا۔ امام مالک نے بیان کیا کہ نماز خوف کے سلسلے میں جتنی روایات میں نے سنی ہیں یہ روایت ان سب میں زیادہ بہتر ہے۔ معاذ بن ہشام کے ساتھ اس حدیث کو لیث بن سعد نے بھی ہشام بن سعد مدنی سے ‘ انہوں نے زید بن اسلم سے روایت کیا اور ان سے قاسم بن محمد نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے غزوہ بنو انمار میں ( نماز خوف ) پڑھی تھی۔' WHERE id = 3959;
UPDATE hadiths SET urdu = 'ہم سے آدم ابن ایاس نے بیان کیا ‘ کہا ہم سے ابن ابی ذئب نے بیان کیا ‘ ان سے عثمان بن عبداللہ بن سراقہ نے بیان کیا اور ان سے جابر بن عبداللہ انصاری رضی اللہ عنہما نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کو غزوہ انمار میں دیکھا کہ نفل نماز آپ اپنی سواری پر مشرق کی طرف منہ کئے ہوئے پڑھ رہے تھے۔' WHERE id = 3969;
UPDATE hadiths SET urdu = 'ہم سے عبیداللہ بن موسیٰ نے بیان کیا ‘ ان سے اسرائیل نے ‘ ان سے ابواسحاق نے ان سے براء بن عازب رضی اللہ عنہ نے کہا کہ تم لوگ ( سورۃ انا فتحنا میں ) فتح سے مراد مکہ کی فتح لیتے ہو۔ فتح مکہ تو بہرحال فتح ہی تھی لیکن ہم غزوہ حدیبیہ کی بیعت رضوان کو حقیقی فتح سمجھتے ہیں۔ اس دن ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ چودہ سو آدمی تھے۔ حدیبیہ نامی ایک کنواں وہاں پر تھا ‘ ہم نے اس میں سے اتنا پانی کھینچا کہ اس کے اندر ایک قطرہ بھی پانی باقی نہ رہا۔ نبی کریم صلی اللہ علیہ وسلم کو جب یہ خبر ہوئی ( کہ پانی ختم ہو گیا ہے ) تو آپ صلی اللہ علیہ وسلم کنویں پر تشریف لائے اور اس کے کنارے پر بیٹھ کر کسی ایک برتن میں پانی طلب فرمایا۔ اس سے آپ صلی اللہ علیہ وسلم نے وضو کیا اور کلی کی اور دعا فرمائی۔ پھر سارا پانی اس کنویں میں ڈال دیا۔ تھوڑی دیر کے لیے ہم نے کنویں کو یوں ہی رہنے دیا اور اس کے بعد جتنا ہم نے چاہا اس میں سے پانی پیا اور اپنی سواریوں کو پلایا۔' WHERE id = 3979;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا ‘ کہا ہم سے ابوعوانہ نے ‘ کہا ہم سے طارق بن عبدالرحمٰن نے ‘ ان سے سعید بن مسیب نے اور ان سے ان کے والد نے کہ انہوں نے بھی رسول اللہ صلی اللہ علیہ وسلم سے اس درخت کے تلے بیعت کی تھی۔ کہتے تھے کہ جب ہم دوسرے سال ادھر گئے تو ہمیں پتہ نہیں چلا کہ وہ کون سا درخت تھا۔' WHERE id = 3991;
UPDATE hadiths SET urdu = 'اور مجزاۃ نے اپنے ہی قبیلہ کے ایک صحابی کے متعلق جو بیعت رضوان میں شریک تھے اور جن کا نام اہبان بن اوس رضی اللہ عنہ تھا ‘ نقل کیا کہ ان کے ایک گھٹنے میں تکلیف تھی ‘ اس لیے جب وہ سجدہ کرتے تو اس گھٹنے کے نیچے کوئی نرم تکیہ رکھ لیتے تھے۔' WHERE id = 4001;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبداللہ بن نمیر نے بیان کیا ‘ کہا ہم سے یعلیٰ بن عبید نے بیان کیا ‘ کہا ہم سے اسماعیل بن ابی خالد نے بیان کیا ‘ کہا کہ میں نے عبداللہ بن ابی اوفی رضی اللہ عنہ سے سنا ‘ آپ نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم نے عمرہ ( قضاء ) کیا تو ہم بھی آپ کے ساتھ تھے۔ آپ صلی اللہ علیہ وسلم نے طواف کیا تو ہم نے بھی آپ کے ساتھ طواف کیا۔ آپ صلی اللہ علیہ وسلم نے نماز پڑھی تو ہم نے بھی آپ کے ساتھ نماز پڑھی اور آپ صلی اللہ علیہ وسلم نے صفا و مروہ کی سعی بھی کی۔ ہم آپ کی اہل مکہ سے حفاظت کرتے تھے تاکہ کوئی تکلیف کی بات آپ کو پیش نہ آ جائے۔' WHERE id = 4013;
UPDATE hadiths SET urdu = 'ہمیں صدقہ بن فضل نے خبر دی ‘ کہا ہم کو ابن عیینہ نے خبر دی ‘ کہا ہم سے ایوب نے بیان کیا ‘ ان سے محمد بن سیرین نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ ہم خیبر صبح کے وقت پہنچے ‘ یہودی اپنے پھاؤڑے وغیرہ لے کر باہر آئے لیکن جب انہوں نے نبی کریم صلی اللہ علیہ وسلم کو دیکھا تو چلانے لگے محمد! اللہ کی قسم محمد ( صلی اللہ علیہ وسلم ) لشکر لے کر آ گئے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ کی ذات سب سے بلند و برتر ہے۔ یقیناً جب ہم کسی قوم کے میدان میں اتر جائیں تو پھر ڈرائے ہوئے لوگوں کی صبح بری ہو جاتی ہے۔ پھر ہمیں وہاں گدھے کا گوشت ملا لیکن آپ صلی اللہ علیہ وسلم کی طرف سے اعلان کرنے والے نے اعلان کیا کہ اللہ اور اس کے رسول تمہیں گدھے کا گوشت کھانے سے منع کرتے ہیں کہ یہ ناپاک ہے۔' WHERE id = 4023;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سعید خزاعی نے بیان کیا ‘ کہا ہم سے زیاد بن ربیع نے بیان کیا ‘ ان سے ابوعمران نے بیان کیا کہ انس بن مالک رضی اللہ عنہ نے ( بصرہ کی مسجد میں ) جمعہ کے دن لوگوں کو دیکھا کہ ( ان کے سروں پر ) چادریں ہیں جن پر پھول کڑھے ہوئے ہیں۔ انہوں نے کہا کہ یہ لوگ اس وقت خیبر کے یہودیوں کی طرح معلوم ہوتے ہیں۔' WHERE id = 4033;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن نصر نے بیان کیا ‘ انہوں نے کہا ہم سے محمد بن عبید نے بیان کیا ‘ انہوں نے کہا ہم سے عبیداللہ نے بیان کیا ‘ ان سے نافع اور سالم نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے پالتو گدھوں کے گوشت کی ممانعت کی تھی۔' WHERE id = 4043;
UPDATE hadiths SET urdu = 'ابوبردہ رضی اللہ عنہ نے بیان کیا کہ اسماء رضی اللہ عنہا نے بیان کیا کہ ابوموسیٰ رضی اللہ عنہ مجھ سے اس حدیث کو باربار سنتے تھے۔ ابوبردہ رضی اللہ عنہ نے بیان کیا اور ان سے ابوموسیٰ رضی اللہ عنہ نے کہ آپ صلی اللہ علیہ وسلم نے فرمایا کہ جب میرے اشعری احباب رات میں آتے ہیں تو میں ان کی قرآن کی تلاوت کی آواز پہچان جاتا ہوں۔ اگرچہ دن میں ‘ میں نے ان کی اقامت گاہوں کو نہ دیکھا ہو لیکن جب رات میں وہ قرآن پڑھتے ہیں تو ان کی آواز سے میں ان کی اقامت گاہوں کو پہچان لیتا ہوں۔ میرے انہی اشعری احباب میں ایک مرد دانا بھی ہے کہ جب کہیں اس کی سواروں سے مڈبھیڑ ہو جاتی ہے یا آپ نے فرمایا کہ دشمن سے ‘ تو ان سے کہتا ہے کہ میرے دوستوں نے کہا ہے کہ تم تھوڑی دیر کے لیے ان کا انتظار کر لو۔' WHERE id = 4055;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا ‘ کہا ہم سے جویریہ نے بیان کیا ‘ ان سے نافع نے ان سے عبداللہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے خیبر ( کی زمین و باغات وہاں کے ) یہودیوں کے پاس ہی رہنے دیئے تھے کہ وہ ان میں کام کریں اور بوئیں جوتیں اور انہیں ان کی پیداوار کا آدھا حصہ ملے گا۔' WHERE id = 4068;
UPDATE hadiths SET urdu = 'ہم سے احمد بن صالح نے بیان کیا ‘ کہا ہم سے عبداللہ بن وہب نے بیان کیا ‘ ان سے عمرو بن حارث انصاری نے ‘ ان سے سعید بن ابی ہلال نے بیان کیا اور کہا کہ مجھ کو نافع نے خبر دی اور انہیں ابن عمر رضی اللہ عنہما نے خبر دی کہ اس غزوہ موتہ میں جعفر طیار رضی اللہ عنہ کی لاش پر کھڑے ہو کر میں نے شمار کیا تو نیزوں اور تلواروں کے پچاس زخم ان کے جسم پر تھے لیکن پیچھے یعنی پیٹھ پر ایک زخم بھی نہیں تھا۔' WHERE id = 4079;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا ‘ کہا ہم سے حاتم بن اسماعیل نے بیان کیا ‘ ان سے یزید بن ابی عبید نے بیان کیا اور انہوں نے سلمہ بن اکوع رضی اللہ عنہ سے سنا ‘ وہ بیان کرتے تھے کہ میں نبی کریم صلی اللہ علیہ وسلم کے ہمراہ سات غزووں میں شریک رہا ہوں اور نو ایسے لشکروں میں شریک ہوا ہوں جو آپ نے روانہ کئے تھے۔ ( مگر آپ خود ان میں نہیں گئے ) کبھی ہم پر ابوبکر رضی اللہ عنہ امیر ہوئے اور کسی فوج کے امیر اسامہ رضی اللہ عنہ ہوئے۔' WHERE id = 4089;
UPDATE hadiths SET urdu = 'ہم سے عبید بن اسماعیل نے بیان کیا ‘ کہا ہم سے ابواسامہ نے بیان کیا ‘ ان سے ہشام بن عروہ نے ‘ ان سے ان کے والد نے بیان کیا کہ جب رسول اللہ صلی اللہ علیہ وسلم فتح مکہ کے لیے روانہ ہوئے تو قریش کو اس کی خبر مل گئی تھی۔، چنانچہ ابوسفیان بن حرب ‘ حکیم بن حزام اور بدیل بن ورقاء نبی کریم صلی اللہ علیہ وسلم کے بارے میں معلومات کے لیے مکہ سے نکلے۔ یہ لوگ چلتے چلتے مقام مر الظہران پر جب پہنچے تو انہیں جگہ جگہ آگ جلتی ہوئی دکھائی دی۔ ایسا معلوم ہوتا تھا کہ مقام عرفات کی آگ ہے۔ ابوسفیان نے کہا یہ آگ کیسی ہے؟ یہ عرفات کی آگ کی طرح دکھائی دیتی ہے۔ اس پر بدیل بن ورقاء نے کہا کہ یہ بنی عمرو ( یعنی قباء کے قبیلے ) کی آگ ہے۔ ابوسفیان نے کہا کہ بنی عمرو کی تعداد اس سے بہت کم ہے۔ اتنے میں نبی کریم صلی اللہ علیہ وسلم کے محافظ دستے نے انہیں دیکھ لیا اور ان کو پکڑ کر نبی کریم صلی اللہ علیہ وسلم کی خدمت میں لائے ‘ پھر ابوسفیان رضی اللہ عنہ نے اسلام قبول کیا۔ اس کے بعد جب نبی کریم صلی اللہ علیہ وسلم آگے ( مکہ کی طرف ) بڑھے تو عباس رضی اللہ عنہ سے فرمایا کہ ابوسفیان کو ایسی جگہ پر روکے رکھو جہاں گھوڑوں کا جاتے وقت ہجوم ہو تاکہ وہ مسلمانوں کی فوجی قوت کو دیکھ لیں۔ چنانچہ عباس رضی اللہ عنہ انہیں ایسے ہی مقام پر روک کر کھڑے ہو گئے اور نبی کریم صلی اللہ علیہ وسلم کے ساتھ قبائل کے دستے ایک ایک کر کے ابوسفیان کے سامنے سے گزرنے لگے۔ ایک دستہ گزرا تو انہوں نے پوچھا: عباس! یہ کون ہیں؟ انہوں نے بتایا کہ یہ قبیلہ غفار ہے۔ ابوسفیان نے کہا کہ مجھے غفار سے کیا سروکار ‘ پھر قبیلہ جہینہ گزرا تو ان کے متعلق بھی انہوں نے یہی کہا ‘ قبیلہ سلیم گزرا تو ان کے متعلق بھی یہی کہا۔ آخر ایک دستہ سامنے آیا۔ اس جیسا فوجی دستہ نہیں دیکھا گیا ہو گا۔ ابوسفیان رضی اللہ عنہ نے پوچھا یہ کون لوگ ہیں؟ عباس رضی اللہ عنہ نے کہا کہ یہ انصار کا دستہ ہے۔ سعد بن عبادہ رضی اللہ عنہ اس کے امیر ہیں اور انہیں کے ہاتھ میں ( انصار کا عَلم ہے ) سعد بن عبادہ رضی اللہ عنہ نے کہا: ابوسفیان! آج کا دن قتل عام کا دن ہے۔ آج کعبہ میں بھی لڑنا درست کر دیا گیا ہے۔ ابوسفیان رضی اللہ عنہ اس پر بولے: اے عباس! ( قریش کی ہلاکت و بربادی کا دن اچھا آ لگا ہے۔ پھر ایک اور دستہ آیا یہ سب سے چھوٹا دستہ تھا۔ اس میں رسول اللہ صلی اللہ علیہ وسلم اور آپ کے صحابہ رضی اللہ عنہم تھے۔ نبی کریم صلی اللہ علیہ وسلم کا عَلم زبیر بن العوام رضی اللہ عنہ اٹھائے ہوئے تھے۔ جب نبی کریم صلی اللہ علیہ وسلم ابوسفیان کے قریب سے گزرے تو انہوں نے کہا آپ کو معلوم نہیں ‘ سعد بن عبادہ رضی اللہ عنہ کیا کہہ گئے ہیں۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ انہوں نے کیا کہا ہے؟ تو ابوسفیان نے بتایا کہ یہ یہ کہہ گئے ہیں کہ آپ قریش کا کام تمام کر دیں گے۔ ( سب کو قتل کر ڈالیں گے ) ۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ سعد نے غلط کہا ہے بلکہ آج کا دن وہ ہے جس میں اللہ کعبہ کی عظمت اور زیادہ کر دے گا۔ آج کعبہ کو غلاف پہنایا جائے گا۔ عروہ نے بیان کیا پھر آپ صلی اللہ علیہ وسلم نے حکم دیا کہ آپ کا عَلم مقام جحون میں گاڑ دیا جائے۔ عروہ نے بیان کیا اور مجھے نافع بن جبیر بن مطعم نے خبر دی ‘ کہا کہ میں نے عباس رضی اللہ عنہ سے سنا ‘ انہوں نے زبیر بن عوام رضی اللہ عنہ سے کہا ( فتح مکہ کے بعد ) کہ نبی کریم صلی اللہ علیہ وسلم نے ان کو یہیں جھنڈا گاڑنے کے لیے حکم فرمایا تھا۔ راوی نے بیان کیا کہ اس دن نبی کریم صلی اللہ علیہ وسلم نے خالد بن ولید رضی اللہ عنہ کو حکم دیا تھا کہ مکہ کے بالائی علاقہ کداء کی طرف سے داخل ہوں اور خود نبی کریم صلی اللہ علیہ وسلم کداء ( نشیبی علاقہ ) کی طرف سے داخل ہوئے۔ اس دن خالد رضی اللہ عنہ کے دستہ کے دو صحابی ‘ حبیش بن اشعر اور کرز بن جابر فہری شہید ہوئے تھے۔' WHERE id = 4099;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا ‘ کہا ہم سے شعبہ نے بیان کیا ‘ ان سے عمرو نے ‘ ان سے ابن ابی لیلیٰ نے کہ ام ہانی رضی اللہ عنہا کے سوا ہمیں کسی نے یہ خبر نہیں دی کہ نبی کریم صلی اللہ علیہ وسلم نے چاشت کی نماز پڑھی ‘ انہی نے کہا کہ جب مکہ فتح ہوا تو نبی کریم صلی اللہ علیہ وسلم نے ان کے گھر غسل کیا اور آٹھ رکعت نماز پڑھی۔ انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم کو میں نے اتنی ہلکی نماز پڑھتے کبھی نہیں دیکھا تھا۔ پھر بھی اس میں آپ صلی اللہ علیہ وسلم رکوع اور سجدہ پوری طرح کرتے تھے۔' WHERE id = 4110;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا ‘ کہا ہم سے حماد بن زید نے بیان کیا ‘ ان سے ایوب سختیانی نے اور ان سے ابوقلابہ نے اور ان سے عمرو بن سلمہ رضی اللہ عنہ نے ‘ ایوب نے کہا کہ مجھ سے ابوقلابہ نے کہا ‘ عمرو بن سلمہ رضی اللہ عنہ کی خدمت میں حاضر ہو کر یہ قصہ کیوں نہیں پوچھتے؟ ابوقلابہ نے کہا کہ پھر میں ان کی خدمت میں گیا اور ان سے سوال کیا ‘ انہوں نے کہا کہ جاہلیت میں ہمارا قیام ایک چشمہ پر تھا جہاں عام راستہ تھا۔ سوار ہمارے قریب سے گزرتے تو ہم ان سے پوچھتے ‘ لوگوں کا کیا خیال ہے ‘ اس شخص کا کیا معاملہ ہے؟ ( یہ اشارہ نبی کریم صلی اللہ علیہ وسلم کی طرف ہوتا تھا ) لوگ بتاتے کہ وہ کہتے ہیں کہ اللہ نے انہیں اپنا رسول بنا کر بھیجا ہے اور اللہ ان پر وحی نازل کرتا ہے ‘ یا اللہ نے ان پر وحی نازل کی ہے ( وہ قرآن کی کوئی آیت سناتے ) میں وہ فوراً یاد کر لیتا ‘ ان کی باتیں میرے دل کو لگتی تھیں۔ ادھر سارے عرب والے فتح مکہ پر اپنے اسلام کو موقوف کئے ہوئے تھے۔ ان کا کہنا یہ تھا کہ اس نبی کو اور اس کی قوم ( قریش ) کو نمٹنے دو ‘ اگر وہ ان پر غالب آ گئے تو پھر واقعی وہ سچے نبی ہیں۔ چنانچہ جب مکہ فتح ہو گیا تو ہر قوم نے اسلام لانے میں پہل کی اور میرے والد نے بھی میری قوم کے اسلام میں جلدی کی۔ پھر جب ( مدینہ ) سے واپس آئے تو کہا کہ میں اللہ کی قسم ایک سچے نبی کے پاس سے آ رہا ہوں۔ انہوں نے فرمایا ہے کہ فلاں نماز اس طرح فلاں وقت پڑھا کرو اور جب نماز کا وقت ہو جائے تو تم میں سے کوئی ایک شخص اذان دے اور امامت وہ کرے جسے قرآن سب سے زیادہ یاد ہو۔ لوگوں نے اندازہ کیا کہ کسے قرآن سب سے زیادہ یاد ہے تو کوئی شخص ان کے قبیلے میں مجھ سے زیادہ قرآن یاد کرنے والا انہیں نہیں ملا۔ کیونکہ میں آنے جانے والے سواروں سے سن کر قرآن مجید یاد کر لیا کرتا تھا۔ اس لیے مجھے لوگوں نے امام بنایا۔ حالانکہ اس وقت میری عمر چھ یا سات سال کی تھی اور میرے پاس ایک ہی چادر تھی۔ جب میں ( اسے لپیٹ کر ) سجدہ کرتا تو اوپر ہو جاتی ( اور پیچھے کی جگہ ) کھل جاتی۔ اس قبیلہ کی ایک عورت نے کہا ‘ تم اپنے قاری کا چوتڑ تو پہلے چھپا دو۔ آخر انہوں نے کپڑا خریدا اور میرے لیے ایک قمیص بنائی، میں جتنا خوش اس قمیص سے ہوا اتنا کسی اور چیز سے نہیں ہوا تھا۔' WHERE id = 4120;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے ابواسحاق نے کہ براء بن عازب رضی اللہ عنہ سے پوچھا گیا اور میں سن رہا تھا کہ تم لوگوں نے نبی کریم صلی اللہ علیہ وسلم کے ساتھ غزوہ حنین میں پیٹھ پھیر لی تھی؟ انہوں نے کہا جہاں تک نبی کریم صلی اللہ علیہ وسلم کا تعلق ہے تو آپ نے پیٹھ نہیں پھیری تھی۔ ہوا یہ تھا کہ ہوازن والے بڑے تیرانداز تھے، نبی کریم صلی اللہ علیہ وسلم نے اس موقع پر فرمایا تھا «أنا النبي لا كذب أنا ابن عبد المطلب» ”میں نبی ہوں اس میں جھوٹ نہیں، میں عبدالمطلب کی اولاد ہوں۔“' WHERE id = 4132;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے وہیب بن خالد نے بیان کیا، ان سے عمرو بن یحییٰ نے، ان سے عباد بن تمیم نے، ان سے عبداللہ بن زید بن عاصم رضی اللہ عنہ نے بیان کیا کہ غزوہ حنین کے موقع پر اللہ تعالیٰ نے اپنے رسول کو جو غنیمت دی تھی آپ نے اس کی تقسیم کمزور ایمان کے لوگوں میں ( جو فتح مکہ کے بعد ایمان لائے تھے ) کر دی اور انصار کو اس میں سے کچھ نہیں دیا۔ اس کا انہیں کچھ ملال ہوا کہ وہ مال جو نبی کریم صلی اللہ علیہ وسلم نے دوسروں کو دیا انہیں کیوں نہیں دیا۔ آپ نے اس کے بعد انہیں خطاب کیا اور فرمایا: اے انصاریو! کیا میں نے تمہیں گمراہ نہیں پایا تھا پھر تم کو میرے ذریعہ اللہ تعالیٰ نے ہدایت نصیب کی اور تم میں آپس میں دشمنی اور نااتفاقی تھی تو اللہ تعالیٰ نے میرے ذریعہ تم میں باہم الفت پیدا کی اور تم محتاج تھے اللہ تعالیٰ نے میرے ذریعہ غنی کیا۔ آپ کے ایک ایک جملے پر انصار کہتے جاتے تھے کہ اللہ اور اس کے رسول کے ہم سب سے زیادہ احسان مند ہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ میری باتوں کا جواب دینے سے تمہیں کیا چیز مانع رہی؟ بیان کیا کہ آپ صلی اللہ علیہ وسلم کے ہر اشارہ پر انصار عرض کرتے جاتے کہ اللہ اور اس کے رسول کے ہم سب سے زیادہ احسان مند ہیں پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر تم چاہتے تو مجھ سے اس طرح بھی کہہ سکتے تھے ( کہ آپ آئے تو لوگ آپ کو جھٹلا رہے تھے، لیکن ہم نے آپ کی تصدیق کی وغیرہ ) کیا تم اس پر خوش نہیں ہو کہ جب لوگ اونٹ اور بکریاں لے جا رہے ہوں تو تم اپنے گھروں کی طرف رسول اللہ صلی اللہ علیہ وسلم کو ساتھ لے جاؤ؟ اگر ہجرت کی فضیلت نہ ہوتی تو میں بھی انصار کا ایک آدمی ہوتا۔ لوگ خواہ کسی گھاٹی یا وادی میں رہیں گے میں تو انصار کی گھاٹی اور وادی میں رہوں گا۔ انصار استر کی طرح ہیں جو جسم سے ہمیشہ لگا رہتا ہے اور دوسرے لوگ اوپر کے کپڑے یعنی ابرہ کی طرح ہیں۔ تم لوگ ( انصار ) دیکھو گے کہ میرے بعد تم پر دوسروں کو ترجیح دی جائے گی۔ تم ایسے وقت میں صبر کرنا یہاں تک کہ مجھ سے حوض پر آ ملو۔' WHERE id = 4144;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے عبدالواحد بن زیاد نے بیان کیا، کہا ہم سے اعمش نے بیان کیا، کہا مجھ سے سعد بن عبیدہ نے بیان کیا، ان سے ابوعبدالرحمٰن اسلمی نے اور ان سے علی رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ایک مختصر لشکر روانہ کیا اور اس کا امیر ایک انصاری صحابی ( عبداللہ بن حذافہ سہمی رضی اللہ عنہ ) کو بنایا اور لشکریوں کو حکم دیا کہ سب اپنے امیر کی اطاعت کریں پھر امیر کسی وجہ سے غصہ ہو گئے اور اپنے فوجیوں سے پوچھا کہ کیا تمہیں رسول اللہ صلی اللہ علیہ وسلم نے میری اطاعت کرنے کا حکم نہیں فرمایا ہے؟ سب نے کہا کہ ہاں فرمایا ہے۔ انہوں نے کہا پھر تم سب لکڑیاں جمع کرو۔ انہوں نے لکڑیاں جمع کیں تو امیر نے حکم دیا کہ اس میں آگ لگاؤ اور انہوں نے آگ لگا دی۔ اب انہوں نے حکم دیا کہ سب اس میں کود جاؤ۔ فوجی کود جانا ہی چاہتے تھے کہ انہیں میں سے بعض نے بعض کو روکا اور کہا کہ ہم تو اس آگ ہی کے خوف سے رسول اللہ صلی اللہ علیہ وسلم کی طرف آئے ہیں! ان باتوں میں وقت گزر گیا اور آگ بھی بجھ گئی۔ اس کے بعد امیر کا غصہ ٹھنڈا ہو گیا۔ جب اس کی خبر رسول اللہ صلی اللہ علیہ وسلم کو پہنچی تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر یہ لوگ اس میں کود جاتے تو پھر قیامت تک اس میں سے نہ نکلتے۔ اطاعت کا حکم صرف نیک کاموں کے لیے ہے۔' WHERE id = 4154;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، کہا ہم سے یحییٰ بن سعد قطان نے بیان کیا، کہا ہم سے اسماعیل بن ابی خالد نے بیان کیا، کہا ہم سے قیس بن ابی حازم نے بیان کیا، کہا مجھ سے جریر بن عبداللہ بجلی رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے مجھ سے فرمایا کہ تم مجھے ذوالخلصہ سے کیوں نہیں بےفکر کرتے؟ یہ قبیلہ خثعم کا ایک بت خانہ تھا۔ اسے کعبہ یمانیہ بھی کہتے تھے۔ چنانچہ میں ڈیڑھ سو قبیلہ احمس کے سواروں کو لے کر روانہ ہوا۔ یہ سب اچھے شہسوا ر تھے۔ مگر میں گھوڑے کی سواری اچھی طرح نہیں کر سکتا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے میرے سینے پر ہاتھ مارا یہاں تک کہ میں نے آپ کی انگلیوں کا اثر اپنے سینے میں پایا۔ پھر آپ نے دعا کی کہ اے اللہ! اسے گھوڑے کا اچھا سوار بنا دے اور اسے راستہ بتلانے والا اور خود راستہ پایا ہوا بنا دے۔ پھر وہ اس بت خانے کی طرف روانہ ہوئے اور اسے ڈھا کر اس میں آگ لگا دی۔ پھر نبی کریم صلی اللہ علیہ وسلم کی خدمت میں اطلاع بھیجی۔ جریر کے ایلچی نے آ کر عرض کیا: اس ذات کی قسم! جس نے آپ کو حق کے ساتھ مبعوث کیا، میں اس وقت تک آپ کی خدمت میں حاضر ہونے کے لیے نہیں چلا جب تک وہ خارش زدہ اونٹ کی طرح جل کر ( سیاہ ) نہیں ہو گیا۔ بیان کیا کہ پھر نبی کریم صلی اللہ علیہ وسلم نے قبیلہ احمس کے گھوڑوں اور لوگوں کے لیے پانچ مرتبہ برکت کی دعا فرمائی۔' WHERE id = 4167;
UPDATE hadiths SET urdu = 'مجھ سے زہیر بن حرب نے بیان کیا، کہا ہم سے جریر بن عبدالحمید نے بیان کیا، ان سے عمارہ بن قعقاع نے، ان سے ابوزرعہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں اس وقت سے ہمیشہ بنو تمیم سے محبت رکھتا ہوں جب سے نبی کریم صلی اللہ علیہ وسلم کی زبانی ان کی تین خوبیاں میں نے سنی ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے ان کے متعلق فرمایا تھا کہ بنو تمیم دجال کے حق میں میری امت کے سب سے زیادہ سخت لوگ ثابت ہوں گے اور بنو تمیم کی ایک قیدی خاتون عائشہ رضی اللہ عنہا کے پاس تھیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اسے آزاد کر دو کیونکہ یہ اسماعیل علیہ السلام کی اولاد میں سے ہے اور ان کے یہاں سے زکوٰۃ وصول ہو کر آئی تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ ایک قوم کی یا ( یہ فرمایا کہ ) یہ میری قوم کی زکوٰۃ ہے۔' WHERE id = 4177;
UPDATE hadiths SET urdu = 'مجھ سے عباس بن حسین نے بیان کیا، کہا ہم سے یحییٰ بن آدم نے بیان کیا، ان سے اسرائیل نے، ان سے ابواسحاق نے، ان سے صلہ بن زفر نے اور ان سے حذیفہ رضی اللہ عنہ نے بیان کیا کہ نجران کے دو سردار عاقب اور سید، رسول اللہ صلی اللہ علیہ وسلم سے مباہلہ کرنے کے لیے آئے تھے لیکن ایک نے اپنے دوسرے ساتھی سے کہا کہ ایسا نہ کرو کیونکہ اللہ کی قسم! اگر یہ نبی ہوئے اور پھر بھی ہم نے ان سے مباہلہ کیا تو ہم پنپ نہیں سکتے اور نہ ہمارے بعد ہماری نسلیں رہ سکیں گی۔ پھر ان دونوں نے نبی کریم صلی اللہ علیہ وسلم سے کہا کہ جو کچھ آپ مانگیں ہم جزیہ دینے کے لیے تیار ہیں۔ آپ ہمارے ساتھ کوئی امین بھیج دیجئیے، جو بھی آدمی ہمارے ساتھ بھیجیں وہ امین ہونا ضروری ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں تمہارے ساتھ ایک ایسا آدمی بھیجوں گا جو امانت دار ہو گا بلکہ پورا پورا امانت دار ہو گا۔ صحابہ رضی اللہ عنہم نبی کریم صلی اللہ علیہ وسلم کے منتظر تھے، آپ نے فرمایا کہ ابوعبیدہ بن الجراح! اٹھو۔ جب وہ کھڑے ہوئے تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ اس امت کے امین ہیں۔' WHERE id = 4188;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، کہا ہم سے ابوالزناد نے بیان کیا، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تمہارے یہاں اہل یمن آئے ہیں جو نرم دل رقیق القلب ہیں، دین کی سمجھ یمن والوں میں ہے اور حکمت بھی یمن کی ہے۔' WHERE id = 4198;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن رافع نے بیان کیا، کہا ہم سے سریج بن نعمان نے بیان کیا، ان سے فلیح بن سلیمان نے بیان کیا ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہا نے بیان کیا کہ فتح مکہ کے دن نبی کریم صلی اللہ علیہ وسلم تشریف لائے، آپ صلی اللہ علیہ وسلم کی قصواء اونٹنی پر پیچھے اسامہ رضی اللہ عنہ بیٹھے ہوئے تھے اور آپ کے ساتھ بلال اور عثمان بن طلحہ رضی اللہ عنہما بھی تھے آپ نے کعبہ کے پاس اپنی اونٹنی بٹھا دی اور عثمان رضی اللہ عنہ سے فرمایا کہ کعبہ کی کنجی لاؤ، وہ کنجی لائے اور دروازہ کھولا۔ آپ اندر داخل ہوئے تو آپ صلی اللہ علیہ وسلم کے ساتھ اسامہ، بلال اور عثمان رضی اللہ عنہم بھی اندر گئے، پھر دروازہ اندر سے بند کر لیا اور دیر تک اندر ( نماز اور دعاؤں میں مشغول ) رہے۔ جب آپ صلی اللہ علیہ وسلم باہر تشریف لائے تو لوگ اندر جانے کے لیے ایک دوسرے سے آگے بڑھنے لگے اور میں سب سے آگے بڑھ گیا۔ میں نے دیکھا کہ بلال رضی اللہ عنہ دروازے کے پیچھے کھڑے ہوئے ہیں۔ میں نے ان سے پوچھا کہ نبی کریم صلی اللہ علیہ وسلم نے نماز کہاں پڑھی تھی؟ انہوں نے بتایا کہ خانہ کعبہ میں چھ ستون تھے۔ دو قطاروں میں اور آپ صلی اللہ علیہ وسلم نے آگے کی قطار کے دو ستونوں کے درمیان نماز پڑھی تھی۔ کعبہ کا دروازہ آپ صلی اللہ علیہ وسلم کی پیٹھ کی طرف تھا اور چہرہ مبارک اس طرف تھا، جدھر دروازے سے اندر جاتے ہوئے چہرہ کرنا پڑتا ہے۔ آپ کے اور دیوار کے درمیان ( تین ہاتھ کا فاصلہ تھا ) ۔ ابن عمر رضی اللہ عنہما نے بیان کیا کہ یہ پوچھنا میں بھول گیا کہ نبی کریم صلی اللہ علیہ وسلم نے کتنی رکعت نماز پڑھی تھی۔ جس جگہ آپ نے نماز پڑھی تھی وہاں سرخ سنگ مرمر بچھا ہوا تھا۔' WHERE id = 4208;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن قزعہ نے بیان کیا، انہوں نے کہا ہم سے امام مالک نے بیان کیا، ان سے شہاب نے بیان کیا (دوسری سند) اور لیث بن سعد نے بیان کیا کہ مجھ سے یونس نے بیان کیا، ان سے ابن شہاب نے بیان کیا، ان سے عبیداللہ بن عبداللہ نے بیان کیا اور انہیں عبداللہ بن عباس رضی اللہ عنہما نے خبر دی کہ وہ ایک گدھے پر سوار ہو کر آئے تو رسول اللہ صلی اللہ علیہ وسلم منیٰ میں کھڑے لوگوں کو نماز پڑھا رہے تھے۔ یہ حجۃ الوداع کا موقع تھا۔ ان کا گدھا صف کے کچھ حصے سے گزرا، پھر وہ اتر کر لوگوں کے ساتھ صف میں کھڑے ہو گئے۔' WHERE id = 4219;
UPDATE hadiths SET urdu = 'ہم سے خالد بن مخلد نے بیان کیا، کہا ہم سے سلیمان بن بلال نے بیان کیا، کہا کہ مجھ سے عمرو بن یحییٰ نے بیان کیا، ان سے عباس بن سہل بن سعد نے اور ان سے ابوحمید رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم کے ساتھ ہم غزوہ تبوک سے واپس آ رہے تھے۔ جب آپ مدینہ کے قریب پہنچے تو ( مدینہ کی طرف اشارہ کر کے ) فرمایا کہ یہ «طابة» ہے اور یہ احد پہاڑ ہے، یہ ہم سے محبت رکھتا ہے اور ہم اس سے محبت رکھتے ہیں۔' WHERE id = 4229;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، انہوں نے کہا ہم سے عبدالرزاق بن ہمام نے بیان کیا، انہیں معمر نے خبر دی، انہیں زہری نے، انہیں عبیداللہ بن عبداللہ بن عتبہ نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ جب رسول اللہ صلی اللہ علیہ وسلم کی وفات کا وقت قریب ہوا تو گھر میں بہت سے صحابہ رضی اللہ عنہم موجود تھے۔ نبی کریم صلی اللہ علیہ وسلم نے ارشاد فرمایا کہ لاؤ، میں تمہارے لیے ایک دستاویز لکھ دوں، اگر تم اس پر چلتے رہے تو پھر تم گمراہ نہ ہو سکو گے۔ اس پر ( عمر رضی اللہ عنہ ) نے کہا کہ نبی کریم صلی اللہ علیہ وسلم پر بیماری کی سختی ہو رہی ہے، تمہارے پاس قرآن موجود ہے۔ ہمارے لیے تو اللہ کی کتاب بس کافی ہے۔ پھر گھر والوں میں جھگڑا ہونے لگا، بعض نے تو یہ کہا کہ نبی کریم صلی اللہ علیہ وسلم کو کوئی چیز لکھنے کی دے دو کہ اس پر آپ ہدایت لکھوا دیں اور تم اس کے بعد گمراہ نہ ہو سکو۔ بعض لوگوں نے اس کے خلاف دوسری رائے پر اصرار کیا۔ جب شور و غل اور نزاع زیادہ ہوا تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہاں سے جاؤ۔ عبیداللہ نے بیان کیا کہ ابن عباس رضی اللہ عنہما کہتے تھے کہ مصیبت سب سے بڑی یہ تھی کہ لوگوں نے اختلاف اور شور کر کے آپ صلی اللہ علیہ وسلم کو وہ ہدایت نہیں لکھنے دی۔' WHERE id = 4239;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، کہا کہ مجھ سے یزید بن الہاد نے بیان کیا، ان سے عبدالرحمٰن بن قاسم نے، ان سے ان کے والد قاسم بن محمد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کی وفات ہوئی تو آپ میری ہنسلی اور ٹھوڑی کے درمیان ( سر رکھے ہوئے ) تھے۔ آپ صلی اللہ علیہ وسلم ( کی شدت سکرات ) دیکھنے کے بعد اب میں کسی کے لیے بھی نزع کی شدت کو برا نہیں سمجھتی۔' WHERE id = 4251;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے ثابت بنانی نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ شدت مرض کے زمانے میں نبی کریم صلی اللہ علیہ وسلم کی بے چینی بہت بڑھ گئی تھی۔ فاطمۃالزہراء رضی اللہ عنہا نے کہا: آہ، ابا جان کو کتنی بے چینی ہے۔ آپ صلی اللہ علیہ وسلم نے اس پر فرمایا کہ آج کے بعد تمہارے ابا جان کی یہ بے چینی نہیں رہے گی۔ پھر جب نبی کریم صلی اللہ علیہ وسلم کی وفات ہو گئی تو فاطمہ رضی اللہ عنہا کہتی تھیں، ہائے ابا جان! آپ اپنے رب کے بلاوے پر چلے گئے، ہائے ابا جان! آپ جنت الفردوس میں اپنے مقام پر چلے گئے۔ ہم جبرائیل علیہ السلام کو آپ کی وفات کی خبر سناتے ہیں۔ پھر جب نبی کریم صلی اللہ علیہ وسلم دفن کر دئیے گئے تو آپ رضی اللہ عنہا نے انس رضی اللہ عنہ سے کہا ”انس! تمہارے دل رسول اللہ صلی اللہ علیہ وسلم کی نعش پر مٹی ڈالنے کے لیے کس طرح آمادہ ہو گئے تھے۔“' WHERE id = 4263;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے شعبہ نے بیان کیا کہ مجھ سے خبیب بن عبدالرحمٰن نے بیان کیا، ان سے حفص بن عاصم نے اور ان سے ابوسعید بن معلی رضی اللہ عنہ نے بیان کیا کہ میں مسجد میں نماز پڑھ رہا تھا، رسول اللہ صلی اللہ علیہ وسلم نے مجھے اسی حالت میں بلایا، میں نے کوئی جواب نہیں دیا ( پھر بعد میں، میں نے حاضر ہو کر ) عرض کیا: یا رسول اللہ! میں نماز پڑھ رہا تھا۔ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا کہ کیا اللہ تعالیٰ نے تم سے نہیں فرمایا ہے «استجيبوا لله وللرسول إذا دعاكم‏» ”اللہ اور اس کے رسول جب تمہیں بلائیں تو ہاں میں جواب دو۔“ پھر آپ صلی اللہ علیہ وسلم نے مجھ سے فرمایا کہ آج میں تمہیں مسجد سے نکلنے سے پہلے ایک ایسی سورت کی تعلیم دوں گا جو قرآن کی سب سے بڑی سورت ہے۔ پھر آپ نے میرا ہاتھ اپنے ہاتھ میں لیا اور جب آپ باہر نکلنے لگے تو میں نے یاد دلایا کہ آپ نے مجھے قرآن کی سب سے بڑی سورت بتانے کا وعدہ کیا تھا۔ آپ صلی اللہ علیہ وسلم نے فرمایا «الحمد لله رب العالمين‏» یہی وہ سبع مثانی اور قرآن عظیم ہے جو مجھے عطا کیا گیا ہے۔' WHERE id = 4274;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، انہوں نے کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے ابن شہاب نے، ان سے سالم بن عبداللہ نے، ان سے عبداللہ بن محمد بن ابی بکر نے، ان سے عبداللہ بن عمر رضی اللہ عنہما نے اور ان سے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”دیکھتی نہیں ہو کہ جب تمہاری قوم ( قریش ) نے کعبہ کی تعمیر کی تو ابراہیم علیہ السلام کی بنیادوں سے اسے کم کر دیا۔“ میں نے عرض کیا: یا رسول اللہ! پھر آپ ابراہیم علیہ السلام کی بنیادوں کے مطابق پھر سے کعبہ کی تعمیر کیوں نہیں کروا دیتے۔ آپ صلی اللہ علیہ وسلم نے فرمایا ”اگر تمہاری قوم ابھی نئی نئی کفر سے نکلی نہ ہوتی ( تو میں ایسا ہی کرتا ) ۔ عبداللہ بن عمر رضی اللہ عنہما نے کہا، جب کہ عائشہ رضی اللہ عنہا نے کہا کہ میں نے یہ حدیث رسول اللہ صلی اللہ علیہ وسلم سے سنی ہے تو میں سمجھتا ہوں کہ آپ صلی اللہ علیہ وسلم نے ان دو رکنوں کا جو حطیم کے قریب ہیں ( طواف کے وقت ) چھونا اسی لیے چھوڑا تھا کہ بیت اللہ کی تعمیر ابراہیم علیہ السلام کی بنیاد کے مطابق مکمل نہیں تھی۔' WHERE id = 4284;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، ان سے امام مالک نے، ان سے عبداللہ بن دینار نے اور ان سے ابن عمر رضی اللہ عنہما نے بیان کیا کہ ابھی لوگ مسجد قباء میں صبح کی نماز پڑھ ہی رہے تھے کہ ایک آنے والے صاحب آئے اور کہا کہ رات کو رسول اللہ صلی اللہ علیہ وسلم پر قرآن نازل ہوا ہے اور آپ کو کعبہ کی طرف منہ کرنے کا حکم ہوا ہے۔ اس لیے آپ لوگ بھی اسی طرف منہ کر لیں۔ وہ لوگ شام کی طرف منہ کر کے نماز پڑھ رہے تھے لیکن اسی وقت کعبہ کی طرف پھر گئے۔' WHERE id = 4294;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن مثنیٰ نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، کہا ہم سے ہشام نے بیان کیا، کہا کہ مجھے میرے والد نے خبر دی اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ عاشوراء کے دن قریش زمانہ جاہلیت میں روزے رکھتے تھے اور نبی کریم صلی اللہ علیہ وسلم بھی اس دن روزہ رکھتے تھے۔ جب آپ صلی اللہ علیہ وسلم مدینہ تشریف لائے تو یہاں بھی آپ صلی اللہ علیہ وسلم نے اس دن روزہ رکھا اور صحابہ رضی اللہ عنہم کو بھی اس کے رکھنے کا حکم دیا، لیکن جب رمضان کے روزوں کا حکم نازل ہوا تو رمضان کے روزے فرض ہو گئے اور عاشوراء کے روزہ ( کی فرضیت ) باقی نہیں رہی۔ اب جس کا جی چاہے اس دن بھی روزہ رکھے اور جس کا جی چاہے نہ رکھے۔' WHERE id = 4304;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے، ان سے عبدالرحمٰن بن اصبہانی نے، کہا میں نے عبداللہ بن معقل سے سنا، انہوں نے بیان کیا کہ میں کعب بن عجرہ رضی اللہ عنہ کی خدمت میں اس مسجد میں حاضر ہوا، ان کی مراد کوفہ کی مسجد سے تھی اور ان سے روزے کے فدیہ کے متعلق پوچھا۔ انہوں نے بیان کیا کہ مجھے احرام میں رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں لوگ لے گئے اور جوئیں ( سر سے ) میرے چہرے پر گر رہی تھیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ میرا خیال یہ نہیں تھا کہ تم اس حد تک تکلیف میں مبتلا ہو گئے ہو تم کوئی بکری نہیں مہیا کر سکتے؟ میں نے عرض کیا کہ نہیں۔ فرمایا، پھر تین دن کے روزے رکھ لو یا چھ مسکینوں کو کھانا کھلا دو، ہر مسکین کو آدھا صاع کھانا کھلانا اور اپنا سر منڈوا لو۔ کعب رضی اللہ عنہ نے کہا تو یہ آیت خاص میرے بارے میں نازل ہوئی تھی اور اس کا حکم تم سب کے لیے عام ہے۔' WHERE id = 4315;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن راہویہ نے بیان کیا، کہا ہم سے روح بن عبادہ نے بیان کیا، کہا ہم سے شبل بن عباد نے بیان کیا، ان سے ابن ابی نجیح نے اور انہوں نے مجاہد سے آیت «والذين يتوفون منكم ويذرون أزواجا‏» ”اور تم میں سے جو لوگ وفات پا جاتے ہیں اور بیویاں چھوڑ جاتے ہیں۔“ کے بارے میں ( زمانہ جاہلیت کی طرح ) کہا کہ عدت ( یعنی چار مہینے دس دن کی ) تھی جو شوہر کے گھر عورت کو گزارنی ضروری تھی۔ پھر اللہ تعالیٰ نے یہ آیت نازل کی «والذين يتوفون منكم ويذرون أزواجا وصية لأزواجهم متاعا إلى الحول غير إخراج فإن خرجن فلا جناح عليكم فيما فعلن في أنفسهن من معروف‏» ”اور جو لوگ تم میں سے وفات پا جائیں اور بیویاں چھوڑ جائیں ان کو چاہیے کہ اپنی بیویوں کے حق میں نفع اٹھانے کی وصیت ( کر جائیں ) کہ وہ ایک سال تک گھر سے نہ نکالی جائیں، لیکن اگر وہ ( خود ) نکل جائیں تو کوئی گناہ تم پر نہیں۔ اگر وہ دستور کے موافق اپنے لیے کوئی کام کریں۔“ فرمایا کہ اللہ تعالیٰ نے عورت کے لیے سات مہینے اور بیس دن وصیت کے قرار دیئے کہ اگر وہ اس مدت میں چاہے تو اپنے لیے وصیت کے مطابق ( شوہر کے گھر میں ہی ) ٹھہرے اور اگر چاہے تو کہیں اور چلی جائے کہ اگر ایسی عورت کہیں اور چلی جائے تو تمہارے حق میں کوئی گناہ نہیں۔ پس عدت کے ایام تو وہی ہیں جنہیں گزارنا اس پر ضروری ہے ( یعنی چار مہینے دس دن ) ۔ شبل نے کہا ابن ابی نجیح نے مجاہد سے ایسا ہی نقل کیا ہے اور عطا بن ابی رباح نے کہا کہ ابن عباس رضی اللہ عنہما نے کہا، اس آیت نے اس رسم کو منسوخ کر دیا کہ عورت اپنے خاوند کے گھر والوں کے پاس عدت گزارے۔ اس آیت کی رو سے عورت کو اختیار ملا جہاں چاہے وہاں عدت گزارے اور اللہ پاک کے قول «غير إخراج‏» کا یہی مطلب ہے۔ عطا نے کہا، عورت اگر چاہے تو اپنے خاوند کے گھر والوں میں عدت گزارے اور خاوند کی وصیت کے موافق اسی کے گھر میں رہے اور اگر چاہے تو وہاں سے نکل جائے کیونکہ اللہ تعالیٰ نے فرمایا «فلا جناح عليكم فيما فعلن‏» ”اگر وہ نکل جائیں تو دستور کے موافق اپنے حق میں جو بات کریں اس میں کوئی گناہ تم پر نہ ہو گا۔“ عطاء نے کہا کہ پھر میراث کا حکم نازل ہوا جو سورۃ نساء میں ہے اور اس نے ( عورت کے لیے ) گھر میں رکھنے کے حکم کو منسوخ قرار دیا۔ اب عورت جہاں چاہے عدت گزار سکتی ہے۔ اسے مکان کا خرچہ دینا ضروری نہیں اور محمد بن یوسف نے روایت کیا، ان سے ورقاء بن عمرو نے بیان کیا، ان سے ابن ابی نجیح نے اور ان سے مجاہد نے، یہی قول بیان کیا اور فرزندان ابن ابی نجیح سے نقل کیا، ان سے عطاء بن ابی رباح نے بیان کیا اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ اس آیت نے صرف شوہر کے گھر میں عدت کے حکم کو منسوخ قرار دیا ہے۔ اب وہ جہاں چاہے عدت گزار سکتی ہے۔ جیسا کہ اللہ تعالیٰ کے ارشاد «غير إخراج‏» وغیرہ سے ثابت ہے۔' WHERE id = 4327;
UPDATE hadiths SET urdu = 'ہم سے بشر بن خالد نے بیان کیا، انہوں نے کہا ہم کو محمد بن جعفر نے خبر دی، انہیں شعبہ نے، انہیں سلیمان اعمش نے، انہوں نے کہا کہ میں نے ابوالضحیٰ سے سنا، وہ مسروق سے روایت کرتے تھے کہ ان سے عائشہ رضی اللہ عنہا نے بیان کیا جب سورۃ البقرہ کی آخری آیتیں نازل ہوئیں تو رسول اللہ صلی اللہ علیہ وسلم باہر تشریف لائے اور مسجد میں انہیں پڑھ کر سنایا اس کے بعد شراب کی تجارت حرام ہو گئی۔' WHERE id = 4337;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا ہم سے ہشام نے، ان سے معمر نے (دوسری سند) امام بخاری رحمہ اللہ نے کہا کہ اور مجھ سے عبداللہ بن محمد مسندی نے بیان کیا، کہا ہم کو عبدالرزاق نے خبر دی، کہا ہم کو معمر نے خبر دی، ان سے امام زہری نے بیان کیا، انہیں عبیداللہ بن عبداللہ بن عتبہ نے خبر دی، کہا کہ مجھ سے ابن عباس رضی اللہ عنہما نے بیان کیا، کہا کہ مجھ سے ابوسفیان رضی اللہ عنہ نے منہ در منہ بیان کیا، انہوں نے بتلایا کہ جس مدت میں میرے اور رسول اللہ صلی اللہ علیہ وسلم کے درمیان صلح ( صلح حدیبیہ کے معاہدہ کے مطابق ) تھی، میں ( سفر تجارت پر شام میں ) گیا ہوا تھا کہ نبی کریم صلی اللہ علیہ وسلم کا خط ہرقل کے پاس پہنچا۔ انہوں نے بیان کیا کہ دحیہ الکلبی رضی اللہ عنہ وہ خط لائے تھے اور عظیم بصریٰ کے حوالے کر دیا تھا اور ہرقل کے پاس اسی سے پہنچا تھا۔ ابوسفیان رضی اللہ عنہ نے بیان کیا کہ ہرقل نے پوچھا کیا ہمارے حدود سلطنت میں اس شخص کی قوم کے بھی کچھ لوگ ہیں جو نبی ہونے کا دعویدار ہے؟ درباریوں نے بتایا کہ جی ہاں موجود ہیں۔ ابوسفیان رضی اللہ عنہ نے بیان کیا کہ پھر مجھے قریش کے چند دوسرے آدمیوں کے ساتھ بلایا گیا۔ ہم ہرقل کے دربار میں داخل ہوئے اور اس کے سامنے ہمیں بٹھا دیا گیا۔ اس نے پوچھا، تم لوگوں میں اس شخص سے زیادہ قریبی کون ہے جو نبی ہونے کا دعویٰ کرتا ہے؟ ابوسفیان رضی اللہ عنہ نے بیان کیا کہ میں نے کہا کہ میں زیادہ قریب ہوں۔ اب درباریوں نے مجھے بادشاہ کے بالکل قریب بٹھا دیا اور میرے دوسرے ساتھیوں کو میرے پیچھے بٹھا دیا۔ اس کے بعد ترجمان کو بلایا اور اس سے ہرقل نے کہا کہ انہیں بتاؤ کہ میں اس شخص کے بارے میں تم سے کچھ سوالات کروں گا، جو نبی ہونے کا دعویدار ہے، اگر یہ ( یعنی ابوسفیان رضی اللہ عنہ ) جھوٹ بولے تو تم اس کے جھوٹ کو ظاہر کر دینا۔ ابوسفیان رضی اللہ عنہ کا بیان تھا کہ اللہ کی قسم! اگر مجھے اس کا خوف نہ ہوتا کہ میرے ساتھی کہیں میرے متعلق جھوٹ بولنا نقل نہ کر دیں تو میں ( نبی کریم صلی اللہ علیہ وسلم کے بارے میں ) ضرور جھوٹ بولتا۔ پھر ہرقل نے اپنے ترجمان سے کہا کہ اس سے پوچھو کہ جس نے نبی ہونے کا دعویٰ کیا ہے وہ اپنے نسب میں کیسے ہیں؟ ابوسفیان رضی اللہ عنہ نے بتلایا کہ ان کا نسب ہم میں بہت ہی عزت والا ہے۔ اس نے پوچھا کیا ان کے باپ دادا میں کوئی بادشاہ بھی ہوا ہے؟ بیان کیا کہ میں نے کہا، نہیں۔ اس نے پوچھا، تم نے دعویٰ نبوت سے پہلے کبھی ان پر جھوٹ کی تہمت لگائی تھی؟ میں نے کہا نہیں۔ پوچھا ان کی پیروی معزز لوگ زیادہ کرتے ہیں یا کمزور؟ میں نے کہا کہ قوم کے کمزور لوگ زیادہ ہیں۔ اس نے پوچھا، ان کے ماننے والوں میں زیادتی ہوتی رہتی ہے یا کمی؟ میں نے کہا کہ نہیں بلکہ زیادتی ہوتی رہتی ہے۔ پوچھا کبھی ایسا بھی کوئی واقعہ پیش آیا ہے کہ کوئی شخص ان کے دین کو قبول کرنے کے بعد پھر ان سے بدگمان ہو کر ان سے پھر گیا ہو؟ میں نے کہا ایسا بھی کبھی نہیں ہوا۔ اس نے پوچھا، تم نے کبھی ان سے جنگ بھی کی ہے؟ میں نے کہا کہ ہاں۔ اس نے پوچھا، تمہاری ان کے ساتھ جنگ کا کیا نتیجہ رہا؟ میں نے کہا کہ ہماری جنگ کی مثال ایک ڈول کی ہے کہ کبھی ان کے ہاتھ میں اور کبھی ہمارے ہاتھ میں۔ اس نے پوچھا، کبھی انہوں نے تمہارے ساتھ کوئی دھوکا بھی کیا؟ میں نے کہا کہ اب تک تو نہیں کیا، لیکن آج کل بھی ہمارا ان سے ایک معاہدہ چل رہا ہے، نہیں کہا جا سکتا کہ اس میں ان کا طرز عمل کیا رہے گا۔ ابوسفیان رضی اللہ عنہ نے بیان کیا کہ اللہ کی قسم! اس جملہ کے سوا اور کوئی بات میں اس پوری گفتگو میں اپنی طرف سے نہیں ملا سکا، پھر اس نے پوچھا اس سے پہلے بھی یہ دعویٰ تمہارے یہاں کسی نے کیا تھا؟ میں نے کہا کہ نہیں۔ اس کے بعد ہرقل نے اپنے ترجمان سے کہا، اس سے کہو کہ میں نے تم سے نبی کے نسب کے بارے میں پوچھا تو تم نے بتایا کہ وہ تم لوگوں میں باعزت اور اونچے نسب کے سمجھے جاتے ہیں، انبیاء کا بھی یہی حال ہے۔ ان کی بعثت ہمیشہ قوم کے صاحب حسب و نسب خاندان میں ہوتی ہے اور میں نے تم سے پوچھا تھا کہ کیا کوئی ان کے باپ دادوں میں بادشاہ گزرا ہے، تو تم نے اس کا انکار کیا میں اس سے اس فیصلہ پر پہنچا کہ اگر ان کے باپ دادوں میں کوئی بادشاہ گزرا ہوتا تو ممکن تھا کہ وہ اپنی خاندانی سلطنت کو اس طرح واپس لینا چاہتے ہوں اور میں نے تم سے ان کی اتباع کرنے والوں کے متعلق پوچھا کہ آیا وہ قوم کے کمزور لوگ ہیں یا اشراف، تو تم نے بتایا کہ کمزور لوگ ان کی پیروی کرنے والوں میں ( زیادہ ) ہیں۔ یہی طبقہ ہمیشہ سے انبیاء کی اتباع کرتا رہا ہے اور میں نے تم سے پوچھا تھا کہ کیا تم نے دعویٰ نبوت سے پہلے ان پر جھوٹ کا کبھی شبہ کیا تھا، تو تم نے اس کا بھی انکار کیا۔ میں نے اس سے یہ سمجھا کہ جس شخص نے لوگوں کے معاملہ میں کبھی جھوٹ نہ بولا ہو، وہ اللہ کے معاملے میں کس طرح جھوٹ بول دے گا اور میں نے تم سے پوچھا تھا کہ ان کے دین کو قبول کرنے کے بعد پھر ان سے بدگمان ہو کر کوئی شخص ان کے دین سے کبھی پھرا بھی ہے، تو تم نے اس کا بھی انکار کیا۔ ایمان کا یہی اثر ہوتا ہے جب وہ دل کی گہرائیوں میں اتر جائے۔ میں نے تم سے پوچھا تھا کہ ان کے ماننے والوں کی تعداد بڑھتی رہتی ہے یا کم ہوتی ہے، تو تم نے بتایا کہ ان میں اضافہ ہی ہوتا ہے، ایمان کا یہی معاملہ ہے، یہاں تک کہ وہ کمال کو پہنچ جائے۔ میں نے تم سے پوچھا تھا کہ کیا تم نے کبھی ان سے جنگ بھی کی ہے؟ تو تم نے بتایا کہ جنگ کی ہے اور تمہارے درمیان لڑائی کا نتیجہ ایسا رہا ہے کہ کبھی تمہارے حق میں اور کبھی ان کے حق میں۔ انبیاء کا بھی یہی معاملہ ہے، انہیں آزمائش میں ڈالا جاتا ہے اور آخر انجام انہیں کے حق میں ہوتا ہے اور میں نے تم سے پوچھا تھا کہ اس نے تمہارے ساتھ کبھی خلاف عہد بھی معاملہ کیا ہے تو تم نے اس سے بھی انکار کیا۔ انبیاء کبھی عہد کے خلاف نہیں کرتے اور میں نے تم سے پوچھا تھا کہ کیا تمہارے یہاں اس طرح کا دعویٰ پہلے بھی کسی نے کیا تھا تو تم نے کہا کہ پہلے کسی نے اس طرح کا دعویٰ نہیں کیا، میں اس سے اس فیصلے پر پہنچا کہ اگر کسی نے تمہارے یہاں اس سے پہلے اس طرح کا دعویٰ کیا ہوتا تو یہ کہا جا سکتا تھا کہ یہ بھی اسی کی نقل کر رہے ہیں۔ بیان کیا کہ پھر ہرقل نے پوچھا وہ تمہیں کن چیزوں کا حکم دیتے ہیں؟ میں نے کہا نماز، زکوٰۃ، صلہ رحمی اور پاکدامنی کا۔ آخر اس نے کہا کہ جو کچھ تم نے بتایا ہے اگر وہ صحیح ہے تو یقیناً وہ نبی ہیں اس کا علم تو مجھے بھی تھا کہ ان کی نبوت کا زمانہ قریب ہے لیکن یہ خیال نہ تھا کہ وہ تمہاری قوم میں ہوں گے۔ اگر مجھے ان تک پہنچ سکنے کا یقین ہوتا تو میں ضرور ان سے ملاقات کرتا اور اگر میں ان کی خدمت میں ہوتا تو ان کے قدموں کو دھوتا اور ان کی حکومت میرے ان دو قدموں تک پہنچ کر رہے گی۔ ابوسفیان رضی اللہ عنہ نے بیان کیا کہ پھر اس نے رسول اللہ صلی اللہ علیہ وسلم کا خط منگوایا اور اسے پڑھا، اس میں یہ لکھا ہوا تھا، اللہ، رحمن، رحیم کے نام سے شروع کرتا ہوں۔ اللہ کے رسول صلی اللہ علیہ وسلم کی طرف سے عظیم روم ہرقل کی طرف، سلامتی ہو اس پر جو ہدایت کی اتباع کرے۔ امابعد! میں تمہیں اسلام کی طرف بلاتا ہوں، اسلام لاؤ تو سلامتی پاؤ گے اور اسلام لاؤ تو اللہ تمہیں دوہرا اجر دے گا۔ لیکن تم نے اگر منہ موڑا تو تمہاری رعایا ( کے کفر کا بار بھی سب ) تم پر ہو گا اور اے کتاب والو! ایک ایسی بات کی طرف آ جاؤ جو ہم میں اور تم میں برابر ہے، وہ یہ کہ ہم سوائے اللہ کے اور کسی کی عبادت نہ کریں۔ اللہ تعالیٰ کے فرمان «اشهدوا بأنا مسلمون‏» تک جب ہرقل خط پڑھ چکا تو دربار میں بڑا شور برپا ہو گیا اور پھر ہمیں دربار سے باہر کر دیا گیا۔ باہر آ کر میں نے اپنے ساتھیوں سے کہا کہ ابن ابی کبشہ کا معاملہ تو اب اس حد تک پہنچ چکا ہے کہ ملک بنی الاصفر ( ہرقل ) بھی ان سے ڈرنے لگا۔ اس واقعہ کے بعد مجھے یقین ہو گیا کہ نبی کریم صلی اللہ علیہ وسلم غالب آ کر رہیں گے اور آخر اللہ تعالیٰ نے اسلام کی روشنی میرے دل میں بھی ڈال ہی دی۔ زہری نے کہا کہ پھر ہرقل نے روم کے سرداروں کو بلا کر ایک خاص کمرے میں جمع کیا، پھر ان سے کہا اے رومیو! کیا تم ہمیشہ کے لیے اپنی فلاح اور بھلائی چاہتے ہو اور یہ کہ تمہارا ملک تمہارے ہی ہاتھ میں رہے ( اگر تم ایسا چاہتے ہو تو اسلام قبول کر لو ) راوی نے بیان کیا کہ یہ سنتے ہی وہ سب وحشی جانوروں کی طرح دروازے کی طرف بھاگے، دیکھا تو دروازہ بند تھا، پھر ہرقل نے سب کو اپنے پاس بلایا کہ انہیں میرے پاس لاؤ اور ان سے کہا کہ میں نے تو تمہیں آزمایا تھا کہ تم اپنے دین میں کتنے پختہ ہو، اب میں نے اس چیز کا مشاہدہ کر لیا جو مجھے پسند تھی۔ چنانچہ سب درباریوں نے اسے سجدہ کیا اور اس سے راضی ہو گئے۔' WHERE id = 4348;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، میں سمجھتا ہوں کہ انہوں نے یہ کہا کہ ہم سے ابوبکر شعبہ بن عیاش نے بیان کیا، ان سے ابوحصین عثمان بن عاصم نے اور ان سے ابوالضحیٰ نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ کلمہ «حسبنا الله ونعم الوكيل‏» ابراہیم علیہ السلام نے کہا تھا، اس وقت جب ان کو آگ میں ڈالا گیا تھا اور یہی کلمہ محمد صلی اللہ علیہ وسلم نے اس وقت کہا تھا جب لوگوں نے مسلمانوں کو ڈرانے کے لیے کہا تھا کہ لوگوں ( یعنی قریش ) نے تمہارے خلاف بڑا سامان جنگ اکٹھا کر رکھا ہے، ان سے ڈرو لیکن اس بات نے ان مسلمانوں کا ( جوش ) ایمان اور بڑھا دیا اور یہ مسلمان بولے کہ ہمارے لیے اللہ کافی ہے اور وہی بہترین کام بنانے والا ہے۔' WHERE id = 4358;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا ہم کو ہشام بن یوسف نے خبر دی، ان سے ابن جریج نے کہا، کہا مجھ کو ہشام بن عروہ نے خبر دی، انہیں ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ ایک آدمی کی پرورش میں ایک یتیم لڑکی تھی، پھر اس نے اس سے نکاح کر لیا، اس یتیم لڑکی کی ملکیت میں کھجور کا ایک باغ تھا۔ اسی باغ کی وجہ سے یہ شخص اس کی پرورش کرتا رہا حالانکہ دل میں اس سے کوئی خاص لگاؤ نہ تھا۔ اس سلسلے میں یہ آیت اتری «وإن خفتم أن لا تقسطوا في اليتامى‏» کہ ”اگر تمہیں اندیشہ ہو کہ تم یتیموں کے حق میں انصاف نہ کر سکو گے۔“ ہشام بن یوسف نے کہا میں سمجھتا ہوں، ابن جریج نے یوں کہا یہ لڑکی اس درخت اور دوسرے مال اسباب میں اس مرد کی حصہ دار تھی۔' WHERE id = 4368;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام بیکندی نے بیان کیا، کہا ہم کو عبدہ بن سلیمان نے خبر دی، انہیں ہشام بن عروہ نے، انہیں ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ ( مجھ سے ) اسماء رضی اللہ عنہا کا ایک ہار گم ہو گیا تو رسول اللہ صلی اللہ علیہ وسلم نے چند صحابہ رضی اللہ عنہم کو اسے تلاش کرنے کے لیے بھیجا۔ ادھر نماز کا وقت ہو گیا، نہ لوگ وضو سے تھے اور نہ پانی موجود تھا۔ اس لیے وضو کے بغیر نماز پڑھی گئی اس پر اللہ تعالیٰ نے تیمم کی آیت نازل کی۔' WHERE id = 4378;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے ابواسحاق نے اور ان سے براء بن عازب رضی اللہ عنہ نے کہا کہ جب آیت «لا يستوي القاعدون من المؤمنين‏» نازل ہوئی تو رسول اللہ صلی اللہ علیہ وسلم نے زید بن ثابت رضی اللہ عنہ کو کتابت کے لیے بلایا اور انہوں نے وہ آیت لکھ دی۔ پھر عبداللہ بن ام مکتوم رضی اللہ عنہ حاضر ہوئے اور اپنے نابینا ہونے کا عذر پیش کیا، تو اللہ تعالیٰ نے «غير أولي الضرر‏» کے الفاظ اور نازل کئے۔' WHERE id = 4388;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے سفیان ثوری نے بیان کیا، کہا ہم سے اعمش نے بیان کیا، ان سے ابووائل نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”کسی کے لیے مناسب نہیں کہ مجھے یونس بن متی سے بہتر کہے۔“' WHERE id = 4398;
UPDATE hadiths SET urdu = 'ہم سے علی بن سلمہ نے بیان کیا، کہا ہم سے مالک بن سعید نے بیان کیا، کہا ہم سے ہشام نے بیان کیا، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے کہ آیت «لا يؤاخذكم الله باللغو في أيمانكم‏» ”اللہ تم سے تمہاری فضول قسموں پر پکڑ نہیں کرتا۔“ کسی کے اس طرح قسم کھانے کے بارے میں نازل ہوئی تھی کہ نہیں، اللہ کی قسم، ہاں اللہ کی قسم!۔' WHERE id = 4408;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے بیان کیا، ان سے صالح بن کیسان نے، ان سے ابن شہاب نے اور ان سے سعید بن مسیب نے بیان کیا کہ «بحيرة» اس اونٹنی کو کہتے تھے جس کا دودھ بتوں کے لیے روک دیا جاتا اور کوئی شخص اس کے دودھ کو دوہنے کا مجاز نہ سمجھا جاتا اور «سائبة» اس اونٹنی کو کہتے تھے جسے وہ اپنے دیوتاؤں کے نام پر آزاد چھوڑ دیتے اور اس سے باربرداری و سواری وغیرہ کا کام نہ لیتے۔ سعید راوی نے بیان کیا کہ ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ میں نے عمرو بن عامر خزاعی کو دیکھا کہ وہ اپنی آنتوں کو جہنم میں گھسیٹ رہا تھا، اس نے سب سے پہلے سانڈ چھوڑنے کی رسم نکالی تھی۔ اور «وصيلة» اس جوان اونٹنی کو کہتے تھے جو پہلی مرتبہ مادہ بچہ جنتی اور پھر دوسری مرتبہ بھی مادہ ہی جنتی، اسے بھی وہ بتوں کے نام پر چھوڑ دیتے تھے لیکن اسی صورت میں جبکہ وہ برابر دو مرتبہ مادہ بچہ جنتی اور اس درمیان میں کوئی نر بچہ نہ ہوتا۔ اور «حام» وہ نر اونٹ جو مادہ پر شمار سے کئی دفعہ چڑھتا ( اس کے نطفے سے دس بچے پیدا ہو جاتے ) جب وہ اتنی صحبتیں کر چکتا تو اس کو بھی بتوں کے نام پر چھوڑ دیتے اور بوجھ لادنے سے معاف کر دیتے ( نہ سواری کرتے ) اس کا نام «حام» رکھتے اور ابوالیمان ( حکم بن نافع ) نے کہا ہم کو شعیب نے خبر دی، انہوں نے زہری سے سنا، کہا میں نے سعید بن مسیب سے یہی حدیث سنی جو اوپر گزری۔ سعید نے کہا ابوہریرہ رضی اللہ عنہ نے کہا میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا ( وہی عمرو بن عامر خزاعی کا قصہ جو اوپر گزرا ) اور یزید بن عبداللہ بن ہاد نے بھی اس حدیث کو ابن شہاب سے روایت کیا۔ انہوں نے سعید بن مسیب سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے، کہا میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا۔' WHERE id = 4418;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن خالد نے بیان کیا، کہا ہم سے لیث نے بیان کیا، ان سے یزید بن ابی حبیب نے کہ عطاء نے بیان کیا کہ انہوں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا انہوں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، نبی کریم صلی اللہ علیہ وسلم نے فرمایا، اللہ یہودیوں کو غارت کرے، جب اللہ تعالیٰ نے ان پر مردہ جانوروں کی چربی حرام کر دی تو اس کا تیل نکال کر اسے بیچنے اور کھانے لگے۔ اور ابوعاصم نے بیان کیا، ان سے عبدالحمید نے بیان کیا، ان سے یزید نے بیان کیا، انہیں عطاء نے لکھا تھا کہ میں نے جابر رضی اللہ عنہ سے سنا اور انہوں نے نبی کریم صلی اللہ علیہ وسلم سے۔' WHERE id = 4428;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ نے بیان کیا، کہا ہم سے وکیع نے بیان کیا، ان سے ہشام نے، ان سے ان کے والد نے اور ان سے عبداللہ بن زبیر رضی اللہ عنہما نے بیان کیا کہ آیت «خذ العفو وأمر بالعرف‏» ”معافی اختیار کیجئے اور نیک کام کا حکم دیتے رہئیے۔“ لوگوں کے اخلاق کی اصلاح کے لیے ہی نازل ہوئی ہے۔' WHERE id = 4438;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن عبداللہ سلمی نے بیان کیا، انہوں نے کہا ہم کو عبداللہ بن مبارک نے خبر دی، انہوں نے کہا ہم کو جریر بن حازم نے خبر دی، انہوں نے کہا کہ مجھے زبیر ابن خریت نے خبر دی، انہیں عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ جب یہ آیت اتری «إن يكن منكم عشرون صابرون يغلبوا مائتين‏» کہ ”اگر تم میں سے بیس آدمی بھی صبر کرنے والے ہوں گے تو وہ دو سو پر غالب آ جائیں گے۔“ تو مسلمانوں پر سخت گزرا کیونکہ اس آیت میں ان پر یہ فرض قرار دیا گیا تھا کہ ایک مسلمان دس کافروں کے مقابلے سے نہ بھاگے۔ اس لیے اس کے بعد تخفیف کی گئی۔ اور اللہ تعالیٰ نے فرمایا «الآن خفف الله عنكم وعلم أن فيكم ضعفا فإن يكن منكم مائة صابرة يغلبوا مائتين‏» کہ ”اب اللہ نے تم سے تخفیف کر دی اور معلوم کر لیا کہ تم میں جوش کی کمی ہے۔ سو اب اگر تم میں صبر کرنے والے ہوں گے تو وہ دو سو پر غالب آ جائیں گے۔“ ابن عباس رضی اللہ عنہما نے کہا کہ تعداد کی اس کمی سے اتنی ہی مسلمانوں کے صبر میں کمی ہو گئی۔' WHERE id = 4448;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد جعفی نے بیان کیا، کہا ہم سے حبان بن ہلال باہلی نے بیان کیا، کہا ہم سے ہمام بن یحییٰ نے بیان کیا، کہا ہم سے ثابت نے بیان کیا، کہا ہم سے انس بن مالک رضی اللہ عنہ نے بیان کیا، کہا کہ مجھ سے ابوبکر صدیق رضی اللہ عنہ نے بیان کیا: انہوں نے کہا کہ میں غار ثور میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ تھا۔ میں نے کافروں کے پاؤں دیکھے ( جو ہمارے سر پر کھڑے ہوئے تھے ) ابوبکر صدیق رضی اللہ عنہ گھبرا گئے اور بولے: یا رسول اللہ! اگر ان میں سے کسی نے ذرا بھی قدم اٹھائے تو وہ ہم کو دیکھ لے گا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ تو کیا سمجھتا ہے ان دو آدمیوں کو ( کوئی نقصان پہنچا سکے گا ) جن کے ساتھ تیسرا اللہ تعالیٰ ہو۔' WHERE id = 4458;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن سعید نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، ان سے عبدالرحمٰن بن عبداللہ نے اور ان سے عبداللہ بن کعب بن مالک نے بیان کیا کہ انہوں نے کعب بن مالک رضی اللہ عنہ سے ان کے غزوہ تبوک میں شریک نہ ہو سکنے کا واقعہ سنا۔ انہوں نے بتلایا، اللہ کی قسم! ہدایت کے بعد اللہ نے مجھ پر اتنا بڑا اور کوئی انعام نہیں کیا جتنا رسول اللہ صلی اللہ علیہ وسلم کے سامنے سچ بولنے کے بعد ظاہر ہوا تھا کہ اس نے مجھے جھوٹ بولنے سے بچایا، ورنہ میں بھی اسی طرح ہلاک ہو جاتا جس طرح دوسرے لوگ جھوٹی معذرتیں بیان کرنے والے ہلاک ہوئے تھے اور اللہ تعالیٰ نے ان کے بارے میں وحی نازل کی تھی «سيحلفون بالله لكم إذا انقلبتم إليهم‏» کہ ”عنقریب یہ لوگ تمہارے سامنے، جب تم ان کے پاس واپس جاؤ گے۔ اللہ کی قسم کھا جائیں گے۔“ آخر آیت «الفاسقين‏» تک۔' WHERE id = 4468;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن زبیر حمیدی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے، کہا ہم سے عمرو بن دینار نے بیان کیا، کہا کہ ابن عباس رضی اللہ عنہما نے آیت کی قرآت اس طرح کی تھی «ألا إنهم يثنون صدورهم ليستخفوا منه ألا حين يستغشون ثيابهم‏» اور عمرو بن دینار کے علاوہ اوروں نے بیان کیا ابن عباس رضی اللہ عنہما سے کہ «يستغشون‏» یعنی اپنے سر چھپا لیتے ہیں۔ «سيء بهم‏» یعنی اپنی قوم سے وہ بدگمان ہوا۔ «وضاق بهم‏» یعنی اپنے مہمانوں کو دیکھ کر وہ بدگمان ہوا کہ ان کی قوم انہیں بھی پریشان کرے گی۔ «بقطع من الليل‏» یعنی رات کی سیاہی میں اور مجاہد نے کہا «أنيب‏» کے معنی میں رجوع کرتا ہوں ( متوجہ ہوتا ہوں ) ۔' WHERE id = 4478;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن زبیر حمیدی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے اعمش نے، ان سے مسلم نے، ان سے مسروق نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے کہ قریش نے جب رسول اللہ صلی اللہ علیہ وسلم پر ایمان لانے میں تاخیر کی تو آپ نے ان کے حق میں بددعا کی کہ اے اللہ! ان پر یوسف علیہ السلام کے زمانہ کا سا قحط نازل فرما۔ چنانچہ ایسا قحط پڑا کہ کوئی چیز نہیں ملتی تھی اور وہ ہڈیوں کے کھانے پر مجبور ہو گئے تھے۔ لوگوں کی اس وقت یہ کیفیت تھی کہ آسمان کی طرف نظر اٹھا کے دیکھتے تھے تو بھوک و پیاس کی شدت سے دھواں سا نظر آتا تھا۔ اللہ تعالیٰ نے فرمایا «فارتقب يوم تأتي السماء بدخان مبين‏» ”تو آپ انتظار کیجئے اس روز کا جب آسمان کی طرف ایک نظر آنے والا دھواں پیدا ہو۔“ اور فرمایا «إنا كاشفو العذاب قليلا إنكم عائدون‏» ”بیشک ہم اس عذاب کو ہٹا لیں گے اور تم بھی ( اپنی پہلی حالت پر ) لوٹ آؤ گے۔“ ابن مسعود رضی اللہ عنہ نے کہا کہ عذاب سے یہی قحط کا عذاب مراد ہے کیونکہ آخرت کا عذاب کافروں سے ٹلنے والا نہیں ہے۔' WHERE id = 4488;
UPDATE hadiths SET urdu = 'مجھ سے یعقوب بن ابراہیم نے بیان کیا، انہوں نے کہا ہم سے ہشیم نے بیان کیا، انہیں ابوبشر نے خبر دی، انہیں سعید بن جبیر نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا آیت «الذين جعلوا القرآن عضين‏» ”جنہوں نے قرآن کے ٹکڑے کر رکھے ہیں“ کے متعلق کہا کہ اس سے مراد اہل کتاب ہیں کہ انہوں نے قرآن کے ٹکڑے ٹکڑے کر دیئے۔' WHERE id = 4500;
UPDATE hadiths SET urdu = 'ہم سے بشر بن خالد نے بیان کیا، انہوں نے کہا ہم کو محمد بن جعفر نے خبر دی، انہیں شعبہ نے، انہیں سلیمان اعمش نے، انہیں ابراہیم نخعی نے، انہیں ابومعمر نے اور انہیں عبداللہ بن مسعود رضی اللہ عنہ نے آیت «الذين يدعون يبتغون إلى ربهم الوسيلة‏» کی تفسیر میں کہا کہ کچھ جِن ایسے تھے جن کی آدمی پرستش کیا کرتے تھے پھر وہ جِن مسلمان ہو گئے۔' WHERE id = 4510;
UPDATE hadiths SET urdu = 'ہم سے عبدااللہ بن زبیر حمیدی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، کہا ہم سے عمرو بن دینار نے بیان کیا، کہا کہ مجھے سعید بن جبیر نے خبر دی، کہا کہ میں نے ابن عباس رضی اللہ عنہما سے کہا نوف بکالی کہتا ہے ( جو کعب احبار کا رہیب تھا ) کہ جن موسیٰ کی خضر کے ساتھ ملاقات ہوئی تھی وہ بنی اسرائیل کے ( رسول ) موسیٰ کے علاوہ دوسرے ہیں۔ ( یعنی موسیٰ بن میثا بن افراثیم بن یوسف بن یعقوب ) ابن عباس رضی اللہ عنہما نے کہا دشمن خدا نے غلط کہا۔ مجھ سے ابی بن کعب نے بیان کیا کہ انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم فرما رہے تھے کہ موسیٰ علیہ السلام بنی اسرائیل کو وعظ سنانے کے لیے کھڑے ہوئے تو ان سے پوچھا گیا کہ انسانوں میں سب سے زیادہ علم کسے ہے؟ انہوں نے فرمایا کہ مجھے۔ اس پر اللہ تعالیٰ نے ان پر غصہ کیا کیونکہ انہوں نے علم کو اللہ تعالیٰ کی طرف منسوب نہیں کیا تھا۔ اللہ تعالیٰ نے انہیں وحی کے ذریعہ بتایا کہ دو دریاؤں ( فارس اور روم ) کے سنگم پر میرا ایک بندہ ہے جو تم سے زیادہ علم رکھتا ہے۔ موسیٰ علیہ السلام نے عرض کیا: اے رب! میں ان تک کیسے پہنچ پاؤں گا؟ اللہ تعالیٰ نے بتایا کہ اپنے ساتھ ایک مچھلی لے لو اور اسے ایک زنبیل میں رکھ لو، وہ جہاں گم ہو جائے ( زندہ ہو کر دریا میں کود جائے ) بس میرا وہ بندہ وہیں ملے گا چنانچہ آپ نے مچھلی لی اور زنبیل میں رکھ کر روانہ ہوئے۔ آپ کے ساتھ آپ کے خادم یوشع بن نون بھی تھے۔ جب یہ دونوں چٹان کے پاس آئے تو سر رکھ کر سو گئے، ادھر مچھلی زنبیل میں تڑپی اور اس سے نکل گئی اور اس نے دریا میں اپنا راستہ پا لیا۔ مچھلی جہاں گری تھی اللہ تعالیٰ نے وہاں پانی کی روانی کو روک دیا اور پانی ایک طاق کی طرح اس پر بن گیا ( یہ حال یوشع اپنی آنکھوں سے دیکھ رہے تھے ) پھر جب موسیٰ علیہ السلام بیدار ہوئے تو یوشع ان کو مچھلی کے متعلق بتانا بھول گئے۔ اس لیے دن اور رات کا جو حصہ باقی تھا اس میں چلتے رہے، دوسرے دن موسیٰ علیہ السلام نے اپنے خادم سے فرمایا کہ اب کھانا لاؤ، ہم کو سفر نے بہت تھکا دیا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ موسیٰ علیہ السلام اس وقت تک نہیں تھکے جب تک وہ اس مقام سے نہ گزر چکے جس کا اللہ تعالیٰ نے انہیں حکم دیا تھا۔ اب ان کے خادم نے کہا آپ نے نہیں دیکھا جب ہم چٹان کے پاس تھے تو مچھلی کے متعلق بتانا بھول گیا تھا اور صرف شیطانوں نے یاد رہنے نہیں دیا۔ اس نے تو عجیب طریقہ سے اپنا راستہ بنا لیا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا: مچھلی نے تو دریا میں اپنا راستہ لیا اور موسیٰ اور ان کے خادم کو ( مچھلی کا جو نشان پانی میں اب تک موجود تھا ) دیکھ کر تعجب ہوا۔ موسیٰ علیہ السلام نے فرمایا کہ یہ وہی جگہ تھی جس کی تلاش میں ہم تھے، چنانچہ دونوں حضرات پیچھے اسی راستہ سے لوٹے۔ بیان کیا کہ دونوں حضرات پیچھے اپنے نقش قدم پر چلتے چلتے آخر اس چٹان تک پہنچ گئے وہاں انہوں نے دیکھا کہ ایک صاحب ( خضر علیہ السلام ) کپڑے میں لپٹے ہوئے وہاں بیٹھے ہیں۔ موسیٰ علیہ السلام نے انہیں سلام کیا۔ خضر علیہ السلام نے کہا ( تم کون ہو ) تمہارے ملک میں ”سلام“ کہاں سے آ گیا۔ موسیٰ علیہ السلام نے فرمایا کہ میں موسیٰ ہوں۔ پوچھا بنی اسرائیل کے موسیٰ؟ فرمایا کہ جی ہاں۔ آپ کے پاس اس غرض سے حاضر ہوا ہوں تاکہ جو ہدایت کا علم آپ کو حاصل ہے وہ مجھے بھی سکھا دیں۔ خضر علیہ السلام نے فرمایا، موسیٰ! آپ میرے ساتھ صبر نہیں کر سکتے مجھے اللہ تعالیٰ کی طرف سے ایک خاص علم ملا ہے جسے آپ نہیں جانتے، اسی طرح آپ کو اللہ تعالیٰ کی طرف سے جو علم ملا ہے وہ میں نہیں جانتا۔ موسیٰ علیہ السلام نے فرمایا ان شاءاللہ آپ مجھے صابر پائیں گے اور میں کسی معاملے میں آپ کے خلاف نہیں کروں گا۔ خضر علیہ السلام نے فرمایا، اچھا اگر آپ میرے ساتھ چلیں تو کسی چیز کے متعلق سوال نہ کریں یہاں تک کہ میں خود آپ کو اس کے متعلق بتا دوں گا۔ اب یہ دونوں سمندر کے کنارے کنارے روانہ ہوئے اتنے میں ایک کشتی گزری، انہوں نے کشتی والوں سے بات کی کہ انہیں بھی اس پر سوار کر لیں۔ کشتی والوں نے خضر علیہ السلام کو پہچان لیا اور کسی کرایہ کے بغیر انہیں سوار کر لیا۔ جب یہ دونوں کشتی پر بیٹھ گئے تو خضر علیہ السلام نے کلہاڑے سے کشتی کا ایک تختہ نکال ڈالا۔ اس پر موسیٰ علیہ السلام نے دیکھا تو خضر علیہ السلام سے کہا کہ ان لوگوں نے ہمیں بغیر کسی کرایہ کے اپنی کشتی میں سوار کر لیا تھا اور آپ نے انہیں کی کشتی چیر ڈالی تاکہ سارے مسافر ڈوب جائیں۔ بلاشبہ آپ نے یہ بڑا ناگوار کام کیا ہے۔ خضر علیہ السلام نے فرمایا، کیا میں نے آپ سے پہلے ہی نہ کہا تھا کہ آپ میرے ساتھ صبر نہیں کر سکتے۔ موسیٰ علیہ السلام نے فرمایا جو بات میں بھول گیا تھا اس پر مجھے معاف کر دیں اور میرے معاملہ میں تنگی نہ کریں۔ بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، یہ پہلی مرتبہ موسیٰ علیہ السلام نے بھول کر انہیں ٹوکا تھا۔ راوی نے بیان کیا کہ اتنے میں ایک چڑیا آئی اور اس نے کشتی کے کنارے بیٹھ کر سمندر میں ایک مرتبہ اپنی چونچ ماری تو خضر علیہ السلام نے موسیٰ علیہ السلام سے کہا کہ میرے اور آپ کے علم کی حیثیت اللہ کے علم کے مقابلے میں اس سے زیادہ نہیں ہے جتنا اس چڑیا نے اس سمندر کے پانی سے کم کیا ہے۔ پھر یہ دونوں کشتی سے اتر گئے، ابھی وہ سمندر کے کنارے چل ہی رہے تھے کہ خضر علیہ السلام نے ایک بچہ کو دیکھا جو دوسرے بچوں کے ساتھ کھیل رہا تھا۔ آپ نے اس بچے کا سر اپنے ہاتھ میں دبایا اور اسے ( گردن سے ) اکھاڑ دیا اور اس کی جان لے لی۔ موسیٰ علیہ السلام اس پر بولے، آپ نے ایک بےگناہ کی جان بغیر کسی جان کے بدلے کے لے لی، یہ آپ نے بڑا ناپسند کام کیا۔ خضر علیہ السلام نے فرمایا کہ میں تو پہلے ہی کہہ چکا تھا کہ آپ میرے ساتھ صبر نہیں کر سکتے۔ سفیان بن عیینہ ( راوی حدیث ) نے کہا اور یہ کام تو پہلے سے بھی زیادہ سخت تھا۔ موسیٰ علیہ السلام نے آخر اس مرتبہ بھی معذرت کی کہ اگر میں نے اس کے بعد پھر آپ سے سوال کیا تو آپ مجھے ساتھ نہ رکھئے گا۔ آپ میرا باربار عذر سن چکے ہیں ( اس کے بعد میرے لیے بھی عذر کا کوئی موقع نہ رہے گا ) پھر دونوں روانہ ہوئے، یہاں تک کہ ایک بستی میں پہنچے اور بستی والوں سے کہا کہ ہمیں اپنا مہمان بنا لو، لیکن انہوں نے میزبانی سے انکار کیا، پھر انہیں بستی میں ایک دیوار دکھائی دی جو بس گرنے ہی والی تھی۔ بیان کیا کہ دیوار جھک رہی تھی۔ خضر علیہ السلام کھڑے ہو گئے اور دیوار اپنے ہاتھ سے سیدھی کر دی۔ موسیٰ علیہ السلام نے فرمایا کہ ان لوگوں کے یہاں ہم آئے اور ان سے کھانے کے لیے کہا، لیکن انہوں نے ہماری میزبانی سے انکار کیا، اگر آپ چاہتے تو دیوار کے اس سیدھا کرنے کے کام پر اجرت لے سکتے تھے۔ خضر علیہ السلام نے فرمایا کہ بس اب میرے اور آپ کے درمیان جدائی ہے، اللہ تعالیٰ کے ارشاد «ذلك تأويل ما لم تسطع عليه صبرا‏» تک۔ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، ہم تو چاہتے تھے کہ موسیٰ نے صبر کیا ہوتا تاکہ اللہ تعالیٰ ان کے اور واقعات ہم سے بیان کرتا۔ سعید بن جبیر نے بیان کیا کہ عبداللہ بن عباس رضی اللہ عنہما اس آیت کی تلاوت کرتے تھے ( جس میں خضر علیہ السلام نے اپنے کاموں کی وجہ بیان کی ہے کہ ) کشتی والوں کے آگے ایک بادشاہ تھا جو ہر اچھی کشتی کو چھین لیا کرتا تھا اور اس کی بھی آپ تلاوت کرتے تھے کہ اور وہ غلام ( جس کی گردن خضر علیہ السلام نے توڑ دی تھی ) تو وہ ( اللہ کے علم میں ) کافر تھا اور اس کے والدین مومن تھے۔' WHERE id = 4520;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن موسیٰ بلخی نے بیان کیا، کہا ہم سے وکیع نے بیان کیا، ان سے اعمش نے، ان سے ابوالضحیٰ نے، ان سے مسروق نے اور ان سے خباب بن ارت نے بیان کیا کہ میں پہلے لوہار تھا اور عاص بن وائل پر میرا قرض چاہئے تھا۔ میں اس کے پاس تقاضا کرنے گیا تو کہنے لگا کہ جب تک تم محمد صلی اللہ علیہ وسلم سے نہ پھر جاؤ گے تمہارا قرض نہیں دوں گا، میں نے کہا کہ میں نبی کریم صلی اللہ علیہ وسلم کے دین سے ہرگز نہیں پھروں گا۔ یہاں تک کہ اللہ تعالیٰ تجھے مار دے اور پھر زندہ کر دے۔ اس نے کہا کیا موت کے بعد میں دوبارہ زندہ کیا جاؤں گا پھر تو مجھے مال و اولاد بھی مل جائیں گے اور اسی وقت تمہارا قرض بھی ادا کر دوں گا۔ راوی نے بیان کیا کہ اس کے متعلق آیت نازل ہوئی «أفرأيت الذي كفر بآياتنا وقال لأوتين مالا وولدا * أطلع الغيب أم اتخذ عند الرحمن عهدا * كلا سنكتب ما يقول ونمد له من العذاب مدا * ونرثه ما يقول ويأتينا فردا‏» کہ ”بھلا تم نے اس شخص کو بھی دیکھا جو ہماری آیتوں کا انکار کرتا ہے اور کہتا ہے کہ مجھے تو مال اور اولاد مل کر رہیں گے، تو کیا یہ غیب پر آگاہ ہو گیا ہے۔ یا اس نے خدائے رحمن سے کوئی عہد کر لیا ہے؟ ہرگز نہیں، البتہ ہم اس کا کہا ہوا بھی لکھ لیتے ہیں اور اس کے لیے عذاب بڑھاتے ہی چلے جائیں گے اور اس کی کہی ہوئی کے ہم ہی مالک ہوں گے اور وہ ہمارے پاس اکیلا آئے گا۔“' WHERE id = 4530;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن منصور نے بیان کیا، کہا ہم سے محمد بن یوسف فریابی نے، کہا ہم سے امام اوزاعی نے، کہا کہ مجھ سے زہری نے بیان کیا۔ ان سے سہل بن سعد نے بیان کیا کہ عویمر بن حارث بن زید بن جد بن عجلان عاصم بن عدی کے پاس آئے۔ عاصم بنی عجلان کے سردار تھے۔ انہوں نے آپ سے کہا کہ آپ لوگوں کا ایک ایسے شخص کے بارے میں کیا خیال ہے جو اپنی بیوی کے ساتھ کسی غیر مرد کو پا لیتا ہے کیا وہ اسے قتل کر دے؟ لیکن تم پھر اسے قصاص میں قتل کر دو گے! آخر ایسی صورت میں انسان کیا طریقہ اختیار کرے؟ رسول اللہ صلی اللہ علیہ وسلم سے اس کے متعلق پوچھ کے مجھے بتائیے۔ چنانچہ عاصم، نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور عرض کیا: یا رسول اللہ! ( صورت مذکورہ میں خاوند کیا کرے ) نبی کریم صلی اللہ علیہ وسلم نے ان مسائل ( میں سوال و جواب ) کو ناپسند فرمایا۔ جب عویمر نے ان سے پوچھا تو انہوں نے بتا دیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ان مسائل کو ناپسند فرمایا ہے۔ عویمر نے ان سے کہا کہ واللہ میں خود نبی کریم صلی اللہ علیہ وسلم سے اسے پوچھوں گا۔ چنانچہ وہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور عرض کیا۔ یا رسول اللہ! ایک شخص اپنی بیوی کے ساتھ ایک غیر مرد کو دیکھتا ہے کیا وہ اس کو قتل کر دے؟ لیکن پھر آپ قصاص میں اس کو قتل کریں گے۔ ایسی صورت میں اس کو کیا کرنا چاہئے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ نے تمہارے اور تمہاری بیوی کے بارے میں قرآن کی آیت اتاری ہے۔ پھر آپ نے انہیں قرآن کے بتائے ہوئے طریقہ کے مطابق لعان کا حکم دیا۔ اور عویمر نے اپنی بیوی کے ساتھ لعان کیا، پھر انہوں نے کہا: یا رسول اللہ! اگر میں اپنی بیوی کو روکے رکھوں تو میں ظالم ہوں گا۔ اس لیے عویمر نے اسے طلاق دے دی۔ اس کے لعان کے بعد میاں بیوی میں جدائی کا طریقہ جاری ہو گیا۔ نبی کریم صلی اللہ علیہ وسلم نے پھر فرمایا کہ دیکھتے رہو اگر اس عورت کے کالا، بہت کالی پتلیوں والا، بھاری سرین اور بھری ہوئی پنڈلیوں والا بچہ پیدا ہو تو میرا خیال ہے کہ عویمر نے الزام غلط نہیں لگایا ہے۔ لیکن اگر سرخ سرخ گر گٹ جیسا پیدا ہو تو میرا خیال ہے کہ عویمر نے غلط الزام لگایا ہے۔ اس کے بعد ان عورت کے جو بچہ پیدا ہوا وہ انہیں صفات کے مطابق تھا جو نبی کریم صلی اللہ علیہ وسلم نے بیان کی تھیں اور جس سے عویمر کی تصدیق ہوتی تھی۔ چنانچہ اس لڑکے کا نسب اس کی ماں کی طرف رکھا گیا۔' WHERE id = 4540;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف فریابی نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے اعمش نے، ان سے ابوالضحیٰ نے، ان سے مسروق نے کہ عائشہ رضی اللہ عنہا سے ملاقات کرنے کی حسان بن ثابت رضی اللہ عنہ نے اجازت چاہی۔ میں نے عرض کیا کہ آپ انہیں بھی اجازت دیتی ہیں ( حالانکہ انہوں نے بھی آپ پر تہمت لگانے والوں کا ساتھ دیا تھا ) اس پر عائشہ رضی اللہ عنہا نے کہا۔ کیا انہیں اس کی ایک بڑی سزا نہیں ملی ہے۔ سفیان نے کہا کہ ان کا اشارہ ان کے نابینا ہو جانے کی طرف تھا۔ پھر حسان نے یہ شعر پڑھا۔ ”عفیفہ اور بڑی عقلمند ہیں کہ ان کے متعلق کسی کو کوئی شبہ بھی نہیں گزر سکتا۔ وہ غافل اور پاکدامن عورتوں کا گوشت کھانے سے اکمل پرہیز کرتی ہیں۔“ عائشہ رضی اللہ عنہا نے فرمایا، لیکن تو نے ایسا نہیں کیا۔' WHERE id = 4550;
UPDATE hadiths SET urdu = 'ہم سے سعد بن حفص نے بیان کیا، کہا ہم سے شیبان نے بیان کیا، ان سے منصور نے، ان سے سعید بن جبیر نے بیان کیا کہ ان سے عبدالرحمٰن بن ابزیٰ نے بیان کیا کہ ابن عباس رضی اللہ عنہما سے آیت «ومن يقتل مؤمنا متعمدا فجزاؤه جهنم‏» ”اور جو کوئی کسی مومن کو جان کر قتل کرے اس کی سزا جہنم ہے۔“ اور سورۃ الفرقان کی آیت «‏‏‏‏لا يقتلون النفس التي حرم الله إلا بالحق‏» ”اور جس انسان کی جان مارنے کو اللہ نے حرام قرار دیا ہے اسے قتل نہیں کرتے مگر ہاں حق کے ساتھ“ «إلا من تاب‏» تک، میں نے اس آیت کے متعلق پوچھا تو انہوں نے کہا کہ جب یہ آیت نازل ہوئی تو اہل مکہ نے کہا کہ پھر تو ہم نے اللہ کے ساتھ شریک بھی ٹھہرایا ہے اور ناحق ایسے قتل بھی کئے ہیں جنہیں اللہ نے حرام قرار دیا تھا اور ہم نے بدکاریوں کا بھی ارتکاب کیا ہے۔ اس پر اللہ تعالیٰ نے یہ آیت نازل کی «إلا من تاب وآمن وعمل عملا صالحا‏» کہ ”مگر ہاں جو توبہ کرے اور ایمان لائے اور نیک کام کرتا رہے، اللہ بہت بخشنے والا بڑا ہی مہربان ہے“ تک۔' WHERE id = 4560;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہمیں عبداللہ بن مبارک نے خبر دی، انہیں یونس بن یزید نے خبر دی، ان سے زہری نے بیان کیا، انہیں ابوسلمہ بن عبدالرحمٰن نے خبر دی اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ ہر پیدا ہونے والا بچہ دین فطرت پر پیدا ہوتا ہے لیکن اس کے ماں باپ اسے یہودی، نصرانی یا مجوسی بنا لیتے ہیں۔ اس کی مثال ایسی ہے جیسی جانور کا بچہ صحیح سالم پیدا ہوتا ہے کیا تم نے انہیں ناک کان کٹا ہوا کوئی بچہ دیکھا ہے۔ اس کے بعد آپ صلی اللہ علیہ وسلم نے اس آیت کی تلاوت کی «فطرة الله التي فطر الناس عليها لا تبديل لخلق الله ذلك الدين القيم‏» ”اللہ کی اس فطرت کی اتباع کرو جس پر اس نے انسان کو پیدا کیا ہے، اللہ کی بنائی ہوئی فطرت میں کوئی تبدیلی ممکن نہیں، یہی سیدھا دین ہے۔“' WHERE id = 4570;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، کہا کہ مجھے ابوسلمہ بن عبدالرحمٰن نے خبر دی اور انہیں نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے خبر دی کہ جب اللہ تعالیٰ نے رسول اللہ صلی اللہ علیہ وسلم کو حکم دیا کہ نبی کریم ( صلی اللہ علیہ وسلم ) اپنی ازواج کو ( آپ کے سامنے رہنے یا آپ سے علیحدگی کا ) اختیار دیں تو آپ عائشہ رضی اللہ عنہا کے پاس بھی تشریف لے گئے اور فرمایا کہ میں تم سے ایک معاملہ کے متعلق کہنے آیا ہوں ضروری نہیں کہ تم اس میں جلد بازی سے کام لو، اپنے والدین سے بھی مشورہ کر سکتی ہو۔ نبی کریم صلی اللہ علیہ وسلم تو جانتے ہی تھے کہ میرے والد کبھی آپ سے جدائی کا مشورہ نہیں دے سکتے۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ کا فرمان ہے «يا أيها النبي قل لأزواجك‏» کہ ”اے نبی! اپنی بیویوں سے فرما دیجئیے“ آخر آیت تک۔ میں نے عرض کیا، لیکن کس چیز کے لیے مجھے اپنے والدین سے مشورہ کی ضرورت ہے، کھلی ہوئی بات ہے کہ میں اللہ، اس کے رسول اور عالم آخرت کو چاہتی ہوں۔' WHERE id = 4580;
UPDATE hadiths SET urdu = 'ہم سے زکریا بن یحییٰ نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے ہشام نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ ام المؤمنین سودہ رضی اللہ عنہا پردہ کا حکم نازل ہونے کے بعد قضائے حاجت کے لیے نکلیں وہ بہت بھاری بھر کم تھیں جو انہیں جانتا تھا اس سے پوشیدہ نہیں رہ سکتی تھیں۔ راستے میں عمر بن خطاب رضی اللہ عنہ نے انہیں دیکھ لیا اور کہا کہ اے سودہ! ہاں اللہ کی قسم! آپ ہم سے اپنے آپ کو نہیں چھپا سکتیں دیکھئیے تو آپ کس طرح باہر نکلی ہیں۔ بیان کیا کہ سودہ رضی اللہ عنہا الٹے پاؤں وہاں سے واپس آ گئیں، رسول اللہ صلی اللہ علیہ وسلم اس وقت میرے حجرہ میں تشریف رکھتے تھے اور رات کا کھانا کھا رہے تھے۔ نبی کریم صلی اللہ علیہ وسلم کے ہاتھ میں اس وقت گوشت کی ایک ہڈی تھی۔ سودہ رضی اللہ عنہا نے داخل ہوتے ہی کہا: یا رسول اللہ! میں قضائے حاجت کے لیے نکلی تھی تو عمر ( رضی اللہ عنہ ) نے مجھ سے باتیں کیں، بیان کیا کہ آپ صلی اللہ علیہ وسلم پر وحی کا نزول شروع ہو گیا اور تھوڑی دیر بعد یہ کیفیت ختم ہوئی، ہڈی اب بھی آپ کے ہاتھ میں تھی۔ آپ نے اسے رکھا نہیں تھا۔ پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تمہیں ( اللہ کی طرف سے ) قضائے حاجت کے لیے باہر جانے کی اجازت دے دی گئی ہے۔' WHERE id = 4590;
UPDATE hadiths SET urdu = 'مجھ سے ابراہیم بن المنذر نے بیان کیا، انہوں نے کہا ہم سے محمد بن فلیح نے بیان کیا، انہوں نے کہا مجھ سے میرے والد نے بیان کیا، ان سے بنی عامر بن لوی کے ہلال بن علی نے، ان سے عطاء بن یسار نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جو شخص یہ دعویٰ کرے کہ میں یونس بن متی علیہ السلام سے بہتر ہوں وہ جھوٹا ہے۔' WHERE id = 4600;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے ولید بن مسلم نے بیان کیا، کہا ہم سے اوزاعی نے بیان کیا، کہا کہ مجھ سے یحییٰ بن ابی کثیر نے بیان کیا، کہا کہ مجھ سے محمد بن ابراہیم تیمی نے بیان کیا، کہا کہ مجھ سے عروہ بن زبیر نے بیان کیا، آپ نے بیان کیا کہ میں نے عبداللہ بن عمرو بن العاص رضی اللہ عنہما سے پوچھا کہ رسول اللہ صلی اللہ علیہ وسلم کے ساتھ سب سے زیادہ سخت معاملہ مشرکین نے کیا کیا تھا؟ عبداللہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کعبہ کے قریب نماز پڑھ رہے تھے کہ عقبہ بن ابی معیط آیا اس نے آپ کا شانہ مبارک پکڑ کر آپ کی گردن میں اپنا کپڑا لپیٹ دیا اور اس کپڑے سے آپ کا گلا بڑی سختی کے ساتھ گھونٹنے لگا۔ اتنے میں ابوبکر صدیق رضی اللہ عنہ بھی آ گئے اور انہوں نے اس بدبخت کا مونڈھا پکڑ کر اسے نبی کریم صلی اللہ علیہ وسلم سے جدا کیا اور کہا کہ کیا تم ایک ایسے شخص کو قتل کر دینا چاہتے ہو جو کہتا ہے کہ میرا رب اللہ ہے اور وہ تمہارے رب کے پاس سے اپنی سچائی کے لیے روشن دلائل بھی ساتھ لایا ہے۔' WHERE id = 4610;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ نے بیان کیا، کہا ہم سے وکیع نے بیان کیا، ان سے اعمش نے، ان سے مسلم نے، ان سے مسروق نے اور ان سے عبداللہ رضی اللہ عنہ نے بیان کیا کہ پانچ ( قرآن مجید کی پیشیں گوئیاں ) گزر چکی ہیں۔ «اللزام» ( بدر کی لڑائی کی ہلاکت ) ، «الروم» ( غلبہ روم ) «البطشة» ( سخت پکڑ ) ، «القمر» ( چاند کے ٹکڑے ہونا ) اور «والدخان‏» دھواں، شدت فاقہ کی وجہ سے۔' WHERE id = 4620;
UPDATE hadiths SET urdu = 'ہم سے صدقہ بن فضل نے بیان کیا، انہیں ابن عیینہ نے خبر دی، ان سے زیاد نے بیان کیا اور انہوں نے مغیرہ بن شعبہ رضی اللہ عنہ سے سنا کہ رسول اللہ صلی اللہ علیہ وسلم نماز میں رات بھر کھڑے رہے یہاں تک کہ آپ کے دونوں پاؤں سوج گئے۔ آپ صلی اللہ علیہ وسلم سے عرض کیا گیا کہ اللہ تعالیٰ نے تو آپ کی اگلی پچھلی تمام خطائیں معاف کر دی ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کیا میں شکر گزار بندہ نہ بنوں؟' WHERE id = 4630;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے ازہر بن سعد نے بیان کیا، کہا ہم کو ابن عون نے خبر دی، کہا کہ مجھے موسیٰ بن انس نے خبر دی، اور انہیں انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے ثابت بن قیس رضی اللہ عنہ کو نہیں پایا۔ ایک صحابی نے عرض کیا: یا رسول اللہ! میں آپ کے لیے ان کی خبر لاتا ہوں۔ پھر وہ ثابت بن قیس رضی اللہ عنہ کے یہاں آئے دیکھا کہ وہ گھر میں سر جھکائے بیٹھے ہیں پوچھا کیا حال ہے؟ کہا کہ برا حال ہے کہ نبی کریم صلی اللہ علیہ وسلم کی آواز کے مقابلہ میں بلند آواز سے بولا کرتا تھا اب سارے نیک عمل اکارت ہوئے اور اہل دوزخ میں قرار دے دیا گیا ہوں۔ وہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور انہوں نے جو کچھ کہا تھا اس کی اطلاع آپ کو دی۔ موسیٰ بن انس نے بیان کیا کہ وہ شخص اب دوبارہ ان کے لیے ایک عظیم بشارت لے کر ان کے پاس آئے۔ آپ صلی اللہ علیہ وسلم نے فرمایا تھا کہ ان کے پاس جاؤ اور کہو کہ تم اہل دوزخ میں سے نہیں ہو بلکہ تم اہل جنت میں سے ہو۔' WHERE id = 4640;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، ان سے عبدالوحد بن زیاد نے بیان کیا، کہا ہم سے سلیمان شیبانی نے بیان کیا، کہا کہ میں نے زر بن حبیش سے سنا اور انہوں نے عبداللہ بن مسعود رضی اللہ عنہ سے آیت «فكان قاب قوسين أو أدنى * فأوحى إلى عبده ما أوحى‏» یعنی ”صرف دو کمانوں کا فاصلہ رہ گیا تھا بلکہ اور بھی کم۔ پھر اللہ نے اپنے بندہ پر وحی نازل کی جو کچھ بھی نازل کیا“ کے متعلق بیان کیا کہ ہم سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے جبرائیل علیہ السلام کو ان کی اصل صورت میں دیکھا تھا ان کے چھ سو پر تھے۔' WHERE id = 4650;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا کہ مجھ سے بکر نے بیان کیا، ان سے جعفر نے، ان سے عراک بن مالک نے، ان سے عبیداللہ بن عبداللہ بن عتبہ بن مسعود نے بیان کیا کہ عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے زمانے میں چاند پھٹ گیا تھا۔' WHERE id = 4660;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا ہم سے ہشام بن یوسف نے بیان کیا، انہیں ابن جریج نے خبر دی، کہا کہ مجھے یوسف بن ماہک نے خبر دی، انہوں نے بیان کیا کہ میں ام المؤمنین عائشہ رضی اللہ عنہا کی خدمت میں حاضر تھا۔ آپ نے فرمایا کہ جس وقت آیت «بل الساعة موعدهم والساعة أدهى وأمر‏» ”لیکن ان کا اصل وعدہ تو قیامت کے دن کا ہے اور قیامت بڑی سخت اور تلخ چیز ہے“ محمد صلی اللہ علیہ وسلم پر مکہ میں نازل ہوئی تو میں بچی تھی اور کھیلا کرتی تھی۔' WHERE id = 4670;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے عبدالرحمٰن بن مہدی نے بیان کیا، ان سے سفیان ثوری نے بیان کیا کہ میں نے عبدالرحمٰن بن عابس سے منصور بن معتمر کی حدیث کا ذکر کیا جو وہ ابراہیم سے بیان کرتے تھے کہ ان سے علقمہ نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے سر کے قدرتی بالوں کے ساتھ مصنوعی بال لگانے والیوں پر لعنت بھیجی تھی۔ عبدالرحمٰن بن عابس نے کہا کہ میں نے بھی ام یعقوب نامی ایک عورت سے سنا تھا وہ عبداللہ بن مسعود رضی اللہ عنہ منصور کی حدیث کے مثل بیان کرتی تھی۔' WHERE id = 4680;
UPDATE hadiths SET urdu = 'مجھ سے عبدالعزیز بن عبداللہ نے بیان کیا، کہا کہ مجھ سے سلیمان بن ہلال نے بیان کیا، ان سے ثور نے، ان سے ابوالغیث سالم نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ ہم رسول اللہ صلی اللہ علیہ وسلم کے پاس بیٹھے ہوئے تھے کہ سورۃ الجمعہ کی یہ آیتیں نازل ہوئیں «وآخرين منهم لما يلحقوا بهم‏» الایۃ اور دوسروں کے لیے بھی جو ابھی ان میں شامل نہیں ہوئے ہیں۔ ( نبی کریم صلی اللہ علیہ وسلم ہادی اور معلم ہیں ) بیان کیا میں نے عرض کی یا رسول اللہ! یہ دوسرے کون لوگ ہیں؟ نبی کریم صلی اللہ علیہ وسلم نے کوئی جواب نہیں دیا۔ آخر یہی سوال تین مرتبہ کیا۔ مجلس میں سلمان فارسی رضی اللہ عنہ بھی موجود تھے نبی کریم صلی اللہ علیہ وسلم نے ان پر ہاتھ رکھ کر فرمایا اگر ایمان ثریا پر بھی ہو گا تب بھی ان لوگوں ( یعنی فارس والوں ) میں سے اس تک پہنچ جائیں گے یا یوں فرمایا کہ ایک آدمی ان لوگوں میں سے اس تک پہنچ جائے گا۔' WHERE id = 4690;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن زبیر حمیدی نے بیان کیا، انہوں نے کہا ہم سے سفیان بن عیینہ نے بیان کیا، انہوں نے کہا کہ ہم نے یہ حدیث عمرو بن دینار سے یاد کی، انہوں نے بیان کیا کہ میں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا، وہ بیان کرتے تھے کہ ہم ایک غزوہ میں تھے، اچانک مہاجرین کے ایک آدمی نے انصاری کے ایک آدمی کو مار دیا۔ انصار نے کہا: اے انصاریو! دوڑو اور مہاجر نے کہا: اے مہاجرین! دوڑو۔ اللہ تعالیٰ نے یہ اپنے رسول صلی اللہ علیہ وسلم کو بھی سنایا۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کیا بات ہے؟ لوگوں نے بتایا کہ ایک مہاجر نے ایک انصاری کو مار دیا ہے۔ اس پر انصاری نے کہا کہ اے انصاریو! دوڑو اور مہاجر نے کہا کہ اے مہاجرین! دوڑو۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا اس طرح پکارنا چھوڑ دو کہ یہ نہایت ناپاک باتیں ہیں۔ جابر رضی اللہ عنہ نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم مدینہ تشریف لائے تو شروع میں انصار کی تعداد زیادہ تھی لیکن بعد میں مہاجرین زیادہ ہو گئے تھے۔ عبداللہ بن ابی نے کہا اچھا اب نوبت یہاں تک پہنچ گئی ہے۔ اللہ کی قسم! مدینہ واپس ہو کر عزت والے ذلیلوں کو باہر نکال دیں گے۔ عمر بن خطاب رضی اللہ عنہ نے کہا: یا رسول اللہ! اجازت ہو تو اس منافق کی گردن اڑا دوں۔ تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ نہیں ورنہ لوگ یوں کہیں گے محمد ( صلی اللہ علیہ وسلم ) اپنے ساتھیوں کو قتل کرانے لگے ہیں۔' WHERE id = 4700;
UPDATE hadiths SET urdu = 'ہم سے محمود نے بیان کیا، کہا ہم سے عبیداللہ نے بیان کیا، ان سے اسرائیل نے، ان سے ابوحصین نے، ان سے مجاہد نے اور ان سے ابن عباس رضی اللہ عنہما نے آیت «عتل بعد ذلك زنيم‏» یعنی ”وہ ظالم سخت مزاج ہے اس کے علاوہ حرامی بھی ہے۔“ کے متعلق فرمایا کہ یہ آیت قریش کے ایک شخص کے بارے میں ہوئی تھی اس کی گردن میں نشانی تھی جیسے بکری میں نشانی ہوتی ہے کہ بعض ان میں کا کوئی عضو بڑھا ہوا ہوتا ہے۔' WHERE id = 4710;
UPDATE hadiths SET urdu = 'ہم سے حمیدی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، کہا ہم سے موسیٰ بن ابی عائشہ نے بیان کیا اور موسیٰ ثقہ تھے، انہوں نے سعید بن جبیر سے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم پر وحی نازل ہوتی تو آپ صلی اللہ علیہ وسلم اس پر اپنی زبان ہلایا کرتے تھے۔ سفیان نے کہا کہ اس ہلانے سے آپ کا مقصد وحی کو یاد کرنا ہوتا تھا۔ اس پر اللہ تعالیٰ نے یہ آیت نازل کی «لا تحرك به لسانك لتعجل به‏» ”آپ جلدی جلدی لینے کے لیے اس پر زبان نہ ہلایا کریں، اس کا جمع کر دینا اور اس کا پڑھوا دینا، یہ ہر دو کام تو ہمارے ذمہ ہیں۔“' WHERE id = 4720;
UPDATE hadiths SET urdu = 'ہم سے آدم نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم سے قتادہ نے بیان کیا، کہا کہ میں نے زرارہ بن اوفی سے سنا، وہ سعد بن ہشام سے بیان کرتے تھے اور ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس شخص کی مثال جو قرآن پڑھتا ہے اور وہ اس کا حافظ بھی ہے، مکرم اور نیک لکھنے والے ( فرشتوں ) جیسی ہے اور جو شخص قرآن مجید باربار پڑھتا ہے۔ پھر بھی وہ اس کے لیے دشوار ہے تو اسے دوگنا ثواب ملے گا۔' WHERE id = 4731;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن موسیٰ بلخی نے بیان کیا، کہا ہم سے وکیع نے بیان کیا، ان سے اعمش نے، ان سے سعد بن عبیدہ نے، ان سے ابوعبدالرحمٰن سلمی نے اور ان سے علی رضی اللہ عنہ نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے پاس بیٹھے ہوئے تھے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہم میں کوئی ایسا نہیں جس کا جہنم کا ٹھکانا اور جنت کا ٹھکانا لکھا نہ جا چکا ہو۔ ہم نے عرض کیا: یا رسول اللہ! پھر ہم اسی پر بھروسہ کیوں نہ کر لیں؟ فرمایا نہیں عمل کرتے رہو کیونکہ ہر شخص کو آسانی دی گئی ہے اور اس کے بعد آپ نے اس آیت کی تلاوت کی «فأما من أعطى واتقى * وصدق بالحسنى * فسنيسره لليسرى‏» یعنی ”سو جس نے دیا اور اللہ سے ڈرا اور اچھی بات کو سچا سمجھا اس کے لیے راحت کی چیز آسان کر دیں گے۔“ تا «فسنيسره للعسرى‏» ۔' WHERE id = 4742;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا اور ان سے عقیل نے، ان سے ابن شہاب نے بیان کیا، انہوں نے عروہ سے سنا، ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ پھر رسول اللہ صلی اللہ علیہ وسلم خدیجہ رضی اللہ عنہا کے پاس واپس تشریف لائے اور فرمایا «زملوني زملوني» کہ مجھے چادر اڑھا دو، مجھے چادر اڑھا دو۔ پھر آپ نے سارا واقعہ بیان فرمایا۔' WHERE id = 4752;
UPDATE hadiths SET urdu = 'ہم سے حسن بن ربیع نے بیان کیا، کہا ہم سے ابوالاحوص نے بیان کیا، ان سے اعمش نے، ان سے ابوالضحیٰ نے، ان سے مسروق نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ آیت «إذا جاء نصر الله والفتح‏» یعنی ”جب اللہ کی مدد اور فتح آ پہنچی“ جب سے نازل ہوئی تھی تو رسول اللہ صلی اللہ علیہ وسلم نے کوئی نماز ایسی نہیں پڑھی جس میں آپ یہ دعا نہ کرتے ہوں «سبحانك ربنا وبحمدك،‏‏‏‏ اللهم اغفر لي‏ ‏‏.‏» یعنی ”پاک ہے تیری ذات، اے اللہ! اے ہمارے رب! اور تیرے ہی لیے تعریف ہے۔ اے اللہ میری مغفرت فرما دے۔“' WHERE id = 4762;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، ان سے سفیان ثوری نے بیان کیا، ان سے عبدہ بن ابی لبابہ نے بیان کیا، ان سے زر بن حبیش نے (سفیان نے کہا) اور ہم سے عاصم نے بھی بیان کیا، ان سے زر نے بیان کیا کہ میں نے ابی بن کعب رضی اللہ عنہ سے پوچھا کہ یا اباالمنذر! آپ کے بھائی عبداللہ بن مسعود رضی اللہ عنہ تو یہ کہتے ہیں کہ سورۃ معوذتین قرآن میں داخل نہیں ہیں۔ ابی بن کعب نے کہا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے اس بات کو پوچھا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے مجھ سے فرمایا کہ ( جبرائیل علیہ السلام کی زبانی ) مجھ سے یوں کہا گیا کہ ایسا کہئیے اور میں نے کہا، ابی بن کعب رضی اللہ عنہ نے کہا کہ ہم بھی وہی کہتے ہیں جیسا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا تھا۔' WHERE id = 4772;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے یونس نے، ان سے ابن شہاب نے، ان سے عبید ابن سباق نے بیان کیا اور ان سے زید بن ثابت رضی اللہ عنہ نے بیان کیا کہ ابوبکر رضی اللہ عنہ نے اپنے زمانہ خلافت میں مجھے بلایا اور کہا کہ تم رسول اللہ صلی اللہ علیہ وسلم کے سامنے قرآن لکھتے تھے۔ اس لیے اب بھی قرآن ( جمع کرنے کے لیے ) تم ہی تلاش کرو۔ میں نے تلاش کی اور سورۃ التوبہ کی آخری دو آیتیں مجھے خزیمہ انصاری کے پاس لکھی ہوئی ملیں، ان کے سوا اور کہیں یہ دو آیتیں نہیں مل رہی تھیں۔ وہ آیتیں یہ تھیں «لقد جاءكم رسول من أنفسكم عزيز عليه ما عنتم‏» آخر تک۔' WHERE id = 4783;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے عمرو بن مرہ نے، ان سے ابراہیم نخعی نے، ان سے مسروق نے کہ عبداللہ بن عمرو بن العاص نے عبداللہ بن مسعود رضی اللہ عنہ کا ذکر کیا اور کہا کہ اس وقت سے ان کی محبت میرے دل میں گھر کر گئی ہے جب سے میں نے نبی کریم صلی اللہ علیہ وسلم کو یہ کہتے ہوئے سنا کہ قرآن مجید کو چار اصحاب سے حاصل کرو جو عبداللہ بن مسعود، سالم، معاذ اور ابی بن کعب ہیں۔' WHERE id = 4793;
UPDATE hadiths SET urdu = 'اور ہم سے ابونعیم نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے منصور بن معتمر نے، ان سے ابراہیم نخعی نے، ان سے عبدالرحمٰن بن یزید نے اور ان سے ابومسعود رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جس نے سورۃ البقرہ کی دو آخری آیتیں رات میں پڑھ لیں وہ اسے ہر آفت سے بچانے کے لیے کافی ہو جائیں گی۔' WHERE id = 4803;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا ‘ کہا ہم سے سفیان بن عیینہ نے بیان کیا ‘ ان سے عبدالعزیز بن رفیع نے بیان کیا کہ میں اور شداد بن معقل ابن عباس رضی اللہ عنہما کے پاس گئے۔ شداد بن معقل نے ان سے پوچھا کیا نبی کریم صلی اللہ علیہ وسلم نے اس قرآن کے سوا کوئی اور بھی قرآن چھوڑا تھا۔ ابن عباس رضی اللہ عنہما نے کہا نبی کریم صلی اللہ علیہ وسلم نے ( وحی متلو ) جو کچھ بھی چھوڑی ہے وہ سب کی سب ان دو گتوں کے درمیان صحیفہ میں محفوظ ہے عبدالعزیز بن رفیع کہتے ہیں کہ ہم محمد بن حنیفہ کی خدمت میں بھی حاضر ہوئے اور ان سے بھی پوچھا تو انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے جو بھی وحی متلو چھوڑی وہ سب دو دفتیوں کے درمیان ( قرآن مجید کی شکل میں ) محفوظ ہے۔' WHERE id = 4813;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن عون نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے ابوحازم نے بیان کیا، ان سے سہل بن سعد رضی اللہ عنہ نے بیان کیا کہ ایک خاتون نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئی اور کہا کہ انہوں نے اپنے آپ کو اللہ اور اس کے رسول ( کی رضا ) کے لیے ہبہ کر دیا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اب مجھے عورتوں سے نکاح کی کوئی حاجت نہیں ہے۔ ایک صاحب نے عرض کیا: یا رسول اللہ! ان کا نکاح مجھ سے کر دیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر انہیں ( مہر میں ) ایک کپڑا لا کے دے دو۔ انہوں نے عرض کیا کہ مجھے تو یہ بھی میسر نہیں ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا پھر انہیں کچھ تو دو ایک لوہے کی انگوٹھی ہی سہی۔ وہ اس پر بہت پریشان ہوئے ( کیونکہ ان کے پاس یہ بھی نہ تھی ) ۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اچھا تم کو قرآن کتنا یاد ہے؟ انہوں نے عرض کیا کہ فلاں فلاں سورتیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر میں نے تمہارا ان سے قرآن کی ان سورتوں پر نکاح کیا جو تمہیں یاد ہیں۔' WHERE id = 4823;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے منصور نے، ان سے ابووائل نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کسی کے لیے یہ مناسب نہیں کہ یہ کہے کہ میں فلاں فلاں آیتیں بھول گیا بلکہ اسے ( یوں کہنا چاہئے ) کہ میں فلاں فلاں آیتوں کو بھلا دیا گیا۔' WHERE id = 4835;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، کہا ہم سے ہمارے والد نے، ان سے اعمش نے بیان کیا، ان سے ابراہیم نے بیان کیا، ان سے عبیدہ نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ مجھ سے رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ مجھے قرآن مجید پڑھ کر سناؤ۔ میں نے عرض کیا میں آپ کو قرآن سناؤں آپ پر تو قرآن نازل ہوتا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں قرآن مجید دوسرے سے سننا محبوب رکھتا ہوں۔' WHERE id = 4845;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے یحییٰ قطان نے بیان کیا، ان سے قتادہ نے، ان سے انس بن مالک نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس مومن کی مثال جو قرآن مجید پڑھتا ہے اور اس پر عمل بھی کرتا ہے میٹھے لیموں کی سی ہے جس کا مزا بھی لذت دار اور خوشبو بھی اچھی اور وہ مومن جو قرآن پڑھتا تو نہیں لیکن اس پر عمل کرتا ہے اس کی مثال کھجور کی ہے جس کا مزہ تو عمدہ ہے لیکن خوشبو کے بغیر اور اس منافق کی مثال جو قرآن پڑھتا ہے ریحان کی سی ہے جس کی خوشبو تو اچھی ہوتی ہے لیکن مزا کڑوا ہوتا ہے اور اس منافق کی مثال جو قرآن بھی نہیں پڑھتا اندرائن کے پھل کی سی ہے جس کا مزہ بھی کڑوا ہوتا ہے ( راوی کو شک ہے ) کہ لفظ «مر» ہے یا «خبيث» اور اس کی بو بھی خراب ہوتی ہے۔' WHERE id = 4856;
UPDATE hadiths SET urdu = 'ہم سے علی بن حکم انصاری نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، ان سے رقبہ نے، ان سے طلحہ الیامی نے، ان سے سعید بن جبیر نے بیان کیا کہ مجھ سے ابن عباس رضی اللہ عنہما نے دریافت فرمایا کہ تم نے شادی کر لی ہے؟ میں نے عرض کیا کہ نہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ شادی کر لو کیونکہ اس امت کے بہترین شخص جو تھے ( یعنی نبی کریم صلی اللہ علیہ وسلم ) ان کی بہت سی بیویاں تھیں۔ بعضوں نے یوں ترجمہ کیا ہے کہ اس امت میں اچھے وہی لوگ ہیں جن کی بہت عورتیں ہوں۔' WHERE id = 4866;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، کہا ہم سے ہشیم نے بیان کیا، کہا ہم سے سیار بن ابی سیار نے بیان کیا، ان سے عامر شعبی نے اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ ایک جہاد سے واپس ہو رہے تھے۔ میں اپنے اونٹ کو، جو سست تھا تیز چلانے کی کوشش کر رہا تھا۔ اتنے میں میرے پیچھے سے ایک سوار مجھ سے آ کر ملا اور اپنا نیزہ میرے اونٹ کو چبھو دیا۔ اس کی وجہ سے میرا اونٹ تیز چل پڑا جیسا کہ کسی عمدہ قسم کے اونٹ کی چال تم نے دیکھی ہو گی۔ اچانک نبی کریم صلی اللہ علیہ وسلم مل گئے۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا جلدی کیوں کر رہے ہو؟ میں نے عرض کیا ابھی میری شادی نئی ہوئی ہے۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ کنواری سے یا بیوہ سے؟ میں نے عرض کیا کہ بیوہ سے۔ نبی کریم صلی اللہ علیہ وسلم نے اس پر فرمایا کہ کسی کنواری سے کیوں نہ کی تم اس کے ساتھ کھیل کود کرتے اور وہ تمہارے ساتھ کرتی۔ بیان کیا کہ پھر جب ہم مدینہ میں داخل ہونے والے تھے تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ تھوڑی دیر ٹھہر جاؤ اور رات ہو جائے تب داخل ہو تاکہ پریشان بالوں والی کنگھا کر لیوے اور جن کے شوہر موجود نہیں تھے وہ اپنے بال صاف کر لیں۔' WHERE id = 4876;
UPDATE hadiths SET urdu = 'ہم سے عبید بن اسماعیل نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا ان سے ہشام بن عروہ نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم ضباعہ بنت زبیر رضی اللہ عنہما کے پاس گئے ( یہ زبیر عبدالمطلب کے بیٹے اور نبی کریم صلی اللہ علیہ وسلم کے چچا تھے ) اور ان سے فرمایا شاید تمہارا ارادہ حج کا ہے؟ انہوں نے عرض کیا: اللہ کی قسم! میں تو اپنے آپ کو بیمار پاتی ہوں نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا کہ پھر بھی حج کا احرام باندھ لے۔ البتہ شرط لگا لینا اور یہ کہہ لینا کہ اے اللہ! میں اس وقت حلال ہو جاؤں گی جب تو مجھے ( مرض کی وجہ سے ) روک لے گا۔ اور ( ضباعہ بنت زبیر قریشی رضی اللہ عنہا ) مقداد بن اسود رضی اللہ عنہ کے نکاح میں تھیں۔' WHERE id = 4886;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا کہ مجھ سے امام مالک نے، ان سے عبداللہ بن ابوبکر نے، ان سے عمرہ بنت عبدالرحمٰن نے اور ان سے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم ان کے یہاں تشریف رکھتے تھے اور آپ نے سنا کہ کوئی صاحب ام المؤمنین حفصہ رضی اللہ عنہا کے گھر میں اندر آنے کی اجازت چاہتے ہیں۔ بیان کیا کہ میں نے عرض کیا: یا رسول اللہ! یہ شخص آپ کے گھر میں آنے کی اجازت چاہتا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میرا خیال ہے کہ یہ فلاں شخص ہے، آپ صلی اللہ علیہ وسلم نے حفصہ رضی اللہ عنہا کے ایک دودھ کے چچا کا نام لیا۔ اس پر عائشہ رضی اللہ عنہا نے پوچھا: کیا فلاں، جو ان کے دودھ کے چچا تھے، اگر زندہ ہوتے تو میرے یہاں آ جا سکتے تھے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہاں جیسے خون ملنے سے حرمت ہوتی ہے، ویسے ہی دودھ پینے سے بھی حرمت ثابت ہو جاتی ہے۔' WHERE id = 4896;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم کو امام مالک نے خبر دی، انہیں ابوالزناد نے، انہیں اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ کسی عورت کو اس کی پھوپھی یا اس کی خالہ کے ساتھ نکاح میں جمع نہ کیا جائے۔' WHERE id = 4906;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، کہا ہم سے لیث نے بیان کیا، ان سے یزید بن ابی حبیب نے، ان سے عراک بن مالک نے اور انہیں زینب بنت ابی سلمہ نے خبر دی کہ ام حبیبہ رضی اللہ عنہا نے رسول اللہ صلی اللہ علیہ وسلم سے کہا کہ ہمیں معلوم ہوا ہے کہ آپ درہ بنت ابی سلمہ سے نکاح کرنے والے ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کیا میں اس سے اس کے باوجود نکاح کر سکتا ہوں کہ ( ان کی ماں ) ام سلمہ میرے نکاح میں پہلے ہی سے موجود ہے اور اگر میں ام سلمہ سے نکاح نہ کئے ہوتا جب بھی وہ درہ میرے لیے حلال نہیں تھی۔ کیونکہ اس کے والد ( ابوسلمہ رضی اللہ عنہ ) میرے رضاعی بھائی تھے۔' WHERE id = 4918;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف بیکندی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے جب ان کا نکاح کیا تو ان کی عمر چھ سال تھی اور جب ان سے صحبت کی تو اس وقت ان کی عمر نو برس کی تھی اور وہ نو برس آپ کے پاس رہیں۔' WHERE id = 4928;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، انہیں زھری نے، کہا کہ مجھے سالم بن عبداللہ نے خبر دی، انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے سنا، وہ بیان کرتے تھے کہ عمر رضی اللہ عنہ نے بیان کیا کہ میری بیٹی حفصہ رضی اللہ عنہا بیوہ ہوئیں تو میں ابوبکر صدیق رضی اللہ عنہ سے ملا اور ان سے کہا کہ اگر آپ چاہیں تو میں آپ کا نکاح عزیزہ حفصہ بنت عمر رضی اللہ عنہما سے کر دوں۔ پھر کچھ دنوں کے بعد رسول اللہ صلی اللہ علیہ وسلم نے ان کے نکاح کا پیغام بھیجا اس کے بعد ابوبکر رضی اللہ عنہ مجھ سے ملے اور کہا آپ نے جو صورت میرے سامنے رکھی تھی اس کا جواب میں نے صرف اس وجہ سے نہیں دیا تھا کہ مجھے معلوم تھا رسول اللہ صلی اللہ علیہ وسلم نے ان کا ذکر کیا ہے۔ میں نہیں چاہتا کہ آپ کا راز کھولوں ہاں نبی کریم صلی اللہ علیہ وسلم انہیں چھوڑ دیتے تو میں ان کو قبول کر لیتا۔ شعیب کے ساتھ اس حدیث کو یونس بن یزید اور موسیٰ بن عقبہ اور محمد بن ابی عتیق نے بھی زہری سے روایت کیا ہے۔' WHERE id = 4939;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے ثابت نے اور ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے عبدالرحمٰن بن عوف پر زردی کا نشان دیکھا تو پوچھا کہ یہ کیا ہے؟ انہوں نے کہا کہ میں نے ایک عورت سے ایک گٹھلی کے وزن کے برابر سونے کے مہر پر نکاح کیا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ تمہیں برکت دے دعوت ولیمہ کر خواہ ایک بکری ہی کی ہو۔' WHERE id = 4949;
UPDATE hadiths SET urdu = 'ہم سے سعد بن حفص طلحی نے بیان کیا، کہا ہم سے شیبان بن عبدالرحمٰن نے، ان سے منصور بن معتمر نے، ان سے سالم بن ابی الجعد نے، ان سے کریب نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کوئی شخص اپنی بیوی کے پاس ہمبستری کے لیے جب آئے تو یہ دعا پڑھے «باسم الله،‏‏‏‏ ‏‏‏‏ اللهم جنبني الشيطان،‏‏‏‏ ‏‏‏‏ وجنب الشيطان ما رزقتنا» یعنی میں اللہ کے نام سے شروع کرتا ہوں اے اللہ! شیطان کو مجھ سے دور رکھ اور شیطان کو اس چیز سے بھی دور رکھ جو ( اولاد ) ہمیں تو عطا کرے۔ پھر اس عرصہ میں ان کے لیے کوئی اولاد نصیب ہو تو اسے شیطان کبھی ضرر نہ پہنچا سکے گا۔' WHERE id = 4959;
UPDATE hadiths SET urdu = 'ہم سے حسن بن ربیع نے بیان کیا، کہا ہم سے ابوالاحوص (سلام بن سلیم) نے بیان کیا، ان سے اشعث بن ابی الشعثاء نے، ان سے معاویہ بن سوید نے کہ براء بن عازب رضی اللہ عنہ نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے ہمیں سات کاموں کا حکم دیا اور سات کاموں سے منع فرمایا۔ ہمیں نبی کریم صلی اللہ علیہ وسلم نے بیمار کی عیادت، جنازہ کے پیچھے چلنے، چھینکنے والے کے جواب دینے ( یرحمک اللہ یعنی اللہ تم پر رحم کرے کہنا ) قسم کو پورا کرنے، مظلوم کی مدد کرنے، سب کو سلام کرنے اور دعوت کرنے والے کی دعوت قبول کرنے کا حکم دیا تھا اور ہمیں نبی کریم صلی اللہ علیہ وسلم نے سونے کی انگوٹھی پہننے، چاندی کے برتن استعمال کرنے، ریشمی گدے، قسیہ ( ریشمی کپڑا ) استبرق ( موٹے ریشم کا کپڑا ) اور دیباج ( ایک ریشمی کپڑا ) کے استعمال سے منع فرمایا تھا۔ ابوعوانہ اور شیبانی نے اشعث کی روایت سے لفظ «إفشاء السلام‏.‏» میں ابوالاحوص کی متابعت کی ہے۔' WHERE id = 4969;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے عبداللہ بن دینار نے اور ان سے ابن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے وقت میں ہم اپنی بیویوں کے ساتھ گفتگو اور بہت زیادہ بےتکلفی سے اس ڈر کی وجہ سے پرہیز کرتے تھے کہ کہیں کوئی بےاعتدالی ہو جائے اور ہماری برائی میں کوئی حکم نازل نہ ہو جائے۔ پھر جب نبی کریم صلی اللہ علیہ وسلم کی وفات ہو گئی تو ہم نے ان سے خوب کھل کے گفتگو کی اور خوب بےتکلفی کرنے لگے۔' WHERE id = 4980;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم کو امام مالک نے خبر دی، انہیں زید بن اسلم نے، انہیں عطاء بن یسار نے اور انہیں عبداللہ بن عباس رضی اللہ عنہما نے، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے زمانہ میں سورج گرہن ہوا تو نبی کریم صلی اللہ علیہ وسلم نے لوگوں کے ساتھ اس کی نماز پڑھی۔ آپ نے بہت لمبا قیام کی اتنا طویل کہ سورۃ البقرہ پڑھی جا سکے پھر طویل رکوع کیا۔ رکوع سے سر اٹھا کر بہت دیر تک قیام کیا۔ یہ قیام پہلے قیام سے کچھ کم تھا۔ پھر آپ نے دوسرا طویل رکوع کیا۔ یہ رکوع طوالت میں پہلے رکوع سے کچھ کم تھا۔ پھر سر اٹھایا اور سجدہ کیا۔ پھر دوبارہ قیام کیا اور بہت دیر تک حالت قیام میں رہے۔ یہ قیام پہلی رکعت کے قیام سے کچھ کم تھا۔ پھر طویل رکوع کیا، یہ رکوع پہلے رکوع سے کچھ کم طویل تھا۔ پھر سر اٹھایا اور طویل قیام کیا۔ یہ قیام پہلے قیام سے کچھ کم تھا۔ پھر رکوع کیا، طویل رکوع۔ اور یہ رکوع پہلے رکوع سے کچھ کم طویل تھا۔ پھر سر اٹھایا اور سجدہ میں گئے۔ جب آپ نماز سے فارغ ہوئے تو گرہن ختم ہو چکا تھا۔ اس کے بعد آپ صلی اللہ علیہ وسلم نے فرمایا کہ سورج اور چاند اللہ کی نشانیوں میں سے دو نشانیاں ہیں۔ ان میں گرہن کسی کی موت یا کسی کی حیات کی وجہ سے نہیں ہوتا۔ اس لیے جب تم گرہن دیکھو تو اللہ کو یاد کرو۔ صحابہ نے عرض کیا: یا رسول اللہ! ہم نے آپ کو دیکھا کہ آپ نے اپنی جگہ سے کوئی چیز بڑھ کر لی۔ پھر ہم نے دیکھا کہ آپ ہم سے ہٹ گئے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں نے جنت دیکھی تھی یا ( نبی کریم صلی اللہ علیہ وسلم نے فرمایا راوی کو شک تھا ) مجھے جنت دکھائی گئی تھی۔ میں نے اس کا خوشہ توڑنے کے لیے ہاتھ بڑھایا تھا اور اگر میں اسے توڑ لیتا تو تم رہتی دنیا تک اسے کھاتے اور میں نے دوزخ دیکھی آج کا اس سے زیادہ ہیبت ناک منظر میں نے کبھی نہیں دیکھا اور میں نے دیکھا کہ اس میں عورتوں کی تعداد زیادہ ہے۔ صحابہ نے عرض کیا: یا رسول اللہ! ایسا کیوں ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ وہ شوہر کی ناشکری کرتی ہیں اور ان کے احسان کا انکار کرتی ہیں، اگر تم ان میں سے کسی ایک کے ساتھ زندگی بھر بھی حسن سلوک کا معاملہ کرو پھر بھی تمہاری طرف سے کوئی چیز اس کے لیے ناگواری خاطر ہوئی تو کہہ دے گی کہ میں نے تو تم سے کبھی بھلائی دیکھی ہی نہیں۔' WHERE id = 4990;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے یحییٰ بن سعید نے بیان کیا، ان سے ابن جریج نے، ان سے عطاء نے اور ان سے جابر رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے زمانہ میں ہم عزل کیا کرتے تھے۔' WHERE id = 5000;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے ہشام نے، ان سے فاطمہ بنت منذر نے اور ان سے اسماء بنت ابی بکر رضی اللہ عنہما نے نبی کریم صلی اللہ علیہ وسلم سے (دوسری سند) اور مجھ سے محمد بن مثنٰی نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے ہشام نے، ان سے فاطمہ بنت منذر نے بیان کیا اور ان سے اسماء بنت ابوبکر رضی اللہ عنہما نے کہ ایک خاتون نے عرض کیا: یا رسول اللہ! میری سوکن ہے اگر اپنے شوہر کی طرف سے ان چیزوں کے حاصل ہونے کی بھی داستانیں اسے سناؤں جو حقیقت میں میرا شوہر مجھے نہیں دیتا تو کیا اس میں کوئی حرج ہے؟ نبی کریم صلی اللہ علیہ وسلم نے اس پر فرمایا کہ جو چیز حاصل نہ ہو اس پر فخر کرنے والا اس شخص جیسا ہے جو فریب کا جوڑا یعنی ( دوسروں کے کپڑے ) مانگ کر پہنے۔' WHERE id = 5011;
UPDATE hadiths SET urdu = 'مجھ سے احمد بن ابی رجاء نے بیان کیا، کہا ہم سے نضر بن شمیل نے بیان کیا، ان سے ہشام بن عروہ نے، کہا کہ مجھے میرے والد نے خبر دی، ان سے عائشہ رضی اللہ عنہا نے، آپ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کے لیے کسی عورت پر مجھے اتنی غیرت نہیں آتی تھی جتنی ام المؤمنین خدیجہ رضی اللہ عنہا پر آتی تھی کیونکہ نبی کریم صلی اللہ علیہ وسلم ان کا ذکر بکثرت کیا کرتے تھے اور ان کی تعریف کرتے تھے اور نبی کریم صلی اللہ علیہ وسلم پر وحی کی گئی تھی کہ آپ خدیجہ کو جنت میں ان کے موتی کے گھر کی بشارت دے دیں۔' WHERE id = 5021;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تینسی نے بیان کیا، کہا ہم کو امام مالک رحمہ اللہ نے خبر دی، انہیں ہشام بن عروہ نے، انہیں ان کے والد عروہ بن زبیر نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ میرے دودھ چچا ( رضاعی چچا، افلح ) آئے اور میرے پاس اندر آنے کی اجازت چاہی لیکن میں نے کہا کہ جب تک میں رسول اللہ صلی اللہ علیہ وسلم سے پوچھ نہ لوں، اجازت نہیں دے سکتی۔ پھر آپ صلی اللہ علیہ وسلم تشریف لائے تو میں نے آپ سے اس کے متعلق پوچھا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ وہ تمہارے رضاعی چچا ہیں، انہیں اندر بلا لو۔ میں نے اس پر کہا کہ یا رسول اللہ! عورت نے مجھے دودھ پلایا تھا کوئی مرد نے تھوڑا ہی پلایا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہیں تو وہ تمہارے چچا ہی ( رضاعی ) اس لیے وہ تمہارے پاس آ سکتے ہیں، یہ واقعہ ہمارے لیے پردہ کا حکم نازل ہونے کے بعد کا ہے۔ عائشہ رضی اللہ عنہا نے کہا کہ خون سے جو چیزیں حرام ہوتی ہیں رضاعت سے بھی وہ حرام ہو جاتی ہیں۔' WHERE id = 5031;
UPDATE hadiths SET urdu = 'ہم سے احمد بن محمد نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، کہا ہم کو سفیان ثوری نے خبر دی، ان سے عبدالرحمٰن بن عابس نے، کہا میں نے ابن عباس رضی اللہ عنہما سے سنا، ان سے ایک شخص نے یہ سوال کیا تھا کہ تم بقر عید یا عید کے موقع پر رسول اللہ صلی اللہ علیہ وسلم کے ساتھ موجود تھے؟ انہوں نے کہا کہ ہاں۔ اگر میں نبی کریم صلی اللہ علیہ وسلم کا رشتہ دار نہ ہوتا تو میں اپنی کم سنی کی وجہ سے ایسے موقع پر حاضر نہیں ہو سکتا تھا۔ ان کا اشارہ ( اس زمانے میں ) اپنے بچپن کی طرف تھا۔ انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم باہر تشریف لے گئے اور ( لوگوں کے ساتھ عید کی ) نماز پڑھی اور اس کے بعد خطبہ دیا۔ ابن عباس رضی اللہ عنہما نے اذان اور اقامت کا ذکر نہیں کیا، پھر آپ عورتوں کے پاس آئے اور انہیں وعظ و نصیحت کی اور انہیں خیرات دینے کا حکم دیا۔ میں نے انہیں دیکھا کہ پھر وہ اپنے کانوں اور گلے کی طرف ہاتھ بڑھا بڑھا کر ( اپنے زیورات ) بلال رضی اللہ عنہ کو دینے لگیں۔ اس کے بعد بلال رضی اللہ عنہ کے ساتھ نبی کریم صلی اللہ علیہ وسلم واپس تشریف لائے۔' WHERE id = 5041;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے عبیداللہ بن عمر عمری نے، کہا کہ مجھ سے قاسم بن محمد نے بیان کیا اور ان سے عائشہ رضی اللہ عنہا نے کہ ایک صاحب نے اپنی بیوی کو تین طلاق دے دی تھی۔ ان کی بیوی نے دوسری شادی کر لی، پھر دوسرے شوہر نے بھی ( ہمبستری سے پہلے ) انہیں طلاق دے دی۔ رسول اللہ صلی اللہ علیہ وسلم سے سوال کیا گیا کہ کیا پہلا شوہر اب ان کے لیے حلال ہے ( کہ ان سے دوبارہ شادی کر لیں ) ۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ نہیں، یہاں تک کہ وہ یعنی شوہر ثانی اس کا مزہ چکھے جیسا کہ پہلے نے مزہ چکھا تھا۔' WHERE id = 5053;
UPDATE hadiths SET urdu = 'ہم سے ازہر بن جمیل نے بیان کیا، کہا ہم سے عبدالوہاب ثقفی نے بیان کیا، کہا ہم سے خالد نے بیان کیا، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ ثابت بن قیس رضی اللہ عنہ کی بیوی نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئی اور عرض کیا کہ یا رسول اللہ! مجھے ان کے اخلاق اور دین کی وجہ سے ان سے کوئی شکایت نہیں ہے۔ البتہ میں اسلام میں کفر کو پسند نہیں کرتی۔ ( کیونکہ ان کے ساتھ رہ کر ان کے حقوق زوجیت کو نہیں ادا کر سکتی ) ۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا کہ کیا تم ان کا باغ ( جو انہوں نے مہر میں دیا تھا ) واپس کر سکتی ہو؟ انہوں نے کہا کہ جی ہاں۔ نبی کریم صلی اللہ علیہ وسلم نے ( ثابت رضی اللہ عنہ سے ) فرمایا کہ باغ قبول کر لو اور انہیں طلاق دے دو۔' WHERE id = 5064;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام بیکندی نے بیان کیا، کہا ہم کو عبدالوہاب ثقفی نے خبر دی، کہا ہم سے خالد حذاء نے، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ بریرہ رضی اللہ عنہا کے شوہر غلام تھے اور ان کا نام مغیث تھا۔ گویا میں اس وقت اس کو دیکھ رہا ہوں جب وہ بریرہ رضی اللہ عنہا کے پیچھے پیچھے روتے ہوئے پھر رہے تھے اور آنسوؤں سے ان کی ڈاڑھی تر ہو رہی تھی۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے عباس رضی اللہ عنہ سے فرمایا: عباس! کیا تمہیں مغیث کی بریرہ سے محبت اور بریرہ کی مغیث سے نفرت پر حیرت نہیں ہوئی؟ آخر نبی کریم صلی اللہ علیہ وسلم نے بریرہ رضی اللہ عنہا سے فرمایا کہ کاش! تم اس کے بارے میں اپنا فیصلہ بدل دیتیں۔ انہوں نے عرض کیا: یا رسول اللہ! کیا آپ مجھے اس کا حکم فرما رہے ہیں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں صرف سفارش کر رہا ہوں۔ انہوں نے اس پر کہا کہ مجھے مغیث کے پاس رہنے کی خواہش نہیں ہے۔' WHERE id = 5074;
UPDATE hadiths SET urdu = 'اور اویسی نے بیان کیا، ان سے ابراہیم بن سعد نے بیان کیا، ان سے شعبہ بن حجاج نے، ان سے ہشام بن یزید نے، ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے زمانہ میں ایک یہودی نے ایک لڑکی پر ظلم کیا، اس کے چاندی کے زیورات جو وہ پہنے ہوئے تھی چھین لیے اور اس کا سر کچل دیا۔ لڑکی کے گھر والے اسے نبی کریم صلی اللہ علیہ وسلم کے پاس لائے تو اس کی زندگی کی بس آخری گھڑی باقی تھی اور وہ بول نہیں سکتی تھی۔ نبی کریم صلی اللہ علیہ وسلم نے اس سے پوچھا کہ تمہیں کس نے مارا ہے؟ فلاں نے؟ نبی کریم صلی اللہ علیہ وسلم نے اس واقعہ سے غیر متعلق آدمی کا نام لیا۔ اس لیے اس نے اپنے سر کے اشارہ سے کہا کہ نہیں۔ بیان کیا کہ پھر نبی کریم صلی اللہ علیہ وسلم نے ایک دوسرے شخص کا نام لیا اور وہ بھی اس واقعہ سے غیر متعلق تھا تو لڑکی نے سر کے اشارہ سے کہا کہ نہیں، پھر نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ فلاں نے تمہیں مارا ہے؟ تو اس لڑکی نے سر کے اشارہ سے ہاں کہا۔' WHERE id = 5086;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ نے بیان کیا، ان سے امام مالک نے بیان کیا، ان سے ابن شہاب نے، ان سے سعید بن مسیب نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ ایک صحابی نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور عرض کیا: یا رسول اللہ! میرے یہاں تو کالا کلوٹا بچہ پیدا ہوا ہے۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تمہارے پاس کچھ اونٹ بھی ہیں؟ انہوں نے کہا جی ہاں۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ ان کے رنگ کیسے ہیں؟ انہوں نے کہا کہ سرخ رنگ کے ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ ان میں کوئی سیاہی مائل سفید اونٹ بھی ہے؟ انہوں نے کہا کہ جی ہاں۔ نبی کریم صلی اللہ علیہ وسلم نے اس پر فرمایا کہ پھر یہ کہاں سے آ گیا؟ انہوں نے کہا کہ اپنی نسل کے کسی بہت پہلے کے اونٹ پر یہ پڑا ہو گا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اسی طرح تمہارا یہ لڑکا بھی اپنی نسل کے کسی دور کے رشتہ دار پر پڑا ہو گا۔' WHERE id = 5096;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہ ہم سے مالک نے، کہا کہ مجھ سے نافع نے بیان کیا اور ان سے ابن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے ایک صاحب اور ان کی بیوی کے درمیان لعان کرایا تھا۔ پھر ان صاحب نے اپنی بیوی کے لڑکے کا انکار کیا تو نبی کریم صلی اللہ علیہ وسلم نے دونوں کے درمیان جدائی کرا دی اور لڑکا عورت کو دے دیا۔' WHERE id = 5106;
UPDATE hadiths SET urdu = 'ہم سے حجاج نے بیان کیا، کہا ہم سے یزید بن ابراہیم نے بیان کیا، کہا ہم سے محمد بن سیرین نے بیان کیا، کہا مجھ سے یونس بن جبیر نے بیان کیا کہ میں نے ابن عمر رضی اللہ عنہما سے پوچھا تو انہوں نے بتلایا کہ ابن عمر رضی اللہ عنہما نے اپنی بیوی کو طلاق دے دی، اس وقت وہ حائضہ تھیں۔ پھر عمر رضی اللہ عنہ نے اس کے متعلق نبی کریم صلی اللہ علیہ وسلم سے پوچھا تو نبی کریم صلی اللہ علیہ وسلم نے حکم دیا کہ ابن عمر اپنی بیوی سے رجوع کر لیں۔ پھر جب طلاق کا صحیح وقت آئے تو طلاق دیں ( یونس بن جبیر نے بیان کیا کہ ابن عمر رضی اللہ عنہما سے ) میں نے پوچھا کہ کیا اس طلاق کا بھی شمار ہوا تھا؟ انہوں نے بتلایا کہ اگر کوئی طلاق دینے والا شرع کے احکام بجا لانے سے عاجز ہو یا احمق بیوقوف ہو ( تو کیا طلاق نہیں پڑے گی؟ ) ۔' WHERE id = 5120;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، ان سے سفیان ثوری نے بیان کیا، ان سے عبداللہ بن ابی بکر بن عمرو بن حزم نے بیان کیا، ان سے حمید بن نافع نے بیان، ان سے زینب بنت ام سلمہ رضی اللہ عنہما نے بیان کیا اور ان سے ام حبیبہ بنت ابی سفیان رضی اللہ عنہما نے بیان کیا کہ جب ان کے والد کی وفات کی خبر پہنچی تو انہوں نے خوشبو منگوائی اور اپنے دونوں بازؤں پر لگائی پھر کہا کہ مجھے خوشبو کی کوئی ضرورت نہ تھی لیکن میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا ہے کہ جو عورت اللہ اور آخرت پر ایمان رکھتی ہو وہ کسی میت کا تین دن سے زیادہ سوگ نہ منائے سوا شوہر کے کہ اس کے لیے چار مہینے دس دن ہیں۔' WHERE id = 5132;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن حفص نے بیان کیا۔ کہا ہم سے ہمارے والد نے بیان کیا، ان سے اعمش نے بیان کیا، ان سے ابوصالح نے بیان کیا، کہا کہ مجھ سے ابوہریرہ رضی اللہ عنہ نے بیان کیا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ سب سے بہترین صدقہ وہ ہے جسے دے کر دینے والا مالدار ہی رہے اور ہر حال میں اوپر کا ہاتھ ( دینے والے کا ) نیچے کے ( لینے والے کے ) ہاتھ سے بہتر ہے اور ( خرچ کی ) ابتداء ان سے کرو جو تمہاری نگہبانی میں ہیں۔ عورت کو اس مطالبہ کا حق ہے کہ مجھے کھانا دے ورنہ طلاق دے۔ غلام کو اس مطالبہ کا حق ہے کہ مجھے کھانا دو اور مجھ سے کام لو۔ بیٹا کہہ سکتا ہے کہ مجھے کھانا کھلاؤ یا کسی اور پر چھوڑ دو۔ لوگوں نے کہا: اے ابوہریرہ! کیا ( یہ آخری ٹکڑا بھی ) کہ جورو کہتی ہے آخر تک۔ آپ نے رسول اللہ صلی اللہ علیہ وسلم سے سنا ہے؟ انہوں نے کہا کہ نہیں بلکہ یہ ابوہریرہ کی خود اپنی سمجھ ہے۔' WHERE id = 5142;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، کہا ہم سے عبداللہ بن طاؤس نے بیان کیا، ان سے ان کے والد (طاؤس) اور ابوالزناد نے بیان کیا، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اونٹ پر سوار ہونے والی عورتوں میں ( یعنی عرب کی عورتوں میں ) بہترین عورتیں قریشی عورتیں ہیں۔ دوسرے راوی ( ابن طاؤس ) نے بیان کیا کہ قریش کی صالح، نیک عورتیں ( صرف لفظ قریشی عورتوں کے بجائے ) بچے پر بچپن میں سب سے زیادہ مہربان اور اپنے شوہر کے مال کی سب سے زیادہ حفاظت کرنے والیاں ہوتی ہیں۔ معاویہ اور ابن عباس رضی اللہ عنہما نے بھی نبی کریم صلی اللہ علیہ وسلم سے ایسی ہی روایت کی ہے۔' WHERE id = 5152;
UPDATE hadiths SET urdu = 'ابوحازم سے روایت ہے کہ ان سے ابوہریرہ رضی اللہ عنہ نے ( بیان کیا کہ فاقہ کی وجہ سے ) میں سخت مشقت میں مبتلا تھا، پھر میری ملاقات عمر بن خطاب رضی اللہ عنہ سے ہوئی اور ان سے میں نے قرآن مجید کی ایک آیت پڑھنے کے لیے کہا۔ انہوں نے مجھے وہ آیت پڑھ کر سنائی اور پھر اپنے گھر میں داخل ہو گئے۔ اس کے بعد میں بہت دور تک چلتا رہا۔ آخر مشقت اور بھوک کی وجہ سے میں منہ کے بل گر پڑا۔ اچانک میں نے دیکھا کہ رسول اللہ صلی اللہ علیہ وسلم میرے سر کے پاس کھڑے ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اے ابوہریرہ! میں نے کہا حاضر ہوں، یا رسول اللہ! تیار ہوں۔ پھر نبی کریم صلی اللہ علیہ وسلم نے میرا ہاتھ پکڑ کر مجھے کھڑا کیا۔ آپ سمجھ گئے کہ میں کس تکلیف میں مبتلا ہوں۔ پھر آپ مجھے اپنے گھر لے گئے اور میرے لیے دودھ کا ایک بڑا پیالہ منگوایا۔ میں نے اس میں دودھ پیا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ دوبارہ پیو ( ابوہریرہ! ) میں نے دوبارہ پیا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اور پیو۔ میں نے اور پیا۔ یہاں تک کہ میرا پیٹ بھی پیالہ کی طرح بھرپور ہو گیا۔ ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ پھر عمر رضی اللہ عنہ سے ملا اور ان سے اپنا سارا واقعہ بیان کیا اور کہا کہ اے عمر! اللہ تعالیٰ نے اسے اس ذات کے ذریعہ پورا کرا دیا، جو آپ سے زیادہ مستحق تھی۔ اللہ کی قسم! میں نے تم سے آیت پوچھی تھی حالانکہ میں اسے تم سے بھی زیادہ بہتر طریقہ پر پڑھ سکتا تھا۔ عمر رضی اللہ عنہ نے کہا: اللہ کی قسم! اگر میں نے تم کو اپنے گھر میں داخل کر لیا ہوتا اور تم کو کھانا کھلا دیتا تو لال لال ( عمدہ ) اونٹ ملنے سے بھی زیادہ مجھ کو خوشی ہوتی۔' WHERE id = 5162;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سنان نے بیان کیا، ان سے ہمام نے بیان کیا، ان سے قتادہ نے کہا کہ ہم انس رضی اللہ عنہ کی خدمت میں بیٹھے ہوئے تھے، اس وقت ان کا روٹی پکانے والا خادم بھی موجود تھا۔ انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے کبھی چپاتی ( میدہ کی روٹی ) نہیں کھائی اور نہ ساری دم پختہ بکری کھائی یہاں تک کہ آپ اللہ سے جا ملے۔' WHERE id = 5172;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، انہوں نے کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عمرو بن دینار نے کہ ابونہیک بڑے کھانے والے تھے۔ ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ہے کہ کافر ساتوں آنتوں میں کھاتا ہے۔ ابونہیک نے اس پر عرض کیا کہ میں اللہ اور اس کے رسول پر ایمان رکھتا ہوں۔' WHERE id = 5182;
UPDATE hadiths SET urdu = 'ایوب اور عاصم سے روایت ہے، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے پکتی ہوئی ہنڈیا میں سے ادھ کچی بوٹی نکالی اور اسے کھایا پھر نماز پڑھائی اور نیا وضو نہیں کیا۔' WHERE id = 5192;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن ابی الاسود نے بیان کیا، کہا ہم سے معاذ بن ہشام نے بیان کیا، ان سے ان کے والد نے بیان کیا، ان سے یونس بن ابی الفرات نے، ان سے قتادہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے کبھی میز پر کھانا نہیں کھایا اور نہ تشتری میں دو چار قسم کی چیزیں رکھ کر کھائیں اور نہ کبھی چپاتی کھائی۔ میں نے قتادہ سے پوچھا، پھر آپ کس چیز پر کھانا کھاتے تھے؟ بتلایا کہ سفرہ ( چمڑے کے دستر خوان ) پر۔' WHERE id = 5202;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے اسماعیل بن جعفر نے بیان کیا، ان سے مطلب بن عبداللہ بن حنطب کے غلام عمرو بن ابی عمرو نے، انہوں نے انس بن مالک رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ابوطلحہ رضی اللہ عنہ سے فرمایا کہ اپنے یہاں کے بچوں میں کوئی بچہ تلاش کر لاؤ جو میرے کام کر دیا کرے۔ چنانچہ ابوطلحہ رضی اللہ عنہ مجھے اپنی سواری پر اپنے پیچھے بٹھا کر لائے۔ میں نبی کریم صلی اللہ علیہ وسلم کی، جب بھی آپ کہیں پڑاؤ کرتے خدمت کرتا۔ میں سنا کرتا تھا کہ نبی کریم صلی اللہ علیہ وسلم بکثرت یہ دعا پڑھا کرتے تھے «اللهم إني أعوذ بك من الهم والحزن،‏‏‏‏ ‏‏‏‏ والعجز والكسل،‏‏‏‏ ‏‏‏‏ والبخل والجبن وضلع الدين،‏‏‏‏ ‏‏‏‏ وغلبة الرجال» ”اے اللہ! میں تیری پناہ مانگتا ہوں غم سے، رنج سے، عجز سے، سستی سے، بخل سے، بزدلی سے، قرض کے بوجھ سے اور لوگوں کے غلبہ سے۔“ ( انس رضی اللہ عنہ نے بیان کیا کہ ) پھر میں اس وقت سے برابر آپ کی خدمت کرتا رہا۔ یہاں تک کہ ہم خیبر سے واپس ہوئے اور صفیہ بنت حیی رضی اللہ عنہا بھی ساتھ تھیں۔ نبی کریم صلی اللہ علیہ وسلم نے انہیں پسند فرمایا تھا۔ میں دیکھتا تھا کہ نبی کریم صلی اللہ علیہ وسلم نے ان کے لیے اپنی سواری پر پیچھے کپڑے سے پردہ کیا اور پھر انہیں وہاں بٹھایا۔ آخر جب مقام صہبا میں پہنچے تو آپ نے دستر خوان پر حیس ( کھجور، پنیر اور گھی وغیرہ کا ملیدہ ) بنایا پھر مجھے بھیجا اور میں نے لوگوں کو بلا لایا، پھر سب لوگوں نے اسے کھایا۔ یہی نبی کریم صلی اللہ علیہ وسلم کی طرف سے صفیہ رضی اللہ عنہا سے نکاح کی دعوت ولیمہ تھی۔ پھر آپ روانہ ہوئے اور جب احد دکھائی دیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ پہاڑ ہم سے محبت رکھتا ہے اور ہم اس سے محبت رکھتے ہیں۔ اس کے بعد جب مدینہ نظر آیا تو فرمایا کہ اے اللہ! میں اس کے دونوں پہاڑوں کے درمیانی علاقے کو اسی طرح حرمت والا علاقہ بناتا ہوں جس طرح ابراہیم علیہ السلام نے مکہ کو حرمت والا شہر بنایا تھا۔ اے اللہ! اس کے رہنے والوں کو برکت عطا فرما۔ ان کے مد میں اور ان کے صاع میں برکت فرما۔' WHERE id = 5212;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن منیر نے بیان کیا، انہوں نے نضر سے سنا، انہیں ابن عون نے خبر دی، کہا کہ مجھے ثمامہ بن عبداللہ بن انس نے خبر دی اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ میں نوعمر تھا اور رسول اللہ صلی اللہ علیہ وسلم کے ساتھ رہتا تھا۔ نبی کریم صلی اللہ علیہ وسلم اپنے ایک درزی غلام کے پاس تشریف لے گئے۔ وہ ایک پیالہ لایا جس میں کھانا تھا اور اوپر کدو کے قتلے تھے۔ آپ کدو تلاش کرنے لگے۔ انس رضی اللہ عنہ نے بیان کیا کہ جب میں نے یہ دیکھا تو کدو کے قتلے آپ کے سامنے جمع کر کے رکھنے لگا۔ انس رضی اللہ عنہ نے بیان کیا کہ ( پیالہ نبی کریم صلی اللہ علیہ وسلم کے سامنے رکھنے کے بعد ) غلام اپنے کام میں لگ گیا۔ انس رضی اللہ عنہ نے بیان کیا کہ اسی وقت سے میں کدو پسند کرنے لگا، جب میں نے نبی کریم صلی اللہ علیہ وسلم کا یہ عمل دیکھا۔' WHERE id = 5222;
UPDATE hadiths SET urdu = 'ہم سے جمعہ بن عبداللہ نے بیان کیا، انہوں نے کہا ہم سے مروان نے بیان کیا، انہوں نے کہا ہم کو ہاشم بن ہاشم نے خبر دی، انہوں نے کہا ہم کو عامر بن سعد نے خبر دی اور ان سے ان کے والد سعد بن ابی وقاص رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جس نے ہر دن صبح کے وقت سات عجوہ کھجوریں کھا لیں، اسے اس دن نہ زہر نقصان پہنچا سکے گا اور نہ جادو۔' WHERE id = 5233;
UPDATE hadiths SET urdu = 'یحییٰ نے بیان کیا کہ میں نے بشیر سے سنا، انہوں نے بیان کیا ہم سے سوید رضی اللہ عنہ نے بیان کیا ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ خیبر کی طرف نکلے جب ہم مقام صہبا پر پہنچے۔ یحییٰ نے کہا کہ یہ جگہ خیبر سے ایک منزل کی دوری پر ہے تو نبی کریم صلی اللہ علیہ وسلم نے کھانا طلب فرمایا لیکن ستو کے سوا اور کوئی چیز نہیں لائی گئی۔ ہم نے اسے آپ صلی اللہ علیہ وسلم کے ساتھ کھایا پھر آپ نے ہمیں مغرب کی نماز پڑھائی اور نیا وضو نہیں کیا اور سفیان نے کہا گویا کہ تم یہ حدیث یحییٰ ہی سے سن رہے ہو۔' WHERE id = 5243;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جب نماز کھڑی ہو چکے اور رات کا کھانا بھی سامنے ہو تو کھانا کھاؤ۔ وہیب اور یحییٰ بن سعید نے بیان کیا، ان سے ہشام نے کہ جب رات کا کھانا رکھا جا چکے۔' WHERE id = 5253;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم فضل بن دکین نے بیان کیا، کہا ہم سے زکریا بن ابی زائدہ نے بیان کیا، ان سے عامر شعبی نے، ان سے عدی بن حاتم رضی اللہ عنہ نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے بے پر کے تیر یا لکڑی یا گز سے شکار کے بارے میں پوچھا تو آپ نے فرمایا کہ اگر اس کی نوک شکار کو لگ جائے تو کھا لو لیکن اگر اس کی عرض کی طرف سے شکار کو لگے تو وہ نہ کھاؤ کیونکہ وہ «موقوذة‏» ہے اور میں نے آپ سے کتے کے شکار کے بارے میں سوال کیا تو آپ نے فرمایا کہ جسے وہ تمہارے لیے رکھے ( یعنی وہ خود نہ کھائے ) اسے کھا لو کیونکہ کتے کا شکار کو پکڑ لینا یہ بھی ذبح کرنا ہے اور اگر تم اپنے کتے یا کتوں کے ساتھ کوئی دوسرا کتا بھی پاؤ اور تمہیں اندیشہ ہو کہ تمہارے کتے نے شکار اس دوسرے کے ساتھ پکڑا ہو گا اور کتا شکار کو مار چکا ہو تو ایسا شکار نہ کھاؤ کیونکہ تم نے اللہ کا نام ( بسم اللہ پڑھ کر ) اپنے کتے پر لیا تھا دوسرے کتے پر نہیں لیا تھا۔' WHERE id = 5264;
UPDATE hadiths SET urdu = 'اور عبدالاعلیٰ نے بیان کیا، ان سے داؤد بن ابی یاسر نے، ان سے عامر شعبی نے اور ان سے عدی بن حاتم رضی اللہ عنہ نے کہ انہوں نے نبی کریم صلی اللہ علیہ وسلم سے عرض کی کہ وہ شکار تیر سے مارتے ہیں پھر دو یا تین دن پر اسے تلاش کرتے ہیں، تب وہ مردہ حالت میں ملتا ہے اور اس کے اندر ان کا تیر گھسا ہوا ہوتا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر تو چاہے تو کھا سکتا ہے۔' WHERE id = 5274;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، انہوں نے کہا ہم سے شعبہ بن حجاج نے بیان کیا، ان سے ابویعفور نے بیان کیا کہ میں نے عبداللہ بن ابی اوفی رضی اللہ عنہما سے سنا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ سات یا چھ غزووں میں شریک ہوئے، ہم آپ کے ساتھ ٹڈی کھاتے تھے۔ سفیان، ابوعوانہ اور اسرائیل نے ابویعفور سے بیان کیا اور ان سے ابن ابی اوفی نے، سات غزوہ کے لفظ روایت کئے۔' WHERE id = 5284;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے نافع نے، ان سے قبیلہ انصار کے ایک آدمی نے کہ معاذ بن سعد یا سعد بن معاذ نے انہیں خبر دی کہ کعب بن مالک رضی اللہ عنہ کی ایک لونڈی سلع پہاڑی پر بکریاں چرایا کرتی تھی۔ ریوڑ میں سے ایک بکری مرنے لگی تو اس نے اسے مرنے سے پہلے پتھر سے ذبح کر دیا پھر نبی کریم صلی اللہ علیہ وسلم سے اس کے متعلق پوچھا گیا تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اسے کھاؤ۔' WHERE id = 5294;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، کہا ہم سے ابوعوانہ نے، ان سے ابوبشر نے، ان سے سعید بن جبیر نے کہ میں ابن عمر رضی اللہ عنہما کے ساتھ تھا وہ چند جوانوں یا ( یہ کہا کہ ) چند آدمیوں کے پاس سے گزرے جنہوں نے ایک مرغی باندھ رکھی تھی اور اس پر تیر کا نشانہ لگا رہے تھے جب انہوں نے ابن عمر رضی اللہ عنہما کو دیکھا تو وہاں سے بھاگ گئے۔ ابن عمر رضی اللہ عنہما نے کہا یہ کون کر رہا تھا؟ ایسا کرنے والوں پر نبی کریم صلی اللہ علیہ وسلم نے لعنت بھیجی ہے۔ اس کی متابعت سلیمان نے شعبہ سے کی ہے۔' WHERE id = 5304;
UPDATE hadiths SET urdu = 'ہم سے اسحاق نے بیان کیا، کہا ہم کو یعقوب بن ابراہیم نے خبر دی، کہا ہم سے ہمارے والد نے بیان کیا، ان سے صالح نے، ان سے ابن شہاب نے، انہیں ابوادریس نے خبر دی اور ان سے ابوثعلبہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے پالتو گدھے کا گوشت کھانا حرام قرار دیا تھا۔ اس روایت کی متابعت زبیدی اور عقیل نے ابن شہاب سے کی ہے۔ مالک، معمر، ماجشون، یونس اور ابن اسحاق نے زہری سے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ہر پھاڑ کر کھانے والے درندے کا گوشت کھانے سے منع فرمایا ہے۔' WHERE id = 5315;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، ان سے امام مالک نے، ان سے ابن شہاب نے، ان سے ابوامامہ بن سہل نے، ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا اور ان سے خالد بن ولید رضی اللہ عنہ نے بیان کیا کہ وہ نبی کریم صلی اللہ علیہ وسلم کے ساتھ ام المؤمنین میمونہ رضی اللہ عنہا کے گھر گئے تو نبی کریم صلی اللہ علیہ وسلم کی خدمت میں بھنا ہوا ساہنہ لایا گیا آپ نے اس کی طرف ہاتھ بڑھایا لیکن بعض عورتوں نے کہا کہ آپ جو کھانا دیکھ رہے ہیں اس کے متعلق نبی کریم صلی اللہ علیہ وسلم کو بتا دو، عورتوں نے کہا کہ یہ ساہنہ ہے یا رسول اللہ! چنانچہ نبی کریم صلی اللہ علیہ وسلم نے اپنا ہاتھ کھینچ لیا۔ میں نے عرض کیا: یا رسول اللہ! کیا یہ حرام ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ نہیں لیکن چونکہ یہ ہمارے ملک میں نہیں پایا جاتا اس لیے طبیعت اس سے انکار کرتی ہے۔ خالد رضی اللہ عنہ نے بیان کیا کہ پھر میں نے اسے اپنی طرف کھینچ لیا اور کھایا اور نبی کریم صلی اللہ علیہ وسلم دیکھ رہے تھے۔' WHERE id = 5325;
UPDATE hadiths SET urdu = 'ہم سے معاذ بن فضالہ نے بیان کیا، کہا ہم سے ہشام بن عروہ نے بیان کیا، ان سے یحییٰ نے اور ان سے بعجہ الجہنی نے اور ان سے عقبہ بن عامر جہنی رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے اپنے صحابہ میں قربانی کے جانور تقسیم کئے۔ عقبہ رضی اللہ عنہ کے حصہ میں ایک سال سے کم کا بکری کا بچہ آیا۔ انہوں نے بیان کیا کہ اس پر میں نے عرض کیا: یا رسول اللہ! میرے حصہ میں تو ایک سال سے کم کا بچہ آیا ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم اسی کی قربانی کر لو۔' WHERE id = 5335;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے محمد بن جعفر نے بیان کیا، ان سے شعبہ نے بیان کیا، ان سے سلمہ نے، ان سے ابوجحیفہ نے اور ان سے براء رضی اللہ عنہ نے بیان کیا کہ ابوبردہ رضی اللہ عنہ نے نماز عید سے پہلے قربانی ذبح کر لی تھی تو نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا کہ اس کے بدلے میں دوسری قربانی کر لو۔ انہوں نے عرض کیا کہ میرے پاس ایک سال سے کم عمر کے بچے کے سوا اور کوئی جانور نہیں۔ شعبہ نے بیان کیا کہ میرا خیال ہے کہ ابوبردہ رضی اللہ عنہ نے یہ بھی کہا تھا کہ وہ ایک سال کی بکری سے بھی عمدہ ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر اسی کی اس کے بدلے میں قربانی کر دو لیکن تمہارے بعد یہ کسی کے لیے کافی نہیں ہو گی۔ اور حاتم بن وردان نے بیان کیا، ان سے ایوب نے، ان سے محمد نے اور ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم سے آخر حدیث تک ( اس روایت میں یہ لفظ ہیں ) کہ ”ایک سال سے کم عمر کی بچی ہے۔“' WHERE id = 5345;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، ان سے سفیان نے بیان کیا کہ عمرو نے بیان کیا، انہیں عطاء نے خبر دی، انہوں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ مدینہ پہنچنے تک ہم رسول اللہ صلی اللہ علیہ وسلم کے زمانے میں قربانی کا گوشت جمع کرتے تھے اور کئی مرتبہ ( بجائے «لحوم الأضاحي» کے ) «لحوم الهدى‏.‏» کا لفظ استعمال کیا۔' WHERE id = 5355;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے ہشام دستوائی نے بیان کیا، کہا ہم سے قتادہ نے بیان کیا اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے ایک حدیث سنی جو تم سے اب میرے سوا کوئی اور نہیں بیان کرے گا ( کیونکہ اب میرے سوا کوئی صحابی زندہ موجود نہیں رہا ہے ) ۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ قیامت کی نشانیوں میں سے یہ ہے کہ جہالت غالب ہو جائے گی اور علم کم ہو جائے گا، زناکاری بڑھ جائے گی، شراب کثرت سے پی جانے لگے گی، عورتیں بہت ہو جائیں گی، یہاں تک کہ پچاس پچاس عورتوں کی نگرانی کرنے والا صرف ایک ہی مرد رہ جائے گا۔' WHERE id = 5365;
UPDATE hadiths SET urdu = 'اور زہری سے روایت ہے، کہا کہ مجھ سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ ”دباء“ اور ”مزفت“ میں نبیذ نہ بنایا کرو اور ابوہریرہ رضی اللہ عنہ اس کے ساتھ ”حنتم“ اور ”نقیر“ کا بھی اضافہ کیا کرتے تھے۔' WHERE id = 5375;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے یعقوب بن عبدالرحمٰن القاری نے بیان کیا، ان سے ابوحازم نے، انہوں نے سہیل بن سعد سے سنا کہ ابواسید ساعدی رضی اللہ عنہ نے اپنے ولیمہ کی دعوت نبی کریم صلی اللہ علیہ وسلم کو دی، اس دن ان کی بیوی ( ام اسید سلامہ ) ہی مہمانوں کی خدمت کر رہی تھیں۔ زوجہ ابواسید نے کہا تم جانتے ہو میں نے رسول اللہ صلی اللہ علیہ وسلم کے لیے کس چیز کا شربت تیار کیا تھا پتھر کے کونڈے میں رات کے وقت کچھ کھجوریں بھگو دی تھیں اور دوسرے دن صبح کو آپ کو پلا دی تھی۔' WHERE id = 5385;
UPDATE hadiths SET urdu = 'مجھ سے محمود نے بیان کیا، کہا ہم کو ابوالنضر نے خبر دی، کہا ہم کو شعبہ نے خبر دی، ان سے ابواسحاق نے بیان کیا کہ میں نے براء بن عازب رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم مکہ مکرمہ سے تشریف لائے تو ابوبکر رضی اللہ عنہ آپ کے ساتھ تھے۔ ابوبکر رضی اللہ عنہ نے کہا کہ ( راستہ میں ) ہم ایک چرواہے کے قریب سے گزرے۔ نبی کریم صلی اللہ علیہ وسلم پیاسے تھے پھر میں نے ایک پیالے میں ( چرواہے سے پوچھ کر ) کچھ دودھ دوہا۔ آپ صلی اللہ علیہ وسلم نے وہ دودھ پیا اور اس سے مجھے خوشی حاصل ہوئی اور سراقہ بن جعشم گھوڑے پر سوار ہمارے پاس ( تعاقب کرتے ہوئے ) پہنچ گیا۔ نبی کریم صلی اللہ علیہ وسلم نے اس کے لیے بددعا کی۔ آخر اس نے کہا کہ نبی کریم صلی اللہ علیہ وسلم اس کے حق میں بددعا نہ کریں اور وہ واپس ہو جائے گا۔ نبی کریم صلی اللہ علیہ وسلم نے ایسا ہی کیا۔' WHERE id = 5395;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے عاصم احول نے، ان سے شعبی نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے زمزم کا پانی کھڑے ہو کر پیا۔' WHERE id = 5405;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، کہا ہم سے ایوب نے بیان کیا کہ ہم سے عکرمہ نے کہا، تمہیں میں چند چھوٹی چھوٹی باتیں نہ بتا دوں جنہیں ہم سے ابوہریرہ رضی اللہ عنہ نے بیان کیا تھا کہ رسول اللہ صلی اللہ علیہ وسلم نے مشک کے منہ سے منہ لگا کر پانی پینے کی ممانعت کی تھی اور ( اس سے بھی آپ صلی اللہ علیہ وسلم نے منع فرمایا تھا کہ ) کوئی شخص اپنے پڑوس کو اپنی دیوار میں کھونٹی وغیرہ گاڑنے سے روکے۔' WHERE id = 5415;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا، کہا ہم سے ابوغسان نے بیان کیا، کہا کہ مجھ سے ابوحازم نے بیان کیا، ان سے سہل بن سعد رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم سے ایک عرب عورت کا ذکر کیا گیا پھر آپ نے اسید ساعدی رضی اللہ عنہ کو ان کے پاس انہیں لانے کے لیے کسی کو بھیجنے کا حکم دیا چنانچہ انہوں نے بھیجا اور وہ آئیں اور بنی ساعدہ کے قلعہ میں اتریں اور نبی کریم صلی اللہ علیہ وسلم بھی تشریف لائے اور ان کے پاس گئے۔ آپ نے دیکھا کہ ایک عورت سر جھکائے بیٹھی ہے۔ نبی کریم صلی اللہ علیہ وسلم نے جب ان سے گفتگو کی تو وہ کہنے لگیں کہ میں تم سے اللہ کی پناہ مانگتی ہوں۔ نبی کریم صلی اللہ علیہ وسلم نے اس پر فرمایا کہ میں نے تجھ کو پناہ دی! لوگوں نے بعد میں ان سے پوچھا۔ تمہیں معلوم بھی ہے یہ کون تھے۔ اس عورت نے جواب دیا کہ نہیں۔ لوگوں نے کہا کہ یہ تو رسول اللہ صلی اللہ علیہ وسلم تھے تم سے نکاح کے لیے تشریف لائے تھے۔ اس پر وہ بولیں کہ پھر تو میں بڑی بدبخت ہوں ( کہ نبی کریم صلی اللہ علیہ وسلم کو ناراض کر کے واپس کر دیا ) اسی دن نبی کریم صلی اللہ علیہ وسلم تشریف لائے اور سقیفہ بنی ساعدہ میں اپنے صحابی کے ساتھ بیٹھے پھر فرمایا کہ سہل! پانی پلاؤ۔ میں نے ان کے لیے یہ پیالہ نکالا اور انہیں اس میں پانی پلایا۔ سہل رضی اللہ عنہ ہمارے لیے بھی وہی پیالہ نکال کر لائے اور ہم نے بھی اس میں پانی پیا۔ راوی نے بیان کیا کہ پھر بعد میں خلیفہ عمر بن عبدالعزیز رحمہ اللہ نے ان سے یہ مانگ لیا تھا اور انہوں نے یہ ان کو ہبہ کر دیا تھا۔' WHERE id = 5425;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، ان سے منصور نے، ان سے ابووائل نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ بھوکے کو کھانا کھلاؤ اور مریض کی عیادت یعنی مزاج پرسی کرو اور قیدی کو چھڑاؤ۔' WHERE id = 5436;
UPDATE hadiths SET urdu = 'ہم سے مکی بن ابراہیم نے بیان کیا، کہا ہم کو جعید بن عبدالرحمٰن نے خبر دی، انہیں عائشہ بنت سعد نے کہ ان کے والد ( سعد بن ابی وقاص رضی اللہ عنہ ) نے بیان کیا کہ میں مکہ میں بہت سخت بیمار پڑ گیا تو رسول اللہ صلی اللہ علیہ وسلم میری مزاج پرسی کے لیے تشریف لائے۔ میں نے عرض کیا: اے اللہ کے نبی! ( اگر وفات ہو گئی تو ) میں مال چھوڑوں گا اور میرے پاس سوا ایک لڑکی کے اور کوئی وارث نہیں ہے۔ کیا میں اپنے دو تہائی مال کی وصیت کر دوں اور ایک تہائی چھوڑ دوں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ نہیں میں نے عرض کیا پھر آدھے کی وصیت کر دوں اور آدھا ( اپنی بچی کے لیے ) چھوڑ دوں فرمایا کہ نہیں پھر میں نے کہا کہ ایک تہائی کی وصیت کر دوں اور باقی دو تہائی لڑکی کے لیے چھوڑ دوں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ایک تہائی کر دو اور ایک تہائی بھی بہت ہے۔ پھر نبی کریم صلی اللہ علیہ وسلم نے اپنا ہاتھ ان کی پیشانی پر رکھا ( سعد رضی اللہ عنہ نے بیان کیا ) اور میرے چہرے اور پیٹ پر آپ صلی اللہ علیہ وسلم نے اپنا مبارک ہاتھ پھیرا پھر فرمایا: اے اللہ! سعد کو شفاء عطا فرما اور اس کی ہجرت کو مکمل کر۔ نبی کریم صلی اللہ علیہ وسلم کے دست مبارک کی ٹھنڈک اپنے جگر کے حصہ پر میں اب تک پا رہا ہوں۔' WHERE id = 5446;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا ہم سے ہشام بن عروہ نے بیان کیا، ان سے معمر نے (دوسری سند) اور مجھ سے عبداللہ بن محمد نے بیان کیا، کہا ہم سے عبدالرزاق نے بیان کیا، کہا ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں عبیداللہ بن عبداللہ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ جب رسول اللہ صلی اللہ علیہ وسلم کی وفات کا وقت قریب آیا تو گھر میں کئی صحابہ موجود تھے۔ عمر بن خطاب رضی اللہ عنہ بھی وہیں موجود تھے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ لاؤ میں تمہارے لیے ایک تحریر لکھ دوں تاکہ اس کے بعد تم غلط راہ پر نہ چلو۔ عمر رضی اللہ عنہ نے اس پر کہا کہ نبی کریم صلی اللہ علیہ وسلم اس وقت سخت تکلیف میں ہیں اور تمہارے پاس قرآن مجید تو موجود ہے ہی، ہمارے لیے اللہ کی کتاب کافی ہے۔ اس مسئلہ پر گھر میں موجود صحابہ کا اختلاف ہو گیا اور بحث کرنے لگے۔ بعض صحابہ کہتے تھے کہ نبی کریم صلی اللہ علیہ وسلم کو ( لکھنے کی چیزیں ) دے دو تاکہ نبی کریم صلی اللہ علیہ وسلم ایسی تحریر لکھ دیں جس کے بعد تم گمراہ نہ ہو سکو اور بعض صحابہ وہ کہتے تھے جو عمر رضی اللہ عنہ نے کہا تھا۔ جب نبی کریم صلی اللہ علیہ وسلم کے پاس اختلاف اور بحث بڑھ گئی تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہاں سے چلے جاؤ۔ عبیداللہ نے بیان کیا کہ ابن عباس رضی اللہ عنہما کہا کرتے تھے کہ سب سے زیادہ افسوس یہی ہے کہ ان کے اختلاف اور بحث کی وجہ سے نبی کریم صلی اللہ علیہ وسلم نے وہ تحریر نہیں لکھی جو آپ مسلمانوں کے لیے لکھنا چاہتے تھے۔' WHERE id = 5456;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا ہم سے بشر بن مفضل نے بیان کیا، ان سے خالد بن ذکوان نے اور ان سے ربیع بنت معوذ بن عفراء رضی اللہ عنہم نے بیان کیا، انہوں نے کہا کہ ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ غزوات میں شریک ہوتی تھیں اور مسلمان مجاہد کو پانی پلاتی، ان کی خدمت کرتیں اور مقتولین اور مجروحین کو مدینہ منورہ لایا کرتیں تھیں۔' WHERE id = 5466;
UPDATE hadiths SET urdu = 'ہم سے حبان بن موسیٰ نے بیان کیا، کہا ہم کو عبداللہ نے خبر دی، انہیں یونس بن یزید نے خبر دی، انہیں عقیل نے، انہیں ابن شہاب نے، انہیں عروہ نے کہ عائشہ رضی اللہ عنہا بیمار کے لیے اور میت کے سوگواروں کے لیے تلبینہ ( روا، دودھ اور شہد ملا کر دلیہ ) پکانے کا حکم دیتی تھیں اور فرماتی تھیں کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا آپ صلی اللہ علیہ وسلم نے فرمایا کہ تلبینہ مریض کے دل کو سکون پہنچاتا ہے اور غم کو دور کرتا ہے ( کیونکہ اسے پینے کے بعد عموماً نیند آ جاتی ہے یہ زود ہضم بھی ہے ) ۔' WHERE id = 5476;
UPDATE hadiths SET urdu = 'ہم سے عمران بن میسرہ نے بیان کیا، کہا ہم سے محمد بن فضیل نے بیان کیا، ان سے حصین بن عبدالرحمٰن نے بیان کیا، ان سے عامر شعبی نے اور ان سے عمران بن حصین رضی اللہ عنہما نے کہا کہ نظر بد اور زہریلے جانور کے کاٹ کھانے کے سوا اور کسی چیز پر جھاڑ پھونک صحیح نہیں۔ ( حصین نے بیان کیا کہ ) پھر میں نے اس کا ذکر سعید بن جبیر سے کیا تو انہوں نے بیان کیا کہ ہم سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ میرے سامنے تمام امتیں پیش کی گئیں ایک ایک، دو دو نبی اور ان کے ساتھ ان کے ماننے والے گزرتے رہے اور بعض نبی ایسے بھی تھے کہ ان کے ساتھ کوئی نہیں تھا آخر میرے سامنے ایک بڑی بھاری جماعت آئی۔ میں نے پوچھا یہ کون ہیں، کیا یہ میری امت کے لوگ ہیں؟ کہا گیا کہ یہ موسیٰ علیہ السلام اور ان کی قوم ہے پھر کہا گیا کہ کناروں کی طرف دیکھو میں نے دیکھا کہ ایک بہت ہی عظیم جماعت ہے جو کناروں پر چھائی ہوئی ہے پھر مجھ سے کہا گیا کہ ادھر دیکھو، ادھر دیکھو آسمان کے مختلف کناروں میں میں نے دیکھا کہ جماعت ہے جو تمام افق پر چھائی ہوئی ہے۔ کہا گیا کہ یہ آپ کی امت ہے اور اس میں سے ستر ہزار حساب کے بغیر جنت میں داخل کر دیئے جائیں گے۔ اس کے بعد آپ ( اپنے حجرہ میں ) تشریف لے گئے اور کچھ تفصیل نہیں فرمائی لوگ ان جنتیوں کے بارے میں بحث کرنے لگے اور کہنے لگے کہ ہم اللہ پر ایمان لائے ہیں اور اس کے رسول کی اتباع کی ہے، اس لیے ہم ہی ( صحابہ ) وہ لوگ ہیں یا ہماری وہ اولاد ہیں جو اسلام میں پیدا ہوئے کیونکہ ہم جاہلیت میں پیدا ہوئے تھے۔ یہ باتیں جب نبی کریم صلی اللہ علیہ وسلم کو معلوم ہوئیں تو آپ صلی اللہ علیہ وسلم باہر تشریف لائے اور فرمایا کہ یہ وہ لوگ ہوں گے جو جھاڑ پھونک نہیں کراتے، فال نہیں دیکھتے اور داغ کر علاج نہیں کرتے بلکہ اپنے رب پر بھروسہ کرتے ہیں۔ اس پر عکاشہ بن محصن رضی اللہ عنہ نے عرض کیا: یا رسول اللہ! کیا میں بھی ان میں سے ہوں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہاں۔ اس کے بعد دوسرے صحابی کھڑے ہوئے اور عرض کیا: یا رسول اللہ! میں بھی ان میں ہوں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ عکاشہ تم سے بازی لے گئے۔' WHERE id = 5489;
UPDATE hadiths SET urdu = 'مجھ سے سعید بن عفیر نے بیان کیا، انہوں نے کہا ہم سے یعقوب بن عبدالرحمٰن نے بیان کیا، ان سے ابوحازم نے بیان کیا، اور ان سے سہل بن سعد ساعدی رضی اللہ عنہ نے بیان کیا کہ جب رسول اللہ صلی اللہ علیہ وسلم کے سر پر ( احد کے دن ) خود ٹوٹ گیا آپ کا مبارک چہرہ خون آلود ہو گیا اور سامنے کے دانت ٹوٹ گئے تو علی رضی اللہ عنہ ڈھال بھربھر کر پانی لاتے تھے اور فاطمہ رضی اللہ عنہا آپ کے چہرہ مبارک سے خون دھو رہی تھیں۔ پھر جب فاطمہ رضی اللہ عنہا نے دیکھا کہ خون پانی سے بھی زیادہ آ رہا ہے تو انہوں نے ایک بوریا جلا کر رسول اللہ صلی اللہ علیہ وسلم کے زخموں پر لگایا اور اس سے خون رکا۔' WHERE id = 5501;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے عبدالواحد نے بیان کیا، کہا ہم سے عاصم نے بیان کیا، کہا مجھ سے حفصہ بنت سیرین نے بیان کیا، کہا کہ مجھ سے انس بن مالک رضی اللہ عنہ نے پوچھا کہ یحییٰ بن سیرین کا کس بیماری میں انتقال ہوا تھا۔ میں نے کہا کہ طاعون میں، بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ طاعون ہر مسلمان کے لیے شہادت ہے۔' WHERE id = 5511;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے عبدالوارث بن سعید نے بیان کیا، ان سے عبدالعزیز بن صہیب نے بیان کیا کہ میں اور ثابت بنانی انس بن مالک رضی اللہ عنہ کی خدمت میں حاضر ہوئے۔ ثابت نے کہا: ابوحمزہ! ( انس رضی اللہ عنہ کی کنیت ) میری طبیعت خراب ہو گئی ہے۔ انس رضی اللہ عنہ نے کہا پھر کیوں نہ میں تم پر وہ دعا پڑھ کر دم کر دوں جسے رسول اللہ صلی اللہ علیہ وسلم پڑھا کرتے تھے، ثابت نے کہا کہ ضرور کیجئے۔ انس رضی اللہ عنہ نے اس پر یہ دعا پڑھ کر دم کیا «اللهم رب الناس مذهب الباس اشف أنت الشافي لا شافي إلا أنت،‏‏‏‏ ‏‏‏‏ شفاء لا يغادر سقما» ”اے اللہ! لوگوں کے رب! تکلیف کو دور کر دینے والے! شفاء عطا فرما، تو ہی شفاء دینے والا ہے تیرے سوا کوئی شفاء دینے والا نہیں، ایسی شفاء عطا فرما کہ بیماری بالکل باقی نہ رہے۔' WHERE id = 5521;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے حصین بن نمیر نے بیان کیا، ان سے حصین بن عبدالرحمٰن نے، ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم ایک دن ہمارے پاس باہر تشریف لائے اور فرمایا کہ ( خواب میں ) مجھ پر تمام امتیں پیش کی گئیں۔ بعض نبی گزرتے اور ان کے ساتھ ( ان کی اتباع کرنے والا ) صرف ایک ہوتا۔ بعض گزرتے اور ان کے ساتھ دو ہوتے بعض کے ساتھ پوری جماعت ہوتی اور بعض کے ساتھ کوئی بھی نہ ہوتا پھر میں نے ایک بڑی جماعت دیکھی جس سے آسمان کا کنارہ ڈھک گیا تھا میں سمجھا کہ یہ میری ہی امت ہو گی لیکن مجھ سے کہا گیا کہ یہ موسیٰ علیہ السلام اور ان کی امت کے لوگ ہیں پھر مجھ سے کہا کہ دیکھو میں نے ایک بہت بڑی جماعت دیکھی جس نے آسمانوں کا کنارہ ڈھانپ لیا ہے۔ پھر مجھ سے کہا گیا کہ ادھر دیکھو، ادھر دیکھو، میں نے دیکھا کہ بہت سی جماعتیں ہیں جو تمام افق پر محیط تھیں۔ کہا گیا کہ یہ آپ کہ امت ہے اور اس میں سے ستر ہزار وہ لوگ ہوں گے جو بے حساب جنت میں داخل کئے جائیں گے پھر صحابہ مختلف جگہوں میں اٹھ کر چلے گئے اور نبی کریم صلی اللہ علیہ وسلم نے اس کی وضاحت نہیں کی کہ یہ ستر ہزار کون لوگ ہوں گے۔ صحابہ کرام رضی اللہ عنہم نے آپس میں اس کے متعلق مذاکرہ کیا اور کہا کہ ہماری پیدائش تو شرک میں ہوئی تھی البتہ بعد میں ہم اللہ اور اس کے رسول پر ایمان لے آئے لیکن یہ ستر ہزار ہمارے بیٹے ہوں گے جو پیدائش ہی سے مسلمان ہیں۔ جب رسول اللہ صلی اللہ علیہ وسلم کو یہ بات پہنچی تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ ستر ہزار وہ لوگ ہوں گے جو بدفالی نہیں کرتے، نہ منتر سے جھاڑ پھونک کراتے ہیں اور نہ داغ لگاتے ہیں بلکہ اپنے رب پر بھروسہ کرتے ہیں۔ یہ سن کر عکاشہ بن محصن رضی اللہ عنہ نے عرض کیا: یا رسول اللہ! کیا میں بھی ان میں سے ہوں؟ فرمایا کہ ہاں۔ ایک دوسرے صاحب سعد بن عبادہ رضی اللہ عنہ نے کھڑے ہو کر عرض کیا میں بھی ان میں سے ہوں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ عکاشہ تم سے بازی لے گئے کہ تم سے پہلے عکاشہ کے لیے جو ہونا تھا ہو چکا۔' WHERE id = 5531;
UPDATE hadiths SET urdu = 'مجھ سے عبدالعزیز بن عبداللہ اویسی نے بیان کیا، کہا مجھ سے سلیمان بن بلال نے بیان کیا، ان سے ثور بن زید نے، ان سے ابوالغیث نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”تباہ کر دینے والی چیز اللہ کے ساتھ شرک کرنا ہے اس سے بچو اور جادو کرنے کرانے سے بھی بچو۔“' WHERE id = 5542;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے لیث بن سعد نے، ان سے سعید بن ابی سعید نے اور ان سے ابوہریرہ رضی اللہ عنہ نے، انہوں نے بیان کیا کہ جب خیبر فتح ہوا تو رسول اللہ صلی اللہ علیہ وسلم کو ایک بکری ہدیہ میں پیش کی گئی ( ایک یہودی عورت زینب بنت حرث نے پیش کی تھی ) جس میں زہر بھرا ہوا تھا، اس پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہاں پر جتنے یہودی ہیں انہیں میرے پاس جمع کرو۔ چنانچہ سب نبی کریم صلی اللہ علیہ وسلم کے پاس جمع کئے گئے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں تم سے ایک بات پوچھوں گا کیا تم مجھے صحیح صحیح بات بتا دو گے؟ انہوں نے کہا کہ ہاں اے ابوالقاسم! پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تمہارا پردادا کون ہے؟ انہوں نے کہا کہ فلاں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم جھوٹ کہتے ہو تمہارا پردادا تو فلاں ہے۔ اس پر وہ بولے کہ آپ نے سچ فرمایا، درست فرمایا، پھر نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا کیا اگر میں تم سے کوئی بات پوچھوں گا تو تم مجھے سچ سچ بتا دو گے؟ انہوں نے کہا کہ ہاں اے ابوالقاسم! اور اگر ہم جھوٹ بولیں بھی تو آپ ہمارا جھوٹ پکڑ لیں گے جیسا کہ ابھی ہمارے پردادا کے متعلق آپ نے ہمارا جھوٹ پکڑ لیا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ دوزخ والے کون لوگ ہیں؟ انہوں نے کہا کہ کچھ دن کے لیے تو ہم اس میں رہیں گے پھر آپ لوگ ہماری جگہ لے لیں گے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم اس میں ذلت کے ساتھ پڑے رہو گے، واللہ! ہم اس میں تمہاری جگہ کبھی نہیں لیں گے۔ آپ نے پھر ان سے دریافت فرمایا کیا اگر میں تم سے ایک بات پوچھوں تو تم مجھے اس کے متعلق صحیح صحیح بتا دو گے؟ انہوں نے کہا کہ ہاں؟ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کیا تم نے اس بکری میں زہر ملایا تھا، انہوں نے کہا کہ ہاں۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ تمہیں اس کام پر کس جذبہ نے آمادہ کیا تھا؟ انہوں نے کہا کہ ہمارا مقصد یہ تھا کہ اگر آپ جھوٹے ہوں گے تو ہمیں آپ سے نجات مل جائے گی اور اگر سچے ہوں گے تو آپ کو نقصان نہیں پہنچا سکے گا۔' WHERE id = 5553;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم سے محمد بن زیاد نے بیان کیا، کہا کہ میں نے ابوہریرہ رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ نبی یا ( یہ بیان کیا کہ ) ابوالقاسم صلی اللہ علیہ وسلم نے فرمایا ” ( بنی اسرائیل میں ) ایک شخص ایک جوڑا پہن کر کبر و غرور میں سر مست، سر کے بالوں میں کنگھی کئے ہوئے اکڑ کر اتراتا جا رہا تھا کہ اللہ تعالیٰ نے اسے زمین میں دھنسا دیا اب وہ قیامت تک اس میں تڑپتا رہے گا یا دھنستا رہے گا۔“' WHERE id = 5564;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے زکریا نے بیان کیا، ان سے عامر نے، ان سے عروہ بن مغیرہ نے اور ان سے ان کے والد مغیرہ رضی اللہ عنہ نے بیان کیا کہ میں ایک رات سفر میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ تھا آپ نے دریافت فرمایا تمہارے پاس پانی ہے؟ میں نے عرض کیا کہ جی ہاں۔ نبی کریم صلی اللہ علیہ وسلم اپنی سواری سے اترے اور چلتے رہے یہاں تک کہ رات کی تاریکی میں آپ چھپ گئے پھر واپس تشریف لائے تو میں نے برتن کا پانی آپ کو استعمال کرایا نبی کریم صلی اللہ علیہ وسلم نے اپنا چہرہ دھویا، ہاتھ دھوئے آپ اون کا جبہ پہنے ہوئے تھے جس کی آستین چڑھانی آپ کے لیے دشوار تھی چنانچہ آپ نے اپنے ہاتھ جبہ کے نیچے سے نکالے اور بازوؤں کو ( کہنیوں تک ) دھویا۔ پھر سر پر مسح کیا پھر میں بڑھا کہ نبی کریم صلی اللہ علیہ وسلم کے موزے اتار دوں لیکن آپ صلی اللہ علیہ وسلم نے فرمایا کہ رہنے دو میں نے طہارت کے بعد انہیں پہنا تھا چنانچہ آپ نے ان پر مسح کیا۔' WHERE id = 5574;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن عبداللہ نے بیان کیا، کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے اسحاق بن عبداللہ بن ابی طلحہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ میں رسول اللہ صلی اللہ علیہ وسلم کے ساتھ چل رہا تھا۔ نبی کریم صلی اللہ علیہ وسلم کے جسم مبارک پر ( یمن کے ) نجران کی بنی ہوئی موٹے حاشیے کی ایک چادر تھی۔ اتنے میں ایک دیہاتی آ گیا اور اس نے نبی کریم صلی اللہ علیہ وسلم کی چادر کو پکڑ کر اتنی زور سے کھینچا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کے مونڈھے پر دیکھا کہ اس کے زور سے کھینچنے کی وجہ سے نشان پڑ گیا تھا۔ پھر اس نے کہا: اے محمد! مجھے اس مال میں سے دیئے جانے کا حکم کیجیئے جو اللہ کا مال آپ کے پاس ہے۔ نبی کریم صلی اللہ علیہ وسلم اس کی طرف متوجہ ہوئے اور مسکرائے اور آپ نے اسے دیئے جانے کا حکم فرمایا۔' WHERE id = 5584;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، انہوں نے کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے ابوالزناد نے بیان کیا، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے دو طرح کے پہناوے سے منع فرمایا یہ کہ کوئی شخص ایک ہی کپڑے سے اپنی کمر اور پنڈلی کو ملا کر باندھ لے اور شرمگاہ پر کوئی دوسرا کپڑا نہ ہو اور یہ کہ کوئی شخص ایک کپڑے کو اس طرح جسم پر لپیٹے کہ ایک طرف کپڑے کا کوئی حصہ نہ ہو اور آپ نے ملامسہ اور منابذہ سے منع فرمایا۔' WHERE id = 5595;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے حکم نے، ان سے ابن ابی لیلیٰ نے بیان کیا کہ حذیفہ رضی اللہ عنہ مدائن میں تھے۔ انہوں نے پانی مانگا۔ ایک دیہاتی چاندی کے برتن میں پانی لایا۔ انہوں نے اسے پھینک دیا اور کہا کہ میں نے صرف اسے اس لیے پھینکا ہے کہ میں اس شخص کو منع کر چکا ہوں ( کہ چاندی کے برتن میں مجھے کھانا اور پانی نہ دیا کرو ) لیکن وہ نہیں مانا۔ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ہے کہ سونا، چاندی، ریشم اور دیبا ان ( کفار ) کے لیے دنیا میں ہے اور تمہارے ( مسلمانوں ) کے لیے آخرت میں۔' WHERE id = 5605;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا کہ مجھ سے جویریہ نے بیان کیا، ان سے نافع نے، ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ عمر رضی اللہ عنہ نے ریشمی دھاریوں والا ایک جوڑا فروخت ہوتے دیکھا تو عرض کیا کہ یا رسول اللہ! بہتر ہے کہ آپ اسے خرید لیں اور وفود سے ملاقات کے وقت اور جمعہ کے دن اسے زیب تن کیا کریں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اسے وہ پہنتا ہے جس کا ( آخرت میں ) کوئی حصہ نہیں ہوتا۔ اس کے بعد نبی کریم صلی اللہ علیہ وسلم نے خود عمر رضی اللہ عنہ کے پاس ریشم کی دھاریوں والا ایک جوڑا حلہ بھیجا، ہدیہ کے طور پر۔ عمر رضی اللہ عنہ نے عرض کیا آپ نے مجھے یہ جوڑا حلہ عنایت فرمایا ہے حالانکہ میں خود آپ سے اس کے بارے میں وہ بات سن چکا ہوں جو آپ نے فرمائی تھی۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں نے تمہیں یہ کپڑا اس لیے دیا ہے کہ اسے بیچ دو یا ( عورتوں وغیرہ میں سے ) کسی کو پہنا دو۔' WHERE id = 5615;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، ان سے امام مالک نے، ان سے مقبری نے، ان سے عبید بن جریج نے کہ انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے عرض کیا کہ میں آپ کو چار ایسی چیزیں کرتے دیکھتا ہوں جو میں نے آپ کے کسی ساتھی کو کرتے نہیں دیکھا۔ ابن عمر رضی اللہ عنہما نے کہا: ابن جریج! وہ کیا چیزیں ہیں؟ انہوں نے کہا کہ میں نے آپ کو دیکھا ہے کہ آپ ( خانہ کعبہ کے ) کسی کونے کو طواف میں ہاتھ نہیں لگاتے صرف دو ارکان یمانی ( یعنی صرف رکن یمانی اور حجر اسود ) کو چھوتے ہیں اور میں نے آپ کو دیکھا ہے کہ آپ صاف زین کے چمڑے کا جوتا پہنتے ہیں اور میں نے آپ کو دیکھا کہ آپ اپنا کپڑا زرد رنگ سے رنگتے ہیں یا زرد خضاب لگاتے ہیں اور میں نے آپ کو دیکھا کہ جب مکہ میں ہوتے ہیں تو سب لوگ تو ذی الحجہ کا چاند دیکھ کر احرام باندھ لیتے ہیں لیکن آپ احرام نہیں باندھتے بلکہ ترویہ کے دن ( 8 ذی الحجہ کو ) کو احرام باندھتے ہیں۔ ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہا کہ خانہ کعبہ کے ارکان کے متعلق جو تم نے کہا تو میں نے رسول اللہ صلی اللہ علیہ وسلم کو ہمیشہ صرف حجر اسود اور رکن یمانی کو چھوتے دیکھا۔ صاف تری کے چمڑے کے جوتوں کے متعلق جو تم نے پوچھا تو میں نے دیکھا ہے کہ نبی کریم صلی اللہ علیہ وسلم اسی چمڑے کا جوتا پہنتے تھے جس میں بال نہیں ہوتے تھے اور آپ اس کو پہنے ہوئے وضو کرتے تھے اس لیے میں بھی پسند کرتا ہوں کہ ایسا ہی جوتا استعمال کروں۔ زرد رنگ کے متعلق تم نے جو کہا ہے تو میں نے نبی کریم صلی اللہ علیہ وسلم کو اس سے خضاب کرتے یا کپڑے رنگتے دیکھا ہے اس لیے میں بھی اس زرد رنگ کو پسند کرتا ہوں اور رہا احرام باندھنے کا مسئلہ تو میں نے نبی کریم صلی اللہ علیہ وسلم کو دیکھا کہ آپ اسی وقت احرام باندھتے جب اونٹ پر سوار ہو کر جانے لگتے۔' WHERE id = 5625;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن ابی بکر نے بیان کیا، انہوں نے کہا ہم سے معتمر نے بیان کیا، ان سے عبیداللہ نے بیان کیا، ان سے سعید بن ابی سعید نے بیان کیا، ان سے ابوسلمہ بن عبدالرحمٰن نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم رات میں چٹائی کا گھیرا بنا لیتے تھے اور ان گھیرے میں نماز پڑھتے تھے اور اسی چٹائی کو دن میں بچھاتے تھے اور اس پر بیٹھتے تھے پھر لوگ ( رات کی نماز کے وقت ) نبی کریم صلی اللہ علیہ وسلم کے پاس جمع ہونے لگے اور نبی کریم صلی اللہ علیہ وسلم کی نماز کی اقتداء کرنے لگے جب مجمع زیادہ بڑھ گیا تو نبی کریم صلی اللہ علیہ وسلم متوجہ ہوئے اور فرمایا کہ لوگو! عمل اتنے ہی کیا کرو جتنی کہ تم میں طاقت ہو کیونکہ اللہ تعالیٰ ( اجر دینے سے ) نہیں تھکتا مگر تم ( عمل سے ) تھک جاتے ہو اور اللہ کی بارگاہ میں سب سے زیادہ پسند وہ عمل ہے جسے پابندی سے ہمیشہ کیا جائے، خواہ وہ کم ہی ہو۔' WHERE id = 5635;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، کہا ہم سے عبدالعزیز بن ابی حازم نے بیان کیا، ان سے ان کے والد نے اور انہوں نے سہل رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ ایک عورت نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئیں اور عرض کی کہ میں اپنے آپ کو ہبہ کرنے آئی ہوں، دیر تک وہ عورت کھڑی رہی۔ نبی کریم صلی اللہ علیہ وسلم نے انہیں دیکھا اور پھر سر جھکا لیا جب دیر تک وہ وہیں کھڑی رہیں تو ایک صاحب نے اٹھ کر عرض کیا: اگر نبی کریم صلی اللہ علیہ وسلم کو ان کی ضرورت نہیں ہے تو ان کا نکاح مجھ سے کر دیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا، تمہارے پاس کوئی چیز ہے جو مہر میں انہیں دے سکو، انہوں نے کہا کہ نہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ دیکھ لو۔ وہ گئے اور واپس آ کر عرض کیا کہ واللہ! مجھے کچھ نہیں ملا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جاؤ تلاش کرو، لوہے کی ایک انگوٹھی ہی سہی۔ وہ گئے اور واپس آ کر عرض کیا کہ وہ مجھے لوہے کی ایک انگوٹھی بھی نہیں ملی۔ وہ ایک تہمد پہنے ہوئے تھے اور ان کے جسم پر ( کرتے کی جگہ ) چادر بھی نہیں تھی۔ انہوں نے عرض کیا کہ میں انہیں اپنا تہمد مہر میں دے دوں گا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر تمہارا تہمد یہ پہن لیں گی تو تمہارے لیے کچھ باقی نہیں رہے گا۔ اور اگر تم اسے پہن لو گے تو ان کے لیے کچھ نہیں رہے گا۔ وہ صاحب اس کے بعد ایک طرف بیٹھ گئے پھر جب نبی کریم صلی اللہ علیہ وسلم نے انہیں جاتے دیکھا تو آپ صلی اللہ علیہ وسلم نے انہیں بلوایا اور فرمایا تمہیں قرآن کتنا یاد ہے؟ انہوں نے عرض کیا کہ فلاں فلاں سورتیں۔ انہوں نے سورتوں کو شمار کیا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جا میں نے اس عورت کو تمہارے نکاح میں اس قرآن کے عوض میں دے دیا جو تمہیں یاد ہے۔' WHERE id = 5645;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عرعرہ نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے عدی بن ثابت نے، ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم عیدالفطر کے دن ( آبادی سے باہر ) گئے اور دو رکعت نماز پڑھائی آپ نے اس سے پہلے اور اس کے بعد کوئی دوسری نفل نماز نہیں پڑھی پھر آپ عورتوں کے مجمع کی طرف آئے اور انہیں صدقہ کا حکم فرمایا۔ چنانچہ عورتیں اپنی بالیاں اور خوشبو اور مشک کے ہار صدقہ میں دینے لگیں۔' WHERE id = 5655;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، انہوں نے کہا ہم سے ابراہیم بن سعد نے بیان کیا، انہوں نے کہا ہم سے ابن شہاب نے بیان کیا، ان سے سعید بن مسیب نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا ”پانچ چیزیں ختنہ کرانا، زیر ناف مونڈنا، مونچھ کترانا، ناخن ترشوانا اور بغل کے بال نوچنا پیدائشی سنتیں ہیں۔“' WHERE id = 5665;
UPDATE hadiths SET urdu = 'ہم سے مالک بن اسماعیل نے بیان کیا، کہا ہم سے اسرائیل نے، ان سے ابواسحاق نے، کہا میں براء رضی اللہ عنہ سے سنا، انہوں نے بیان کہا کہ میں نے سرخ حلہ میں نبی کریم صلی اللہ علیہ وسلم سے زیادہ کسی کو خوبصورت نہیں دیکھا ( امام بخاری رحمہ اللہ نے کہا کہ ) مجھ سے میرے بعض اصحاب نے امام مالک رحمہ اللہ سے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے سر کے بال شانہ مبارک کے قریب تک تھے۔ ابواسحاق نے بیان کیا کہ میں نے براء رضی اللہ عنہ کو ایک مرتبہ سے زیادہ یہ حدیث بیان کرتے سنا جب بھی وہ یہ حدیث بیان کرتے تو مسکراتے۔ اس روایت کی متابعت شعبہ نے کی کہ نبی کریم صلی اللہ علیہ وسلم کے بال آپ کے کانوں کی لو تک تھے۔' WHERE id = 5675;
UPDATE hadiths SET urdu = 'مجھ سے حبان بن موسیٰ اور احمد بن محمد نے بیان کیا، انہوں نے کہا کہ ہمیں عبداللہ بن مبارک نے خبر دی، انہوں نے کہا ہم کو یونس نے خبر دی، انہیں زہری نے، انہیں سالم نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے اپنے بال جما لیے تھے اور احرام کے وقت یوں آپ لبیک کہہ رہے تھے «لبيك اللهم لبيك،‏‏‏‏ لبيك لا شريك لك لبيك،‏‏‏‏ إن الحمد والنعمة لك والملك لا شريك لك» ان کلمات کے اوپر اور کچھ آپ نہیں بڑھاتے تھے۔' WHERE id = 5687;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تینسی نے بیان کیا، انہوں نے کہا ہم کو امام مالک نے خبر دی، انہیں ابن شہاب نے خبر دی، انہیں عروہ بن زبیر نے اور ان سے ام المؤمنین عائشہ رضی اللہ عنہا نے بیان کیا کہ میں حالت حیض کے باوجود نبی کریم صلی اللہ علیہ وسلم کے سر میں کنگھا کرتی تھی۔ ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو امام مالک نے خبر دی، انہیں ہشام نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے اسی طرح یہ حدیث بیان کی۔' WHERE id = 5697;
UPDATE hadiths SET urdu = 'مجھ سے احمد بن مقدام نے بیان کیا، کہا ہم سے فضل بن سلیمان نے بیان کیا، کہا ہم سے منصور بن عبدالرحمٰن نے بیان کیا، کہا کہ مجھ سے میری والدہ صفیہ بنت شیبہ نے بیان کیا، ان سے اسماء بنت ابی بکر رضی اللہ عنہما نے بیان کیا کہ ایک خاتون نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئیں اور کہا کہ میں نے اپنی لڑکی کی شادی کی ہے اس کے بعد وہ بیمار ہو گئی اور اس کے سر کے بال جھڑ گئے اور اس کا شوہر مجھ پر اس کے معاملہ میں زور دیتا ہے۔ کیا میں اس کے سر میں مصنوعی بال لگا دوں؟ اس پر نبی کریم صلی اللہ علیہ وسلم نے مصنوعی بال جوڑنے والیوں اور جڑوانے والیوں کو برا کہا، ان پر لعنت بھیجی۔' WHERE id = 5707;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے عون بن ابی حجیفہ نے بیان کیا کہ میں نے اپنے والد (ابوحجیفہ رضی اللہ عنہ) کو دیکھا، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے خون کی قیمت، کتے کی قیمت کھانے سے منع فرمایا اور سود لینے والے اور دینے والے، گودنے والی اور گودانے والی ( پر لعنت بھیجی ) ۔' WHERE id = 5718;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے عبداللہ بن داؤد نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم سفر سے آئے اور میں نے پردہ لٹکا رکھا تھا جس میں تصویریں تھیں، نبی کریم صلی اللہ علیہ وسلم نے مجھے اس کے اتار لینے کا حکم دیا تو میں نے اسے اتار لیا۔' WHERE id = 5728;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یزید بن زریع نے بیان کیا، کہا ہم سے خالد حذاء نے بیان کیا، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم مکہ مکرمہ تشریف لائے ( فتح کے موقع پر ) تو عبدالمطلب کی اولاد نے ( جو مکہ میں تھی ) آپ کا استقبال کیا۔ ( یہ سب بچے ہی تھے ) آپ نے از راہ محبت ایک بچے کو اپنے سامنے اور ایک کو اپنے پیچھے بٹھا لیا۔' WHERE id = 5738;
UPDATE hadiths SET urdu = 'ہم سے سعد بن حفص نے بیان کیا، کہا ہم سے شیبان نے بیان کیا، ان سے منصور نے، ان سے مسیب نے ان سے وراد نے اور ان سے مغیرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ نے تم پر ماں کی نافرمانی حرام قرار دی ہے اور ( والدین کے حقوق ) نہ دینا اور ناحق ان سے مطالبات کرنا بھی حرام قرار دیا ہے، لڑکیوں کو زندہ دفن کرنا ( بھی حرام قرار دیا ہے ) اور «قيل وقال» ( فضول باتیں ) کثرت سوال اور مال کی بربادی کو بھی ناپسند کیا ہے۔' WHERE id = 5748;
UPDATE hadiths SET urdu = 'مجھ سے ابراہیم بن المنذر نے بیان کیا، انہوں نے کہا ہم سے محمد بن معن نے بیان کیا، انہوں نے کہا کہ مجھ سے میرے والد نے بیان کیا، انہوں نے کہا ہم سے سعید بن ابی سعید نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جسے پسند ہے کہ اس کی روزی میں فراخی ہو اور اس کی عمردراز کی جائے تو وہ صلہ رحمی کیا کرے۔' WHERE id = 5758;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، کہا مجھ سے عبداللہ بن ابی بکر نے بیان کیا، انہیں عروہ بن زبیر نے خبر دی اور ان سے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے بیان کیا کہ میرے یہاں ایک عورت ( اور ) اس کے ساتھ دو بچیاں تھیں، وہ مانگنے آئی تھی۔ میرے پاس سے سوا ایک کھجور کے اسے اور کچھ نہ ملا۔ میں نے اسے وہ کھجور دے دی اور اس نے وہ کھجور اپنی دونوں لڑکیوں کو تقسیم کر دی۔ پھر اٹھ کر چلی گئی اس کے بعد نبی کریم صلی اللہ علیہ وسلم تشریف لائے تو میں نے آپ سے اس کا ذکر کیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ جو شخص بھی اس طرح کی لڑکیوں کی پرورش کرے گا اور ان کے ساتھ اچھا معاملہ کرے گا تو یہ اس کے لیے جہنم سے پردہ بن جائیں گی۔' WHERE id = 5768;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن عبدالوہاب نے بیان کیا، کہا کہ مجھ سے عبدالعزیز بن ابی حازم نے بیان کیا، کہا کہ مجھ سے میرے والد نے بیان کیا، کہا کہ میں نے سہل بن سعد رضی اللہ عنہ سے سنا، ان سے نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں اور یتیم کی پرورش کرنے والا جنت میں اس طرح ہوں گے اور آپ نے شہادت اور درمیانی انگلیوں کے اشارہ سے ( قرب کو ) بتایا۔' WHERE id = 5778;
UPDATE hadiths SET urdu = 'ہم سے محمد بن منہال نے بیان کیا، کہا ہم سے یزید بن زریع نے بیان کیا، ان سے عمر بن محمد نے، ان سے ان کے والد نے اور ان سے ابن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جبرائیل علیہ السلام مجھے اس طرح باربار پڑوسی کے حق میں وصیت کرتے رہے کہ مجھے خیال گزرا کہ شاید پڑوسی کو وراثت میں شریک نہ کر دیں۔“' WHERE id = 5788;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن عبدالوہاب نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے ثابت نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہا کہ ایک دیہاتی نے مسجد میں پیشاب کر دیا تھا۔ صحابہ کرام ان کی طرف دوڑے لیکن رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اس کے پیشاب کو مت روکو۔ پھر آپ نے پانی کا ڈول منگوایا اور وہ پیشاب کی جگہ پر بہا دیا گیا۔' WHERE id = 5798;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، انہیں زہری نے کہا کہ مجھے حمید بن عبدالرحمٰن نے خبر دی اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”زمانہ جلدی جلدی گزرے گا اور دین کا علم دنیا میں کم ہو جائے گا اور دلوں میں بخیلی سما جائے گی اور لڑائی بڑھ جائے گی۔“ صحابہ رضی اللہ عنہم نے عرض کیا «هرج» کیا ہوتا ہے؟ فرمایا قتل خون ریزی۔' WHERE id = 5809;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے عثمان بن عمر نے، کہا ہم سے علی بن مبارک نے بیان کیا، ان سے یحییٰ بن ابی کثیر نے، ان سے ابوقلابہ نے کہ ثابت بن ضحاک رضی اللہ عنہ اصحاب شجر ( بیعت رضوان کرنے والوں ) میں سے تھے، انہوں نے ان سے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جو اسلام کے سوا کسی اور مذہب پر قسم کھائے ( کہ اگر میں نے فلاں کام کیا تو میں نصرانی ہوں، یہودی ہوں ) تو وہ ایسا ہو جائے گا جیسے کہ اس نے کہا اور کسی انسان پر ان چیزوں کی نذر صحیح نہیں ہوتی جو اس کے اختیار میں نہ ہوں اور جس نے دنیا میں کسی چیز سے خودکشی کر لی اسے اسی چیز سے آخرت میں عذاب ہو گا اور جس نے کسی مسلمان پر لعنت بھیجی تو یہ اس کے خون کرنے کے برابر ہے اور جو شخص کسی مسلمان کو کافر کہے تو وہ ایسا ہے جیسے اس کا خون کیا۔' WHERE id = 5819;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، کہا ہم سے ابن ابی ذئب نے بیان کیا، ان سے سعید مقبری نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جو شخص ( روزہ کی حالت میں ) جھوٹ بات کرنا اور فریب کرنا اور جہالت کی باتوں کو نہ چھوڑے تو اللہ کو اس کی کوئی ضرورت نہیں کہ وہ اپنا کھانا پینا چھوڑے۔ احمد بن یونس نے کہا یہ حدیث میں نے سنی تو تھی مگر میں اس کی سند بھول گیا تھا جو مجھ کو ایک شخص ( ابن ابی ذئب ) نے بتلا دی۔' WHERE id = 5829;
UPDATE hadiths SET urdu = 'ہم سے سعید بن عفیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میں گمان کرتا ہوں کہ فلاں اور فلاں ہمارے دین کی کوئی بات نہیں جانتے ہیں۔“ لیث بن سعد نے بیان کیا کہ یہ دونوں آدمی منافق تھے۔' WHERE id = 5839;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا ہم کو عبدالوہاب ثقفی نے خبر دی، انہیں خالد حذاء نے، انہیں انس بن سیرین نے اور انہیں انس بن مالک رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم قبیلہ انصار کے گھرانہ میں ملاقات کے لیے تشریف لے گئے اور انہیں کے یہاں کھانا کھایا، جب آپ واپس تشریف لانے لگے تو آپ کے حکم سے ایک چٹائی پر پانی چھڑکا گیا اور نبی کریم صلی اللہ علیہ وسلم نے اس پر نماز پڑھی اور گھر والوں کے لیے دعا کی۔' WHERE id = 5850;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، کہا ہم سے یحییٰ قطان نے بیان کیا، ان سے ہشام بن عروہ نے بیان کیا، انہیں ان کے والد نے خبر دی، انہیں زینب بنت ام سلمہ رضی اللہ عنہما نے، انہیں ام سلمہ رضی اللہ عنہا نے کہ ام سلیم رضی اللہ عنہا نے عرض کیا: یا رسول اللہ! اللہ حق سے نہیں شرماتا، کیا عورت کو جب احتلام ہو تو اس پر غسل واجب ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہاں جب عورت پانی دیکھے ( تو اس پر غسل واجب ہے ) اس پر ام سلمہ رضی اللہ عنہا ہنسیں اور عرض کیا، کیا عورت کو بھی احتلام ہوتا ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر بچہ کی صورت ماں سے کیوں ملتی ہے۔' WHERE id = 5860;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن حفص بن غیاث نے بیان کیا، کہا ہم سے ہمارے والد نے بیان کیا، کہا ہم سے اعمش نے بیان کیا، کہا ہم سے مسلم نے بیان کیا، ان سے مسروق نے بیان کیا اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ایک کام کیا اور لوگوں کو بھی اس کی اجازت دے دی لیکن کچھ لوگوں نے اس کا نہ کرنا اچھا جانا۔ جب نبی کریم صلی اللہ علیہ وسلم کو اس کی اطلاع ہوئی تو آپ نے خطبہ دیا اور اللہ کی حمد کے بعد فرمایا کہ ان لوگوں کو کیا ہو گیا ہے جو اس کام سے پرہیز کرتے ہیں، جو میں کرتا ہوں، اللہ کی قسم میں اللہ کو ان سب سے زیادہ جانتا ہوں اور ان سب سے زیادہ اللہ سے ڈرنے والا ہوں۔' WHERE id = 5870;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے کہا ہم سے جویریہ نے بیان کیا، ان سے نافع نے بیان کیا اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نماز پڑھ رہے تھے کہ آپ صلی اللہ علیہ وسلم نے مسجد میں قبلہ کی جانب منہ کا تھوک دیکھا۔ پھر آپ نے اسے اپنے ہاتھ سے صاف کیا اور غصہ ہوئے پھر فرمایا جب تم میں سے کوئی شخص نماز میں ہوتا ہے اللہ تعالیٰ اس کے سامنے ہوتا ہے۔ اس لیے کوئی شخص نماز میں اپنے سامنے نہ تھوکے۔' WHERE id = 5880;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا مجھ سے امام مالک نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے، ان سے زینب بنت ابی سلمہ رضی اللہ عنہا نے اور ان سے ام سلمہ رضی اللہ عنہا نے بیان کیا کہ ام سلیم رضی اللہ عنہا رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئیں اور عرض کیا: یا رسول اللہ! اللہ حق بات سے حیاء نہیں کرتا کیا عورت کو جب احتلام ہو تو اس پر غسل واجب ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہاں اگر عورت منی کی تری دیکھے تو اس پر بھی غسل واجب ہے۔' WHERE id = 5890;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے، ان سے ابن المنکدر نے، ان سے عروہ بن زبیر نے اور انہیں عائشہ رضی اللہ عنہا نے خبر دی کہ نبی کریم صلی اللہ علیہ وسلم سے ایک شخص نے اندر آنے کی اجازت چاہی تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اسے اندر بلا لو، یہ اپنی قوم کا بہت ہی برا آدمی ہے۔ جب وہ شخص اندر آ گیا تو نبی کریم صلی اللہ علیہ وسلم نے اس کے ساتھ نرمی کے ساتھ گفتگو فرمائی۔ میں نے عرض کیا: یا رسول اللہ! آپ نے ابھی اس کے متعلق کیا فرمایا تھا اور پھر اتنی نرمی کے ساتھ گفتگو فرمائی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، عائشہ اللہ کے نزدیک مرتبہ کے اعتبار سے وہ شخص سب سے برا ہے جسے لوگ اس کی بدخلقی کی وجہ سے چھوڑ دیں۔' WHERE id = 5900;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن مثنیٰ نے بیان کیا، کہا ہم سے ابن ابی عدی نے بیان کیا، ان سے سلیمان ابن طرفان نے، ان سے ابوعثمان نہدی نے کہ عبدالرحمٰن بن ابی بکر رضی اللہ عنہما نے بیان کیا کہ ابوبکر رضی اللہ عنہ اپنا ایک مہمان یا کئی مہمان لے کر گھر آئے۔ پھر آپ شام ہی سے نبی کریم صلی اللہ علیہ وسلم کے پاس چلے گئے، جب وہ لوٹ کر آئے تو میری والدہ نے کہا کہ آج اپنے مہمانوں کو چھوڑ کر آپ کہاں رہ گئے تھے۔ ابوبکر رضی اللہ عنہ نے پوچھا کیا تم نے ان کو کھانا نہیں کھلایا۔ انہوں نے کہا کہ ہم نے تو کھانا ان کے سامنے پیش کیا لیکن انہوں نے انکار کیا۔ یہ سن کر ابوبکر رضی اللہ عنہ کو غصہ آیا اور انہوں نے ( گھر والوں کی ) سرزنش کی اور دکھ کا اظہار کیا اور قسم کھا لی کہ میں کھانا نہیں کھاؤں گا۔ عبدالرحمٰن کہتے ہیں کہ میں تو ڈر کے مارے چھپ گیا تو آپ نے پکارا کہ اے پاجی! کدھر ہے تو ادھر آ۔ میری والدہ نے بھی قسم کھا لی کہ اگر وہ کھانا نہیں کھائیں گے تو وہ بھی نہیں کھائیں گی۔ اس کے بعد مہمانوں نے بھی قسم کھا لی کہ اگر ابوبکر رضی اللہ عنہ نہیں کھائیں گے تو وہ بھی نہیں کھائیں گے۔ آخر ابوبکر رضی اللہ عنہ نے کہا کہ یہ غصہ کرنا شیطانی کام تھا، پھر آپ نے کھانا منگوایا اور خود بھی مہمانوں کے ساتھ کھایا ( اس کھانے میں یہ برکت ہوئی ) جب یہ لوگ ایک لقمہ اٹھاتے تو نیچے سے کھانا اور بھی بڑھ جاتا تھے۔ ابوبکر رضی اللہ عنہ نے کہا: اے بنی فراس کی بہن! یہ کیا ہو رہا ہے، کھانا تو اور بڑھ گیا۔ انہوں نے کہا کہ میری آنکھوں کی ٹھنڈک! اب یہ اس سے بھی زیادہ ہو گیا۔ جب ہم نے کھانا کھایا بھی نہیں تھا۔ پھر سب نے کھایا اور اس میں سے نبی کریم صلی اللہ علیہ وسلم کی خدمت میں بھیجا، کہتے ہیں کہ نبی کریم صلی اللہ علیہ وسلم نے بھی اس کھانے میں سے کھایا۔' WHERE id = 5910;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے عدی بن ثابت نے اور ان سے براء بن عازب رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے حسان رضی اللہ عنہ سے فرمایا ان کی ہجو کرو ( یعنی مشرکین قریش کی ) ۔ یا نبی کریم صلی اللہ علیہ وسلم نے ( «هاجهم» کے الفاظ فرمائے ) جبرائیل علیہ السلام تیرے ساتھ ہیں۔' WHERE id = 5921;
UPDATE hadiths SET urdu = 'مجھ سے عبدالرحمٰن بن ابراہیم نے بیان کیا، کہا ہم سے ولید نے بیان کیا، ان سے امام اوزاعی نے، ان سے زہری نے، ان سے ابوسلمہ اور ضحاک نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ ایک دن نبی کریم صلی اللہ علیہ وسلم کچھ تقسیم کر رہے تھے۔ بنی تمیم کے ایک شخص ذوالخویصرۃ نے کہا: یا رسول اللہ! انصاف سے کام لیجئے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، افسوس! اگر میں ہی انصاف نہیں کروں گا تو پھر کون کرے گا۔ عمر رضی اللہ عنہ نے کہا: یا رسول اللہ! مجھے اجازت دیں تو میں اس کی گردن مار دوں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ نہیں۔ اس کے کچھ ( قبیلہ والے ) ایسے لوگ پیدا ہوں گے کہ تم ان کی نماز کے مقابلہ میں اپنی نماز کو معمولی سمجھو گے اور ان کے روزوں کے مقابلہ میں اپنے روزے کو معمولی سمجھو گے لیکن وہ دین سے اس طرح نکل چکے ہوں گے جس طرح تیر شکار سے نکل جاتا ہے۔ تیر کے پھل میں دیکھا جائے تو اس پر بھی کوئی نشان نہیں ملے گا۔ اس کی لکڑی پر دیکھا جائے تو اس پر بھی کوئی نشان نہیں ملے گا۔ پھر اس کے دندانوں میں دیکھا جائے اور اس میں بھی کچھ نہیں ملے گا پھر اس کے پر میں دیکھا جائے تو اس میں بھی کچھ نہیں ملے گا۔ ( یعنی شکار کے جسم کو پار کرنے کا کوئی نشان ) تیر لید اور خون کو پار کر کے نکل چکا ہو گا۔ یہ لوگ اس وقت پیدا ہوں گے جب لوگوں میں پھوٹ پڑ جائے گی۔ ( ایک خلیفہ پر متفق نہ ہوں گے ) ان کی نشانی ان کا ایک مرد ( سردار لشکر ) ہو گا۔ جس کا ایک ہاتھ عورت کے پستان کی طرح ہو گا یا ( فرمایا ) گوشت کے لوتھڑے کی طرح تھل تھل ہل رہا ہو گا۔ ابوسعید رضی اللہ عنہ نے بیان کیا کہ میں گواہی دیتا ہوں کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے یہ حدیث سنی اور میں گواہی دیتا ہوں کہ میں علی رضی اللہ عنہ کے ساتھ تھا۔ جب انہوں نے ان خارجیوں سے ( نہروان میں ) جنگ کی تھی۔ مقتولین میں تلاش کی گئی تو ایک شخص انہیں صفات کا لایا گیا جو نبی کریم صلی اللہ علیہ وسلم نے بیان کی تھیں۔ اس کا ایک ہاتھ پستان کی طرح کا تھا۔' WHERE id = 5931;
UPDATE hadiths SET urdu = 'سالم نے بیان کیا کہ عبداللہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم لوگوں کے مجمع میں کھڑے ہوئے اور اللہ کی اس کی شان کے مطابق تعریف کرنے کے بعد آپ صلی اللہ علیہ وسلم نے دجال کا ذکر کیا اور فرمایا کہ میں تمہیں اس سے ڈراتا ہوں۔ کوئی نبی ایسا نہیں گزرا جس نے اپنی قوم کو اس سے نہ ڈرایا ہو۔ نوح علیہ السلام نے اپنی قوم کو اس سے ڈرایا لیکن میں اس کی تمہیں ایک ایسی نشانی بتاؤں گا جو کسی نبی نے اپنی قوم کو نہیں بتائی تم جانتے ہو کہ وہ کانا ہو گا اور اللہ کانا نہیں ہے۔' WHERE id = 5941;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے بشر بن مفضل نے بیان کیا، کہا ہم سے یحییٰ بن ابی اسحاق نے بیان کیا اور ان سے انس بن مالک رضی اللہ عنہ نے کہ وہ اور ابوطلحہ نبی کریم صلی اللہ علیہ وسلم کے ساتھ ( مدینہ منورہ کے لیے ) روانہ ہوئے۔ ام المؤمنین صفیہ رضی اللہ عنہا نبی کریم صلی اللہ علیہ وسلم کی سواری پر آپ کے پیچھے تھیں، راستہ میں کسی جگہ اونٹنی کا پاؤں پھسل گیا اور نبی کریم صلی اللہ علیہ وسلم اور ام المؤمنین گر گئے۔ انس رضی اللہ عنہ نے بیان کیا کہ میرا خیال ہے ابوطلحہ نے اپنی سواری سے فوراً اپنے کو گرا دیا اور نبی کریم صلی اللہ علیہ وسلم کی خدمت میں پہنچ گئے اور عرض کیا: یا نبی اللہ! اللہ آپ پر مجھے قربان کرے کیا آپ کو کوئی چوٹ آئی؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ نہیں، البتہ عورت کو دیکھو۔ چنانچہ ابوطلحہ رضی اللہ عنہ نے کپڑا اپنے چہرے پر ڈال لیا، پھر ام المؤمنین کی طرف بڑھے اور اپنا کپڑا ان کے اوپر ڈال دیا۔ اس کے بعد وہ کھڑی ہو گئیں اور نبی کریم صلی اللہ علیہ وسلم اور ام المؤمنین کے لیے ابوطلحہ نے پالان مضبوط باندھا۔ اب آپ نے سوار ہو کر پھر سفر شروع کیا، جب مدینہ منورہ کے قریب پہنچے ( یا یوں کہا کہ مدینہ دکھائی دینے لگا ) تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا «آيبون تائبون،‏‏‏‏ عابدون لربنا حامدون» ”ہم لوٹنے والے ہیں توبہ کرتے ہوئے اپنے رب کی عبادت کرتے ہوئے اور اس کی حمد بیان کرتے ہوئے۔“ نبی کریم صلی اللہ علیہ وسلم اسے برابر کہتے رہے یہاں تک کہ مدینہ میں داخل ہو گئے۔' WHERE id = 5951;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم کو شعبہ نے خبر دی، انہیں عدی بن ثابت نے کہا کہ میں نے براء رضی اللہ عنہ سے سنا، بیان کیا کہ جب آپ کے فرزند ابراہیم علیہ السلام کا انتقال ہوا تو رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اس کے لیے جنت میں ایک دودھ پلانے والی دایہ مقرر ہو گئی ہے۔“' WHERE id = 5961;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، کہا ہم سے ابوالزناد نے بیان کیا، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”قیامت کے دن اللہ کے نزدیک سب سے بدترین نام اس کا ہو گا جو اپنا نام ملک الاملاک ( شہنشاہ ) رکھے۔“' WHERE id = 5971;
UPDATE hadiths SET urdu = 'ہم سے ابن ابی مریم نے بیان کیا، کہا ہم سے محمد بن جعفر نے بیان کیا، کہا کہ مجھے شریک نے خبر دی، انہیں کریب نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ میں نے ایک رات میمونہ رضی اللہ عنہا ( خالہ ) کے گھر گزاری، نبی کریم صلی اللہ علیہ وسلم بھی اس رات وہیں ٹھہرے ہوئے تھے۔ جب رات کا آخری تہائی حصہ ہوا یا اس کا بعض حصہ رہ گیا تو نبی کریم صلی اللہ علیہ وسلم اٹھ بیٹھے اور آسمان کی طرف دیکھا پھر اس آیت کی تلاوت کی «إن في خلق السموات والأرض واختلاف الليل والنهار لآيات لأولي الألباب‏» ”بلاشبہ آسمان کی اور زمین کی پیدائش میں اور دن رات کے بدلتے رہنے میں عقل والوں کے لیے نشانیاں ہیں۔“' WHERE id = 5981;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم سے سلیمان تیمی نے بیان کیا، کہا کہ میں نے انس رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کی موجودگی میں دو آدمیوں نے چھینکا۔ لیکن نبی کریم صلی اللہ علیہ وسلم نے ان میں سے ایک کی چھینک پر یرحمک اللہ کہا اور دوسرے کی چھینک پر نہیں کہا۔ اس پر دوسرا شخص بولا کہ یا رسول اللہ! آپ نے ان کی چھینک پر یرحمک اللہ فرمایا۔ لیکن میری چھینک پر نہیں فرمایا؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ انہوں نے الحمدللہ کہا تھا اور تم نے نہیں کہا تھا۔' WHERE id = 5991;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، کہا ہم سے جریر نے بیان کیا، ان سے شیبانی نے، ان سے اشعث بن ابی الشعثاء نے، ان سے معاویہ بن سوید بن مقرن نے اور ان سے براء بن عازب رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ہمیں سات باتوں کا حکم دیا تھا۔ بیمار کی مزاج پرسی کرنے کا، جنازے کے پیچھے چلنے کا، چھینکنے والے کے جواب دینے کا۔ کمزور کی مدد کرنے کا، مظلوم کی مدد کرنے کا، افشاء سلام ( سلام کا جواب دینے اور بکثرت سلام کرنے ) کا، قسم ( حق ) کھانے والے کی قسم پوری کرنے کا، اور نبی کریم صلی اللہ علیہ وسلم نے چاندی کے برتن میں پینے سے منع فرمایا تھا اور سونے کی انگوٹھی پہننے سے ہمیں منع فرمایا تھا۔ میثر ( ریشم کی زین ) پر سوار ہونے سے، ریشم اور دیباج پہننے، قسی ( ریشمی کپڑا ) اور استبرق پہننے سے ( منع فرمایا تھا ) ۔' WHERE id = 6001;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، کہا ہم سے یزید بن خصیفہ نے بیان کیا ان سے بسر بن سعید اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ میں انصار کی ایک مجلس میں تھا کہ ابوموسیٰ رضی اللہ عنہ تشریف لائے جیسے گھبرائے ہوئے ہوں۔ انہوں نے کہا کہ میں نے عمر رضی اللہ عنہ کے یہاں تین مرتبہ اندر آنے کی اجازت چاہی لیکن مجھے کوئی جواب نہیں ملا، اس لیے واپس چلا آیا ( عمر رضی اللہ عنہ کو معلوم ہوا ) تو انہوں نے دریافت کیا کہ ( اندر آنے میں ) کیا بات مانع تھی؟ میں نے کہا کہ میں نے تین مرتبہ اندر آنے کی اجازت مانگی اور جب مجھے کوئی جواب نہیں ملا تو واپس چلا گیا اور رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ہے کہ جب تم میں سے کوئی کسی سے تین مرتبہ اجازت چاہے اور اجازت نہ ملے تو واپس چلا جانا چاہئے۔ عمر رضی اللہ عنہ نے کہا: واللہ! تمہیں اس حدیث کی صحت کے لیے کوئی گواہ لانا ہو گا۔ ( ابوموسیٰ رضی اللہ عنہ نے مجلس والوں سے پوچھا ) کیا تم میں کوئی ایسا ہے جس نے نبی کریم صلی اللہ علیہ وسلم سے یہ حدیث سنی ہو؟ ابی بن کعب رضی اللہ عنہ نے کہا کہ اللہ کی قسم! تمہارے ساتھ ( اس کی گواہی دینے کے سوا ) جماعت میں سب سے کم عمر شخص کے کوئی اور نہیں کھڑا ہو گا۔ ابوسعید نے کہا اور میں ہی جماعت کا وہ سب سے کم عمر آدمی تھا میں ان کے ساتھ اٹھ کھڑا ہو گیا اور عمر رضی اللہ عنہ سے کہا کہ واقعی نبی کریم صلی اللہ علیہ وسلم نے ایسا فرمایا ہے۔ اور ابن مبارک نے بیان کیا کہ مجھ کو سفیان بن عیینہ نے خبر دی، کہا مجھ سے یزید بن خصیفہ نے بیان کیا، انہوں نے بسر بن سعید سے، کہا میں نے ابوسعید رضی اللہ عنہ سے سنا پھر یہی حدیث نقل کی۔' WHERE id = 6011;
UPDATE hadiths SET urdu = 'ہم سے ابن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، ان سے عبدالرحمٰن بن عبداللہ نے اور ان سے عبداللہ بن کعب نے بیان کیا کہ میں نے کعب بن مالک سے سنا، وہ بیان کرتے تھے کہ جب وہ غزوہ تبوک میں شریک نہیں ہو سکے تھے اور نبی کریم صلی اللہ علیہ وسلم نے ہم سے بات چیت کرنے کی ممانعت کر دی تھی اور میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہو کر سلام کرتا تھا اور یہ اندازہ لگاتا تھا کہ نبی کریم صلی اللہ علیہ وسلم نے جواب سلام میں ہونٹ مبارک ہلائے یا نہیں، آخر پچاس دن گزر گئے اور نبی کریم صلی اللہ علیہ وسلم نے اللہ کی بارگاہ میں ہماری توبہ کے قبول کئے جانے کا نماز فجر کے بعد اعلان کیا۔' WHERE id = 6021;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے سیف نے بیان کیا، انہوں نے کہا کہ میں نے مجاہد سے سنا، انہوں نے کہا کہ مجھ سے عبداللہ بن بخرہ ابومعمر نے بیان کیا کہ میں نے عبداللہ بن مسعود رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے مجھے تشہد سکھایا، اس وقت میرا ہاتھ نبی کریم صلی اللہ علیہ وسلم کی ہتھیلیوں کے درمیان میں تھا ( اس طرح سکھایا ) جس طرح آپ قرآن کی سورت سکھایا کرتے تھے۔ «التحيات لله والصلوات والطيبات،‏‏‏‏ السلام عليك أيها النبي ورحمة الله وبركاته،‏‏‏‏ السلام علينا وعلى عباد الله الصالحين،‏‏‏‏ أشهد أن لا إله إلا الله وأشهد أن محمدا عبده ورسوله‏.‏» نبی کریم صلی اللہ علیہ وسلم اس وقت حیات تھے۔ جب آپ کی وفات ہو گئی تو ہم ( خطاب کا صیغہ کے بجائے ) اس طرح پڑھنے لگے «السلام‏.‏ على النبي» یعنی نبی کریم صلی اللہ علیہ وسلم پر سلام ہو۔' WHERE id = 6031;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم نے بیان کیا، ان سے عمر بن سعید نے بیان کیا، ان سے ابن ابی ملیکہ نے اور ان سے عقبہ بن حارث رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ہمیں عصر کی نماز پڑھائی اور پھر بڑی تیزی کے ساتھ چل کر آپ گھر میں داخل ہو گئے۔' WHERE id = 6041;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن صباح نے بیان کیا، کہا ہم سے معتمر بن سلیمان نے بیان کیا، کہا کہ میں نے اپنے والد سے سنا کہ میں نے انس بن مالک رضی اللہ عنہ سے سنا کہ رسول اللہ صلی اللہ علیہ وسلم نے مجھ سے ایک راز کی بات کہی تھی اور میں نے وہ راز کسی کو نہیں بتایا ( ان کی والدہ ) ام سلیم رضی اللہ عنہا نے بھی مجھ سے اس کے متعلق پوچھا لیکن میں نے انہیں بھی نہیں بتایا۔' WHERE id = 6053;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبدالرحیم نے بیان کیا، کہا ہم کو عباد بن موسیٰ نے خبر دی، کہا ہم سے اسماعیل بن جعفر نے بیان کیا، کہا ہم سے اسرائیل نے، ان سے ابواسحاق نے، ان سے سعید بن جبیر نے کہ ابن عباس رضی اللہ عنہما سے پوچھا گیا کہ جب نبی کریم صلی اللہ علیہ وسلم کی وفات ہوئی تو آپ کی عمر کیا تھی؟ کہا کہ ان دنوں میرا ختنہ ہو چکا تھا اور عرب لوگوں کی عادت تھی جب تک لڑکا جوانی کے قریب نہ ہوتا اس کا ختنہ نہ کرتے تھے۔' WHERE id = 6063;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن منصور نے بیان کیا، کہا ہم کو حبان بن ہلال نے خبر دی، کہا ہم سے ہمام بن یحییٰ نے بیان کیا، کہا ہم سے قتادہ نے بیان کیا اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا اور ان سے نبی کریم صلی اللہ علیہ وسلم نے (دوسری سند) امام بخاری رحمہ اللہ نے کہا کہ ہم سے ہدبہ نے بیان کیا، کہا ہم سے ہمام نے بیان کیا، کہا ہم سے قتادہ نے بیان کیا، ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ اپنے بندے کی توبہ سے تم میں سے اس شخص سے بھی زیادہ خوش ہوتا ہے جس کا اونٹ مایوسی کے بعد اچانک اسے مل گیا ہو حالانکہ وہ ایک چٹیل میدان میں گم ہوا تھا۔“' WHERE id = 6073;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم سے لیث بن سعد نے بیان کیا، انہوں نے کہا کہ مجھ سے عقیل نے بیان کیا، ان سے ابن شہاب نے بیان کیا، انہیں عروہ نے خبر دی اور انہیں ام المؤمنین عائشہ رضی اللہ عنہا نے کہ جب رسول اللہ صلی اللہ علیہ وسلم لیٹتے تو اپنے ہاتھوں پر پھونکتے اور معوذات پڑھتے اور دونوں ہاتھ اپنے جسم پر پھیرتے۔' WHERE id = 6083;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن منصور نے بیان کیا، کہا ہم کو زید بن ہارون نے خبر دی، کہا ہم کو ورقاء نے خبر دی، انہیں سمی نے، انہیں ابوصالح ذکوان نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ صحابہ کرام نے عرض کیا: یا رسول اللہ! مالدار لوگ بلند درجات اور ہمیشہ رہنے والی جنت کی نعمتوں کو حاصل کر لے گئے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ کیسے؟ صحابہ کرام نے عرض کیا جس طرح ہم نماز پڑھتے ہیں وہ بھی پڑھتے ہیں اور جس طرح ہم جہاد کرتے ہیں وہ بھی جہاد کرتے ہیں اور اس کے ساتھ وہ اپنا زائد مال بھی ( اللہ کے راستہ میں ) خرچ کرتے ہیں اور ہمارے پاس مال نہیں ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کیا میں تمہیں ایک ایسا عمل نہ بتلاؤں جس سے تم اپنے آگے کے لوگوں کے ساتھ ہو جاؤ اور اپنے پیچھے آنے والوں سے آگے نکل جاؤ اور کوئی شخص اتنا ثواب نہ حاصل کر سکے جتنا تم نے کیا ہو، سوا اس صورت کے جب کہ وہ بھی وہی عمل کرے جو تم کرو گے ( اور وہ عمل یہ ہے ) کہ ہر نماز کے بعد دس مرتبہ «سبحان الله» پڑھا کرو، دس مرتبہ «الحمد الله» پڑھا کرو اور دس مرتبہ «الله اكبر» پڑھا کرو۔ اس کی روایت عبیداللہ بن عمر نے سمی اور رجاء بن حیوہ سے کی اور اس کی روایت جریر نے عبدالعزیز بن رفیع سے کی، ان سے ابوصالح نے اور ان سے ابودرداء رضی اللہ عنہ نے۔ اور اس کی روایت سہیل نے اپنے والد سے کی، ان سے ابوہریرہ رضی اللہ عنہ نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے۔' WHERE id = 6093;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، ان سے امام مالک نے، ان سے ابوالزناد نے، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”تم میں سے کوئی شخص اس طرح نہ کہے کہ یا اللہ! اگر تو چاہے تو مجھے معاف کر دے، میری مغفرت کر دے۔ بلکہ یقین کے ساتھ دعا کرے کیونکہ اللہ پر کوئی زبردستی کرنے والا نہیں ہے۔“' WHERE id = 6103;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے اسماعیل بن ابی خالد نے بیان کیا، ان سے قیس بن ابی حازم نے بیان کیا، کہا کہ میں خباب بن ارت رضی اللہ عنہ کی خدمت میں حاضر ہوا انہوں نے سات داغ ( کسی بیماری کے علاج کے لیے ) لگوائے تھے۔ انہوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے اگر ہمیں موت کی دعا کرنے سے منع نہ کیا ہوتا تو میں ضرور اس کی دعا کرتا۔' WHERE id = 6113;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعبہ نے یبان کیا، ان سے عمرو بن مرہ نے اور ان سے ابن ابی اوفی رضی اللہ عنہ نے بیان کیا جب رسول اللہ صلی اللہ علیہ وسلم کے پاس کوئی شخص اپنی زکوٰۃ لے کر آتا تو آپ فرماتے «اللهم صل عليه‏ ‏» ”اے اللہ! اس پر اپنی رحمت نازل فرما۔“ میرے والد بھی اپنی زکوٰۃ لے کر آئے تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا «اللهم صل على آل أبي أوفى‏ ‏» ”اے اللہ! آل ابی اوفی پر اپنی رحمت نازل فرما۔“' WHERE id = 6123;
UPDATE hadiths SET urdu = 'ہم سے خالد بن مخلد نے بیان کیا، انہوں نے کہا ہم سے سلیمان نے بیان کیا، انہوں نے کہا کہ مجھ سے عمرو بن ابی عمرو نے بیان کیا، انہوں نے کہا کہ میں نے انس بن مالک رضی اللہ عنہ سے سنا، کہا کہ نبی کریم صلی اللہ علیہ وسلم کہتے تھے «اللهم إني أعوذ بك من الهم والحزن،‏‏‏‏ والعجز والكسل،‏‏‏‏ والجبن والبخل،‏‏‏‏ وضلع الدين،‏‏‏‏ وغلبة الرجال» ”اے اللہ! میں تیری پناہ مانگتا ہوں غم و الم سے، عاجزی سے، سستی سے، بزدلی سے، بخل، قرض چڑھ جانے اور لوگوں کے غلبہ سے۔“' WHERE id = 6133;
UPDATE hadiths SET urdu = 'ہم سے ابومصعب مطرف بن عبداللہ نے بیان کیا، کہا ہم سے عبدالرحمٰن بن ابی الموال نے بیان کیا، ان سے محمد بن منکدر نے اور ان سے جابر رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم ہمیں تمام معاملات میں استخارہ کی تعلیم دیتے تھے، قرآن کی سورت کی طرح ( نبی کریم صلی اللہ علیہ وسلم نے فرمایا ) جب تم میں سے کوئی شخص کسی ( مباح ) کام کا ارادہ کرے ( ابھی پکا عزم نہ ہوا ہو ) تو دو رکعات ( نفل ) پڑھے اس کے بعد یوں دعا کرے کہ اے اللہ! میں بھلائی مانگتا ہوں ( استخارہ ) تیری بھلائی سے، تو علم والا ہے، مجھے علم نہیں اور تو تمام پوشیدہ باتوں کو جاننے والا ہے، اے اللہ! اگر تو جانتا ہے کہ یہ کام میرے لیے بہتر ہے، میرے دین کے اعتبار سے، میری معاش اور میرے انجام کار کے اعتبار سے یا دعا میں یہ الفاظ کہے «في عاجل أمري وآجله» تو اسے میرے لیے مقدر کر دے اور اگر تو جانتا ہے کہ یہ کام میرے لیے برا ہے میرے دین کے لیے، میری زندگی کے لیے اور میرے انجام کار کے لیے یا یہ الفاظ فرمائے «في عاجل أمري وآجله» تو اسے مجھ سے پھیر دے اور مجھے اس سے پھیر دے اور میرے لیے بھلائی مقدر کر دے جہاں کہیں بھی وہ ہو اور پھر مجھے اس سے مطمئن کر دے ( یہ دعا کرتے وقت ) اپنی ضرورت کا بیان کر دینا چاہئے۔' WHERE id = 6144;
UPDATE hadiths SET urdu = 'ہم سے ابن سلام نے بیان کیا، کہا ہم کو وکیع نے خبر دی، انہیں ابن ابی خالد نے، کہا میں نے ابن ابی اوفی رضی اللہ عنہما سے سنا، کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے احزاب کے لیے بددعا کی «اللهم منزل الكتاب،‏‏‏‏ سريع الحساب،‏‏‏‏ اهزم الأحزاب،‏‏‏‏ اهزمهم وزلزلهم» ”اے اللہ! کتاب کے نازل کرنے والے! حساب جلدی لینے والے! احزاب کو ( مشرکین کی جماعتوں کو، غزوہ احزاب میں ) شکست دے، انہیں شکست دیدے اور انہیں جھنجوڑ دے۔“' WHERE id = 6154;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے سفیان نے بیان کیا کہ زہری نے بیان کیا کہ ہم سے سعید بن مسیب نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جب پڑھنے والا آمین کہے تو تم بھی آمین کہو کیونکہ اس وقت ملائکہ بھی آمین کہتے ہیں اور جس کی آمین ملائکہ کی آمین کے ساتھ ہوتی ہے اس کے پچھلے گناہ معاف کر دئیے جاتے ہیں۔“' WHERE id = 6164;
UPDATE hadiths SET urdu = 'ہم سے مکی بن ابراہیم نے بیان کیا، انہوں نے کہا ہم کو عبداللہ بن سعید نے خبر دی، وہ ابوہند کے صاحب زادے ہیں، انہیں ان کے والد نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”دو نعمتیں ایسی ہیں کہ اکثر لوگ ان کی قدر نہیں کرتے، صحت اور فراغت۔“ عباس عنبری نے بیان کیا کہ ہم سے صفوان بن عیسیٰ نے بیان کیا، ان سے عبداللہ بن ابی ہند نے، ان سے ان کے والد نے کہ میں نے عبداللہ بن عباس رضی اللہ عنہما سے سنا، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے اسی حدیث کی طرح۔' WHERE id = 6174;
UPDATE hadiths SET urdu = 'ہم سے معاذ بن اسد نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، انہیں معمر نے خبر دی، ان سے زہری نے بیان کیا کہ مجھے محمود بن ربیع انصاری نے خبر دی اور وہ کہتے تھے کہ رسول اللہ صلی اللہ علیہ وسلم کی یہ بات خوب میرے ذہن میں محفوظ ہے۔ انہیں یاد ہے کہ نبی کریم صلی اللہ علیہ وسلم نے ان کے ایک ڈول میں سے پانی لے کر مجھ پر کلی کر دی تھی۔' WHERE id = 6184;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، ان سے سفیان بن عیینہ نے، ان سے اعمش نے ان سے ابووائل نے اور ان سے خباب بن ارت رضی اللہ عنہ نے بیان کیا کہ ہم نے رسول اللہ صلی اللہ علیہ وسلم کے ساتھ ہجرت کی تھی اور اس کا قصہ بیان کیا۔' WHERE id = 6194;
UPDATE hadiths SET urdu = 'مجھ سے عمر بن حفص نے بیان کیا، کہا مجھ سے میرے والد نے بیان کیا، کہا ہم سے اعمش نے بیان کیا، کہا کہ مجھ سے ابراہیم تیمی نے بیان کیا، ان سے حارث بن سوید نے کہ عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”تم میں کون ہے جسے اپنے مال سے زیادہ اپنے وارث کا مال پیارا ہو۔“ صحابہ نے عرض کیا: یا رسول اللہ! ہم میں کوئی ایسا نہیں جسے مال زیادہ پیارا نہ ہو۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”پھر اس کا مال وہ ہے جو اس نے ( موت سے ) پہلے ( اللہ کے راستہ میں خرچ ) کیا اور اس کے وارث کا مال وہ ہے جو وہ چھوڑ کر مرا۔“' WHERE id = 6204;
UPDATE hadiths SET urdu = 'مجھ سے ابونعیم نے یہ حدیث آدھی کے قریب بیان کی اور آدھی دوسرے شخص نے، کہا ہم سے عمر بن ذر نے بیان کیا، کہا ہم سے مجاہد نے بیان کیا کہ ابوہریرہ رضی اللہ عنہ کہا کرتے تھے کہ اللہ کی قسم جس کے سوا کوئی معبود نہیں میں ( زمانہ نبوی میں ) بھوک کے مارے زمین پر اپنے پیٹ کے بل لیٹ جاتا تھا اور کبھی میں بھوک کے مارے اپنے پیٹ پر پتھر باندھا کرتا تھا۔ ایک دن میں اس راستے پر بیٹھ گیا جس سے صحابہ نکلتے تھے۔ ابوبکر صدیق رضی اللہ عنہ گزرے اور میں نے ان سے کتاب اللہ کی ایک آیت کے بارے میں پوچھا، میرے پوچھنے کا مقصد صرف یہ تھا کہ وہ مجھے کچھ کھلا دیں مگر وہ چلے گئے اور کچھ نہیں کیا۔ پھر عمر رضی اللہ عنہ میرے پاس سے گزرے، میں نے ان سے بھی قرآن مجید کی ایک آیت پوچھی اور پوچھنے کا مقصد صرف یہ تھا کہ وہ مجھے کچھ کھلا دیں مگر وہ بھی گزر گئے اور کچھ نہیں کیا۔ اس کے بعد نبی کریم صلی اللہ علیہ وسلم گزرے اور آپ نے جب مجھے دیکھا تو آپ مسکرا دئیے اور جو میرے دل میں اور جو میرے چہرے پر تھا آپ نے پہچان لیا۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا، اباہر! میں نے عرض کیا لبیک، یا رسول اللہ! فرمایا میرے ساتھ آ جاؤ اور آپ چلنے لگے۔ میں نبی کریم صلی اللہ علیہ وسلم کے پیچھے چل دیا۔ پھر نبی کریم صلی اللہ علیہ وسلم اندر گھر میں تشریف لے گئے۔ پھر میں نے اجازت چاہی اور مجھے اجازت ملی۔ جب آپ داخل ہوئے تو ایک پیالے میں دودھ ملا۔ دریافت فرمایا کہ یہ دودھ کہاں سے آیا ہے؟ کہا فلاں یا فلانی نے نبی کریم صلی اللہ علیہ وسلم کے لیے تحفہ میں بھیجا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، اباہر! میں نے عرض کیا لبیک، یا رسول اللہ! فرمایا، اہل صفہ کے پاس جاؤ اور انہیں بھی میرے پاس بلا لاؤ۔ کہا کہ اہل صفہ اسلام کے مہمان ہیں، وہ نہ کسی کے گھر پناہ ڈھونڈھتے، نہ کسی کے مال میں اور نہ کسی کے پاس! جب نبی کریم صلی اللہ علیہ وسلم کے پاس صدقہ آتا تو اسے نبی کریم صلی اللہ علیہ وسلم انہیں کے پاس بھیج دیتے اور خود اس میں سے کچھ نہ رکھتے۔ البتہ جب آپ کے پاس تحفہ آتا تو انہیں بلوا بھیجتے اور خود بھی اس میں سے کچھ کھاتے اور انہیں بھی شریک کرتے۔ چنانچہ مجھے یہ بات ناگوار گزری اور میں نے سوچا کہ یہ دودھ ہے ہی کتنا کہ سارے صفہ والوں میں تقسیم ہو، اس کا حقدار میں تھا کہ اسے پی کر کچھ قوت حاصل کرتا۔ جب صفہ والے آئیں گے تو نبی کریم صلی اللہ علیہ وسلم مجھ سے فرمائیں گے اور میں انہیں اسے دے دوں گا۔ مجھے تو شاید اس دودھ میں سے کچھ بھی نہیں ملے گا لیکن اللہ اور اس کے رسول کی حکم برداری کے سوا کوئی اور چارہ بھی نہیں تھا۔ چنانچہ میں ان کے پاس آیا اور نبی کریم صلی اللہ علیہ وسلم کی دعوت پہنچائی، وہ آ گئے اور اجازت چاہی۔ انہیں اجازت مل گئی پھر وہ گھر میں اپنی اپنی جگہ بیٹھ گئے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا: اباہر! میں نے عرض کیا لبیک، یا رسول اللہ! فرمایا لو اور اسے ان سب حاضرین کو دے دو۔ بیان کیا کہ پھر میں نے پیالہ پکڑ لیا اور ایک ایک کو دینے لگا۔ ایک شخص دودھ پی کر جب سیراب ہو جاتا تو مجھے پیالہ واپس کر دیتا پھر دوسرے شخص کو دیتا وہ بھی سیراب ہو کر پیتا پھر پیالہ مجھ کو واپس کر دیتا اور اسی طرح تیسرا پی کر پھر مجھے پیالہ واپس کر دیتا۔ اس طرح میں نبی کریم صلی اللہ علیہ وسلم تک پہنچا لوگ پی کر سیراب ہو چکے تھے۔ آخر میں نبی کریم صلی اللہ علیہ وسلم نے پیالہ پکڑا اور اپنے ہاتھ پر رکھ کر آپ صلی اللہ علیہ وسلم نے میری طرف دیکھا اور مسکرا کر فرمایا، اباہر! میں نے عرض کیا، لبیک، یا رسول اللہ! فرمایا، اب میں اور تم باقی رہ گئے ہیں۔ میں نے عرض کیا: یا رسول اللہ! آپ نے سچ فرمایا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا بیٹھ جاؤ اور پیو۔ میں بیٹھ گیا اور میں نے دودھ پیا اور نبی کریم صلی اللہ علیہ وسلم برابر فرماتے رہے کہ اور پیو آخر مجھے کہنا پڑا، نہیں اس ذات کی قسم جس نے آپ کو حق کے ساتھ بھیجا ہے، اب بالکل گنجائش نہیں ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، پھر مجھے دے دو، میں نے پیالہ نبی کریم صلی اللہ علیہ وسلم کو دے دیا آپ صلی اللہ علیہ وسلم نے اللہ کی حمد بیان کی اور بسم اللہ پڑھ کر بچا ہوا خود پی گئے۔' WHERE id = 6214;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، ان سے امام مالک نے، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کو سب سے زیادہ پسندیدہ وہ عمل تھا جس کو آدمی ہمیشہ کرتا رہے۔' WHERE id = 6224;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق نے بیان کیا، انہوں نے کہا ہم سے روح بن عبادہ نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، انہوں نے کہا کہ میں نے حصین بن عبداللہ سے سنا، انہوں نے کہا کہ میں سعید بن جبیر کی خدمت میں بیٹھا ہوا تھا، انہوں نے ابن عباس رضی اللہ عنہما سے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”میری امت کے ستر ہزار لوگ بے حساب جنت میں جائیں گے۔ یہ وہ لوگ ہوں گے جو جھاڑ پھونک نہیں کراتے نہ شگون لیتے ہیں اور اپنے رب ہی پر بھروسہ رکھتے ہیں۔“' WHERE id = 6234;
UPDATE hadiths SET urdu = 'ہم سے محمد بن علاء نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے برید بن عبداللہ بن ابی بردہ نے ان سے ابوبردہ نے، اور ان سے ابوموسیٰ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”میری اور جو کچھ کلام اللہ نے میرے ساتھ بھیجا ہے اس کی مثال ایک ایسے شخص جیسی ہے جو اپنی قوم کے پاس آیا اور کہا کہ میں نے ( تمہارے دشمن کا ) لشکر اپنی آنکھوں سے دیکھا ہے اور میں واضح ڈرانے والا ہوں۔ پس بھاگو، پس بھاگو ( اپنی جان بچاؤ ) اس پر ایک جماعت نے اس کی بات مان لی اور رات ہی رات اطمینان سے کسی محفوظ جگہ پر نکل گئے اور نجات پائی۔ لیکن دوسری جماعت نے اسے جھٹلایا اور دشمن کے لشکر نے صبح کے وقت اچانک انہیں آ لیا اور تباہ کر دیا۔“' WHERE id = 6244;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے مہدی نے بیان کیا، ان سے غیلان نے، ان سے انس رضی اللہ عنہ نے، انہوں نے کہا کہ تم ایسے ایسے عمل کرتے ہو جو تمہاری نظر میں بال سے زیادہ باریک ہیں ( تم اسے حقیر سمجھتے ہو، بڑا گناہ نہیں سمجھتے ) اور ہم لوگ نبی کریم صلی اللہ علیہ وسلم کے زمانہ میں ان کاموں کو ہلاک کر دینے والا سمجھتے تھے۔ امام بخاری رحمہ اللہ نے کہا کہ حدیث میں جو لفظ «موبقات» ہے اس کا معنی ہلاک کرنے والے۔' WHERE id = 6254;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن عثمان نے بیان کیا، کہا ہم سے خالد بن مخلد نے، کہا ہم سے سلیمان بن بلال نے، ان سے شریک بن عبداللہ بن ابی نمر نے، ان سے عطاء نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ فرماتا ہے کہ جس نے میرے کسی ولی سے دشمنی کی اسے میری طرف سے اعلان جنگ ہے اور میرا بندہ جن جن عبادتوں سے میرا قرب حاصل کرتا ہے اور کوئی عبادت مجھ کو اس سے زیادہ پسند نہیں ہے جو میں نے اس پر فرض کی ہے ( یعنی فرائض مجھ کو بہت پسند ہیں جیسے نماز، روزہ، حج، زکوٰۃ ) اور میرا بندہ فرض ادا کرنے کے بعد نفل عبادتیں کر کے مجھ سے اتنا نزدیک ہو جاتا ہے کہ میں اس سے محبت کرنے لگ جاتا ہوں۔ پھر جب میں اس سے محبت کرنے لگ جاتا ہوں تو میں اس کا کان بن جاتا ہوں جس سے وہ سنتا ہے، اس کی آنکھ بن جاتا ہوں جس سے وہ دیکھتا ہے، اس کا ہاتھ بن جاتا ہوں جس سے وہ پکڑتا ہے، اس کا پاؤں بن جاتا ہوں جس سے وہ چلتا ہے اور اگر وہ مجھ سے مانگتا ہے تو میں اسے دیتا ہوں اگر وہ کسی دشمن یا شیطان سے میری پناہ مانگتا ہے تو میں اسے محفوظ رکھتا ہوں اور میں جو کام کرنا چاہتا ہوں اس میں مجھے اتنا تردد نہیں ہوتا جتنا کہ مجھے اپنے مومن بندے کی جان نکالنے میں ہوتا ہے۔ وہ تو موت کو بوجہ تکلیف جسمانی کے پسند نہیں کرتا اور مجھ کو بھی اسے تکلیف دینا برا لگتا ہے۔' WHERE id = 6264;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے محمد بن عمرو حلحلہ نے، ان سے سعد بن کعب بن مالک نے، ان سے ابوقتادہ بن ربعی انصاری رضی اللہ عنہ نے، وہ بیان کرتے تھے کہ رسول اللہ صلی اللہ علیہ وسلم کے قریب سے لوگ ایک جنازہ لے کر گزرے تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ «مستريح» یا «مستراح» ہے یعنی اسے آرام مل گیا، یا اس سے آرام مل گیا۔ صحابہ نے عرض کیا: یا رسول اللہ! ”المستریح او المستراح منہ“ کا کیا مطلب ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ مومن بندہ دنیا کی مشقتوں اور تکلیفوں سے اللہ کی رحمت میں نجات پا جاتا ہے وہ «مستريح» ہے اور «مستراح» منہ وہ ہے کہ فاجر بندہ سے اللہ کے بندے، شہر، درخت اور چوپائے سب آرام پا جاتے ہیں۔' WHERE id = 6274;
UPDATE hadiths SET urdu = 'ہم سے معلیٰ بن اسد نے بیان کیا، کہا ہم سے وہیب بن خالد نے بیان کیا، ان سے عبداللہ بن طاؤس نے، ان سے ان کے والد طاؤس نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”لوگوں کا حشر تین فرقوں میں ہو گا ( ایک فرقہ والے ) لوگ رغبت کرنے نیز ڈرنے والے ہوں گے۔ ( دوسرا فرقہ ایسے لوگوں کا ہو گا کہ ) ایک اونٹ پر دو آدمی سوار ہوں گے کسی اونٹ پر تین ہوں گے، کسی اونٹ پر چار ہوں گے اور کسی پر دس ہوں گے۔ اور باقی لوگوں کو آگ جمع کرے گی ( اہل شرک کا یہ تیسرا فرقہ ہو گا ) جب وہ قیلولہ کریں گے تو آگ بھی ان کے ساتھ ٹھہری ہو گی جب وہ رات گزاریں گے تو آگ بھی ان کے ساتھ وہاں ٹھہری ہو گی جب وہ صبح کریں گے تو آگ بھی صبح کے وقت وہاں موجود ہو گی اور جب وہ شام کریں گے تو آگ بھی شام کے وقت ان کے ساتھ موجود ہو گی۔“' WHERE id = 6284;
UPDATE hadiths SET urdu = 'مجھ سے عبدالعزیز بن عبداللہ اویسی نے بیان کیا، انہوں نے کہا کہ مجھ سے سلیمان بن بلال نے بیان کیا، ان سے ثور بن زید نے بیان کیا، ان سے ابوالغیث نے اور انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”قیامت کے دن لوگ پسینے میں شرابور ہو جائیں گے اور حالت یہ ہو جائے گی کہ تم میں سے ہر کسی کا پسینہ زمین پر ستر ہاتھ تک پھیل جائے گا اور منہ تک پہنچ کر کانوں کو چھونے لگے گا۔“' WHERE id = 6294;
UPDATE hadiths SET urdu = 'ہم سے معاذ بن اسد مروزی نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، کہا ہم کو یونس بن یزید نے خبر دی، ان سے زہری نے بیان کیا، کہا کہ مجھ سے سعید بن مسیب نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میری امت کی ایک جماعت جنت میں داخل ہو گی جس کی تعداد ستر ہزار ہو گی۔ ان کے چہرے اس طرح روشن ہوں گے جیسے چودہویں رات کا چاند روشن ہوتا ہے۔ ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ اس پر عکاشہ بن محصن اسدی رضی اللہ عنہ کھڑے ہوئے، اپنی دھاری دار کملی جو ان کے جسم پر تھی، اٹھاتے ہوئے عرض کیا: یا رسول اللہ! اللہ تعالیٰ سے دعا کیجئے کہ مجھے بھی ان میں سے کر دے۔ نبی کریم صلی اللہ علیہ وسلم نے دعا کی کہ اے اللہ! انہیں بھی ان میں سے کر دے۔ اس کے بعد ایک اور صحابی کھڑے ہوئے اور عرض کیا: یا رسول اللہ! دعا کیجئے کہ اللہ مجھے بھی ان میں سے کر دے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ عکاشہ تم پر سبقت لے گئے۔' WHERE id = 6304;
UPDATE hadiths SET urdu = 'اور اسحاق بن ابراہیم نے بیان کیا، انہوں نے کہا ہم کو مغیرہ بن سلمہ نے خبر دی، انہوں نے کہا ہم سے وہیب نے بیان کیا، ان سے ابوحازم نے بیان کیا، ان سے سہل بن سعد رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جنت میں ایک درخت ہے جس کے سایہ میں سوار سو سال تک چلنے کے بعد بھی اسے طے نہیں کر سکے گا۔“' WHERE id = 6314;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن رجاء نے بیان کیا، کہا ہم سے اسرائیل نے بیان کیا، ان سے ابواسحاق نے، ان سے نعمان بن بشیر رضی اللہ عنہ نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ قیامت کے دن دوزخیوں میں عذاب کے اعتبار سے سب سے ہلکا عذاب پانے والا وہ شخص ہو گا جس کے دونوں پیروں کے نیچے دو انگارے رکھ دئیے جائیں گے جن کی وجہ سے اس کا دماغ کھول رہا ہو گا جس طرح ہانڈی اور کیتلی جوش کھاتی ہے۔' WHERE id = 6324;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، انہیں زہری نے، کہا مجھ کو سعید اور عطا بن یزید نے خبر دی اور انہیں ابوہریرہ رضی اللہ عنہ نے اور انہیں نبی کریم صلی اللہ علیہ وسلم نے (دوسری سند) اور مجھ سے محمود بن غیلان نے بیان کیا، کہا ہم سے عبدالرزاق بن ہمام نے، کہا ہم کو معمر نے، انہیں زہری نے، انہیں عطا بن یزید لیثی نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ کچھ لوگوں نے عرض کیا: یا رسول اللہ! کیا قیامت کے دن ہم اپنے رب کو دیکھ سکیں گے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کیا سورج کو دیکھنے میں تمہیں کوئی دشواری ہوتی ہے جبکہ اس پر کوئی بادل ( ابر ) وغیرہ نہ ہو؟ صحابہ نے عرض کیا: نہیں یا رسول اللہ! نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کیا جب کوئی بادل نہ ہو تو تمہیں چودہویں رات کے چاند کو دیکھنے میں کوئی دشواری ہوتی ہے؟ صحابہ نے عرض کیا: نہیں یا رسول اللہ! آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر تم اللہ تعالیٰ کو اسی طرح قیامت کے دن دیکھو گے۔ اللہ تعالیٰ لوگوں کو جمع کرے گا اور کہے گا کہ تم میں سے جو شخص جس چیز کی پوجا پاٹ کیا کرتا تھا وہ اسی کے پیچھے لگ جائے، چنانچہ جو لوگ سورج کی پرستش کیا کرتے تھے وہ اس کے پیچھے لگ جائیں گے اور جو لوگ چاند کی پوجا کرتے تھے وہ ان کے پیچھے ہو لیں گے۔ جو لوگ بتوں کی پرستش کرتے تھے وہ ان کے پیچھے لگ جائیں گے اور آخر میں یہ امت باقی رہ جائے گی اور اس میں منافقین کی جماعت بھی ہو گی، اس وقت اللہ تعالیٰ ان کے سامنے اس صورت میں آئے گا جس کو وہ پہچانتے نہ ہوں گے اور کہے گا کہ میں تمہارا رب ہوں۔ لوگ کہیں گے تجھ سے اللہ کی پناہ۔ ہم اپنی جگہ پر اس وقت تک رہیں گے جب تک کہ ہمارا پروردگار ہمارے سامنے نہ آئے۔ جب ہمارا رب ہمارے پاس آئے گا تو ہم اسے پہچان لیں گے ( کیونکہ وہ حشر میں ایک بار اس کو پہلے دیکھ چکے ہوں گے ) پھر حق تعالیٰ اس صورت میں آئے گا جس کو وہ پہچانتے ہوں گے اور ان سے کہا جائے گا ( آؤ میرے ساتھ ہو لو ) میں تمہارا رب ہوں! لوگ کہیں گے کہ تو ہمارا رب ہے، پھر اسی کے پیچھے ہو جائیں گے اور جہنم پر پل بنا دیا جائے گا۔ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ میں سب سے پہلا شخص ہوں گا جو اس پل کو پار کروں گا اور اس دن رسولوں کی دعا یہ ہو گی کہ اے اللہ! مجھ کو سلامت رکھیو۔ اے اللہ! مجھ کو سلامت رکھیو اور وہاں سعدان کے کانٹوں کی طرح آنکڑے ہوں گے۔ تم نے سعدان کے کانٹے دیکھے ہیں؟ صحابہ کرام نے عرض کیا جی ہاں دیکھے ہیں یا رسول اللہ! آپ صلی اللہ علیہ وسلم نے فرمایا کہ وہ پھر سعدان کے کانٹوں کی طرح ہوں گے البتہ اس کی لمبائی چوڑائی اللہ کے سوا اور کوئی نہیں جانتا۔ وہ لوگوں کو ان کے اعمال کے مطابق اچک لیں گے اور اس طرح ان میں سے بعض تو اپنے عمل کی وجہ سے ہلاک ہو جائیں گے اور بعض کا عمل رائی کے دانے کے برابر ہو گا، پھر وہ نجات پا جائے گا۔ آخر جب اللہ تعالیٰ اپنے بندوں کے درمیان فیصلے سے فارغ ہو جائے گا اور جہنم سے انہیں نکالنا چاہے گا جنہیں نکالنے کی اس کی مشیت ہو گی۔ یعنی وہ جنہوں نے کلمہ «لا إله إلا الله» کی گواہی دی ہو گی اور اللہ تعالیٰ فرشتوں کو حکم دے گا کہ وہ ایسے لوگوں کو جہنم سے نکالیں۔ فرشتے انہیں سجدوں کے نشانات سے پہچان لیں گے کیونکہ اللہ تعالیٰ نے آگ پر حرام کر دیا ہے کہ وہ ابن آدم کے جسم میں سجدوں کے نشان کو کھائے۔ چنانچہ فرشتے ان لوگوں کو نکالیں گے۔ یہ جل کر کوئلے ہو چکے ہوں گے پھر ان پر پانی چھڑکا جائے گا جسے «ماء الحياة» زندگی بخشنے والا پانی کہتے ہیں۔ اس وقت وہ اس طرح تروتازہ ہو جائیں گے جیسے سیلاب کے بعد زرخیز زمین میں دانہ اگ آتا ہے۔ ایک ایسا شخص باقی رہ جائے گا جس کا چہرہ جہنم کی طرف ہو گا اور وہ کہے گا اے میرے رب! اس کی بدبوں نے مجھے پریشان کر دیا ہے اور اس کی لپٹ نے مجھے جھلسا دیا ہے اور اس کی تیزی نے مجھے جلا ڈالا ہے، ذرا میرا منہ آگ کی طرف سے دوسری طرف پھیر دے۔ وہ اسی طرح اللہ سے دعا کرتا رہے گا۔ آخر اللہ تعالیٰ فرمائے گا اگر میں تیرا یہ مطالبہ پورا کر دوں تو کہیں تو کوئی دوسری چیز مانگنی شروع نہ کر دے۔ وہ شخص عرض کرے گا نہیں، تیری عزت کی قسم! میں اس کے سوا کوئی دوسری چیز نہیں مانگوں گا۔ چنانچہ اس کا چہرہ جہنم کی طرف سے دوسری طرف پھیر دیا جائے گا۔ اب اس کے بعد وہ کہے گا۔ اے میرے رب! مجھے جنت کے دروازے کے قریب کر دیجئیے۔ اللہ تعالیٰ فرمائے گا کیا تو نے ابھی یقین نہیں دلایا تھا کہ اس کے سوا اور کوئی چیز نہیں مانگے گا۔ افسوس! اے ابن آدم! تو بہت زیادہ وعدہ خلاف ہے۔ پھر وہ برابر اسی طرح دعا کرتا رہے گا تو اللہ تعالیٰ فرمائے گا کہ اگر میں تیری یہ دعا قبول کر لوں تو تو پھر اس کے علاوہ کچھ اور چیز مانگنے لگے گا۔ وہ شخص کہے گا نہیں، تیری عزت کی قسم! میں اس کے سوا اور کوئی چیز تجھ سے نہیں مانگوں گا اور وہ اللہ سے عہد و پیمان کرے گا کہ اس کے سوا اب کوئی اور چیز نہیں مانگے گا۔ چنانچہ اللہ تعالیٰ اسے جنت کے دروازے کے قریب کر دے گا۔ جب وہ جنت کے اندر کی نعمتوں کو دیکھے گا تو جتنی دیر تک اللہ تعالیٰ چاہے گا وہ شخص خاموش رہے گا، پھر کہے گا اے میرے رب! مجھے جنت میں داخل کر دے۔ اللہ تعالیٰ فرمائے گا کہ کیا تو نے یہ یقین نہیں دلایا تھا کہ اب تو اس کے سوا کوئی چیز نہیں مانگے گا۔ اے ابن آدم! افسوس، تو کتنا وعدہ خلاف ہے۔ وہ شخص عرض کرے گا اے میرے رب! مجھے اپنی مخلوق کا سب سے بدبخت بندہ نہ بنا۔ وہ برابر دعا کرتا رہے گا یہاں تک کہ اللہ تعالیٰ ہنس دے گا۔ جب اللہ ہنس دے گا تو اس شخص کو جنت میں داخل ہونے کی اجازت مل جائے گی۔ جب وہ اندر چلا جائے گا تو اس سے کہا جائے گا کہ فلاں چیز کی خواہش کر چنانچہ وہ اس کی خواہش کرے گا۔ پھر اس سے کہا جائے گا کہ فلاں چیز کی خواہش کرو، چنانچہ وہ پھر خواہش کرے گا یہاں تک کہ اس کی خواہشات ختم ہو جائیں گی تو اللہ تعالیٰ کی طرف سے کہا جائے گا کہ تیری یہ ساری خواہشات پوری کی جاتی ہیں اور اتنی ہی زیادہ نعمتیں اور دی جاتی ہیں۔ ابوہریرہ رضی اللہ عنہ نے اسی سند سے کہا کہ یہ شخص جنت میں سب سے آخر میں داخل ہونے والا ہو گا۔' WHERE id = 6334;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابومریم نے بیان کیا، کہا ہم سے محمد بن مطرف نے بیان کیا، کہا کہ مجھ سے ابوحازم نے، ان سے سہل بن سعد رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میں اپنے حوض کوثر پر تم سے پہلے موجود رہوں گا۔ جو شخص بھی میری طرف سے گزرے گا وہ اس کا پانی پئے گا اور جو اس کا پانی پئے گا وہ پھر کبھی پیاسا نہیں ہو گا اور وہاں کچھ ایسے لوگ بھی آئیں گے جنہیں میں پہچانوں گا اور وہ مجھے پہچانیں گے لیکن پھر انہیں میرے سامنے سے ہٹا دیا جائے گا۔“' WHERE id = 6344;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا، ان سے نافع بن عمر نے، کہا کہ مجھ سے ابن ابی ملیکہ نے بیان کیا، ان سے اسماء بنت ابی بکر رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میں حوض پر موجود رہوں گا اور دیکھوں گا کہ تم میں سے کون میرے پاس آتا ہے۔ پھر کچھ لوگوں کو مجھ سے الگ کر دیا جائے گا۔ میں عرض کروں گا کہ اے میرے رب! یہ تو میرے ہی آدمی ہیں اور میری امت کے لوگ ہیں۔ مجھ سے کہا جائے گا کہ تمہیں معلوم بھی ہے انہوں نے تمہارے بعد کیا کام کئے تھے؟ واللہ یہ مسلسل الٹے پاؤں لوٹتے رہے۔ ( دین اسلام سے پھر گئے ) ابن ابی ملیکہ ( جو کہ یہ حدیث اسماء سے روایت فرماتے ہیں ) کہا کرتے تھے کہ اے اللہ! ہم اس بات سے تیری پناہ مانگتے ہیں کہ ہم الٹے پاؤں ( دین سے ) لوٹ جائیں یا اپنے دین کے بارے میں فتنہ میں ڈال دئیے جائیں۔ ابوعبداللہ امام بخاری رحمہ اللہ نے کہا کہ سورۃ مومنون میں جو اللہ تعالیٰ کا فرمان ہے «أعقابكم تنكصون‏» اس کا معنی بھی یہی ہے کہ تم دین سے اپنی ایڑیوں کے بل الٹے پھر گئے تھے یعنی اسلام سے مرتد ہو گئے تھے۔' WHERE id = 6354;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، ان سے ابوحمزہ نے، ان سے اعمش نے، ان سے سعد بن عبیدہ نے، ان سے ابوعبدالرحمٰن سلمی نے اور ان سے علی رضی اللہ عنہ نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ بیٹھے ہوئے تھے اور نبی کریم صلی اللہ علیہ وسلم کے ہاتھ میں ایک لکڑی تھی جس سے آپ زمین کرید رہے تھے اور آپ صلی اللہ علیہ وسلم نے ( اسی اثناء میں ) فرمایا کہ تم میں سے ہر شخص کا جہنم کا یا جنت کا ٹھکانا لکھا جا چکا ہے، ایک مسلمان نے اس پر عرض کیا: یا رسول اللہ! پھر کیوں نہ ہم اس پر بھروسہ کر لیں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ نہیں عمل کرو کیونکہ ہر شخص ( اپنی تقدیر کے مطابق ) عمل کی آسانی پاتا ہے۔ پھر آپ صلی اللہ علیہ وسلم نے اس آیت کی تلاوت کی «فأما من أعطى واتقى‏» الآیہ پس جس نے راہ للہ دیا اور تقویٰ اختیار کیا… الخ۔' WHERE id = 6365;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سنان نے بیان کیا، کہا ہم سے فلیح نے بیان کیا، کہا ہم سے عبدہ بن ابی لبابہ نے بیان کیا، ان سے مغیرہ بن شعبہ کے غلام وردا نے بیان کیا کہ معاویہ رضی اللہ عنہ نے مغیرہ بن شعبہ رضی اللہ عنہ کو لکھا مجھے رسول اللہ صلی اللہ علیہ وسلم کی وہ دعا لکھ کر بھیجو جو تم نے نبی کریم صلی اللہ علیہ وسلم کو نماز کے بعد کرتے سنی ہے۔ چنانچہ مغیرہ رضی اللہ عنہ نے مجھ کو لکھوایا۔ انہوں نے کہا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا ہے نبی کریم صلی اللہ علیہ وسلم ہر فرض نماز کے بعد یہ دعا کیا کرتے تھے «اللهم لا مانع لما أعطيت،‏‏‏‏ ولا معطي لما منعت،‏‏‏‏ ولا ينفع ذا الجد منك الجد» ”اللہ کے سوا کوئی معبود نہیں وہ ایک ہے اس کا کوئی شریک نہیں، اے اللہ! جو تو دینا چاہے اسے کوئی روکنے والا نہیں اور جو تو روکنا چاہے اسے کوئی دینے والا نہیں اور تیرے سامنے دولت والے کی دولت کچھ کام نہیں دے سکتی۔ اور ابن جریج نے کہا کہ مجھ کو عبدہ نے خبر دی اور انہیں وردا نے خبر دی، پھر اس کے بعد میں معاویہ رضی اللہ عنہ کے یہاں گیا تو میں نے دیکھا کہ وہ لوگوں کو اس دعا کے پڑھنے کا حکم دے رہے تھے۔' WHERE id = 6375;
UPDATE hadiths SET urdu = 'پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ واللہ ( بسا اوقات ) اپنے گھر والوں کے معاملہ میں تمہارا اپنی قسموں پر اصرار کرتے رہنا اللہ کے نزدیک اس سے زیادہ گناہ کی بات ہوتی ہے کہ ( قسم توڑ کر ) اس کا وہ کفارہ ادا کر دیا جائے جو اللہ تعالیٰ نے اس پر فرض کیا ہے۔' WHERE id = 6385;
UPDATE hadiths SET urdu = 'مجھ سے ابراہیم بن موسیٰ نے بیان کیا، انہوں نے کہا ہم کو ہشام بن یوسف نے خبر دی، انہیں معمر نے، انہیں ہمام بن منبہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اس ذات کی قسم! جس کے ہاتھ میں میری جان ہے اگر تم بھی آخرت کی وہ مشکلات جانتے جو میں جانتا ہوں تو تم زیادہ روتے اور کم ہنستے۔“' WHERE id = 6396;
UPDATE hadiths SET urdu = 'ہم سے سعید بن عفیر نے بیان کیا، کہا ہم سے ابن وہب نے بیان کیا، ان سے یونس نے، ان سے ابن شہاب نے، ان سے سالم نے کہ ابن عمر رضی اللہ عنہما نے کہا کہ میں نے عمر رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے مجھ سے فرمایا تھا کہ اللہ تعالیٰ نے تمہیں باپ دادوں کی قسم کھانے سے منع کیا ہے۔ عمر رضی اللہ عنہ نے بیان کیا واللہ! پھر میں نے ان کی نبی کریم صلی اللہ علیہ وسلم سے ممانعت سننے کے بعد کبھی قسم نہیں کھائی نہ اپنی طرف سے غیر اللہ کی قسم کھائی نہ کسی دوسرے کی زبان سے نقل کی۔ مجاہد نے کہا سورۃ الاحقاف میں جو «أثرة من علم‏» ہے اس کا معنی یہ ہے کہ علم کی کوئی بات نقل کرتا ہو۔ یونس کے ساتھ اس حدیث کو عقیل اور محمد بن ولید زبیدی اور اسحاق بن یحییٰ کلبی نے بھی زہری سے روایت کیا اور سفیان بن عیینہ اور معمر نے اس کو زہری سے روایت کیا، انہوں نے سالم سے، انہوں نے ابن عمر رضی اللہ عنہما سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے کہ آپ نے عمر رضی اللہ عنہ کو غیر اللہ کی قسم کھاتے سنا۔ روایت میں لفظ «اثارة» کی تفسیر «اثرا» کی مناسبت سے بیان کر دی کیونکہ دونوں کا مادہ ایک ہی ہے۔' WHERE id = 6406;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، کہا مجھ سے غندر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے معبد بن خالد نے، کہا میں نے حارثہ بن وہب سے سنا، کہا میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم فرماتے تھے کہ میں تم کو بتلاؤں بہشتی کون لوگ ہیں، ہر ایک غریب ناتواں جو اگر اللہ کے بھروسے پر قسم کھا بیٹھے تو اللہ اس کو سچا کرے ( اس کی قسم پوری کر دے ) اور دوزخی کون لوگ ہیں ہر ایک موٹا، لڑاکا، مغرور، فسادی۔' WHERE id = 6416;
UPDATE hadiths SET urdu = 'مجھ سے یوسف بن موسیٰ نے بیان کیا، انہوں نے کہا ہم سے ابواسامہ نے بیان کیا، انہوں نے کہا کہ مجھ سے عوف اعرابی نے بیان کیا، ان سے خلاص بن عمرو اور محمد بن سیرین نے کہا کہ ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جس نے روزہ رکھا ہو اور بھول کر کھا لیا ہو تو اسے اپنا روزہ پورا کر لینا چاہئے کیونکہ اسے اللہ نے کھلایا پلایا ہے۔“' WHERE id = 6427;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، انہیں سعید بن مسیب نے خبر دی، ان کے والد (مسیب رضی اللہ عنہ) نے بیان کیا کہ جب جناب ابوطالب کی موت کی وقت قریب ہوا تو رسول اللہ صلی اللہ علیہ وسلم ان کے پاس آئے اور کہا کہ آپ کہہ دیجئیے کہ ”لا الہٰ الا اللہ“ تو میں آپ کے لیے اللہ سے جھگڑ سکوں گا۔' WHERE id = 6438;
UPDATE hadiths SET urdu = 'ہم سے حسن بن محمد نے بیان کیا، کہا ہم سے ابن جریج نے بیان کیا کہ عطاء کہتے تھے کہ انہوں نے عبید بن عمیر سے سنا، کہا میں نے عائشہ رضی اللہ عنہا سے سنا، وہ کہتی تھیں کہ نبی کریم صلی اللہ علیہ وسلم ( ام المؤمنین ) زینب بنت جحش رضی اللہ عنہا کے یہاں رکتے تھے اور شہد پیتے تھے۔ پھر میں نے اور ( ام المؤمنین ) حفصہ ( رضی اللہ عنہا ) نے عہد کیا کہ ہم میں سے جس کے پاس بھی نبی کریم صلی اللہ علیہ وسلم آئیں تو وہ کہے کہ نبی کریم صلی اللہ علیہ وسلم کے منہ سے مغافیر کی بو آتی ہے، آپ نے مغافیر تو نہیں کھائی ہے؟ چنانچہ نبی کریم صلی اللہ علیہ وسلم جب ایک کے یہاں تشریف لائے تو انہوں نے یہی بات آپ سے پوچھی۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ نہیں بلکہ میں نے شہد پیا ہے زینب بنت جحش کے یہاں اور اب کبھی نہیں پیوں گا۔ ( کیونکہ نبی کریم صلی اللہ علیہ وسلم کو یقین ہو گیا کہ واقعی اس میں مغافیر کی بو آتی ہے ) اس پر یہ آیت نازل ہوئی «يا أيها النبي لم تحرم ما أحل الله لك» ”اے نبی! آپ ایسی چیز کیوں حرام کرتے ہیں جو اللہ نے آپ کے لیے حلال کی ہے۔“ «إن تتوبا إلى الله» میں عائشہ اور حفصہ رضی اللہ عنہا کی طرف اشارہ ہے اور «وإذ أسر النبي إلى بعض أزواجه حديثا» سے اشارہ نبی کریم صلی اللہ علیہ وسلم کے اس ارشاد کی طرف ہے کہ ”نہیں“ میں نے شہد پیا ہے۔“ اور مجھ سے ابراہیم بن موسیٰ نے ہشام سے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا تھا کہ اب کبھی میں شہد نہیں پیوں گا میں نے قسم کھا لی ہے تم اس کی کسی کو خبر نہ کرنا ( پھر آپ نے اس قسم کو توڑ دیا ) ۔' WHERE id = 6448;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے حمید نے، ان سے ثابت نے اور ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ اس سے بےپروا ہے کہ یہ شخص اپنی جان کو عذاب میں ڈالے۔“ نبی کریم صلی اللہ علیہ وسلم نے اسے دیکھا کہ وہ اپنے دو بیٹوں کے درمیان چل رہا تھا اور فزاری نے بیان کیا، ان سے حمید نے، ان سے ثابت نے بیان کیا اور ان سے انس رضی اللہ عنہ نے۔' WHERE id = 6458;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے زہری نے، ان سے حمید بن عبدالرحمٰن نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ ایک صاحب نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور عرض کیا کہ میں تو تباہ ہو گیا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کیا بات ہے؟ کہا کہ میں نے رمضان میں اپنی بیوی سے صحبت کر لی ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کیا تمہارے پاس کوئی غلام ہے جسے آزاد کر سکو؟ انہوں نے کہا نہیں۔ دریافت فرمایا، کیا متواتر دو مہینے تم روزے رکھ سکتے ہو؟ کہا کہ نہیں، دریافت فرمایا کیا ساٹھ مسکینوں کو کھانا کھلا سکتے ہو؟ عرض کیا کہ اس کے لیے بھی میرے پاس کچھ نہیں ہے۔ اس کے بعد نبی کریم صلی اللہ علیہ وسلم کے پاس ایک ٹوکرا لایا گیا جس میں کھجوریں تھیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا اسے لے جا اور صدقہ کر۔ انہوں نے پوچھا کہ اپنے سے زیادہ محتاج پر؟ ان دونوں میدان کے درمیان ہم سے زیادہ محتاج کوئی نہیں ہے۔ آخر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اچھا اسے لے جا اور اپنے گھر والوں کو کھلا دے۔' WHERE id = 6468;
UPDATE hadiths SET urdu = 'ہم سے علی بن حجر نے بیان کیا، کہا ہم سے اسماعیل بن ابراہیم نے بیان کیا، ان سے ایوب سختیانی نے، ان سے قاسم تمیمی نے، ان سے زہدم جرمی نے بیان کیا کہ ہم ابوموسیٰ اشعری رضی اللہ عنہ کے پاس تھے اور ہمارے قبیلہ اور اس قبیلہ جرم میں بھائی چارگی اور باہمی حسن معاملہ کی روش تھی۔ راوی نے بیان کیا کہ پھر کھانا لایا گیا اور کھانے میں مرغی کا گوشت بھی تھا۔ راوی نے بیان کیا کہ حاضرین میں بنی تیم اللہ کا ایک شخص سرخ رنگ کا بھی تھا جیسے مولیٰ ہو۔ بیان کیا کہ وہ شخص کھانے پر نہیں آیا تو موسیٰ رضی اللہ عنہ نے اس سے کہا کہ شریک ہو جاؤ، میں نے رسول اللہ صلی اللہ علیہ وسلم کو اس کا گوشت کھاتے دیکھا ہے۔ اس شخص نے کہا کہ میں نے اسے گندگی کھاتے دیکھا تھا جب سے اس سے گھن آنے لگی اور اسی وقت میں نے قسم کھا لی کہ کبھی اس کا گوشت نہیں کھاؤں گا۔ ابوموسیٰ نے کہا: قریب آؤ میں تمہیں اس کے متعلق بتاؤں گا۔ ہم رسول اللہ صلی اللہ علیہ وسلم کے یہاں اشعریوں کی ایک جماعت کے ساتھ آئے اور میں نے نبی کریم صلی اللہ علیہ وسلم سے سواری کا جانور مانگا۔ نبی کریم صلی اللہ علیہ وسلم اس وقت صدقہ کے اونٹوں میں سے تقسیم کر رہے تھے۔ ایوب نے بیان کیا کہ میرا خیال ہے کہ ابوموسیٰ رضی اللہ عنہ نے کہا کہ نبی کریم صلی اللہ علیہ وسلم اس وقت غصہ تھے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ کی قسم! میں تمہیں سواری کے جانور نہیں دے سکتا اور نہ میرے پاس کوئی ایسی چیز ہے جو سواری کے لیے تمہیں دے سکوں۔ بیان کیا کہ پھر ہم واپس آ گئے۔ پھر نبی کریم صلی اللہ علیہ وسلم کے پاس غنیمت کے اونٹ آئے، تو پوچھا گیا کہ اشعریوں کی جماعت کہاں ہے۔ ہم حاضر ہوئے تو نبی کریم صلی اللہ علیہ وسلم نے ہمیں پانچ عمدہ اونٹ دئیے جانے کا حکم دیا۔ بیان کیا کہ ہم وہاں سے روانہ ہوئے تو میں نے اپنے ساتھیوں سے کہا کہ ہم پہلے نبی کریم صلی اللہ علیہ وسلم کے پاس سواری کے لیے آئے تھے تو آپ نے قسم کھا لی تھی کہ سواری کا انتظام نہیں کر سکتے۔ پھر ہمیں بلا بھیجا اور سواری کا جانور عنایت فرمائے۔ نبی کریم صلی اللہ علیہ وسلم اپنی قسم بھول گئے ہوں گے۔ واللہ! اگر ہم نے نبی کریم صلی اللہ علیہ وسلم کو آپ کی قسم کے بارے میں غفلت میں رکھا تو ہم کبھی کامیاب نہیں ہوں گے۔ چلو ہم سب آپ کے پاس واپس چلیں اور آپ کو آپ کی قسم یاد دلائیں۔ چنانچہ ہم واپس آئے اور عرض کیا کہ یا رسول اللہ! ہم پہلے آئے تھے اور آپ سے سواری کا جانور مانگا تھا تو آپ نے قسم کھا لی تھی کہ آپ اس کا انتظام نہیں کر سکتے، ہم نے سمجھا کہ آپ اپنی قسم بھول گئے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جاؤ، تمہیں اللہ نے سواری دی ہے، واللہ اگر اللہ نے چاہا تو میں جب بھی کوئی قسم کھا لوں اور پھر دوسری چیز کو اس کے مقابل بہتر سمجھوں تو وہی کروں گا جو بہتر ہو گا اور اپنی قسم توڑ دوں گا۔ اس روایت کی متابعت حماد بن زید نے ایوب سے کی، ان سے ابوقلابہ اور قاسم بن عاصم کلیبی نے۔' WHERE id = 6478;
UPDATE hadiths SET urdu = 'ہم سے امام حمیدی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، کہا ہم سے زہری نے بیان کیا، کہا مجھے عامر بن سعد بن ابی وقاص نے خبر دی اور ان سے ان کے والد نے بیان کیا کہ میں مکہ مکرمہ میں ( حجۃ الوداع میں ) بیمار پڑ گیا اور موت کے قریب پہنچ گیا۔ پھر نبی کریم صلی اللہ علیہ وسلم میری عیادت کے لیے تشریف لائے تو میں نے عرض کیا: یا رسول اللہ! میرے پاس بہت زیادہ مال ہے اور ایک لڑکی کے سوا اس کا کوئی وارث نہیں تو کیا مجھے اپنے مال کے دو تہائی حصہ کا صدقہ کر دینا چاہئے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ نہیں۔ بیان کیا کہ میں نے عرض کیا پھر آدھے کا کر دوں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ نہیں۔ میں نے عرض کیا ایک تہائی کا؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہاں۔ گو تہائی بھی بہت ہے، اگر تم اپنے بچوں کو مالدار چھوڑو تو یہ اس سے بہتر ہے کہ انہیں تنگدست چھوڑو اور وہ لوگوں کے سامنے ہاتھ پھیلاتے پھریں اور تم جو بھی خرچ کرو گے اس پر تمہیں ثواب ملے گا یہاں تک کہ اس لقمہ پر بھی ثواب ملے گا جو تم اپنی بیوی کے منہ میں رکھو گے۔ پھر میں نے عرض کیا: یا رسول اللہ! کیا میں اپنی ہجرت میں پیچھے رہ جاؤں گا؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر میرے بعد تم پیچھے رہ بھی گئے تب بھی جو عمل تم کرو گے اور اس سے اللہ کی خوشنودی مقصود ہو گی تو اس کے ذریعہ درجہ و مرتبہ بلند ہو گا اور غالباً تم میرے بعد زندہ رہو گے اور تم سے بہت سے لوگوں کو فائدہ ہو گا اور بہتوں کو نقصان پہنچے گا۔ قابل افسوس تو سعد ابن خولہ ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے ان کے بارے میں اس لیے افسوس کا اظہار کیا کہ ( ہجرت کے بعد اتفاق سے ) ان کی وفات مکہ مکرمہ میں ہی ہو گئی۔ سفیان نے بیان کیا کہ سعد ابن خولہ رضی اللہ عنہ بنی عامر بن لوی کے ایک آدمی تھے۔' WHERE id = 6489;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن عثمان نے بیان کیا، انہوں نے کہا ہم کو عبداللہ بن مبارک نے خبر دی، کہا ہم کو شعبہ بن حجاج نے خبر دی، ان سے محمد بن منکدر نے بیان کیا، انہوں نے جابر رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم میرے گھر تشریف لائے اور میں بیمار تھا۔ نبی کریم صلی اللہ علیہ وسلم نے پانی منگوایا اور وضو کیا، پھر اپنے وضو کے پانی سے مجھ پر چھینٹا ڈالا تو مجھے ہوش آ گیا۔ میں نے نبی کریم صلی اللہ علیہ وسلم سے عرض کیا: یا رسول اللہ! میری بہنیں ہیں؟ اس پر میراث کی آیت نازل ہوئی۔' WHERE id = 6499;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ بن عقبہ نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے ابوقیس نے، ان سے ہزیل نے انہوں نے عبداللہ سے نقل کیا، انہوں نے فرمایا کہ عبداللہ رضی اللہ عنہ نے فرمایا مسلمان سائبہ نہیں بناتے اور دور جاہلیت میں مشرکین سائبہ بناتے تھے۔' WHERE id = 6509;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے عدی نے، ان سے ابوحازم نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جس نے مال چھوڑا ( اپنی موت کے بعد ) وہ اس کے وارثوں کا ہے اور جس نے قرض چھوڑا ہے وہ ہمارے ذمہ ہے۔“' WHERE id = 6519;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے وہیب بن خالد نے بیان کیا، ان سے ایوب نے، ان سے عبداللہ بن ابی ملکہ نے اور ان سے عقبہ بن حارث رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم کے پاس نعیمان یا ابن نعیمان کو لایا گیا، وہ نشہ میں تھا۔ نبی کریم صلی اللہ علیہ وسلم پر یہ ناگوار گزرا اور آپ نے گھر میں موجود لوگوں کو حکم دیا کہ انہیں ماریں۔ چنانچہ لوگوں نے انہیں لکڑی اور جوتوں سے مارا اور میں بھی ان لوگوں میں تھا جنہوں نے اسے مارا تھا۔' WHERE id = 6530;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن عبداللہ نے بیان کیا، انہوں نے کہا ہم سے عاصم بن علی نے بیان کیا، انہوں نے کہا ہم عاصم بن محمد نے بیان کیا، ان سے واقد بن محمد نے بیان کیا، انہوں نے اپنے والد سے سنا کہ عبداللہ رضی اللہ عنہ نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے حجۃ الوداع کے موقع پر فرمایا ”ہاں تم لوگ کس چیز کو سب سے زیادہ حرمت والی سمجھتے ہو؟“ لوگوں نے کہا کہ اپنے اسی مہینہ کو۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”ہاں، کس شہر کو تم سب سے زیادہ حرمت والا سمجھتے ہو؟“ لوگوں نے جواب دیا کہ اپنے اسی شہر کو۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا ”ہاں، کس دن کو تم سب سے زیادہ حرمت والا خیال کرتے ہو؟“ لوگوں نے کہا کہ اپنے اسی دن کو۔ نبی کریم صلی اللہ علیہ وسلم نے اب فرمایا ”پھر بلاشبہ اللہ نے تمہارے خون، تمہارے مال اور تمہاری عزتوں کو حرمت والا قرار دیا ہے، سوا اس کے حق کے، جیسا کہ اس دن کی حرمت اس شہر اور اس مہینہ میں ہے۔ ہاں! کیا میں نے تمہیں پہنچا دیا۔“ تین مرتبہ آپ صلی اللہ علیہ وسلم نے فرمایا اور ہر مرتبہ صحابہ نے جواب دیا کہ جی ہاں، پہنچا دیا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”افسوس میرے بعد تم کافر نہ بن جانا کہ ایک دوسرے کی گردن مارنے لگو۔“' WHERE id = 6540;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، انہوں نے کہا کہ مجھ سے مالک بن انس نے بیان کیا، ان سے عبداللہ بن عمر رضی اللہ عنہما کے آزاد کردہ غلام نافع نے بیان کیا، ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ایک ڈھال پر ہاتھ کاٹا تھا جس کی قیمت تین درہم تھی۔' WHERE id = 6550;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے ایوب سختیانی نے، ان سے ابوقلابہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ قبیلہ عکل یا عرینہ کے چند لوگ میں سمجھتا ہوں عکل کا لفظ کہا، مدینہ آئے اور نبی کریم صلی اللہ علیہ وسلم نے ان کے لیے دودھ دینے والی اونٹنیوں کا انتظام کر دیا اور فرمایا کہ وہ اونٹوں کے گلہ میں جائیں اور ان کا پیشاب اور دودھ پئیں۔ چنانچہ انہوں نے پیا اور جب وہ تندرست ہو گئے تو چرواہے کو قتل کر دیا اور اونٹوں کو ہنکا لے گئے۔ نبی کریم صلی اللہ علیہ وسلم کے پاس یہ خبر صبح کے وقت پہنچی تو آپ نے ان کے پیچھے سوار دوڑائے۔ ابھی دھوپ زیادہ پھیلی بھی نہیں تھی کہ وہ پکڑ کر لائے گئے۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم کے حکم سے ان کے بھی ہاتھ پاؤں کاٹ دئیے گئے اور ان کی بھی آنکھوں میں سلائی پھیر دی گئی اور انہیں حرہ میں ڈال دیا گیا۔ وہ پانی مانگتے تھے لیکن انہیں پانی نہیں دیا جاتا تھا۔ ابوقلابہ نے کہا کہ یہ وہ لوگ تھے جنہوں نے چوری کی تھی، قتل کیا تھا، ایمان کے بعد کفر اختیار کیا تھا اور اللہ اور اس کے رسول سے غدارانہ لڑائی لڑی تھی۔' WHERE id = 6560;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے ابن شہاب نے، ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ سعد بن ابی وقاص اور عبد بن زمعہ رضی اللہ عنہما نے آپس میں ( ایک بچے عبدالرحمٰن نامی میں ) اختلاف کیا تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”عبد بن زمعہ! بچہ تو لے لے بچہ اسی کو ملے گا جس کی جورو یا لونڈی کے پیٹ سے وہ پیدا ہوا اور سودہ! تم اس سے پردہ کیا کرو۔“ امام بخاری رحمہ اللہ نے کہا کہ قتیبہ نے لیث سے اس زیادہ کے ساتھ بیان کیا کہ زانی کے حصہ میں پتھر کی سزا ہے۔' WHERE id = 6571;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، ان سے سعید بن مسیب نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے ایسے شخص کے بارے میں جس نے زنا کیا تھا اور وہ غیر شادی شدہ تھا، حد قائم کرنے کے ساتھ ایک سال تک شہر باہر کرنے کا فیصلہ کیا تھا۔' WHERE id = 6584;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن علی نے بیان کیا، انہوں نے کہا ہم سے فضیل بن سلیمان نے بیان کیا، انہوں نے کہا ہم سے مسلم بن ابی مریم نے بیان کیا، کہا مجھ سے عبدالرحمٰن بن جابر نے ان صحابی سے بیان کیا جنہوں نے نبی کریم صلی اللہ علیہ وسلم سے سنا تھا کہ آپ صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ کی حدود میں سے کسی حد کے سوا مجرم کو دس کوڑے سے زیادہ کی سزا نہ دی جائے۔“' WHERE id = 6597;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے جریر بن عبدالحمید نے بیان کیا، ان سے اعمش نے، ان سے ابووائل نے، ان سے عمرو بن شرجیل نے بیان کیا، ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ ایک صاحب یعنی خود آپ نے کہا: یا رسول اللہ! اللہ کے نزدیک کون سا گناہ سب سے بڑا ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا یہ کہ تم اللہ کا کسی کو شریک ٹھہراؤ جبکہ اس نے تمہیں پیدا کیا ہے۔ پوچھا: پھر کون سا؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر یہ کہ تم اپنے لڑکے کو اس ڈر سے مار ڈالو کہ وہ تمہارے ساتھ کھانا کھائے گا۔ پوچھا: پھر کون سا؟ فرمایا پھر یہ کہ تم اپنے پڑوسی کی بیوی سے زنا کرو۔ پھر اللہ تعالیٰ نے اس کی تصدیق میں یہ آیت نازل کی «والذين لا يدعون مع الله إلها آخر ولا يقتلون النفس التي حرم الله إلا بالحق ولا يزنون ومن يفعل ذلك يلق أثاما يضاعف له العذاب» ”اور وہ لوگ جو اللہ کے ساتھ کسی دوسرے معبود کو نہیں پکارتے اور نہ کسی ایسے انسان کی ناحق جان لیتے ہیں جسے اللہ نے حرام کیا اور نہ زنا کرتے ہیں اور جو کوئی ایسا کرے گا۔“ آخر آیت تک۔' WHERE id = 6608;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، کہا ہم سے یزید نے بیان کیا، ان سے ابوالخیر نے، ان سے صنابحی نے اور ان سے عبادہ بن صامت رضی اللہ عنہ نے بیان کیا کہ میں ان نقیبوں میں سے تھا جنہوں نے ( منیٰ میں لیلۃالعقبہ کے موقع پر ) رسول اللہ صلی اللہ علیہ وسلم سے بیعت کی تھی۔ ہم نے اس کی بیعت ( عہد ) کی تھی کہ ہم اللہ کے ساتھ کسی کو شریک نہیں ٹھہرائیں گے، ہم چوری نہیں کریں گے، زنا نہیں کریں گے، کسی کی ناحق جان نہیں لیں گے جو اللہ نے حرام کی ہے، ہم لوٹ مار نہیں کریں گے اور آپ صلی اللہ علیہ وسلم کی نافرمانی نہیں کریں گے اور یہ کہ اگر ہم نے اس پر عمل کیا تو ہمیں جنت ملے گی اور اگر ہم نے ان میں سے کسی طرح کا گناہ کیا تو اس کا فیصلہ اللہ تبارک و تعالیٰ کے یہاں ہو گا۔' WHERE id = 6619;
UPDATE hadiths SET urdu = 'ہم سے فروہ بن ابی المغراء نے بیان کیا، کہا ہم سے علی بن مسہر نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے کہ مشرکین نے احد کی لڑائی میں پہلے شکست کھائی تھی ( دوسری سند ) امام بخاری رحمہ اللہ نے کہا مجھ سے محمد بن حرب نے بیان کیا، ان سے ابومروان یحییٰ ابن ابی زکریا نے بیان کیا، ان سے ہشام نے، ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ ابلیس احد کی لڑائی میں لوگوں میں چیخا۔ اے اللہ کے بندو! اپنے پیچھے والوں سے، مگر یہ سنتے ہی آگے کے مسلمان پیچھے کی طرف پلٹ پڑے یہاں تک کہ مسلمانوں نے ( غلطی میں ) حذیفہ کے والد یمان رضی اللہ عنہ کو قتل کر دیا۔ اس پر حذیفہ رضی اللہ عنہ نے کہا کہ یہ میرے والد ہیں، میرے والد! لیکن انہیں قتل ہی کر ڈالا۔ پھر حذیفہ رضی اللہ عنہ نے کہا اللہ تمہاری مغفرت کرے۔ بیان کیا کہ مشرکین کی ایک جماعت میدان سے بھاگ کر طائف تک پہنچ گئی تھی۔' WHERE id = 6629;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبداللہ انصاری نے بیان کیا، کہا ہم سے حمید طویل نے بیان کیا، ان سے انس رضی اللہ عنہ نے کہ نضرت کی بیٹی نے ایک لڑکی کو طمانچہ مارا تھا اور اس کے دانت ٹوٹ گئے تھے۔ لوگ نبی کریم صلی اللہ علیہ وسلم کے پاس مقدمہ لائے تو نبی کریم صلی اللہ علیہ وسلم نے قصاص کا حکم دیا۔' WHERE id = 6639;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو امام مالک نے خبر دی۔ (دوسری سند) امام بخاری رحمہ اللہ نے کہا کہ اور ہم سے اسماعیل نے بیان کیا، ان سے امام مالک نے، ان سے ابن شہاب نے، ان سے ابوسلمہ بن عبدالرحمٰن نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ قبیلہ ہذیل کی دو عورتوں نے ایک دوسری کو ( پتھر سے ) مارا جس سے ایک کے پیٹ کا بچہ ( جنین ) گر گیا پھر اس ( سلسلہ ) میں رسول اللہ صلی اللہ علیہ وسلم نے اسے ایک غلام یا کنیز دینے کا فیصلہ کیا۔' WHERE id = 6650;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف بیکندی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے، انہوں نے عمرو بن یحییٰ مازنی سے انہوں نے اپنے والد (یحییٰ بن عمارہ) سے، انہوں نے ابو سعید خدری رضی اللہ عنہ سے، انہوں نے کہا یہود میں سے ایک شخص نبی کریم صلی اللہ علیہ وسلم کے پاس آیا، اس کو کسی نے طمانچہ لگایا تھا۔ کہنے لگا: اے محمد! ( صلی اللہ علیہ وسلم ) تمہارے اصحاب میں سے ایک انصاری شخص نے مجھ کو طمانچہ مارا۔ آپ نے لوگوں سے فرمایا اس کو بلاؤ تو انہوں نے بلایا ( وہ حاضر ہوا ) آپ نے پوچھا تو نے اس کے منہ پر طمانچہ کیوں مارا۔ وہ کہنے لگا: یا رسول اللہ! ایسا ہوا کہ میں یہودیوں کے پاس سے گزرا، میں نے سنا یہ یہودی یوں قسم کھا رہا تھا قسم اس پروردگار کی جس نے موسیٰ علیہ السلام کو سارے آدمیوں میں سے چن لیا۔ میں نے کہا کیا محمد صلی اللہ علیہ وسلم سے بھی وہ افضل ہیں؟ اور اس وقت مجھے غصہ آ گیا۔ میں نے ایک طمانچہ لگا دیا ( غصے میں یہ خطا مجھ سے ہو گئی ) آپ صلی اللہ علیہ وسلم نے فرمایا ( دیکھو خیال رکھو ) اور پیغمبروں پر مجھ کو فضیلت نہ دو قیامت کے دن ایسا ہو گا سب لوگ ( ہیبت خداوندی سے ) بیہوش ہو جائیں گے پھر میں سب سے پہلے ہوش میں آؤں گا۔ کیا دیکھوں گا موسیٰ علیہ السلام ( مجھ سے بھی پہلے ) عرش کا ایک کونہ تھامے کھڑے ہیں۔ اب یہ میں نہیں جانتا کہ وہ مجھ سے پہلے ہوش میں آ جائیں گے یا کوہ طور پر جو ( دنیا میں ) بیہوش ہو چکے تھے اس کے بدل وہ آخرت میں بیہوش ہی نہ ہوں گے۔' WHERE id = 6662;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، کہا ہم سے ہمارے والد نے، کہا ہم سے اعمش نے، کہا مجھ سے شقیق ابن سلمہ نے کہ عبداللہ بن مسعود رضی اللہ عنہ نے کہا جیسے میں ( اس وقت ) نبی کریم صلی اللہ علیہ وسلم کو دیکھ رہا ہوں آپ ایک پیغمبر ( نوح علیہ السلام ) کی حکایت بیان کر رہے تھے ان کی قوم والوں نے ان کو اتنا مارا کہ لہولہان کر دیا وہ اپنے منہ سے خون پونچھتے تھے اور یوں دعا کرتے جاتے «رب اغفر لقومي،‏‏‏‏ فإنهم لا يعلمون‏.‏» ”پروردگار میری قوم والوں کو بخش دے وہ نادان ہیں۔“' WHERE id = 6673;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ابوعوانہ وضاح شکری نے بیان کیا، ان سے حصین بن عبدالرحمٰن سلمی نے، ان سے فلاں شخص (سعید بن عبیدہ) نے کہ ابوعبدالرحمٰن اور حبان بن عطیہ کا آپس میں اختلاف ہوا۔ ابوعبدالرحمٰن نے حبان سے کہا کہ آپ کو معلوم ہے کہ آپ کے ساتھی خون بہانے میں کس قدر جری ہو گئے ہیں۔ ان کا اشارہ علی رضی اللہ عنہ کی طرف تھا اس پر حبان نے کہا انہوں نے کیا کیا ہے، تیرا باپ نہیں۔ ابوعبدالرحمٰن نے کہا کہ علی رضی اللہ عنہ کہتے تھے کہ مجھے، زبیر اور ابومرثد رضی اللہ عنہم کو رسول اللہ صلی اللہ علیہ وسلم نے بھیجا اور ہم سب گھوڑوں پر سوار تھے نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جاؤ اور جب روضہ خاخ پر پہنچو ( جو مدینہ سے بارہ میل کے فاصلہ پر ایک جگہ ہے ) ابوسلمہ نے بیان کیا کہ ابوعوانہ نے خاخ کے بدلے حاج کہا ہے۔ تو وہاں تمہیں ایک عورت ( سارہ نامی ) ملے گی اور اس کے پاس حاطب بن ابی بلتعہ کا ایک خط ہے جو مشرکین مکہ کو لکھا گیا ہے تم وہ خط میرے پاس لاؤ۔ چنانچہ ہم اپنے گھوڑوں پر دوڑے اور ہم نے اسے وہیں پکڑا جہاں نبی کریم صلی اللہ علیہ وسلم نے بتایا تھا۔ وہ عورت اپنے اونٹ پر سوار جا رہی تھی حاطب بن ابی بلتعہ رضی اللہ عنہ نے اہل مکہ کو نبی کریم صلی اللہ علیہ وسلم کی مکہ کو آنے کی خبر دی تھی۔ ہم نے اس عورت سے کہا کہ تمہارے پاس وہ خط کہاں ہے اس نے کہا کہ میرے پاس تو کوئی خط نہیں ہے ہم نے اس کا اونٹ بٹھا دیا اور اس کے کجاوہ کی تلاشی لی لیکن اس میں کوئی خط نہیں ملا۔ میرے ساتھی نے کہا کہ اس کے پاس کوئی خط نہیں معلوم ہوتا۔ راوی نے بیان کیا کہ ہمیں یقین ہے کہ نبی کریم صلی اللہ علیہ وسلم نے غلط بات نہیں فرمائی پھر علی رضی اللہ عنہ نے قسم کھائی کہ اس ذات کی قسم جس کی قسم کھائی جاتی ہے خط نکال دے ورنہ میں تجھے ننگی کروں گا اب وہ عورت اپنے نیفے کی طرف جھکی اس نے ایک چادر کمر پر باندھ رکھی تھی اور خط نکالا۔ اس کے بعد یہ لوگ خط نبی کریم صلی اللہ علیہ وسلم کے پاس لائے۔ عمر رضی اللہ عنہ نے عرض کیا: یا رسول اللہ! اس نے اللہ اور اس کے رسول اور مسلمانوں کے ساتھ خیانت کی ہے، مجھے اجازت دیجئیے کہ میں اس کی گردن مار دوں۔ لیکن نبی کریم صلی اللہ علیہ وسلم نے فرمایا، حاطب! تم نے ایسا کیوں کیا؟ حاطب رضی اللہ عنہ نے کہا: یا رسول اللہ! بھلا کیا مجھ سے یہ ممکن ہے کہ میں اللہ اور اس کے رسول پر ایمان نہ رکھوں میرا مطلب اس خط کے لکھنے سے صرف یہ تھا کہ میرا ایک احسان مکہ والوں پر ہو جائے جس کی وجہ سے میں اپنی جائیداد اور بال بچوں کو ( ان کے ہاتھ سے ) بچا لوں۔ بات یہ ہے کہ آپ کے اصحاب میں کوئی ایسا نہیں جس کے مکہ میں ان کی قوم میں کے ایسے لوگ نہ ہوں جس کی وجہ سے اللہ ان کے بچوں اور جائیداد پر کوئی آفت نہیں آنے دیتا۔ مگر میرا وہاں کوئی نہیں ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ حاطب نے سچ کہا ہے۔ بھلائی کے سوا ان کے بارے میں اور کچھ نہ کہو۔ بیان کیا کہ عمر رضی اللہ عنہ نے دوبارہ کہا کہ یا رسول اللہ صلی اللہ علیہ وسلم اس نے اللہ اور اس کے رسول اور مومنوں کے ساتھ خیانت کی ہے۔ مجھے اجازت دیجئیے کہ میں اس کی گردن مار دوں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کیا یہ جنگ بدر میں شریک ہونے والوں میں سے نہیں ہیں؟ تمہیں کیا معلوم اللہ تعالیٰ ان کے اعمال سے واقف تھا اور پھر فرمایا کہ جو چاہو کرو میں نے جنت تمہارے لیے لکھ دی ہے اس پر عمر رضی اللہ عنہ کی آنکھوں میں ( خوشی سے ) آنسو بھر آئے اور عرض کیا: اللہ اور اس کے رسول ہی کو حقیقت کا زیادہ علم ہے۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) نے کہا کہ «خاخ» زیادہ صحیح ہے لیکن ابوعوانہ نے «حاج» ہی بیان کیا ہے اور لفظ «حاج» بدلا ہوا ہے یہ ایک جگہ کا نام ہے اور ہشیم نے «خاخ» بیان کیا ہے۔' WHERE id = 6683;
UPDATE hadiths SET urdu = 'اور لیث بن سعد نے بیان کیا کہ مجھ سے نافع نے بیان کیا، انہیں صفیہ بنت ابی عبید نے خبر دی کہ حکومت کے غلاموں میں سے ایک نے حصہ خمس کی ایک باندی سے صحبت کر لی اور اس کے ساتھ زبردستی کر کے اس کی بکارت توڑ دی تو عمر رضی اللہ عنہ نے غلام پر حد جاری کرائی اور اسے شہر بدر بھی کر دیا لیکن باندی پر حد نہیں جاری کی۔ کیونکہ غلام نے اس کے ساتھ زبردستی کی تھی۔ زہری نے ایسی کنواری باندی کے متعلق کہا جس کے ساتھ کسی آزاد نے ہمبستری کر لی ہو کہ حاکم کنواری باندی میں اس کی وجہ سے اس شخص سے اتنے دام بھر لے جتنے بکارت جاتے رہنے کی وجہ سے اس کے دام کم ہو گئے ہیں اور اس کو کوڑے بھی لگائے اگر آزاد مرد ثیبہ لونڈی سے زنا کرے تب خریدے۔ اماموں نے یہ حکم نہیں دیا ہے کہ اس کو کچھ مالی تاوان دینا پڑے گا بلکہ صرف حد لگائی جائے گی۔' WHERE id = 6693;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا ہم سے یحییٰ قطان نے بیان کیا، ان سے عبیداللہ بن عمر نے بیان کیا، انہوں نے کہا کہ ہم سے زہری نے بیان کیا، ان سے حسن اور عبداللہ بن محمد بن علی نے بیان کیا، ان سے ان کے والد نے کہ علی رضی اللہ عنہ سے کہا گیا کہ عبداللہ بن عباس رضی اللہ عنہما عورتوں کے متعہ میں کوئی حرج نہیں سمجھتے انہوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے خیبر کی لڑائی کے موقع پر متعہ سے اور پالتو گدھوں کے گوشت سے منع کر دیا تھا اور بعض لوگ کہتے ہیں کہ اگر کسی نے حیلہ سے متعہ کر لیا تو نکاح فاسد ہے اور بعض لوگوں نے کہا کہ نکاح جائز ہو جائے گا اور میعاد کی شرط باطل ہو جائے گی۔' WHERE id = 6704;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم ضحاک بن مخلد نے بیان کیا، ان سے ابن جریج نے، ان سے ابن ابی ملیکہ نے، ان سے ذکوان نے، اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”کنواری لڑکی سے اجازت لی جائے گی۔“ میں نے پوچھا کہ کنواری لڑکی شرمائے گی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس کی خاموشی ہی اجازت ہے۔ اور بعض لوگوں کا کہنا ہے کہ کوئی شخص اگر کسی یتیم لڑکی یا کنواری لڑکی سے نکاح کا خواہشمند ہو۔ لیکن لڑکی راضی نہ ہو اس پر اس نے حیلہ کیا اور دو جھوٹے گواہوں کی گواہی اس کی دلائی کہ اس نے لڑکی سے شادی کر لی ہے پھر جب وہ لڑکی جوان ہوئی اور اس نکاح سے وہ بھی راضی ہو گئی اور قاضی نے اس جھوٹی شہادت کو قبول کر لیا حالانکہ وہ جانتا ہے کہ یہ سارا ہی جھوٹ اور فریب ہے تب بھی اس سے جماع کرنا جائز ہے۔' WHERE id = 6714;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا ‘ کہا ہم سے یحییٰ نے بیان کیا ‘ ان سے سفیان نے ‘ ان سے ابراہیم بن میسرہ نے بیان کیا ‘ ان سے عمرو بن شرید نے کہ ابورافع رضی اللہ عنہ نے سعد بن مالک رضی اللہ عنہ کو ایک گھر چار سو مثقال میں بیچا اور کہا کہ اگر میں نے نبی کریم صلی اللہ علیہ وسلم سے یہ نہ سنا ہوتا کہ پڑوسی حق پڑوس کا زیادہ حقدار ہے تو میں آپ کو یہ گھر نہ دیتا ( اور کسی کے ہاتھ بیچ ڈالتا ) ۔' WHERE id = 6724;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، انہوں نے کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے بیان کیا، ان سے ابن شہاب نے بیان کیا، ان سے سالم بن عبداللہ نے، ان سے ابن عمر رضی اللہ عنہما نے کہ کچھ لوگوں کو خواب میں شب قدر ( رمضان کی ) سات آخری تاریخوں میں دکھائی گئی اور کچھ لوگوں کو دکھائی گئی کہ وہ آخری دس تاریخوں میں ہو گی تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اسے آخری سات تاریخوں میں تلاش کرو۔' WHERE id = 6734;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو امام مالک نے خبر دی، انہیں اسحاق بن عبداللہ بن ابی طلحہ نے اور انہوں نے انس بن مالک رضی اللہ عنہ سے سنا کہ رسول اللہ صلی اللہ علیہ وسلم ام حرام بنت ملحان رضی اللہ عنہا کے ہاں تشریف لے جایا کرتے تھے، وہ عبادہ بن صامت کے نکاح میں تھیں۔ ایک دن آپ ان کے یہاں گئے تو انہوں نے آپ کے سامنے کھانے کی چیز پیش کی اور آپ کا سر جھاڑنے لگیں۔ اس عرصہ میں نبی کریم صلی اللہ علیہ وسلم سو گئے پھر بیدار ہوئے تو آپ صلی اللہ علیہ وسلم مسکرا رہے تھے۔' WHERE id = 6744;
UPDATE hadiths SET urdu = 'ہم سے محمد نے بیان کیا، کہا ہم کو ابومعاویہ نے خبر دی، کہا ہم کو ہشام نے خبر دی، انہیں ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”تم سے شادی کرنے سے پہلے مجھے تم دو مرتبہ دیکھائی گئیں، میں نے دیکھا کہ ایک فرشتہ تمہیں ریشم کے ایک ٹکڑے میں اٹھائے ہوئے ہے۔ میں نے اس سے کہا کہ کھولو اس نے کھولا تو وہ تم تھیں۔ میں نے کہا کہ اگر یہ اللہ کے پاس سے ہے تو وہ خود ہی اسے انجام تک پہنچائے گا۔ پھر میں نے تمہیں دیکھا کہ فرشتہ تمہیں ریشم کے ایک ٹکڑے میں اٹھائے ہوئے ہے۔ میں نے کہا کہ کھولو! اس نے کھولا تو اس میں تم تھیں، پھر میں نے کہا کہ یہ تو اللہ کی طرف سے ہے جو ضرور پورا ہو گا۔“' WHERE id = 6754;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن علی نے بیان کیا، انہوں نے کہا ہم سے معتمر بن سلیمان نے بیان کیا، ان سے عبیداللہ بن عمر نے بیان کیا، ان سے محمد بن منکدر نے اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”میں جنت میں داخل ہوا تو وہاں ایک سونے کا محل مجھے نظر آیا۔ میں نے پوچھا یہ کس کا ہے؟ کہا کہ قریش کے ایک شخص کا۔ اے ابن الخطاب! مجھے اس کے اندر جانے سے تمہاری غیرت نے روک دیا ہے جسے میں خوب جانتا ہوں۔“ عمر رضی اللہ عنہ نے عرض کیا: یا رسول اللہ! کیا میں آپ پر غیرت کروں گا۔' WHERE id = 6765;
UPDATE hadiths SET urdu = 'ہم سے ابوبکر المقدمی نے بیان کیا ‘ انہوں نے کہا ہم سے فضیل بن سلیمان نے بیان کیا ‘ ان سے موسیٰ نے بیان کیا، ان سے سالم بن عبداللہ نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے مدینہ میں خواب کے سلسلے میں کہ ( نبی کریم صلی اللہ علیہ وسلم نے فرمایا ) ”میں نے ایک پراگندہ بال، سیاہ عورت دیکھی کہ وہ مدینہ سے نکل کر مہیعہ چلی گئی۔ میں نے اس کی تعبیر لی کہ مدینہ کی وبا مهيعۃ منتقل ہو گئی ہے۔“ مہیعہ یعنی الجحفۃ کو کہتے ہیں۔' WHERE id = 6777;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ابوعوانہ نے، ان سے ابووائل کے غلام مغیرہ ابن مقسم نے بیان کیا اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”حوض کوثر پر تم لوگوں کا پیش خیمہ ہوں گا اور تم میں سے کچھ لوگ میری طرف آئیں گے جب میں انہیں ( حوض کا پانی ) دینے کے لیے جھکوں گا تو انہیں میرے سامنے سے کھینچ لیا جائے گا۔ میں کہوں گا اے میرے رب! یہ تو میری امت کے لوگ ہیں۔ اللہ تعالیٰ فرمائے گا آپ کو معلوم نہیں کہ انہوں نے آپ کے بعد دین میں کیا کیا نئی باتیں نکال لی تھیں۔“' WHERE id = 6787;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، انہوں نے کہا ہم سے جریر نے بیان کیا، ان سے اعمش نے بیان کیا اور ان سے ابووائل نے بیان کیا کہ میں عبداللہ بن مسعود اور ابوموسیٰ رضی اللہ عنہما کے ساتھ بیٹھا ہوا تھا تو ابوموسیٰ رضی اللہ عنہ نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا اسی طرح۔ «هرج» حبشہ کی زبان میں قتل کو کہتے ہیں۔' WHERE id = 6801;
UPDATE hadiths SET urdu = 'ہم سے محمد بن العلاء نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے برید نے، ان سے ابوبردہ نے اور ان سے ابوموسیٰ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جب تم میں سے کوئی ہماری مسجد میں یا ہمارے بازار میں گزرے اور اس کے پاس تیر ہوں تو اسے چاہئیے کہ اس کی نوک کا خیال رکھے۔“ یا آپ صلی اللہ علیہ وسلم نے فرمایا کہ اپنے ہاتھ سے انہیں تھامے رہے۔ کہیں کسی مسلمان کو اس سے کوئی تکلیف نہ پہنچے۔' WHERE id = 6811;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یزید نے بیان کیا، کہا ہم سے حیوہ بن شریح وغیرہ نے بیان کیا کہ ہم سے ابوالاسود نے بیان کیا، یا لیث نے ابوالاسود سے بیان کیا کہ اہل مدینہ کا ایک لشکر تیار کیا گیا ( یعنی عبداللہ بن زبیر رضی اللہ عنہما کے زمانہ میں شام والوں سے مقابلہ کرنے کے لیے ) اور میرا نام اس میں لکھ دیا گیا۔ پھر میں عکرمہ سے ملا اور میں نے انہیں خبر دی تو انہوں نے مجھے شرکت سے سختی کے ساتھ منع کیا۔ پھر کہا کہ ابن عباس رضی اللہ عنہما نے مجھے خبر دی ہے کہ کچھ مسلمان جو مشرکین کے ساتھ رہتے تھے وہ رسول اللہ صلی اللہ علیہ وسلم کے خلاف ( غزوات ) میں مشرکین کی جماعت کی زیادتی کا باعث بنتے۔ پھر کوئی تیر آتا اور ان میں سے کسی کو لگ جاتا اور قتل کر دیتا یا انہیں کوئی تلوار سے قتل کر دیتا، پھر اللہ تعالیٰ نے یہ آیت نازل کی «إن الذين توفاهم الملائكة ظالمي أنفسهم‏» ”بلا شک وہ لوگ جن کو فرشتے فوت کرتے ہیں اس حال میں کہ وہ اپنی جانوں پر ظلم کرنے والے ہوتے ہیں۔“' WHERE id = 6821;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن شاہین واسطی نے بیان کیا، کہا ہم سے خلف بن عبداللہ طحان نے بیان کیا، ان سے بیان ابن بصیر نے، ان سے وبرہ بن عبدالرحمٰن نے، ان سے سعید بن جبیر نے بیان کیا کہ عبداللہ بن عمر رضی اللہ عنہما ہمارے پاس آئے تو ہم نے امید کی کہ وہ ہم سے کوئی اچھی بات کریں گے۔ اتنے میں ایک صاحب حکیم نامی ہم سے پہلے ان کے پاس پہنچ گئے اور پوچھا: اے ابوعبدالرحمٰن! ہم سے زمانہ فتنہ میں قتال کے متعلق حدیث بیان کیجئے۔ اللہ تعالیٰ فرماتا ہے تم ان سے جنگ کرو یہاں تک کہ فتنہ باقی نہ رہے۔ ابن عمر رضی اللہ عنہما نے کہا تمہیں معلوم بھی ہے کہ فتنہ کیا ہے؟ تمہاری ماں تمہیں روئے۔ محمد صلی اللہ علیہ وسلم فتنہ رفع کرنے کے لیے مشرکین سے جنگ کرتے تھے، شرک میں پڑنا یہ فتنہ ہے۔ کیا نبی کریم صلی اللہ علیہ وسلم کی لڑائی تم لوگوں کی طرح بادشاہت حاصل کرنے کے لیے ہوتی تھی؟' WHERE id = 6831;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، انہوں نے کہا ہم سے حماد بن زید نے بیان کیا، ان سے ایوب نے، ان سے نافع نے کہ جب اہل مدینہ نے یزید بن معاویہ کی بیعت سے انکار کیا تو عبداللہ بن عمر رضی اللہ عنہما نے اپنے خادموں اور لڑکوں کو جمع کیا اور کہا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا ہے، آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہر غدر کرنے والے کے لیے قیامت کے دن ایک جھنڈا کھڑا کیا جائے گا اور ہم نے اس شخص ( یزید ) کی بیعت، اللہ اور اس کے رسول کے نام پر کی ہے اور میرے علم میں کوئی غدر اس سے بڑھ کر نہیں ہے کہ کسی شخص سے اللہ اور اس کے رسول کے نام پر بیعت کی جائے اور پھر اس سے جنگ کی جائے اور دیکھو مدینہ والو! تم میں سے جو کوئی یزید کی بیعت کو توڑے اور دوسرے کسی سے بیعت کرے تو مجھ میں اور اس میں کوئی تعلق نہیں رہا، میں اس سے الگ ہوں۔' WHERE id = 6843;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، کہا ہم سے ابوالزناد نے بیان کیا، ان سے عبدالرحمٰن نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”قیامت اس وقت تک قائم نہ ہو گی جب تک دو عظیم جماعتیں جنگ نہ کریں گی۔ ان دونوں جماعتوں کے درمیان بڑی خونریزی ہو گی۔ حالانکہ دونوں کا دعویٰ ایک ہی ہو گا اور یہاں تک کہ بہت سے جھوٹے دجال بھیجے جائیں گے۔ تقریباً تین دجال۔ ان میں سے ہر ایک دعویٰ کرے گا کہ وہ اللہ کا رسول ہے اور یہاں تک کہ علم اٹھا لیا جائے گا اور زلزلوں کی کثرت ہو گی اور زمانہ قریب ہو جائے گا اور فتنے ظاہر ہو جائیں گے اور ہرج بڑھ جائے گا اور ہرج سے مراد قتل ہے اور یہاں تک کہ تمہارے پاس مال کی کثرت ہو جائے گی بلکہ بہہ پڑے گا اور یہاں تک کہ صاحب مال کو اس کا فکر دامن گیر ہو گا کہ اس کا صدقہ قبول کون کرے اور یہاں تک کہ وہ پیش کرے گا لیکن جس کے سامنے پیش کرے گا وہ کہے گا کہ مجھے اس کی ضرورت نہیں ہے اور یہاں تک کہ لوگ بڑی بڑی عمارتوں پر آپس میں فخر کریں گے۔ ایک سے ایک بڑھ چڑھ کر عمارات بنائیں گے اور یہاں تک کہ ایک شخص دوسرے کی قبر سے گزرے گا اور کہے گا کہ کاش میں بھی اسی جگہ ہوتا اور یہاں تک کہ سورج مغرب سے نکلے گا۔ پس جب وہ اس طرح طلوع ہو گا اور لوگ دیکھ لیں گے تو سب ایمان لے آئیں گے لیکن یہ وہ وقت ہو گا جب کسی ایسے شخص کو اس کا ایمان لانا فائدہ نہ پہنچائے گا جو پہلے سے ایمان نہ لایا ہو یا اس نے اپنے ایمان کے ساتھ اچھے کام نہ کئے ہوں اور قیامت اچانک اس طرح قائم ہو جائے گی کہ دو آدمیوں نے اپنے درمیان کپڑا پھیلا رکھا ہو گا اور اسے ابھی بیچ نہ پائے ہوں گے نہ لپیٹ پائے ہوں گے اور قیامت اس طرح برپا ہو جائے گی کہ ایک شخص اپنی اونٹنی کا دودھ نکال کر واپس ہوا ہو گا کہ اسے کھا بھی نہ پایا ہو گا اور قیامت اس طرح قائم ہو جائے گی کہ وہ اپنے حوض کو درست کر رہا ہو گا اور اس میں سے پانی بھی نہ پیا ہو گا اور قیامت اس طرح قائم ہو جائے گی کہ اس نے اپنا لقمہ منہ کی طرف اٹھایا ہو گا اور ابھی اسے کھایا بھی نہ ہو گا۔' WHERE id = 6853;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جو نبی بھی مبعوث کیا گیا تو انہوں نے اپنی قوم کو کانے جھوٹے سے ڈرایا، آگاہ رہو کہ وہ کانا ہے اور تمہارا رب کانا نہیں ہے۔ اور اس کی دونوں آنکھوں کے درمیان ”کافر“ لکھا ہوا ہے۔“ اس باب میں ابوہریرہ رضی اللہ عنہ اور ابن عباس رضی اللہ عنہما نے بھی نبی کریم صلی اللہ علیہ وسلم سے یہ حدیث روایت کی ہے۔' WHERE id = 6863;
UPDATE hadiths SET urdu = 'ہم سے شہاب بن عباد نے بیان کیا، کہا ہم سے ابراہیم بن حمید نے بیان کیا، ان سے اسماعیل بن ابی خالد نے، ان سے قیس بن ابی حازم نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”رشک بس دو آدمیوں پر ہی کیا جانا چاہئے۔ ایک وہ شخص جسے اللہ نے مال دیا اور پھر اس نے وہ حق کے راستے میں بےدریغ خرچ کیا اور دوسرا وہ شخص جسے اللہ نے حکمت دین کا علم ( قرآن و حدیث کا ) دیا ہے وہ اس کے موافق فیصلے کرتا ہے۔“' WHERE id = 6873;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن منصور نے بیان کیا، کہا ہم کو حسین الجعفی نے خبر دی کہ زائدہ نے بیان کیا، ان سے ہشام نے اور ان سے حسن نے بیان کیا کہ ہم معقل بن یسار رضی اللہ عنہ کی عیادت کے لیے ان کے پاس گئے پھر عبیداللہ بھی آئے تو معقل رضی اللہ عنہ نے ان سے کہا کہ میں تم سے ایک ایسی حدیث بیان کرتا ہوں جسے میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر کوئی شخص مسلمانوں کا حاکم بنایا گیا اور اس نے ان کے معاملہ میں خیانت کی اور اسی حالت میں مر گیا تو اللہ تعالیٰ اس پر جنت کو حرام کر دیتا ہے۔' WHERE id = 6883;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، انہیں زہری نے، انہیں عروہ نے بیان کیا اور ان سے عائشہ رضی اللہ عنہا نے کہ ہند بنت عتبہ بن ربیعہ آئیں اور کہا: یا رسول اللہ! روئے زمین کا کوئی گھرانہ ایسا نہیں تھا جس کے متعلق اس درجہ میں ذلت کی خواہشمند ہوں جتنا آپ کے گھرانہ کی ذلت و رسوائی کی میں خواہشمند تھی لیکن اب میرا یہ حال ہے کہ میں سب سے زیادہ خواہشمند ہوں کہ روئے زمین کے تمام گھرانوں میں آپ کا گھرانہ عزت و سربلندی والا ہو۔ پھر انہوں نے کہا کہ ابوسفیان رضی اللہ عنہ بخیل آدمی ہیں، تو کیا میرے لیے کوئی حرج ہے اگر میں ان کے مال میں سے ( ان کی اجازت کے بغیر لے کر ) اپنے اہل و عیال کو کھلاؤں؟ نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا کہ تمہارے لیے کوئی حرج نہیں ہے، اگر تم انہیں دستور کے مطابق کھلاؤ۔' WHERE id = 6893;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے بیان کیا، ان سے ابن شہاب نے اور ان سے جناب زین العابدین علی بن حسین رحمہ اللہ نے کہ صفیہ بنت حیی رضی اللہ عنہا ( رات کے وقت ) نبی کریم صلی اللہ علیہ وسلم کے پاس آئیں ( اور نبی کریم صلی اللہ علیہ وسلم مسجد میں معتکف تھے ) جب وہ واپس آنے لگیں تو نبی کریم صلی اللہ علیہ وسلم بھی ان کے ساتھ آئے۔ اس وقت دو انصاری صحابی ادھر سے گزرے تو نبی کریم صلی اللہ علیہ وسلم نے انہیں بلایا اور فرمایا کہ یہ صفیہ ہیں۔ ان دونوں انصاریوں نے کہا، سبحان اللہ ( کیا ہم آپ پر شبہ کریں گے ) نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ شیطان انسان کے اندر اس طرح دوڑتا ہے جیسے خون دوڑتا ہے۔ اس کی روایت شعیب، ابن مسافر، ابن ابی عتیق اور اسحاق بن یحییٰ نے زہری سے کی ہے، ان سے علی بن حسین نے اور ان سے صفیہ رضی اللہ عنہا نے نبی کریم صلی اللہ علیہ وسلم سے یہی واقعہ نقل کیا ہے۔' WHERE id = 6903;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن نفر نے بیان کیا، کہا ہم سے عبدالرزاق نے بیان کیا، کہا ہم کو سفیان نے خبر دی ‘، انہیں منصور اور اعمش نے، ان سے ابووائل نے بیان کیا کہ عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جو شخص ایسی قسم کھائے جو جھوٹی ہو جس کے ذریعہ وہ کسی دوسرے کا مال مار لے تو اللہ سے وہ اس حال میں ملے کا کہ وہ اس پر غضبناک ہو گا۔“ پھر اللہ تعالیٰ نے یہ آیت ( اس کی تصدیق میں ) نازل فرمائی «إن الذين يشترون بعهد الله‏ وأيمانهم ثمنا قليلا» ”بلاشبہ جو لوگ اللہ کے عہد اور اس کی قسموں کو تھوڑی پونجی کے بدلے خریدتے ہیں“ الآية‏.‏۔' WHERE id = 6914;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی انہیں زہری نے، انہیں عبیداللہ بن عبداللہ نے خبر دی اور انہیں عبداللہ بن عباس رضی اللہ عنہما نے خبر دی کہ ابوسفیان بن حرب نے انہیں خبر دی کہ ہرقل نے انہیں قریش کی ایک جماعت کے ساتھ بلا بھیجا، پھر اپنے ترجمان سے کہا، ان سے کہو کہ میں ان کے بارے میں پوچھوں گا۔ اگر یہ مجھ سے جھوٹ بات کہے تو اسے جھٹلا دیں۔ پھر پوری حدیث بیان کی اس سے کہو کہ اگر تمہاری باتیں صحیح ہیں تو وہ شخص اس ملک کا بھی ہو جائے گا جو اس وقت میرے قدموں کے نیچے ہے۔' WHERE id = 6925;
UPDATE hadiths SET urdu = 'ہم سے ابوالعاصم نے بیان کیا، کہا ہم سے یزید بن ابی عبید نے، ان سے سلمہ رضی اللہ عنہ نے بیان کیا کہ ہم نے نبی کریم صلی اللہ علیہ وسلم سے درخت کے نیچے بیعت کی۔ نبی کریم صلی اللہ علیہ وسلم نے مجھ سے فرمایا ”سلمہ! کیا تم بیعت نہیں کرو گے؟ میں نے عرض کیا: یا رسول اللہ! میں نے پہلی ہی مرتبہ میں بیعت کر لی ہے، فرمایا کہ اور دوسری مرتبہ میں بھی کر لو۔“' WHERE id = 6936;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے بیان کیا، ان سے ان کے والد نے، ان سے محمد بن جبیر بن مطعم نے، ان سے ان کے والد نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے پاس ایک خاتون آئیں اور کسی معاملہ میں آپ سے گفتگو کی، پھر نبی کریم صلی اللہ علیہ وسلم نے ان سے کہا کہ وہ دوبارہ آپ کے پاس آئیں۔ انہوں نے عرض کیا: یا رسول اللہ! اگر میں آؤں اور آپ کو نہ پاؤں تو پھر آپ کیا فرماتے ہیں؟ جیسے ان کا اشارہ وفات کی طرف ہو۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر مجھے نہ پاؤ تو ابوبکر کے پاس آئیو۔' WHERE id = 6948;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا، کہا ہم سے جریر بن عبدالحمید نے بیان کیا، ان سے اعمش نے، ان سے ابوصالح نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”رشک صرف دو شخصوں پر ہو سکتا ہے ایک وہ جسے اللہ نے قرآن دیا ہے اور وہ اسے دن رات پڑھتا رہتا ہے اور اس پر ( سننے والا ) کہے کہ اگر مجھے بھی اس کا ایسا ہی علم ہوتا جیسا کہ اس شخص کو دیا گیا ہے تو میں بھی اسی طرح کرتا جیسا کہ یہ کرتا ہے اور دوسرا وہ شخص جسے اللہ نے مال دیا اور وہ اسے اللہ کے راستے میں خرچ کرتا ہے تو ( دیکھنے والا ) کہے کہ اگر مجھے بھی اتنا دیا جاتا جیسا اسے دیا گیا ہے تو میں بھی اسی طرح کرتا جیسا کہ یہ کر رہا ہے۔“ ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے جریر نے پھر یہی حدیث بیان کی۔' WHERE id = 6959;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، کہا ہم کو زہری نے خبر دی اور لیث نے کہا کہ مجھ سے عبدالرحمٰن بن خالد نے بیان کیا، ان سے ابن شہاب (زہری) نے، انہیں سعید بن مسیب نے خبر دی اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے صوم وصال سے منع کیا تو صحابہ نے عرض کی کہ آپ تو وصال کرتے ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم میں کون مجھ جیسا ہے، میں تو اس حال میں رات گزارتا ہوں کہ میرا رب مجھے کھلاتا پلاتا ہے لیکن جب لوگ نہ مانے تو آپ نے ایک دن کے ساتھ دوسرا دن ملا کر ( وصال کا ) روزہ رکھا، پھر لوگوں نے ( عید کا ) چاند دیکھا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر چاند نہ ہوتا تو میں اور وصال کرتا، گویا آپ صلی اللہ علیہ وسلم نے انہیں تنبیہ کرنے کے لیے ایسا فرمایا۔' WHERE id = 6969;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن موسیٰ بلخی نے بیان کیا، کہا ہم سے وکیع بن جراح نے بیان کیا، ان سے اسرائیل بن یونس نے، ان سے ابواسحاق سبیعی نے اور ان سے براء بن عازب رضی اللہ عنہ نے بیان کیا کہ جب رسول اللہ صلی اللہ علیہ وسلم مدینہ تشریف لائے تو آپ سولہ یا سترہ مہینے تک بیت المقدس کی طرف منہ کر کے نماز پڑھتے رہے لیکن آپ کی آرزو تھی کہ کعبہ کی طرف منہ کر کے نماز پڑھیں۔ پھر اللہ تعالیٰ نے ( سورۃ البقرہ میں ) یہ آیت نازل کی «قد نرى تقلب وجهك في السماء فلنولينك قبلة ترضاها‏» ”ہم آپ کے منہ کے باربار آسمان کی طرف اٹھنے کو دیکھتے ہیں، عنقریب ہم آپ کو منہ کو اس قبلہ کی طرف پھیر دیں گے جس سے آپ خوش ہوں گے۔“ چنانچہ رخ کعبہ کی طرف کر دیا گیا۔ ایک صاحب نے عصر کی نماز نبی کریم صلی اللہ علیہ وسلم کے ساتھ پڑھی، پھر وہ مدینہ سے نکل کر انصار کی ایک جماعت تک پہنچے اور کہا کہ وہ گواہی دیتے ہیں کہ انہوں نے نبی کریم صلی اللہ علیہ وسلم کے ساتھ نماز پڑھی ہے اور کعبہ کی طرف منہ کرنے کا حکم ہو گیا ہے چنانچہ سب لوگ کعبہ رخ ہو گئے حالانکہ وہ عصر کی نماز کے رکوع میں تھے۔' WHERE id = 6979;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، انہوں نے کہا مجھ سے لیث بن سعد نے بیان کیا، ان سے یونس نے بیان کیا، ان سے ابن شہاب نے بیان کیا، انہیں عبیداللہ بن عبداللہ بن عتبہ نے خبر دی، انہیں عبداللہ بن عباس رضی اللہ عنہما نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم نے کسریٰ پرویز شاہ ایران کو خط بھیجا اور قاصد عبداللہ بن حذافہ رضی اللہ عنہ کو حکم دیا کہ خط بحرین کے گورنر منذر بن ساوی کے حوالہ کریں وہ اسے کسریٰ تک پہنچائے گا۔ جب کسریٰ نے وہ خط پڑھا تو اسے پھاڑ دیا۔ مجھے یاد ہے کہ سعید بن المسیب نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے اسے بددعا دی کہ اللہ انہیں بھی ٹکڑے ٹکڑے کر دے۔' WHERE id = 6990;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ اویسی نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے سعید بن ابی سعید نے، ان سے ان کے والد نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”انبیاء میں سے کوئی نبی ایسا نہیں جن کو کچھ نشانیاں ( یعنی معجزات ) نہ دئیے گئے ہوں جن کے مطابق ان پر ایمان لایا گیا ( آپ صلی اللہ علیہ وسلم نے فرمایا کہ ) انسان ایمان لائے اور مجھے جو بڑا معجزہ دیا گیا وہ قرآن مجید ہے جو اللہ نے میری طرف بھیجا، پس میں امید کرتا ہوں کہ قیامت کے دن شمار میں تمام انبیاء سے زیادہ پیروی کرنے والے میرے ہوں گے۔“' WHERE id = 7000;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا مجھ سے امام مالک نے بیان کیا، ان سے ابوالزناد نے، ان سے اعرج نے، ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جب تک میں تم سے یکسو رہوں تم بھی مجھے چھوڑ دو ( اور سوالات وغیرہ نہ کرو ) کیونکہ تم سے پہلے کی امتیں اپنے ( غیر ضروری ) سوال اور انبیاء کے سامنے اختلاف کی وجہ سے تباہ ہو گئیں۔ پس جب میں تمہیں کسی چیز سے روکوں تو تم بھی اس سے پرہیز کرو اور جب میں تمہیں کسی بات کا حکم دوں تو بجا لاؤ جس حد تک تم میں طاقت ہو۔“' WHERE id = 7012;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے عبداللہ بن دینار نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے سونے کی ایک انگوٹھی بنوائی تو دوسرے لوگوں نے بھی سونے کی انگوٹھیاں بنوا لیں، پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں نے سونے کی ایک انگوٹھی بنوائی تھی، پھر آپ صلی اللہ علیہ وسلم نے پھینک دی اور فرمایا کہ میں اسے کبھی نہیں پہنوں گا اور لوگوں نے بھی اپنی انگوٹھیاں پھینک دیں۔' WHERE id = 7022;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہم کو ابوحمزہ نے خبر دی، کہا میں نے اعمش سے سنا، کہا کہ میں نے ابووائل سے پوچھا تم صفین کی لڑائی میں شریک تھے؟ کہا کہ ہاں، پھر میں نے سہل بن حنیف کو کہتے سنا ( دوسری سند ) امام بخاری رحمہ اللہ نے کہا اور ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، ان سے اعمش نے، ان سے ابووائل نے بیان کیا کہ سہل بن حنیف رضی اللہ عنہ نے ( جنگ صفین کے موقع پر ) کہا کہ لوگوں! اپنے دین کے مقابلہ میں اپنی رائے کو بےحقیقت سمجھو میں نے اپنے آپ کو ابوجندل رضی اللہ عنہ کے واقعہ کے دن ( صلح حدیبیہ کے موقع پر ) دیکھا کہ اگر میرے اندر رسول اللہ صلی اللہ علیہ وسلم کے حکم سے ہٹنے کی طاقت ہوتی تو میں اس دن آپ سے انحراف کرتا ( اور کفار قریش کے ساتھ ان شرائط کو قبول نہ کرتا ) اور ہم نے جب کسی مہم پر اپنی تلواریں کاندھوں پر رکھیں ( لڑائی شروع کی ) تو ان تلواروں کی بدولت ہم کو ایک آسانی مل گئی جسے ہم پہچانتے تھے مگر اس مہم میں ( یعنی جنگ صفین میں مشکل میں گرفتار ہیں دونوں طرف والے اپنے اپنے دلائل پیش کرتے ہیں ) ابواعمش نے کہا کہ ابووائل نے بتایا کہ میں صفین میں موجود تھا اور صفین کی لڑائی بھی کیا بری لڑائی تھی جس میں مسلمان آپس میں کٹ مرے۔' WHERE id = 7032;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبدالعزیز نے بیان کیا، کہا ہم سے یمن کے ابوعمر صنعانی بیان کیا، ان سے زید بن اسلم نے، ان سے عطاء بن یسار نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”تم اپنے سے پہلی امتوں کی ایک ایک بالشت اور ایک ایک گز میں اتباع کرو گے، یہاں تک کہ اگر وہ کسی گوہ کے سوراخ میں داخل ہوئے ہوں گے تو تم اس میں بھی ان کی اتباع کرو گے۔“ ہم نے پوچھا: یا رسول اللہ! کیا یہود و نصاریٰ مراد ہیں؟ فرمایا پھر اور کون۔' WHERE id = 7043;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر نے بیان کیا، کہا ہم سے ابوضمرہ نے بیان کیا، کہا ہم سے موسیٰ بن عقبہ نے، ان سے نافع نے اور ان سے ابن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم کے پاس یہودی ایک مرد اور ایک عورت کو لے کر آئے جنہوں نے زنا کیا تھا تو نبی کریم صلی اللہ علیہ وسلم نے ان کے لیے رجم کا حکم دیا اور انہیں مسجد کی ایک جگہ کے قریب رجم کیا گیا جہاں جنازے رکھے جاتے ہیں۔' WHERE id = 7054;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے عبداللہ بن دینار نے اور ان سے ابن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے اہل نجد کے لیے مقام قرن، حجفہ کو اہل شام کے لیے اور ذوالحلیفہ کو اہل مدینہ کے لیے میقات مقرر کیا۔ بیان کیا کہ میں نے یہ نبی کریم صلی اللہ علیہ وسلم سے سنا اور مجھے معلوم ہوا ہے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اہل یمن کے لیے یلملم ( میقات ) ہے اور عراق کا ذکر ہوا تو انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم کے زمانے میں عراق نہیں تھا۔' WHERE id = 7065;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا مجھ سے امام مالک نے بیان کیا، ان سے زید بن اسلم نے، ان سے ابی صالح السمان نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”گھوڑے تین طرح کے لوگوں کے لیے ہیں۔ ایک شخص کے لیے ان کا رکھنا کار ثواب ہے، دوسرے کے لیے برابر برابر نہ عذاب نہ ثواب اور تیسرے کے لیے وبال جان ہیں۔ جس کے لیے وہ اجر ہیں یہ وہ شخص ہے جس نے اسے اللہ کے راستے کے لیے باندھ کر رکھا اور اس کی رسی چراہ گاہ میں دراز کر دی تو وہ گھوڑا جتنی دور تک چراہ گاہ میں گھوم کر چرے گا وہ مالک کی نیکیوں میں ترقی کا ذریعہ ہو گا اور اگر گھوڑے نے اس دراز رسی کو بھی تڑوا لیا اور ایک یا دو دوڑ اس نے لگائی تو اس کے نشانات قدم اور اس کی لید بھی مالک کے لیے باعث اجر و ثواب ہو گی اور اگر گھوڑا کسی نہر سے گزرا اور اس نے نہر کا پانی پی لیا، مالک نے اسے پلانے کا کوئی ارادہ نہیں کیا تھا تب بھی مالک کے لیے یہ اجر کا باعث ہو گا اور ایسا گھوڑا اپنے مالک کے لیے ثواب ہوتا ہے اور دوسرا شخص برابر برابر والا ہوتا ہے جو گھوڑے کو اظہار بے نیازی یا اپنے بچاؤ کی غرض سے باندھتا ہے اور اس کی پشت اور گردن پر اللہ کے حق کو بھی نہیں بھولتا تو یہ گھوڑا اس کے لیے نہ عذاب ہے نہ ثواب اور تیسرا وہ شخص ہے جو گھوڑے کو فخر اور ریا کے لیے باندھتا ہے تو یہ اس کے لیے وبال جان ہے اور رسول اللہ صلی اللہ علیہ وسلم سے گدھوں کے متعلق پوچھا گیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ نے اس سلسلہ میں مجھ پر اس جامع اور نادر آیت کے سوا اور کچھ نہیں نازل فرمایا ہے «فمن يعمل مثقال ذرة خيرا يره * ومن يعمل مثقال ذرة شرا يره‏» ”پس جو کوئی ایک ذرہ برابر بھی بھلائی کرے گا وہ اسے دیکھے گا اور جو کوئی ایک ذرہ برابر بھی برائی کرے گا وہ اسے دیکھے گا۔“' WHERE id = 7076;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا ہم کو ہشام نے خبر دی، انہیں معمر نے، انہیں زہری نے، انہیں عبیداللہ بن عبداللہ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم کی وفات کا وقت قریب آیا تو گھر میں بہت سے صحابہ موجود تھے، جن میں عمر بن خطاب رضی اللہ عنہ بھی تھے اس وقت آپ صلی اللہ علیہ وسلم نے فرمایا کہ آؤ میں تمہارے لیے ایک ایسا مکتوب لکھ دوں کہ اس کے بعد تم کبھی گمراہ نہ ہو۔ عمر رضی اللہ عنہ نے کہا کہ اس وقت آپ صلی اللہ علیہ وسلم نے فرمایا کہ آؤ میں تمہارے لیے ایک ایسا مکتوب لکھ دوں کہ اس کے بعد تم کبھی گمراہ نہ ہو۔ عمر رضی اللہ عنہ نے کہا نبی کریم صلی اللہ علیہ وسلم تکلیف میں مبتلا ہیں، تمہارے پاس اللہ کی کتاب ہے اور یہی ہمارے لیے کافی ہے۔ گھر کے لوگوں میں بھی اختلاف ہو گیا اور آپس میں بحث کرنے لگے۔ ان میں سے بعض نے کہا کہ نبی کریم صلی اللہ علیہ وسلم کے قریب ( لکھنے کا سامان ) کر دو۔ وہ تمہارے لیے ایسی چیز لکھ دیں گے کہ اس کے بعد تم گمراہ نہیں ہو گے اور بعض نے وہی بات کہی جو عمر رضی اللہ عنہ کہہ چکے تھے۔ جب نبی کریم صلی اللہ علیہ وسلم کے پاس لوگ اختلاف و بحث زیادہ کرنے لگے تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ میرے پاس سے ہٹ جاؤ۔ عبیداللہ رضی اللہ عنہ نے بیان کیا کہ ابن عباس رضی اللہ عنہما کہا کرتے تھے کہ سب سے بھاری مصیبت تو وہ تھے جو رسول اللہ صلی اللہ علیہ وسلم اور اس نوشت لکھوانے کے درمیان حائل ہوئے، یعنی جھگڑا اور شور۔' WHERE id = 7086;
UPDATE hadiths SET urdu = 'ہم سے محمد نے بیان کیا، انہوں نے کہا ہم کو ابومعاویہ نے خبر دی، انہیں اعمش نے، انہیں زید بن وہب اور ابوظبیان نے اور ان سے جریر بن عبداللہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جو لوگوں پر رحم نہیں کھاتا اللہ بھی اس پر رحم نہیں کھاتا۔“' WHERE id = 7096;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے ایوب سختیانی نے، ان سے ابوعثمان نہدی نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ ایک سفر میں تھے اور جب ہم بلندی پر چڑھتے تو ( زور سے چلا کر ) تکبیر کہتے۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ لوگو! اپنے اوپر رحم کھاؤ! اللہ بہرا نہیں ہے اور نہ وہ کہیں دور ہے۔ تم ایک بہت سننے، بہت واقف کار اور قریب رہنے والی ذات کو بلاتے ہو۔ پھر نبی کریم صلی اللہ علیہ وسلم میرے پاس آئے۔ میں اس وقت دل میں «لا حول ولا قوة إلا بالله» کہہ رہا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے مجھ سے فرمایا ”عبداللہ بن قیس! «لا حول ولا قوة إلا بالله» کہا کرو کہ یہ جنت کے خزانوں میں سے ایک خزانہ ہے۔“ یا آپ صلی اللہ علیہ وسلم نے فرمایا کہ کیا میں تمہیں یہ نہ بتا دوں۔' WHERE id = 7106;
UPDATE hadiths SET urdu = 'ہم سے یوسف بن موسیٰ نے بیان کیا، انہوں نے کہا ہم سے ابوخالد احمر نے بیان کیا، انہوں نے کہا کہ میں نے ہشام بن عروہ سنا، وہ اپنے والد (عروہ بن زبیر) سے بیان کرتے تھے کہ ان سے ام المؤمنین عائشہ صدیقہ رضی اللہ عنہا نے بیان کیا کہ لوگوں نے کہا: یا رسول اللہ! وہاں کے قبیلے ابھی حال ہی میں اسلام لائے اور وہ ہمیں گوشت لا کر دیتے ہیں۔ ہمیں یقین نہیں ہوتا کہ ذبح کرتے وقت انہوں نے اللہ کا نام بھی لیا تھا یا نہیں ( تو کیا ہم اسے کھا سکتے ہیں؟ ) نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم اس پر اللہ کا نام لے کر اسے کھا لیا کرو۔ اس روایت کی متابعت محمد بن عبدالرحمٰن دراوردی اور اسامہ بن حفص نے کی۔' WHERE id = 7117;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم کو قتادہ نے خبر دی، کہا میں نے انس رضی اللہ عنہ سے سنا اور ان سے نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ نے جتنے نبی بھیجے ان سب نے جھوٹے کانے دجال سے اپنی قوم کو ڈرایا، وہ دجال کانا ہو گا اور تمہارا رب ( آنکھوں والا ہے ) کانا نہیں ہے، اس دجال کی دونوں آنکھوں کے درمیان لکھا ہوا ہو گا ( لفظ ) کافر۔“' WHERE id = 7127;
UPDATE hadiths SET urdu = 'ہم سے احمد نے بیان کیا، کہا ہم سے محمد بن ابی بکر المقدمی نے بیان کیا، انہوں نے کہا ہم سے حماد بن زید نے بیان کیا، ان سے ثابت نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ زید بن حارثہ رضی اللہ عنہ ( اپنی بیوی کی ) شکایت کرنے لگے تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ ڈرو اور اپنی بیوی کو اپنے پاس ہی رکھو۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ اگر نبی کریم صلی اللہ علیہ وسلم کسی بات کو چھپانے والے ہوتے تو اسے ضرور چھپاتے۔ بیان کیا چنانچہ زینب رضی اللہ عنہا تمام ازواج مطہرات پر فخر سے کہتی تھی کہ تم لوگوں کی تمہارے گھر والوں نے شادی کی۔ اور میری اللہ تعالیٰ نے سات آسمانوں کے اوپر سے شادی کی اور ثابت رضی اللہ عنہ سے مروی ہے کہ آیت «وتخفي في نفسك ما الله مبديه وتخشى الناس‏» ”اور آپ اس چیز کو اپنے دل میں چھپاتے ہیں جسے اللہ ظاہر کرنے والا ہے۔“ زینب اور زید بن حارث رضی اللہ عنہ کے بارے میں نازل ہوئی تھی۔' WHERE id = 7138;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ نے بیان کیا، انہوں نے کہا ہم سے سفیان نے بیان کیا، ان سے ان کے والد نے بیان کیا، ان سے ابن ابی نعم یا ابونعم نے۔۔۔ قبیصہ کو شک تھا۔۔۔ اور ان سے ابوسعید رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے پاس کچھ سونا بھیجا گیا تو آپ نے اسے چار آدمیوں میں تقسیم کر دیا۔ اور مجھ سے اسحاق بن نصر نے بیان کیا، ان سے عبدالرزاق نے بیان کیا، انہیں سفیان نے خبر دی، انہیں ان کے والد نے، انہیں ابن ابی نعم نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ علی رضی اللہ عنہ نے یمن سے کچھ سونا نبی کریم صلی اللہ علیہ وسلم کی خدمت میں بھیجا تو نبی کریم صلی اللہ علیہ وسلم نے اسے اقرع بن حابس حنظلی، عیینہ بن بدری فزاری، علقمہ بن علاثہ العامری اور زید الخیل الطائی میں تقسیم کر دیا۔ اس پر قریش اور انصار کو غصہ آ گیا اور انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نجد کے رئیسوں کو تو دیتے ہیں اور ہمیں چھوڑ دیتے ہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں ایک مصلحت کے لیے ان کا دل بہلاتا ہوں۔ پھر ایک شخص جس کی آنکھیں دھنسی ہوئی تھیں، پیشانی ابھری ہوئی تھی، داڑھی گھنی تھی، دونوں کلے پھولے ہوئے تھے اور سر گٹھا ہوا تھا۔ اس مردود نے کہا: اے محمد! اللہ سے ڈر۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر میں بھی اس ( اللہ ) کی نافرمانی کروں گا تو پھر کون اس کی اطاعت کرے گا؟ اس نے مجھے زمین پر امین بنایا ہے اور تم مجھے امین نہیں سمجھتے۔ پھر حاضرین میں سے ایک صحابی خالد رضی اللہ عنہ یا عمر رضی اللہ عنہ نے اس کے قتل کی اجازت چاہی تو نبی کریم صلی اللہ علیہ وسلم نے منع فرمایا۔ پھر جب وہ جانے لگا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس شخص کی نسل سے ایسے لوگ پیدا ہوں گے جو قرآن کے صرف لفظ پڑھیں گے لیکن قرآن ان کے حلق سے نیچے نہیں اترے گا، وہ اسلام سے اس طرح نکال کر پھینک دئیے جائیں گے جس طرح تیر شکاری جانور میں سے پار نکل جاتا ہے، وہ اہل اسلام کو ( کافر کہہ کر ) قتل کریں اور بت پرستوں کو چھوڑ دیں گے اگر میں نے ان کا دور پایا تو انہیں قوم عاد کی طرح نیست و نابود کر دوں گا۔' WHERE id = 7149;
UPDATE hadiths SET urdu = 'ہم سے یوسف بن موسیٰ نے بیان کیا، کہا ہم سے اسامہ نے بیان کیا، کہا مجھ سے اعمش نے بیان کیا، ان سے خیشمہ بن عبدالرحمٰن نے اور ان سے عدی بن حاتم رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”تم میں کوئی ایسا نہیں ہو گا جس سے اس کا رب کلام نہ کرے، اس کے اور بندے کے درمیان کوئی ترجمان نہ ہو گا اور نہ کوئی حجاب ہو گا جو اسے چھپائے رکھے۔“' WHERE id = 7159;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا ہم سے امام مالک نے بیان کیا، ان سے ابوالزناد نے، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جب اللہ تعالیٰ مخلوق کو پیدا کر چکا تو عرش کے اوپر اپنے پاس یہ لکھا کہ میری رحمت میرے غصہ سے آگے بڑھ گئی ہے۔' WHERE id = 7169;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم کو امام مالک نے خبر دی، انہیں ابوالزناد نے، انہیں اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جس نے اللہ کے راستے میں جہاد کیا اور اپنے گھر سے صرف اس غرض سے نکلا کہ خالص اللہ کے راستے میں جہاد کرے اور اس کے کلمہ توحید کی تصدیق کرے تو اللہ تعالیٰ اس کی ضمانت لے لیتا ہے کہ اسے جنت میں داخل کرے گا یا پھر ثواب اور غنیمت کے ساتھ اس کے گھر واپس کرے گا۔“' WHERE id = 7179;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن ابی عیسیٰ نے بیان کیا، انہوں نے کہا ہم کو یزید بن ہارون نے خبر دی، انہیں شعبہ نے خبر دی، انہیں قتادہ نے اور انہیں انس بن مالک رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”دجال مدینہ تک آئے گا لیکن دیکھے گا کہ فرشتہ اس کی حفاظت کر رہے ہیں پس نہ تو دجال اس سے قریب ہو سکے گا اور نہ طاعون، اگر اللہ نے چاہا۔“' WHERE id = 7189;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، انہوں نے کہا ہم سے ہمارے والد نے بیان کیا، انہوں نے کہا ہم سے اعمش نے بیان کیا، ان سے ابوصالح نے بیان کیا اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ فرمائے گا، اے آدم! وہ کہیں گے «لبيك وسعديك‏.‏» پھر بلند آواز سے ندا دے گا کہ اللہ تمہیں حکم دیتا ہے کہ اپنی نسل میں سے دوزخ کا لشکر نکال۔“' WHERE id = 7199;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، کہا ہم سے عبدالرزاق نے بیان کیا، کہا ہم کو معمر نے خبر دی، انہیں ہمام نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”ایوب علیہ السلام کپڑے اتار کر نہا رہے تھے کہ سونے کی ٹڈیوں کا ایک دل ان پر آ کر گرا اور آپ انہیں کپڑے میں سمیٹنے لگے۔ ان کے رب نے انہیں پکارا کہ اے ایوب! کیا میں نے تجھے مالدار بنا کر ان ٹڈیوں سے بےپروا نہیں کر دیا ہے۔ انہوں نے عرض کیا کہ کیوں نہیں بیشک تو نے مجھ کو بےپروا مالدار کیا ہے مگر تیرے فضل و کرم اور رحمت سے بھی میں کہیں بےپروا ہو سکتا ہوں۔“' WHERE id = 7209;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، کہا ہم سے ابوالزناد نے بیان کیا، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ فرماتا ہے کہ میں اپنے بندے کے گمان کے ساتھ ہوں جو وہ میرے متعلق رکھتا ہے۔“' WHERE id = 7220;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث نے بیان کیا، کہا ہم سے عقیل نے بیان کیا، ان سے ابن شہاب نے، کہا ہم سے حمید بن عبدالرحمٰن نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”آدم علیہ السلام اور موسیٰ علیہ السلام نے بحث کی، موسیٰ علیہ السلام نے کہا کہ آپ آدم ہیں جنہوں نے اپنی نسل کو جنت سے نکالا۔ آدم علیہ السلام نے کہا کہ آپ موسیٰ ہیں جنہیں اللہ نے اپنے پیغام اور کلام کے لیے منتخب کیا اور پھر بھی آپ مجھے ایک ایسی بات کے لیے ملامت کرتے ہیں جو اللہ نے میری پیدائش سے پہلے ہی میری تقدیر میں لکھ دی تھی، چنانچہ آدم علیہ السلام موسیٰ علیہ السلام پر غالب آئے۔' WHERE id = 7230;
UPDATE hadiths SET urdu = 'مجھ سے عمرو بن زرارہ نے بیان کیا، ان سے ہشیم نے بیان کیا، انہوں نے کہا ہم کو ابوبشر نے خبر دی، انہیں سعید بن جبیر نے اور انہیں عبداللہ بن عباس رضی اللہ عنہما نے اللہ تعالیٰ کے ارشاد «ولا تجهر بصلاتك ولا تخافت بها‏» کے بارے میں کہ یہ آیت جب نازل ہوئی تو رسول اللہ صلی اللہ علیہ وسلم مکہ میں چھپ کر ( اعمال اسلام ادا کرتے تھے ) لیکن جب اپنے صحابہ کو نماز پڑھاتے تو قرآن مجید بلند آواز سے پڑھتے، جب مشرکین سنتے تو قرآن مجید کو، اس کے اتارنے والے کو اور اسے لے کر آنے والے کو گالی دیتے۔ چنانچہ اللہ تعالیٰ نے اپنے نبی صلی اللہ علیہ وسلم سے کہا کہ اپنی قرآت میں آواز بلند نہ کریں کہ مشرکین سنین اور پھر قرآن کو گالی دیں اور نہ اتنا آہستہ ہی پڑھیں کہ آپ کے صحابہ بھی نہ سن سکیں بلکہ ان کے درمیان کا راستہ اختیار کریں۔' WHERE id = 7240;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، کہا ہم سے جریر بن حازم نے بیان کیا، ان سے امام حسن بصری نے، ان سے عمرو بن تغلب رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے پاس مال آیا اور آپ نے اس میں سے کچھ لوگوں کو دیا اور کچھ کو نہیں دیا۔ پھر نبی کریم صلی اللہ علیہ وسلم کو معلوم ہوا کہ اس پر کچھ لوگ ناراض ہوئے ہیں تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں ایک شخص کو دیتا ہوں اور دوسرے کو نہیں دیتا اور جسے نہیں دیتا وہ مجھے اس سے زیادہ عزیز ہوتا ہے جسے دیتا ہوں۔ میں کچھ لوگوں کو اس لیے دیتا ہوں کہ ان کے دلوں میں گھبراہٹ اور بے چینی ہے اور دوسرے لوگوں پر اعتماد کرتا ہوں کہ اللہ نے ان کے دلوں کو بے نیازی اور بھلائی عطا فرمائی ہے۔ انہیں میں سے عمرو بن تغلب بھی ہیں۔ عمرو رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے اس کلمہ کے مقابلہ میں مجھے لال لال اونٹ ملتے تو اتنی خوشی نہ ہوتی۔' WHERE id = 7250;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، انہوں نے کہا ہم سے ہشیم نے بیان کیا، ان سے ابوبشر نے بیان کیا، ان سے سعید بن جبیر نے بیان کیا اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم مکہ مکرمہ میں چھپ کر تبلیغ کرتے تھے تو قرآن بلند آواز سے پڑھتے، مشرکین جب سنتے تو قرآن کو برا بھلا کہتے اور اس کے لانے والے کو برا بھلا کہتے۔ اس پر اللہ تعالیٰ نے اپنے نبی صلی اللہ علیہ وسلم سے فرمایا کہ ”اپنی نماز میں نہ آواز بلند کرو اور نہ بہت پست۔“' WHERE id = 7262;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، ان سے لیث نے بیان کیا، ان سے نافع نے بیان کیا، ان سے قاسم بن محمد نے بیان کیا اور ان سے ام المؤمنین عائشہ صدیقہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”ان تصویروں کو بنانے والوں پر قیامت میں عذاب ہو گا اور ان سے کہا جائے گا کہ تم نے جو بنایا ہے اسے زندہ بھی کر کے دکھاؤ۔“' WHERE id = 7272;
